-- PROCEDURE NAME: dbo.SMTP_GET_Email_Attachments
CREATE procedure [dbo].[SMTP_GET_Email_Attachments]
@AlertID int
AS

BEGIN
	SELECT FPath
	FROM EAlertQAtt
	WHERE Active = 1
	AND AlertID = @AlertID
END

 




GO
