-- PROCEDURE NAME: dbo.SMTP_Update_Email_Lists
CREATE  PROCEDURE [dbo].[SMTP_Update_Email_Lists]
 (
 @p_AlertID int,
 @p_SysID varchar(50),
 @p_Status varchar(1),
 @p_ErrorMsg varchar(255) OUTPUT
 )
AS
--------------------------------------------------------------------------------------------------------------
-- Procedure Name 	: SMTP_GET_Email_Lists 
-- Date Created		: 16/03/2018
-- Purpose			: To Send Email Alert using SMTP
---------------------------------------------------------------------------------------------------------------


set @p_ErrorMsg=''

 

 UPDATE EALERTQ set   Status =@p_Status,					 
                      LASTUPDATEDON =getdate(),
                      LASTUPDATEDBY =@p_SysID
 where AlertID=@p_AlertID;
 -------------
 

---------------------------------------
GO
