-- PROCEDURE NAME: dbo.sp_api_send_sms
CREATE PROCEDURE [dbo].[sp_api_send_sms] 
	@contactno nvarchar(MAX) = null,
	@subject nvarchar(500) = null,
	@msg nvarchar(MAX) = null,
	@ret nvarchar(5) output
AS

BEGIN

DECLARE @AlertID AS INTEGER;

DECLARE @RowID INTEGER
DECLARE @Value NVARCHAR(100)
DECLARE @DerContactNo NVARCHAR(100)

--SET @contactno = @contactno + '@sbstsms2.com,'
SET @contactno = @contactno + ',83681010'
--SET @contactno = '96734774'

/*
	DECLARE @ret nvarchar(5)
	SET @ret = ''
	exec sp_api_send_sms '96734774,91832674', 'TAMS SMS', 'TOA...', @ret OUTPUT
	SELECT @ret
*/

SET @DerContactNo = ''

DECLARE @Cur02 CURSOR;	

	SET @Cur02 = CURSOR FAST_FORWARD 
	FOR

		SELECT * FROM [dbo].[SPLIT] (',', @contactno)
				
	OPEN @Cur02
	
	FETCH NEXT FROM @Cur02 INTO @RowID, @Value
	
	WHILE @@FETCH_STATUS = 0 
	
		BEGIN
			SET @DerContactNo = @DerContactNo + @Value + ','
			
			FETCH NEXT FROM @Cur02 INTO @RowID, @Value
		END 	

	CLOSE @Cur02
	
	DEALLOCATE @Cur02

EXEC  [dbo].SMSEAlertQ_EnQueue 'TAMSadmin', --@Sender,
	@Subject,		-- @Subject,
	'',				--@Sys,
	'',				--@Greetings,   
	@msg,			--@AlertMsg,   -- do not send null for ntext
	'TAMSadmin',		--@UserId,
	@DerContactNo,		--@SendTo,
	'',				--@CC, -- do not send null for ntext
	'',				--@BCC, -- do not send null for ntext
	',',			--@Separator,
	@AlertID OUTPUT

SET @ret = '0'

RETURN @ret 

END












GO
/****** END PROCEDURE 9 ******/

/****** START PROCEDURE 10 ******/
-- PROCEDURE NAME: dbo.SP_Call_SMTP_Send_SMSAlert
CREATE PROCEDURE [dbo].[SP_Call_SMTP_Send_SMSAlert]
	 @Message		AS NVARCHAR(500) = NULL OUTPUT
AS
------------------------------------------------------------------------------------------
-- Procedure Name 		: [SP_SMTP_Send_SMSAlert]
-- Date Created			: 31/05/2017
-- Purpose				: Send SMS ALert using SMTP
-- Version   	Date         		 		Changes
-- ----------------------------------------------------------------------------------------
-- 1.0    		 31/05/2017			Initial version
--									 
 -------------------------------------------------------------------------------------------

BEGIN
	 
DECLARE	@IntrnlTrans	TINYINT		
SELECT 	@IntrnlTrans 	= 0	

IF (@@TRANCOUNT = 0) 
BEGIN
	SET @IntrnlTrans = 1
	BEGIN TRAN
END

SET @Message = ''

DECLARE @p_Alertid INT,
	@p_from VARCHAR(100),
	@p_To VARCHAR(100),
	@p_Alertmsg VARCHAR(MAX),
	@p_sysname VARCHAR(50)
	
DECLARE @CurMain CURSOR
SET @CurMain = CURSOR FAST_FORWARD FOR
	
	SELECT a.AlertID, a.[From], a.AlertMsg, 'SMTP Alert'
	FROM dbo.SMSEAlertQ a 	  
		WHERE a.status = 'Q' 		
	
OPEN @CurMain 
FETCH NEXT FROM @CurMain INTO @p_Alertid,@p_from,@p_Alertmsg,@p_sysname
WHILE (@@FETCH_STATUS = 0 )
	BEGIN 
		
		DECLARE @CurDetl CURSOR
		SET @CurDetl = CURSOR FAST_FORWARD FOR
				 
		SELECT b.Recipient
			FROM dbo.SMSEAlertQTo b
		WHERE b.AlertID=@p_Alertid

		OPEN @CurDetl 
		FETCH NEXT FROM @CurDetl INTO @p_To
		WHILE (@@FETCH_STATUS = 0 )
			BEGIN 
		 
				EXEC [dbo].[SP_SMTP_SMS_NetPage] @p_from, @p_To, @p_Alertmsg, @p_Alertid, @p_sysname
		
				FETCH NEXT FROM @CurDetl INTO @p_To
			END
		CLOSE @CurDetl
		DEALLOCATE @CurDetl
	
		----------------------
		UPDATE SMSEAlertQ 
			SET status='S', 
				LastUpdatedOn = getdate(),
				LastUpdatedBy = @p_sysname
			WHERE AlertID = @p_Alertid
		----------------------
	FETCH NEXT FROM @CurMain INTO  @p_Alertid, @p_from, @p_Alertmsg, @p_sysname
	END

CLOSE @CurMain
DEALLOCATE @CurMain

IF @@ERROR <> 0 BEGIN
	SET @Message = 'Error Sending SMS'
	GOTO TRAP_ERROR
END

FORCE_EXIT_PROC:	
	IF @IntrnlTrans = 1 COMMIT TRAN
	RETURN @Message 

TRAP_ERROR:
	IF @IntrnlTrans = 1 ROLLBACK TRAN
	RETURN @Message

END	  

GO
/****** END PROCEDURE 10 ******/

/****** START PROCEDURE 11 ******/
-- PROCEDURE NAME: dbo.SP_CheckPagePermission
CREATE PROCEDURE [dbo].[SP_CheckPagePermission]
	-- Add the parameters for the stored procedure here
	@userid as nvarchar(50),
	@menuid as nvarchar(50),
	@res as bit OUTPUT
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

	IF EXISTS(Select DISTINCT MenuID from TAMS_Menu_Role 
	INNER JOIN TAMS_Role ON TAMS_Role.ID=TAMS_Menu_Role.RoleId
	INNER JOIN TAMS_User_Role ON TAMS_Menu_Role.RoleId=TAMS_User_Role.RoleID
	INNER JOIN TAMS_User ON TAMS_User_Role.UserID=TAMS_User.Userid
	where Loginid=@userid and MenuID=@menuid)
	BEGIN
		SET @RES=1;
	END
	ELSE
	BEGIN
		SET @RES=0;
	END

END
GO
/****** END PROCEDURE 11 ******/

/****** START PROCEDURE 12 ******/
-- PROCEDURE NAME: dbo.sp_Generate_Ref_Num
CREATE   procedure [dbo].[sp_Generate_Ref_Num]
	@FormType	AS NVARCHAR(20) = NULL,
	@Line		AS NVARCHAR(20) = NULL,
	@TrackType	AS NVARCHAR(50) = NULL,
	@RefNum		AS NVARCHAR(20) = NULL OUTPUT,
	@Message	AS NVARCHAR(500) = NULL OUTPUT
AS
BEGIN

DECLARE	@IntrnlTrans	TINYINT,
	@ErrorMsg		NVARCHAR(500)			

SET @ErrorMsg = ''

SELECT 	@IntrnlTrans 	= 0	

IF (@@TRANCOUNT = 0) 
BEGIN
	SET @IntrnlTrans = 1
	BEGIN TRAN
END

-- >>



DECLARE @MaxNum	BIGINT

SET @MaxNum = 1

IF @FormType = 'TAR'
	BEGIN
		IF (SELECT COUNT(*) 
			FROM [dbo].[TAMS_RefSerialNumber]
				WHERE FormType = @FormType
					AND Line = @Line
					and TrackType = @TrackType
					AND [Year] = YEAR(GETDATE())) = 0
			BEGIN
				INSERT INTO [dbo].[TAMS_RefSerialNumber]
					([Line],[TrackType], [Year], [OperationDate], [FormType], [MaxNum])
				VALUES 
					(@Line,@TrackType, YEAR(GETDATE()), GETDATE(), @FormType, @MaxNum)
			END
		ELSE
			BEGIN
				SELECT @MaxNum = [MaxNum] 
					FROM [dbo].[TAMS_RefSerialNumber]
						WHERE FormType = @FormType
							AND Line = @Line
							and TrackType = @TrackType
							AND [Year] = YEAR(GETDATE())

				SET @MaxNum = @MaxNum + 1

				UPDATE [dbo].[TAMS_RefSerialNumber]
					SET MaxNum = @MaxNum
				WHERE FormType = @FormType
					AND Line = @Line
					AND TrackType = @TrackType
					AND [Year] = YEAR(GETDATE())
			END

			if @TrackType = 'Depot' 
			begin
				set @Line = @Line + 'D';
			end;
			SET @RefNum = @Line + '-' + @FormType + '-' + CAST(YEAR(GETDATE()) AS NVARCHAR(20)) + '-' + RIGHT('00000' + CAST(@MaxNum AS VARCHAR(5)), 5)
	END

-- >>

IF @@ERROR <> 0 BEGIN
	SET @Message = 'ERROR GENERATING REF NUM'
	GOTO TRAP_ERROR
END

FORCE_EXIT_PROC:	
	IF @IntrnlTrans = 1 COMMIT TRAN
	RETURN @Message 

TRAP_ERROR:
	IF @IntrnlTrans = 1 ROLLBACK TRAN
	RETURN @Message

END
GO
/****** END PROCEDURE 12 ******/

/****** START PROCEDURE 13 ******/
-- PROCEDURE NAME: dbo.sp_Generate_Ref_Num_TOA
CREATE PROCEDURE [dbo].[sp_Generate_Ref_Num_TOA]
	@FormType	AS NVARCHAR(20) = NULL,
	@Line		AS NVARCHAR(20) = NULL,
	@TARID		AS Int = 0, 
	@OperationDate	AS NVARCHAR(20) = NULL,
	@TrackType	AS NVARCHAR(50) = 'MainLine',
	@RefNum		AS NVARCHAR(20) = NULL OUTPUT,
	@Message	AS NVARCHAR(500) = NULL OUTPUT
AS

BEGIN

DECLARE	@IntrnlTrans	TINYINT,
	@ErrorMsg		NVARCHAR(500)			

SET @ErrorMsg = ''

SELECT 	@IntrnlTrans 	= 0	

IF (@@TRANCOUNT = 0) 
BEGIN
	SET @IntrnlTrans = 1
	BEGIN TRAN
END

-- >>

DECLARE @MaxNum	BIGINT
SET @MaxNum = 1

DECLARE @OPDateStr			NVARCHAR(20)
DECLARE @CurrTimeStr		NVARCHAR(20)
DECLARE @RefNumOPDateStr	NVARCHAR(20)
DECLARE @RefNumCurrStr		NVARCHAR(20)

Declare @AccessDate	Date;
Select @AccessDate = AccessDate 
From TAMS_TAR 
Where ID = @TARID;


SET @OPDateStr = CONVERT(NVARCHAR(20), @AccessDate, 103)
SET @CurrTimeStr = CONVERT(NVARCHAR(20), CONVERT(TIME, GETDATE(), 108), 108)

SET @RefNumOPDateStr = CAST(LEFT(@OPDateStr, 2) AS NVARCHAR(2)) + CAST(SUBSTRING(@OPDateStr, 4, 2) AS NVARCHAR(2))
SET @RefNumCurrStr = CAST(LEFT(@CurrTimeStr, 2) AS NVARCHAR(2)) + CAST(SUBSTRING(@CurrTimeStr, 4, 2) AS NVARCHAR(2))

IF @FormType = 'TOA'
	BEGIN
		IF (SELECT COUNT(*) 
			FROM [dbo].[TAMS_RefSerialNumber]
				WHERE FormType = @FormType
					AND Line = @Line
					and UPPER(TrackType) = UPPER(@TrackType)
					AND [Year] = YEAR(GETDATE())
					AND OperationDate = CONVERT(DATE, CONVERT(DATETIME, @OperationDate, 103))) = 0
			BEGIN
				INSERT INTO [dbo].[TAMS_RefSerialNumber]
					([Line], [TrackType], [Year], [OperationDate], [FormType], [MaxNum])
				VALUES 
					(@Line, @TrackType, YEAR(GETDATE()), CONVERT(DATE, CONVERT(DATETIME, @OperationDate, 103)), @FormType, @MaxNum)
			END
		ELSE
			BEGIN
				--SELECT @MaxNum = [MaxNum] 
				--	FROM [dbo].[TAMS_RefSerialNumber]
				--		WHERE FormType = @FormType
				--			AND Line = @Line
				--			AND [Year] = YEAR(GETDATE())
				--			AND OperationDate = CONVERT(DATE, @OperationDate, 103)

				--SET @MaxNum = @MaxNum + 1

				UPDATE [dbo].[TAMS_RefSerialNumber]
					SET MaxNum = ISNULL(MaxNum, 0) + 1
				WHERE FormType = @FormType
					AND Line = @Line
					AND [Year] = YEAR(GETDATE())
					and UPPER(TrackType) = UPPER(@TrackType)
					AND OperationDate = CONVERT(DATE, CONVERT(DATETIME, @OperationDate, 103))

				SELECT @MaxNum = ISNULL(MaxNum, 0)
					FROM [dbo].[TAMS_RefSerialNumber]
					WHERE FormType = @FormType
					AND Line = @Line
					and UPPER(TrackType) = UPPER(@TrackType)
					AND [Year] = YEAR(GETDATE())
					AND OperationDate = CONVERT(DATE, CONVERT(DATETIME, @OperationDate, 103))

			END


			--XXX-TOA-DDMM-hhmm-# 

			--where XXX – Line (DTL, NEL)
			--		DDMM – access date in day & month
			--		hhmm – TOA generation time.
			--			   hh in 24 hrs format
			--			   mm minutes
			--		# - Running no. Reset to 1 daily.

			--Eg: DTL-TOA-1504-0123-1
			--	DTL-TOA-1504-0126-2
			--	DTL-TOA-1504-0130-3
			--	DTL-TOA-1504-0130-4


		if @TrackType = 'Depot' 
		begin
				set @Line = @Line + 'D';
		end;
		
		SET @RefNum = @Line + '-' + 
			@FormType + '-' + 
			CAST(@RefNumOPDateStr AS NVARCHAR(5)) + '-' + 
			CAST(@RefNumCurrStr AS NVARCHAR(5)) + '-' + 
			CAST(@MaxNum AS VARCHAR(2))
	END

IF @@ERROR <> 0 BEGIN
	SET @Message = 'ERROR GENERATING REF NUM'
	GOTO TRAP_ERROR
END

FORCE_EXIT_PROC:	
	IF @IntrnlTrans = 1 COMMIT TRAN
	RETURN @Message 

TRAP_ERROR:
	IF @IntrnlTrans = 1 ROLLBACK TRAN
	RETURN @Message

END
GO
/****** END PROCEDURE 13 ******/

