SELECT 	@IntrnlTrans 	= 0	

IF (@@TRANCOUNT = 0) 
BEGIN
	SET @IntrnlTrans = 1
	BEGIN TRAN
END

IF (SELECT COUNT(*) 
		FROM [dbo].[TAMS_TAR_TVF]
			WHERE TARId = @TARID
				AND TVFStationId = @StationID
				AND TVFDirection = @Direction) = 0
	BEGIN
		INSERT INTO [dbo].[TAMS_TAR_TVF]
			([TARId], [TVFStationId], [TVFDirection])
		VALUES
			(@TARID, @StationID, @Direction)
	END

-- >>

IF @@ERROR <> 0 BEGIN
	SET @Message = 'ERROR INSERTING INTO TAMS_TAR'
	GOTO TRAP_ERROR
END

FORCE_EXIT_PROC:	
	IF @IntrnlTrans = 1 COMMIT TRAN
	RETURN @Message 

