-- PROCEDURE NAME: dbo.sp_TAMS_Approval_Endorse20250120
CREATE PROCEDURE  [dbo].[sp_TAMS_Approval_Endorse20250120]
	@TARID		AS INTEGER,						-- >> TAR ID
	@TARWFID	AS INTEGER,						-- >> Current WF ID
	@EID		AS INTEGER,						-- >> Current Endorser ID
	@ELevel		AS INTEGER,						-- >> Current Endorser Level
	@Remarks	AS NVARCHAR(1000) = NULL,		-- >> Remarks -- Mandatory for Reject / Optional for Approved / Endorse
	@TVFRunMode			AS NVARCHAR(50) = NULL,	-- >> New Column to be confirmed with Adeline
	@TVFRunModeUpdInd	AS NVARCHAR(5) = NULL,	-- >> Indicator to Update TVF Run Mode or Not.
	@UserLI		AS NVARCHAR(100) = NULL,			-- >> User Login ID	
	@Message	AS NVARCHAR(500) = NULL OUTPUT
AS

BEGIN

DECLARE	@IntrnlTrans	TINYINT
SELECT 	@IntrnlTrans 	= 0	

IF (@@TRANCOUNT = 0) 
BEGIN
	SET @IntrnlTrans = 1
	BEGIN TRAN
END

-- >>
SET @Message = ''
DECLARE @UserID		INTEGER
DECLARE @UserName	NVARCHAR(500)

DECLARE @EMTARID		INTEGER
DECLARE @EMTARStatus	NVARCHAR(20)
DECLARE @EMTARNo		NVARCHAR(50)
DECLARE @EMRemarks		NVARCHAR(1000)
DECLARE @EMActor		NVARCHAR(100)
DECLARE @EMToSend		NVARCHAR(1000)
DECLARE @EMCCSend		NVARCHAR(1000)
DECLARE @EMCompany		NVARCHAR(100)
DECLARE @EMMsg			NVARCHAR(500)
DECLARE @TrackType		NVARCHAR(50)

DECLARE @TARDate		DATE

SELECT @UserID = Userid, @UserName = [Name]
FROM TAMS_User
	WHERE LoginId = @UserLI

-- >>>
DECLARE @TARWFCtr	INTEGER
SET @TARWFCtr = 0

SELECT @TARWFCtr = COUNT(*) 
	FROM TAMS_TAR_Workflow
		WHERE TARId = @TARID
			AND ActionBy = @UserID
			AND WFStatus = 'Approved'

IF @TARWFCtr > 0
	BEGIN
		--SET @Message = 'Error! User ID have already approved this TAR.'
		SET @Message = '1001'
		GOTO FORCE_EXIT_PROC
	END
-- >>>

UPDATE TAMS_TAR_Workflow
	SET WFStatus = 'Approved',
		ActionBy = @UserID,
		ActionOn = GETDATE(),
		Remark = @Remarks
	WHERE ID =  @TARWFID

IF @TVFRunModeUpdInd = 1
	BEGIN
		UPDATE TAMS_TAR
			SET TVFMode = @TVFRunMode
		WHERE ID = @TARID
	END

DECLARE @NextEndID		INTEGER
DECLARE @NextEndTitle	NVARCHAR(100)
DECLARE @NextWFID		INTEGER
DECLARE @NextWFStatID	INTEGER
DECLARE @NextRoleID		INTEGER
DECLARE @TARType	NVARCHAR(20)
DECLARE @WFID		INTEGER
DECLARE @Line		NVARCHAR(10)

SELECT @TARType = TARType,
		@Line = Line,
		@EMToSend = Email,		-- >> ToSendEmail
		@EMCCSend = Email,
		@EMTARID = Id,
		@EMTARNo = TARNo,
		@EMRemarks = ARRemark,
		@EMCompany = Company,
		@TARDate = AccessDate, 
		@TrackType = TrackType
	FROM TAMS_TAR
		WHERE ID = @TARID

print '@Line'; 
print @Line;

SELECT @WFID = WorkflowId 
	FROM TAMS_TAR_Workflow
		WHERE ID = @TARWFID

-- >> Current Level Endorser
SELECT @EMActor = Title
	FROM TAMS_Endorser
		WHERE WorkflowId = @WFID
			AND [Level] = @ELevel

-- >> Next Level Endorser
SELECT @NextEndID = ID, 
		@NextEndTitle = Title,
		@NextWFID = WorkflowId,
		@NextWFStatID = WFStatusId,
		@NextRoleID = RoleId
	FROM TAMS_Endorser
		WHERE WorkflowId = @WFID
			AND [Level] = @ELevel + 1

IF ISNULL(@NextEndTitle, '') = ''
	BEGIN
		-- >> Last Level Approved TAR
		
		-- >> If NEL Approved = 9 Else DTL or LRT = 8
		UPDATE TAMS_TAR
			SET TARStatusId = CASE WHEN @Line = 'NEL' THEN 9 ELSE 8 END,
				UpdatedOn = GETDATE(),
				UpdatedBy = @UserID
			WHERE ID = @TARID

		IF @TARType = 'Urgent'
			BEGIN
				-- >> APPROVED EMAIL
				-- >> PRINT 'Urgent Email'
				SET @EMTARStatus = 'Approved'
				SET @EMMsg = ''

					print 'before sending email sp_TAMS_Email_Urgent_TAR';
					print @EMTARStatus; 
				EXEC sp_TAMS_Email_Urgent_TAR @EMTARID, @EMTARStatus, @EMTARNo, @EMRemarks, @EMActor, @EMToSend, @EMMsg OUTPUT
			END

	END
ELSE
	BEGIN
		IF (SELECT COUNT(*) FROM TAMS_TAR_Workflow
			WHERE TARId = @TARID
				AND WorkflowId = @NextWFID
				AND EndorserId = @NextEndID) = 0
			BEGIN	
				INSERT INTO [dbo].[TAMS_TAR_Workflow]
					([TARId], [WorkflowId], [EndorserId], [UserId], [WFStatus], [Remark], [ActionOn], [ActionBy])
				VALUES
					(@TARID, @NextWFID, @NextEndID, NULL, 'Pending', '', GETDATE(), @UserID)
			END

		UPDATE TAMS_TAR
			SET TARStatusId = @NextWFStatID,
				UpdatedOn = GETDATE(),
				UpdatedBy = @UserID
			WHERE Id = @TARID

		IF @TARType = 'Urgent'
			BEGIN
				-- >> NEXT ROLE ID EMAIL ALERT
				-- >> PRINT 'Urgent Email'
				DECLARE @RoleEmail	NVARCHAR(1000)
				SET @RoleEmail = ''
				SET @EMMsg = ''

				SELECT @RoleEmail = @RoleEmail + ISNULL(a.Email + ', ', '') 
					FROM TAMS_User a, TAMS_User_Role b
						WHERE a.Userid = b.UserID
							AND a.IsActive = 1
							AND @TARDate BETWEEN a.ValidFrom AND a.ValidTo
							-- >> AND b.RoleID = @NextEndID -- >> Orig, Wrongone
							AND b.RoleID = @NextRoleID

				IF LEN(LTRIM(RTRIM(@RoleEmail))) > 0
					BEGIN
						SET @RoleEmail = LEFT(LTRIM(RTRIM(@RoleEmail)), LEN(LTRIM(RTRIM(@RoleEmail))) - 1)
					END

				-- >> Select all email where role id = next role id
				SET @EMToSend = @RoleEmail

				-- >> 2024-01-31 Changes to add nelocc email to the recipient list for Urgent After and if next level is OCC Approval
				DECLARE @WFTypeChk	NVARCHAR(50)

				SELECT @WFTypeChk = WorkflowType
					FROM TAMS_Workflow
						WHERE ID = @WFID

				IF @WFTypeChk = 'UrgentAfter' AND @NextEndTitle = 'OCC Approval'
					BEGIN 
						declare @OCCEmailForUrgent as nvarchar(100);
						set @OCCEmailForUrgent = '';
						
						SELECT @OCCEmailForUrgent = ParaValue3 
							FROM TAMS_Parameters
								WHERE ParaCode = 'OCCContact'
									AND ParaValue1 = @Line
									AND LTRIM(RTRIM(ISNULL(ParaValue3, ''))) <> ''

						IF LEN(LTRIM(RTRIM(@EMToSend))) > 0
							BEGIN
								-- >> 2024-01-16 Changes to add nelocc email to the recipient list 
						 		SET @EMToSend = @EMToSend + ', ' + @OCCEmailForUrgent
							END
					END;
				ELSE IF @WFTypeChk = 'UrgentAfter' AND @NextEndTitle = 'SDS Approval'
					BEGIN 
						declare @SDSEmailForUrgent as nvarchar(100);
						set @SDSEmailForUrgent = '';
						
						SELECT @SDSEmailForUrgent = ParaValue3 
							FROM TAMS_Parameters
								WHERE ParaCode = 'SDSContact'
									AND ParaValue1 = @Line
									AND LTRIM(RTRIM(ISNULL(ParaValue3, ''))) <> ''

						IF LEN(LTRIM(RTRIM(@EMToSend))) > 0
							BEGIN
								-- >> 2024-01-16 Changes to add nelocc email to the recipient list 
						 		SET @EMToSend = @EMToSend + ', ' + @SDSEmailForUrgent
							END
					END;
				-- >> 2024-01-31 Changes to add nelocc email to the recipient list for Urgent After and if next level is OCC Approval

				print 'before sending email sp_TAMS_Email_Urgent_TAR 2';
					print @NextEndTitle; 
				EXEC sp_TAMS_Email_Apply_Urgent_TAR 2, @EMCompany, @EMTARNo, @NextEndTitle, @EMToSend, @EMCCSend, @EMMsg OUTPUT
			END
	END

-- >> Action Log
DECLARE @LogMsg	NVARCHAR(100)
-- >> SET @LogMsg = 'TAR Form has approved by : ' + '' + ' On ' + GETDATE()	
	SET @LogMsg = 'TAR Form Approved by : ' + CAST(@UserName AS NVARCHAR(500)) + ' On ' + CAST(CONVERT(NVARCHAR(20), GETDATE(), 103) AS NVARCHAR(20)) + ' ' + CAST(CONVERT(NVARCHAR(20), GETDATE(), 108) AS NVARCHAR(20))
		
INSERT INTO [dbo].[TAMS_Action_Log]
	([Line], [Module], [Function], [TransactionID], [LogMessage], [CreatedOn], [CreatedBy])
VALUES 
	(@Line, 'TAR', 'Approved TAR', @TARID, @LogMsg, GETDATE(), @UserID)

DECLARE @WFType	NVARCHAR(50)
DECLARE @InvPow	BIT

SELECT @WFType = WorkflowType,
		@InvPow = InvolvePower 
	FROM TAMS_Workflow
		WHERE ID = @WFID

IF @WFType = 'UrgentAfter' AND @InvPow = 1 AND @ELevel = 2
	BEGIN
		-- >> TAMS_DTL_PFR
		-- >> PRINT 'EMAIL'

		DECLARE @OCCEmail	NVARCHAR(1000)
		DECLARE @OCCRole	NVARCHAR(50)
		DECLARE @OCCEmailAdd	NVARCHAR(100)

		SET @OCCEmail = ''
		SET @OCCEmailAdd = ''
		SET @OCCRole = @Line + '_PFR'
		SET @EMTARStatus = 'Approved'
		SET @EMMsg = ''

		SELECT @OCCEmail = @OCCEmail + ISNULL(a.Email + ', ', '') 
			FROM TAMS_User a, TAMS_User_Role b, TAMS_Role c
				WHERE a.Userid = b.UserID
					AND b.RoleID = c.ID
					AND a.IsActive = 1
					AND @TARDate BETWEEN a.ValidFrom AND a.ValidTo
					AND c.Role = @OCCRole

		-- >> 2024-01-16 Changes to add nelocc email to the recipient list 
		if @TrackType = 'Mainline'
		Begin
			SELECT @OCCEmailAdd = ParaValue3 
			FROM TAMS_Parameters
				WHERE ParaCode = 'OCCContact'
					AND ParaValue1 = @Line
					AND LTRIM(RTRIM(ISNULL(ParaValue3, ''))) <> ''
		end;
		else  -- Depot 
		begin 
			SELECT @OCCEmailAdd = ParaValue3 
			FROM TAMS_Parameters
				WHERE ParaCode = 'SDSContact'
					AND ParaValue1 = @Line
					AND LTRIM(RTRIM(ISNULL(ParaValue3, ''))) <> ''
		end;
		

		IF LEN(LTRIM(RTRIM(@OCCEmail))) > 0
			BEGIN
				-- >> 2024-01-16 Changes to add nelocc email to the recipient list 
				SET @OCCEmail = LEFT(LTRIM(RTRIM(@OCCEmail)), LEN(LTRIM(RTRIM(@OCCEmail))) - 1)
				SET @OCCEmail = @OCCEmail + ', ' + @OCCEmailAdd
			END
		print 'before sending email to OCC';
		print @EMTARStatus; 
		EXEC sp_TAMS_Email_Urgent_TAR_OCC @TARID, @EMTARStatus, @EMTARNo, @Remarks, @OCCEmail, @EMMsg OUTPUT
	END

-- >>

IF @@ERROR <> 0 BEGIN
	SET @Message = 'ERROR INSERTING INTO TAMS_TAR'
	GOTO TRAP_ERROR
END

FORCE_EXIT_PROC:	
	IF @IntrnlTrans = 1 COMMIT TRAN
	RETURN @Message 

TRAP_ERROR:
	IF @IntrnlTrans = 1 ROLLBACK TRAN
	RETURN @Message

END
GO
/****** END PROCEDURE 31 ******/

/****** START PROCEDURE 32 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_Approval_Get_Add_BufferZone
CREATE PROCEDURE [dbo].[sp_TAMS_Approval_Get_Add_BufferZone]
	@TARID		BIGINT
AS

BEGIN

-- >> Buffer Zone -- Additional
-- >> Table[0]
SELECT a.Sector AS StrSector, a.ID AS SectorID
	FROM TAMS_Sector a, TAMS_TAR_Sector b
		WHERE a.ID = b.SectorId
			AND b.TARId = @TARID
			AND b.IsBuffer = 1
	ORDER BY a.ID

END
GO
/****** END PROCEDURE 32 ******/

/****** START PROCEDURE 33 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_Approval_Get_Add_TVFStation
CREATE PROCEDURE [dbo].[sp_TAMS_Approval_Get_Add_TVFStation]
	@TARID		BIGINT
AS

BEGIN

-- >> TVF Station

-- >> Table[0]
SELECT a.StationName AS StrStation, b.TVFDirection AS StrDirection, b.ID AS TVFID
	FROM TAMS_Station a, TAMS_TAR_TVF b
		WHERE a.ID = b.TVFStationId
			AND b.TARID = @TARID
	ORDER BY a.ID

-- >> 1
-- >> TVF Run Mode
SELECT TVFMode 
	FROM TAMS_TAR
		WHERE ID = @TARID


END
GO
/****** END PROCEDURE 33 ******/

/****** START PROCEDURE 34 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_Approval_OnLoad
CREATE PROCEDURE [dbo].[sp_TAMS_Approval_OnLoad]
	@TARID		BIGINT,
	@LogInUser	NVARCHAR(20)
AS

BEGIN

	DECLARE @Line			NVARCHAR(10)
	DECLARE @AccessDate		DATE
	DECLARE @TARType		NVARCHAR(50)
	DECLARE @AccessType		NVARCHAR(50)
	DECLARE @IsExclusive	BIT
	DECLARE @TrackType		NVARCHAR(50);

	SELECT @Line		= Line,
		@AccessDate		= AccessDate,
		@TARType		= TARType,
		@AccessType		= AccessType,
		@IsExclusive	= IsExclusive,
		@TrackType = TrackType
	FROM TAMS_TAR
		WHERE ID = @TARID

	-- >> Table[0]
	SELECT [Id], [Line], [TARNo], [TARType],
		[Company], [Designation], [Name], [OfficeNo], [MobileNo], [Email],
		[SubmitDate], 
		CONVERT(NVARCHAR(20), [AccessDate], 103) AS [AccessDate], 
		[AccessTimeFrom], 
		[AccessTimeTo], 
		[AccessLocation], [AccessType],
		[IsNeutralGap], [IsExclusive],
		[DescOfWork], [ARRemark], 
		[TARStatusId],
		[InvolvePower], [PowerOn], [Is13ASocket],
		[CrossOver], [TVFMode]
	FROM TAMS_TAR
		WHERE ID = @TARID

-- >> Sector

	DECLARE @SelSectorNotGap	NVARCHAR(1000)
	DECLARE @SelSectorGap		NVARCHAR(1000)
	DECLARE @EntryStation		NVARCHAR(1000)
	
	SET @SelSectorNotGap = ''
	SET @SelSectorGap = ''
	SET @EntryStation = ''

	-- EXEC sp_TAMS_Form_OnLoad 'NEL', '01/02/2021', 'Possession', '143;144;145;180;181;182'

	-- >> Selected Sector IsGap = 0
	SELECT @SelSectorNotGap = @SelSectorNotGap + ISNULL(b.Sector + ', ', '') 
		FROM TAMS_TAR_Sector a, TAMS_Sector b
			WHERE a.TARId = @TARID
				AND a.IsBuffer = 0
				AND a.SectorId = b.ID
				AND ISNULL(b.IsGap, 0) = 0
			GROUP BY b.Sector
			-- >> ORDER BY b.[Order]

	IF LEN(LTRIM(RTRIM(@SelSectorNotGap))) > 0
		BEGIN
			SET @SelSectorNotGap = LEFT(LTRIM(RTRIM(@SelSectorNotGap)), LEN(LTRIM(RTRIM(@SelSectorNotGap))) - 1)
		END

	-- >> Selected Sector IsGap = 1
	SELECT @SelSectorGap = @SelSectorGap + ISNULL(Sector + ', ', '') 
		FROM TAMS_TAR_Sector a, TAMS_Sector b
			WHERE a.TARId = @TARID
				AND a.IsBuffer = 0
				AND a.SectorId = b.ID
				AND ISNULL(b.IsGap, 0) = 1
			GROUP BY b.Sector
			-- >> ORDER BY b.[Order]

	IF LEN(LTRIM(RTRIM(@SelSectorGap))) > 0
		BEGIN
			SET @SelSectorGap = LEFT(LTRIM(RTRIM(@SelSectorGap)), LEN(LTRIM(RTRIM(@SelSectorGap))) - 1)
		END

	SELECT @EntryStation = @EntryStation + ISNULL(b.StationCode + ', ', '') 
		FROM TAMS_TAR_Station a, TAMS_Station b
			WHERE a.StationId = b.ID
				AND a.TARId = @TARID
				AND b.IsActive = 1
			GROUP BY b.StationCode
			-- >> ORDER BY b.[Order]
	
	IF LEN(LTRIM(RTRIM(@EntryStation))) > 0
		BEGIN
			SET @EntryStation = LEFT(LTRIM(RTRIM(@EntryStation)), LEN(LTRIM(RTRIM(@EntryStation))) - 1)
		END

	DECLARE @IsGap	NVARCHAR(5)

	SET @IsGap = CASE WHEN @SelSectorGap = '' THEN 'No' ELSE 'Yes' END

	-- >> Table[1]
	SELECT @SelSectorNotGap AS SelSectorNotGap,
		@SelSectorGap AS SelSectorGap,
		@EntryStation AS EntryStation,
		@IsGap AS IsGap


	-- >> Table[2]
	SELECT a.IsSelected, b.OperationRequirement, a.IsAttachment, a.ID AS ID, 
		(SELECT COUNT(*) FROM TAMS_TAR_Attachment c WHERE c.TARAccessReqId = a.ID) AS AttCtr 
	FROM [dbo].[TAMS_TAR_AccessReq] a, [dbo].[TAMS_Access_Requirement] b
		WHERE a.TARId = @TARID
			AND b.TrackType =   @TrackType
			AND a.IsSelected = 1
			AND a.IsPower = 0
			AND a.OperationRequirement = b.ID
			AND b.IsActive = 1
		ORDER BY a.[Order]

	-- >> Table[3]
	SELECT a.IsSelected, b.OperationRequirement, b.ID 
	FROM [dbo].[TAMS_TAR_AccessReq] a, [dbo].[TAMS_Access_Requirement] b
		WHERE a.TARId = @TARID
			AND b.TrackType = @TrackType
			AND a.IsSelected = 1
			AND a.IsPower = 1
			AND a.OperationRequirement = b.ID
			AND b.IsActive = 1
		ORDER BY a.[Order]

	DECLARE @PossID		INT
	DECLARE @PowerOnOff	INT
	DECLARE @TypeOfWork	INT

	SELECT @PossID = [ID],
		@PowerOnOff = [PowerOnOff],
		@TypeOfWork = [TypeOfWorkId]
	  FROM [dbo].[TAMS_Possession]
		WHERE TARId = @TARID

	-- >> Table[4]
	SELECT [ID], [TARId],
		[Summary], [WorkDesc], [TypeOfWorkId], 
		[WorkWithinPossession], [TakePossession], [GiveUpPossession],
		[Remarks], 
		[PowerOnOff],
		[EngTrainFormation],
		[EngTrainArriveLoc], [EngTrainArriveTime],
		[EngTrainDepartLoc], [EngTrainDepartTime],
		[PCName]
	  FROM [dbo].[TAMS_Possession]
		WHERE TARId = @TARID

	-- >> Table[5]
	SELECT ID, TypeOfProtectionLimit, RedFlashingLampsLoc 
		FROM [dbo].[TAMS_Possession_Limit]
			WHERE PossessionId = @PossID
				ORDER BY ID

	-- >> Table[6]
	SELECT ID, RedFlashingLampsLoc 
		FROM [dbo].[TAMS_Possession_WorkingLimit]
			WHERE PossessionId = @PossID
				ORDER BY ID

	-- >> Table[7]
	SELECT ID, OtherProtection 
		FROM [dbo].[TAMS_Possession_OtherProtection]
			WHERE PossessionId = @PossID
				ORDER BY ID

	-- >> Table[8]
	SELECT ID, PowerSector, @PowerOnOff AS PowerOnOff, NoOFSCD, 
			CASE WHEN BreakerOut = 1 THEN 'Y' ELSE 'N' END AS BreakerOut
		FROM [dbo].[TAMS_Possession_PowerSector]
			WHERE PossessionId = @PossID
				ORDER BY ID
			
			PRINT @TypeOfWork
			PRINT @TrackType
	-- >> Table[9]
	SELECT TypeOfWork 
		FROM TAMS_Type_Of_Work
			WHERE ID = @TypeOfWork
			and TrackType =   @TrackType
				AND IsActive = 1

	-- >> For Approval and Showing of Level

	DECLARE @MaxWFCtr		INT
	DECLARE @PendingWFCtr	INT
	DECLARE @ApprovedWFCtr	INT

	-- >> Get Max Workflow
	SELECT @MaxWFCtr = MAX(b.Level)
		FROM TAMS_TAR_Workflow a, TAMS_Endorser b
			WHERE a.WorkflowId = b.WorkflowId
				--AND a.EndorserId = b.ID
				AND a.TARId = @TARID

	SELECT @ApprovedWFCtr = COUNT(*)
		FROM TAMS_TAR_Workflow a, TAMS_Endorser b
			WHERE a.WorkflowId = b.WorkflowId
				AND a.EndorserId = b.ID
				AND a.TARId = @TARID
				AND a.WFStatus = 'Approved'

	SELECT @PendingWFCtr = COUNT(*)
		FROM TAMS_TAR_Workflow a, TAMS_Endorser b
			WHERE a.WorkflowId = b.WorkflowId
				AND a.EndorserId = b.ID
				AND a.TARId = @TARID
				AND a.WFStatus = 'Pending'

	-- >> Table[10]
	SELECT @MaxWFCtr AS MaxWFCtr, @ApprovedWFCtr AS AppWFCtr, @PendingWFCtr AS PendWFCtr

	-- >> Table[11]
	-- >> Workflow -- Approved
	SELECT a.TARId, a.UserId, a.WFStatus, a.Remark, a.ActionOn, a.ActionBy, c.[Name] AS ActionByName,
			b.RoleId, b.Title, b.RequireValidation, b.RequireTVF, b.WFStatusId, a.ID AS WFID, b.ID AS EID, b.Level
		FROM TAMS_TAR_Workflow a, TAMS_Endorser b, TAMS_User c
			WHERE a.WorkflowId = b.WorkflowId
				AND a.EndorserId = b.ID
				AND a.ActionBy = c.Userid
				AND a.TARId = @TARID
				AND a.WFStatus <> 'Pending'
			ORDER BY a.ID

	DECLARE @UserName	NVARCHAR(200)

	SELECT @UserName = [Name] FROM TAMS_User
		WHERE LoginId = @LogInUser

	-- >> Table[12]
	-- >> Workflow -- Pending
	SELECT a.TARId, a.UserId, a.WFStatus, a.Remark, a.ActionOn, a.ActionBy, c.[Name] AS ActionByName,
			b.RoleId, b.Title, b.RequireValidation, b.RequireTVF, b.RequireBuffer, b.WFStatusId, a.ID AS WFID, b.ID AS EID, b.Level, @UserName AS UserName
		FROM TAMS_TAR_Workflow a, TAMS_Endorser b, TAMS_User c
			WHERE a.WorkflowId = b.WorkflowId
				AND a.EndorserId = b.ID
				AND a.ActionBy = c.Userid
				AND a.TARId = @TARID
				AND a.WFStatus = 'Pending'
			ORDER BY a.ID

	--EXEC sp_TAMS_Approval_OnLoad 5, 'CSAPEX57'
	--EXEC sp_TAMS_Approval_OnLoad 4, 'CSAPEX57'
	
	-- >> Buffer Zone -- Additional
	-- >> Table[13]
	SELECT sect.Sector,
			sect.ID 
		FROM TAMS_Sector sect
			WHERE sect.ID NOT IN (SELECT SectorId 
					FROM TAMS_TAR_Sector ts LEFT JOIN TAMS_TAR t ON t.Id = ts.TARId
						WHERE (t.Id = @TarID OR
							(
							  ((t.TARStatusId = 8 and  t.Line = 'DTL') or (t.TARStatusId = 9 and  t.Line = 'NEL'))
							--t.TARStatusId = 8 
								AND t.AccessDate = @AccessDate
								AND t.Line = @Line)))
				AND sect.Line = @Line
				AND sect.TrackType = @TrackType
				AND sect.IsActive = 1
				AND @AccessDate BETWEEN sect.EffectiveDate AND sect.ExpiryDate
			ORDER BY sect.ID

	-- >> Buffer Zone -- Additional
	-- >> Table[14]
	SELECT a.Sector AS StrSector, a.ID AS SectorID
		FROM TAMS_Sector a, TAMS_TAR_Sector b
			WHERE a.ID = b.SectorId
				AND b.TARId = @TARID
				AND b.IsBuffer = 1
		ORDER BY a.ID

	-- >> TVF Station -- Additional
	-- >> Table[15]
	SELECT StationName AS StrStation, ID AS StationID
		FROM TAMS_Station
			WHERE Line = @Line
				AND IsStation = 1
				AND IsActive = 1
			ORDER BY [Order]

	-- >> Table[16]
	SELECT a.StationName AS StrStation, b.TVFDirection AS StrDirection, b.ID AS TVFID
		FROM TAMS_Station a, TAMS_TAR_TVF b
			WHERE a.ID = b.TVFStationId
				AND b.TARID = @TARID
		ORDER BY a.ID

	-- >> Get Exception TARs - Sector Conflict
	CREATE TABLE #TmpExc 
	(TARID			BIGINT,
	TARNo			NVARCHAR(20),
	TARType			NVARCHAR(10),
	AccessDate		NVARCHAR(20),
	AccessType		NVARCHAR(20),
	IsExclusive		INT)

	CREATE TABLE #TmpExcSector 
	(TARID			BIGINT,
	TARNo			NVARCHAR(20),
	TARType			NVARCHAR(10),
	AccessDate		NVARCHAR(20),
	AccessType		NVARCHAR(20),
	IsExclusive		INT,
	SectorID		INT,
	SectorStr		NVARCHAR(50),
	IsBuffer		INT)
	
	TRUNCATE TABLE #TmpExc
	TRUNCATE TABLE #TmpExcSector

	DECLARE @Cur01 CURSOR;

	DECLARE @CID			INTEGER
	DECLARE @CSectorID		INTEGER
	DECLARE @CIsBuffer		BIT
	DECLARE @CColourCode	NVARCHAR(20)
	DECLARE @CIsAddBuffer	BIT

	DECLARE @Cur02 CURSOR;

	DECLARE @C2TARID		INTEGER 
	DECLARE @C2TARNo		NVARCHAR(20) 
	DECLARE @C2TARType		NVARCHAR(20)
	DECLARE @C2AccessDate	DATE
	DECLARE @C2AccessType	NVARCHAR(20) 
	DECLARE @C2IsExclusive	BIT
	DECLARE @C2SectorID		INTEGER 
	DECLARE @C2SectorStr	NVARCHAR(20) 
	DECLARE @C2IsBuffer		BIT 

	SET @Cur01 = CURSOR FAST_FORWARD 
	FOR
		SELECT ID, SectorId, IsBuffer, ColourCode, IsAddedBuffer FROM TAMS_TAR_Sector
			WHERE TARId = @TARID
				ORDER BY SectorId

	OPEN @Cur01
	
	FETCH NEXT FROM @Cur01 INTO @CID, @CSectorID, @CIsBuffer, @CColourCode, @CIsAddBuffer
	
	WHILE @@FETCH_STATUS = 0 
	
		BEGIN

			IF @CIsBuffer = 1
				BEGIN
					-- >> Is Buffer
					-- PRINT 1
					INSERT INTO #TmpExcSector
						(TARID, TARNo, TARType, AccessDate, AccessType, IsExclusive, SectorID, SectorStr, IsBuffer)
					SELECT t.Id, t.TARNo, t.TARType, t.AccessDate, t.AccessType, t.IsExclusive,
							ts.SectorId, s.Sector, ts.IsBuffer 
						FROM TAMS_TAR t, TAMS_TAR_Sector ts, TAMS_Sector s
							WHERE t.Id = ts.TARId
								AND s.ID = ts.SectorId
								AND t.AccessDate = @AccessDate
								AND ts.IsBuffer = 0
								AND ((t.TARStatusId = 8 and  t.Line = 'DTL') or (t.TARStatusId = 9 and  t.Line = 'NEL'))
								--AND t.TARStatusId = 8
								AND ts.SectorId = @CSectorID
								AND t.Id <> @TARID
								AND s.IsActive = 1
								AND @AccessDate BETWEEN s.EffectiveDate and S.ExpiryDate
				END
			ELSE
				BEGIN
					-- >> Not Buffer
					-- PRINT 2
					INSERT INTO #TmpExcSector
						(TARID, TARNo, TARType, AccessDate, AccessType, IsExclusive, SectorID, SectorStr, IsBuffer)
					SELECT t.Id, t.TARNo, t.TARType, t.AccessDate, t.AccessType, t.IsExclusive,
							ts.SectorId, s.Sector, ts.IsBuffer 
						FROM TAMS_TAR t, TAMS_TAR_Sector ts, TAMS_Sector s
							WHERE t.Id = ts.TARId
								AND s.ID = ts.SectorId
								AND t.AccessDate = @AccessDate
								-- >> AND ts.IsBuffer = 0
								AND ((t.TARStatusId = 8 and  t.Line = 'DTL') or (t.TARStatusId = 9 and  t.Line = 'NEL'))
								--AND t.TARStatusId = 8
								AND ts.SectorId = @CSectorID
								AND t.Id <> @TARID
								AND s.IsActive = 1
								AND @AccessDate BETWEEN s.EffectiveDate and S.ExpiryDate
				END
				
			-- >> #TmpExcSector
			SET @Cur02 = CURSOR FAST_FORWARD 
			FOR
				SELECT TARID, TARNo, TARType, AccessDate, AccessType, IsExclusive, SectorID, SectorStr, IsBuffer 
					FROM #TmpExcSector
							ORDER BY TARID, SectorID

			OPEN @Cur02
	
			FETCH NEXT FROM @Cur02 INTO @C2TARID, @C2TARNo, @C2TARType, @C2AccessDate, @C2AccessType, @C2IsExclusive, @C2SectorID, @C2SectorStr,@C2IsBuffer
	
			WHILE @@FETCH_STATUS = 0 
	
				BEGIN
					IF @AccessType = 'Protection' AND @IsExclusive = 0
						BEGIN
							print 1
							IF @C2AccessType = 'Protection' AND @C2IsExclusive = 0
								BEGIN
									PRINT 'DO NOTHING'
								END
							ELSE
								BEGIN
									IF (SELECT COUNT(*) FROM #TmpExc WHERE TARID = @C2TARID) = 0
										BEGIN
											INSERT INTO #TmpExc
												(TARID, TARNo, TARType, AccessDate, AccessType, IsExclusive)
											VALUES 
												(@C2TARID, @C2TARNo, @C2TARType, @C2AccessDate, @C2AccessType, @C2IsExclusive)
										END
								END
						END
					ELSE
						BEGIN
							IF (SELECT COUNT(*) FROM #TmpExc WHERE TARID = @C2TARID) = 0
								BEGIN
									INSERT INTO #TmpExc
										(TARID, TARNo, TARType, AccessDate, AccessType, IsExclusive)
									VALUES 
										(@C2TARID, @C2TARNo, @C2TARType, @C2AccessDate, @C2AccessType, @C2IsExclusive)
								END
						END

					FETCH NEXT FROM @Cur02 INTO @C2TARID, @C2TARNo, @C2TARType, @C2AccessDate, @C2AccessType, @C2IsExclusive, @C2SectorID, @C2SectorStr,@C2IsBuffer
				END 	

			CLOSE @Cur02
	
			DEALLOCATE @Cur02
			-- >> #TmpExcSector

			FETCH NEXT FROM @Cur01 INTO @CID, @CSectorID, @CIsBuffer, @CColourCode, @CIsAddBuffer
		END 	

	CLOSE @Cur01
	
	DEALLOCATE @Cur01

	-- >> Exception List. Sector Conflict, to show only if RequireValidation = True for current Level Endorser
	-- >> Table[17]
	SELECT TARID, TARNo, TARType, AccessDate, AccessType, IsExclusive 
		FROM #TmpExc

	-- >> Table[18]
	IF @AccessType = 'Protection'
		BEGIN
			SELECT ID, OperationRequirement 
				FROM TAMS_Access_Requirement
					WHERE Line = @Line
						AND TrackType = @TrackType
						AND IsPowerReq = 1
						AND OperationRequirement <> 'Traction Power ON'
						AND IsActive = 1
					ORDER BY [Order]
		END
	ELSE
		BEGIN
			SELECT ID, OperationRequirement 
				FROM TAMS_Access_Requirement
					WHERE Line = @Line
						AND TrackType = @TrackType
						AND IsPowerReq = 1
						AND IsActive = 1
					ORDER BY [Order]
		END
END
GO
/****** END PROCEDURE 34 ******/

/****** START PROCEDURE 35 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_Approval_OnLoad_bak20230531
CREATE PROCEDURE [dbo].[sp_TAMS_Approval_OnLoad_bak20230531]
	@TARID		BIGINT,
	@LogInUser	NVARCHAR(20)
AS

BEGIN

	DECLARE @Line			NVARCHAR(10)
	DECLARE @AccessDate		DATE
	DECLARE @TARType		NVARCHAR(50)
	DECLARE @AccessType		NVARCHAR(50)
	DECLARE @IsExclusive	BIT

	SELECT @Line		= Line,
		@AccessDate		= AccessDate,
		@TARType		= TARType,
		@AccessType		= AccessType,
		@IsExclusive	= IsExclusive
	FROM TAMS_TAR
		WHERE ID = @TARID

	-- >> Table[0]
	SELECT [Id], [Line], [TARNo], [TARType],
		[Company], [Designation], [Name], [OfficeNo], [MobileNo], [Email],
		[SubmitDate], 
		CONVERT(NVARCHAR(20), [AccessDate], 103) AS [AccessDate], 
		[AccessTimeFrom], 
		[AccessTimeTo], 
		[AccessLocation], [AccessType],
		[IsNeutralGap], [IsExclusive],
		[DescOfWork], [ARRemark], 
		[TARStatusId],
		[InvolvePower], [PowerOn], [Is13ASocket],
		[CrossOver], [TVFMode]
	FROM TAMS_TAR
		WHERE ID = @TARID

-- >> Sector

	DECLARE @SelSectorNotGap	NVARCHAR(1000)
	DECLARE @SelSectorGap		NVARCHAR(1000)
	DECLARE @EntryStation		NVARCHAR(1000)
	
	SET @SelSectorNotGap = ''
	SET @SelSectorGap = ''
	SET @EntryStation = ''

	-- EXEC sp_TAMS_Form_OnLoad 'NEL', '01/02/2021', 'Possession', '143;144;145;180;181;182'

	-- >> Selected Sector IsGap = 0
	SELECT @SelSectorNotGap = @SelSectorNotGap + ISNULL(b.Sector + ', ', '') 
		FROM TAMS_TAR_Sector a, TAMS_Sector b
			WHERE a.TARId = @TARID
				AND a.IsBuffer = 0
				AND a.SectorId = b.ID
				AND ISNULL(b.IsGap, 0) = 0
			GROUP BY b.Sector
			-- >> ORDER BY b.[Order]

	IF LEN(LTRIM(RTRIM(@SelSectorNotGap))) > 0
		BEGIN
			SET @SelSectorNotGap = LEFT(LTRIM(RTRIM(@SelSectorNotGap)), LEN(LTRIM(RTRIM(@SelSectorNotGap))) - 1)
		END

	-- >> Selected Sector IsGap = 1
	SELECT @SelSectorGap = @SelSectorGap + ISNULL(Sector + ', ', '') 
		FROM TAMS_TAR_Sector a, TAMS_Sector b
			WHERE a.TARId = @TARID
				AND a.IsBuffer = 0
				AND a.SectorId = b.ID
				AND ISNULL(b.IsGap, 0) = 1
			GROUP BY b.Sector
			-- >> ORDER BY b.[Order]

	IF LEN(LTRIM(RTRIM(@SelSectorGap))) > 0
		BEGIN
			SET @SelSectorGap = LEFT(LTRIM(RTRIM(@SelSectorGap)), LEN(LTRIM(RTRIM(@SelSectorGap))) - 1)
		END

	SELECT @EntryStation = @EntryStation + ISNULL(b.StationCode + ', ', '') 
		FROM TAMS_TAR_Station a, TAMS_Station b
			WHERE a.StationId = b.ID
				AND a.TARId = @TARID
				AND b.IsActive = 1
			GROUP BY b.StationCode
			-- >> ORDER BY b.[Order]
	
	IF LEN(LTRIM(RTRIM(@EntryStation))) > 0
		BEGIN
			SET @EntryStation = LEFT(LTRIM(RTRIM(@EntryStation)), LEN(LTRIM(RTRIM(@EntryStation))) - 1)
		END

	DECLARE @IsGap	NVARCHAR(5)

	SET @IsGap = CASE WHEN @SelSectorGap = '' THEN 'No' ELSE 'Yes' END

	-- >> Table[1]
	SELECT @SelSectorNotGap AS SelSectorNotGap,
		@SelSectorGap AS SelSectorGap,
		@EntryStation AS EntryStation,
		@IsGap AS IsGap


	-- >> Table[2]
	SELECT a.IsSelected, b.OperationRequirement, a.IsAttachment, a.ID AS ID, 
		(SELECT COUNT(*) FROM TAMS_TAR_Attachment c WHERE c.TARAccessReqId = a.ID) AS AttCtr 
	FROM [dbo].[TAMS_TAR_AccessReq] a, [dbo].[TAMS_Access_Requirement] b
		WHERE a.TARId = @TARID
			AND a.IsSelected = 1
			AND a.IsPower = 0
			AND a.OperationRequirement = b.ID
			AND b.IsActive = 1
		ORDER BY a.[Order]

	-- >> Table[3]
	SELECT a.IsSelected, b.OperationRequirement, b.ID 
	FROM [dbo].[TAMS_TAR_AccessReq] a, [dbo].[TAMS_Access_Requirement] b
		WHERE a.TARId = @TARID
			AND a.IsSelected = 1
			AND a.IsPower = 1
			AND a.OperationRequirement = b.ID
			AND b.IsActive = 1
		ORDER BY a.[Order]

	DECLARE @PossID		INT
	DECLARE @PowerOnOff	INT
	DECLARE @TypeOfWork	INT

	SELECT @PossID = [ID],
		@PowerOnOff = [PowerOnOff],
		@TypeOfWork = [TypeOfWorkId]
	  FROM [dbo].[TAMS_Possession]
		WHERE TARId = @TARID

	-- >> Table[4]
	SELECT [ID], [TARId],
		[Summary], [WorkDesc], [TypeOfWorkId], 
		[WorkWithinPossession], [TakePossession], [GiveUpPossession],
		[Remarks], 
		[PowerOnOff],
		[EngTrainFormation],
		[EngTrainArriveLoc], [EngTrainArriveTime],
		[EngTrainDepartLoc], [EngTrainDepartTime],
		[PCName]
	  FROM [dbo].[TAMS_Possession]
		WHERE TARId = @TARID

	-- >> Table[5]
	SELECT ID, TypeOfProtectionLimit, RedFlashingLampsLoc 
		FROM [dbo].[TAMS_Possession_Limit]
			WHERE PossessionId = @PossID
				ORDER BY ID

	-- >> Table[6]
	SELECT ID, RedFlashingLampsLoc 
		FROM [dbo].[TAMS_Possession_WorkingLimit]
			WHERE PossessionId = @PossID
				ORDER BY ID

	-- >> Table[7]
	SELECT ID, OtherProtection 
		FROM [dbo].[TAMS_Possession_OtherProtection]
			WHERE PossessionId = @PossID
				ORDER BY ID

	-- >> Table[8]
	SELECT ID, PowerSector, @PowerOnOff AS PowerOnOff, NoOFSCD, 
			CASE WHEN BreakerOut = 1 THEN 'Y' ELSE 'N' END AS BreakerOut
		FROM [dbo].[TAMS_Possession_PowerSector]
			WHERE PossessionId = @PossID
				ORDER BY ID
			
	-- >> Table[9]
	SELECT TypeOfWork 
		FROM TAMS_Type_Of_Work
			WHERE ID = @TypeOfWork
				AND IsActive = 1

	-- >> For Approval and Showing of Level

	DECLARE @MaxWFCtr		INT
	DECLARE @PendingWFCtr	INT
	DECLARE @ApprovedWFCtr	INT

	-- >> Get Max Workflow
	SELECT @MaxWFCtr = MAX(b.Level)
		FROM TAMS_TAR_Workflow a, TAMS_Endorser b
			WHERE a.WorkflowId = b.WorkflowId
				--AND a.EndorserId = b.ID
				AND a.TARId = @TARID

	SELECT @ApprovedWFCtr = COUNT(*)
		FROM TAMS_TAR_Workflow a, TAMS_Endorser b
			WHERE a.WorkflowId = b.WorkflowId
				AND a.EndorserId = b.ID
				AND a.TARId = @TARID
				AND a.WFStatus = 'Approved'

	SELECT @PendingWFCtr = COUNT(*)
		FROM TAMS_TAR_Workflow a, TAMS_Endorser b
			WHERE a.WorkflowId = b.WorkflowId
				AND a.EndorserId = b.ID
				AND a.TARId = @TARID
				AND a.WFStatus = 'Pending'

	-- >> Table[10]
	SELECT @MaxWFCtr AS MaxWFCtr, @ApprovedWFCtr AS AppWFCtr, @PendingWFCtr AS PendWFCtr

	-- >> Table[11]
	-- >> Workflow -- Approved
	SELECT a.TARId, a.UserId, a.WFStatus, a.Remark, a.ActionOn, a.ActionBy, c.[Name] AS ActionByName,
			b.RoleId, b.Title, b.RequireValidation, b.RequireTVF, b.WFStatusId, a.ID AS WFID, b.ID AS EID, b.Level
		FROM TAMS_TAR_Workflow a, TAMS_Endorser b, TAMS_User c
			WHERE a.WorkflowId = b.WorkflowId
				AND a.EndorserId = b.ID
				AND a.ActionBy = c.Userid
				AND a.TARId = @TARID
				AND a.WFStatus <> 'Pending'
			ORDER BY a.ID

	DECLARE @UserName	NVARCHAR(200)

	SELECT @UserName = [Name] FROM TAMS_User
		WHERE LoginId = @LogInUser

	-- >> Table[12]
	-- >> Workflow -- Pending
	SELECT a.TARId, a.UserId, a.WFStatus, a.Remark, a.ActionOn, a.ActionBy, c.[Name] AS ActionByName,
			b.RoleId, b.Title, b.RequireValidation, b.RequireTVF, b.RequireBuffer, b.WFStatusId, a.ID AS WFID, b.ID AS EID, b.Level, @UserName AS UserName
		FROM TAMS_TAR_Workflow a, TAMS_Endorser b, TAMS_User c
			WHERE a.WorkflowId = b.WorkflowId
				AND a.EndorserId = b.ID
				AND a.ActionBy = c.Userid
				AND a.TARId = @TARID
				AND a.WFStatus = 'Pending'
			ORDER BY a.ID

	--EXEC sp_TAMS_Approval_OnLoad 5, 'CSAPEX57'
	--EXEC sp_TAMS_Approval_OnLoad 4, 'CSAPEX57'
	
	-- >> Buffer Zone -- Additional
	-- >> Table[13]
	SELECT sect.Sector,
			sect.ID 
		FROM TAMS_Sector sect
			WHERE sect.ID NOT IN (SELECT SectorId 
					FROM TAMS_TAR_Sector ts LEFT JOIN TAMS_TAR t ON t.Id = ts.TARId
						WHERE (t.Id = @TarID OR
							(t.TARStatusId = 8 
								AND t.AccessDate = @AccessDate
								AND t.Line = @Line)))
				AND sect.Line = @Line
				AND sect.IsActive = 1
				AND @AccessDate BETWEEN sect.EffectiveDate AND sect.ExpiryDate
			ORDER BY sect.ID

	-- >> Buffer Zone -- Additional
	-- >> Table[14]
	SELECT a.Sector AS StrSector, a.ID AS SectorID
		FROM TAMS_Sector a, TAMS_TAR_Sector b
			WHERE a.ID = b.SectorId
				AND b.TARId = @TARID
				AND b.IsBuffer = 1
		ORDER BY a.ID

	-- >> TVF Station -- Additional
	-- >> Table[15]
	SELECT StationName AS StrStation, ID AS StationID
		FROM TAMS_Station
			WHERE Line = @Line
				AND IsStation = 1
				AND IsActive = 1
			ORDER BY [Order]

	-- >> Table[16]
	SELECT a.StationName AS StrStation, b.TVFDirection AS StrDirection, b.ID AS TVFID
		FROM TAMS_Station a, TAMS_TAR_TVF b
			WHERE a.ID = b.TVFStationId
				AND b.TARID = @TARID
		ORDER BY a.ID

	-- >> Get Exception TARs - Sector Conflict
	CREATE TABLE #TmpExc 
	(TARID			BIGINT,
	TARNo			NVARCHAR(20),
	TARType			NVARCHAR(10),
	AccessDate		NVARCHAR(20),
	AccessType		NVARCHAR(20),
	IsExclusive		INT)

	CREATE TABLE #TmpExcSector 
	(TARID			BIGINT,
	TARNo			NVARCHAR(20),
	TARType			NVARCHAR(10),
	AccessDate		NVARCHAR(20),
	AccessType		NVARCHAR(20),
	IsExclusive		INT,
	SectorID		INT,
	SectorStr		NVARCHAR(50),
	IsBuffer		INT)
	
	TRUNCATE TABLE #TmpExc
	TRUNCATE TABLE #TmpExcSector

	DECLARE @Cur01 CURSOR;

	DECLARE @CID			INTEGER
	DECLARE @CSectorID		INTEGER
	DECLARE @CIsBuffer		BIT
	DECLARE @CColourCode	NVARCHAR(20)
	DECLARE @CIsAddBuffer	BIT

	DECLARE @Cur02 CURSOR;

	DECLARE @C2TARID		INTEGER 
	DECLARE @C2TARNo		NVARCHAR(20) 
	DECLARE @C2TARType		NVARCHAR(20)
	DECLARE @C2AccessDate	DATE
	DECLARE @C2AccessType	NVARCHAR(20) 
	DECLARE @C2IsExclusive	BIT
	DECLARE @C2SectorID		INTEGER 
	DECLARE @C2SectorStr	NVARCHAR(20) 
	DECLARE @C2IsBuffer		BIT 

	SET @Cur01 = CURSOR FAST_FORWARD 
	FOR
		SELECT ID, SectorId, IsBuffer, ColourCode, IsAddedBuffer FROM TAMS_TAR_Sector
			WHERE TARId = @TARID
				ORDER BY SectorId

	OPEN @Cur01
	
	FETCH NEXT FROM @Cur01 INTO @CID, @CSectorID, @CIsBuffer, @CColourCode, @CIsAddBuffer
	
	WHILE @@FETCH_STATUS = 0 
	
		BEGIN

			IF @CIsBuffer = 1
				BEGIN
					-- >> Is Buffer
					-- PRINT 1
					INSERT INTO #TmpExcSector
						(TARID, TARNo, TARType, AccessDate, AccessType, IsExclusive, SectorID, SectorStr, IsBuffer)
					SELECT t.Id, t.TARNo, t.TARType, t.AccessDate, t.AccessType, t.IsExclusive,
							ts.SectorId, s.Sector, ts.IsBuffer 
						FROM TAMS_TAR t, TAMS_TAR_Sector ts, TAMS_Sector s
							WHERE t.Id = ts.TARId
								AND s.ID = ts.SectorId
								AND t.AccessDate = @AccessDate
								AND ts.IsBuffer = 0
								AND t.TARStatusId = 8
								AND ts.SectorId = @CSectorID
								AND t.Id <> @TARID
								AND s.IsActive = 1
								AND @AccessDate BETWEEN s.EffectiveDate and S.ExpiryDate
				END
			ELSE
				BEGIN
					-- >> Not Buffer
					-- PRINT 2
					INSERT INTO #TmpExcSector
						(TARID, TARNo, TARType, AccessDate, AccessType, IsExclusive, SectorID, SectorStr, IsBuffer)
					SELECT t.Id, t.TARNo, t.TARType, t.AccessDate, t.AccessType, t.IsExclusive,
							ts.SectorId, s.Sector, ts.IsBuffer 
						FROM TAMS_TAR t, TAMS_TAR_Sector ts, TAMS_Sector s
							WHERE t.Id = ts.TARId
								AND s.ID = ts.SectorId
								AND t.AccessDate = @AccessDate
								-- >> AND ts.IsBuffer = 0
								AND t.TARStatusId = 8
								AND ts.SectorId = @CSectorID
								AND t.Id <> @TARID
								AND s.IsActive = 1
								AND @AccessDate BETWEEN s.EffectiveDate and S.ExpiryDate
				END
				
			-- >> #TmpExcSector
			SET @Cur02 = CURSOR FAST_FORWARD 
			FOR
				SELECT TARID, TARNo, TARType, AccessDate, AccessType, IsExclusive, SectorID, SectorStr, IsBuffer 
					FROM #TmpExcSector
							ORDER BY TARID, SectorID

			OPEN @Cur02
	
			FETCH NEXT FROM @Cur02 INTO @C2TARID, @C2TARNo, @C2TARType, @C2AccessDate, @C2AccessType, @C2IsExclusive, @C2SectorID, @C2SectorStr,@C2IsBuffer
	
			WHILE @@FETCH_STATUS = 0 
	
				BEGIN
					IF @AccessType = 'Protection' AND @IsExclusive = 0
						BEGIN
							print 1
							IF @C2AccessType = 'Protection' AND @C2IsExclusive = 0
								BEGIN
									PRINT 'DO NOTHING'
								END
							ELSE
								BEGIN
									IF (SELECT COUNT(*) FROM #TmpExc WHERE TARID = @C2TARID) = 0
										BEGIN
											INSERT INTO #TmpExc
												(TARID, TARNo, TARType, AccessDate, AccessType, IsExclusive)
											VALUES 
												(@C2TARID, @C2TARNo, @C2TARType, @C2AccessDate, @C2AccessType, @C2IsExclusive)
										END
								END
						END
					ELSE
						BEGIN
							IF (SELECT COUNT(*) FROM #TmpExc WHERE TARID = @C2TARID) = 0
								BEGIN
									INSERT INTO #TmpExc
										(TARID, TARNo, TARType, AccessDate, AccessType, IsExclusive)
									VALUES 
										(@C2TARID, @C2TARNo, @C2TARType, @C2AccessDate, @C2AccessType, @C2IsExclusive)
								END
						END

					FETCH NEXT FROM @Cur02 INTO @C2TARID, @C2TARNo, @C2TARType, @C2AccessDate, @C2AccessType, @C2IsExclusive, @C2SectorID, @C2SectorStr,@C2IsBuffer
				END 	

			CLOSE @Cur02
	
			DEALLOCATE @Cur02
			-- >> #TmpExcSector

			FETCH NEXT FROM @Cur01 INTO @CID, @CSectorID, @CIsBuffer, @CColourCode, @CIsAddBuffer
		END 	

	CLOSE @Cur01
	
	DEALLOCATE @Cur01

	-- >> Exception List. Sector Conflict, to show only if RequireValidation = True for current Level Endorser
	-- >> Table[17]
	SELECT TARID, TARNo, TARType, AccessDate, AccessType, IsExclusive 
		FROM #TmpExc

	-- >> Table[18]
	IF @AccessType = 'Protection'
		BEGIN
			SELECT ID, OperationRequirement 
				FROM TAMS_Access_Requirement
					WHERE Line = @Line
						AND IsPowerReq = 1
						AND OperationRequirement <> 'Traction Power ON'
						AND IsActive = 1
					ORDER BY [Order]
		END
	ELSE
		BEGIN
			SELECT ID, OperationRequirement 
				FROM TAMS_Access_Requirement
					WHERE Line = @Line
						AND IsPowerReq = 1
						AND IsActive = 1
					ORDER BY [Order]
		END
END
GO
/****** END PROCEDURE 35 ******/

/****** START PROCEDURE 36 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_Approval_Proceed_To_App
CREATE   procedure  [dbo].[sp_TAMS_Approval_Proceed_To_App]
	@TARID		AS INTEGER,						-- >> TAR ID
	@TARWFID	AS INTEGER,						-- >> Current WF ID
	@EID		AS INTEGER,						-- >> Current Endorser ID
	@ELevel		AS INTEGER,						-- >> Current Endorser Level
	@Remarks	AS NVARCHAR(1000) = NULL,		-- >> Remarks -- Mandatory for Reject / Optional for Approved / Endorse
	@TVFRunMode			AS NVARCHAR(50) = NULL,	-- >> New Column to be confirmed with Adeline
	@TVFRunModeUpdInd	AS NVARCHAR(5) = NULL,	-- >> Indicator to Update TVF Run Mode or Not.
	@UserLI		AS NVARCHAR(100) = NULL,			-- >> User Login ID	
	@Message	AS NVARCHAR(500) = NULL OUTPUT
AS

BEGIN

DECLARE	@IntrnlTrans	TINYINT
SELECT 	@IntrnlTrans 	= 0	

IF (@@TRANCOUNT = 0) 
BEGIN
	SET @IntrnlTrans = 1
	BEGIN TRAN
END

-- >>
SET @Message = ''
DECLARE @UserID		INTEGER
DECLARE @UserName NVARCHAR(500)

DECLARE @EMTARID		INTEGER
DECLARE @EMTARStatus	NVARCHAR(20)
DECLARE @EMTARNo		NVARCHAR(50)
DECLARE @EMRemarks		NVARCHAR(1000)
DECLARE @EMActor		NVARCHAR(100)
DECLARE @EMToSend		NVARCHAR(1000)
DECLARE @EMCCSend		NVARCHAR(1000)
DECLARE @EMCompany		NVARCHAR(100)
DECLARE @EMMsg			NVARCHAR(500)

DECLARE @TARDate		DATE

SELECT @UserID = Userid, @UserName = [Name]
FROM TAMS_User
	WHERE LoginId = @UserLI

DECLARE @CurEndID		INTEGER
DECLARE @CurEndTitle	NVARCHAR(100)
DECLARE @CurWFID		INTEGER
DECLARE @CurWFStatID	INTEGER
DECLARE @CurRoleID		INTEGER
DECLARE @CurReqVal		INTEGER
DECLARE @CurReqTVF		INTEGER

DECLARE @WFID		INTEGER

DECLARE @Line			NVARCHAR(10)
DECLARE @AccessDate		DATE
DECLARE @AccessTimeSlot	NVARCHAR(50)
DECLARE @TARType		NVARCHAR(50)
DECLARE @AccessType		NVARCHAR(50)
DECLARE @IsExclusive	BIT

-- >>>
DECLARE @TARWFCtr	INTEGER
SET @TARWFCtr = 0

SELECT @TARWFCtr = COUNT(*) 
	FROM TAMS_TAR_Workflow
		WHERE TARId = @TARID
			AND ActionBy = @UserID
			AND WFStatus = 'Approved'

IF @TARWFCtr > 0
	BEGIN
		--SET @Message = 'Error! User ID have already approved this TAR.'
		SET @Message = '1001'
		GOTO FORCE_EXIT_PROC
	END
-- >>>

IF @TVFRunModeUpdInd = 1
	BEGIN
		UPDATE TAMS_TAR
			SET TVFMode = @TVFRunMode
		WHERE ID = @TARID
	END

SELECT @Line		= Line,
		@AccessDate		= AccessDate,
		@AccessTimeSlot = isnull(AccessTimeSlot,''),
		@TARType		= TARType,
		@AccessType		= AccessType,
		@IsExclusive	= IsExclusive,
		@EMToSend = Email,		-- >> ToSendEmail
		@EMCCSend = Email,
		@EMTARID = Id,
		@EMTARNo = TARNo,
		@EMRemarks = ARRemark,
		@EMCompany = Company
	FROM TAMS_TAR
		WHERE ID = @TARID

SELECT @WFID = WorkflowId 
	FROM TAMS_TAR_Workflow
		WHERE ID = @TARWFID

-- >> Current Level Endorser
SELECT @CurEndID = ID, 
		@CurEndTitle = Title,
		@CurWFID = WorkflowId,
		@CurWFStatID = WFStatusId,
		@CurRoleID = RoleId,
		@CurReqVal = RequireValidation,
		@CurReqTVF = RequireTVF
	FROM TAMS_Endorser
		WHERE WorkflowId = @WFID
			AND [Level] = @ELevel

	-- >> Get Exception TARs - Sector Conflict

	CREATE TABLE #TmpExc 
	(TARID			BIGINT,
	TARNo			NVARCHAR(20),
	TARType			NVARCHAR(10),
	AccessDate		NVARCHAR(20),
	AccessTimeSlot  NVARCHAR(50),
	AccessType		NVARCHAR(20),
	IsExclusive		INT,
	EmailAdd		NVARCHAR(200))

	CREATE TABLE #TmpExcSector 
	(TARID			BIGINT,
	TARNo			NVARCHAR(20),
	TARType			NVARCHAR(10),
	AccessDate		NVARCHAR(20),
	AccessTimeSlot  NVARCHAR(50),
	AccessType		NVARCHAR(20),
	IsExclusive		INT,
	SectorID		INT,
	SectorStr		NVARCHAR(50),
	IsBuffer		INT,
	EmailAdd		NVARCHAR(200))
	
	TRUNCATE TABLE #TmpExc
	TRUNCATE TABLE #TmpExcSector

	DECLARE @Cur01 CURSOR;

	DECLARE @CID			INTEGER
	DECLARE @CSectorID		INTEGER
	DECLARE @CIsBuffer		BIT
	DECLARE @CColourCode	NVARCHAR(20)
	DECLARE @CIsAddBuffer	BIT

	DECLARE @Cur02 CURSOR;

	DECLARE @C2TARID		INTEGER 
	DECLARE @C2TARNo		NVARCHAR(20) 
	DECLARE @C2TARType		NVARCHAR(20)
	DECLARE @C2AccessDate	DATE
	DECLARE @C2AccessTimeSlot NVARCHAR(50)
	DECLARE @C2AccessType	NVARCHAR(20) 
	DECLARE @C2IsExclusive	BIT
	DECLARE @C2SectorID		INTEGER 
	DECLARE @C2SectorStr	NVARCHAR(20) 
	DECLARE @C2IsBuffer		BIT 
	DECLARE @C2EmailAdd		NVARCHAR(200) 

	SET @Cur01 = CURSOR FAST_FORWARD 
	FOR
		SELECT ID, SectorId, IsBuffer, ColourCode, IsAddedBuffer FROM TAMS_TAR_Sector
			WHERE TARId = @TARID
				ORDER BY SectorId

	OPEN @Cur01
	
	FETCH NEXT FROM @Cur01 INTO @CID, @CSectorID, @CIsBuffer, @CColourCode, @CIsAddBuffer
	
	WHILE @@FETCH_STATUS = 0 
	
		BEGIN

			IF @CIsBuffer = 1
				BEGIN
					-- >> Is Buffer
					-- PRINT 1
					INSERT INTO #TmpExcSector
						(TARID, TARNo, TARType, AccessDate, AccessTimeSlot,AccessType, IsExclusive, SectorID, SectorStr, IsBuffer, EmailAdd)
					SELECT t.Id, t.TARNo, t.TARType, t.AccessDate,t.AccessTimeSlot, t.AccessType, t.IsExclusive,
							ts.SectorId, s.Sector, ts.IsBuffer, t.Email 
						FROM TAMS_TAR t, TAMS_TAR_Sector ts, TAMS_Sector s
							WHERE t.Id = ts.TARId
								AND s.ID = ts.SectorId
								AND t.AccessDate = @AccessDate
								AND isnull(t.AccessTimeSlot,'') = @AccessTimeSlot
								AND ts.IsBuffer = 0
								AND t.TARStatusId =   CASE WHEN @Line = 'NEL' THEN 9 ELSE 8 END   --Updated by HNin to include NEL approval status
								AND ts.SectorId = @CSectorID
								AND t.Id <> @TARID
								AND s.IsActive = 1
								AND @AccessDate BETWEEN s.EffectiveDate and S.ExpiryDate
				END
			ELSE
				BEGIN
					-- >> Not Buffer
					-- PRINT 2
					INSERT INTO #TmpExcSector
						(TARID, TARNo, TARType, AccessDate,AccessTimeSlot, AccessType, IsExclusive, SectorID, SectorStr, IsBuffer, EmailAdd)
					SELECT t.Id, t.TARNo, t.TARType, t.AccessDate,t.AccessTimeSlot, t.AccessType, t.IsExclusive,
							ts.SectorId, s.Sector, ts.IsBuffer, t.Email 
						FROM TAMS_TAR t, TAMS_TAR_Sector ts, TAMS_Sector s
							WHERE t.Id = ts.TARId
								AND s.ID = ts.SectorId
								AND t.AccessDate = @AccessDate
								AND isnull(t.AccessTimeSlot,'') = @AccessTimeSlot
								-- >> AND ts.IsBuffer = 0
								AND t.TARStatusId =  CASE WHEN @Line = 'NEL' THEN 9 ELSE 8 END   --Updated by HNin to include NEL approval status
								AND ts.SectorId = @CSectorID
								AND t.Id <> @TARID
								AND s.IsActive = 1
								AND @AccessDate BETWEEN s.EffectiveDate and S.ExpiryDate
				END
				
			-- >> #TmpExcSector
			SET @Cur02 = CURSOR FAST_FORWARD 
			FOR
				SELECT TARID, TARNo, TARType, AccessDate, AccessTimeSlot,AccessType, IsExclusive, SectorID, SectorStr, IsBuffer, EmailAdd 
					FROM #TmpExcSector
							ORDER BY TARID, SectorID

			OPEN @Cur02
	
			FETCH NEXT FROM @Cur02 INTO @C2TARID, @C2TARNo, @C2TARType, @C2AccessDate, @C2AccessTimeSlot, @C2AccessType, @C2IsExclusive, @C2SectorID, @C2SectorStr, @C2IsBuffer, @C2EmailAdd
	
			WHILE @@FETCH_STATUS = 0 
	
				BEGIN
					IF @AccessType = 'Protection' AND @IsExclusive = 0
						BEGIN
							print 1
							IF @C2AccessType = 'Protection' AND @C2IsExclusive = 0
								BEGIN
									PRINT 'DO NOTHING'
								END
							ELSE
								BEGIN
									IF (SELECT COUNT(*) FROM #TmpExc WHERE TARID = @C2TARID) = 0
										BEGIN
											INSERT INTO #TmpExc
												(TARID, TARNo, TARType, AccessDate,AccessTimeSlot, AccessType, IsExclusive, EmailAdd)
											VALUES 
												(@C2TARID, @C2TARNo, @C2TARType, @C2AccessDate,@C2AccessTimeSlot, @C2AccessType, @C2IsExclusive, @C2EmailAdd)
										END
								END
						END
					ELSE
						BEGIN
							IF (SELECT COUNT(*) FROM #TmpExc WHERE TARID = @C2TARID) = 0
								BEGIN
									INSERT INTO #TmpExc
										(TARID, TARNo, TARType, AccessDate,AccessTimeSlot, AccessType, IsExclusive, EmailAdd)
									VALUES 
										(@C2TARID, @C2TARNo, @C2TARType, @C2AccessDate,@C2AccessTimeSlot, @C2AccessType, @C2IsExclusive, @C2EmailAdd)
								END
						END

					FETCH NEXT FROM @Cur02 INTO @C2TARID, @C2TARNo, @C2TARType, @C2AccessDate,@C2AccessTimeSlot, @C2AccessType, @C2IsExclusive, @C2SectorID, @C2SectorStr, @C2IsBuffer, @C2EmailAdd
				END 	

			CLOSE @Cur02
	
			DEALLOCATE @Cur02
			-- >> #TmpExcSector

			FETCH NEXT FROM @Cur01 INTO @CID, @CSectorID, @CIsBuffer, @CColourCode, @CIsAddBuffer
		END 	

	CLOSE @Cur01
	
	DEALLOCATE @Cur01

	-- >> Exception List. Sector Conflict, to show only if RequireValidation = True for current Level Endorser

DECLARE @Cur03 CURSOR;

DECLARE @C3TARID		INTEGER 
DECLARE @C3TARNo		NVARCHAR(20) 
DECLARE @C3TARType		NVARCHAR(20)
DECLARE @C3AccessDate	DATE
DECLARE @C3AccessTimeSlot NVARCHAR(20)
DECLARE @C3AccessType	NVARCHAR(20) 
DECLARE @C3IsExclusive	BIT
DECLARE @C3EmailAdd		NVARCHAR(200) 

-- >> Action Log
DECLARE @LogMsg	NVARCHAR(100)


-- >> #TmpExcSector
SET @Cur03 = CURSOR FAST_FORWARD 
FOR
	SELECT TARID, TARNo, TARType, AccessDate,AccessTimeSlot, AccessType, IsExclusive, EmailAdd 
		FROM #TmpExc
			ORDER BY TARID

OPEN @Cur03
	
FETCH NEXT FROM @Cur03 INTO @C3TARID, @C3TARNo, @C3TARType, @C3AccessDate, @C3AccessTimeSlot,@C3AccessType, @C3IsExclusive, @C3EmailAdd
	
WHILE @@FETCH_STATUS = 0 
	
	BEGIN
		
		-- >> NEL Cancel = 10 Else DTL or LRt = 9
		UPDATE TAMS_TAR
			SET TARStatusId = CASE WHEN @Line = 'NEL' THEN 10 ELSE 9 END,
				UpdatedOn = GETDATE(),
				UpdatedBy = @UserID
		WHERE Id = @C3TARID

		SET @LogMsg = 'TAR Form Cancelled by : ' + CAST(@UserName AS NVARCHAR(500)) + ' On ' + CAST(CONVERT(NVARCHAR(20), GETDATE(), 103) AS NVARCHAR(20)) + ' ' + CAST(CONVERT(NVARCHAR(20), GETDATE(), 108) AS NVARCHAR(20))
		INSERT INTO [dbo].[TAMS_Action_Log]
			([Line], [Module], [Function], [TransactionID], [LogMessage], [CreatedOn], [CreatedBy])
		VALUES 
			(@Line, 'TAR', 'Approval - Cancel', @C3TARID, @LogMsg, GETDATE(), @UserID)

		IF @TARType = 'Urgent' -- >> If Current TAR Type is Urgent then send Email
			BEGIN
				-- >> Cancel Urgent TAR
				SET @EMTARStatus = 'Cancelled'
				SET @EMMsg = ''

				EXEC sp_TAMS_Email_Cancel_TAR @C3TARID, @EMTARStatus, @C3TARNo, @C3EmailAdd, @EMMsg OUTPUT

			END
		
		FETCH NEXT FROM @Cur03 INTO @C3TARID, @C3TARNo, @C3TARType, @C3AccessDate,@C3AccessTimeSlot, @C3AccessType, @C3IsExclusive, @C3EmailAdd
	END 	

CLOSE @Cur03
	
DEALLOCATE @Cur03
-- >> #TmpExcSector

	-- >> Get Exception TARs - Sector Conflict

UPDATE TAMS_TAR_Workflow
	SET WFStatus = 'Approved',
		ActionBy = @UserID,
		ActionOn = GETDATE()
	WHERE ID =  @TARWFID

DECLARE @NextEndID		INTEGER
DECLARE @NextEndTitle	NVARCHAR(100)
DECLARE @NextWFID		INTEGER
DECLARE @NextWFStatID	INTEGER
DECLARE @NextRoleID		INTEGER

-- >> Next Level Endorser
SELECT @NextEndID = ID, 
		@NextEndTitle = Title,
		@NextWFID = WorkflowId,
		@NextWFStatID = WFStatusId,
		@NextRoleID = RoleId
	FROM TAMS_Endorser
		WHERE WorkflowId = @WFID
			AND [Level] = @ELevel + 1

IF ISNULL(@NextEndTitle, '') = ''
	BEGIN
		-- >> If NEL Approved = 9 Else DTL or LRT = 8
		UPDATE TAMS_TAR
			SET TARStatusId = CASE WHEN @Line = 'NEL' THEN 9 ELSE 8 END,
				UpdatedOn = GETDATE(),
				UpdatedBy = @UserID
			WHERE ID = @TARID

		IF @TARType = 'Urgent'
			BEGIN
				SET @EMTARStatus = 'Approved'
				SET @EMMsg = ''

				EXEC sp_TAMS_Email_Urgent_TAR @EMTARID, @EMTARStatus, @EMTARNo, @EMRemarks, @EMActor, @EMToSend, @EMMsg OUTPUT
			END

	END
ELSE
	BEGIN

		IF (SELECT COUNT(*) FROM TAMS_TAR_Workflow
			WHERE TARId = @TARID
				AND WorkflowId = @NextWFID
				AND EndorserId = @NextEndID) = 0
			BEGIN	
				INSERT INTO [dbo].[TAMS_TAR_Workflow]
					([TARId], [WorkflowId], [EndorserId], [UserId], [WFStatus], [Remark], [ActionOn], [ActionBy])
				VALUES
					(@TARID, @NextWFID, @NextEndID, NULL, 'Pending', '', GETDATE(), @UserID)
			END

		UPDATE TAMS_TAR
			SET TARStatusId = @NextWFStatID,
				UpdatedOn = GETDATE(),
				UpdatedBy = @UserID
			WHERE Id = @TARID

		IF @TARType = 'Urgent'
			BEGIN
				-- >> NEXT ROLE ID EMAIL ALERT
				-- >> PRINT 'Urgent Email'
				DECLARE @RoleEmail	NVARCHAR(1000)
				SET @RoleEmail = ''
				SET @EMMsg = ''

				SELECT @RoleEmail = @RoleEmail + ISNULL(a.Email + ', ', '') 
					FROM TAMS_User a, TAMS_User_Role b
						WHERE a.Userid = b.UserID
							AND a.IsActive = 1
							AND @TARDate BETWEEN a.ValidFrom AND a.ValidTo
							AND b.RoleID = @NextEndID

				IF LEN(LTRIM(RTRIM(@RoleEmail))) > 0
					BEGIN
						SET @RoleEmail = LEFT(LTRIM(RTRIM(@RoleEmail)), LEN(LTRIM(RTRIM(@RoleEmail))) - 1)
					END

				-- >> Select all email where role id = next role id
				SET @EMToSend = @RoleEmail

				-- >> 2024-01-31 Changes to add nelocc email to the recipient list for Urgent After and if next level is OCC Approval
				DECLARE @WFTypeChk	NVARCHAR(50)

				SELECT @WFTypeChk = WorkflowType
					FROM TAMS_Workflow
						WHERE ID = @WFID

				IF @WFTypeChk = 'UrgentAfter' AND @NextEndTitle = 'SDS Approval'
					BEGIN 
						declare @SDSEmailForUrgent as nvarchar(100);
						set @SDSEmailForUrgent = '';
						
						SELECT @SDSEmailForUrgent = ParaValue3 
							FROM TAMS_Parameters
								WHERE ParaCode = 'SDSContact'
									AND ParaValue1 = @Line
									AND LTRIM(RTRIM(ISNULL(ParaValue3, ''))) <> ''

						IF LEN(LTRIM(RTRIM(@EMToSend))) > 0
							BEGIN
								-- >> 2024-01-16 Changes to add nelocc email to the recipient list 
						 		SET @EMToSend = @EMToSend + ', ' + @SDSEmailForUrgent
							END
					END;
				-- >> 2024-01-31 Changes to add nelocc email to the recipient list for Urgent After and if next level is OCC Approval

				EXEC sp_TAMS_Email_Apply_Urgent_TAR 2, @EMCompany, @EMTARNo, @NextEndTitle, @EMToSend, @EMCCSend, @EMMsg OUTPUT
			END
	END

	-- >> SET @LogMsg = 'TAR Form has approved by : ' + '' + ' On ' + GETDATE()	
	SET @LogMsg = 'TAR Form Approved by : ' + CAST(@UserName AS NVARCHAR(500)) + ' On ' + CAST(CONVERT(NVARCHAR(20), GETDATE(), 103) AS NVARCHAR(20)) + ' ' + CAST(CONVERT(NVARCHAR(20), GETDATE(), 108) AS NVARCHAR(20))
		
	INSERT INTO [dbo].[TAMS_Action_Log]
		([Line], [Module], [Function], [TransactionID], [LogMessage], [CreatedOn], [CreatedBy])
	VALUES 
		(@Line, 'TAR', 'Approved TAR', @TARID, @LogMsg, GETDATE(), @UserID)

DECLARE @WFType	NVARCHAR(50)
DECLARE @InvPow	BIT

SELECT @WFType = WorkflowType,
		@InvPow = InvolvePower 
	FROM TAMS_Workflow
		WHERE ID = @WFID

IF @WFType = 'UrgentAfter' AND @InvPow = 1 AND @ELevel = 2
	BEGIN
		-- >> TAMS_DTL_PFR
		-- >> PRINT 'EMAIL'

		DECLARE @SDSEmail	NVARCHAR(1000)
		DECLARE @SDSRole	NVARCHAR(50)
		DECLARE @SDSEmailAdd	NVARCHAR(100)

		SET @SDSEmail = ''
		SET @SDSEmailAdd = ''
		SET @SDSRole = @Line + '_PFR'
		SET @EMTARStatus = 'Approved'
		SET @EMMsg = ''

		SELECT @SDSEmail = @SDSEmail + ISNULL(a.Email + ', ', '') 
			FROM TAMS_User a, TAMS_User_Role b, TAMS_Role c
				WHERE a.Userid = b.UserID
					AND b.RoleID = c.ID
					AND a.IsActive = 1
					AND @TARDate BETWEEN a.ValidFrom AND a.ValidTo
					AND c.Role = @SDSRole

		-- >> 2024-01-16 Changes to add nelocc email to the recipient list 
		SELECT @SDSEmailAdd = ParaValue3 
			FROM TAMS_Parameters
				WHERE ParaCode = 'SDSContact'
					AND ParaValue1 = @Line
					AND LTRIM(RTRIM(ISNULL(ParaValue3, ''))) <> ''

		IF LEN(LTRIM(RTRIM(@SDSEmail))) > 0
			BEGIN
				-- >> 2024-01-16 Changes to add nelocc email to the recipient list 
				SET @SDSEmail = LEFT(LTRIM(RTRIM(@SDSEmail)), LEN(LTRIM(RTRIM(@SDSEmail))) - 1)
				SET @SDSEmail = @SDSEmail + ', ' + @SDSEmailAdd
			END

		EXEC sp_TAMS_Email_Urgent_TAR_OCC @TARID, @EMTARStatus, @EMTARNo, @Remarks, @SDSEmail, @EMMsg OUTPUT
	END

-- >>

IF @@ERROR <> 0 BEGIN
	SET @Message = 'ERROR INSERTING INTO TAMS_TAR'
	GOTO TRAP_ERROR
END

FORCE_EXIT_PROC:	
	IF @IntrnlTrans = 1 COMMIT TRAN
	RETURN @Message 

TRAP_ERROR:
	IF @IntrnlTrans = 1 ROLLBACK TRAN
	RETURN @Message

END
GO
/****** END PROCEDURE 36 ******/

/****** START PROCEDURE 37 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_Approval_Proceed_To_App_20220930
CREATE PROCEDURE [dbo].[sp_TAMS_Approval_Proceed_To_App_20220930]
	@TARID		AS INTEGER,						-- >> TAR ID
	@TARWFID	AS INTEGER,						-- >> Current WF ID
	@EID		AS INTEGER,						-- >> Current Endorser ID
	@ELevel		AS INTEGER,						-- >> Current Endorser Level
	@Remarks	AS NVARCHAR(1000) = NULL,		-- >> Remarks -- Mandatory for Reject / Optional for Approved / Endorse
	@TVFRunMode			AS NVARCHAR(50) = NULL,	-- >> New Column to be confirmed with Adeline
	@TVFRunModeUpdInd	AS NVARCHAR(5) = NULL,	-- >> Indicator to Update TVF Run Mode or Not.
	@UserLI		AS NVARCHAR(50) = NULL,			-- >> User Login ID	
	@Message	AS NVARCHAR(500) = NULL OUTPUT
AS

BEGIN

DECLARE	@IntrnlTrans	TINYINT
SELECT 	@IntrnlTrans 	= 0	

IF (@@TRANCOUNT = 0) 
BEGIN
	SET @IntrnlTrans = 1
	BEGIN TRAN
END

-- >>
SET @Message = ''
DECLARE @UserID		INTEGER
DECLARE @UserName NVARCHAR(500)

DECLARE @EMTARID		INTEGER
DECLARE @EMTARStatus	NVARCHAR(20)
DECLARE @EMTARNo		NVARCHAR(50)
DECLARE @EMRemarks		NVARCHAR(1000)
DECLARE @EMActor		NVARCHAR(100)
DECLARE @EMToSend		NVARCHAR(1000)
DECLARE @EMCCSend		NVARCHAR(1000)
DECLARE @EMCompany		NVARCHAR(100)
DECLARE @EMMsg			NVARCHAR(500)

DECLARE @TARDate		DATE

SELECT @UserID = Userid, @UserName = [Name]
FROM TAMS_User
	WHERE LoginId = @UserLI

DECLARE @CurEndID		INTEGER
DECLARE @CurEndTitle	NVARCHAR(100)
DECLARE @CurWFID		INTEGER
DECLARE @CurWFStatID	INTEGER
DECLARE @CurRoleID		INTEGER
DECLARE @CurReqVal		INTEGER
DECLARE @CurReqTVF		INTEGER

DECLARE @WFID		INTEGER

DECLARE @Line			NVARCHAR(10)
DECLARE @AccessDate		DATE
DECLARE @TARType		NVARCHAR(50)
DECLARE @AccessType		NVARCHAR(50)
DECLARE @IsExclusive	BIT

IF @TVFRunModeUpdInd = 1
	BEGIN
		UPDATE TAMS_TAR
			SET TVFMode = @TVFRunMode
		WHERE ID = @TARID
	END

SELECT @Line		= Line,
		@AccessDate		= AccessDate,
		@TARType		= TARType,
		@AccessType		= AccessType,
		@IsExclusive	= IsExclusive,
		@EMToSend = Email,		-- >> ToSendEmail
		@EMCCSend = Email,
		@EMTARID = Id,
		@EMTARNo = TARNo,
		@EMRemarks = ARRemark,
		@EMCompany = Company
	FROM TAMS_TAR
		WHERE ID = @TARID

SELECT @WFID = WorkflowId 
	FROM TAMS_TAR_Workflow
		WHERE ID = @TARWFID

-- >> Current Level Endorser
SELECT @CurEndID = ID, 
		@CurEndTitle = Title,
		@CurWFID = WorkflowId,
		@CurWFStatID = WFStatusId,
		@CurRoleID = RoleId,
		@CurReqVal = RequireValidation,
		@CurReqTVF = RequireTVF
	FROM TAMS_Endorser
		WHERE WorkflowId = @WFID
			AND [Level] = @ELevel

	-- >> Get Exception TARs - Sector Conflict

	CREATE TABLE #TmpExc 
	(TARID			BIGINT,
	TARNo			NVARCHAR(20),
	TARType			NVARCHAR(10),
	AccessDate		NVARCHAR(20),
	AccessType		NVARCHAR(20),
	IsExclusive		INT,
	EmailAdd		NVARCHAR(200))

	CREATE TABLE #TmpExcSector 
	(TARID			BIGINT,
	TARNo			NVARCHAR(20),
	TARType			NVARCHAR(10),
	AccessDate		NVARCHAR(20),
	AccessType		NVARCHAR(20),
	IsExclusive		INT,
	SectorID		INT,
	SectorStr		NVARCHAR(50),
	IsBuffer		INT,
	EmailAdd		NVARCHAR(200))
	
	TRUNCATE TABLE #TmpExc
	TRUNCATE TABLE #TmpExcSector

	DECLARE @Cur01 CURSOR;

	DECLARE @CID			INTEGER
	DECLARE @CSectorID		INTEGER
	DECLARE @CIsBuffer		BIT
	DECLARE @CColourCode	NVARCHAR(20)
	DECLARE @CIsAddBuffer	BIT

	DECLARE @Cur02 CURSOR;

	DECLARE @C2TARID		INTEGER 
	DECLARE @C2TARNo		NVARCHAR(20) 
	DECLARE @C2TARType		NVARCHAR(20)
	DECLARE @C2AccessDate	DATE
	DECLARE @C2AccessType	NVARCHAR(20) 
	DECLARE @C2IsExclusive	BIT
	DECLARE @C2SectorID		INTEGER 
	DECLARE @C2SectorStr	NVARCHAR(20) 
	DECLARE @C2IsBuffer		BIT 
	DECLARE @C2EmailAdd		NVARCHAR(200) 

	SET @Cur01 = CURSOR FAST_FORWARD 
	FOR
		SELECT ID, SectorId, IsBuffer, ColourCode, IsAddedBuffer FROM TAMS_TAR_Sector
			WHERE TARId = @TARID
				ORDER BY SectorId

	OPEN @Cur01
	
	FETCH NEXT FROM @Cur01 INTO @CID, @CSectorID, @CIsBuffer, @CColourCode, @CIsAddBuffer
	
	WHILE @@FETCH_STATUS = 0 
	
		BEGIN

			IF @CIsBuffer = 1
				BEGIN
					-- >> Is Buffer
					-- PRINT 1
					INSERT INTO #TmpExcSector
						(TARID, TARNo, TARType, AccessDate, AccessType, IsExclusive, SectorID, SectorStr, IsBuffer, EmailAdd)
					SELECT t.Id, t.TARNo, t.TARType, t.AccessDate, t.AccessType, t.IsExclusive,
							ts.SectorId, s.Sector, ts.IsBuffer, t.Email 
						FROM TAMS_TAR t, TAMS_TAR_Sector ts, TAMS_Sector s
							WHERE t.Id = ts.TARId
								AND s.ID = ts.SectorId
								AND t.AccessDate = @AccessDate
								AND ts.IsBuffer = 0
								AND t.TARStatusId = 8
								AND ts.SectorId = @CSectorID
								AND t.Id <> @TARID
								AND s.IsActive = 1
								AND @AccessDate BETWEEN s.EffectiveDate and S.ExpiryDate
				END
			ELSE
				BEGIN
					-- >> Not Buffer
					-- PRINT 2
					INSERT INTO #TmpExcSector
						(TARID, TARNo, TARType, AccessDate, AccessType, IsExclusive, SectorID, SectorStr, IsBuffer, EmailAdd)
					SELECT t.Id, t.TARNo, t.TARType, t.AccessDate, t.AccessType, t.IsExclusive,
							ts.SectorId, s.Sector, ts.IsBuffer, t.Email 
						FROM TAMS_TAR t, TAMS_TAR_Sector ts, TAMS_Sector s
							WHERE t.Id = ts.TARId
								AND s.ID = ts.SectorId
								AND t.AccessDate = @AccessDate
								-- >> AND ts.IsBuffer = 0
								AND t.TARStatusId = 8
								AND ts.SectorId = @CSectorID
								AND t.Id <> @TARID
								AND s.IsActive = 1
								AND @AccessDate BETWEEN s.EffectiveDate and S.ExpiryDate
				END
				
			-- >> #TmpExcSector
			SET @Cur02 = CURSOR FAST_FORWARD 
			FOR
				SELECT TARID, TARNo, TARType, AccessDate, AccessType, IsExclusive, SectorID, SectorStr, IsBuffer, EmailAdd 
					FROM #TmpExcSector
							ORDER BY TARID, SectorID

			OPEN @Cur02
	
			FETCH NEXT FROM @Cur02 INTO @C2TARID, @C2TARNo, @C2TARType, @C2AccessDate, @C2AccessType, @C2IsExclusive, @C2SectorID, @C2SectorStr, @C2IsBuffer, @C2EmailAdd
	
			WHILE @@FETCH_STATUS = 0 
	
				BEGIN
					IF @AccessType = 'Protection' AND @IsExclusive = 0
						BEGIN
							print 1
							IF @C2AccessType = 'Protection' AND @C2IsExclusive = 0
								BEGIN
									PRINT 'DO NOTHING'
								END
							ELSE
								BEGIN
									IF (SELECT COUNT(*) FROM #TmpExc WHERE TARID = @C2TARID) = 0
										BEGIN
											INSERT INTO #TmpExc
												(TARID, TARNo, TARType, AccessDate, AccessType, IsExclusive, EmailAdd)
											VALUES 
												(@C2TARID, @C2TARNo, @C2TARType, @C2AccessDate, @C2AccessType, @C2IsExclusive, @C2EmailAdd)
										END
								END
						END
					ELSE
						BEGIN
							IF (SELECT COUNT(*) FROM #TmpExc WHERE TARID = @C2TARID) = 0
								BEGIN
									INSERT INTO #TmpExc
										(TARID, TARNo, TARType, AccessDate, AccessType, IsExclusive, EmailAdd)
									VALUES 
										(@C2TARID, @C2TARNo, @C2TARType, @C2AccessDate, @C2AccessType, @C2IsExclusive, @C2EmailAdd)
								END
						END

					FETCH NEXT FROM @Cur02 INTO @C2TARID, @C2TARNo, @C2TARType, @C2AccessDate, @C2AccessType, @C2IsExclusive, @C2SectorID, @C2SectorStr, @C2IsBuffer, @C2EmailAdd
				END 	

			CLOSE @Cur02
	
			DEALLOCATE @Cur02
			-- >> #TmpExcSector

			FETCH NEXT FROM @Cur01 INTO @CID, @CSectorID, @CIsBuffer, @CColourCode, @CIsAddBuffer
		END 	

	CLOSE @Cur01
	
	DEALLOCATE @Cur01

	-- >> Exception List. Sector Conflict, to show only if RequireValidation = True for current Level Endorser

DECLARE @Cur03 CURSOR;

DECLARE @C3TARID		INTEGER 
DECLARE @C3TARNo		NVARCHAR(20) 
DECLARE @C3TARType		NVARCHAR(20)
DECLARE @C3AccessDate	DATE
DECLARE @C3AccessType	NVARCHAR(20) 
DECLARE @C3IsExclusive	BIT
DECLARE @C3EmailAdd		NVARCHAR(200) 

-- >> Action Log
DECLARE @LogMsg	NVARCHAR(100)


-- >> #TmpExcSector
SET @Cur03 = CURSOR FAST_FORWARD 
FOR
	SELECT TARID, TARNo, TARType, AccessDate, AccessType, IsExclusive, EmailAdd 
		FROM #TmpExc
			ORDER BY TARID

OPEN @Cur03
	
FETCH NEXT FROM @Cur03 INTO @C3TARID, @C3TARNo, @C3TARType, @C3AccessDate, @C3AccessType, @C3IsExclusive, @C3EmailAdd
	
WHILE @@FETCH_STATUS = 0 
	
	BEGIN
		
		-- >> NEL Cancel = 10 Else DTL or LRt = 9
		UPDATE TAMS_TAR
			SET TARStatusId = CASE WHEN @Line = 'NEL' THEN 10 ELSE 9 END,
				UpdatedOn = GETDATE(),
				UpdatedBy = @UserID
		WHERE Id = @C3TARID

		SET @LogMsg = 'TAR Form Cancelled by : ' + CAST(@UserName AS NVARCHAR(500)) + ' On ' + CAST(CONVERT(NVARCHAR(20), GETDATE(), 103) AS NVARCHAR(20)) + ' ' + CAST(CONVERT(NVARCHAR(20), GETDATE(), 108) AS NVARCHAR(20))
		INSERT INTO [dbo].[TAMS_Action_Log]
			([Line], [Module], [Function], [TransactionID], [LogMessage], [CreatedOn], [CreatedBy])
		VALUES 
			(@Line, 'TAR', 'Approval - Cancel', @C3TARID, @LogMsg, GETDATE(), @UserID)

		IF @TARType = 'Late' -- >> If Current TAR Type is Late then send Email
			BEGIN
				-- >> Cancel Late TAR
				SET @EMTARStatus = 'Cancelled'
				SET @EMMsg = ''

				EXEC sp_TAMS_Email_Cancel_TAR @C3TARID, @EMTARStatus, @C3TARNo, @C3EmailAdd, @EMMsg OUTPUT

			END
		
		FETCH NEXT FROM @Cur03 INTO @C3TARID, @C3TARNo, @C3TARType, @C3AccessDate, @C3AccessType, @C3IsExclusive, @C3EmailAdd
	END 	

CLOSE @Cur03
	
DEALLOCATE @Cur03
-- >> #TmpExcSector

	-- >> Get Exception TARs - Sector Conflict

UPDATE TAMS_TAR_Workflow
	SET WFStatus = 'Approved',
		ActionBy = @UserID,
		ActionOn = GETDATE()
	WHERE ID =  @TARWFID

DECLARE @NextEndID		INTEGER
DECLARE @NextEndTitle	NVARCHAR(100)
DECLARE @NextWFID		INTEGER
DECLARE @NextWFStatID	INTEGER
DECLARE @NextRoleID		INTEGER

-- >> Next Level Endorser
SELECT @NextEndID = ID, 
		@NextEndTitle = Title,
		@NextWFID = WorkflowId,
		@NextWFStatID = WFStatusId,
		@NextRoleID = RoleId
	FROM TAMS_Endorser
		WHERE WorkflowId = @WFID
			AND [Level] = @ELevel + 1

IF ISNULL(@NextEndTitle, '') = ''
	BEGIN
		-- >> If NEL Approved = 9 Else DTL or LRT = 8
		UPDATE TAMS_TAR
			SET TARStatusId = CASE WHEN @Line = 'NEL' THEN 9 ELSE 8 END,
				UpdatedOn = GETDATE(),
				UpdatedBy = @UserID
			WHERE ID = @TARID

		IF @TARType = 'Late'
			BEGIN
				SET @EMTARStatus = 'Approved'
				SET @EMMsg = ''

				EXEC sp_TAMS_Email_Late_TAR @EMTARID, @EMTARStatus, @EMTARNo, @EMRemarks, @EMActor, @EMToSend, @EMMsg OUTPUT
			END

	END
ELSE
	BEGIN

		IF (SELECT COUNT(*) FROM TAMS_TAR_Workflow
			WHERE TARId = @TARID
				AND WorkflowId = @NextWFID
				AND EndorserId = @NextEndID) = 0
			BEGIN	
				INSERT INTO [dbo].[TAMS_TAR_Workflow]
					([TARId], [WorkflowId], [EndorserId], [UserId], [WFStatus], [Remark], [ActionOn], [ActionBy])
				VALUES
					(@TARID, @NextWFID, @NextEndID, NULL, 'Pending', '', GETDATE(), @UserID)
			END

		UPDATE TAMS_TAR
			SET TARStatusId = @NextWFStatID,
				UpdatedOn = GETDATE(),
				UpdatedBy = @UserID
			WHERE Id = @TARID

		IF @TARType = 'Late'
			BEGIN
				-- >> NEXT ROLE ID EMAIL ALERT
				-- >> PRINT 'Late Email'
				DECLARE @RoleEmail	NVARCHAR(1000)
				SET @RoleEmail = ''
				SET @EMMsg = ''

				SELECT @RoleEmail = @RoleEmail + ISNULL(a.Email + ', ', '') 
					FROM TAMS_User a, TAMS_User_Role b
						WHERE a.Userid = b.UserID
							AND a.IsActive = 1
							AND @TARDate BETWEEN a.ValidFrom AND a.ValidTo
							AND b.RoleID = @NextEndID

				IF LEN(LTRIM(RTRIM(@RoleEmail))) > 0
					BEGIN
						SET @RoleEmail = LEFT(LTRIM(RTRIM(@RoleEmail)), LEN(LTRIM(RTRIM(@RoleEmail))) - 1)
					END

				-- >> Select all email where role id = next role id
				SET @EMToSend = @RoleEmail

				EXEC sp_TAMS_Email_Apply_Late_TAR 2, @EMCompany, @EMTARNo, @NextEndTitle, @EMToSend, @EMCCSend, @EMMsg OUTPUT
			END
	END

	-- >> SET @LogMsg = 'TAR Form has approved by : ' + '' + ' On ' + GETDATE()	
	SET @LogMsg = 'TAR Form Approved by : ' + CAST(@UserName AS NVARCHAR(500)) + ' On ' + CAST(CONVERT(NVARCHAR(20), GETDATE(), 103) AS NVARCHAR(20)) + ' ' + CAST(CONVERT(NVARCHAR(20), GETDATE(), 108) AS NVARCHAR(20))
		
	INSERT INTO [dbo].[TAMS_Action_Log]
		([Line], [Module], [Function], [TransactionID], [LogMessage], [CreatedOn], [CreatedBy])
	VALUES 
		(@Line, 'TAR', 'Approved TAR', @TARID, @LogMsg, GETDATE(), @UserID)

DECLARE @WFType	NVARCHAR(50)
DECLARE @InvPow	BIT

SELECT @WFType = WorkflowType,
		@InvPow = InvolvePower 
	FROM TAMS_Workflow
		WHERE ID = @WFID

IF @WFType = 'LateAfter' AND @InvPow = 1 AND @ELevel = 2
	BEGIN
		-- >> TAMS_DTL_PFR
		-- >> PRINT 'EMAIL'

		DECLARE @OCCEmail	NVARCHAR(1000)
		DECLARE @OCCRole	NVARCHAR(50)

		SET @OCCEmail = ''
		SET @OCCRole = @Line + '_PFR'
		SET @EMTARStatus = 'Approved'
		SET @EMMsg = ''

		SELECT @OCCEmail = @OCCEmail + ISNULL(a.Email + ', ', '') 
			FROM TAMS_User a, TAMS_User_Role b, TAMS_Role c
				WHERE a.Userid = b.UserID
					AND b.RoleID = c.ID
					AND a.IsActive = 1
					AND @TARDate BETWEEN a.ValidFrom AND a.ValidTo
					AND c.Role = @OCCRole

		IF LEN(LTRIM(RTRIM(@OCCEmail))) > 0
			BEGIN
				SET @OCCEmail = LEFT(LTRIM(RTRIM(@OCCEmail)), LEN(LTRIM(RTRIM(@OCCEmail))) - 1)
			END

		EXEC sp_TAMS_Email_Late_TAR_OCC @TARID, @EMTARStatus, @EMTARNo, @Remarks, @OCCEmail, @EMMsg OUTPUT
	END

-- >>

IF @@ERROR <> 0 BEGIN
	SET @Message = 'ERROR INSERTING INTO TAMS_TAR'
	GOTO TRAP_ERROR
END

FORCE_EXIT_PROC:	
	IF @IntrnlTrans = 1 COMMIT TRAN
	RETURN @Message 

TRAP_ERROR:
	IF @IntrnlTrans = 1 ROLLBACK TRAN
	RETURN @Message

END
GO
/****** END PROCEDURE 37 ******/

/****** START PROCEDURE 38 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_Approval_Proceed_To_App_20231009
create PROCEDURE  [dbo].[sp_TAMS_Approval_Proceed_To_App_20231009]
	@TARID		AS INTEGER,						-- >> TAR ID
	@TARWFID	AS INTEGER,						-- >> Current WF ID
	@EID		AS INTEGER,						-- >> Current Endorser ID
	@ELevel		AS INTEGER,						-- >> Current Endorser Level
	@Remarks	AS NVARCHAR(1000) = NULL,		-- >> Remarks -- Mandatory for Reject / Optional for Approved / Endorse
	@TVFRunMode			AS NVARCHAR(50) = NULL,	-- >> New Column to be confirmed with Adeline
	@TVFRunModeUpdInd	AS NVARCHAR(5) = NULL,	-- >> Indicator to Update TVF Run Mode or Not.
	@UserLI		AS NVARCHAR(100) = NULL,			-- >> User Login ID	
	@Message	AS NVARCHAR(500) = NULL OUTPUT
AS

BEGIN

DECLARE	@IntrnlTrans	TINYINT
SELECT 	@IntrnlTrans 	= 0	

IF (@@TRANCOUNT = 0) 
BEGIN
	SET @IntrnlTrans = 1
	BEGIN TRAN
END

-- >>
SET @Message = ''
DECLARE @UserID		INTEGER
DECLARE @UserName NVARCHAR(500)

DECLARE @EMTARID		INTEGER
DECLARE @EMTARStatus	NVARCHAR(20)
DECLARE @EMTARNo		NVARCHAR(50)
DECLARE @EMRemarks		NVARCHAR(1000)
DECLARE @EMActor		NVARCHAR(100)
DECLARE @EMToSend		NVARCHAR(1000)
DECLARE @EMCCSend		NVARCHAR(1000)
DECLARE @EMCompany		NVARCHAR(100)
DECLARE @EMMsg			NVARCHAR(500)

DECLARE @TARDate		DATE

SELECT @UserID = Userid, @UserName = [Name]
FROM TAMS_User
	WHERE LoginId = @UserLI

DECLARE @CurEndID		INTEGER
DECLARE @CurEndTitle	NVARCHAR(100)
DECLARE @CurWFID		INTEGER
DECLARE @CurWFStatID	INTEGER
DECLARE @CurRoleID		INTEGER
DECLARE @CurReqVal		INTEGER
DECLARE @CurReqTVF		INTEGER

DECLARE @WFID		INTEGER

DECLARE @Line			NVARCHAR(10)
DECLARE @AccessDate		DATE
DECLARE @TARType		NVARCHAR(50)
DECLARE @AccessType		NVARCHAR(50)
DECLARE @IsExclusive	BIT

-- >>>
DECLARE @TARWFCtr	INTEGER
SET @TARWFCtr = 0

SELECT @TARWFCtr = COUNT(*) 
	FROM TAMS_TAR_Workflow
		WHERE TARId = @TARID
			AND ActionBy = @UserID
			AND WFStatus = 'Approved'

IF @TARWFCtr > 0
	BEGIN
		--SET @Message = 'Error! User ID have already approved this TAR.'
		SET @Message = '1001'
		GOTO FORCE_EXIT_PROC
	END
-- >>>

IF @TVFRunModeUpdInd = 1
	BEGIN
		UPDATE TAMS_TAR
			SET TVFMode = @TVFRunMode
		WHERE ID = @TARID
	END

SELECT @Line		= Line,
		@AccessDate		= AccessDate,
		@TARType		= TARType,
		@AccessType		= AccessType,
		@IsExclusive	= IsExclusive,
		@EMToSend = Email,		-- >> ToSendEmail
		@EMCCSend = Email,
		@EMTARID = Id,
		@EMTARNo = TARNo,
		@EMRemarks = ARRemark,
		@EMCompany = Company
	FROM TAMS_TAR
		WHERE ID = @TARID

SELECT @WFID = WorkflowId 
	FROM TAMS_TAR_Workflow
		WHERE ID = @TARWFID

-- >> Current Level Endorser
SELECT @CurEndID = ID, 
		@CurEndTitle = Title,
		@CurWFID = WorkflowId,
		@CurWFStatID = WFStatusId,
		@CurRoleID = RoleId,
		@CurReqVal = RequireValidation,
		@CurReqTVF = RequireTVF
	FROM TAMS_Endorser
		WHERE WorkflowId = @WFID
			AND [Level] = @ELevel

	-- >> Get Exception TARs - Sector Conflict

	CREATE TABLE #TmpExc 
	(TARID			BIGINT,
	TARNo			NVARCHAR(20),
	TARType			NVARCHAR(10),
	AccessDate		NVARCHAR(20),
	AccessType		NVARCHAR(20),
	IsExclusive		INT,
	EmailAdd		NVARCHAR(200))

	CREATE TABLE #TmpExcSector 
	(TARID			BIGINT,
	TARNo			NVARCHAR(20),
	TARType			NVARCHAR(10),
	AccessDate		NVARCHAR(20),
	AccessType		NVARCHAR(20),
	IsExclusive		INT,
	SectorID		INT,
	SectorStr		NVARCHAR(50),
	IsBuffer		INT,
	EmailAdd		NVARCHAR(200))
	
	TRUNCATE TABLE #TmpExc
	TRUNCATE TABLE #TmpExcSector

	DECLARE @Cur01 CURSOR;

	DECLARE @CID			INTEGER
	DECLARE @CSectorID		INTEGER
	DECLARE @CIsBuffer		BIT
	DECLARE @CColourCode	NVARCHAR(20)
	DECLARE @CIsAddBuffer	BIT

	DECLARE @Cur02 CURSOR;

	DECLARE @C2TARID		INTEGER 
	DECLARE @C2TARNo		NVARCHAR(20) 
	DECLARE @C2TARType		NVARCHAR(20)
	DECLARE @C2AccessDate	DATE
	DECLARE @C2AccessType	NVARCHAR(20) 
	DECLARE @C2IsExclusive	BIT
	DECLARE @C2SectorID		INTEGER 
	DECLARE @C2SectorStr	NVARCHAR(20) 
	DECLARE @C2IsBuffer		BIT 
	DECLARE @C2EmailAdd		NVARCHAR(200) 

	SET @Cur01 = CURSOR FAST_FORWARD 
	FOR
		SELECT ID, SectorId, IsBuffer, ColourCode, IsAddedBuffer FROM TAMS_TAR_Sector
			WHERE TARId = @TARID
				ORDER BY SectorId

	OPEN @Cur01
	
	FETCH NEXT FROM @Cur01 INTO @CID, @CSectorID, @CIsBuffer, @CColourCode, @CIsAddBuffer
	
	WHILE @@FETCH_STATUS = 0 
	
		BEGIN

			IF @CIsBuffer = 1
				BEGIN
					-- >> Is Buffer
					-- PRINT 1
					INSERT INTO #TmpExcSector
						(TARID, TARNo, TARType, AccessDate, AccessType, IsExclusive, SectorID, SectorStr, IsBuffer, EmailAdd)
					SELECT t.Id, t.TARNo, t.TARType, t.AccessDate, t.AccessType, t.IsExclusive,
							ts.SectorId, s.Sector, ts.IsBuffer, t.Email 
						FROM TAMS_TAR t, TAMS_TAR_Sector ts, TAMS_Sector s
							WHERE t.Id = ts.TARId
								AND s.ID = ts.SectorId
								AND t.AccessDate = @AccessDate
								AND ts.IsBuffer = 0
								AND t.TARStatusId = 8
								AND ts.SectorId = @CSectorID
								AND t.Id <> @TARID
								AND s.IsActive = 1
								AND @AccessDate BETWEEN s.EffectiveDate and S.ExpiryDate
				END
			ELSE
				BEGIN
					-- >> Not Buffer
					-- PRINT 2
					INSERT INTO #TmpExcSector
						(TARID, TARNo, TARType, AccessDate, AccessType, IsExclusive, SectorID, SectorStr, IsBuffer, EmailAdd)
					SELECT t.Id, t.TARNo, t.TARType, t.AccessDate, t.AccessType, t.IsExclusive,
							ts.SectorId, s.Sector, ts.IsBuffer, t.Email 
						FROM TAMS_TAR t, TAMS_TAR_Sector ts, TAMS_Sector s
							WHERE t.Id = ts.TARId
								AND s.ID = ts.SectorId
								AND t.AccessDate = @AccessDate
								-- >> AND ts.IsBuffer = 0
								AND t.TARStatusId = 8
								AND ts.SectorId = @CSectorID
								AND t.Id <> @TARID
								AND s.IsActive = 1
								AND @AccessDate BETWEEN s.EffectiveDate and S.ExpiryDate
				END
				
			-- >> #TmpExcSector
			SET @Cur02 = CURSOR FAST_FORWARD 
			FOR
				SELECT TARID, TARNo, TARType, AccessDate, AccessType, IsExclusive, SectorID, SectorStr, IsBuffer, EmailAdd 
					FROM #TmpExcSector
							ORDER BY TARID, SectorID

			OPEN @Cur02
	
			FETCH NEXT FROM @Cur02 INTO @C2TARID, @C2TARNo, @C2TARType, @C2AccessDate, @C2AccessType, @C2IsExclusive, @C2SectorID, @C2SectorStr, @C2IsBuffer, @C2EmailAdd
	
			WHILE @@FETCH_STATUS = 0 
	
				BEGIN
					IF @AccessType = 'Protection' AND @IsExclusive = 0
						BEGIN
							print 1
							IF @C2AccessType = 'Protection' AND @C2IsExclusive = 0
								BEGIN
									PRINT 'DO NOTHING'
								END
							ELSE
								BEGIN
									IF (SELECT COUNT(*) FROM #TmpExc WHERE TARID = @C2TARID) = 0
										BEGIN
											INSERT INTO #TmpExc
												(TARID, TARNo, TARType, AccessDate, AccessType, IsExclusive, EmailAdd)
											VALUES 
												(@C2TARID, @C2TARNo, @C2TARType, @C2AccessDate, @C2AccessType, @C2IsExclusive, @C2EmailAdd)
										END
								END
						END
					ELSE
						BEGIN
							IF (SELECT COUNT(*) FROM #TmpExc WHERE TARID = @C2TARID) = 0
								BEGIN
									INSERT INTO #TmpExc
										(TARID, TARNo, TARType, AccessDate, AccessType, IsExclusive, EmailAdd)
									VALUES 
										(@C2TARID, @C2TARNo, @C2TARType, @C2AccessDate, @C2AccessType, @C2IsExclusive, @C2EmailAdd)
								END
						END

					FETCH NEXT FROM @Cur02 INTO @C2TARID, @C2TARNo, @C2TARType, @C2AccessDate, @C2AccessType, @C2IsExclusive, @C2SectorID, @C2SectorStr, @C2IsBuffer, @C2EmailAdd
				END 	

			CLOSE @Cur02
	
			DEALLOCATE @Cur02
			-- >> #TmpExcSector

			FETCH NEXT FROM @Cur01 INTO @CID, @CSectorID, @CIsBuffer, @CColourCode, @CIsAddBuffer
		END 	

	CLOSE @Cur01
	
	DEALLOCATE @Cur01

	-- >> Exception List. Sector Conflict, to show only if RequireValidation = True for current Level Endorser

DECLARE @Cur03 CURSOR;

DECLARE @C3TARID		INTEGER 
DECLARE @C3TARNo		NVARCHAR(20) 
DECLARE @C3TARType		NVARCHAR(20)
DECLARE @C3AccessDate	DATE
DECLARE @C3AccessType	NVARCHAR(20) 
DECLARE @C3IsExclusive	BIT
DECLARE @C3EmailAdd		NVARCHAR(200) 

-- >> Action Log
DECLARE @LogMsg	NVARCHAR(100)


-- >> #TmpExcSector
SET @Cur03 = CURSOR FAST_FORWARD 
FOR
	SELECT TARID, TARNo, TARType, AccessDate, AccessType, IsExclusive, EmailAdd 
		FROM #TmpExc
			ORDER BY TARID

OPEN @Cur03
	
FETCH NEXT FROM @Cur03 INTO @C3TARID, @C3TARNo, @C3TARType, @C3AccessDate, @C3AccessType, @C3IsExclusive, @C3EmailAdd
	
WHILE @@FETCH_STATUS = 0 
	
	BEGIN
		
		-- >> NEL Cancel = 10 Else DTL or LRt = 9
		UPDATE TAMS_TAR
			SET TARStatusId = CASE WHEN @Line = 'NEL' THEN 10 ELSE 9 END,
				UpdatedOn = GETDATE(),
				UpdatedBy = @UserID
		WHERE Id = @C3TARID

		SET @LogMsg = 'TAR Form Cancelled by : ' + CAST(@UserName AS NVARCHAR(500)) + ' On ' + CAST(CONVERT(NVARCHAR(20), GETDATE(), 103) AS NVARCHAR(20)) + ' ' + CAST(CONVERT(NVARCHAR(20), GETDATE(), 108) AS NVARCHAR(20))
		INSERT INTO [dbo].[TAMS_Action_Log]
			([Line], [Module], [Function], [TransactionID], [LogMessage], [CreatedOn], [CreatedBy])
		VALUES 
			(@Line, 'TAR', 'Approval - Cancel', @C3TARID, @LogMsg, GETDATE(), @UserID)

		IF @TARType = 'Urgent' -- >> If Current TAR Type is Urgent then send Email
			BEGIN
				-- >> Cancel Urgent TAR
				SET @EMTARStatus = 'Cancelled'
				SET @EMMsg = ''

				EXEC sp_TAMS_Email_Cancel_TAR @C3TARID, @EMTARStatus, @C3TARNo, @C3EmailAdd, @EMMsg OUTPUT

			END
		
		FETCH NEXT FROM @Cur03 INTO @C3TARID, @C3TARNo, @C3TARType, @C3AccessDate, @C3AccessType, @C3IsExclusive, @C3EmailAdd
	END 	

CLOSE @Cur03
	
DEALLOCATE @Cur03
-- >> #TmpExcSector

	-- >> Get Exception TARs - Sector Conflict

UPDATE TAMS_TAR_Workflow
	SET WFStatus = 'Approved',
		ActionBy = @UserID,
		ActionOn = GETDATE()
	WHERE ID =  @TARWFID

DECLARE @NextEndID		INTEGER
DECLARE @NextEndTitle	NVARCHAR(100)
DECLARE @NextWFID		INTEGER
DECLARE @NextWFStatID	INTEGER
DECLARE @NextRoleID		INTEGER

-- >> Next Level Endorser
SELECT @NextEndID = ID, 
		@NextEndTitle = Title,
		@NextWFID = WorkflowId,
		@NextWFStatID = WFStatusId,
		@NextRoleID = RoleId
	FROM TAMS_Endorser
		WHERE WorkflowId = @WFID
			AND [Level] = @ELevel + 1

IF ISNULL(@NextEndTitle, '') = ''
	BEGIN
		-- >> If NEL Approved = 9 Else DTL or LRT = 8
		UPDATE TAMS_TAR
			SET TARStatusId = CASE WHEN @Line = 'NEL' THEN 9 ELSE 8 END,
				UpdatedOn = GETDATE(),
				UpdatedBy = @UserID
			WHERE ID = @TARID

		IF @TARType = 'Urgent'
			BEGIN
				SET @EMTARStatus = 'Approved'
				SET @EMMsg = ''

				EXEC sp_TAMS_Email_Urgent_TAR @EMTARID, @EMTARStatus, @EMTARNo, @EMRemarks, @EMActor, @EMToSend, @EMMsg OUTPUT
			END

	END
ELSE
	BEGIN

		IF (SELECT COUNT(*) FROM TAMS_TAR_Workflow
			WHERE TARId = @TARID
				AND WorkflowId = @NextWFID
				AND EndorserId = @NextEndID) = 0
			BEGIN	
				INSERT INTO [dbo].[TAMS_TAR_Workflow]
					([TARId], [WorkflowId], [EndorserId], [UserId], [WFStatus], [Remark], [ActionOn], [ActionBy])
				VALUES
					(@TARID, @NextWFID, @NextEndID, NULL, 'Pending', '', GETDATE(), @UserID)
			END

		UPDATE TAMS_TAR
			SET TARStatusId = @NextWFStatID,
				UpdatedOn = GETDATE(),
				UpdatedBy = @UserID
			WHERE Id = @TARID

		IF @TARType = 'Urgent'
			BEGIN
				-- >> NEXT ROLE ID EMAIL ALERT
				-- >> PRINT 'Urgent Email'
				DECLARE @RoleEmail	NVARCHAR(1000)
				SET @RoleEmail = ''
				SET @EMMsg = ''

				SELECT @RoleEmail = @RoleEmail + ISNULL(a.Email + ', ', '') 
					FROM TAMS_User a, TAMS_User_Role b
						WHERE a.Userid = b.UserID
							AND a.IsActive = 1
							AND @TARDate BETWEEN a.ValidFrom AND a.ValidTo
							AND b.RoleID = @NextEndID

				IF LEN(LTRIM(RTRIM(@RoleEmail))) > 0
					BEGIN
						SET @RoleEmail = LEFT(LTRIM(RTRIM(@RoleEmail)), LEN(LTRIM(RTRIM(@RoleEmail))) - 1)
					END

				-- >> Select all email where role id = next role id
				SET @EMToSend = @RoleEmail

				EXEC sp_TAMS_Email_Apply_Urgent_TAR 2, @EMCompany, @EMTARNo, @NextEndTitle, @EMToSend, @EMCCSend, @EMMsg OUTPUT
			END
	END

	-- >> SET @LogMsg = 'TAR Form has approved by : ' + '' + ' On ' + GETDATE()	
	SET @LogMsg = 'TAR Form Approved by : ' + CAST(@UserName AS NVARCHAR(500)) + ' On ' + CAST(CONVERT(NVARCHAR(20), GETDATE(), 103) AS NVARCHAR(20)) + ' ' + CAST(CONVERT(NVARCHAR(20), GETDATE(), 108) AS NVARCHAR(20))
		
	INSERT INTO [dbo].[TAMS_Action_Log]
		([Line], [Module], [Function], [TransactionID], [LogMessage], [CreatedOn], [CreatedBy])
	VALUES 
		(@Line, 'TAR', 'Approved TAR', @TARID, @LogMsg, GETDATE(), @UserID)

DECLARE @WFType	NVARCHAR(50)
DECLARE @InvPow	BIT

SELECT @WFType = WorkflowType,
		@InvPow = InvolvePower 
	FROM TAMS_Workflow
		WHERE ID = @WFID

IF @WFType = 'UrgentAfter' AND @InvPow = 1 AND @ELevel = 2
	BEGIN
		-- >> TAMS_DTL_PFR
		-- >> PRINT 'EMAIL'

		DECLARE @OCCEmail	NVARCHAR(1000)
		DECLARE @OCCRole	NVARCHAR(50)

		SET @OCCEmail = ''
		SET @OCCRole = @Line + '_PFR'
		SET @EMTARStatus = 'Approved'
		SET @EMMsg = ''

		SELECT @OCCEmail = @OCCEmail + ISNULL(a.Email + ', ', '') 
			FROM TAMS_User a, TAMS_User_Role b, TAMS_Role c
				WHERE a.Userid = b.UserID
					AND b.RoleID = c.ID
					AND a.IsActive = 1
					AND @TARDate BETWEEN a.ValidFrom AND a.ValidTo
					AND c.Role = @OCCRole

		IF LEN(LTRIM(RTRIM(@OCCEmail))) > 0
			BEGIN
				SET @OCCEmail = LEFT(LTRIM(RTRIM(@OCCEmail)), LEN(LTRIM(RTRIM(@OCCEmail))) - 1)
			END

		EXEC sp_TAMS_Email_Urgent_TAR_OCC @TARID, @EMTARStatus, @EMTARNo, @Remarks, @OCCEmail, @EMMsg OUTPUT
	END

-- >>

IF @@ERROR <> 0 BEGIN
	SET @Message = 'ERROR INSERTING INTO TAMS_TAR'
	GOTO TRAP_ERROR
END

FORCE_EXIT_PROC:	
	IF @IntrnlTrans = 1 COMMIT TRAN
	RETURN @Message 

TRAP_ERROR:
	IF @IntrnlTrans = 1 ROLLBACK TRAN
	RETURN @Message

END
GO
/****** END PROCEDURE 38 ******/

/****** START PROCEDURE 39 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_Approval_Proceed_To_App_20240920
CREATE   procedure  [dbo].[sp_TAMS_Approval_Proceed_To_App_20240920]
	@TARID		AS INTEGER,						-- >> TAR ID
	@TARWFID	AS INTEGER,						-- >> Current WF ID
	@EID		AS INTEGER,						-- >> Current Endorser ID
	@ELevel		AS INTEGER,						-- >> Current Endorser Level
	@Remarks	AS NVARCHAR(1000) = NULL,		-- >> Remarks -- Mandatory for Reject / Optional for Approved / Endorse
	@TVFRunMode			AS NVARCHAR(50) = NULL,	-- >> New Column to be confirmed with Adeline
	@TVFRunModeUpdInd	AS NVARCHAR(5) = NULL,	-- >> Indicator to Update TVF Run Mode or Not.
	@UserLI		AS NVARCHAR(100) = NULL,			-- >> User Login ID	
	@Message	AS NVARCHAR(500) = NULL OUTPUT
AS

BEGIN

DECLARE	@IntrnlTrans	TINYINT
SELECT 	@IntrnlTrans 	= 0	

IF (@@TRANCOUNT = 0) 
BEGIN
	SET @IntrnlTrans = 1
	BEGIN TRAN
END

-- >>
SET @Message = ''
DECLARE @UserID		INTEGER
DECLARE @UserName NVARCHAR(500)

DECLARE @EMTARID		INTEGER
DECLARE @EMTARStatus	NVARCHAR(20)
DECLARE @EMTARNo		NVARCHAR(50)
DECLARE @EMRemarks		NVARCHAR(1000)
DECLARE @EMActor		NVARCHAR(100)
DECLARE @EMToSend		NVARCHAR(1000)
DECLARE @EMCCSend		NVARCHAR(1000)
DECLARE @EMCompany		NVARCHAR(100)
DECLARE @EMMsg			NVARCHAR(500)

DECLARE @TARDate		DATE

SELECT @UserID = Userid, @UserName = [Name]
FROM TAMS_User
	WHERE LoginId = @UserLI

DECLARE @CurEndID		INTEGER
DECLARE @CurEndTitle	NVARCHAR(100)
DECLARE @CurWFID		INTEGER
DECLARE @CurWFStatID	INTEGER
DECLARE @CurRoleID		INTEGER
DECLARE @CurReqVal		INTEGER
DECLARE @CurReqTVF		INTEGER

DECLARE @WFID		INTEGER

DECLARE @Line			NVARCHAR(10)
DECLARE @AccessDate		DATE
DECLARE @AccessTimeSlot	NVARCHAR(50)
DECLARE @TARType		NVARCHAR(50)
DECLARE @AccessType		NVARCHAR(50)
DECLARE @IsExclusive	BIT

-- >>>
DECLARE @TARWFCtr	INTEGER
SET @TARWFCtr = 0

SELECT @TARWFCtr = COUNT(*) 
	FROM TAMS_TAR_Workflow
		WHERE TARId = @TARID
			AND ActionBy = @UserID
			AND WFStatus = 'Approved'

IF @TARWFCtr > 0
	BEGIN
		--SET @Message = 'Error! User ID have already approved this TAR.'
		SET @Message = '1001'
		GOTO FORCE_EXIT_PROC
	END
-- >>>

IF @TVFRunModeUpdInd = 1
	BEGIN
		UPDATE TAMS_TAR
			SET TVFMode = @TVFRunMode
		WHERE ID = @TARID
	END

SELECT @Line		= Line,
		@AccessDate		= AccessDate,
		@AccessTimeSlot = isnull(AccessTimeSlot,''),
		@TARType		= TARType,
		@AccessType		= AccessType,
		@IsExclusive	= IsExclusive,
		@EMToSend = Email,		-- >> ToSendEmail
		@EMCCSend = Email,
		@EMTARID = Id,
		@EMTARNo = TARNo,
		@EMRemarks = ARRemark,
		@EMCompany = Company
	FROM TAMS_TAR
		WHERE ID = @TARID

SELECT @WFID = WorkflowId 
	FROM TAMS_TAR_Workflow
		WHERE ID = @TARWFID

-- >> Current Level Endorser
SELECT @CurEndID = ID, 
		@CurEndTitle = Title,
		@CurWFID = WorkflowId,
		@CurWFStatID = WFStatusId,
		@CurRoleID = RoleId,
		@CurReqVal = RequireValidation,
		@CurReqTVF = RequireTVF
	FROM TAMS_Endorser
		WHERE WorkflowId = @WFID
			AND [Level] = @ELevel

	-- >> Get Exception TARs - Sector Conflict

	CREATE TABLE #TmpExc 
	(TARID			BIGINT,
	TARNo			NVARCHAR(20),
	TARType			NVARCHAR(10),
	AccessDate		NVARCHAR(20),
	AccessTimeSlot  NVARCHAR(50),
	AccessType		NVARCHAR(20),
	IsExclusive		INT,
	EmailAdd		NVARCHAR(200))

	CREATE TABLE #TmpExcSector 
	(TARID			BIGINT,
	TARNo			NVARCHAR(20),
	TARType			NVARCHAR(10),
	AccessDate		NVARCHAR(20),
	AccessTimeSlot  NVARCHAR(50),
	AccessType		NVARCHAR(20),
	IsExclusive		INT,
	SectorID		INT,
	SectorStr		NVARCHAR(50),
	IsBuffer		INT,
	EmailAdd		NVARCHAR(200))
	
	TRUNCATE TABLE #TmpExc
	TRUNCATE TABLE #TmpExcSector

	DECLARE @Cur01 CURSOR;

	DECLARE @CID			INTEGER
	DECLARE @CSectorID		INTEGER
	DECLARE @CIsBuffer		BIT
	DECLARE @CColourCode	NVARCHAR(20)
	DECLARE @CIsAddBuffer	BIT

	DECLARE @Cur02 CURSOR;

	DECLARE @C2TARID		INTEGER 
	DECLARE @C2TARNo		NVARCHAR(20) 
	DECLARE @C2TARType		NVARCHAR(20)
	DECLARE @C2AccessDate	DATE
	DECLARE @C2AccessTimeSlot NVARCHAR(50)
	DECLARE @C2AccessType	NVARCHAR(20) 
	DECLARE @C2IsExclusive	BIT
	DECLARE @C2SectorID		INTEGER 
	DECLARE @C2SectorStr	NVARCHAR(20) 
	DECLARE @C2IsBuffer		BIT 
	DECLARE @C2EmailAdd		NVARCHAR(200) 

	SET @Cur01 = CURSOR FAST_FORWARD 
	FOR
		SELECT ID, SectorId, IsBuffer, ColourCode, IsAddedBuffer FROM TAMS_TAR_Sector
			WHERE TARId = @TARID
				ORDER BY SectorId

	OPEN @Cur01
	
	FETCH NEXT FROM @Cur01 INTO @CID, @CSectorID, @CIsBuffer, @CColourCode, @CIsAddBuffer
	
	WHILE @@FETCH_STATUS = 0 
	
		BEGIN

			IF @CIsBuffer = 1
				BEGIN
					-- >> Is Buffer
					-- PRINT 1
					INSERT INTO #TmpExcSector
						(TARID, TARNo, TARType, AccessDate, AccessTimeSlot,AccessType, IsExclusive, SectorID, SectorStr, IsBuffer, EmailAdd)
					SELECT t.Id, t.TARNo, t.TARType, t.AccessDate,t.AccessTimeSlot, t.AccessType, t.IsExclusive,
							ts.SectorId, s.Sector, ts.IsBuffer, t.Email 
						FROM TAMS_TAR t, TAMS_TAR_Sector ts, TAMS_Sector s
							WHERE t.Id = ts.TARId
								AND s.ID = ts.SectorId
								AND t.AccessDate = @AccessDate
								AND t.AccessTimeSlot = @AccessTimeSlot
								AND ts.IsBuffer = 0
								AND t.TARStatusId =   CASE WHEN @Line = 'NEL' THEN 9 ELSE 8 END   --Updated by HNin to include NEL approval status
								AND ts.SectorId = @CSectorID
								AND t.Id <> @TARID
								AND s.IsActive = 1
								AND @AccessDate BETWEEN s.EffectiveDate and S.ExpiryDate
				END
			ELSE
				BEGIN
					-- >> Not Buffer
					-- PRINT 2
					INSERT INTO #TmpExcSector
						(TARID, TARNo, TARType, AccessDate,AccessTimeSlot, AccessType, IsExclusive, SectorID, SectorStr, IsBuffer, EmailAdd)
					SELECT t.Id, t.TARNo, t.TARType, t.AccessDate,t.AccessTimeSlot, t.AccessType, t.IsExclusive,
							ts.SectorId, s.Sector, ts.IsBuffer, t.Email 
						FROM TAMS_TAR t, TAMS_TAR_Sector ts, TAMS_Sector s
							WHERE t.Id = ts.TARId
								AND s.ID = ts.SectorId
								AND t.AccessDate = @AccessDate
								AND t.AccessTimeSlot = @AccessTimeSlot
								-- >> AND ts.IsBuffer = 0
								AND t.TARStatusId =  CASE WHEN @Line = 'NEL' THEN 9 ELSE 8 END   --Updated by HNin to include NEL approval status
								AND ts.SectorId = @CSectorID
								AND t.Id <> @TARID
								AND s.IsActive = 1
								AND @AccessDate BETWEEN s.EffectiveDate and S.ExpiryDate
				END
				
			-- >> #TmpExcSector
			SET @Cur02 = CURSOR FAST_FORWARD 
			FOR
				SELECT TARID, TARNo, TARType, AccessDate, AccessTimeSlot,AccessType, IsExclusive, SectorID, SectorStr, IsBuffer, EmailAdd 
					FROM #TmpExcSector
							ORDER BY TARID, SectorID

			OPEN @Cur02
	
			FETCH NEXT FROM @Cur02 INTO @C2TARID, @C2TARNo, @C2TARType, @C2AccessDate, @C2AccessTimeSlot, @C2AccessType, @C2IsExclusive, @C2SectorID, @C2SectorStr, @C2IsBuffer, @C2EmailAdd
	
			WHILE @@FETCH_STATUS = 0 
	
				BEGIN
					IF @AccessType = 'Protection' AND @IsExclusive = 0
						BEGIN
							print 1
							IF @C2AccessType = 'Protection' AND @C2IsExclusive = 0
								BEGIN
									PRINT 'DO NOTHING'
								END
							ELSE
								BEGIN
									IF (SELECT COUNT(*) FROM #TmpExc WHERE TARID = @C2TARID) = 0
										BEGIN
											INSERT INTO #TmpExc
												(TARID, TARNo, TARType, AccessDate,AccessTimeSlot, AccessType, IsExclusive, EmailAdd)
											VALUES 
												(@C2TARID, @C2TARNo, @C2TARType, @C2AccessDate,@C2AccessTimeSlot, @C2AccessType, @C2IsExclusive, @C2EmailAdd)
										END
								END
						END
					ELSE
						BEGIN
							IF (SELECT COUNT(*) FROM #TmpExc WHERE TARID = @C2TARID) = 0
								BEGIN
									INSERT INTO #TmpExc
										(TARID, TARNo, TARType, AccessDate,AccessTimeSlot, AccessType, IsExclusive, EmailAdd)
									VALUES 
										(@C2TARID, @C2TARNo, @C2TARType, @C2AccessDate,@C2AccessTimeSlot, @C2AccessType, @C2IsExclusive, @C2EmailAdd)
								END
						END

					FETCH NEXT FROM @Cur02 INTO @C2TARID, @C2TARNo, @C2TARType, @C2AccessDate,@C2AccessTimeSlot, @C2AccessType, @C2IsExclusive, @C2SectorID, @C2SectorStr, @C2IsBuffer, @C2EmailAdd
				END 	

			CLOSE @Cur02
	
			DEALLOCATE @Cur02
			-- >> #TmpExcSector

			FETCH NEXT FROM @Cur01 INTO @CID, @CSectorID, @CIsBuffer, @CColourCode, @CIsAddBuffer
		END 	

	CLOSE @Cur01
	
	DEALLOCATE @Cur01

	-- >> Exception List. Sector Conflict, to show only if RequireValidation = True for current Level Endorser

DECLARE @Cur03 CURSOR;

DECLARE @C3TARID		INTEGER 
DECLARE @C3TARNo		NVARCHAR(20) 
DECLARE @C3TARType		NVARCHAR(20)
DECLARE @C3AccessDate	DATE
DECLARE @C3AccessTimeSlot NVARCHAR(20)
DECLARE @C3AccessType	NVARCHAR(20) 
DECLARE @C3IsExclusive	BIT
DECLARE @C3EmailAdd		NVARCHAR(200) 

-- >> Action Log
DECLARE @LogMsg	NVARCHAR(100)


-- >> #TmpExcSector
SET @Cur03 = CURSOR FAST_FORWARD 
FOR
	SELECT TARID, TARNo, TARType, AccessDate,AccessTimeSlot, AccessType, IsExclusive, EmailAdd 
		FROM #TmpExc
			ORDER BY TARID

OPEN @Cur03
	
FETCH NEXT FROM @Cur03 INTO @C3TARID, @C3TARNo, @C3TARType, @C3AccessDate, @C3AccessTimeSlot,@C3AccessType, @C3IsExclusive, @C3EmailAdd
	
WHILE @@FETCH_STATUS = 0 
	
	BEGIN
		
		-- >> NEL Cancel = 10 Else DTL or LRt = 9
		UPDATE TAMS_TAR
			SET TARStatusId = CASE WHEN @Line = 'NEL' THEN 10 ELSE 9 END,
				UpdatedOn = GETDATE(),
				UpdatedBy = @UserID
		WHERE Id = @C3TARID

		SET @LogMsg = 'TAR Form Cancelled by : ' + CAST(@UserName AS NVARCHAR(500)) + ' On ' + CAST(CONVERT(NVARCHAR(20), GETDATE(), 103) AS NVARCHAR(20)) + ' ' + CAST(CONVERT(NVARCHAR(20), GETDATE(), 108) AS NVARCHAR(20))
		INSERT INTO [dbo].[TAMS_Action_Log]
			([Line], [Module], [Function], [TransactionID], [LogMessage], [CreatedOn], [CreatedBy])
		VALUES 
			(@Line, 'TAR', 'Approval - Cancel', @C3TARID, @LogMsg, GETDATE(), @UserID)

		IF @TARType = 'Urgent' -- >> If Current TAR Type is Urgent then send Email
			BEGIN
				-- >> Cancel Urgent TAR
				SET @EMTARStatus = 'Cancelled'
				SET @EMMsg = ''

				EXEC sp_TAMS_Email_Cancel_TAR @C3TARID, @EMTARStatus, @C3TARNo, @C3EmailAdd, @EMMsg OUTPUT

			END
		
		FETCH NEXT FROM @Cur03 INTO @C3TARID, @C3TARNo, @C3TARType, @C3AccessDate,@C3AccessTimeSlot, @C3AccessType, @C3IsExclusive, @C3EmailAdd
	END 	

CLOSE @Cur03
	
DEALLOCATE @Cur03
-- >> #TmpExcSector

	-- >> Get Exception TARs - Sector Conflict

UPDATE TAMS_TAR_Workflow
	SET WFStatus = 'Approved',
		ActionBy = @UserID,
		ActionOn = GETDATE()
	WHERE ID =  @TARWFID

DECLARE @NextEndID		INTEGER
DECLARE @NextEndTitle	NVARCHAR(100)
DECLARE @NextWFID		INTEGER
DECLARE @NextWFStatID	INTEGER
DECLARE @NextRoleID		INTEGER

-- >> Next Level Endorser
SELECT @NextEndID = ID, 
		@NextEndTitle = Title,
		@NextWFID = WorkflowId,
		@NextWFStatID = WFStatusId,
		@NextRoleID = RoleId
	FROM TAMS_Endorser
		WHERE WorkflowId = @WFID
			AND [Level] = @ELevel + 1

IF ISNULL(@NextEndTitle, '') = ''
	BEGIN
		-- >> If NEL Approved = 9 Else DTL or LRT = 8
		UPDATE TAMS_TAR
			SET TARStatusId = CASE WHEN @Line = 'NEL' THEN 9 ELSE 8 END,
				UpdatedOn = GETDATE(),
				UpdatedBy = @UserID
			WHERE ID = @TARID

		IF @TARType = 'Urgent'
			BEGIN
				SET @EMTARStatus = 'Approved'
				SET @EMMsg = ''

				EXEC sp_TAMS_Email_Urgent_TAR @EMTARID, @EMTARStatus, @EMTARNo, @EMRemarks, @EMActor, @EMToSend, @EMMsg OUTPUT
			END

	END
ELSE
	BEGIN

		IF (SELECT COUNT(*) FROM TAMS_TAR_Workflow
			WHERE TARId = @TARID
				AND WorkflowId = @NextWFID
				AND EndorserId = @NextEndID) = 0
			BEGIN	
				INSERT INTO [dbo].[TAMS_TAR_Workflow]
					([TARId], [WorkflowId], [EndorserId], [UserId], [WFStatus], [Remark], [ActionOn], [ActionBy])
				VALUES
					(@TARID, @NextWFID, @NextEndID, NULL, 'Pending', '', GETDATE(), @UserID)
			END

		UPDATE TAMS_TAR
			SET TARStatusId = @NextWFStatID,
				UpdatedOn = GETDATE(),
				UpdatedBy = @UserID
			WHERE Id = @TARID

		IF @TARType = 'Urgent'
			BEGIN
				-- >> NEXT ROLE ID EMAIL ALERT
				-- >> PRINT 'Urgent Email'
				DECLARE @RoleEmail	NVARCHAR(1000)
				SET @RoleEmail = ''
				SET @EMMsg = ''

				SELECT @RoleEmail = @RoleEmail + ISNULL(a.Email + ', ', '') 
					FROM TAMS_User a, TAMS_User_Role b
						WHERE a.Userid = b.UserID
							AND a.IsActive = 1
							AND @TARDate BETWEEN a.ValidFrom AND a.ValidTo
							AND b.RoleID = @NextEndID

				IF LEN(LTRIM(RTRIM(@RoleEmail))) > 0
					BEGIN
						SET @RoleEmail = LEFT(LTRIM(RTRIM(@RoleEmail)), LEN(LTRIM(RTRIM(@RoleEmail))) - 1)
					END

				-- >> Select all email where role id = next role id
				SET @EMToSend = @RoleEmail

				-- >> 2024-01-31 Changes to add nelocc email to the recipient list for Urgent After and if next level is OCC Approval
				DECLARE @WFTypeChk	NVARCHAR(50)

				SELECT @WFTypeChk = WorkflowType
					FROM TAMS_Workflow
						WHERE ID = @WFID

				IF @WFTypeChk = 'UrgentAfter' AND @NextEndTitle = 'SDS Approval'
					BEGIN 
						declare @SDSEmailForUrgent as nvarchar(100);
						set @SDSEmailForUrgent = '';
						
						SELECT @SDSEmailForUrgent = ParaValue3 
							FROM TAMS_Parameters
								WHERE ParaCode = 'SDSContact'
									AND ParaValue1 = @Line
									AND LTRIM(RTRIM(ISNULL(ParaValue3, ''))) <> ''

						IF LEN(LTRIM(RTRIM(@EMToSend))) > 0
							BEGIN
								-- >> 2024-01-16 Changes to add nelocc email to the recipient list 
						 		SET @EMToSend = @EMToSend + ', ' + @SDSEmailForUrgent
							END
					END;
				-- >> 2024-01-31 Changes to add nelocc email to the recipient list for Urgent After and if next level is OCC Approval

				EXEC sp_TAMS_Email_Apply_Urgent_TAR 2, @EMCompany, @EMTARNo, @NextEndTitle, @EMToSend, @EMCCSend, @EMMsg OUTPUT
			END
	END

	-- >> SET @LogMsg = 'TAR Form has approved by : ' + '' + ' On ' + GETDATE()	
	SET @LogMsg = 'TAR Form Approved by : ' + CAST(@UserName AS NVARCHAR(500)) + ' On ' + CAST(CONVERT(NVARCHAR(20), GETDATE(), 103) AS NVARCHAR(20)) + ' ' + CAST(CONVERT(NVARCHAR(20), GETDATE(), 108) AS NVARCHAR(20))
		
	INSERT INTO [dbo].[TAMS_Action_Log]
		([Line], [Module], [Function], [TransactionID], [LogMessage], [CreatedOn], [CreatedBy])
	VALUES 
		(@Line, 'TAR', 'Approved TAR', @TARID, @LogMsg, GETDATE(), @UserID)

DECLARE @WFType	NVARCHAR(50)
DECLARE @InvPow	BIT

SELECT @WFType = WorkflowType,
		@InvPow = InvolvePower 
	FROM TAMS_Workflow
		WHERE ID = @WFID

IF @WFType = 'UrgentAfter' AND @InvPow = 1 AND @ELevel = 2
	BEGIN
		-- >> TAMS_DTL_PFR
		-- >> PRINT 'EMAIL'

		DECLARE @SDSEmail	NVARCHAR(1000)
		DECLARE @SDSRole	NVARCHAR(50)
		DECLARE @SDSEmailAdd	NVARCHAR(100)

		SET @SDSEmail = ''
		SET @SDSEmailAdd = ''
		SET @SDSRole = @Line + '_PFR'
		SET @EMTARStatus = 'Approved'
		SET @EMMsg = ''

		SELECT @SDSEmail = @SDSEmail + ISNULL(a.Email + ', ', '') 
			FROM TAMS_User a, TAMS_User_Role b, TAMS_Role c
				WHERE a.Userid = b.UserID
					AND b.RoleID = c.ID
					AND a.IsActive = 1
					AND @TARDate BETWEEN a.ValidFrom AND a.ValidTo
					AND c.Role = @SDSRole

		-- >> 2024-01-16 Changes to add nelocc email to the recipient list 
		SELECT @SDSEmailAdd = ParaValue3 
			FROM TAMS_Parameters
				WHERE ParaCode = 'SDSContact'
					AND ParaValue1 = @Line
					AND LTRIM(RTRIM(ISNULL(ParaValue3, ''))) <> ''

		IF LEN(LTRIM(RTRIM(@SDSEmail))) > 0
			BEGIN
				-- >> 2024-01-16 Changes to add nelocc email to the recipient list 
				SET @SDSEmail = LEFT(LTRIM(RTRIM(@SDSEmail)), LEN(LTRIM(RTRIM(@SDSEmail))) - 1)
				SET @SDSEmail = @SDSEmail + ', ' + @SDSEmailAdd
			END

		EXEC sp_TAMS_Email_Urgent_TAR_OCC @TARID, @EMTARStatus, @EMTARNo, @Remarks, @SDSEmail, @EMMsg OUTPUT
	END

-- >>

IF @@ERROR <> 0 BEGIN
	SET @Message = 'ERROR INSERTING INTO TAMS_TAR'
	GOTO TRAP_ERROR
END

FORCE_EXIT_PROC:	
	IF @IntrnlTrans = 1 COMMIT TRAN
	RETURN @Message 

TRAP_ERROR:
	IF @IntrnlTrans = 1 ROLLBACK TRAN
	RETURN @Message

END
GO
/****** END PROCEDURE 39 ******/

/****** START PROCEDURE 40 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_Approval_Reject
CREATE   procedure [dbo].[sp_TAMS_Approval_Reject]
	@TARID		AS INTEGER,						-- >> TAR ID
	@TARWFID	AS INTEGER,						-- >> Current WF ID
	@EID		AS INTEGER,						-- >> Current Endorser ID
	@ELevel		AS INTEGER,						-- >> Current Endorser Level
	@Remarks	AS NVARCHAR(1000) = NULL,		-- >> Remarks -- Mandatory for Reject / Optional for Approved / Endorse
	@UserLI		AS NVARCHAR(100) = NULL,			-- >> User Login ID	
	@Message	AS NVARCHAR(500) = NULL OUTPUT	
AS

BEGIN

DECLARE	@IntrnlTrans	TINYINT
SELECT 	@IntrnlTrans 	= 0	

IF (@@TRANCOUNT = 0) 
BEGIN
	SET @IntrnlTrans = 1
	BEGIN TRAN
END

-- >>
SET @Message = ''

DECLARE @UserID		INTEGER
DECLARE @UserName NVARCHAR(500)

DECLARE @EMTARID		INTEGER
DECLARE @EMTARStatus	NVARCHAR(20)
DECLARE @EMTARNo		NVARCHAR(50)
DECLARE @EMRemarks		NVARCHAR(1000)
DECLARE @EMActor		NVARCHAR(100)
DECLARE @EMToSend		NVARCHAR(1000)
DECLARE @EMCCSend		NVARCHAR(1000)
DECLARE @EMCompany		NVARCHAR(100)
DECLARE @EMMsg			NVARCHAR(500)

DECLARE @TARDate		DATE

SELECT @UserID = Userid, @UserName = [Name]
FROM TAMS_User
	WHERE LoginId = @UserLI

UPDATE TAMS_TAR_Workflow
	SET WFStatus = 'Rejected',
		Remark = @Remarks,
		ActionBy = @UserID,
		ActionOn = GETDATE()
	WHERE ID =  @TARWFID

DECLARE @EndTitle	NVARCHAR(100)
DECLARE @TARType	NVARCHAR(20)
DECLARE @WFID		INTEGER
DECLARE @Line		NVARCHAR(10)

SELECT @EndTitle = Title 
	FROM TAMS_Endorser
		WHERE ID = @EID

SELECT @TARType = TARType,
		@Line = Line,
		@EMToSend = Email,		-- >> ToSendEmail
		@EMCCSend = Email,
		@EMTARID = Id,
		@EMTARNo = TARNo,
		@EMRemarks = ARRemark,
		@EMCompany = Company,
		@TARDate = AccessDate 
	FROM TAMS_TAR
		WHERE ID = @TARID

SELECT @WFID = WorkflowId 
	FROM TAMS_TAR_Workflow
		WHERE ID = @TARWFID

-- >> Current Level Endorser
SELECT @EMActor = Title
	FROM TAMS_Endorser
		WHERE WorkflowId = @WFID
			AND [Level] = @ELevel

-- >> If NEL Rejected = 8 Else DTL or LRT = 7
UPDATE TAMS_TAR
	SET TARStatusId = CASE WHEN @Line = 'NEL' THEN 8 ELSE 7 END,
		UpdatedOn = GETDATE(),
		UpdatedBy = @UserID
	WHERE ID = @TARID

IF @TARType = 'Urgent'
	BEGIN
		-- >> Rejected EMAIL
		-- >> PRINT 'Urgent Email'
		SET @EMTARStatus = 'Rejected'
		SET @EMMsg = ''

		EXEC sp_TAMS_Email_Urgent_TAR @EMTARID, @EMTARStatus, @EMTARNo, @EMRemarks, @EMActor, @EMToSend, @EMMsg OUTPUT
	END

-- >> Action Log

DECLARE @LogMsg	NVARCHAR(100)
SET @LogMsg = 'TAR Form Rejected by : ' + CAST(@UserName AS NVARCHAR(500)) + ' On ' + CAST(CONVERT(NVARCHAR(20), GETDATE(), 103) AS NVARCHAR(20)) + ' ' + CAST(CONVERT(NVARCHAR(20), GETDATE(), 108) AS NVARCHAR(20))
INSERT INTO [dbo].[TAMS_Action_Log]
	([Line], [Module], [Function], [TransactionID], [LogMessage], [CreatedOn], [CreatedBy])
VALUES 
	(@Line, 'TAR', 'Approval - Rejected', @TARID, @LogMsg, GETDATE(), @UserID)

DECLARE @WFType	NVARCHAR(50)
DECLARE @InvPow	BIT

SELECT @WFType = WorkflowType,
		@InvPow = InvolvePower 
	FROM TAMS_Workflow
		WHERE ID = @WFID

IF @WFType = 'UrgentAfter' AND @InvPow = 1 AND @ELevel = 2
	BEGIN
		-- >> TAMS_DTL_PFR
		-- >> PRINT 'EMAIL'

		DECLARE @OCCEmail	NVARCHAR(1000)
		DECLARE @OCCRole	NVARCHAR(50)
		DECLARE @OCCEmailAdd	NVARCHAR(100)

		SET @OCCEmail = ''
		SET @OCCEmailAdd = ''
		SET @OCCRole = @Line + '_PFR'
		SET @EMTARStatus = 'Rejected'
		SET @EMMsg = ''

		SELECT @OCCEmail = @OCCEmail + ISNULL(a.Email + ', ', '') 
			FROM TAMS_User a, TAMS_User_Role b, TAMS_Role c
				WHERE a.Userid = b.UserID
					AND b.RoleID = c.ID
					AND a.IsActive = 1
					AND @TARDate BETWEEN a.ValidFrom AND a.ValidTo
					AND c.Role = @OCCRole

		-- >> 2024-01-16 Changes to add nelocc email to the recipient list 
		SELECT @OCCEmailAdd = ParaValue3 
			FROM TAMS_Parameters
				WHERE ParaCode = 'OCCContact'
					AND ParaValue1 = @Line
					AND LTRIM(RTRIM(ISNULL(ParaValue3, ''))) <> ''

		IF LEN(LTRIM(RTRIM(@OCCEmail))) > 0
			BEGIN
				-- >> 2024-01-16 Changes to add nelocc email to the recipient list 
				SET @OCCEmail = LEFT(LTRIM(RTRIM(@OCCEmail)), LEN(LTRIM(RTRIM(@OCCEmail))) - 1)
				SET @OCCEmail = @OCCEmail + ', ' + @OCCEmailAdd
			END

		EXEC sp_TAMS_Email_Urgent_TAR_OCC @TARID, @EMTARStatus, @EMTARNo, @Remarks, @OCCEmail, @EMMsg OUTPUT
	END

-- >>

IF @@ERROR <> 0 BEGIN
	SET @Message = 'ERROR INSERTING INTO TAMS_TAR'
	GOTO TRAP_ERROR
END

FORCE_EXIT_PROC:	
	IF @IntrnlTrans = 1 COMMIT TRAN
	RETURN @Message 

TRAP_ERROR:
	IF @IntrnlTrans = 1 ROLLBACK TRAN
	RETURN @Message

END
GO
/****** END PROCEDURE 40 ******/

