--INSERT INTO #TmpAppList
--SELECT t.Id, t.TARNo, t.TARType, t.AccessType, t.Company, ws.WFStatus, t.AccessDate, ts.SectorId, s.Sector,  CASE WHEN s.Direction IN ('BB', 'NB') THEN 1 ELSE 2 END
--	FROM TAMS_TAR t, TAMS_TAR_Sector ts, TAMS_WFStatus ws, TAMS_Sector s
