/****** START PROCEDURE 56 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_Depot_Approval_OnLoad
CREATE PROCEDURE [dbo].[sp_TAMS_Depot_Approval_OnLoad]
	@TARID		BIGINT,
	@LogInUser	NVARCHAR(20)
AS

BEGIN

	DECLARE @Line			NVARCHAR(10)
	DECLARE @TrackType		NVARCHAR(10)
	DECLARE @AccessDate		DATE
	DECLARE @AccessTimeSlot NVARCHAR(50)
	DECLARE @TARType		NVARCHAR(50)
	DECLARE @AccessType		NVARCHAR(50)
	DECLARE @IsExclusive	BIT

	SELECT @Line		= Line,
		@TrackType		= Tracktype,
		@AccessDate		= AccessDate,
		@AccessTimeSlot = AccessTimeSlot,
		@TARType		= TARType,
		@AccessType		= AccessType,
		@IsExclusive	= IsExclusive
	FROM TAMS_TAR
		WHERE ID = @TARID

	-- >> Table[0]
	SELECT [Id], [Line], [TARNo], [TARType],
		[Company], [Designation], [Name], [OfficeNo], [MobileNo], [Email],
		[SubmitDate], 
		CONVERT(NVARCHAR(20), [AccessDate], 103) AS [AccessDate], 
		[AccessTimeSlot],
		[AccessTimeFrom], 
		[AccessTimeTo], 
		[AccessLocation], [AccessType],
		[IsNeutralGap], [IsExclusive],
		[DescOfWork], [ARRemark], 
		[TARStatusId],
		[InvolvePower], [PowerOn], [Is13ASocket],
		[CrossOver], [TVFMode], ProtectionType
	FROM TAMS_TAR
		WHERE ID = @TARID

-- >> Sector

	DECLARE @SelSectorNotGap	NVARCHAR(1000)
	DECLARE @SelSectorGap		NVARCHAR(1000)
	DECLARE @PowerZone			NVARCHAR(1000)
	DECLARE @SPKSZone			NVARCHAR(1000)
	
	SET @SelSectorNotGap = ''
	SET @SelSectorGap = ''
	SET @PowerZone = ''
	SET @SPKSZone = ''

	-- EXEC sp_TAMS_Form_OnLoad 'NEL', '01/02/2021', 'Possession', '143;144;145;180;181;182'

	-- >> Selected Sector IsGap = 0
	SELECT @SelSectorNotGap = @SelSectorNotGap + ISNULL(b.Sector + ', ', '') 
		FROM TAMS_TAR_Sector a, TAMS_Sector b
			WHERE a.TARId = @TARID
				AND a.IsBuffer = 0
				AND a.SectorId = b.ID
				AND ISNULL(b.IsGap, 0) = 0
			GROUP BY b.Sector
			-- >> ORDER BY b.[Order]

	IF LEN(LTRIM(RTRIM(@SelSectorNotGap))) > 0
		BEGIN
			SET @SelSectorNotGap = LEFT(LTRIM(RTRIM(@SelSectorNotGap)), LEN(LTRIM(RTRIM(@SelSectorNotGap))) - 1)
		END

		SELECT @PowerZone = @PowerZone + ISNULL(PowerSector + ', ', '') 
			FROM TAMS_Power_Sector a, TAMS_TAR_Power_Sector b	
				WHERE a.ID = b.PowerSectorId
					AND a.IsActive = 1 
					and b.IsBuffer = 0 
					and b.TARId = @TARID
		GROUP BY PowerSector		

		IF LEN(LTRIM(RTRIM(@PowerZone))) > 0
		BEGIN
			SET @PowerZone = LEFT(LTRIM(RTRIM(@PowerZone)), LEN(LTRIM(RTRIM(@PowerZone))) - 1)
		END

		SELECT @SPKSZone = @SPKSZone + ISNULL(a.SPKSZone + ', ', '') 
			FROM TAMS_SPKSZone a, TAMS_TAR_SPKSZone b	
				WHERE a.ID = b.SPKSZoneId
					AND a.IsActive = 1	
					and b.TARId = @TARID
 		GROUP BY a.SPKSZone		

	IF LEN(LTRIM(RTRIM(@SPKSZone))) > 0
		BEGIN
			SET @SPKSZone = LEFT(LTRIM(RTRIM(@SPKSZone)), LEN(LTRIM(RTRIM(@SPKSZone))) - 1)
		END


	-- >> Table[1]
	SELECT @SelSectorNotGap AS SelSectorNotGap,
		@SelSectorGap AS SelSectorGap,
		@PowerZone AS PowerZone,@SPKSZone as SPKSZone


	-- >> Table[2]
	SELECT a.IsSelected, b.OperationRequirement, a.IsAttachment, a.ID AS ID, 
		(SELECT COUNT(*) FROM TAMS_TAR_Attachment c WHERE c.TARAccessReqId = a.ID) AS AttCtr 
	FROM [dbo].[TAMS_TAR_AccessReq] a, [dbo].[TAMS_Access_Requirement] b
		WHERE a.TARId = @TARID
			AND a.IsSelected = 1
			AND a.IsPower = 0
			AND a.OperationRequirement = b.ID
			AND b.IsActive = 1
		ORDER BY a.[Order]

	-- >> Table[3]
	SELECT a.IsSelected, b.OperationRequirement, b.ID 
	FROM [dbo].[TAMS_TAR_AccessReq] a, [dbo].[TAMS_Access_Requirement] b
		WHERE a.TARId = @TARID
			AND a.IsSelected = 1
			AND a.IsPower = 1
			AND a.OperationRequirement = b.ID
			AND b.IsActive = 1
		ORDER BY a.[Order]

	DECLARE @PossID		INT
	DECLARE @PowerOnOff	INT
	DECLARE @TypeOfWork	INT

	SELECT @PossID = [ID],
		@PowerOnOff = [PowerOnOff],
		@TypeOfWork = [TypeOfWorkId]
	  FROM [dbo].[TAMS_Possession]
		WHERE TARId = @TARID

	-- >> Table[4]
	SELECT [ID], [TARId],
		[Summary], [WorkDesc], [TypeOfWorkId], 
		[WorkWithinPossession], [TakePossession], [GiveUpPossession],
		[Remarks], 
		[PowerOnOff],
		[EngTrainFormation],
		[EngTrainArriveLoc], [EngTrainArriveTime],
		[EngTrainDepartLoc], [EngTrainDepartTime],
		[PCName]
	  FROM [dbo].[TAMS_Possession]
		WHERE TARId = @TARID

	-- >> Table[5]
	SELECT ID, TypeOfProtectionLimit, RedFlashingLampsLoc 
		FROM [dbo].[TAMS_Possession_Limit]
			WHERE PossessionId = @PossID
				ORDER BY ID

	-- >> Table[6]
	SELECT ID, RedFlashingLampsLoc 
		FROM [dbo].[TAMS_Possession_WorkingLimit]
			WHERE PossessionId = @PossID
				ORDER BY ID

	-- >> Table[7]
	SELECT ID, OtherProtection 
		FROM [dbo].[TAMS_Possession_OtherProtection]
			WHERE PossessionId = @PossID
				ORDER BY ID

	-- >> Table[8]
	SELECT ID, Sector, case when PowerOff = 1 then 'Y' else 'N' end AS poweroff, NoOFSCD, 
			CASE WHEN BreakerOut = 1 THEN 'Y' ELSE 'N' END AS BreakerOut
		FROM [dbo].[TAMS_Possession_DepotSector]
			WHERE PossessionId = @PossID
				ORDER BY ID
			
	-- >> Table[9]
	SELECT TypeOfWork 
		FROM TAMS_Type_Of_Work
			WHERE ID = @TypeOfWork
				AND IsActive = 1

	-- >> For Approval and Showing of Level

	DECLARE @MaxWFCtr		INT
	DECLARE @PendingWFCtr	INT
	DECLARE @ApprovedWFCtr	INT

	-- >> Get Max Workflow
	SELECT @MaxWFCtr = MAX(b.Level)
		FROM TAMS_TAR_Workflow a, TAMS_Endorser b
			WHERE a.WorkflowId = b.WorkflowId
				--AND a.EndorserId = b.ID
				AND a.TARId = @TARID

	SELECT @ApprovedWFCtr = COUNT(*)
		FROM TAMS_TAR_Workflow a, TAMS_Endorser b
			WHERE a.WorkflowId = b.WorkflowId
				AND a.EndorserId = b.ID
				AND a.TARId = @TARID
				AND a.WFStatus = 'Approved'

	SELECT @PendingWFCtr = COUNT(*)
		FROM TAMS_TAR_Workflow a, TAMS_Endorser b
			WHERE a.WorkflowId = b.WorkflowId
				AND a.EndorserId = b.ID
				AND a.TARId = @TARID
				AND a.WFStatus = 'Pending'

	-- >> Table[10]
	SELECT @MaxWFCtr AS MaxWFCtr, @ApprovedWFCtr AS AppWFCtr, @PendingWFCtr AS PendWFCtr

	-- >> Table[11]
	-- >> Workflow -- Approved
	SELECT a.TARId, a.UserId, a.WFStatus, a.Remark, a.ActionOn, a.ActionBy, c.[Name] AS ActionByName,
			b.RoleId, b.Title, b.RequireValidation, b.RequireTVF, b.WFStatusId, a.ID AS WFID, b.ID AS EID, b.Level
		FROM TAMS_TAR_Workflow a, TAMS_Endorser b, TAMS_User c
			WHERE a.WorkflowId = b.WorkflowId
				AND a.EndorserId = b.ID
				AND a.ActionBy = c.Userid
				AND a.TARId = @TARID
				AND a.WFStatus <> 'Pending'
			ORDER BY a.ID

	DECLARE @UserName	NVARCHAR(200)

	SELECT @UserName = [Name] FROM TAMS_User
		WHERE LoginId = @LogInUser

	-- >> Table[12]
	-- >> Workflow -- Pending
	SELECT a.TARId, a.UserId, a.WFStatus, a.Remark, a.ActionOn, a.ActionBy, c.[Name] AS ActionByName,
			b.RoleId, b.Title, b.RequireValidation, b.RequireTVF, b.RequireBuffer, b.WFStatusId, a.ID AS WFID, b.ID AS EID, b.Level, @UserName AS UserName
		FROM TAMS_TAR_Workflow a, TAMS_Endorser b, TAMS_User c
			WHERE a.WorkflowId = b.WorkflowId
				AND a.EndorserId = b.ID
				AND a.ActionBy = c.Userid
				AND a.TARId = @TARID
				AND a.WFStatus = 'Pending'
			ORDER BY a.ID

	--EXEC sp_TAMS_Approval_OnLoad 5, 'CSAPEX57'
	--EXEC sp_TAMS_Approval_OnLoad 4, 'CSAPEX57'
	
	-- >> Buffer Zone -- Additional
	-- >> Table[13]
	SELECT sect.Sector,
			sect.ID 
		FROM TAMS_Sector sect
			WHERE sect.ID NOT IN (SELECT SectorId 
					FROM TAMS_TAR_Sector ts LEFT JOIN TAMS_TAR t ON t.Id = ts.TARId
						WHERE (t.Id = @TarID OR
							(
							  ((t.TARStatusId = 8 and  t.Line = 'DTL') or (t.TARStatusId = 9 and  t.Line = 'NEL'))
							--t.TARStatusId = 8 
								AND t.AccessDate = @AccessDate
								AND t.AccessTimeSlot = @AccessTimeSlot
								AND t.Line = @Line)))
				AND sect.Line = @Line
				AND sect.TrackType = @TrackType
				AND sect.IsActive = 1
				AND @AccessDate BETWEEN sect.EffectiveDate AND sect.ExpiryDate
			ORDER BY sect.ID

	-- >> Buffer Zone -- Additional
	-- >> Table[14]
	SELECT a.Sector AS StrSector, a.ID AS SectorID
		FROM TAMS_Sector a, TAMS_TAR_Sector b
			WHERE a.ID = b.SectorId
				AND b.TARId = @TARID
				AND b.IsBuffer = 1
		ORDER BY a.ID

	 

	-- >> Get Exception TARs - Sector Conflict
	CREATE TABLE #TmpExc 
	(TARID			BIGINT,
	TARNo			NVARCHAR(20),
	TARType			NVARCHAR(10),
	AccessDate		NVARCHAR(20),
	AccessTimeSlot		NVARCHAR(50),
	AccessType		NVARCHAR(20),
	IsExclusive		INT)

	CREATE TABLE #TmpExcSector 
	(TARID			BIGINT,
	TARNo			NVARCHAR(20),
	TARType			NVARCHAR(10),
	AccessDate		NVARCHAR(20),
	AccessTimeSlot		NVARCHAR(50),
	AccessType		NVARCHAR(20),
	IsExclusive		INT,
	SectorID		INT,
	SectorStr		NVARCHAR(50),
	IsBuffer		INT)
	
	TRUNCATE TABLE #TmpExc
	TRUNCATE TABLE #TmpExcSector

	DECLARE @Cur01 CURSOR;

	DECLARE @CID			INTEGER
	DECLARE @CSectorID		INTEGER
	DECLARE @CIsBuffer		BIT
	DECLARE @CColourCode	NVARCHAR(20)
	DECLARE @CIsAddBuffer	BIT

	DECLARE @Cur02 CURSOR;

	DECLARE @C2TARID		INTEGER 
	DECLARE @C2TARNo		NVARCHAR(20) 
	DECLARE @C2TARType		NVARCHAR(20)
	DECLARE @C2AccessDate	DATE
	DECLARE @C2AccessTimeSlot nvarchar(50)
	DECLARE @C2AccessType	NVARCHAR(20) 
	DECLARE @C2IsExclusive	BIT
	DECLARE @C2SectorID		INTEGER 
	DECLARE @C2SectorStr	NVARCHAR(20) 
	DECLARE @C2IsBuffer		BIT 

	SET @Cur01 = CURSOR FAST_FORWARD 
	FOR
		SELECT ID, SectorId, IsBuffer, ColourCode, IsAddedBuffer FROM TAMS_TAR_Sector
			WHERE TARId = @TARID
				ORDER BY SectorId

	OPEN @Cur01
	
	FETCH NEXT FROM @Cur01 INTO @CID, @CSectorID, @CIsBuffer, @CColourCode, @CIsAddBuffer
	
	WHILE @@FETCH_STATUS = 0 
	
		BEGIN
			print @CSectorID;
			print '@CSectorID';
			IF @CIsBuffer = 1
				BEGIN
					-- >> Is Buffer
					 PRINT 'here 1';
					INSERT INTO #TmpExcSector
						(TARID, TARNo, TARType, AccessDate,AccessTimeSlot, AccessType, IsExclusive, SectorID, SectorStr, IsBuffer)
					SELECT t.Id, t.TARNo, t.TARType, t.AccessDate, t.AccessTimeSlot,t.AccessType, t.IsExclusive,
							ts.SectorId, s.Sector, ts.IsBuffer 
						FROM TAMS_TAR t, TAMS_TAR_Sector ts, TAMS_Sector s
							WHERE t.Id = ts.TARId
								AND s.ID = ts.SectorId
								AND t.AccessDate = @AccessDate
								AND t.AccessTimeSlot = @AccessTimeSlot
								AND ts.IsBuffer = 0
								AND ((t.TARStatusId = 8 and  t.Line = 'DTL') or (t.TARStatusId = 9 and  t.Line = 'NEL'))
								--AND t.TARStatusId = 8
								AND ts.SectorId = @CSectorID
								AND t.Id <> @TARID
								AND s.IsActive = 1
								AND @AccessDate BETWEEN s.EffectiveDate and S.ExpiryDate
				END
			ELSE
				BEGIN
					-- >> Not Buffer
					  PRINT 'here 2';
					INSERT INTO #TmpExcSector
						(TARID, TARNo, TARType, AccessDate, AccessType, IsExclusive, SectorID, SectorStr, IsBuffer)
					SELECT t.Id, t.TARNo, t.TARType, t.AccessDate, t.AccessType, t.IsExclusive,
							ts.SectorId, s.Sector, ts.IsBuffer 
						FROM TAMS_TAR t, TAMS_TAR_Sector ts, TAMS_Sector s
							WHERE t.Id = ts.TARId
								AND s.ID = ts.SectorId
								AND t.AccessDate = @AccessDate
								AND t.AccessTimeSlot = @AccessTimeSlot 
								-- >> AND ts.IsBuffer = 0
								AND ((t.TARStatusId = 8 and  t.Line = 'DTL') or (t.TARStatusId = 9 and  t.Line = 'NEL'))
								--AND t.TARStatusId = 8
								AND ts.SectorId = @CSectorID
								AND t.Id <> @TARID
								AND s.IsActive = 1
								AND @AccessDate BETWEEN s.EffectiveDate and S.ExpiryDate
 
				END
				
			-- >> #TmpExcSector
			SET @Cur02 = CURSOR FAST_FORWARD 
			FOR
				SELECT TARID, TARNo, TARType, AccessDate,AccessTimeSlot, AccessType, IsExclusive, SectorID, SectorStr, IsBuffer 
					FROM #TmpExcSector
							ORDER BY TARID, SectorID

			OPEN @Cur02
	
			FETCH NEXT FROM @Cur02 INTO @C2TARID, @C2TARNo, @C2TARType, @C2AccessDate,@C2AccessTimeSlot, @C2AccessType, @C2IsExclusive, @C2SectorID, @C2SectorStr,@C2IsBuffer
	
			WHILE @@FETCH_STATUS = 0 
	
				BEGIN
					IF @AccessType = 'Protection' AND @IsExclusive = 0
						BEGIN
							print 1
							IF @C2AccessType = 'Protection' AND @C2IsExclusive = 0
								BEGIN

									PRINT 'DO NOTHING'
								END
							ELSE
								BEGIN
									IF (SELECT COUNT(*) FROM #TmpExc WHERE TARID = @C2TARID) = 0
										BEGIN
											INSERT INTO #TmpExc
												(TARID, TARNo, TARType, AccessDate, AccessTimeSlot,AccessType, IsExclusive)
											VALUES 
												(@C2TARID, @C2TARNo, @C2TARType, @C2AccessDate,@C2AccessTimeSlot, @C2AccessType, @C2IsExclusive)
										END
								END
						END
					ELSE
						BEGIN
							IF (SELECT COUNT(*) FROM #TmpExc WHERE TARID = @C2TARID) = 0
								BEGIN
									INSERT INTO #TmpExc
										(TARID, TARNo, TARType, AccessDate,AccessTimeSlot, AccessType, IsExclusive)
									VALUES 
										(@C2TARID, @C2TARNo, @C2TARType, @C2AccessDate, @C2AccessTimeSlot,@C2AccessType, @C2IsExclusive)
								END
						END

					FETCH NEXT FROM @Cur02 INTO @C2TARID, @C2TARNo, @C2TARType, @C2AccessDate,@C2AccessTimeSlot, @C2AccessType, @C2IsExclusive, @C2SectorID, @C2SectorStr,@C2IsBuffer
				END 	

			CLOSE @Cur02
	
			DEALLOCATE @Cur02
			-- >> #TmpExcSector

			FETCH NEXT FROM @Cur01 INTO @CID, @CSectorID, @CIsBuffer, @CColourCode, @CIsAddBuffer
		END 	

	CLOSE @Cur01
	
	DEALLOCATE @Cur01

	-- >> Exception List. Sector Conflict, to show only if RequireValidation = True for current Level Endorser
	-- >> Table[15]
	SELECT TARID, TARNo, TARType, AccessDate, AccessType, IsExclusive 
		FROM #TmpExc

	-- >> Table[16]
	IF @AccessType = 'Protection'
		BEGIN
			SELECT ID, OperationRequirement 
				FROM TAMS_Access_Requirement
					WHERE Line = @Line
						AND IsPowerReq = 1
						and TrackType = @TrackType
						AND OperationRequirement = 'Traction Power ON'
						AND IsActive = 1
					ORDER BY [Order]
		END
	ELSE
		BEGIN
			SELECT ID, OperationRequirement 
				FROM TAMS_Access_Requirement
					WHERE Line = @Line
					and TrackType = @TrackType
						AND IsPowerReq = 1
						AND IsActive = 1
					ORDER BY [Order]
		END
END
GO
/****** END PROCEDURE 56 ******/

/****** START PROCEDURE 57 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_Depot_Form_OnLoad
CREATE procedure  [dbo].[sp_TAMS_Depot_Form_OnLoad]
	@Line		AS NVARCHAR(10) = NULL,
	@TrackType	AS NVARCHAR(50) = NULL,
	@AccessDate	AS NVARCHAR(20) = NULL,
	@AccessType	AS NVARCHAR(20) = NULL,
	@Sectors	AS NVARCHAR(2000) = NULL,
	@PowerSelTxt	AS NVARCHAR(100) = NULL
AS

BEGIN

	DECLARE @isDWONLY as int; 
	set @isDWONLY = 0; 
	DECLARE @DWSectors as nvarchar(500);
	SELECT @DWSectors = ParaValue2 
	FROM TAMS_Parameters
	WHERE ParaCode = 'DWSectors'
	AND ParaValue1 = @Line
	AND CONVERT(DATETIME, @AccessDate, 103) BETWEEN EffectiveDate AND ExpiryDate


	-- check the selection sector is DW only ?
	SELECT @isDWONLY = CASE WHEN (
	   SELECT ISNULL( COUNT(*),0)
	   FROM STRING_SPLIT(@Sectors, ';')
	   WHERE VALUE not IN (
	   SELECT VALUE
	   FROM STRING_SPLIT(@DWSectors, ';'))
	 ) = 0
	 AND (
	   SELECT ISNULL( COUNT(*),0)
	   FROM STRING_SPLIT(@DWSectors, ';')
	   WHERE VALUE not IN (
	   SELECT VALUE
	   FROM STRING_SPLIT(@Sectors, ';'))
	 ) = 0
	THEN 1
	ELSE 0 END  


	SELECT ParaValue1, ParaValue2 
		FROM TAMS_Parameters
			WHERE ParaCode = 'Company'
				AND ParaValue1 = @Line
				AND CONVERT(DATETIME, @AccessDate, 103) BETWEEN EffectiveDate AND ExpiryDate
			ORDER BY [Order]

	SELECT ROW_NUMBER() OVER(ORDER BY ID) as Sno, ID, OperationRequirement, IsAttachment 
		FROM TAMS_Access_Requirement
			WHERE Line = @Line
			AND TrackType= @TrackType
				AND IsPowerReq = 0
				AND IsActive = 1
			ORDER BY [Order]

	IF @AccessType = 'Protection'
		BEGIN
			SELECT ID, OperationRequirement 
				FROM TAMS_Access_Requirement
					WHERE Line = @Line
					and TrackType = @TrackType
						AND IsPowerReq = 1
						AND OperationRequirement = 'Traction Power ON'
						AND IsActive = 1
					ORDER BY [Order]
		END
	ELSE
		BEGIN
			SELECT ID, OperationRequirement 
				FROM TAMS_Access_Requirement
					WHERE Line = @Line
					AND TrackType = @TrackType
						AND IsPowerReq = 1
						AND IsActive = 1
					ORDER BY [Order]
		END
	
	SELECT ID, TypeOfWork, ColourCode 
		FROM [dbo].[TAMS_Type_Of_Work]
			WHERE Line = @Line
			and TrackType = @TrackType
				AND ForSelection = 1
				AND IsActive = 1
			ORDER BY [Order]

	DECLARE @HODRole	 NVARCHAR(50)
	SET @HODRole = ''
	SET @HODRole = @Line + '_ApplicantHOD'

	SELECT a.Userid, a.LoginId, a.[Name] AS EmpName 
		FROM TAMS_User a, TAMS_User_Role b, TAMS_Role c
			WHERE a.Userid = b.UserID
				AND b.RoleID = c.ID
				AND b.Line = c.Line
				AND c.Line = @Line
				and c.TrackType = @TrackType
				AND c.Role = @HODRole
				AND a.IsActive = 1
				AND c.IsActive = 1
	ORDER BY 3

	DECLARE @SelSectorNotGap	NVARCHAR(1000)
	DECLARE @SelSectorGap		NVARCHAR(1000)
	DECLARE @PowerZone			NVARCHAR(1000)
	DECLARE @SPKSZone			NVARCHAR(1000)
	
	SET @SelSectorNotGap = ''
	SET @SelSectorGap = ''
	SET @PowerZone = ''
	SET @SPKSZone = ''

	-- EXEC sp_TAMS_Form_OnLoad 'NEL', '01/02/2021', 'Possession', '143;144;145;180;181;182'

	-- >> Selected Sector IsGap = 0
	SELECT @SelSectorNotGap = @SelSectorNotGap + ISNULL(Sector + ', ', '') 
		FROM TAMS_Sector
			WHERE ID IN (SELECT [VALUE] FROM [dbo].[SPLIT](';', @Sectors))
			AND ISNULL(IsGap, 0) = 0
		GROUP BY Sector

	IF LEN(LTRIM(RTRIM(@SelSectorNotGap))) > 0
		BEGIN
			SET @SelSectorNotGap = LEFT(LTRIM(RTRIM(@SelSectorNotGap)), LEN(LTRIM(RTRIM(@SelSectorNotGap))) - 1)
		END

	  

	SELECT @PowerZone = @PowerZone + ISNULL(PowerSector + ', ', '') 
			FROM TAMS_Power_Sector a, TAMS_Track_Power_Sector b	
				WHERE a.ID = b.PowerSectorId
					AND a.IsActive = 1
					AND b.IsActive = 1
					and b.IsBuffer = 0 
					 AND b.SectorId IN (SELECT [VALUE] FROM [dbo].[SPLIT](';', @Sectors))
		GROUP BY PowerSector		

		IF LEN(LTRIM(RTRIM(@PowerZone))) > 0
		BEGIN
			SET @PowerZone = LEFT(LTRIM(RTRIM(@PowerZone)), LEN(LTRIM(RTRIM(@PowerZone))) - 1)
		END

		SELECT @SPKSZone = @SPKSZone + ISNULL(SPKSZone + ', ', '') 
			FROM TAMS_SPKSZone a, TAMS_Track_SPKSZone b	
				WHERE a.ID = b.SPKSId
					AND a.IsActive = 1
					AND b.IsActive = 1
					 AND b.SectorId IN (SELECT [VALUE] FROM [dbo].[SPLIT](';', @Sectors))
		GROUP BY SPKSZone		

	IF LEN(LTRIM(RTRIM(@SPKSZone))) > 0
		BEGIN
			SET @SPKSZone = LEFT(LTRIM(RTRIM(@SPKSZone)), LEN(LTRIM(RTRIM(@SPKSZone))) - 1)
		END


		SELECT @SelSectorNotGap AS SelSectorNotGap,
		@SelSectorGap AS SelSectorGap,
		@PowerZone AS PowerZone,@SPKSZone as SPKSZone

 

	CREATE TABLE #TmpPossPowSector 
		(PowerSector	NVARCHAR(4000),
		PowerOnOff		NVARCHAR(5),
		NoOFSCD			INT,
		BreakerOut		NVARCHAR(5))
	
	TRUNCATE TABLE #TmpPossPowSector

	DECLARE @StrPowerOnOff NVARCHAR(5)
	DECLARE @StrBreakerOut NVARCHAR(5)
	DECLARE @PowerOnInd	INT

	SET @StrPowerOnOff = ''
	SET @StrBreakerOut = ''

	SET @StrPowerOnOff = CASE WHEN @PowerSelTxt = 'Traction Power ON' THEN 'N' ELSE 'Y' END
	SET @PowerOnInd = CASE WHEN @PowerSelTxt = 'Traction Power ON' THEN 1 ELSE 0 END
	SET @StrBreakerOut = CASE WHEN @PowerSelTxt LIKE '%With Rack Out%' THEN 'Y' ELSE 'N' END

 
	 
			 
			 SELECT @StrPowerOnOff as poweroff,(select top 1 Sector from TAMS_Sector where ID=[VALUE]) as sector,@StrBreakerOut as breaker,0 as NoOFSCD FROM [dbo].[SPLIT](';', @Sectors) 
	
	

	--GET Timeslot based on the weekend/weekday/PH

	 
	DECLARE @DayName	NVARCHAR(20)
	SET @DayName = UPPER(SUBSTRING(DATENAME(dw, CONVERT(DATE, @AccessDate, 103)), 1, 3))

	DECLARE @PHInd	NVARCHAR(5)
	IF (SELECT COUNT(*) FROM TAMS_Calendar
		WHERE HolidayCode = 1
			AND CalendarDate = CONVERT(DATE, GETDATE(), 103)) > 0
		BEGIN
			SET @PHInd = '1'
		END
	ELSE
		BEGIN
			SET @PHInd = '0'
		END
	-- >> If Saturday, Sunday and PH -- Flow to OCC
	-- if Protection, can work on buffer zone, so only need to check for the book sectors has any approved TAR or not. 
	-- if Possession, current sectors are book sectors , so we have to check for all the sectors in TAMS_TAR_Sectors has any approved TAR or not . 
	if @AccessType = 'Protection'
	begin 
			IF (@DayName = 'SAT' OR @DayName = 'SUN' OR @PHInd = '1')
			begin 
				-- get weekend;
				  SELECT   ParaValue2 , CASE WHEN((Select count(*) FROM TAMS_TAR a, TAMS_TAR_Sector b where a.Id = b.TARId AND  Line = @Line and TrackType='Depot' and AccessDate = convert(date,@AccessDate,103)  and AccessTimeSlot=Paravalue2 and TARStatusId = 9 
				 and b.SectorId in (select VALUE  FROM STRING_SPLIT(@Sectors, ';') )
				 and b.IsBuffer = 0
				 and a.AccessType = 'Possession'
				 ) > 0  ) THEN 'false'  ELSE 'true' end as DDLEnable
				 FROM TAMS_Parameters
					WHERE ParaCode = 'AccessTimeSlot_Weekend'
						AND ParaValue1 = @Line
						AND CONVERT(DATETIME, @AccessDate, 103) BETWEEN EffectiveDate AND ExpiryDate
					ORDER BY [Order]
			end;
			else if(@isDWONLY = 1 )  
			begin 
				-- get weekday DW;
				 SELECT   ParaValue2 , CASE WHEN((Select count(*) FROM TAMS_TAR a, TAMS_TAR_Sector b where a.Id = b.TARId AND  Line = @Line and TrackType='Depot' and AccessDate = convert(date,@AccessDate,103)  and AccessTimeSlot=Paravalue2 and TARStatusId = 9 
				 and b.SectorId in (select VALUE  FROM STRING_SPLIT(@Sectors, ';') )
				 and b.IsBuffer = 0
				  and a.AccessType = 'Possession'
				 ) > 0  ) THEN 'false'  ELSE 'true' end as DDLEnable
				FROM TAMS_Parameters
					WHERE ParaCode = 'AccessTimeSlot_Weekday_DW'
						AND ParaValue1 = @Line
						AND CONVERT(DATETIME, @AccessDate, 103) BETWEEN EffectiveDate AND ExpiryDate
					ORDER BY [Order]
			end; 
			else 
			begin 
				-- get weekday 
				 SELECT   ParaValue2 , CASE WHEN((Select count(*) FROM TAMS_TAR a, TAMS_TAR_Sector b where a.Id = b.TARId AND  Line = @Line and TrackType='Depot' and AccessDate = convert(date,@AccessDate,103)  and AccessTimeSlot=Paravalue2 and TARStatusId = 9 
				 and b.SectorId in (select VALUE  FROM STRING_SPLIT(@Sectors, ';') )
				 and b.IsBuffer = 0
				  and a.AccessType = 'Possession'
				 ) > 0  ) THEN 'false'  ELSE 'true' end as DDLEnable
				FROM TAMS_Parameters
					WHERE ParaCode = 'AccessTimeSlot_Weekday'
						AND ParaValue1 = @Line
						AND CONVERT(DATETIME, @AccessDate, 103) BETWEEN EffectiveDate AND ExpiryDate
					ORDER BY [Order]
			end;
	end; 
	else 
	begin 

		 IF (@DayName = 'SAT' OR @DayName = 'SUN' OR @PHInd = '1')
			begin 
				-- get weekend;
				  SELECT   ParaValue2 , CASE WHEN((Select count(*) FROM TAMS_TAR a, TAMS_TAR_Sector b where a.Id = b.TARId AND  Line = @Line and TrackType='Depot' and AccessDate = convert(date,@AccessDate,103)  and AccessTimeSlot=Paravalue2 and TARStatusId = 9 
				 and b.SectorId in (select VALUE  FROM STRING_SPLIT(@Sectors, ';') )
				  ) > 0  ) THEN 'false'  ELSE 'true' end as DDLEnable
				 FROM TAMS_Parameters
					WHERE ParaCode = 'AccessTimeSlot_Weekend'
						AND ParaValue1 = @Line
						AND CONVERT(DATETIME, @AccessDate, 103) BETWEEN EffectiveDate AND ExpiryDate
					ORDER BY [Order]
			end;
			else if(@isDWONLY = 1 )  
			begin 
				-- get weekday DW;
				 SELECT   ParaValue2 , CASE WHEN((Select count(*) FROM TAMS_TAR a, TAMS_TAR_Sector b where a.Id = b.TARId AND  Line = @Line and TrackType='Depot' and AccessDate = convert(date,@AccessDate,103)  and AccessTimeSlot=Paravalue2 and TARStatusId = 9 
				 and b.SectorId in (select VALUE  FROM STRING_SPLIT(@Sectors, ';') )
				  ) > 0  ) THEN 'false'  ELSE 'true' end as DDLEnable
				FROM TAMS_Parameters
					WHERE ParaCode = 'AccessTimeSlot_Weekday_DW'
						AND ParaValue1 = @Line
						AND CONVERT(DATETIME, @AccessDate, 103) BETWEEN EffectiveDate AND ExpiryDate
					ORDER BY [Order]
			end; 
			else 
			begin 
				-- get weekday 
				 SELECT   ParaValue2 , CASE WHEN((Select count(*) FROM TAMS_TAR a, TAMS_TAR_Sector b where a.Id = b.TARId AND  Line = @Line and TrackType='Depot' and AccessDate = convert(date,@AccessDate,103)  and AccessTimeSlot=Paravalue2 and TARStatusId = 9 
				 and b.SectorId in (select VALUE  FROM STRING_SPLIT(@Sectors, ';') )
				  ) > 0  ) THEN 'false'  ELSE 'true' end as DDLEnable
				FROM TAMS_Parameters
					WHERE ParaCode = 'AccessTimeSlot_Weekday'
						AND ParaValue1 = @Line
						AND CONVERT(DATETIME, @AccessDate, 103) BETWEEN EffectiveDate AND ExpiryDate
					ORDER BY [Order]
			end;

	end; 
	
		 
/*
EXEC sp_TAMS_Form_OnLoad 'DTL', '01/02/2021', 'Possession', '143;144;145;180;181;182', 'Traction Power ON'
EXEC sp_TAMS_Form_OnLoad 'DTL', '01/02/2021', 'Possession', '143;144;145;180;181;182', 'Power Off With Rack Out / 22KV Isolation'

EXEC sp_TAMS_Form_OnLoad 'NEL', '01/02/2021', 'Possession', '143;144;145;180;181;182', 'Traction Power ON'
EXEC sp_TAMS_Form_OnLoad 'NEL', '01/02/2021', 'Possession', '143;144;145;180;181;182', 'Power Off With Rack Out / 22KV Isolation'
	
*/
END
GO
/****** END PROCEDURE 57 ******/

/****** START PROCEDURE 58 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_Depot_Form_Save_Access_Details
CREATE procedure  [dbo].[sp_TAMS_Depot_Form_Save_Access_Details]
	@Line			AS NVARCHAR(10) = NULL,
	@TrackType		AS NVARCHAR(50) = NULL,
	@AccessDate		AS NVARCHAR(20) = NULL,
	@AccessTimeSlot	AS NVARCHAR(50) = NULL,
	@AccessType		AS NVARCHAR(20) = NULL,
	@TARType		AS NVARCHAR(10) = NULL,
	@Company		AS NVARCHAR(50) = NULL,
	@Designation	AS NVARCHAR(50) = NULL,
	@Name			AS NVARCHAR(50) = NULL,
	@OfficeNo		AS NVARCHAR(50) = NULL,
	@MobileNo		AS NVARCHAR(50) = NULL,
	@Email			AS NVARCHAR(50) = NULL,
	@AccessTimeFrom AS NVARCHAR(50) = NULL,
	@AccessTimeTo	AS NVARCHAR(50) = NULL,
	@AccessLocation	AS NVARCHAR(50) = NULL,
	@IsNeutralGap	AS INT = 0,
	@IsExclusive	AS INT= 0,
	@DescOfWork		AS NVARCHAR(100) = NULL,
	@ARRemark		AS NVARCHAR(1000) = NULL,
	@InvolvePower	AS INT = 0,
	@PowerOn		AS INT = 0,
	@Is13ASocket	AS INT = 0,
	@CrossOver		AS INT = 0, 
	@UserID			AS NVARCHAR(100) = NULL,
	@ProtectionType			AS NVARCHAR(50) = NULL,
	@TARID			AS BIGINT = 0 OUTPUT,
	@Message		AS NVARCHAR(500) = NULL OUTPUT
AS

BEGIN

DECLARE	@IntrnlTrans	TINYINT		

SET @TARID = 0

SELECT 	@IntrnlTrans 	= 0	

IF (@@TRANCOUNT = 0) 
BEGIN
	SET @IntrnlTrans = 1
	BEGIN TRAN
END

DECLARE @UserIDID	INT = 1;

SELECT @UserIDID = Userid
	FROM TAMS_User
		WHERE LoginId = @UserID
-- >>
INSERT INTO [dbo].[TAMS_TAR]
([Line],[TrackType], [TARNo], [TARType], 
[Company], [Designation], [Name], [OfficeNo], [MobileNo], [Email],
[SubmitDate], [AccessDate], [AccessTimeSlot],  [AccessTimeFrom], [AccessTimeTo],
[AccessLocation], [AccessType],
[IsNeutralGap], [IsExclusive],
[DescOfWork], [ARRemark],
[TARStatusId], 
[InvolvePower], [PowerOn], 
[Is13ASocket], 
[CrossOver],[ProtectionType],
[CreatedOn], [CreatedBy], [UpdatedOn], [UpdatedBy])
VALUES 
(@Line, @TrackType,'', @TARType,
@Company, @Designation, @Name, @OfficeNo, @MobileNo, @Email,
GETDATE(), CONVERT(DATETIME, @AccessDate, 103), @AccessTimeSlot, @AccessTimeFrom, @AccessTimeTo,
@AccessLocation, @AccessType, 
@IsNeutralGap, @IsExclusive,
@DescOfWork, @ARRemark,
0,
@InvolvePower, @PowerOn,
@Is13ASocket,
@CrossOver,@ProtectionType,
GETDATE(), @UserIDID, GETDATE(), @UserIDID)

SELECT @TARID = SCOPE_IDENTITY();

-- >>

IF @@ERROR <> 0 BEGIN
	SET @Message = 'ERROR INSERTING INTO TAMS_TAR'
	GOTO TRAP_ERROR
END

FORCE_EXIT_PROC:	
	IF @IntrnlTrans = 1 COMMIT TRAN
	RETURN @Message 

TRAP_ERROR:
	IF @IntrnlTrans = 1 ROLLBACK TRAN
	RETURN @Message


END
GO
/****** END PROCEDURE 58 ******/

/****** START PROCEDURE 59 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_Depot_Form_Submit
CREATE procedure  [dbo].[sp_TAMS_Depot_Form_Submit]
	@Line			AS NVARCHAR(10) = NULL,
	@TrackType		AS NVARCHAR(50) = NULL,
	@AccessDate		AS NVARCHAR(20) = NULL,
	@AccessType		AS NVARCHAR(20) = NULL,
	@TARType		AS NVARCHAR(10) = NULL,	
	@Sectors		AS NVARCHAR(2000) = NULL,
	@PowerSelVal	AS NVARCHAR(10) = NULL,
	@PowerSelTxt	AS NVARCHAR(100) = NULL,
	@IsExclusive	AS INT = NULL,
	@HODForApp		AS NVARCHAR(20) = NULL,
	@UserID			AS NVARCHAR(100) = NULL,
	@TARID			AS BIGINT = 0,
	@Message		AS NVARCHAR(500) = NULL OUTPUT
AS

BEGIN

DECLARE	@IntrnlTrans	TINYINT		
SELECT 	@IntrnlTrans 	= 0	

IF (@@TRANCOUNT = 0) 
BEGIN
	SET @IntrnlTrans = 1
	BEGIN TRAN
END

DECLARE @UserIDID	INT = 1;

SELECT @UserIDID = Userid
	FROM TAMS_User
		WHERE LoginId = @UserID

		print '@UserIDID';
		print @UserIDID;

	-- >> TAMS_TAR_Sector
	DECLARE @SecColourCode	NVARCHAR(20)

	SET @SecColourCode = ''

	IF @AccessType = 'Protection' AND @IsExclusive = 1
		BEGIN
			SELECT @SecColourCode = ColourCode 
				FROM TAMS_Type_Of_Work
					WHERE Line = @Line
					and TrackType = @TrackType
						AND TypeOfWork = 'Exclusive Protection'
						AND IsActive = 1
		END

	INSERT INTO [dbo].[TAMS_TAR_Sector]
		([TARId], [SectorId], [IsBuffer], [ColourCode], [IsAddedBuffer])
	SELECT @TARID, ID, 0, @SecColourCode, 0
		FROM TAMS_Sector
			WHERE ID IN (SELECT [VALUE] FROM [dbo].[SPLIT](';', @Sectors))
		ORDER BY ID;
	-- >> TAMS_TAR_Sector

	-- >> TAMS_TAR_Station
	INSERT INTO [dbo].[TAMS_TAR_Station]
		([TARId], [StationId])
	SELECT @TARID, a.ID
		FROM TAMS_Station a, TAMS_Entry_Station b	
			WHERE a.ID = b.StationId
				AND a.IsActive = 1
				AND b.IsActive = 1
				AND a.IsStation = 1
				AND b.SectorId IN (SELECT [VALUE] FROM [dbo].[SPLIT](';', @Sectors))
		GROUP BY a.ID
		ORDER BY a.ID;
	-- >> TAMS_TAR_Station
	
	-- >> TAMS_TAR_Power_Sector -- >> Check if Buffer Zone will be added
	DECLARE @PowerOnInd	INT

	SET @PowerOnInd = CASE WHEN @PowerSelTxt = 'Traction Power ON' THEN 1 ELSE 0 END

	--->> Insert Non buffer power sector first 
	INSERT INTO [dbo].[TAMS_TAR_Power_Sector]
		([TARId], [PowerSectorId], [PowerSection], [IsBuffer])
	Select @TARID,A.PSSectorID,A.PowerSection,A.IsBuffer from (
	SELECT ps.PSSectorID, ps.PowerSection, ps.IsBuffer
	FROM (SELECT DISTINCT c.ID AS PSSectorID, c.PowerSection, b.IsBuffer
		FROM TAMS_Sector a, TAMS_Track_Power_Sector b, TAMS_Power_Sector c
	WHERE a.Line = 'NEL'
		and a.TrackType = @TrackType
		AND a.ID = b.SectorId
		AND b.PowerSectorId = c.ID
		AND a.IsActive = 1
		AND b.IsActive = 1
		AND c.IsActive = 1
		 AND ( b.PowerOn is NULL and b.IsBuffer = 0  )
		AND a.ID IN (SELECT [VALUE] FROM [dbo].[SPLIT](';', @Sectors))
		GROUP BY c.ID, c.PowerSection, b.IsBuffer) ps
		) A where NOT EXISTS(Select * from [TAMS_TAR_Power_Sector]
	where [TAMS_TAR_Power_Sector].TARId=@TARID and [TAMS_TAR_Power_Sector].PowerSectorId=A.PSSectorID and IsBuffer=1)
	ORDER BY A.PSSectorID


	--->> Insert Non buffer power sector first 
	INSERT INTO [dbo].[TAMS_TAR_Power_Sector]
		([TARId], [PowerSectorId], [PowerSection], [IsBuffer])
	Select @TARID,A.PSSectorID,A.PowerSection,A.IsBuffer from (
	SELECT ps.PSSectorID, ps.PowerSection, ps.IsBuffer
	FROM (SELECT c.ID AS PSSectorID, c.PowerSection, b.IsBuffer
		FROM TAMS_Sector a, TAMS_Track_Power_Sector b, TAMS_Power_Sector c
	WHERE a.Line = 'NEL'
		and a.TrackType = @TrackType
		AND a.ID = b.SectorId
		AND b.PowerSectorId = c.ID
		AND a.IsActive = 1
		AND b.IsActive = 1
		AND c.IsActive = 1
		 AND ( b.PowerOn = @PowerOnInd and b.IsBuffer = 1  )
		AND a.ID IN (SELECT [VALUE] FROM [dbo].[SPLIT](';', @Sectors))
		AND c.ID not in (
			Select PowerSectorId
			From TAMS_TAR_Power_Sector WHERE TARId = @TARID and IsBuffer = 0 
		)
		GROUP BY c.ID, c.PowerSection, b.IsBuffer) ps

	) A where NOT EXISTS(Select * from [TAMS_TAR_Power_Sector]
	where [TAMS_TAR_Power_Sector].TARId=@TARID and [TAMS_TAR_Power_Sector].PowerSectorId=A.PSSectorID and IsBuffer=0)
	ORDER BY A.PSSectorID
	-- >> TAMS_TAR_Power_Sector 


	INSERT INTO [dbo].[TAMS_TAR_SPKSZone]
		([TARId], [SPKSZoneId], [SPKSZone], [IsBuffer])
	SELECT @TARID,A.SPKSID,A.SPKSZone,0 from (
	SELECT ps.SPKSID, ps.SPKSZone
	FROM (SELECT c.ID AS SPKSID, c.SPKSZone 
		FROM  TAMS_Track_SPKSZone b, TAMS_SPKSZone c
	WHERE   c.ID = b.SPKSId
		 AND b.IsActive = 1
		AND c.IsActive = 1
		--AND ISNULL(b.PowerOn, 0) = @PowerOnInd
		AND b.SectorId IN (SELECT [VALUE] FROM [dbo].[SPLIT](';', @Sectors))
		GROUP BY c.ID, c.SPKSZone ) ps
	) A where NOT EXISTS(Select TARId from TAMS_TAR_SPKSZone
	where TARId=@TARID and SPKSZoneId=A.SPKSID and IsBuffer=0)
	ORDER BY A.SPKSID
	-- >> TAMS_TAR_SPKSZone

	-- >> TAMS_TAR_Attachment from TAMS_TAR_Attachment_Temp
	INSERT INTO [dbo].[TAMS_TAR_Attachment]
		([TARAccessReqId], [FileName], [FileType], [File])
	SELECT b.ID, a.FileName, a.FileType, a.FileUpload 
		FROM TAMS_TAR_Attachment_Temp a, TAMS_TAR_AccessReq b
			WHERE a.TARId = b.TARId
				AND a.TARAccessReqId = b.[Order]  
				AND a.TARId = @TARID
			ORDER BY a.ID
	-- >> TAMS_TAR_Attachment from TAMS_TAR_Attachment_Temp

	-- >> Buffer Zone
	IF @AccessType = 'Possession'
		BEGIN
			-->> Color still missing

			DECLARE @CrossOverInd	INT

			SELECT @CrossOverInd = CASE WHEN CrossOver = 1 THEN 1 ELSE 0 END FROM TAMS_TAR
				WHERE ID = @TARID

			SET @SecColourCode = ''

			SELECT @SecColourCode = ColourCode 
				FROM TAMS_Type_Of_Work
					WHERE Line = @Line
						and TrackType = @TrackType
						AND TypeOfWork = 'Buffer Zone'
						AND IsActive = 1

			INSERT INTO [dbo].[TAMS_TAR_Sector]
			([TARId], [SectorId], [IsBuffer], [ColourCode], [IsAddedBuffer])
			SELECT distinct @TARID, a.ID, 1, @SecColourCode, 0 
				FROM TAMS_Sector a 
					WHERE a.ID IN (SELECT BufferSectorId 
						FROM TAMS_Buffer_Zone
							WHERE Line = @Line
								and TrackType = @TrackType
								AND IsActive = 1
								AND PowerOn = @PowerOnInd
								AND SectorId IN (SELECT SectorId FROM TAMS_TAR_Sector WHERE TARId = @TARID)
								--AND ISNULL(CrossOverBuffer, 0) = 0)
						AND a.ID NOT IN (SELECT SectorId FROM TAMS_TAR_Sector WHERE TARId = @TARID))

			  

			-- >> Update Colour Code of non Buffer Zone

			DECLARE @TypeOfWorkID INT

			SELECT @TypeOfWorkID = TypeOfWorkId 
				FROM TAMS_Possession 
					WHERE TARId = @TARID
			
			SET @SecColourCode = ''

			SELECT @SecColourCode = ColourCode 
				FROM TAMS_Type_Of_Work
					WHERE Line = @Line
						AND ID = @TypeOfWorkID
						AND IsActive = 1
			
			UPDATE [dbo].[TAMS_TAR_Sector]
				SET ColourCode = @SecColourCode
			WHERE TARId = @TARID
				AND IsBuffer = 0
		END
	-- >> Buffer Zone

	DECLARE @WFID	INT
	SET @WFID = 0

	DECLARE @InvolvePower INT
	SET @InvolvePower = 0

	DECLARE @IsPowerWF INT
	SET @IsPowerWF = 0

	SELECT @IsPowerWF = tab.IsPowerWF 
		FROM TAMS_TAR_AccessReq sel, TAMS_Access_Requirement tab
			WHERE tab.IsPowerWF = 1
				AND sel.IsSelected = 1
				AND sel.TARId = @TARID
				AND sel.OperationRequirement = tab.ID

	SET @InvolvePower = @IsPowerWF

	-- >> If Saturday, Sunday and PH -- Flow to OCC
	DECLARE @DayName	NVARCHAR(20)
	SET @DayName = UPPER(SUBSTRING(DATENAME(dw, CONVERT(DATE, GETDATE(), 103)), 1, 3))

	DECLARE @PHInd	NVARCHAR(5)
	IF (SELECT COUNT(*) FROM TAMS_Calendar
		WHERE HolidayCode = 1
			AND CalendarDate = CONVERT(DATE, GETDATE(), 103)) > 0
		BEGIN
			SET @PHInd = '1'
		END
	ELSE
		BEGIN
			SET @PHInd = '0'
		END
	-- >> If Saturday, Sunday and PH -- Flow to OCC

	IF @TARType = 'Urgent'  
		BEGIN
			IF (@DayName = 'SAT' OR @DayName = 'SUN' OR @PHInd = '1')
				BEGIN
					SELECT @WFID = ID 
						FROM TAMS_Workflow
							WHERE IsActive = 1
								AND Line = @Line
								and TrackType = @TrackType
								AND InvolvePower = @InvolvePower
								AND CONVERT(DATETIME, CONVERT(NVARCHAR(20), GETDATE(), 103), 103) BETWEEN EffectiveDate AND ExpiryDate
								AND WorkflowType = 'UrgentAfter' 
				END
			ELSE
				BEGIN
					DECLARE @CutoffTime TIME

					SELECT @CutoffTime = ParaTime 
						FROM TAMS_Parameters
							WHERE ParaCode = 'ApprovalCutOffTime'
								AND ParaValue1 = @Line
								AND ParaValue2 = @TrackType
								AND CONVERT(DATETIME, CONVERT(NVARCHAR(20), GETDATE(), 103), 103) BETWEEN EffectiveDate AND ExpiryDate 

					IF CONVERT(TIME, GETDATE(), 108) <= @CutoffTime
						BEGIN
							SELECT @WFID = ID 
								FROM TAMS_Workflow
									WHERE IsActive = 1
										AND Line = @Line
										and TrackType = @TrackType
										AND InvolvePower = @InvolvePower
										AND CONVERT(DATETIME, CONVERT(NVARCHAR(20), GETDATE(), 103), 103) BETWEEN EffectiveDate AND ExpiryDate
										AND WorkflowType = 'UrgentBefore' 
						END
					ELSE
						BEGIN
							SELECT @WFID = ID 
								FROM TAMS_Workflow
									WHERE IsActive = 1
										AND Line = @Line
										and TrackType = @TrackType
										AND InvolvePower = @InvolvePower
										AND CONVERT(DATETIME, CONVERT(NVARCHAR(20), GETDATE(), 103), 103) BETWEEN EffectiveDate AND ExpiryDate
										AND WorkflowType = 'UrgentAfter' 
						END
				END
		END
	ELSE
		BEGIN
			SELECT @WFID = ID 
				FROM TAMS_Workflow
					WHERE IsActive = 1
						AND Line = @Line
						AND InvolvePower = @InvolvePower
						and TrackType = @TrackType
						AND CONVERT(DATETIME, CONVERT(NVARCHAR(20), GETDATE(), 103), 103) BETWEEN EffectiveDate AND ExpiryDate
						AND WorkflowType = @TARType
		END

	DECLARE @WFStatusID	INT
	DECLARE @EndorserID INT

	SELECT @WFStatusID = WFStatusId,
			@EndorserID = ID
		FROM TAMS_Endorser
			WHERE IsActive = 1
				AND CONVERT(DATETIME, CONVERT(NVARCHAR(20), GETDATE(), 103), 103) BETWEEN EffectiveDate AND ExpiryDate
				AND [Level] = 1
				AND Line = @Line
				AND WorkflowId = @WFID

	DECLARE @RefNum		NVARCHAR(20)
	DECLARE @RefNumMsg	NVARCHAR(20)
	SET @RefNum = ''
	SET @RefNumMsg = ''
	EXEC sp_Generate_Ref_Num 'TAR', @Line,@TrackType, @RefNum OUTPUT, @RefNumMsg OUTPUT

	UPDATE TAMS_TAR
		SET TARNo = @RefNum,
			TARType = @TARType,
			TARStatusId = @WFStatusID,
			InvolvePower = @IsPowerWF,	 
			PowerOn = @PowerOnInd
	WHERE Id = @TARID

	DECLARE @HODUserID INT

	SET @HODUserID = 0

	SELECT @HODUserID = Userid
	FROM TAMS_User
		WHERE LoginId = @HODForApp

	-- Added by yongde on 15032025, this is to prevent double entry of tar workflow approval
	IF NOT EXISTS(SELECT * from [dbo].[TAMS_TAR_Workflow] where TARId=@TARID and 
	[WorkflowId]=@WFID and EndorserId=@EndorserID)
	BEGIN
		INSERT INTO [dbo].[TAMS_TAR_Workflow]
			([TARId], [WorkflowId], [EndorserId], [UserId], [WFStatus], [Remark], [ActionOn], [ActionBy])
		VALUES 
			(@TARID, @WFID, @EndorserID, @HODUserID, 'Pending', '', GETDATE(), @UserIDID)
	END

	--INSERT INTO [dbo].[TAMS_TAR_Workflow]
	--	([TARId], [WorkflowId], [EndorserId], [UserId], [WFStatus], [Remark], [ActionOn], [ActionBy])
	--VALUES 
	--	(@TARID, @WFID, @EndorserID, @HODUserID, 'Pending', '', GETDATE(), @UserIDID)

	DECLARE @ApplicantName	NVARCHAR(200)
	SELECT @ApplicantName = [Name]
		FROM TAMS_TAR
			WHERE ID = @TARID

	DECLARE @Sender NVARCHAR (100);
	DECLARE @SysID NVARCHAR(10);
	DECLARE @Subject NVARCHAR(500);    
	DECLARE @Sys NVARCHAR(100);
	DECLARE @Greetings  NVARCHAR(20);     
	DECLARE @ToList NVARCHAR(MAX);
	DECLARE @CCList NVARCHAR(MAX);
	DECLARE @BCCList NVARCHAR(MAX);
	DECLARE @Separator NVARCHAR(10);        
	DECLARE @AlertMsg NVARCHAR(MAX);
	DECLARE @AlertID AS INTEGER; 

	DECLARE @Body VARCHAR(max)
	DECLARE @Body1 VARCHAR(max)
	DECLARE @Body2 VARCHAR(max)

	DECLARE @LoginPage	NVARCHAR(500);
	Select @LoginPage = ParaValue1
	FROM            TAMS_Parameters
	WHERE ParaCode = 'TAMS URL' ;

	SET @Sender = 'TAMS Admin';
	SET @SysID = 'TAMS';
	SET @Subject = 'Urgent Depot TAR ' + CAST(@RefNum AS NVARCHAR(50)) + ' for Applicant HOD Acceptance.'
	SET @Sys = 'Track Access Management System'   
	SET @Greetings = 'Dear Sir/Madam, '  
	SET @ToList = ''
	SET @CCList = ''   
	SET @BCCList = ''
	SET @Separator = ','    
	SET @CCList = ''

		-- >> If Urgent Send Email to HOD
		IF @TARType = 'Urgent'
			BEGIN
				DECLARE @HODUserEmail NVARCHAR(200)

				SELECT @HODUserEmail = Email 
					FROM TAMS_User
						WHERE Userid = @HODUserID
							AND IsActive = 1
							AND CONVERT(DATETIME, CONVERT(NVARCHAR(20), GETDATE(), 103), 103) BETWEEN ValidFrom AND ValidTo

				SET @ToList = ISNULL(@HODUserEmail, '')

				SET @Body1 = ''
				SET @Body2 = ''
			
				SET @Body1 = @Body1 + '<table width="100%">'
				SET @Body1 = @Body1 + '<tr align="left" valign="middle" style="font-size:10pt; font-face:Arial;">'
				SET @Body1 = @Body1 + '<td>' + CAST(@ApplicantName AS NVARCHAR(200)) + ' has applied an Urgent Depot TAR for your Acceptance.</td>'
				SET @Body1 = @Body1 + '</tr>'
				SET @Body1 = @Body1 + '</table>'
				-- >> SET @LoginPage = 'https://pulsewebuat.sbstransit.com.sg/TAMS/Login.aspx'
				SET @LoginPage = 'https://sbstweb.sbstransit.com.sg/TAMS/Login.aspx'

				SET @Body2 = @Body2 + '<br>'
				SET @Body2 = @Body2 + '<table width="100%">'
				SET @Body2 = @Body2 + '<tr align="left" valign="middle" style="font-size:10pt; font-face:Arial;">'
				SET @Body2 = @Body2 + '<td>Click on the link <a href=' + @LoginPage + '>here</a> to access the TAR Form.</td>'
				SET @Body2 = @Body2 + '</tr>'
				SET @Body2 = @Body2 + '</table>'

				SET @Body = ''
				SET @Body = @Body1 + @Body2

				SET @BCCList = ''

				EXEC [dbo].EAlertQ_EnQueue 
					@Sender = @Sender, 
					@UserId = @SysID, 
					@Subject = @Subject,        
					@Sys = @Sys,  
					@Greetings = @Greetings, 
					@AlertMsg = @Body, 
					@SendTo = @ToList,        
					@CC = @CCList, 
					@BCC= @BCCList, 
					@Separator = @Separator, 
					@AlertID =  @AlertID output
			END

IF @@ERROR <> 0 BEGIN
	SET @Message = 'ERROR INSERTING INTO TAMS_TAR'
	GOTO TRAP_ERROR
END

FORCE_EXIT_PROC:	
	IF @IntrnlTrans = 1 COMMIT TRAN
	RETURN @Message 

TRAP_ERROR:
	IF @IntrnlTrans = 1 ROLLBACK TRAN
	RETURN @Message


END
GO
/****** END PROCEDURE 59 ******/

/****** START PROCEDURE 60 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_Depot_Form_Update_Access_Details
CREATE   procedure [dbo].[sp_TAMS_Depot_Form_Update_Access_Details]
	@Company		AS NVARCHAR(50) = NULL,
	@Designation	AS NVARCHAR(50) = NULL,
	@Name			AS NVARCHAR(50) = NULL,
	@OfficeNo		AS NVARCHAR(50) = NULL,
	@MobileNo		AS NVARCHAR(50) = NULL,
	@Email			AS NVARCHAR(50) = NULL,
	@AccessTimeFrom AS NVARCHAR(50) = NULL,
	@AccessTimeTo	AS NVARCHAR(50) = NULL,
	@IsExclusive	AS INT= 0,
	@DescOfWork		AS NVARCHAR(100) = NULL,
	@ARRemark		AS NVARCHAR(1000) = NULL,
	@InvolvePower	AS INT = 0,
	@PowerOn		AS INT = 0,
	@Is13ASocket	AS INT = 0,
	@CrossOver		AS INT = 0, 
	@UserID			AS NVARCHAR(20) = NULL,
	@ProtectionType	AS NVARCHAR(50) = NULL,
	@TARID			AS BIGINT = 0,
	@Message		AS NVARCHAR(500) = NULL OUTPUT
AS

BEGIN

DECLARE	@IntrnlTrans	TINYINT
SELECT 	@IntrnlTrans 	= 0	

IF (@@TRANCOUNT = 0) 
BEGIN
	SET @IntrnlTrans = 1
	BEGIN TRAN
END

DECLARE @UserIDID	INT = 1;

SELECT @UserIDID = Userid
	FROM TAMS_User
		WHERE LoginId = @UserID
-- >>

UPDATE [dbo].[TAMS_TAR]
SET [Company] = @Company, 
	[Designation] = @Designation, 
	[Name] = @Name, 
	[OfficeNo] = @OfficeNo, 
	[MobileNo] = @MobileNo, 
	[Email] = @Email,
	[AccessTimeFrom] = @AccessTimeFrom, 
	[AccessTimeTo] = @AccessTimeTo,
	[IsExclusive] = @IsExclusive,
	[DescOfWork] = @DescOfWork, 
	[ARRemark] = @ARRemark,
	[InvolvePower] = @InvolvePower, 
	[PowerOn] = @PowerOn, 
	[Is13ASocket] = @Is13ASocket, 
	[CrossOver] = @CrossOver,
	[ProtectionType] = @ProtectionType,
	[UpdatedOn] = GETDATE(), 
	[UpdatedBy] = @UserIDID
WHERE ID = @TARID

-- >>

IF @@ERROR <> 0 BEGIN
	SET @Message = 'ERROR INSERTING INTO TAMS_TAR'
	GOTO TRAP_ERROR
END

FORCE_EXIT_PROC:	
	IF @IntrnlTrans = 1 COMMIT TRAN
	RETURN @Message 

TRAP_ERROR:
	IF @IntrnlTrans = 1 ROLLBACK TRAN
	RETURN @Message

END
GO
/****** END PROCEDURE 60 ******/

/****** START PROCEDURE 61 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_Depot_GetBlockedTarDates
CREATE   procedure [dbo].[sp_TAMS_Depot_GetBlockedTarDates]
	@Line AS nvarchar(10) = NULL,
	@AccessDate AS date = NULL
AS
BEGIN
	SELECT ID, Line, BlockDate, BlockReason
	FROM TAMS_Block_TARDate
	WHERE Line = @Line
	AND BlockDate = @AccessDate
	AND IsActive = 1 
	ORDER BY BlockDate ASC
END
GO
/****** END PROCEDURE 61 ******/

/****** START PROCEDURE 62 ******/
-- PROCEDURE NAME: dbo.SP_TAMS_Depot_GetDTCAuth
CREATE PROCEDURE [dbo].[SP_TAMS_Depot_GetDTCAuth]
	-- Add the parameters for the stored procedure here
	@accessDate as Date
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;


    -- Insert statements for procedure here
	Select TAMS_Depot_Auth.ID as AuthID,TAMS_TAR.TARNo,TAMS_Depot_Auth.DepotAuthStatusId,TAMS_Depot_Auth_Workflow.WFStatus,ActionOn,TAMS_User.Name as ActionBy,TAMS_Depot_Auth_Workflow.WorkflowID,TAMS_Depot_Auth_Workflow.CheckBoxValue,TAMS_Depot_Auth_Remark.Remark,TAMS_WFStatus.[Order]
	from TAMS_TAR LEFT JOIN TAMS_Depot_Auth ON TAMS_Depot_Auth.TarID=TAMS_TAR.Id
	LEFT JOIN TAMS_Depot_Auth_Workflow ON TAMS_Depot_Auth_Workflow.DTCAuthId=TAMS_Depot_Auth.ID
	LEFT JOIN TAMS_Depot_Auth_Remark  ON TAMS_Depot_Auth_Remark.RemarkID=TAMS_Depot_Auth.RemarkID
	LEFT JOIN TAMS_WFStatus on TAMS_WFStatus.ID=TAMS_Depot_Auth_Workflow.WorkflowID
	LEFT JOIN TAMS_User ON TAMS_User.LoginId=ActionBy
	where TAMS_Depot_Auth.AccessDate=@accessDate
	order by TAMS_Depot_Auth.DepotAuthStatusId ASC




END
GO
/****** END PROCEDURE 62 ******/

/****** START PROCEDURE 63 ******/
-- PROCEDURE NAME: dbo.SP_TAMS_Depot_GetDTCAuthEndorser
CREATE PROCEDURE [dbo].[SP_TAMS_Depot_GetDTCAuthEndorser]
	-- Add the parameters for the stored procedure here
	@accessDate as Date,
	@lanid as nvarchar(50)
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

	DECLARE @workflowid as int;
	Select @workflowid=ID from TAMS_Workflow where WorkflowType='OCCAuth' and TrackType='Depot'


	Select TAMS_WFStatus.ID as Workflowid,Title,TAMS_Endorser.RoleId,CASE WHEN @lanid IN (
		Select LoginId from TAMS_OCC_Duty_Roster 
	INNER JOIN TAMS_Roster_Role ON TAMS_OCC_Duty_Roster.RosterCode=TAMS_Roster_Role.RosterCode  and TAMS_OCC_Duty_Roster.TrackType=TAMS_Roster_Role.TrackType
	and TAMS_OCC_Duty_Roster.Line=TAMS_Roster_Role.Line
	INNER JOIN TAMS_User ON TAMS_User.Userid=TAMS_OCC_Duty_Roster.DutyStaffId
	where TAMS_OCC_Duty_Roster.tracktype='Depot' and RoleID=TAMS_Endorser.RoleId and TAMS_OCC_Duty_Roster.OperationDate=@accessDate and TAMS_OCC_Duty_Roster.Line='NEL'
	) THEN 1 else 0 END as Access,TAMS_WFStatus.WFStatusId as StatusID
	from TAMS_Endorser 
	INNER JOIN TAMS_WFStatus ON TAMS_WFStatus.WFStatusId=TAMS_Endorser.WFStatusId
	where WorkflowId=@workflowid and TAMS_Endorser.IsActive=1 and TAMS_WFStatus.WFType='DTCAuth'
	and @accessDate>=EffectiveDate and @accessDate<=ExpiryDate 

END
GO
/****** END PROCEDURE 63 ******/

/****** START PROCEDURE 64 ******/
-- PROCEDURE NAME: dbo.SP_TAMS_Depot_GetDTCAuthPowerzone
CREATE PROCEDURE [dbo].[SP_TAMS_Depot_GetDTCAuthPowerzone]
	-- Add the parameters for the stored procedure here
	@accessDate as Date
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

	
	SELECT * from (
	Select WFType,AuthID,PowerSector,TAMS_Power_Sector.ID,PowerOffType,PowerOffTiming,RackedOutType,RackedOutTiming,PowerOnType,PowerOnTiming,RackedInType,RackedInTiming,PowerOffActionUser.Name as PowerOffActionBy,RackOffActionUser.Name as RackedOffActionBy,PowerOnActionUser.Name as PowerOnActionBy,RackOnActionUser.Name as RackedInActionBy,StatusID,Z.ID as workflowid,TAMS_Depot_Auth_Powerzone.IsBuffer,DENSE_RANK() OVER (ORDER BY AuthID) as rowspan
	from TAMS_Depot_Auth 
	LEFT JOIN TAMS_Depot_Auth_Powerzone ON TAMS_Depot_Auth.ID=TAMS_Depot_Auth_Powerzone.AuthID
	LEFT JOIN TAMS_Power_Sector ON TAMS_Depot_Auth_Powerzone.PowerzoneID=TAMS_Power_Sector.ID
	LEFT JOIN (Select * from TAMS_WFStatus where WFType='DTCAuth') Z ON Z.WFStatusId=StatusID
	LEFT JOIN TAMS_User PowerOffActionUser ON PowerOffActionUser.LoginId=PowerOffActionBy
	LEFT JOIN TAMS_User PowerOnActionUser ON PowerOnActionUser.LoginID=PowerOnActionBy
	LEFT JOIN TAMS_User RackOffActionUser ON RackOffActionUser.LoginId=RackedOffActionBy
	LEFT JOIN TAMS_User RackOnActionUser ON RackOnActionUser.LoginID=RackedInActionBy
	where TAMS_Depot_Auth.AccessDate=@accessDate and TAMS_Power_Sector.IsActive=1
	) A
	order by A.AuthID ASC,A.ID ASC

END
GO
/****** END PROCEDURE 64 ******/

