/****** START PROCEDURE 75 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_Depot_Inbox_Child_OnLoad
CREATE procedure  [dbo].[sp_TAMS_Depot_Inbox_Child_OnLoad]
	@Line		AS NVARCHAR(10) = NULL,
	@TrackType		AS NVARCHAR(50) = NULL,
	@AccessDate	AS NVARCHAR(20) = NULL,
	@TARType	AS NVARCHAR(20) = NULL,
	@LoginUser	AS NVARCHAR(50) = NULL,
	@SectorID	AS INT
AS

BEGIN

DECLARE @UserID INT

SELECT @UserID = Userid 
	FROM TAMS_USER
		WHERE LoginId = @LoginUser

DECLARE @CurrDate	DATETIME
SET @CurrDate = CONVERT(DATETIME, CONVERT(NVARCHAR(20), GETDATE(), 103), 103)

CREATE TABLE #TmpSector 
(Line		NVARCHAR(10),
SectorID	INT,
SectorStr	NVARCHAR(50),
SectorOrder	INT )

CREATE TABLE #TmpInbox 
(TARID			BIGINT,
TARNo			NVARCHAR(20),
TARType			NVARCHAR(10),
AccessDate		NVARCHAR(20),
AccessTimeSlot		NVARCHAR(50),
AccessType		NVARCHAR(20),
SectorID		INT,
SectorStr		NVARCHAR(50) )

CREATE TABLE #TmpInboxList 
(TARID			BIGINT,
TARNo			NVARCHAR(20),
TARType			NVARCHAR(10),
AccessDate		NVARCHAR(20),
AccessTimeSlot		NVARCHAR(50),
AccessType		NVARCHAR(20),
SectorID		INT,
SectorStr		NVARCHAR(50) )

TRUNCATE TABLE #TmpSector
TRUNCATE TABLE #TmpInbox
TRUNCATE TABLE #TmpInboxList

INSERT INTO #TmpSector 
	(Line, SectorID, SectorStr, SectorOrder)
SELECT Line, ID, Sector, [Order] 
	FROM TAMS_Sector
		WHERE Line = @Line
		AND TrackType = @TrackType
			AND IsActive = 1
			AND @CurrDate BETWEEN EffectiveDate AND ExpiryDate
		ORDER BY [Order]

INSERT INTO #TmpInbox
	(TARID, TARNo, TARType, AccessDate,AccessTimeSlot, AccessType, SectorID, SectorStr)
SELECT a.[Id], a.[TARNo], a.[TARType], CONVERT(NVARCHAR(20), a.[AccessDate], 103),a.AccessTimeSlot, a.[AccessType], b.[Id], b.[Sector] 
	FROM TAMS_TAR a, TAMS_Sector b, TAMS_TAR_Sector c, TAMS_TAR_Workflow d, TAMS_Endorser e
		WHERE b.[Id] = c.[SectorId]
			AND c.[TarId] = a.[Id]
			AND a.[Id] = d.[TARid]
			AND d.[EndorserId] = e.[Id]
			AND d.[WFStatus] like '%Pending%'
			-- >> AND ISNULL(b.[IsGap], 0) = 0
			--AND  d.[UserId]  is null
			AND ISNULL(d.[UserId], 0) = 0
			AND e.[RoleId] IN (SELECT f.RoleID FROM TAMS_User_Role f WHERE f.UserID = @UserID) 
			AND (a.AccessDate = CONVERT(DATE, @AccessDate, 103) OR (ISNULL(@AccessDate, '') = '' AND a.AccessDate>GETDATE()))
			AND (a.TARType = @TARType OR ISNULL(@TARType, '') = '')
			AND c.[IsBuffer] = 0
			AND a.TrackType = @TrackType
UNION
SELECT a.[Id], a.[TARNo], a.[TARType], CONVERT(NVARCHAR(20), a.[AccessDate], 103),a.AccessTimeSlot, a.[AccessType], b.[Id], b.[Sector] 
	FROM TAMS_TAR a, TAMS_Sector b, TAMS_TAR_Sector c, TAMS_TAR_Workflow d, TAMS_Endorser e
		WHERE b.[Id] = c.[SectorId]
			AND c.[TarId] = a.[Id]
			AND a.[Id] = d.[TARid]
			AND d.[EndorserId] = e.[Id]
			AND d.[WFStatus] like '%Pending%'
			AND d.[UserId] = @UserID
			AND (a.AccessDate = CONVERT(DATE, @AccessDate, 103) OR (ISNULL(@AccessDate, '') = '' AND a.AccessDate>GETDATE()))
			AND (a.TARType = @TARType OR ISNULL(@TARType, '') = '')
			AND c.[IsBuffer] = 0
			AND a.TrackType = @TrackType

DECLARE @Cur01 CURSOR;
DECLARE @CTARID			BIGINT
DECLARE @CTARNo			NVARCHAR(20)
DECLARE @CTARType		NVARCHAR(10)
DECLARE @CAccessDate	NVARCHAR(20)
DECLARE @CAccessTimeSlot	NVARCHAR(50)
DECLARE @CAccessType	NVARCHAR(20)
DECLARE @CSectorID		INT
DECLARE @CSectorStr		NVARCHAR(50)
DECLARE @CDirection		INT

DECLARE @Cur02 CURSOR;
DECLARE @C2ActionBy		INT
DECLARE @ActionByChk	INT

SET @Cur01 = CURSOR FAST_FORWARD 
FOR
	SELECT TARID, TARNo, TARType, AccessDate,AccessTimeSlot, AccessType, SectorID, SectorStr
		FROM #TmpInbox
			ORDER BY TARID, SectorID;		

OPEN @Cur01
	
FETCH NEXT FROM @Cur01 INTO @CTARID, @CTARNo, @CTARType, @CAccessDate,@CAccessTimeSlot, @CAccessType, @CSectorID, @CSectorStr
	
WHILE @@FETCH_STATUS = 0 
	
	BEGIN

		SET @ActionByChk = 0

		IF (SELECT COUNT(*) 
				FROM TAMS_TAR_Workflow
					WHERE TARId = @CTARID
						AND WFStatus <> 'Pending'
				) = 0
			BEGIN
				INSERT INTO #TmpInboxList
					(TARID, TARNo, TARType, AccessDate,AccessTimeSlot, AccessType, SectorID, SectorStr)
				VALUES
					(@CTARID, @CTARNo, @CTARType, @CAccessDate,@CAccessTimeSlot, @CAccessType, @CSectorID, @CSectorStr)
			END
		ELSE
			BEGIN
				-- >>
				SET @Cur02 = CURSOR FAST_FORWARD 
				FOR
					SELECT ActionBy
						FROM TAMS_TAR_Workflow
							WHERE TARId = @CTARID
								AND WFStatus <> 'Pending'

				OPEN @Cur02
	
				FETCH NEXT FROM @Cur02 INTO @C2ActionBy
	
				WHILE @@FETCH_STATUS = 0 
	
					BEGIN

						 -- >> Comment for 1 Man Testing
						IF (@UserID = @C2ActionBy)
							BEGIN
								SET @ActionByChk = @ActionByChk + 1
							END

						FETCH NEXT FROM @Cur02 INTO @C2ActionBy
					END 	

				CLOSE @Cur02
	
				DEALLOCATE @Cur02
				-- >>
			END

		IF (@ActionByChk = 0)
			BEGIN
				INSERT INTO #TmpInboxList
					(TARID, TARNo, TARType, AccessDate, AccessTimeSlot,AccessType, SectorID, SectorStr)
				VALUES
					(@CTARID, @CTARNo, @CTARType, @CAccessDate, @CAccessTimeSlot,@CAccessType, @CSectorID, @CSectorStr)
			END

		FETCH NEXT FROM @Cur01 INTO @CTARID, @CTARNo, @CTARType, @CAccessDate,@CAccessTimeSlot, @CAccessType, @CSectorID, @CSectorStr
	END 	

CLOSE @Cur01
	
DEALLOCATE @Cur01

SELECT b.TARID, b.TARNo, b.TARType, b.AccessDate,b.AccessTimeSlot, b.AccessType
	FROM #TmpInboxList b
		WHERE b.SectorID = @SectorID
	GROUP BY b.TARID, b.TARNo, b.TARType, b.AccessDate,b.AccessTimeSlot, b.AccessType
	ORDER BY b.TARID, b.TARNo, b.TARType, b.AccessDate,b.AccessTimeSlot, b.AccessType
 
DROP TABLE #TmpSector
DROP TABLE #TmpInbox
DROP TABLE #TmpInboxList

END
GO
/****** END PROCEDURE 75 ******/

/****** START PROCEDURE 76 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_Depot_Inbox_Master_OnLoad
CREATE procedure  [dbo].[sp_TAMS_Depot_Inbox_Master_OnLoad]
	@Line		AS NVARCHAR(10) = NULL,
	@TrackType		AS NVARCHAR(50) = NULL,
	@AccessDate	AS NVARCHAR(20) = NULL,
	@TARType	AS NVARCHAR(20) = NULL,
	@LoginUser	AS NVARCHAR(50) = NULL
AS

BEGIN

DECLARE @UserID INT

SELECT @UserID = Userid 
	FROM TAMS_USER
		WHERE LoginId = @LoginUser

DECLARE @SectorID	INT
DECLARE @CurrDate	DATETIME
SET @CurrDate = CONVERT(DATETIME, CONVERT(NVARCHAR(20), GETDATE(), 103), 103)

CREATE TABLE #TmpSector 
(Line		NVARCHAR(10),
SectorID	INT,
SectorStr	NVARCHAR(50),
SectorOrder	INT )

CREATE TABLE #TmpInbox 
(TARID			BIGINT,
TARNo			NVARCHAR(20),
TARType			NVARCHAR(10),
AccessDate		NVARCHAR(20),
AccessTimeSlot		NVARCHAR(50),
AccessType		NVARCHAR(20),
SectorID		INT,
SectorStr		NVARCHAR(50) )

CREATE TABLE #TmpInboxList 
(TARID			BIGINT,
TARNo			NVARCHAR(20),
TARType			NVARCHAR(10),
AccessDate		NVARCHAR(20),
AccessTimeSlot		NVARCHAR(50),
AccessType		NVARCHAR(20),
SectorID		INT,
SectorStr		NVARCHAR(50) )

TRUNCATE TABLE #TmpSector
TRUNCATE TABLE #TmpInbox
TRUNCATE TABLE #TmpInboxList

INSERT INTO #TmpSector 
	(Line, SectorID, SectorStr, SectorOrder)
SELECT Line, ID, Sector, [Order] 
	FROM TAMS_Sector
		WHERE Line = @Line
		AND TrackType = @TrackType
			AND IsActive = 1
			AND @CurrDate BETWEEN EffectiveDate AND ExpiryDate
		ORDER BY [Order]

INSERT INTO #TmpInbox
	(TARID, TARNo, TARType, AccessDate,AccessTimeSlot, AccessType, SectorID, SectorStr)
SELECT a.[Id], a.[TARNo], a.[TARType], CONVERT(NVARCHAR(20), a.[AccessDate], 103), isnull(a.AccessTimeSlot,'') as AccessTimeSlot,a.[AccessType], b.[Id], b.[Sector] 
	FROM TAMS_TAR a, TAMS_Sector b, TAMS_TAR_Sector c, TAMS_TAR_Workflow d, TAMS_Endorser e
		WHERE b.[Id] = c.[SectorId]
			AND c.[TarId] = a.[Id]
			AND a.[Id] = d.[TARid]
			AND d.[EndorserId] = e.[Id]
			AND d.[WFStatus] like '%Pending%'
			 AND ISNULL(d.[UserId], 0) = 0
			AND e.[RoleId] IN (SELECT f.RoleID FROM TAMS_User_Role f WHERE f.UserID = @UserID) 
			AND (a.AccessDate = CONVERT(DATE, @AccessDate, 103) OR ISNULL(@AccessDate, '') = '')
			AND (a.TARType = @TARType OR ISNULL(@TARType, '') = '')
			AND c.[IsBuffer] = 0
		    AND a.TrackType = @TrackType
UNION
SELECT a.[Id], a.[TARNo], a.[TARType], CONVERT(NVARCHAR(20), a.[AccessDate], 103), isnull(a.AccessTimeSlot,'') as AccessTimeSlot,   a.[AccessType], b.[Id], b.[Sector] 
	FROM TAMS_TAR a, TAMS_Sector b, TAMS_TAR_Sector c, TAMS_TAR_Workflow d, TAMS_Endorser e
		WHERE b.[Id] = c.[SectorId]
			AND c.[TarId] = a.[Id]
			AND a.[Id] = d.[TARid]
			AND d.[EndorserId] = e.[Id]
			AND d.[WFStatus] like '%Pending%'
			AND d.[UserId] = @UserID
			AND (a.AccessDate = CONVERT(DATE, @AccessDate, 103) OR ISNULL(@AccessDate, '') = '')
			AND (a.TARType = @TARType OR ISNULL(@TARType, '') = '')
			AND c.[IsBuffer] = 0
			AND a.TrackType = @TrackType

DECLARE @Cur01 CURSOR;
DECLARE @CTARID			BIGINT
DECLARE @CTARNo			NVARCHAR(20)
DECLARE @CTARType		NVARCHAR(10)
DECLARE @CAccessDate	NVARCHAR(20)
DECLARE @CAccessTimeSlot	NVARCHAR(50)
DECLARE @CAccessType	NVARCHAR(20)
DECLARE @CSectorID		INT
DECLARE @CSectorStr		NVARCHAR(50)
DECLARE @CDirection		INT

DECLARE @Cur02 CURSOR;
DECLARE @C2ActionBy		INT
DECLARE @ActionByChk	INT

SET @Cur01 = CURSOR FAST_FORWARD 
FOR
	SELECT TARID, TARNo, TARType, AccessDate, AccessTimeSlot, AccessType, SectorID, SectorStr
		FROM #TmpInbox
			ORDER BY TARID, SectorID;		

OPEN @Cur01
	
FETCH NEXT FROM @Cur01 INTO @CTARID, @CTARNo, @CTARType, @CAccessDate,@CAccessTimeSlot, @CAccessType, @CSectorID, @CSectorStr
	
WHILE @@FETCH_STATUS = 0 
	
	BEGIN

		SET @ActionByChk = 0

		IF (SELECT COUNT(*) 
				FROM TAMS_TAR_Workflow
					WHERE TARId = @CTARID
						AND WFStatus <> 'Pending'
				) = 0
			BEGIN
				INSERT INTO #TmpInboxList
					(TARID, TARNo, TARType, AccessDate,AccessTimeSlot, AccessType, SectorID, SectorStr)
				VALUES
					(@CTARID, @CTARNo, @CTARType, @CAccessDate,@CAccessTimeSlot, @CAccessType, @CSectorID, @CSectorStr)
			END
		ELSE
			BEGIN
				-- >>
				SET @Cur02 = CURSOR FAST_FORWARD 
				FOR
					SELECT ActionBy
						FROM TAMS_TAR_Workflow
							WHERE TARId = @CTARID
								AND WFStatus <> 'Pending'

				OPEN @Cur02
	
				FETCH NEXT FROM @Cur02 INTO @C2ActionBy
	
				WHILE @@FETCH_STATUS = 0 
	
					BEGIN

						 -- >> Comment for 1 Man Testing
						IF (@UserID = @C2ActionBy)
							BEGIN
								SET @ActionByChk = @ActionByChk + 1
							END

						FETCH NEXT FROM @Cur02 INTO @C2ActionBy
					END 	

				CLOSE @Cur02
	
				DEALLOCATE @Cur02
				-- >>
			END

		IF (@ActionByChk = 0)
			BEGIN
				INSERT INTO #TmpInboxList
					(TARID, TARNo, TARType, AccessDate,AccessTimeSlot, AccessType, SectorID, SectorStr)
				VALUES
					(@CTARID, @CTARNo, @CTARType, @CAccessDate, @CAccessTimeSlot,@CAccessType, @CSectorID, @CSectorStr)
			END

		FETCH NEXT FROM @Cur01 INTO @CTARID, @CTARNo, @CTARType, @CAccessDate,@CAccessTimeSlot,  @CAccessType, @CSectorID, @CSectorStr
	END 	

CLOSE @Cur01
	
DEALLOCATE @Cur01

SELECT a.Line, a.SectorID, a.SectorStr,  a.SectorOrder  
	FROM #TmpSector a 
	GROUP BY a.Line, a.SectorID, a.SectorStr,  a.SectorOrder -- >>, b.TARID, b.TARNo, b.TARType, b.AccessDate, b.AccessType
	ORDER BY a.SectorOrder

 
-- >> Logic to check userid not yet inside

/*
	EXEC sp_TAMS_Inbox_OnLoad 'DTL', '', '', 'CSAPEX57'	
	EXEC sp_TAMS_Inbox_OnLoad 'NEL', '', '', 'CSAPEX57'	
*/

DROP TABLE #TmpSector
DROP TABLE #TmpInbox
DROP TABLE #TmpInboxList

END
GO
/****** END PROCEDURE 76 ******/

/****** START PROCEDURE 77 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_Depot_RGS_AckSurrender
CREATE PROCEDURE [dbo].[sp_TAMS_Depot_RGS_AckSurrender]
	@TARID		AS BIGINT = 0,
	@UserID		AS NVARCHAR(500),
	@Message	AS NVARCHAR(500) = NULL OUTPUT

AS

BEGIN

DECLARE	@IntrnlTrans	TINYINT
SELECT 	@IntrnlTrans 	= 0	

IF (@@TRANCOUNT = 0) 
BEGIN
	SET @IntrnlTrans = 1
	BEGIN TRAN
END

SET @Message = ''

DECLARE @NewLine AS CHAR(2) = CHAR(30) + CHAR(10)

DECLARE @UserIDID	INT = 1;

SELECT @UserIDID = Userid
	FROM TAMS_User
		WHERE LoginId = @UserID

DECLARE @TOAStatusChk INT

SELECT @TOAStatusChk = b.TOAStatus
	FROM TAMS_TAR a, TAMS_TOA b	
		WHERE a.Id = b.TARId
			AND a.Id = @TARID

IF @TOAStatusChk = 4
	BEGIN
		UPDATE TAMS_TOA
			SET	TOAStatus = 5,
				AckSurrenderTime = GETDATE(),
				UpdatedOn = GETDATE(),
				UpdatedBy = @UserID
		WHERE TARId = @TARID

		INSERT INTO TAMS_TOA_Audit
		SELECT @UserID, GETDATE(), 'U', * FROM TAMS_TOA
			WHERE TARId = @TARID

		DECLARE @SMSMsg	NVARCHAR(4000)
		SET @SMSMsg = ''

		DECLARE @lv_IsAllAckSurrender BIT
		DECLARE @AckSurrenderTime NVARCHAR(20)
		DECLARE @TARNo NVARCHAR(50)
		DECLARE @TOANo NVARCHAR(50)
		DECLARE @Line NVARCHAR(5)
		DECLARE @CurrDate NVARCHAR(20)
		DECLARE @CurrTime NVARCHAR(20)
		DECLARE @AccessDate DATE
		DECLARE @OperationDate DATE
		DECLARE @HPNo NVARCHAR(20)

		SET @lv_IsAllAckSurrender = 1

		SET @AckSurrenderTime = ''
		SET @TARNo = ''
		SET @Line = ''
		SET @CurrDate = ''
		SET @HPNo = ''

		SET @CurrDate = CONVERT(NVARCHAR(20), GETDATE(), 103)
		SET @CurrTime = CONVERT(NVARCHAR(20), GETDATE(), 108)

		SELECT @TARNo = a.TARNo,
				@TOANo = b.TOANo, 
				@Line = a.Line, 
				@AckSurrenderTime = CONVERT(NVARCHAR(20), b.AckSurrenderTime, 108),
				@AccessDate = b.AccessDate,
				@OperationDate = b.OperationDate,
				@HPNo = b.MobileNo
			FROM TAMS_TAR a, TAMS_TOA b	
				WHERE a.Id = b.TARId
					AND a.Id = @TARID

		
		DECLARE @Cur01 CURSOR;
		DECLARE @TOAStatus	INT

		SET @Cur01 = CURSOR FAST_FORWARD 
		FOR
		SELECT b.TOAStatus
			FROM TAMS_TAR a, TAMS_TOA b
				WHERE a.Id = b.TARId
					AND b.AccessDate = @AccessDate
					AND b.TOAStatus NOT IN (0, 6)
					AND a.Line = @Line
			ORDER BY b.Id
		OPEN @Cur01
		FETCH NEXT FROM @Cur01 INTO @TOAStatus
		WHILE @@FETCH_STATUS = 0 
			BEGIN
				IF @TOAStatus <> 5
					BEGIN
						SET @lv_IsAllAckSurrender = 0
					END
				FETCH NEXT FROM @Cur01 INTO @TOAStatus
			END 	
		CLOSE @Cur01
		DEALLOCATE @Cur01

		

		/***********************Changes for NEL , to start second phase of OCC once the TAR sectors has cleared********************************/
		IF @Line = 'NEL'
		BEGIN
			iF EXISTS(Select * from TAMS_TOA INNER JOIN TAMS_Depot_Auth ON
			TAMS_Depot_Auth.TarID=TAMS_TOA.TARId
			where TAMS_TOA.TARId=@TARID and TAMS_TOA.TOAStatus>=5)
			BEGIN
				DECLARE @authid as int;
				DECLARE @statusid as int;
				DECLARE @newstatusid as int;
				DECLARE @newworkflowid as int;
				DECLARE @workflowid as int;


				SELECT @authid=TAMS_Depot_Auth.ID,@statusid=DepotAuthStatusId FROM TAMS_Depot_Auth where TarID=@TARID

				if @statusid<>8 
				BEGIN
					SET @Message = 'Depot Authentication status is incorrect.'
					-- Auth status is not 8
					GOTO TRAP_ERROR
				END

				-- get next status
				select @newstatusid=WFStatusId+1 from TAMS_WFStatus where WFType='dtcauth' and WFStatusId=@statusid
				and isActive=1
				order by [Order] ASC;

				SELECT @workflowid=ID from TAMS_WFStatus where WFType='dtcauth' and WFStatusId=@statusid
				Select @newworkflowid=ID from TAMS_WFStatus where WFType='dtcauth' and WFStatusId=@newstatusid


				UPDATE TAMS_Depot_Auth_Workflow
				SET WFStatus='Completed', ActionBy=@UserID, ActionOn=getDate(),CheckBoxValue=1
				where WorkflowID=@workflowid

				INSERT INTO TAMS_Depot_Auth_Workflow
				SELECT @authid, null, null, null, @newworkflowid,null,0

				UPDATE TAMS_Depot_Auth
				SET DepotAuthStatusId=@newstatusid,UpdatedOn=getDate(),UpdatedBy=@UserID
				where ID=@authid
			END
		 			 

		END;
		/***********************END of Changes for NEL , to start second phase of OCC once the TAR sectors has cleared********************************/
		
		IF @Line = 'NEL'
			BEGIN
				SET @SMSMsg = CAST(@TOANo AS NVARCHAR(50)) + ' surrender has been acknowledged by NEL DCC @ ' + CAST(@CurrTime AS NVARCHAR(20))
					+ ' hrs on ' + CAST(@CurrDate AS NVARCHAR(20)) + '. Thank you!'
			END

		-- >> SEND SMS
		DECLARE @RetVal NVARCHAR(5)
		SET @RetVal = ''

			IF LTRIM(RTRIM(ISNULL(@HPNo, ''))) <> '' AND LTRIM(RTRIM(ISNULL(@SMSMsg, ''))) <> ''
				BEGIN
					EXEC sp_api_send_sms @HPNo, 'TAMS RGS', @SMSMsg, @RetVal OUTPUT
				END

	END
ELSE
	BEGIN
		IF @TOAStatus = 5
			BEGIN
				SET @Message = '1'
				-- TOA already granted. Please refresh RGS.
				GOTO TRAP_ERROR
			END
		ELSE
			BEGIN
				SET @Message = 'Invalid TAR status. Please refresg RGS.'
				GOTO TRAP_ERROR
			END
	END


IF @@ERROR <> 0 BEGIN
	SET @Message = 'Error RGS Ack Surrender'
	GOTO TRAP_ERROR
END

FORCE_EXIT_PROC:	
	IF @IntrnlTrans = 1 COMMIT TRAN
	RETURN @Message 

TRAP_ERROR:
	IF @IntrnlTrans = 1 ROLLBACK TRAN
	RETURN @Message

END
GO
/****** END PROCEDURE 77 ******/

/****** START PROCEDURE 78 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_Depot_RGS_GrantTOA
CREATE PROCEDURE [dbo].[sp_TAMS_Depot_RGS_GrantTOA]
	@TARID		AS BIGINT = 0,
	@EncTARID	AS NVARCHAR(250),
	@UserID		AS NVARCHAR(500),
	@toacallbacktiming AS datetime,
	@Message	AS NVARCHAR(500) = NULL OUTPUT
AS

BEGIN

DECLARE	@IntrnlTrans	TINYINT
SELECT 	@IntrnlTrans 	= 0	

IF (@@TRANCOUNT = 0) 
BEGIN
	SET @IntrnlTrans = 1
	BEGIN TRAN
END

SET @Message = ''

DECLARE @NewLine AS CHAR(2) = CHAR(30) + CHAR(10)

DECLARE @SMSMsg	NVARCHAR(4000)
SET @SMSMsg = ''

DECLARE @OPDate NVARCHAR(20)
DECLARE @TARNo NVARCHAR(50)
DECLARE @Line NVARCHAR(5)
DECLARE @CurrDate NVARCHAR(20)
DECLARE @AccessType NVARCHAR(20)
DECLARE @Site NVARCHAR(200)
DECLARE @HPNo NVARCHAR(20)
DECLARE @TOAStatus INT

SET @TARNo = ''
SET @Line = ''
SET @CurrDate = ''
SET @AccessType = ''
SET @Site = ''
SET @HPNo = ''
SET @TOAStatus = 0

SELECT @TARNo = a.TARNo, 
		@Line = a.Line, 
		@OPDate = CONVERT(NVARCHAR(20), b.OperationDate, 103),
		@AccessType = a.AccessType,
		@HPNo = b.MobileNo,
		@TOAStatus = b.TOAStatus
	FROM TAMS_TAR a, TAMS_TOA b	
		WHERE a.Id = b.TARId
			AND a.Id = @TARID

IF @TOAStatus = 2
	BEGIN
		DECLARE @RefNum		NVARCHAR(20)
		DECLARE @RefNumMsg	NVARCHAR(20)
		SET @RefNum = ''
		SET @RefNumMsg = ''
		EXEC sp_Generate_Ref_Num_TOA 'TOA', @Line,@TARID, @OPDate,'Depot', @RefNum OUTPUT, @RefNumMsg OUTPUT

		UPDATE TAMS_TOA
			SET	TOAStatus = 3,
				TOANo = @RefNum,
				TOACallbackTime=@toacallbacktiming,
				GrantTOATime = GETDATE(),
				UpdatedOn = GETDATE(),
				UpdatedBy = @UserID
		WHERE TARId = @TARID

		INSERT INTO TAMS_TOA_Audit
		SELECT @UserID, GETDATE(), 'U', * FROM TAMS_TOA
			WHERE TARId = @TARID

		SET @CurrDate = CONVERT(NVARCHAR(20), GETDATE(), 103)

		--IF @AccessType = 'Possession'
		--	BEGIN
		--		SET @SMSMsg = CAST(@RefNum AS NVARCHAR(50)) + ' has been granted for TAR ID ' + CAST(@TARNo AS NVARCHAR(20))
		--			+ '. You may now setup protection limit. Click on the link to acknowledge TOA :~'
		--			+ @Site + 'https://sbstweb.sbstransit.com.sg/TAMS/RGSAckSMS.aspx?TARID=' + CAST(@EncTARID AS NVARCHAR(500)) + '&SMSType=2'
		--	END
		--ELSE
		--	BEGIN
		--		SET @SMSMsg = CAST(@RefNum AS NVARCHAR(50)) + ' has been granted for TAR ID ' + CAST(@TARNo AS NVARCHAR(20))
		--			+ '. You may now proceed to work on track. Click on the link to acknowledge TOA :~'
		--			+ @Site + 'https://sbstweb.sbstransit.com.sg/TAMS/RGSAckSMS.aspx?TARID=' + CAST(@EncTARID AS NVARCHAR(500)) + '&SMSType=1'
		--	END

		IF @AccessType = 'Possession'
			BEGIN
				SET @SMSMsg = CAST(@RefNum AS NVARCHAR(50)) + ' has been granted for TAR ID ' + CAST(@TARNo AS NVARCHAR(20))
					+ '. Callback Timing: ' + FORMAT(@toacallbacktiming,'HH:mm') + 'hrs. Click on the link to acknowledge TOA :~'
					+ @Site + 'https://sbstweb.sbstransit.com.sg/TAMS/RGSAckSMS.aspx?TARID=' + CAST(@EncTARID AS NVARCHAR(500)) + '&SMSType=2'
			END
		ELSE
			BEGIN
				SET @SMSMsg = CAST(@RefNum AS NVARCHAR(50)) + ' has been granted for TAR ID ' + CAST(@TARNo AS NVARCHAR(20))
					+ '. Callback Timing: ' + FORMAT(@toacallbacktiming,'HH:mm') + 'hrs. Click on the link to acknowledge TOA :~'
					+ @Site + 'https://sbstweb.sbstransit.com.sg/TAMS/RGSAckSMS.aspx?TARID=' + CAST(@EncTARID AS NVARCHAR(500)) + '&SMSType=1'
			END


		-- >> SEND SMS
		DECLARE @RetVal NVARCHAR(5)
		SET @RetVal = ''

			IF @HPNo <> ''
				BEGIN
					EXEC sp_api_send_sms @HPNo, 'TAMS RGS', @SMSMsg, @RetVal OUTPUT
				END

		------ >> 20220818 Quickly trigger SMS Sending
		----	DECLARE @SMSOutputMsg NVARCHAR(500) 

		----	SET @SMSOutputMsg = ''

		----	EXEC SP_Call_SMTP_Send_SMSAlert @SMSOutputMsg OUTPUT

		----	IF @SMSOutputMsg <> ''
		----		BEGIN
		----			SET @Message = 'Error SMS Sending'
		----			GOTO TRAP_ERROR
		----		END
		------ >> 20220818 Quickly trigger SMS Sending
	END
ELSE
	BEGIN
		IF @TOAStatus = 3
			BEGIN
				SET @Message = '1'
				-- TOA already granted. Please refresh RGS.
				GOTO TRAP_ERROR
			END
		ELSE
			BEGIN
				SET @Message = 'Invalid TAR status. Please refresg RGS.'
				GOTO TRAP_ERROR
			END
	END

IF @@ERROR <> 0 BEGIN
	SET @Message = 'Error RGS Grant TOA'
	GOTO TRAP_ERROR
END

FORCE_EXIT_PROC:	
	IF @IntrnlTrans = 1 COMMIT TRAN
	RETURN @Message 

TRAP_ERROR:
	IF @IntrnlTrans = 1 ROLLBACK TRAN
	RETURN @Message

END
GO
/****** END PROCEDURE 78 ******/

/****** START PROCEDURE 79 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_Depot_RGS_OnLoad
CREATE procedure  [dbo].[sp_TAMS_Depot_RGS_OnLoad]
	@Line		NVARCHAR(20) = NULL,
	@TrackType	NVARCHAR(50) = NULL,
	@accessDate DATETIME
AS

BEGIN

DECLARE @NewLine AS NVARCHAR(6)
SET @NewLine = '<br />'

DECLARE @RGSPossBG			NVARCHAR(20)
DECLARE @RGSProtBG			NVARCHAR(20)
DECLARE @RGSCancBG			NVARCHAR(20)

--DECLARE @trainLine as NVARCHAR(10)
--SET @trainLine='DTL'
--DECLARE @trackType as nvarchar(10)
--SET @trackType='mainline'

--DECLARE @accessDate as Date
DECLARE @OperationDate as Date

DECLARE @CurDate		DATE
DECLARE @CurTime		TIME

SET @CurDate =  GETDATE()
SET @CurTime = CONVERT(TIME, GETDATE(), 108)


DECLARE @CutOff	TIME
SET @CutOff = '06:00:00'


SET @OperationDate	= @CurDate--DateAdd(day,-1,@CurDate)
--SET @AccessDate		= @CurDate--DateAdd(day,-1,@CurDate)--@CurDate

	
--SET @OperationDate = '2023-11-17'
--SET @AccessDate = '2023-11-18'

SELECT @RGSPossBG = ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'RGSPossessionBG'
			AND ParaValue1 = @Line

SELECT @RGSProtBG = ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'RGSProtectionBG'
			AND ParaValue1 = @Line

SELECT @RGSCancBG = ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'RGSCancelledBG'
			AND ParaValue1 = @Line


DECLARE @TOACallBackTime	NVARCHAR(10)
SET @TOACallBackTime = '18:00'


			

SELECT ROW_NUMBER() OVER (ORDER BY (SELECT 1)) as Sno,a.TARNo as TARNo, dbo.TAMS_Get_ES_NoBufferZone(a.Id) as ElectricalSections,
		CASE WHEN (a.Line='NEL' AND a.PowerOn = 1 AND a.AccessType='Possession')THEN (
			''
		)  WHEN (a.Line='NEL' ) THEN (
			(SELECT  ISNULL(CONVERT(NVARCHAR(5), max(dauthpz.PowerOffTiming), 108), '')
					FROM TAMS_Depot_Auth dauth INNER JOIN TAMS_Depot_Auth_Powerzone dauthpz ON
						dauth.ID=dauthpz.AuthID
						WHERE -- dauth.OperationDate = @OperationDate
							--AND 
							dauth.AccessDate = @accessDate
							and dauth.TarID=a.Id
							 AND dauthpz.PowerOffTiming is not null  and dauthpz.PowerOffType = 'Completed' 
							 
			)
		) END as PowerOffTime, 
					(SELECT  ISNULL(CONVERT(NVARCHAR(5), max(dauthpz.RackedOutTiming), 108), '')
					FROM TAMS_Depot_Auth dauth INNER JOIN TAMS_Depot_Auth_Powerzone dauthpz ON
						dauth.ID=dauthpz.AuthID INNER JOIN (
					SELECT i11.TARId 
					FROM TAMS_TAR_AccessReq i11, TAMS_Access_Requirement j11
						WHERE i11.IsPower = 1
							AND i11.OperationRequirement = j11.ID
							AND j11.ID = 48	-- >> 27 FOR NEL
							AND i11.IsSelected = 1
						) j2 on j2.TARId=a.Id
						WHERE 
							 dauth.TarID=a.Id
							--AND dauth.OperationDate = @OperationDate
							AND dauth.AccessDate = @accessDate
							 AND dauthpz.RackedOutTiming is not null and dauthpz.RackedOutType = 'Completed' 
						)
					as CircuitBreakOutTime,
						dbo.TAMS_Get_TOA_Parties(b.Id) as PartiesName,
						b.NoOfParties  as NoOfPersons,a.DescOfWork as WorkDescription, (b.MobileNo + @NewLine + b.TetraRadioNo) as ContactNo
						,ISNULL(b.TOANo, '') as TOANo,
		TOACallbackTime as CallBackTime,
		ISNULL(CONVERT(NVARCHAR(5), b.GrantTOATime, 108), '') as RadioMsgTime,
		ISNULL(CONVERT(NVARCHAR(5), b.AckSurrenderTime, 108), '') as LineClearMsgTime,
		[dbo].[SP_TAMS_RGS_Comments](a.Id,b.Id,'NEL','depot') as Remarks,
		b.TOAStatus,
		CONVERT(bit,
			(SELECT IIF(EXISTS(SELECT *
					FROM TAMS_Depot_Auth aa1 
							where 
							--aa1.OperationDate = @OperationDate
							--AND 
							aa1.AccessDate = @accessDate
							 AND aa1.DepotAuthStatusId >= 8 and TarID=a.ID) 
							 ,1,0)
		)) as IsTOAAuth,
		CASE WHEN TOAStatus=6 THEN @RGSCancBG ELSE CASE WHEN a.AccessType='Possession' THEN @RGSPossBG ELSE @RGSProtBG END END as ColourCode,
		--Grant TOA
		CONVERT(bit,1) as IsGrantTOAEnable,
		--CONVERT(bit,IIF(b.TOAStatus=6,1,IIF(a.Line='DTL',IIF(a.AccessType='Possession',1, IIF(@possession_ctrl=1,1,0)),1))) as IsGrantTOAEnable,
		ISNULL(CONVERT(NVARCHAR(5), b.UpdateQTSTime, 108), '') as UpdQTSTime,
		a.AccessType as AccessType,
		ISNULL(CONVERT(NVARCHAR(8), b.AckGrantTOATime, 108), '') as AckGrantTOATime,
		ISNULL(CONVERT(NVARCHAR(5), b.AckProtectionLimitTime, 108), '') as AckProtLimitTIme, 
		a.Id as TARID,
		b.Id as TOAID,
		dbo.DecryptString(b.InChargeNRIC) as InChargeNRIC
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND a.AccessDate = @accessDate
			and UPPER(a.TrackType) = 'DEPOT'
			AND b.TOAStatus <> 0
			AND a.Line = @Line
	-- >> ORDER BY a.AccessType, b.TOAType, a.Id
	ORDER BY a.AccessType,a.TARNo


-- >> Cancel List
SELECT a.Id AS Val, a.TARNo AS Txt
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND b.TOAStatus NOT IN (0, 5, 6)
			AND a.AccessDate = @accessDate
			AND a.Line = @Line
			AND UPPER(a.TrackType) = 'DEPOT'
	ORDER BY 1

SELECT CONVERT(NVARCHAR(20), @OperationDate, 103) AS OperationDate,  
	CONVERT(NVARCHAR(20), @accessDate, 103) AS AccessDate

	
END
GO
/****** END PROCEDURE 79 ******/

/****** START PROCEDURE 80 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_Depot_RGS_OnLoad_Enq
CREATE PROCEDURE  [dbo].[sp_TAMS_Depot_RGS_OnLoad_Enq]
	@Line	NVARCHAR(20) = NULL,
	@TrackType nvarchar(50) = null,
	@accessDate	Date = NULL
AS

BEGIN

DECLARE @NewLine AS NVARCHAR(6)
SET @NewLine = '<br />'

DECLARE @RGSPossBG			NVARCHAR(20)
DECLARE @RGSProtBG			NVARCHAR(20)
DECLARE @RGSCancBG			NVARCHAR(20)

--DECLARE @trainLine as NVARCHAR(10)
--SET @trainLine='DTL'
--DECLARE @trackType as nvarchar(10)
--SET @trackType='mainline'

--DECLARE @accessDate as Date
DECLARE @OperationDate as Date

DECLARE @CurDate		DATE
DECLARE @CurTime		TIME

SET @CurDate =  GETDATE()
SET @CurTime = CONVERT(TIME, GETDATE(), 108)


DECLARE @CutOff	TIME
SET @CutOff = '06:00:00'


SET @OperationDate	= @CurDate--DateAdd(day,-1,@CurDate)
--SET @AccessDate		= @CurDate--DateAdd(day,-1,@CurDate)--@CurDate

	
--SET @OperationDate = '2023-11-17'
--SET @AccessDate = '2023-11-18'

SELECT @RGSPossBG = ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'RGSPossessionBG'
			AND ParaValue1 = @Line

SELECT @RGSProtBG = ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'RGSProtectionBG'
			AND ParaValue1 = @Line

SELECT @RGSCancBG = ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'RGSCancelledBG'
			AND ParaValue1 = @Line


DECLARE @TOACallBackTime	NVARCHAR(10)
SET @TOACallBackTime = '18:00'


			

SELECT ROW_NUMBER() OVER (ORDER BY (SELECT 1)) as Sno,a.TARNo as TARNo, dbo.TAMS_Get_ES_NoBufferZone(a.Id) as ElectricalSections,
		CASE WHEN (a.Line='NEL' AND a.PowerOn = 1 AND a.AccessType='Possession')THEN (
			''
		)  WHEN (a.Line='NEL' ) THEN (
			(SELECT  ISNULL(CONVERT(NVARCHAR(5), max(dauthpz.PowerOffTiming), 108), '')
					FROM TAMS_Depot_Auth dauth INNER JOIN TAMS_Depot_Auth_Powerzone dauthpz ON
						dauth.ID=dauthpz.AuthID
						WHERE -- dauth.OperationDate = @OperationDate
							--AND 
							dauth.AccessDate = @accessDate
							and dauth.TarID=a.Id
							 AND dauthpz.PowerOffTiming is not null  and dauthpz.PowerOffType = 'Completed' 
							 
			)
		) END as PowerOffTime, 
					(SELECT  ISNULL(CONVERT(NVARCHAR(5), max(dauthpz.RackedOutTiming), 108), '')
					FROM TAMS_Depot_Auth dauth INNER JOIN TAMS_Depot_Auth_Powerzone dauthpz ON
						dauth.ID=dauthpz.AuthID INNER JOIN (
					SELECT i11.TARId 
					FROM TAMS_TAR_AccessReq i11, TAMS_Access_Requirement j11
						WHERE i11.IsPower = 1
							AND i11.OperationRequirement = j11.ID
							AND j11.ID = 48	-- >> 27 FOR NEL
							AND i11.IsSelected = 1
						) j2 on j2.TARId=a.Id
						WHERE 
							 dauth.TarID=a.Id
							--AND dauth.OperationDate = @OperationDate
							AND dauth.AccessDate = @accessDate
							 AND dauthpz.RackedOutTiming is not null and dauthpz.RackedOutType = 'Completed' 
						)
					as CircuitBreakOutTime,
						dbo.TAMS_Get_TOA_Parties(b.Id) as PartiesName,
						b.NoOfParties  as NoOfPersons,a.DescOfWork as WorkDescription, (b.MobileNo + @NewLine + b.TetraRadioNo) as ContactNo
						,ISNULL(b.TOANo, '') as TOANo,
		TOACallbackTime as CallBackTime,
		ISNULL(CONVERT(NVARCHAR(5), b.GrantTOATime, 108), '') as RadioMsgTime,
		ISNULL(CONVERT(NVARCHAR(5), b.AckSurrenderTime, 108), '') as LineClearMsgTime,
		[dbo].[SP_TAMS_RGS_Comments](a.Id,b.Id,'NEL','depot') as Remarks,
		b.TOAStatus,
		CONVERT(bit,
			(SELECT IIF(EXISTS(SELECT *
					FROM TAMS_Depot_Auth aa1 
							where 
							--aa1.OperationDate = @OperationDate
							--AND 
							aa1.AccessDate = @accessDate
							 AND aa1.DepotAuthStatusId >= 8 and TarID=a.ID) 
							 ,1,0)
		)) as IsTOAAuth,
		CASE WHEN TOAStatus=6 THEN @RGSCancBG ELSE CASE WHEN a.AccessType='Possession' THEN @RGSPossBG ELSE @RGSProtBG END END as ColourCode,
		--Grant TOA
		CONVERT(bit,1) as IsGrantTOAEnable,
		--CONVERT(bit,IIF(b.TOAStatus=6,1,IIF(a.Line='DTL',IIF(a.AccessType='Possession',1, IIF(@possession_ctrl=1,1,0)),1))) as IsGrantTOAEnable,
		ISNULL(CONVERT(NVARCHAR(5), b.UpdateQTSTime, 108), '') as UpdQTSTime,
		a.AccessType as AccessType,
		ISNULL(CONVERT(NVARCHAR(8), b.AckGrantTOATime, 108), '') as AckGrantTOATime,
		ISNULL(CONVERT(NVARCHAR(5), b.AckProtectionLimitTime, 108), '') as AckProtLimitTIme, 
		a.Id as TARID,
		b.Id as TOAID,
		dbo.DecryptString(b.InChargeNRIC) as InChargeNRIC
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND a.AccessDate = @accessDate
			and UPPER(a.TrackType) = 'DEPOT'
			AND b.TOAStatus <> 0
			AND a.Line = @Line
	-- >> ORDER BY a.AccessType, b.TOAType, a.Id
	ORDER BY a.AccessType,a.TARNo

		
SELECT --CONVERT(NVARCHAR(20), @OperationDate, 105) AS OperationDate,  
	CONVERT(NVARCHAR(20), @AccessDate, 105) AS AccessDate

END
GO
/****** END PROCEDURE 80 ******/

/****** START PROCEDURE 81 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_Depot_RGS_Update_Details
CREATE PROCEDURE  [dbo].[sp_TAMS_Depot_RGS_Update_Details]
	@TARID			AS BIGINT,
	@InchargeNRIC	AS NVARCHAR(50),
	@MobileNo		AS NVARCHAR(20),
	@TetraRadioNo	AS NVARCHAR(50),
	@UserID			AS NVARCHAR(500),
	@TrackType		AS NVARCHAR(50)='Mainline',
	@Message		AS NVARCHAR(500) = NULL OUTPUT
AS

BEGIN

DECLARE	@IntrnlTrans	TINYINT

SELECT 	@IntrnlTrans 	= 0	

IF (@@TRANCOUNT = 0) 
BEGIN
	SET @IntrnlTrans = 1
	BEGIN TRAN
END

CREATE TABLE #tmpnric 
(id BIGINT IDENTITY(1,1) NOT NULL, 
nric NVARCHAR(50),
namestr NVARCHAR(500),
line NVARCHAR(50),
qualdate NVARCHAR(50),
qualcode NVARCHAR(100),
qualstatus NVARCHAR(100))

TRUNCATE TABLE #tmpnric

DECLARE @ExecString	NVARCHAR(MAX)
SET @ExecString = ''
DECLARE @QualDate	NVARCHAR(20)
SET @QualDate = ''

DECLARE @InChargeName	NVARCHAR(500)
DECLARE @InChargeStatus	NVARCHAR(20)

SET @InChargeName = ''
SET @InChargeStatus = ''

DECLARE @Line NVARCHAR(20)
DECLARE @AccessDate DATE
DECLARE @AccessType NVARCHAR(50)
DECLARE @TOAID BIGINT

SELECT @Line = a.Line,
	@AccessDate = a.AccessDate,
	@TOAID = a.Id,
	@AccessType = b.AccessType
FROM TAMS_TOA a, TAMS_TAR b 
	WHERE a.TARId = @TARID
		AND a.TARId = b.Id

DECLARE @QTSQualCode		NVARCHAR(20)
DECLARE @QTSQualCodeProt	NVARCHAR(20)

SELECT @QTSQualCode = STRING_AGG(ParaValue2, ',')
	FROM TAMS_Parameters
		WHERE ParaCode = 'QTSQualCode'
			AND ParaValue1 = @Line
			AND ParaValue3 = CASE WHEN @TrackType='DEPOT' THEN 'Depot Possession' ELSE 'Mainline Possession' END
			AND ParaValue2 like CASE WHEN exists(select * from TAMS_TAR_AccessReq where TARId=@TARID and OperationRequirement in (43,45) and isSelected=1) THEN '%(Train%' ELSE '%(No%'  END								
			AND GETDATE() BETWEEN EffectiveDate AND ExpiryDate

SELECT @QTSQualCodeProt = STRING_AGG(ParaValue2, ',')
	FROM TAMS_Parameters
		WHERE ParaCode = 'QTSQualCode'
			AND ParaValue1 = @Line
			and ParaValue2 = @TrackType
			AND ParaValue3 = CASE WHEN UPPER(@TrackType)='DEPOT' THEN 'Depot Possession' ELSE 'Mainline Possession' END
			AND GETDATE() BETWEEN EffectiveDate AND ExpiryDate


SET @QualDate = CONVERT(NVARCHAR(20), @AccessDate, 103)

SET @QTSQualCode=@QTSQualCode + ','
SET @QTSQualCodeProt=@QTSQualCodeProt + ','

DECLARE @pos as int;
DECLARE @len as int;
DECLARE @qua as nvarchar(50)

set @pos = 0
set @len = 0

WHILE CHARINDEX(',', @QTSQualCode, @pos+1)>0
BEGIN
	set @len = CHARINDEX(',', @QTSQualCode, @pos+1) - @pos
	SELECT @pos, @len, SUBSTRING(@QTSQualCode, @pos, @len)

	SET @ExecString = CASE WHEN UPPER(@TrackType)='DEPOT' THEN 'sp_TAMS_Depot_TOA_QTS_Chk ' ELSE 'sp_TAMS_TOA_QTS_Chk ' END + '''' + @InchargeNRIC + ''', ''' + @QualDate + ''', ''' + @Line + ''', ''' + SUBSTRING(@QTSQualCode, @pos, @len) + ''''
									
	PRINT @ExecString

	INSERT INTO #tmpnric
	EXEC(@ExecString)

	set @pos = CHARINDEX(',', @QTSQualCode, @pos+@len) +1
end


--SET @ExecString = 'sp_TAMS_TOA_QTS_Chk '+ '''' + @InchargeNRIC + ''', ''' + @QualDate + ''', ''' + @Line + ''', ''' + @QTSQualCode + ''''

--INSERT INTO #tmpnric
--EXEC(@ExecString)

SELECT @InChargeName = namestr,
	@InChargeStatus = qualstatus
FROM #tmpnric

DECLARE @QTSFinStatus NVARCHAR(20)
SET @QTSFinStatus = ''

DECLARE @QTSFinQualCode NVARCHAR(50)
SET @QTSFinQualCode = ''

IF not exists(SELECT * FROM #tmpnric where qualstatus	= 'Valid')
		BEGIN
		IF @AccessType = 'Protection'
			BEGIN
				TRUNCATE TABLE #tmpnric
				SET @InChargeName = ''
				SET @InChargeStatus = ''


				set @pos = 0
				set @len = 0

				WHILE CHARINDEX(',', @QTSQualCodeProt, @pos+1)>0
				BEGIN
					set @len = CHARINDEX(',', @QTSQualCodeProt, @pos+1) - @pos

					SET @ExecString = CASE WHEN UPPER(@TrackType)='DEPOT' THEN 'sp_TAMS_Depot_TOA_QTS_Chk ' ELSE 'sp_TAMS_TOA_QTS_Chk ' END + '''' + @InchargeNRIC + ''', ''' + @QualDate + ''', ''' + @Line + ''', ''' + SUBSTRING(@QTSQualCodeProt, @pos, @len) + ''''
														
					PRINT @ExecString
					INSERT INTO #tmpnric
					EXEC(@ExecString)

					Select * from #tmpnric
								

					set @pos = CHARINDEX(',', @QTSQualCodeProt, @pos+@len) +1
				end

				--SET @ExecString = CASE WHEN UPPER(@TrackType)='DEPOT' THEN 'sp_TAMS_Depot_TOA_QTS_Chk ' ELSE 'sp_TAMS_TOA_QTS_Chk ' END + '''' + @InchargeNRIC + ''', ''' + @QualDate + ''', ''' + @Line + ''', '''' + @QTSQualCodeProt + '''''

				--INSERT INTO #tmpnric
				--EXEC(@ExecString)

				SELECT @InChargeName = namestr,
					@InChargeStatus = qualstatus
				FROM #tmpnric

				IF not exists(SELECT * FROM #tmpnric where qualstatus	= 'Valid')
					BEGIN
						SET @QTSFinStatus = 'InValid'
						SET @QTSFinQualCode = ''
					END
				ELSE
					BEGIN
						SET @QTSFinStatus = 'Valid'
						SELECT @QTSFinQualCode= STRING_AGG(qualcode, ',')  FROM #tmpnric where qualstatus	= 'Valid'
							PRINT @QTSFinQualCode
		
						--SET @QTSFinQualCode = @QTSFinQualCode + @QTSQualCodeProt + ',' 
					END
			END
		ELSE
			BEGIN
				SET @QTSFinStatus = 'InValid'
				SET @QTSFinQualCode = ''
			END
	END
ELSE
	BEGIN
		SET @QTSFinStatus = 'Valid'
	END

DROP TABLE #tmpnric

IF @QTSFinStatus = 'InValid'
	BEGIN
		SET @Message = '1' -- >> Invalid Qualification
	END
ELSE
	BEGIN
		DECLARE @InchargeCtr INT
		SET @InchargeCtr = 0
		SELECT @InchargeCtr = COUNT(*)
			FROM TAMS_TOA
				WHERE TARId = @TARID
					AND dbo.DecryptString(InChargeNRIC) = @InchargeNRIC

		IF @InchargeCtr = 0 -- >> New Incharge need to delete TOA_Parties
			BEGIN
				UPDATE TAMS_TOA
					SET InChargeNRIC = dbo.EncryptString(@InchargeNRIC),
						InChargeName = @InChargeName,
						MobileNo = @MobileNo,
						TetraRadioNo = @TetraRadioNo,
						UpdatedOn = GETDATE(),
						UpdatedBy = @UserID
					WHERE TARId = @TARID

				INSERT INTO TAMS_TOA_Audit
				SELECT @UserID, GETDATE(), 'U', * FROM TAMS_TOA
					WHERE TARId = @TARID

				INSERT INTO TAMS_TOA_Parties_Audit
				SELECT @UserID, GETDATE(), 'D', * FROM TAMS_TOA_Parties
					WHERE TOAId = @TOAID
						AND IsInCharge = 1

				DELETE FROM TAMS_TOA_Parties
					WHERE TOAId = @TOAID
						AND IsInCharge = 1

				INSERT INTO TAMS_TOA_Parties
					(TOAId, [Name], NRIC, IsInCharge, IsWitness, IsTMC, BookInTime, BookOutTime, BookInStatus)
				VALUES (@TOAID, @InChargeName, dbo.EncryptString(@InchargeNRIC), 1, 0, 0, GETDATE(), NULL, 'In')

				INSERT INTO TAMS_TOA_Parties_Audit
				SELECT @UserID, GETDATE(), 'I', * FROM TAMS_TOA_Parties
					WHERE TOAId = @TOAID
						AND IsInCharge = 1

			END
		ELSE
			BEGIN
				UPDATE TAMS_TOA
					SET MobileNo = @MobileNo,
						TetraRadioNo = @TetraRadioNo,
						UpdatedOn = GETDATE(),
						UpdatedBy = @UserID
					WHERE TARId = @TARID

				INSERT INTO TAMS_TOA_Audit
				SELECT @UserID, GETDATE(), 'U', * FROM TAMS_TOA
					WHERE TARId = @TARID
			END

		SET @Message = '0' -- >> Updated
	END

IF @@ERROR <> 0 BEGIN
	SET @Message = 'ERROR INSERTING INTO TAMS_TOA'
	GOTO TRAP_ERROR
END

FORCE_EXIT_PROC:	
	IF @IntrnlTrans = 1 COMMIT TRAN
	RETURN @Message 

TRAP_ERROR:
	IF @IntrnlTrans = 1 ROLLBACK TRAN
	RETURN @Message

END
GO
/****** END PROCEDURE 81 ******/

