/****** START PROCEDURE 83 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_Depot_RGS_Update_QTS
CREATE PROCEDURE  [dbo].[sp_TAMS_Depot_RGS_Update_QTS]
	@TARID			AS BIGINT,
	@InchargeNRIC	AS NVARCHAR(50),
	@UserID			AS NVARCHAR(500),
	@TrackType		AS NVARCHAR(50)='Mainline',
	@Message		AS NVARCHAR(500) = NULL OUTPUT,
	@QTSQCode		AS NVARCHAR(50) = NULL OUTPUT,
	@QTSLine		AS NVARCHAR(10) = NULL OUTPUT
AS

BEGIN

DECLARE	@IntrnlTrans	TINYINT

SELECT 	@IntrnlTrans 	= 0	

IF (@@TRANCOUNT = 0) 
BEGIN
	SET @IntrnlTrans = 1
	BEGIN TRAN
END

CREATE TABLE #tmpnric 
(id BIGINT IDENTITY(1,1) NOT NULL, 
nric NVARCHAR(50),
namestr NVARCHAR(500),
line NVARCHAR(50),
qualdate NVARCHAR(50),
qualcode NVARCHAR(100),
qualstatus NVARCHAR(100))

TRUNCATE TABLE #tmpnric

DECLARE @ExecString	NVARCHAR(MAX)
SET @ExecString = ''
DECLARE @QualDate	NVARCHAR(20)
SET @QualDate = ''

DECLARE @InChargeName	NVARCHAR(500)
DECLARE @InChargeStatus	NVARCHAR(20)

SET @InChargeName = ''
SET @InChargeStatus = ''

DECLARE @Line NVARCHAR(20)
DECLARE @AccessDate DATE
DECLARE @AccessType NVARCHAR(50)
DECLARE @TOAID BIGINT

SELECT @Line = a.Line,
	@AccessDate = a.AccessDate,
	@TOAID = a.Id,
	@AccessType = b.AccessType
FROM TAMS_TOA a, TAMS_TAR b 
	WHERE a.TARId = @TARID
		AND a.TARId = b.Id

DECLARE @QTSQualCode		NVARCHAR(50)
DECLARE @QTSQualCodeProt	NVARCHAR(50)

--SELECT @QTSQualCode = STRING_AGG(ParaValue2, ',')
--	FROM TAMS_Parameters
--		WHERE ParaCode = 'QTSQualCode'
--			AND ParaValue1 = @Line
--			AND ParaValue3 = CASE WHEN UPPER(@TrackType)='DEPOT' THEN 'Depot Possession' ELSE 'Mainline Possession' END
--			AND GETDATE() BETWEEN EffectiveDate AND ExpiryDate

SELECT @QTSQualCode = STRING_AGG(ParaValue2, ',')
	FROM TAMS_Parameters
		WHERE ParaCode = 'QTSQualCode'
			AND ParaValue1 = @Line
			AND ParaValue3 = CASE WHEN UPPER(@TrackType)='DEPOT' THEN 'Depot Possession' ELSE 'Mainline Possession' END
			-- AND ParaValue2 like CASE WHEN exists(select * from TAMS_TAR_AccessReq where TARId=@TARID and OperationRequirement in (43,45) and isSelected=1) THEN '%(Train%' ELSE '%(No%'  END	
			AND ParaValue2 like CASE WHEN exists(select * from TAMS_TAR_AccessReq where TARId=@TARID and OperationRequirement in (43,45) and isSelected=1) THEN '%(Train%' ELSE '%PC D%'  END								
			AND GETDATE() BETWEEN EffectiveDate AND ExpiryDate

SELECT @QTSQualCodeProt = STRING_AGG(ParaValue2, ',')
	FROM TAMS_Parameters
		WHERE ParaCode = 'QTSQualCode'
			AND ParaValue1 = @Line
			AND ParaValue3 = CASE WHEN UPPER(@TrackType)='DEPOT' THEN 'Depot' ELSE 'Mainline' END
			AND GETDATE() BETWEEN EffectiveDate AND ExpiryDate


SET @QualDate = CONVERT(NVARCHAR(20), @AccessDate, 103)

SET @QTSQualCode=@QTSQualCode + ','
SET @QTSQualCodeProt=@QTSQualCodeProt + ','

PRINT @QTSQualCode;
PRINT @QTSQualCodeProt

--SET @ExecString = CASE WHEN UPPER(@TrackType)='DEPOT' THEN 'sp_TAMS_Depot_TOA_QTS_Chk ' ELSE 'sp_TAMS_TOA_QTS_Chk ' END + '''' + @InchargeNRIC + ''', ''' + @QualDate + ''', ''' + @Line + ''', ' + '''' + @QTSQualCode + '''' + ''''


DECLARE @pos as int;
DECLARE @len as int;
DECLARE @qua as nvarchar(50)

set @pos = 0
set @len = 0

WHILE CHARINDEX(',', @QTSQualCode, @pos+1)>0
BEGIN
	set @len = CHARINDEX(',', @QTSQualCode, @pos+1) - @pos
	SELECT @pos, @len, SUBSTRING(@QTSQualCode, @pos, @len)

	SET @ExecString = CASE WHEN UPPER(@TrackType)='DEPOT' THEN 'sp_TAMS_Depot_TOA_QTS_Chk ' ELSE 'sp_TAMS_TOA_QTS_Chk ' END + '''' + @InchargeNRIC + ''', ''' + @QualDate + ''', ''' + @Line + ''', ''' + SUBSTRING(@QTSQualCode, @pos, @len) + ''''
									
	PRINT @ExecString

	INSERT INTO #tmpnric
	EXEC(@ExecString)

	set @pos = CHARINDEX(',', @QTSQualCode, @pos+@len) +1
end


--print @ExecString

--INSERT INTO #tmpnric
--EXEC(@ExecString)
--print 'nric'

SELECT @InChargeName = namestr,
	@InChargeStatus = qualstatus
FROM #tmpnric

DECLARE @QTSFinStatus NVARCHAR(20)
SET @QTSFinStatus = ''

DECLARE @QTSFinQualCode NVARCHAR(50)
SET @QTSFinQualCode = ''
	PRINT @QTSFinQualCode

IF not exists(SELECT * FROM #tmpnric where qualstatus	= 'Valid')
--IF @InChargeStatus	= 'InValid'
	BEGIN
		IF @AccessType = 'Protection'
			BEGIN
				TRUNCATE TABLE #tmpnric
				SET @InChargeName = ''
				SET @InChargeStatus = ''


				set @pos = 0
				set @len = 0

				WHILE CHARINDEX(',', @QTSQualCodeProt, @pos+1)>0
				BEGIN
					set @len = CHARINDEX(',', @QTSQualCodeProt, @pos+1) - @pos

					SET @ExecString = CASE WHEN UPPER(@TrackType)='DEPOT' THEN 'sp_TAMS_Depot_TOA_QTS_Chk ' ELSE 'sp_TAMS_TOA_QTS_Chk ' END + '''' + @InchargeNRIC + ''', ''' + @QualDate + ''', ''' + @Line + ''', ''' + SUBSTRING(@QTSQualCodeProt, @pos, @len) + ''''
														
					PRINT @ExecString
					INSERT INTO #tmpnric
					EXEC(@ExecString)

					Select * from #tmpnric
								

					set @pos = CHARINDEX(',', @QTSQualCodeProt, @pos+@len) +1
				end

				--SET @ExecString = CASE WHEN UPPER(@TrackType)='DEPOT' THEN 'sp_TAMS_Depot_TOA_QTS_Chk ' ELSE 'sp_TAMS_TOA_QTS_Chk ' END + '''' + @InchargeNRIC + ''', ''' + @QualDate + ''', ''' + @Line + ''', '''' + @QTSQualCodeProt + '''''

				--INSERT INTO #tmpnric
				--EXEC(@ExecString)

				SELECT @InChargeName = namestr,
					@InChargeStatus = qualstatus
				FROM #tmpnric

				IF not exists(SELECT * FROM #tmpnric where qualstatus	= 'Valid')
					BEGIN
						SET @QTSFinStatus = 'InValid'
						SET @QTSFinQualCode = ''
					END
				ELSE
					BEGIN
						SET @QTSFinStatus = 'Valid'
						SELECT @QTSFinQualCode= STRING_AGG(qualcode, ',')  FROM #tmpnric where qualstatus	= 'Valid'
							PRINT @QTSFinQualCode
		
						--SET @QTSFinQualCode = @QTSFinQualCode + @QTSQualCodeProt + ',' 
					END
			END
		ELSE
			BEGIN
				SET @QTSFinStatus = 'InValid'
				SET @QTSFinQualCode = ''
			END
	END
ELSE
	BEGIN
		SET @QTSFinStatus = 'Valid'
		select * from #tmpnric

		SELECT @QTSFinQualCode= STRING_AGG(qualcode, ',')  FROM #tmpnric where qualstatus	= 'Valid'
		PRINT @QTSFinQualCode
		--SET @QTSFinQualCode = @QTSFinQualCode + @QTSQualCode + ','
	END

DROP TABLE #tmpnric


--SELECT @QTSFinQualCode

IF @QTSFinStatus = 'InValid'
	BEGIN
		SET @Message = '1' -- >> Invalid Qualification
		SET @QTSQCode = ''
		SET @QTSLine = ''
	END
ELSE
	BEGIN

		-- >> Remove update of QTS time before calling QTS update // 05/09/2023
		--UPDATE TAMS_TOA
		--	SET UpdateQTSTime = GETDATE(),
		--		UpdatedOn = GETDATE(),
		--		UpdatedBy = @UserID
		--	WHERE TARId = @TARID

		--INSERT INTO TAMS_TOA_Audit
		--SELECT @UserID, GETDATE(), 'U', * FROM TAMS_TOA
		--	WHERE TARId = @TARID
		-- >> Remove update of QTS time before calling QTS update // 05/09/2023

		SET @Message = '0' -- >> Updated
		SET @QTSQCode = @QTSFinQualCode
		SET @QTSLine = @Line

		DECLARE @TAMSUser	NVARCHAR(500)
		SET @TAMSUser = ''
		SET @TAMSUser = 'TAMS-' + @UserID

		DECLARE @RetMsg NVARCHAR(500)
		SET @RetMsg = '1'


		DECLARE @ParamDefinition nvarchar(max)
		set @ParamDefinition = '  @Message nvarchar(500) ';
		
		-- >> EXEC [MSSQLDEVPSVR1].[QTSDB].[dbo].[sp_api_tams_qts_upd_accessdate] @InchargeNRIC, @QTSFinQualCode, @Line, @UserID, @RetMsg OUTPUT
		--EXEC [MSSQLDEVPSVR1].[QTSDB].[dbo].[sp_api_tams_qts_upd_accessdate] @InchargeNRIC, @QTSFinQualCode, @Line, @TAMSUser, @RetMsg OUTPUT
		
		set @pos = 0
		set @len = 0
		SET @QTSFinQualCode=@QTSFinQualCode + ','



		WHILE CHARINDEX(',', @QTSFinQualCode, @pos+1)>0
				BEGIN
					set @len = CHARINDEX(',', @QTSFinQualCode, @pos+1) - @pos
					
					--SET @ExecString = 'EXEC [QTSDB].[dbo].[sp_api_tams_qts_upd_accessdate] ' + '''' + @InchargeNRIC + ''', ''' + SUBSTRING(@QTSFinQualCode, @pos, @len) + ''', ''' + @Line + ''', ''' + @TAMSUser + '''' + ',' + '@Message OUTPUT'
					
					DECLARE @qualcode as nvarchar(4000);
					SET @qualcode=SUBSTRING(@QTSFinQualCode, @pos, @len)

					EXEC [flexnetskgsvr].[QTSDB].[dbo].[sp_api_tams_qts_upd_accessdate] @nric = @InchargeNRIC,@qcode=@qualcode,@rail=@line,@UserID=@TAMSUser,@Msg=@Retmsg OUTPUT

					--EXEC [QTSDB].[dbo].[sp_api_tams_qts_upd_accessdate] @nric = @InchargeNRIC,@qcode=@qualcode,@rail=@line,@UserID=@TAMSUser,@Message=@Retmsg OUTPUT

					 --PRINT 'msg' + @Retmsg
					--SET @ParamDefinition=N'@RetMsg NVARCHAR(500) OUTPUT'

					--PRINT @ExecString
					--EXEC sp_executesql @ExecString, @ParamDefinition, @Message=@RetMsg
					--EXEC [QTSDB].[dbo].[sp_api_tams_qts_upd_accessdate] @InchargeNRIC, SUBSTRING(@QTSFinQualCode, @pos, @len) , @Line, @TAMSUser, @RetMsg OUTPUT
		--SELECT @RetMsg
					set @pos = CHARINDEX(',', @QTSFinQualCode, @pos+@len) +1
				end

				--PRINT 'Return msg'
				--PRINT LEN(@RetMsg)
		IF TRIM(@RetMsg) = ''
			BEGIN
				UPDATE TAMS_TOA
					SET UpdateQTSTime = GETDATE(),
						UpdatedOn = GETDATE(),
						UpdatedBy = @UserID
					WHERE TARId = @TARID

				INSERT INTO TAMS_TOA_Audit
				SELECT @UserID, GETDATE(), 'U', * FROM TAMS_TOA
					WHERE TARId = @TARID

				SET @Message = '0' -- >> Updated
			END
		ELSE
			BEGIN
				SET @Message = '2'-- >> Error Updating
			END

	END

DECLARE @ErrorMessage NVARCHAR(4000);
DECLARE @ErrorNumber INT;
DECLARE @ErrorSeverity INT;
DECLARE @ErrorState INT;

SET @ErrorMessage = '';
SET @ErrorNumber = 0;
SET @ErrorSeverity = 0;
SET @ErrorState = 0;

IF @@ERROR <> 0 BEGIN
	SET @Message = 'ERROR INSERTING INTO TAMS_TOA'

	SET @ErrorMessage = ERROR_MESSAGE();
    SET @ErrorNumber = ERROR_NUMBER();
    SET @ErrorSeverity = ERROR_SEVERITY();
    SET @ErrorState = ERROR_STATE();

	GOTO TRAP_ERROR
END

FORCE_EXIT_PROC:	
	IF @IntrnlTrans = 1 COMMIT TRAN
	RETURN @Message 

TRAP_ERROR:
	IF @IntrnlTrans = 1 ROLLBACK TRAN

	INSERT INTO TAMS_QTS_Error_Log
		(TARID, InchargeNRIC, QualCode, RailLine, UserID, ErrorDateTime, FullErrorMsg)
	VALUES
		(@TARID, dbo.EncryptString(@InchargeNRIC), @QTSFinQualCode, @Line, @TAMSUser, GETDATE(), @ErrorMessage)

	RETURN @Message

END
GO
/****** END PROCEDURE 83 ******/

/****** START PROCEDURE 84 ******/
-- PROCEDURE NAME: dbo.SP_TAMS_Depot_SaveDTCAuthComments
CREATE PROCEDURE [dbo].[SP_TAMS_Depot_SaveDTCAuthComments]
	-- Add the parameters for the stored procedure here
	--@authid as int,
	@str TAMS_DTC_AUTH_COMMENTS readonly,
	@success as bit=NULL OUTPUT,
	@Message AS NVARCHAR(500) = NULL OUTPUT
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

	
	DECLARE	@IntrnlTrans	TINYINT
	SELECT 	@IntrnlTrans 	= 0	

	IF (@@TRANCOUNT = 0) 
	BEGIN
		SET @IntrnlTrans = 1
		BEGIN TRAN
	END

			-- insert comments

		DECLARE @authid as int;
		DECLARE @comments as nvarchar(max);

		DECLARE C CURSOR FOR
		SELECT authid,comments from @str 
		OPEN C;

		FETCH NEXT FROM C INTO @authid, @comments
		WHILE @@FETCH_STATUS=0
		BEGIN 
		
			DECLARE @remarkid as int=-1;
			Select @remarkid=RemarkID from TAMS_Depot_Auth where id=@authid and RemarkID is not null

			if @remarkid<>-1
			BEGIN
				UPDATE TAMS_Depot_Auth_Remark
				SET Remark=@comments
				where RemarkID=@remarkid
			END
			ELSE
			BEGIN
				INSERT INTO TAMS_Depot_Auth_Remark
				VALUES(@comments)

				SET @remarkid=SCOPE_IDENTITY();

				UPDATE TAMS_Depot_Auth
				SET RemarkID=@remarkid
				where id=@authid;
			END
		
	
		FETCH NEXT FROM C INTO @authid, @comments
	END
	CLOSE C;
	DEALLOCATE C;

		
	IF @@ERROR <> 0 BEGIN
		SET @Message = 'ERROR INSERTING INTO Depot Authorization module.'
		
		PRINT 'trap error'
		GOTO TRAP_ERROR
	END

	FORCE_EXIT_PROC:	
	
		PRINT 'trap error 1'
		IF @IntrnlTrans = 1 COMMIT TRAN
		set @success=1;
		RETURN;
		--RETURN @Message 

	TRAP_ERROR:
	
		PRINT 'trap error 2'
		IF @IntrnlTrans = 1 ROLLBACK TRAN
		set @success=0;
		RETURN;
		--RETURN @Message
END
GO
/****** END PROCEDURE 84 ******/

/****** START PROCEDURE 85 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_Depot_SectorBooking_OnLoad
CREATE procedure  [dbo].[sp_TAMS_Depot_SectorBooking_OnLoad]
	@Line		AS NVARCHAR(10) = NULL,
	@TrackType	AS NVARCHAR(50) = NULL,
	@AccessDate	AS NVARCHAR(20) = NULL,
	@TARType	AS NVARCHAR(20) = NULL,
	@AccessType	AS NVARCHAR(20) = NULL	
AS

BEGIN

	CREATE TABLE #ListES
	(Line				NVARCHAR(10),
	SectorID			BIGINT,
	Sector				NVARCHAR(50),
	PowerZone			NVARCHAR(100),
	SPKSZone			NVARCHAR(100),
	FromTrack			NVARCHAR(200),
	ToTrack			NVARCHAR(200),
	IsSelected			BIT,
	IsEnabled			BIT,
	ColorCode			NVARCHAR(50),
	OrderID				INT 
	  )
	
	TRUNCATE TABLE #ListES

	DECLARE @CurID					BIGINT
	DECLARE @CurLine				NVARCHAR(10)
	 DECLARE @CurSector				NVARCHAR(50)
 	DECLARE @CurOrderID				INT
	DECLARE @PowerZone				NVARCHAR(100)
	DECLARE @SPKSZone				NVARCHAR(100)
	 
 

	DECLARE @ColorCode		NVARCHAR(50)
	SET @ColorCode = ''

	DECLARE @CCAccessType	NVARCHAR(50)
	SET @CCAccessType = ''

	-- >> Insert into temp table
	IF @Line = 'NEL'
		BEGIN
			INSERT INTO #ListES (Line,   SectorID, Sector, FromTrack,ToTrack, OrderID, IsEnabled)
			SELECT a.Line,  a.ID, a.Sector, a.FromTrack,a.ToTrack, a.[Order], 1
				FROM TAMS_Sector a
					WHERE a.Line = @Line
					and TrackType = @TrackType
						AND a.IsActive = 1 
							AND (a.EffectiveDate <= GETDATE() AND a.ExpiryDate >= GETDATE())
				ORDER BY a.[Order] ASC
		END
 

		DECLARE @Cur01 CURSOR;

		SET @Cur01 = CURSOR FAST_FORWARD 
		FOR

			SELECT a.ID, a.Line,  a.Sector,   a.[Order]
				FROM TAMS_Sector a
					WHERE a.Line = @Line
					and TrackType = @TrackType
						AND a.IsActive = 1 
						AND (a.EffectiveDate <= GETDATE() AND a.ExpiryDate >= GETDATE())
			ORDER BY a.[Order] ASC

		OPEN @Cur01
	
		FETCH NEXT FROM @Cur01 INTO @CurID, @CurLine,  @CurSector,   @CurOrderID
	
		WHILE @@FETCH_STATUS = 0 
	
			BEGIN

				SET @PowerZone = ''
				SET @ColorCode = ''
				SET @SPKSZone = ''
				 

				SELECT @SPKSZone = @SPKSZone + ISNULL(SPKSZone + ',', '') 
					FROM TAMS_SPKSZone a, TAMS_Track_SPKSZone b	
						WHERE a.ID = b.SPKSId
							AND a.IsActive = 1
							AND b.IsActive = 1
							 AND b.SectorId = @CurID
				SELECT @PowerZone = @PowerZone + ISNULL(PowerSector + ',', '') 
					FROM TAMS_Power_Sector a, TAMS_Track_Power_Sector b	
						WHERE a.ID = b.PowerSectorId
							AND a.IsActive = 1
							AND b.IsActive = 1
							AND b.IsBuffer = 0 
							 AND b.SectorId = @CurID
				 		

					IF LEN(LTRIM(RTRIM(@SPKSZone))) > 0
					BEGIN
						SET @SPKSZone = LEFT(LTRIM(RTRIM(@SPKSZone)), LEN(LTRIM(RTRIM(@SPKSZone))) - 1)
					END

					IF LEN(LTRIM(RTRIM(@PowerZone))) > 0
					BEGIN
						SET @PowerZone = LEFT(LTRIM(RTRIM(@PowerZone)), LEN(LTRIM(RTRIM(@PowerZone))) - 1)
					END
				
				SELECT @ColorCode = ISNULL(b.ColourCode, ''),
						@CCAccessType = ISNULL(a.AccessType, '') 
					FROM TAMS_TAR a, TAMS_TAR_Sector b
						WHERE a.Id = b.TARId
							AND a.AccessDate = CONVERT(DATETIME, @AccessDate, 103)
							AND ( (a.Line = 'NEL' and a.TARStatusId = 9 ) or (a.Line = 'DTL' and a.TARStatusId = 8)) -- >> Approved
							AND a.IsExclusive = 1 
							AND b.SectorId = @CurID 
							AND a.Line = @Line
							and TrackType = @TrackType
				
				IF @ColorCode = ''
					BEGIN
						UPDATE #ListES
							SET IsEnabled = 1,
								ColorCode = '',
								SPKSZone = @SPKSZone, 
								PowerZone = @PowerZone
						WHERE SectorID = @CurID
					END
				ELSE
					BEGIN
						UPDATE #ListES
							SET ColorCode = @ColorCode,
								SPKSZone = @SPKSZone, 
								PowerZone = @PowerZone
						WHERE SectorID = @CurID

						IF (@TARType = '2' OR @TARType = '3') 
								AND @AccessType = 'Protection' 
								AND @ColorCode = ''
								AND @CCAccessType = 'Possession'
							BEGIN
								UPDATE #ListES
									SET IsEnabled = 1,
										ColorCode = '',
										SPKSZone = @SPKSZone, 
									PowerZone = @PowerZone
								WHERE SectorID = @CurID
							END
						ELSE
							BEGIN
								UPDATE #ListES
									SET 
										--IsEnabled = 0,
										SPKSZone = @SPKSZone, 
										PowerZone = @PowerZone
								WHERE SectorID = @CurID
							END
					END

				FETCH NEXT FROM @Cur01 INTO @CurID, @CurLine,   @CurSector,  @CurOrderID
			END 	

		CLOSE @Cur01
	
		DEALLOCATE @Cur01
	
	SELECT Line,
		 SectorID,
		Sector,
 		IsSelected,
		IsEnabled,
		ColorCode,
 		OrderID,
		PowerZone,
		SPKSZone, 
		FromTrack,
		ToTrack
	FROM #ListES
	 	ORDER BY OrderID, SectorID

 

/*
	EXEC sp_TAMS_SectorBooking_OnLoad 'DTL', '01/02/2021', '2', 'Possession'
	EXEC sp_TAMS_SectorBooking_OnLoad 'DTL', '01/02/2021', '2', 'Protection'
	EXEC sp_TAMS_SectorBooking_OnLoad 'DTL', '01/02/2021', '1', 'Protection'
	EXEC sp_TAMS_SectorBooking_OnLoad 'NEL', '01/02/2021', '1', 'Protection'
*/

	IF @AccessType = 'Protection'
		BEGIN
			SELECT ID, OperationRequirement 
				FROM TAMS_Access_Requirement
					WHERE Line = @Line
					and TrackType = @TrackType
						AND IsPowerReq = 1
						AND OperationRequirement = 'Traction Power ON'
						AND IsActive = 1
					ORDER BY [Order]
		END
	ELSE
		BEGIN
			SELECT ID, OperationRequirement 
				FROM TAMS_Access_Requirement
					WHERE Line = @Line
					and TrackType = @TrackType
						AND IsPowerReq = 1
						AND IsActive = 1
					ORDER BY [Order]
		END

END
GO
/****** END PROCEDURE 85 ******/

/****** START PROCEDURE 86 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_Depot_SectorBooking_QTS_Chk
CREATE   procedure  [dbo].[sp_TAMS_Depot_SectorBooking_QTS_Chk] 
	@nric NVARCHAR(MAX) = null,
	@qualdate NVARCHAR(MAX) = null,
	@line NVARCHAR(MAX) = null,
	@TrackType NVARCHAR(50) = null
AS
BEGIN

/*
exec sp_TAMS_SectorBooking_QTS_Chk 'S1111111A',
	'10/05/2021',
	'DTL'
*/

DECLARE @Message NVARCHAR(500)

SET @Message = ''

DECLARE @EPCtr BIGINT
DECLARE @BLCtr BIGINT
DECLARE @RTCtr BIGINT

SET @EPCtr = 0
SET @BLCtr = 0
SET @RTCtr = 0

DECLARE @RetVal NVARCHAR(5)

SET @RetVal = '0'

CREATE TABLE #tmpqtsqc 
(id BIGINT IDENTITY(1,1) NOT NULL, 
access_id NVARCHAR(50),
pq_lastaccess_date	DATETIME NULL,
pq_validaccess_date	DATETIME NULL,
pq_validtill_date	DATETIME NULL,
suspened_till		DATETIME NULL)

CREATE TABLE #tmpnric 
(id BIGINT IDENTITY(1,1) NOT NULL, 
nric NVARCHAR(50),
namestr NVARCHAR(500),
qualdate NVARCHAR(50),
qualcode NVARCHAR(100),
line NVARCHAR(50),
qualstatus NVARCHAR(100))

CREATE TABLE #tmpqualcode 
( qual_code nvarchar(50))

TRUNCATE TABLE #tmpnric;
TRUNCATE TABLE #tmpqtsqc;
TRUNCATE TABLE #tmpqualcode;

 

insert into #tmpqualcode
SELECT   ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'QTSQualCode'
			AND ParaValue1 = @line
			 AND ParaValue3 = 'Depot Possession' 
			AND CONVERT(DATETIME, @qualdate, 103) BETWEEN EffectiveDate AND ExpiryDate

INSERT INTO #tmpnric (nric, namestr, qualdate, qualcode, line, qualstatus)
VALUES (@nric, NULL, @qualdate, '', @line, NULL)

DECLARE @CurID		BIGINT
DECLARE @CurNRIC	NVARCHAR(50)
DECLARE @CurQualDate NVARCHAR(50)
DECLARE @CurQualCode NVARCHAR(100)
DECLARE @CurLine	NVARCHAR(50)
DECLARE @CurNameStr		NVARCHAR(500)

DECLARE @QualCtr	BIGINT
SET @QualCtr = 0

DECLARE @Cur01 CURSOR;
SET @Cur01 = CURSOR FAST_FORWARD 
FOR

SELECT id, nric, qualdate, qualcode, line
FROM #tmpnric
	ORDER BY 1 ASC

OPEN @Cur01
	FETCH NEXT FROM @Cur01 INTO @CurID, @CurNRIC, @CurQualDate, @CurQualCode, @CurLine
	WHILE @@FETCH_STATUS = 0 
		BEGIN
			SET @QualCtr = 0

			SELECT @CurNameStr = p_name
				FROM [FLEXNETSKGSVR].[QTSDB].[dbo].QTS_Personnel
					WHERE p_active = 1
					AND dbo.DecryptStringQTS(p_access_id) = @CurNRIC

TRUNCATE TABLE #tmpqtsqc

print '@CurQualCode'; 
print @CurQualCode; 
INSERT INTO #tmpqtsqc
(access_id, pq_lastaccess_date, pq_validaccess_date, pq_validtill_date, suspened_till)
SELECT dbo.DecryptStringQTS(cc.p_access_id),
	aa.pq_lastaccess_date AS pq_lastaccess_date,
	aa.pq_validaccess_date AS pq_validaccess_date,
	aa.pq_validtill_date AS pq_validtill_date,
CASE WHEN aa.pq_suspend_to IS NOT NULL THEN
	CASE WHEN aa.pq_reinstate_eff IS NULL THEN
			CASE WHEN aa.pq_suspend_to > current_timestamp THEN aa.pq_suspend_to ELSE '' END
		WHEN aa.pq_suspend_to < aa.pq_reinstate_eff
			THEN CASE WHEN aa.pq_suspend_to > current_timestamp THEN aa.pq_suspend_to ELSE '' END
				ELSE CASE WHEN aa.pq_reinstate_eff > current_timestamp THEN aa.pq_reinstate_eff ELSE '' END
	END
END AS suspened_till
FROM [FLEXNETSKGSVR].[QTSDB].[dbo].QTS_Personnel_Qualification aa, 
	[FLEXNETSKGSVR].[QTSDB].[dbo].QTS_Qualification bb, 
	[FLEXNETSKGSVR].[QTSDB].[dbo].QTS_Personnel cc
WHERE cc.p_id = aa.pq_p_id
	AND aa.pq_qual_id = bb.qual_id
	AND cc.p_rail = @CurLine
	AND bb.qual_rail = @CurLine
	AND (bb.qual_access_period != 99
		AND bb.qual_code not like '%EPIC%'
		AND bb.qual_code not like '%OSM%'
		AND bb.qual_code  != 'TTP')
	AND bb.qual_code in (Select qual_code from #tmpqualcode)
	AND dbo.DecryptStringQTS(cc.p_access_id) = @CurNRIC

			SELECT @QualCtr = COUNT(*) 
				FROM #tmpqtsqc
					WHERE access_id = @CurNRIC

			IF @QualCtr = 0 -- >> IF NO RECORD, INVALID
				BEGIN
					-- >> SELECT '1'
					UPDATE #tmpnric
						SET qualstatus = 'InValid',
						namestr = @CurNameStr
					WHERE id = @CurID
				END
			ELSE
				BEGIN
					SELECT @QualCtr = COUNT(*) 
						FROM #tmpqtsqc
							WHERE access_id = @CurNRIC
								AND suspened_till IS NULL

					IF @QualCtr > 0 -- >> No Suspension Information
						BEGIN
							SELECT @QualCtr = COUNT(*) 
								FROM #tmpqtsqc
									WHERE access_id = @CurNRIC
										AND (CONVERT(DATETIME, @CurQualDate, 103) < pq_validaccess_date
										AND CONVERT(DATETIME, @CurQualDate, 103) < pq_validtill_date)

								IF @QualCtr > 0
									BEGIN
										-- >> SELECT '3'
										UPDATE #tmpnric
											SET qualstatus = 'Valid',
												namestr = @CurNameStr
										WHERE id = @CurID
									END
								ELSE
									BEGIN
										-- >> SELECT '4'
										UPDATE #tmpnric
											SET qualstatus = 'InValid',
												namestr = @CurNameStr
										WHERE id = @CurID
									END
						END
					ELSE
						BEGIN
							UPDATE #tmpnric
								SET qualstatus = 'InValid',
									namestr = @CurNameStr
							WHERE id = @CurID
						END
				END

			---SELECT @CurID, @CurNRIC, @CurQualDate, @CurQualCode, @CurLine

			FETCH NEXT FROM @Cur01 INTO @CurID, @CurNRIC, @CurQualDate, @CurQualCode, @CurLine
		END 	
	CLOSE @Cur01
	DEALLOCATE @Cur01

SELECT LTRIM(RTRIM(ISNULL(nric, ''))) AS nric, 
		LTRIM(RTRIM(ISNULL(namestr, ''))) AS namestr,
		LTRIM(RTRIM(ISNULL(line, ''))) AS line,
		LTRIM(RTRIM(ISNULL(qualdate, ''))) AS qualdate, 
		LTRIM(RTRIM(ISNULL(qualcode, ''))) AS qualcode, 
		LTRIM(RTRIM(ISNULL(qualstatus, ''))) AS qualstatus
	FROM #tmpnric
ORDER BY ID

------SELECT * FROM #tmpqtsqc

DROP TABLE #tmpqtsqc
DROP TABLE #tmpnric
drop table #tmpqualcode

END
GO
/****** END PROCEDURE 86 ******/

/****** START PROCEDURE 87 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_Depot_TOA_QTS_Chk
CREATE PROCEDURE [dbo].[sp_TAMS_Depot_TOA_QTS_Chk] 
	@nric		NVARCHAR(50) = NULL,
	@qualdate	NVARCHAR(20) = NULL,
	@line		NVARCHAR(20) = NULL,
	@QualCode	NVARCHAR(50) = NULL
AS
BEGIN

DECLARE @Message NVARCHAR(500)

SET @Message = ''

DECLARE @EPCtr BIGINT
DECLARE @BLCtr BIGINT
DECLARE @RTCtr BIGINT

SET @EPCtr = 0
SET @BLCtr = 0
SET @RTCtr = 0

DECLARE @RetVal NVARCHAR(5)

SET @RetVal = '0'

CREATE TABLE #tmpqtsqc 
(id BIGINT IDENTITY(1,1) NOT NULL, 
access_id NVARCHAR(50),
pq_lastaccess_date	DATETIME NULL,
pq_validaccess_date	DATETIME NULL,
pq_validtill_date	DATETIME NULL,
suspened_till		DATETIME NULL)

TRUNCATE TABLE #tmpqtsqc

DECLARE @CurID		BIGINT
DECLARE @CurNRIC	NVARCHAR(50)
DECLARE @CurQualDate NVARCHAR(50)
DECLARE @CurQualCode NVARCHAR(100)
DECLARE @CurLine	NVARCHAR(50)
DECLARE @CurNameStr		NVARCHAR(500)

DECLARE @QualStatus			NVARCHAR(50)
DECLARE @lastaccess_date	DATETIME
DECLARE @validaccess_date	DATETIME
DECLARE @validtill_date		DATETIME
DECLARE @suspened_till		DATETIME

DECLARE @QualCtr	BIGINT
SET @QualCtr = 0

SELECT @CurNameStr = p_name
	FROM [flexnetskgsvr].[QTSDB].[dbo].QTS_Personnel
		WHERE p_active = 1
		AND dbo.DecryptStringQTS(p_access_id) = @nric

TRUNCATE TABLE #tmpqtsqc

INSERT INTO #tmpqtsqc
(access_id, pq_lastaccess_date, pq_validaccess_date, pq_validtill_date, suspened_till)
SELECT dbo.DecryptStringQTS(cc.p_access_id),
	aa.pq_lastaccess_date AS pq_lastaccess_date,
	aa.pq_validaccess_date AS pq_validaccess_date,
	aa.pq_validtill_date AS pq_validtill_date,
CASE WHEN aa.pq_suspend_to IS NOT NULL THEN
	CASE WHEN aa.pq_reinstate_eff IS NULL THEN
			CASE WHEN aa.pq_suspend_to > current_timestamp THEN aa.pq_suspend_to ELSE '' END
		WHEN aa.pq_suspend_to < aa.pq_reinstate_eff
			THEN CASE WHEN aa.pq_suspend_to > current_timestamp THEN aa.pq_suspend_to ELSE '' END
				ELSE CASE WHEN aa.pq_reinstate_eff > current_timestamp THEN aa.pq_reinstate_eff ELSE '' END
	END
END AS suspened_till
FROM [flexnetskgsvr].[QTSDB].[dbo].QTS_Personnel_Qualification aa, 
	[flexnetskgsvr].[QTSDB].[dbo].QTS_Qualification bb, 
	[flexnetskgsvr].[QTSDB].[dbo].QTS_Personnel cc
WHERE cc.p_id = aa.pq_p_id
	AND aa.pq_qual_id = bb.qual_id
	AND cc.p_rail = @line
	AND bb.qual_rail = @line
	AND bb.qual_code IN (@QualCode)
	AND dbo.DecryptStringQTS(cc.p_access_id) = @nric

SELECT @QualCtr = COUNT(*) 
	FROM #tmpqtsqc
		WHERE access_id = @nric

IF @QualCtr = 0
	BEGIN
		-- SELECT 1
		SET @QualStatus = 'InValid'
	END
ELSE
	BEGIN
		SELECT @lastaccess_date	=	pq_lastaccess_date,
				@validaccess_date	=	pq_validaccess_date,
				@validtill_date		=	pq_validtill_date,
				@suspened_till		=	suspened_till
			FROM #tmpqtsqc

		IF ISNULL(@suspened_till, '1900-01-01 00:00:00.000') <> '1900-01-01 00:00:00.000'  
			BEGIN
				-- SELECT 2
				SET @QualStatus = 'InValid'
			END
		ELSE
			BEGIN
				IF (CONVERT(DATETIME, @qualdate, 103) < @validaccess_date
					AND CONVERT(DATETIME, @qualdate, 103) < @validtill_date)
					BEGIN
						-- SELECT 3
						SET @QualStatus = 'Valid'
					END
				ELSE
					BEGIN
						-- SELECT 4
						SET @QualStatus = 'InValid'
					END
			END
	END

SELECT LTRIM(RTRIM(ISNULL(@nric, ''))) AS nric, 
		LTRIM(RTRIM(ISNULL(@CurNameStr, ''))) AS namestr,
		LTRIM(RTRIM(ISNULL(@line, ''))) AS line,
		LTRIM(RTRIM(ISNULL(@qualdate, ''))) AS qualdate, 
		LTRIM(RTRIM(ISNULL(@QualCode, ''))) AS qualcode, 
		LTRIM(RTRIM(ISNULL(@QualStatus, ''))) AS qualstatus

DROP TABLE #tmpqtsqc


END
GO
/****** END PROCEDURE 87 ******/

/****** START PROCEDURE 88 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_Depot_TOA_Register
CREATE PROCEDURE  [dbo].[sp_TAMS_Depot_TOA_Register]
	@Line		AS NVARCHAR(20) = NULL,
	@TrackType  as nvarchar(50) = null,
	@Type		AS NVARCHAR(20) = NULL,
	@Loc		AS NVARCHAR(20) = NULL,			-- >> SELECT StationName from TAMS_Station
	@TARNo		AS NVARCHAR(30) = NULL,
	@NRIC		AS NVARCHAR(20) = NULL,
	@TOAID		AS BIGINT = 0 OUTPUT,
	@Message	AS NVARCHAR(500) = NULL OUTPUT
AS

BEGIN

DECLARE	@IntrnlTrans	TINYINT

SELECT 	@IntrnlTrans 	= 0	

IF (@@TRANCOUNT = 0) 
BEGIN
	SET @IntrnlTrans = 1
	BEGIN TRAN
END

CREATE TABLE #tmpnric 
(id BIGINT IDENTITY(1,1) NOT NULL, 
nric NVARCHAR(50),
namestr NVARCHAR(500),
line NVARCHAR(50),
qualdate NVARCHAR(50),
qualcode NVARCHAR(100),
qualstatus NVARCHAR(100))

TRUNCATE TABLE #tmpnric

DECLARE @ExecString	NVARCHAR(MAX)
SET @ExecString = ''
DECLARE @QualDate	NVARCHAR(20)
SET @QualDate = ''

DECLARE @InChargeName	NVARCHAR(500)
DECLARE @InChargeStatus	NVARCHAR(20)

SET @InChargeName = ''
SET @InChargeStatus = ''

DECLARE @CutOffTime		TIME
DECLARE @QTSQualCode	NVARCHAR(200)
DECLARE @QTSQualCodeProt	NVARCHAR(200)

SELECT @CutOffTime = ParaTime 
	FROM TAMS_Parameters
		WHERE ParaCode = 'TOACutOffTime'
			AND ParaValue1 = @Line
			and ParaValue2 = @TrackType
			AND GETDATE() BETWEEN EffectiveDate AND ExpiryDate

SELECT @QTSQualCode = STRING_AGG(ParaValue2, ',')
	FROM TAMS_Parameters
		WHERE ParaCode = 'QTSQualCode'
			AND ParaValue1 = @Line
			AND ParaValue3 = CASE WHEN @TrackType='DEPOT' THEN 'Depot Possession' ELSE 'Mainline Possession' END
			AND ParaValue2 like CASE WHEN exists(select * from TAMS_TAR_AccessReq LEFT JOIN TAMS_TAR ON TAMS_TAR.ID=TAMS_TAR_AccessReq.TARId where TAMS_TAR.TARNo=@TARNo and OperationRequirement in (43,45) and isSelected=1) THEN '%(Train%' ELSE '%PC D%'  END								
			AND GETDATE() BETWEEN EffectiveDate AND ExpiryDate

--SELECT @QTSQualCode = STRING_AGG(ParaValue2, ',')
--	FROM TAMS_Parameters
--		WHERE ParaCode = 'QTSQualCode'
--			AND ParaValue1 = @Line
--			AND ParaValue3 = CASE WHEN @TrackType='DEPOT' THEN 'Depot Possession' ELSE 'Mainline Possession' END
--			AND GETDATE() BETWEEN EffectiveDate AND ExpiryDate

SELECT @QTSQualCodeProt = STRING_AGG(ParaValue2, ',')
	FROM TAMS_Parameters
		WHERE ParaCode = 'QTSQualCode'
			AND ParaValue1 = @Line
			AND ParaValue3 = CASE WHEN @TrackType='DEPOT' THEN 'Depot' ELSE 'Mainline' END
			AND GETDATE() BETWEEN EffectiveDate AND ExpiryDate

DECLARE @TARCtr	INT

SET @QTSQualCode=@QTSQualCode + ','
SET @QTSQualCodeProt=@QTSQualCodeProt + ','

IF @Line = 'DTL'
	BEGIN
		SELECT @TARCtr = COUNT(*)
			FROM TAMS_TAR
				WHERE TARNo = @TARNo
					AND TARStatusId = CASE WHEN @Line = 'NEL' THEN 9 ELSE 8 END
					AND PowerOn = 0
	END
ELSE
	BEGIN
		SELECT @TARCtr = COUNT(*)
			FROM TAMS_TAR
				WHERE TARNo = @TARNo
					AND TARStatusId = CASE WHEN @Line = 'NEL' THEN 9 ELSE 8 END
					-- >> AND PowerOn = 0
	END


SET @TOAID = 0

DECLARE @StationCtr	BIGINT
SET @StationCtr = 0


DECLARE @RecStatus NVARCHAR(5)
DECLARE @ErrorDescription NVARCHAR(500)
SET @RecStatus = ''
SET @ErrorDescription = ''

-- >> "Invalid Location for selected TAR."
if UPPER(@TrackType)='DEPOT'
BEGIN
	SELECT @StationCtr=1
END
ELSE
BEGIN
SELECT @StationCtr = COUNT(*) 
	FROM TAMS_TAR_Station a, TAMS_Station b, TAMS_TAR c
		WHERE a.StationId = b.ID
			AND a.TARId = c.Id
			AND c.TARNo = @TARNo
			AND b.StationName = @Loc
END


IF @TARCtr = 0 OR @StationCtr = 0
	BEGIN
		IF @TARCtr = 0
			BEGIN
				SET @Message = '1'	-- >> Invalid TAR No
				SET @RecStatus = 'F'
				SET @ErrorDescription = 'Invalid TAR No'
			END
		ELSE
			BEGIN
				IF @StationCtr = 0
					BEGIN
						SET @Message = '1'	-- >> Invalid Location for selected TAR.
						SET @RecStatus = 'F'
						SET @ErrorDescription = 'Invalid TAR No'
						--SET @ErrorDescription = 'Invalid Location for selected TAR'
					END
			END
	END
ELSE
	BEGIN
		DECLARE @TARID		BIGINT
		DECLARE @TARLine	NVARCHAR(20)
		DECLARE @TARAccessDate	DATE
		DECLARE @AccessType NVARCHAR(50)
		
		if @Line = 'NEL' 
		begin 
			
			SELECT @TARID = ID,
					@TARLine = Line,
					@TARAccessDate = AccessDate,
					@AccessType = AccessType
				FROM TAMS_TAR
					WHERE TARNo = @TARNo
						AND TARStatusId = CASE WHEN @Line = 'NEL' THEN 9 ELSE 8 END
						--AND PowerOn = 0
		end;
		else 
		begin 

			SELECT @TARID = ID,
					@TARLine = Line,
					@TARAccessDate = AccessDate,
					@AccessType = AccessType
				FROM TAMS_TAR
					WHERE TARNo = @TARNo
						AND TARStatusId = CASE WHEN @Line = 'NEL' THEN 9 ELSE 8 END
						AND PowerOn = 0
		end;

		
		IF @Line <> @TARLine
			BEGIN
				SET @Message = '2'	-- >> Invalid Line for selected TAR
				SET @RecStatus = 'F'
				SET @ErrorDescription = 'Invalid Line for selected TAR'
			END
		ELSE
			BEGIN
				DECLARE @TOACtr		INT
				DECLARE @GetTime	TIME
				DECLARE @OPDate		DATE
				DECLARE @GetDate	DATE

				SET @TOAID = 0

				SELECT @TOAID = Id
					FROM TAMS_TOA
						WHERE TARId = @TARID
				
				SET @GetTime = GETDATE()
				--SET @GetDate = GETDATE()
				SET @GetDate = CASE WHEN @TrackType='DEPOT' THEN @TARAccessDate ELSE GETDATE() END

				-- >> SELECT @GetTime, @GetDate, @TARAccessDate, DATEADD(DAY, 1, @GetDate)
				
				
				print @TOAID
				IF @TOAID = 0
					BEGIN
					
					if @TrackType='DEPOT'
					BEGIN
						SET @OPDate=GETDATE()
					END
					ELSE
					BEGIN
						IF @GetTime <= @CutOffTime
							BEGIN
								SET @OPDate = DATEADD(DAY, -1, GETDATE())

								
								IF @TARAccessDate <> @GetDate
									BEGIN
										SET @Message = '3' -- >> Invalid TAR Access Date
										SET @RecStatus = 'F'
										SET @ErrorDescription = '3 Invalid TAR Access Date'
									END
							
						END
						ELSE
							BEGIN
								SET @OPDate = GETDATE()
							END
					END

						PRINT 'tracktype'

						IF @TrackType='DEPOT'
						BEGIN

							if not exists(SELECT *,dateadd(hour, -3, CONVERT(DATETIME, CONVERT(CHAR(8), AccessDate, 112) + ' ' + CONVERT(CHAR(8), AccessTimeFrom, 108))) from TAMS_TAR 
							where ID=@TARID and 
							GETDATE() >= dateadd(hour, -3, CONVERT(DATETIME, CONVERT(CHAR(8), AccessDate, 112) + ' ' + CONVERT(CHAR(8), AccessTimeFrom, 108))) and 
							GETDATE() <= dateadd(minute, 125, dateadd(hour, -3, CONVERT(DATETIME, CONVERT(CHAR(8), AccessDate, 112) + ' ' + CONVERT(CHAR(8), AccessTimeFrom, 108)))))
							
							--GETDATE() <= dateadd(minute, 125 , CONVERT(DATETIME, CONVERT(CHAR(8), AccessDate, 112) + ' ' + CONVERT(CHAR(8), AccessTimeFrom, 108))))
							BEGIN
								SET @Message = '11' -- >> Invalid TAR Access Date
								SET @RecStatus = 'F'
								SET @ErrorDescription = '10 Curent access date time is not within stipulated timing'
								
								ROLLBACK TRAN;
								RETURN;

							END
						END

						


						
						IF @TARAccessDate <> CASE WHEN @TrackType='DEPOT' THEN @GetDate ELSE DATEADD(DAY, 1, @GetDate) END
							BEGIN
								SET @Message = '4' -- >> Invalid TAR Access Date
								SET @RecStatus = 'F'
								SET @ErrorDescription = '4 Invalid TAR Access Date'
								
							END
						ELSE
							BEGIN
								

								PRINT '1' -- @QTSQualCode

								SET @QualDate = CONVERT(NVARCHAR(20), @TARAccessDate, 103)

								DECLARE @pos as int;
								DECLARE @len as int;
								DECLARE @qua as nvarchar(50)

								set @pos = 0
								set @len = 0

								
								WHILE CHARINDEX(',', @QTSQualCode, @pos+1)>0
								BEGIN
								    set @len = CHARINDEX(',', @QTSQualCode, @pos+1) - @pos
									SELECT @pos, @len, SUBSTRING(@QTSQualCode, @pos, @len)

									SET @ExecString = CASE WHEN UPPER(@TrackType)='DEPOT' THEN 'sp_TAMS_Depot_TOA_QTS_Chk ' ELSE 'sp_TAMS_TOA_QTS_Chk ' END + '''' + @NRIC + ''', ''' + @QualDate + ''', ''' + @Line + ''', ''' + SUBSTRING(@QTSQualCode, @pos, @len) + ''''
									
									PRINT @ExecString

									INSERT INTO #tmpnric
									EXEC(@ExecString)

								    set @pos = CHARINDEX(',', @QTSQualCode, @pos+@len) +1
								end

								
								SELECT @InChargeName = namestr,
									@InChargeStatus = qualstatus
								FROM #tmpnric
								
								DECLARE @QTSFinStatus NVARCHAR(20)
								SET @QTSFinStatus = ''

								IF not exists(SELECT *
								FROM #tmpnric where qualstatus	= 'Valid')
									BEGIN
										IF @AccessType = 'Protection'
											BEGIN
												TRUNCATE TABLE #tmpnric
												SET @InChargeName = ''
												SET @InChargeStatus = ''


												--SET @ExecString = CASE WHEN UPPER(@TrackType)='DEPOT' THEN 'sp_TAMS_Depot_TOA_QTS_Chk ' ELSE 'sp_TAMS_TOA_QTS_Chk ' END + '''' + @NRIC + ''', ''' + @QualDate + ''', ''' + @Line + ''', ''' + @QTSQualCodeProt + ''''

												--INSERT INTO #tmpnric
												--EXEC(@ExecString)
													set @pos = 0
													set @len = 0

													WHILE CHARINDEX(',', @QTSQualCodeProt, @pos+1)>0
													BEGIN
														set @len = CHARINDEX(',', @QTSQualCodeProt, @pos+1) - @pos

														SET @ExecString = CASE WHEN UPPER(@TrackType)='DEPOT' THEN 'sp_TAMS_Depot_TOA_QTS_Chk ' ELSE 'sp_TAMS_TOA_QTS_Chk ' END + '''' + @NRIC + ''', ''' + @QualDate + ''', ''' + @Line + ''', ''' + SUBSTRING(@QTSQualCodeProt, @pos, @len) + ''''
														
														PRINT @ExecString
														INSERT INTO #tmpnric
														EXEC(@ExecString)

														Select * from #tmpnric
								

														set @pos = CHARINDEX(',', @QTSQualCode, @pos+@len) +1
													end

												SELECT @InChargeName = namestr,
													@InChargeStatus = qualstatus
												FROM #tmpnric

													IF not exists(SELECT * FROM #tmpnric where qualstatus	= 'Valid')
													BEGIN
														SET @QTSFinStatus = 'InValid'
													END
												ELSE
													BEGIN
														SET @QTSFinStatus = 'Valid'
													END
											END
										ELSE
											BEGIN
												SET @QTSFinStatus = 'InValid'
											END
									END
								ELSE
									BEGIN
										SET @QTSFinStatus = 'Valid'
									END

								DROP TABLE #tmpnric
								-- >> CHECK QTS

								IF @QTSFinStatus = 'InValid'
									BEGIN
										SET @Message = '9' -- >> Invalid Qualification
										SET @RecStatus = 'F'
										SET @ErrorDescription = 'Invalid Qualification'
									END
								ELSE
									BEGIN
										DECLARE @protectiontype as nvarchar(50)
										SET @protectiontype=NULL;

										IF @TrackType='DEPOT'
										BEGIN
											SELECT @protectiontype=ISNULL(protectiontype,NULL) from TAMS_TAR
											where id=@TARID;
										END


										-- >> Insert into TOA Table
										INSERT INTO [dbo].[TAMS_TOA]
										([Line],[TrackType], [OperationDate], [AccessDate], [TARId], 
											[QRLocation], [TOAType], 
											[InChargeName], [InChargeNRIC], 
											[MobileNo], [TetraRadioNo],
											[NoOfParties],
											[RegisteredTime], [AckRegisterTime], 
											[GrantTOATime], [AckGrantTOATime],
											[ReqProtectionLimitTime], [AckProtectionLimitTime],
											[UpdateQTSTime],
											[SurrenderTime], [AckSurrenderTime],
											[TOAStatus], [TOANo],
											[CancelRemark],[Protectiontype],
											[CreatedOn], [CreatedBy], [UpdatedOn], [UpdatedBy])
										VALUES
										(@Line,@TrackType, @OPDate, @TARAccessDate, @TARID,
											@Loc, @Type,
											@InChargeName, dbo.EncryptString(@NRIC), 
											'', '', 
											1,
											GETDATE(), NULL, 
											NULL, NULL, 
											NULL, NULL, 
											NULL, 
											NULL, NULL, 
											0, NULL, 
											NULL, 
											@protectiontype,
											-- >> GETDATE(), @NRIC, GETDATE(), @NRIC)
											GETDATE(), @InChargeName, GETDATE(), @InChargeName)

										SELECT @TOAID = SCOPE_IDENTITY();


										INSERT INTO TAMS_TOA_Audit
										-- >> SELECT @NRIC, GETDATE(), 'U', * FROM TAMS_TOA
										SELECT LEFT(LTRIM(RTRIM(@InChargeName)), 50), GETDATE(), 'I', * FROM TAMS_TOA
										WHERE TARId = @TARID

									

										-- >> Insert into TOA Parties Table

										INSERT INTO [dbo].[TAMS_TOA_Parties]
											([TOAId], [Name], [NRIC], [IsInCharge], [IsWitness], [IsTMC], 
												[BookInTime], [BookOutTime], [BookInStatus])
										VALUES
											(@TOAID, @InChargeName, dbo.EncryptString(@NRIC), 1, 0, 0,
												GETDATE(), NULL, 'In')

										SET @Message = '99' -- >> BookIn
										SET @RecStatus = 'S'
										SET @ErrorDescription = 'BookIn'
									END
							END
					END
				ELSE
					BEGIN
						DECLARE @InChargeCtr	INT
						
						SELECT @InChargeCtr = COUNT(*)
							FROM TAMS_TOA
								WHERE TARId = @TARID
									AND dbo.DecryptString(InChargeNRIC) = LTRIM(RTRIM(@NRIC))

						IF @InChargeCtr = 0
							BEGIN
								SET @Message = '5' -- >> NRIC / Fin No does not match with InCharge
								SET @RecStatus = 'F'
								SET @ErrorDescription = 'NRIC / Fin No does not match with InCharge'
							END
						ELSE
							BEGIN
								DECLARE @TOStatus	INT

								SELECT @TOStatus = TOAStatus
									FROM TAMS_TOA
										WHERE TARId = @TARID
											AND dbo.DecryptString(InChargeNRIC) = LTRIM(RTRIM(@NRIC))

								IF @TOStatus = 0
									BEGIN
										if @Type='DEPOT'
										BEGIN
											SET @OPDate = GETDATE()
										END
										ELSE 
											IF @GetTime <= @CutOffTime
												BEGIN
													SET @OPDate = DATEADD(DAY, -1, GETDATE())

													IF @TARAccessDate <> @GetDate
														BEGIN
															SET @Message = '6' -- >> Invalid TAR Access Date
															SET @RecStatus = 'F'
															SET @ErrorDescription = '6 Invalid TAR Access Date'
														END
												END
											ELSE
												BEGIN
													SET @OPDate = GETDATE()
												END
									

										IF @TARAccessDate <> CASE WHEN @type='DEPOT' THEN @GetDate ELSE DATEADD(DAY, 1, @GetDate) END
											BEGIN
												SET @Message = '7' -- >> Invalid TAR Access Date
												SET @RecStatus = 'F'
												SET @ErrorDescription = '7 Invalid TAR Access Date'
											END
										ELSE
											BEGIN
												UPDATE TAMS_TOA
													SET OperationDate = @OPDate
														WHERE TARId = @TARID

												SET @Message = '99' -- >> BookIn
												SET @RecStatus = 'S'
												SET @ErrorDescription = 'BookIn'
											END
									END
								ELSE
									BEGIN
										IF @TOStatus = 3 OR @TOStatus = 2 OR @TOStatus = 1
											BEGIN
												IF @TOStatus = 2 OR @TOStatus = 1
													BEGIN
														SET @Message = '98' -- >> AddParties
														SET @RecStatus = 'S'
														SET @ErrorDescription = 'AddParties'
													END
												ELSE
													BEGIN
														SET @Message = '97' -- >> BookOut
														SET @RecStatus = 'S'
														SET @ErrorDescription = 'BookOut'
													END
											END
										ELSE
											BEGIN
												SET @Message = '8' -- >> Invalid TAR Status
												SET @RecStatus = 'F'
												SET @ErrorDescription = '8 Invalid TAR Status'
											END
									END
							END
					END

			END
	END


INSERT INTO [dbo].[TAMS_TOA_Registration_Log]
	([Line], [Station], [TARNo], [TPOPC], [RecStatus], [ErrorDescription], [CreatedOn])
VALUES
	(@Line, @Loc, @TARNo, dbo.EncryptString(LTRIM(RTRIM(@NRIC))), @RecStatus, @ErrorDescription, GETDATE())
-- >>

IF @@ERROR <> 0 BEGIN
	SET @Message = 'ERROR INSERTING INTO TAMS_TOA'
	GOTO TRAP_ERROR
END

FORCE_EXIT_PROC:	
	IF @IntrnlTrans = 1 COMMIT TRAN
	RETURN @Message 

TRAP_ERROR:
	IF @IntrnlTrans = 1 ROLLBACK TRAN
	RETURN @Message

END
GO
/****** END PROCEDURE 88 ******/

/****** START PROCEDURE 89 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_Depot_TOA_Register_1
CREATE PROCEDURE  [dbo].[sp_TAMS_Depot_TOA_Register_1]
	@Line		AS NVARCHAR(20) = NULL,
	@TrackType  as nvarchar(50) = null,
	@Type		AS NVARCHAR(20) = NULL,
	@Loc		AS NVARCHAR(20) = NULL,			-- >> SELECT StationName from TAMS_Station
	@TARNo		AS NVARCHAR(30) = NULL,
	@NRIC		AS NVARCHAR(20) = NULL,
	@TOAID		AS BIGINT = 0 OUTPUT,
	@Message	AS NVARCHAR(500) = NULL OUTPUT
AS

BEGIN

DECLARE	@IntrnlTrans	TINYINT

SELECT 	@IntrnlTrans 	= 0	

IF (@@TRANCOUNT = 0) 
BEGIN
	SET @IntrnlTrans = 1
	BEGIN TRAN
END

CREATE TABLE #tmpnric 
(id BIGINT IDENTITY(1,1) NOT NULL, 
nric NVARCHAR(50),
namestr NVARCHAR(500),
line NVARCHAR(50),
qualdate NVARCHAR(50),
qualcode NVARCHAR(100),
qualstatus NVARCHAR(100))

TRUNCATE TABLE #tmpnric

DECLARE @ExecString	NVARCHAR(MAX)
SET @ExecString = ''
DECLARE @QualDate	NVARCHAR(20)
SET @QualDate = ''

DECLARE @InChargeName	NVARCHAR(500)
DECLARE @InChargeStatus	NVARCHAR(20)

SET @InChargeName = ''
SET @InChargeStatus = ''

DECLARE @CutOffTime		TIME
DECLARE @QTSQualCode	NVARCHAR(200)
DECLARE @QTSQualCodeProt	NVARCHAR(200)

SELECT @CutOffTime = ParaTime 
	FROM TAMS_Parameters
		WHERE ParaCode = 'TOACutOffTime'
			AND ParaValue1 = @Line
			and ParaValue2 = @TrackType
			AND GETDATE() BETWEEN EffectiveDate AND ExpiryDate

			

SELECT @QTSQualCode = STRING_AGG(ParaValue2, ',')
	FROM TAMS_Parameters
		WHERE ParaCode = 'QTSQualCode'
			AND ParaValue1 = @Line
			AND ParaValue3 = CASE WHEN @TrackType='DEPOT' THEN 'Depot Possession' ELSE 'Mainline Possession' END
			AND ParaValue2 like CASE WHEN exists(select * from TAMS_TAR_AccessReq LEFT JOIN TAMS_TAR ON TAMS_TAR.ID=TAMS_TAR_AccessReq.TARId where TAMS_TAR.TARNo=@TARNo and OperationRequirement in (43,45) and isSelected=1) THEN '%(Train%' ELSE '%PC%'  END								
			AND GETDATE() BETWEEN EffectiveDate AND ExpiryDate

--SELECT @QTSQualCode = STRING_AGG(ParaValue2, ',')
--	FROM TAMS_Parameters
--		WHERE ParaCode = 'QTSQualCode'
--			AND ParaValue1 = @Line
--			AND ParaValue3 = CASE WHEN @TrackType='DEPOT' THEN 'Depot Possession' ELSE 'Mainline Possession' END
--			AND GETDATE() BETWEEN EffectiveDate AND ExpiryDate

SELECT @QTSQualCodeProt = STRING_AGG(ParaValue2, ',')
	FROM TAMS_Parameters
		WHERE ParaCode = 'QTSQualCode'
			AND ParaValue1 = @Line
			AND ParaValue3 = CASE WHEN @TrackType='DEPOT' THEN 'Depot' ELSE 'Mainline' END
			AND GETDATE() BETWEEN EffectiveDate AND ExpiryDate

DECLARE @TARCtr	INT

SET @QTSQualCode=@QTSQualCode + ','
SET @QTSQualCodeProt=@QTSQualCodeProt + ','

IF @Line = 'DTL'
	BEGIN
		SELECT @TARCtr = COUNT(*)
			FROM TAMS_TAR
				WHERE TARNo = @TARNo
					AND TARStatusId = CASE WHEN @Line = 'NEL' THEN 9 ELSE 8 END
					AND PowerOn = 0
	END
ELSE
	BEGIN
		SELECT @TARCtr = COUNT(*)
			FROM TAMS_TAR
				WHERE TARNo = 'NELD-TAR-2024-00460'
					AND TARStatusId = CASE WHEN 'NEL' = 'NEL' THEN 9 ELSE 8 END
					-- >> AND PowerOn = 0
	END


SET @TOAID = 0

DECLARE @StationCtr	BIGINT
SET @StationCtr = 0


DECLARE @RecStatus NVARCHAR(5)
DECLARE @ErrorDescription NVARCHAR(500)
SET @RecStatus = ''
SET @ErrorDescription = ''

PRINT @TrackType
-- >> "Invalid Location for selected TAR."
if UPPER(@TrackType)='DEPOT'
BEGIN
	SELECT @StationCtr=1
END
ELSE
BEGIN
SELECT @StationCtr = COUNT(*) 
	FROM TAMS_TAR_Station a, TAMS_Station b, TAMS_TAR c
		WHERE a.StationId = b.ID
			AND a.TARId = c.Id
			AND c.TARNo = @TARNo
			AND b.StationName = @Loc
END

PRINT @StationCtr
PRINT @TARCtr

IF @TARCtr = 0 OR @StationCtr = 0
	BEGIN
		IF @TARCtr = 0
			BEGIN
				SET @Message = '1'	-- >> Invalid TAR No
				SET @RecStatus = 'F'
				SET @ErrorDescription = 'Invalid TAR No'
			END
		ELSE
			BEGIN
				IF @StationCtr = 0
					BEGIN
						SET @Message = '1'	-- >> Invalid Location for selected TAR.
						SET @RecStatus = 'F'
						SET @ErrorDescription = 'Invalid TAR No'
						--SET @ErrorDescription = 'Invalid Location for selected TAR'
					END
			END
	END
ELSE
	BEGIN
		DECLARE @TARID		BIGINT
		DECLARE @TARLine	NVARCHAR(20)
		DECLARE @TARAccessDate	DATE
		DECLARE @AccessType NVARCHAR(50)
		
		if @Line = 'NEL' 
		begin 
			
			SELECT @TARID = ID,
					@TARLine = Line,
					@TARAccessDate = AccessDate,
					@AccessType = AccessType
				FROM TAMS_TAR
					WHERE TARNo = @TARNo
						AND TARStatusId = CASE WHEN @Line = 'NEL' THEN 9 ELSE 8 END
						--AND PowerOn = 0
		end;
		else 
		begin 

			SELECT @TARID = ID,
					@TARLine = Line,
					@TARAccessDate = AccessDate,
					@AccessType = AccessType
				FROM TAMS_TAR
					WHERE TARNo = @TARNo
						AND TARStatusId = CASE WHEN @Line = 'NEL' THEN 9 ELSE 8 END
						AND PowerOn = 0
		end;

		
		IF @Line <> @TARLine
			BEGIN
				SET @Message = '2'	-- >> Invalid Line for selected TAR
				SET @RecStatus = 'F'
				SET @ErrorDescription = 'Invalid Line for selected TAR'
			END
		ELSE
			BEGIN
				DECLARE @TOACtr		INT
				DECLARE @GetTime	TIME
				DECLARE @OPDate		DATE
				DECLARE @GetDate	DATE

				SET @TOAID = 0

				SELECT @TOAID = Id
					FROM TAMS_TOA
						WHERE TARId = @TARID
				
				SET @GetTime = GETDATE()
				--SET @GetDate = GETDATE()
				SET @GetDate = CASE WHEN @TrackType='DEPOT' THEN @TARAccessDate ELSE GETDATE() END

				-- >> SELECT @GetTime, @GetDate, @TARAccessDate, DATEADD(DAY, 1, @GetDate)
				
				
				print @TOAID
				IF @TOAID = 0
					BEGIN
					
					if @TrackType='DEPOT'
					BEGIN
						SET @OPDate=GETDATE()
					END
					ELSE
					BEGIN
						IF @GetTime <= @CutOffTime
							BEGIN
								SET @OPDate = DATEADD(DAY, -1, GETDATE())

								
								IF @TARAccessDate <> @GetDate
									BEGIN
										SET @Message = '3' -- >> Invalid TAR Access Date
										SET @RecStatus = 'F'
										SET @ErrorDescription = '3 Invalid TAR Access Date'
									END
							
						END
						ELSE
							BEGIN
								SET @OPDate = GETDATE()
							END
					END

						PRINT 'tracktype'

						IF @TrackType='DEPOT'
						BEGIN

							if not exists(SELECT *,dateadd(hour, -3, CONVERT(DATETIME, CONVERT(CHAR(8), AccessDate, 112) + ' ' + CONVERT(CHAR(8), AccessTimeFrom, 108))) from TAMS_TAR 
							where ID=@TARID and 
							GETDATE() >= dateadd(hour, -3, CONVERT(DATETIME, CONVERT(CHAR(8), AccessDate, 112) + ' ' + CONVERT(CHAR(8), AccessTimeFrom, 108))) and 
							GETDATE() <= dateadd(minute, 125, dateadd(hour, -3, CONVERT(DATETIME, CONVERT(CHAR(8), AccessDate, 112) + ' ' + CONVERT(CHAR(8), AccessTimeFrom, 108)))))
							
							--GETDATE() <= dateadd(minute, 125 , CONVERT(DATETIME, CONVERT(CHAR(8), AccessDate, 112) + ' ' + CONVERT(CHAR(8), AccessTimeFrom, 108))))
							BEGIN
								SET @Message = '11' -- >> Invalid TAR Access Date
								SET @RecStatus = 'F'
								SET @ErrorDescription = '10 Curent access date time is not within stipulated timing'
								
								ROLLBACK TRAN;
								RETURN;

							END
						END

						


						
						IF @TARAccessDate <> CASE WHEN @TrackType='DEPOT' THEN @GetDate ELSE DATEADD(DAY, 1, @GetDate) END
							BEGIN
								SET @Message = '4' -- >> Invalid TAR Access Date
								SET @RecStatus = 'F'
								SET @ErrorDescription = '4 Invalid TAR Access Date'
								
							END
						ELSE
							BEGIN
								

								PRINT '1' -- @QTSQualCode

								SET @QualDate = CONVERT(NVARCHAR(20), @TARAccessDate, 103)

								DECLARE @pos as int;
								DECLARE @len as int;
								DECLARE @qua as nvarchar(50)

								set @pos = 0
								set @len = 0

								
								WHILE CHARINDEX(',', @QTSQualCode, @pos+1)>0
								BEGIN
								    set @len = CHARINDEX(',', @QTSQualCode, @pos+1) - @pos
									SELECT @pos, @len, SUBSTRING(@QTSQualCode, @pos, @len)

									SET @ExecString = CASE WHEN UPPER(@TrackType)='DEPOT' THEN 'sp_TAMS_Depot_TOA_QTS_Chk ' ELSE 'sp_TAMS_TOA_QTS_Chk ' END + '''' + @NRIC + ''', ''' + @QualDate + ''', ''' + @Line + ''', ''' + SUBSTRING(@QTSQualCode, @pos, @len) + ''''
									
									PRINT @ExecString

									INSERT INTO #tmpnric
									EXEC(@ExecString)

								    set @pos = CHARINDEX(',', @QTSQualCode, @pos+@len) +1
								end

								
								SELECT @InChargeName = namestr,
									@InChargeStatus = qualstatus
								FROM #tmpnric
								
								DECLARE @QTSFinStatus NVARCHAR(20)
								SET @QTSFinStatus = ''


								DROP TABLE #tmpnric
								-- >> CHECK QTS

								
							END
					END
				ELSE
					BEGIN
						DECLARE @InChargeCtr	INT
						
						SELECT @InChargeCtr = COUNT(*)
							FROM TAMS_TOA
								WHERE TARId = @TARID
									AND dbo.DecryptString(InChargeNRIC) = LTRIM(RTRIM(@NRIC))

						IF @InChargeCtr = 0
							BEGIN
								SET @Message = '5' -- >> NRIC / Fin No does not match with InCharge
								SET @RecStatus = 'F'
								SET @ErrorDescription = 'NRIC / Fin No does not match with InCharge'
							END
						ELSE
							BEGIN
								DECLARE @TOStatus	INT

								SELECT @TOStatus = TOAStatus
									FROM TAMS_TOA
										WHERE TARId = @TARID
											AND dbo.DecryptString(InChargeNRIC) = LTRIM(RTRIM(@NRIC))

								IF @TOStatus = 0
									BEGIN
										if @Type='DEPOT'
										BEGIN
											SET @OPDate = GETDATE()
										END
										ELSE 
											IF @GetTime <= @CutOffTime
												BEGIN
													SET @OPDate = DATEADD(DAY, -1, GETDATE())

													IF @TARAccessDate <> @GetDate
														BEGIN
															SET @Message = '6' -- >> Invalid TAR Access Date
															SET @RecStatus = 'F'
															SET @ErrorDescription = '6 Invalid TAR Access Date'
														END
												END
											ELSE
												BEGIN
													SET @OPDate = GETDATE()
												END
									

										IF @TARAccessDate <> CASE WHEN @type='DEPOT' THEN @GetDate ELSE DATEADD(DAY, 1, @GetDate) END
											BEGIN
												SET @Message = '7' -- >> Invalid TAR Access Date
												SET @RecStatus = 'F'
												SET @ErrorDescription = '7 Invalid TAR Access Date'
											END
										ELSE
											BEGIN
												UPDATE TAMS_TOA
													SET OperationDate = @OPDate
														WHERE TARId = @TARID

												SET @Message = '99' -- >> BookIn
												SET @RecStatus = 'S'
												SET @ErrorDescription = 'BookIn'
											END
									END
								ELSE
									BEGIN
										IF @TOStatus = 3 OR @TOStatus = 2 OR @TOStatus = 1
											BEGIN
												IF @TOStatus = 2 OR @TOStatus = 1
													BEGIN
														SET @Message = '98' -- >> AddParties
														SET @RecStatus = 'S'
														SET @ErrorDescription = 'AddParties'
													END
												ELSE
													BEGIN
														SET @Message = '97' -- >> BookOut
														SET @RecStatus = 'S'
														SET @ErrorDescription = 'BookOut'
													END
											END
										ELSE
											BEGIN
												SET @Message = '8' -- >> Invalid TAR Status
												SET @RecStatus = 'F'
												SET @ErrorDescription = '8 Invalid TAR Status'
											END
									END
							END
					END

			END
	END


INSERT INTO [dbo].[TAMS_TOA_Registration_Log]
	([Line], [Station], [TARNo], [TPOPC], [RecStatus], [ErrorDescription], [CreatedOn])
VALUES
	(@Line, @Loc, @TARNo, dbo.EncryptString(LTRIM(RTRIM(@NRIC))), @RecStatus, @ErrorDescription, GETDATE())
-- >>

IF @@ERROR <> 0 BEGIN
	SET @Message = 'ERROR INSERTING INTO TAMS_TOA'
	GOTO TRAP_ERROR
END

FORCE_EXIT_PROC:	
	IF @IntrnlTrans = 1 COMMIT TRAN
	RETURN @Message 

TRAP_ERROR:
	IF @IntrnlTrans = 1 ROLLBACK TRAN
	RETURN @Message

END
GO
/****** END PROCEDURE 89 ******/

/****** START PROCEDURE 90 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_Depot_UpdateDTCAuth
CREATE PROCEDURE [dbo].[sp_TAMS_Depot_UpdateDTCAuth]
	-- Add the parameters for the stored procedure here
	@username as nvarchar(50),
	@authid as int,
	@workflowid as int,
	@statusid as int,
	@val as bit=NULL,
	@valstr as nvarchar(50)=NULL,
	@powerzoneid as int=NULL,
	@success as bit=NULL OUTPUT,
	@type as int, -- type is 1 if checkbox, 2 if dropdown
	@spksid as int=NULL,
	@Message AS NVARCHAR(500) = NULL OUTPUT
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

	DECLARE	@IntrnlTrans	TINYINT

	SELECT 	@IntrnlTrans 	= 0	

	IF (@@TRANCOUNT = 0) 
	BEGIN
		SET @IntrnlTrans = 1
		BEGIN TRAN
	END

    -- Insert statements for procedure here

	DECLARE @access as bit=0;

	IF not EXISTS(select TAMS_User.LoginId from TAMS_Endorser INNER JOIN TAMS_User_Role 
	ON TAMS_User_Role.ID=TAMS_Endorser.RoleId INNER JOIN TAMS_User
	ON TAMS_User.LoginId=@username 
	where TAMS_Endorser.ID=@workflowid)
	BEGIN
		SET @access=1
	END

	if @access=0
	BEGIN
		--throw exception
		set @Message='User ' + @username + ' do not have access to update the information';
		
		GOTO TRAP_ERROR
	END


	if @workflowid<>139 and @workflowid<>141
	BEGIN
		if not Exists(Select * from TAMS_Depot_Auth_Workflow where WorkflowID=@workflowid)
		BEGIN
			set @Message='Workflow not found or is invalid';
		
			GOTO TRAP_ERROR
		END
	END


	--check if workflow is already updated
	IF Exists(Select * from TAMS_Depot_Auth_Workflow where DTCAuthId=@authid and WorkflowID=@workflowid
	and WFStatus is not NULL and CheckBoxValue is not null)
	BEGIN
		-- already updated
		-- throw error
		set @Message='Workflow ID ' + CONVERT(nvarchar(10),@workflowid) + ' is already updated';
		GOTO TRAP_ERROR

	END

	DECLARE @newstatusid as int;
	-- get next status
	select @newstatusid=WFStatusId+1 from TAMS_WFStatus where WFType='dtcauth' and WFStatusId=@statusid
	and isActive=1
	order by [Order] ASC;


	--update current workflow

	UPDATE TAMS_Depot_Auth_Workflow
	SET WFStatus=CASE when @type=1 THEN 'Completed' ELSE @valstr END, ActionBy=@username, ActionOn=getDate(),CheckBoxValue=CASE WHEN @type=1 THEN @val ELSE NULL END
	where WorkflowID=@workflowid and
	@workflowid<>127 and @workflowid<>131 and @workflowid<>139 and @workflowid<>135 and @workflowid<>136 and @workflowid<>137

	-- get next workflow
	DECLARE @currentStatus as int;
	DECLARE @newworkflowid as int;

	select @currentStatus=WFStatusId from TAMS_WFStatus where WFType='dtcauth' and Id=@workflowid
	Select @newworkflowid=ID from TAMS_WFStatus where WFType='dtcauth' and WFStatusId=(@currentStatus+1)

	-- insert next workflow 
	INSERT INTO TAMS_Depot_Auth_Workflow
	SELECT @authid, null, null, null, @newworkflowid,null,0
	where @workflowid<>127 and @workflowid<>131 and @workflowid<>139 and @workflowid<>135 and @workflowid<>136 and @workflowid<>137


	if @workflowid=126
	BEGIN
		UPDATE TAMS_Depot_DTCAuth_SPKS
		SET ProtectOffTiming=getDate(), ProtectOffType=@valstr,ProtectOffActionBy=@username
		where AuthID=@authid
	END
	


	if @workflowid=127
	BEGIN

		UPDATE TAMS_Depot_Auth_Powerzone
		SET PowerOffTiming=getDate(),PowerOffType=@valstr,PowerOffActionBy=@username,statusID=@newstatusid
		where AuthID=@authid and PowerzoneID=@powerzoneid

	END

	if @workflowid=135
	BEGIN

		UPDATE TAMS_Depot_Auth_Powerzone
		SET PowerOnTiming=getDate(),PowerOnType=@valstr,PowerOnActionBy=@username,statusID=@newstatusid
		where AuthID=@authid and PowerzoneID=@powerzoneid

	END


	if @workflowid=137
	BEGIN
		UPDATE TAMS_Depot_DTCAuth_SPKS
		SET ProtectOnTiming=getDate(), ProtectOnType=@valstr,ProtectOnActionBy=@username,StatusID=@newstatusid
		where AuthID=@authid and SPKSID=@spksid
	END

	if @workflowid=131 or @workflowid=139
	BEGIN
		UPDATE TAMS_Depot_Auth_Powerzone
		SET RackedOutTiming=getDate(),RackedOutType=@valstr,RackedOffActionBy=@username,statusID=@newstatusid
		where AuthID=@authid and PowerzoneID=@powerzoneid

	END


	if @workflowid=136
	BEGIN
		UPDATE TAMS_Depot_Auth_Powerzone
		SET RackedInTiming=getDate(),RackedInType=@valstr,RackedInActionBy=@username,statusID=@newstatusid
		where AuthID=@authid and PowerzoneID=@powerzoneid

		UPDATE TAMS_Depot_DTCAuth_SPKS
		SET StatusID=@newstatusid+1
		where AuthID=@authid and SPKSID NOT IN 
		(
			Select DISTINCT SPKSId from (
			(Select PowerzoneID,TAMS_Depot_Auth_Powerzone.StatusID from TAMS_Depot_Auth_Powerzone
			where TAMS_Depot_Auth_Powerzone.AuthID=@authid) B
			LEFT JOIN
			(Select DISTINCT PowerSectorId, PowerSector,SPKSId  from 
			TAMS_Track_Power_Sector INNER JOIN TAMS_Track_SPKSZone 
			ON TAMS_Track_Power_Sector.SectorId=TAMS_Track_SPKSZone.SectorId 
			INNER JOIN TAMS_Power_Sector 
			ON TAMS_Power_Sector.ID=TAMS_Track_Power_Sector.PowerSectorId 
			) A ON A.PowerSectorId=B.PowerzoneID)
			where StatusID<>12
			group by SPKSId,PowerSectorId,StatusID
		) and SPKSID not in
		(
			Select TAMS_Depot_DTCAuth_SPKS.SPKSID from (
			Select B.* from (Select AccessDate,ID from TAMS_Depot_Auth) A  
			join TAMS_Depot_Auth B ON B.AccessDate=A.AccessDate
			where A.ID=@authid ) C JOIN TAMS_Depot_DTCAuth_SPKS ON C.ID=TAMS_Depot_DTCAuth_SPKS.AuthID 
			where C.ID<>@authid and TAMS_Depot_DTCAuth_SPKS.StatusID<13 and TAMS_Depot_DTCAuth_SPKS.StatusID is null
		) and SPKSID not in
		(
			Select SPKSID from TAMS_Depot_DTCAuth_SPKS 
			where authID=@authid and StatusID=14
		)
		
	END
	
	

	if @workflowid=127 or @workflowid=131 or @workflowid=139 or @workflowid=135 or @workflowid=136 or @workflowid=137
	BEGIN
		DECLARE @checkstatus as int;
		
		if @workflowid=127 or @workflowid=135
		BEGIN
			Select @checkstatus=WFStatusId from TAMS_WFStatus where ID=@workflowid
		END
		ELSE
		BEGIN
			Select @checkstatus=WFStatusId+1 from TAMS_WFStatus where ID=@workflowid
		END

		
		DECLARE @newstatus as int

		if @workflowid=137
		BEGIN
		if not exists(Select * from TAMS_Depot_DTCAuth_SPKS where AuthID=@authid and (StatusID<@checkstatus or StatusID is null))
			BEGIN
				SET @newstatus=@checkstatus+1;

				UPDATE TAMS_Depot_Auth
				SET DepotAuthStatusId=@newstatus,UpdatedOn=getDate(),UpdatedBy=@username
				where ID=@authid

				UPDATE TAMS_Depot_Auth_Workflow
				SET WFStatus=CASE when @type=1 THEN 'Completed' ELSE @valstr END, ActionBy=@username, ActionOn=getDate(),CheckBoxValue=CASE WHEN @type=1 THEN @val ELSE NULL END
				where WorkflowID=@workflowid

				Select @newworkflowid=ID from TAMS_WFStatus where WFType='dtcauth' and WFStatusId=@newstatus


				INSERT INTO TAMS_Depot_Auth_Workflow
				VALUES(@authid, 'Completed', getDate(), 'csapmg72', @newworkflowid,null,0)
			END
		END
		ELSE
		BEGIN
		if not exists(Select * from TAMS_Depot_Auth_Powerzone where AuthID=@authid and (StatusID<@checkstatus or StatusID is null))
			BEGIN
				SET @newstatus=@checkstatus+1;

				UPDATE TAMS_Depot_Auth
				SET DepotAuthStatusId=@newstatus,UpdatedOn=getDate(),UpdatedBy=@username
				where ID=@authid

				UPDATE TAMS_Depot_Auth_Workflow
				SET WFStatus=CASE when @type=1 THEN 'Completed' ELSE @valstr END, ActionBy=@username, ActionOn=getDate(),CheckBoxValue=CASE WHEN @type=1 THEN @val ELSE NULL END
				where WorkflowID=@workflowid

				Select @newworkflowid=ID from TAMS_WFStatus where WFType='dtcauth' and WFStatusId=@newstatus

				INSERT INTO TAMS_Depot_Auth_Workflow
				VALUES(@authid, null, null, null, @newworkflowid,null,0)
			END
		END
	END
	ELSE
	BEGIN
			UPDATE TAMS_Depot_Auth
			SET DepotAuthStatusId=@newstatusid,UpdatedOn=getDate(),UpdatedBy=@username
			where ID=@authid
	END

	IF @@ERROR <> 0 BEGIN
		SET @Message = 'ERROR INSERTING INTO Depot Authorization module.'
		
		PRINT 'trap error'
		GOTO TRAP_ERROR
	END

	FORCE_EXIT_PROC:	
	
		PRINT 'trap error 1'
		IF @IntrnlTrans = 1 COMMIT TRAN
		set @success=1;
		RETURN;
		--RETURN @Message 

	TRAP_ERROR:
	
		PRINT 'trap error 2'
		IF @IntrnlTrans = 1 ROLLBACK TRAN
		set @success=0;
		RETURN;
		--RETURN @Message

END
GO
/****** END PROCEDURE 90 ******/

/****** START PROCEDURE 91 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_Depot_UpdateDTCAuthBatch
CREATE PROCEDURE [dbo].[sp_TAMS_Depot_UpdateDTCAuthBatch]
	-- Add the parameters for the stored procedure here
	--@username as nvarchar(50),
	--@authid as int,
	--@workflowid as int,
	--@statusid as int,
	--@val as bit=NULL,
	--@valstr as nvarchar(50)=NULL,
	--@powerzoneid as int=NULL,
	--@type as int, -- type is 1 if checkbox, 2 if dropdown
	--@spksid as int=NULL,
	 @success as bit=NULL OUTPUT,
	 @Message AS NVARCHAR(500) = NULL OUTPUT,
	 @str AS TAMS_DTC_AUTH READONLY
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

	DECLARE	@IntrnlTrans	TINYINT
	SELECT 	@IntrnlTrans 	= 0	

	IF (@@TRANCOUNT = 0) 
	BEGIN
		SET @IntrnlTrans = 1
		BEGIN TRAN
	END DECLARE @valstr as nvarchar(50)=NULL;
	 DECLARE @powerzoneid as int=NULL;
	 DECLARE @type as int; -- type is 1 if checkbox, 2 if dropdown
	 DECLARE @spksid as int=NULL;


	 DECLARE @username as nvarchar(50);
	 DECLARE @authid as int;
	 DECLARE @workflowid as int;
     DECLARE @statusid as int;
	 DECLARE @val as bit=NULL;
	
	DECLARE C CURSOR FOR
	SELECT username, authid, workflowid, statusid, val, valstr, powerzoneid, [type], spksid from @str 
	

	OPEN C;

	FETCH NEXT FROM C INTO @username, @authid, @workflowid, @statusid, @val, @valstr, @powerzoneid, @type, @spksid 
	WHILE @@FETCH_STATUS=0
	BEGIN 
		DECLARE @access as bit=0;
		DECLARE @WFStatusID as int;
		SELECT @WFStatusID=TAMS_WFStatus.WFStatusId from TAMS_WFStatus where ID=@workflowid

		DECLARE @toastatus as int;
		SELECT @toastatus=TAMS_TOA.TOAStatus from TAMS_Depot_Auth INNER JOIN TAMS_TOA ON TAMS_TOA.TARId=TAMS_Depot_Auth.TarID 
		where TAMS_Depot_Auth.ID=@authid

		if @statusid > @WFStatusID
		BEGIN
			SET @WFStatusID=@statusid
		END
		
	

		DECLARE @accessDate as DateTime
		Select @accessDate=AccessDate from TAMS_Depot_Auth where id=@authid

		DECLARE @mworkflowid as INT
		Select @mworkflowid=ID from TAMS_Workflow where WorkflowType='OCCAuth' and TrackType='DEPOT' and Line='NEL'

		DECLARE @operationDate as DateTime
		DECLARE @cutofftiming as Time
		SELECT @cutofftiming=ParaTime from TAMS_Parameters where ParaCode='OpDateCutOffTime' and ParaValue1='NEL' and ParaValue2='Depot'

		DECLARE @TodayDate as Date=CAST(GETDATE() AS DATE)
		DECLARE @combineDateTime as DateTime=CAST(@TodayDate As datetime) + CAST(@cutofftiming As datetime)



		if @combineDateTime >= GETDATE()
		BEGIN
			SET @operationDate=CAST(DATEADD(day,-1,GETDATE()) As date)
		END
		ELSE
		BEGIN
			SET @operationDate=CAST(GETDATE() As date)
		END
		
		PRINT @operationDate
		IF EXISTS(Select TAMS_Roster_Role.RoleId,TAMS_OCC_Duty_Roster.DutyStaffId,TAMS_User.LoginId 
		from TAMS_OCC_Duty_Roster 
		INNER JOIN TAMS_Roster_Role ON TAMS_Roster_Role.RosterCode=TAMS_OCC_Duty_Roster.RosterCode
		and TAMS_OCC_Duty_Roster.Line=TAMS_Roster_Role.Line and TAMS_OCC_Duty_Roster.TrackType=TAMS_Roster_Role.TrackType
		INNER JOIN TAMS_User ON TAMS_User.Userid=TAMS_OCC_Duty_Roster.DutyStaffId 
		INNER JOIN TAMS_Endorser ON TAMS_Endorser.RoleId=TAMS_Roster_Role.RoleId
		where TAMS_OCC_Duty_Roster.tracktype='Depot' and OperationDate=@operationDate--@accessDate
		and LoginId=@username and TAMS_Endorser.WorkflowId=@mworkflowid and TAMS_Endorser.WFStatusId=@WFStatusID)
		BEGIN
			SET @access=1
		END


		--IF not EXISTS(select TAMS_User.LoginId from TAMS_Endorser INNER JOIN TAMS_User_Role 
		--ON TAMS_User_Role.ID=TAMS_Endorser.RoleId INNER JOIN TAMS_User
		--ON TAMS_User.LoginId=@username 
		--where TAMS_Endorser.ID=@workflowid 
		--and TAMS_User.LoginId IN (SELECT DutyStaffId from TAMS_OCC_Duty_Roster where TrackType='DEPOT' and OperationDate=@accessDate))
		--BEGIN
		--	SET @access=1
		--END

		if @access=0
		BEGIN
			--throw exception
			set @Message='User ' + @username + ' do not have access to update the information';
		
			GOTO TRAP_ERROR
		END
		
		
		if  @WFStatusID<>6 and @WFStatusID<>13
		BEGIN
			if not Exists(Select * from TAMS_Depot_Auth_Workflow where WorkflowID=@workflowid)
			BEGIN
			--	if @WFStatusID=5 
			--	BEGIN
			--		if not Exists(Select * from TAMS_Depot_Auth_Powerzone where StatusID=@WFStatusID)
			--		BEGIN
			--			set @Message='Workflow not found or is invalid';
					
			--			GOTO TRAP_ERROR
			--		END
			--	END
			--	ELSE
			--	BEGIN
					set @Message='Workflow not found or is invalid';
					GOTO TRAP_ERROR
			--	END
			END
		END


		-- check if spks zone is still in used by another tar 
		if @WFStatusID=14
		BEGIN
			if Exists(
			Select * from (
			Select B.* from (Select AccessDate,ID from TAMS_Depot_Auth) A  
					join TAMS_Depot_Auth B ON B.AccessDate=A.AccessDate
				where A.ID=@authid) C JOIN TAMS_Depot_DTCAuth_SPKS ON C.ID=TAMS_Depot_DTCAuth_SPKS.AuthID 
				where C.ID<>@authid and TAMS_Depot_DTCAuth_SPKS.SPKSID=@spksid and DepotAuthStatusId=8)
				BEGIN
					set @Message='The SPKS Zone ' + CONVERT(nvarchar(50),@spksid) + ' is being access by another TAR';
					GOTO TRAP_ERROR
				END
		END
		
		-- check if power zone is still in used by another tar 
		--if @WFStatusID=11
		--BEGIN 
		--	if Exists(
		--	Select * from (
		--	Select B.* from (Select AccessDate,ID from TAMS_Depot_Auth) A  
		--			join TAMS_Depot_Auth B ON B.AccessDate=A.AccessDate
		--		where A.ID=@authid) C JOIN TAMS_Depot_Auth_Powerzone ON C.ID=TAMS_Depot_Auth_Powerzone.AuthID 
		--		where C.ID<>@authid and TAMS_Depot_Auth_Powerzone.PowerzoneID=@powerzoneid and DepotAuthStatusId=8)
		--		BEGIN
		--			DECLARE @powersector as nvarchar(50)
		--			SELECT DISTINCT @powersector=PowerSector from TAMS_Depot_Auth_Powerzone INNER JOIN 
		--			TAMS_Power_Sector ON TAMS_Depot_Auth_Powerzone.PowerzoneID=TAMS_Power_Sector.ID where 
		--			TAMS_Depot_Auth_Powerzone.PowerzoneID=@powerzoneid and AuthID=@authid


		--			set @Message='The power Zone ' + @powersector + ' is being access by another TAR';
		--			GOTO TRAP_ERROR
		--		END
		--END


		--check if workflow is already updated
		IF Exists(Select * from TAMS_Depot_Auth_Workflow where DTCAuthId=@authid and WorkflowID=@workflowid
		and WFStatus is not NULL and CheckBoxValue is not null)
		BEGIN
			-- already updated
			-- throw error
			set @Message='Workflow ID ' + CONVERT(nvarchar(10),@workflowid) + ' is already updated';
			GOTO TRAP_ERROR

		END

		DECLARE @newstatusid as int;
		-- get next status
		select @newstatusid=WFStatusId+1 from TAMS_WFStatus where WFType='dtcauth' and WFStatusId=@statusid
		and isActive=1
		order by [Order] ASC;


		--update current workflow
		UPDATE TAMS_Depot_Auth_Workflow
		SET WFStatus=CASE when @type=1 THEN 'Completed' ELSE @valstr END, ActionBy=@username, ActionOn=getDate(),CheckBoxValue=CASE WHEN @type=1 THEN @val ELSE NULL END
		where WorkflowID=@workflowid and DTCAuthId=@authid and
		@WFStatusID<>4 and @WFStatusID<>5 and @WFStatusID<>6 and @WFStatusID<>11 and @WFStatusID<>12 and @WFStatusID<>14 and @WFStatusID<>7



		-- get next workflow
		DECLARE @currentStatus as int;
		DECLARE @newworkflowid as int;

		select @currentStatus=WFStatusId from TAMS_WFStatus where WFType='dtcauth' and Id=@workflowid
		Select @newworkflowid=ID from TAMS_WFStatus where WFType='dtcauth' and WFStatusId=(@currentStatus+1)

		-- insert next workflow 
		INSERT INTO TAMS_Depot_Auth_Workflow
		SELECT @authid, null, null, null, @newworkflowid,null,0
		where @WFStatusID<>7 and @WFStatusID<>4 and @WFStatusID<>5 and @WFStatusID<>6 and @WFStatusID<>11 and @WFStatusID<>12 and @WFStatusID<>14

		-- if surrender, enable line clear stage
		if @WFStatusID=7
		BEGIN

				UPDATE TAMS_Depot_Auth_Workflow
				SET WFStatus=CASE when @type=1 THEN 'Completed' ELSE @valstr END, ActionBy=@username, ActionOn=getDate(),CheckBoxValue=CASE WHEN @type=1 THEN @val ELSE NULL END
				where WorkflowID=@workflowid and DTCAuthId=@authid 

				INSERT INTO TAMS_Depot_Auth_Workflow
				SELECT @authid, null, null, null, @newworkflowid,null,0

				UPDATE TAMS_Depot_Auth
				SET DepotAuthStatusId=@newstatusid,UpdatedOn=getDate(),UpdatedBy=@username
				where ID=@authid
			
		END


		if @WFStatusID=10
		BEGIN
			-- set powerzone id to next id
			UPDATE TAMS_Depot_Auth_Powerzone
			SET TAMS_Depot_Auth_Powerzone.StatusID=TAMS_Depot_Auth_Powerzone.StatusID+1 
			where AuthID=@authid
		END

		if @WFStatusID=3
		BEGIN
			UPDATE TAMS_Depot_DTCAuth_SPKS
			SET ProtectOffTiming=getDate(), ProtectOffType=@valstr,ProtectOffActionBy=@username
			where AuthID=@authid
		END
	


		if @WFStatusID=4
		BEGIN

			UPDATE TAMS_Depot_Auth_Powerzone
			SET 
			--RackedOutTiming=getDate(),RackedOutType=@valstr,RackedOffActionBy=@username,
			PowerOffTiming=getDate(),PowerOffType=@valstr,PowerOffActionBy=@username,
			statusID=@newstatusid
			where AuthID=@authid and PowerzoneID=@powerzoneid



		END

		if @WFStatusID=12
		BEGIN

			UPDATE TAMS_Depot_Auth_Powerzone
			SET  PowerOnTiming=getDate(),PowerOnType=@valstr,PowerOnActionBy=@username,statusID=@newstatusid
			where AuthID=@authid and PowerzoneID=@powerzoneid

			UPDATE TAMS_Depot_DTCAuth_SPKS
			SET StatusID=@newstatusid+1
			where AuthID=@authid and SPKSID NOT IN 
			(
				Select DISTINCT SPKSId from (
				(Select PowerzoneID,TAMS_Depot_Auth_Powerzone.StatusID from TAMS_Depot_Auth_Powerzone
				where TAMS_Depot_Auth_Powerzone.AuthID=@authid) B
				LEFT JOIN
				(Select DISTINCT PowerSectorId, PowerSector,SPKSId  from 
				TAMS_Track_Power_Sector INNER JOIN TAMS_Track_SPKSZone 
				ON TAMS_Track_Power_Sector.SectorId=TAMS_Track_SPKSZone.SectorId 
				INNER JOIN TAMS_Power_Sector 
				ON TAMS_Power_Sector.ID=TAMS_Track_Power_Sector.PowerSectorId 
				) A ON A.PowerSectorId=B.PowerzoneID)
				where StatusID<>13
				group by SPKSId,PowerSectorId,StatusID
			) 
			and SPKSID not in
			(
				Select SPKSID from TAMS_Depot_DTCAuth_SPKS 
				where authID=@authid and StatusID=15
			)

		END


		if @WFStatusID=14
		BEGIN
			UPDATE TAMS_Depot_DTCAuth_SPKS
			SET ProtectOnTiming=getDate(), ProtectOnType=@valstr,ProtectOnActionBy=@username,StatusID=@newstatusid
			where AuthID=@authid and SPKSID=@spksid
		END

		if @WFStatusID=5 or @WFStatusID=6
		BEGIN
			UPDATE TAMS_Depot_Auth_Powerzone
			SET RackedOutTiming=getDate(),RackedOutType=@valstr,RackedOffActionBy=@username,statusID=@newstatusid
			where AuthID=@authid and PowerzoneID=@powerzoneid

		END


		if @WFStatusID=11
		BEGIN
			UPDATE TAMS_Depot_Auth_Powerzone
			SET RackedInTiming=getDate(),RackedInType=@valstr,RackedInActionBy=@username,statusID=@newstatusid
			where AuthID=@authid and PowerzoneID=@powerzoneid

		
		
		END
	
	

		if @WFStatusID=4 or @WFStatusID=5 or @WFStatusID=6 or @WFStatusID=11 or @WFStatusID=12 or @WFStatusID=14
		BEGIN
			DECLARE @checkstatus as int;
		
			if @WFStatusID=4 or @WFStatusID=11
			BEGIN
				Select @checkstatus=WFStatusId from TAMS_WFStatus where WFStatusId=@WFStatusID
			END
			ELSE
			BEGIN
				Select @checkstatus=WFStatusId+1 from TAMS_WFStatus where WFStatusId=@WFStatusID
			END

		
			DECLARE @newstatus as int

			if @WFStatusID=14
			BEGIN
			if not exists(Select * from TAMS_Depot_DTCAuth_SPKS where AuthID=@authid and (StatusID<@checkstatus or StatusID is null))
				BEGIN
					SET @newstatus=@checkstatus+1;

					UPDATE TAMS_Depot_Auth
					SET DepotAuthStatusId=@newstatus,UpdatedOn=getDate(),UpdatedBy=@username
					where ID=@authid

					UPDATE TAMS_Depot_Auth_Workflow
					SET WFStatus=CASE when @type=1 THEN 'Completed' ELSE @valstr END, ActionBy=@username, ActionOn=getDate(),CheckBoxValue=CASE WHEN @type=1 THEN @val ELSE NULL END
					where WorkflowID=@workflowid and DTCAuthId=@authid 

					Select @newworkflowid=ID from TAMS_WFStatus where WFType='dtcauth' and WFStatusId=@newstatus


					INSERT INTO TAMS_Depot_Auth_Workflow
					VALUES(@authid, 'Completed', getDate(), @username, @newworkflowid,null,0)
				END
			END
			ELSE
			BEGIN
			if not exists(Select * from TAMS_Depot_Auth_Powerzone where AuthID=@authid and (StatusID<@checkstatus or StatusID is null))
				BEGIN
					SET @newstatus=@checkstatus+1;

					UPDATE TAMS_Depot_Auth
					SET DepotAuthStatusId=@newstatus,UpdatedOn=getDate(),UpdatedBy=@username
					where ID=@authid

					UPDATE TAMS_Depot_Auth_Workflow
					SET WFStatus=CASE when @type=1 THEN 'Completed' ELSE @valstr END, ActionBy=@username, ActionOn=getDate(),CheckBoxValue=CASE WHEN @type=1 THEN @val ELSE NULL END
					where WorkflowID=@workflowid and DTCAuthId=@authid 

					Select @newworkflowid=ID from TAMS_WFStatus where WFType='dtcauth' and WFStatusId=@newstatus

					INSERT INTO TAMS_Depot_Auth_Workflow
					VALUES(@authid, null, null, null, @newworkflowid,null,0)
				END
			END
		END
		ELSE
		BEGIN

			--check for cancel tar
			if @toastatus=6 
			BEGIN
				DECLARE @notrainsds INT;
				SELECT @notrainsds=WFStatusID from TAMS_WFStatus where WFStatus='Pending No Train Movement (SDS)'  and TrackType='Depot' and WFType='DTCAuth' and Line='NEL'

				DECLARE @notraindtc INT;
				SELECT @notraindtc=WFStatusID from TAMS_WFStatus where WFStatus='Pending No Train Movement (DTC)' and TrackType='Depot' and WFType='DTCAuth' and Line='NEL'
			

				DECLARE @lineclearcerdtctstatus INT;
				SELECT @lineclearcerdtctstatus=WFStatusID from TAMS_WFStatus where WFStatus='Line Clear Certification (TOA/SCD) (DTC)' and TrackType='Depot' and WFType='DTCAuth' and Line='NEL'

				DECLARE @lineclearcertccstatus INT;
				SELECT @lineclearcertccstatus=WFStatusID from TAMS_WFStatus where WFStatus='Line Clear Certification (TOA/SCD) (CC)' and TrackType='Depot' and WFType='DTCAuth' and Line='NEL'
			
				DECLARE @completestatus INT;
				SELECT @completestatus=WFStatusID from TAMS_WFStatus where WFStatus='Completed' 

		
				-- check if cancel toa
				DECLARE @cancelstatusid as int
				SELECT @cancelstatusid=TAMS_WFStatus.WFStatusId-1 from TAMS_Depot_Auth_Workflow INNER JOIN TAMS_WFStatus 
				ON TAMS_Depot_Auth_Workflow.WorkflowID=TAMS_WFStatus.ID
				where DTCAuthId=@authid and TAMS_Depot_Auth_Workflow.isCancelled=1 

				if @cancelstatusid=@notrainsds
				BEGIN
					SET @newstatusid=CASE WHEN @WFStatusID=@lineclearcerdtctstatus THEN  @completestatus+1 ELSE @newstatusid END
				END
				ELSE if @cancelstatusid=@notraindtc
				BEGIN 
					SET @newstatusid=CASE WHEN @WFStatusID=@lineclearcertccstatus THEN  @completestatus+1 ELSE @newstatusid END
				END
			END
		
			UPDATE TAMS_Depot_Auth
			SET DepotAuthStatusId=@newstatusid,UpdatedOn=getDate(),UpdatedBy=@username
			where ID=@authid and @WFStatusID<>7
			
		END


		FETCH NEXT FROM C INTO @username, @authid, @workflowid, @statusid, @val, @valstr, @powerzoneid, @type, @spksid 
	END
	CLOSE C;
	DEALLOCATE C;

	IF @@ERROR <> 0 BEGIN
		SET @Message = 'ERROR INSERTING INTO Depot Authorization module.'
		
		PRINT 'trap error'
		GOTO TRAP_ERROR
	END

	FORCE_EXIT_PROC:	
	
		PRINT 'trap error 1'
		IF @IntrnlTrans = 1 COMMIT TRAN
		set @success=1;
		RETURN;
		--RETURN @Message 

	TRAP_ERROR:
	
		PRINT 'trap error 2'
		IF @IntrnlTrans = 1 ROLLBACK TRAN
		set @success=0;
		RETURN;
		--RETURN @Message

END
GO
/****** END PROCEDURE 91 ******/

/****** START PROCEDURE 92 ******/
