		SET @Body3 = @Body3 + '<td>***********************************************<br>Do Not reply. This is a computer generated Email. <br>***********************************************</td>'
		SET @Body3 = @Body3 + '</tr>'
		SET @Body3 = @Body3 + '</table>'

		SET @Body = ''
		SET @Body = @Body1 + @Body2 + @Body3

		SET @BCCList = ''

		EXEC [dbo].EAlertQ_EnQueue 
			@Sender = @Sender, 
			@UserId = @SysID, 
			@Subject = @Subject,        
