-- PROCEDURE NAME: dbo.sp_TAMS_Get_External_UserInfo_by_LoginIDPWD
CREATE PROCEDURE [dbo].[sp_TAMS_Get_External_UserInfo_by_LoginIDPWD] 
	@LoginID	NVARCHAR(100),
	@LoginPWD	NVARCHAR(200)
AS
BEGIN

	IF EXISTS (SELECT * FROM TAMS_User 
					WHERE LoginID = @LoginID
						AND IsExternal = 1
						AND IsActive = 1)
		BEGIN
			SELECT * 
				FROM TAMS_User u
					WHERE u.LoginID = @LoginID 
						AND dbo.DecryptString(u.[Password]) = @LoginPWD;
		END

