-- PROCEDURE NAME: dbo.sp_TAMS_Get_RegistrationCompanyInformationbyRegID
CREATE PROCEDURE [dbo].[sp_TAMS_Get_RegistrationCompanyInformationbyRegID] 
	@RegID INT
AS
BEGIN
	-- RegStatus 1 = Applicant Company Registration Stage
	IF EXISTS(SELECT * FROM TAMS_Reg_Module WHERE RegID = @RegID AND RegStatus IN (1, 8, 15))
	BEGIN
		SELECT * FROM TAMS_Registration WHERE ID = @RegID
	END;
	

END







