				(@ID, @UserRail, @UserType, @UserID, @UserName, @UModule, @IsActive);
		END;
		
		FETCH NEXT FROM cur INTO @ID, @UserID, @UserType, @UserName, @IsActive;
	END

	CLOSE cur;
	DEALLOCATE cur;

