-- PROCEDURE NAME: dbo.sp_TAMS_Get_UserInfo_by_ID
CREATE PROCEDURE [dbo].[sp_TAMS_Get_UserInfo_by_ID] 
	@UserID NVARCHAR(100) = NULL
AS
BEGIN

	--IF EXISTS (SELECT * FROM TAMS_User WHERE UserID = @UserID)
	--BEGIN
		SELECT * 
		FROM TAMS_User u
		WHERE u.UserID = @UserID

	--END
	
	--IF EXISTS (SELECT * FROM TAMS_Company WHERE ID = (SELECT CompanyID FROM TAMS_User WHERE UserID = @UserID))
	--BEGIN

	SELECT * FROM TAMS_Company WHERE ID = (SELECT CompanyID FROM TAMS_User WHERE UserID = @UserID);

	SELECT * FROM TAMS_User_QueryDept WHERE UserID = @UserID
	--END;

	-- Get User Access Portion
	-- DTL TAR
	SELECT ID, RoleDesc, Line,TrackType, Module, Role, UserID FROM
	(
		SELECT r.ID, r.RoleDesc, r.Line, r.TrackType, r.Module, r.Role, ur.UserID 
		FROM TAMS_Role r LEFT JOIN TAMS_User_Role ur
		ON ur.RoleID = r.ID
		AND ur.UserID = @UserID
		AND r.Line = 'DTL' 
		AND r.Module = 'TAR'
		AND ur.Line = 'DTL'
		AND r.IsActive = 1
		AND r.Line NOT IN ('All')
	) a
	WHERE Line = 'DTL'
	AND Module = 'TAR' and TrackType='mainline'

	-- DTL OCC
	SELECT ID, RoleDesc, Line,TrackType, Module, Role, UserID FROM
	(
		SELECT r.ID, r.RoleDesc, r.Line,r.TrackType, r.Module, r.Role, ur.UserID 
		FROM TAMS_Role r LEFT JOIN TAMS_User_Role ur
		ON ur.RoleID = r.ID
		AND ur.UserID = @UserID
		AND r.Line = 'DTL' 
		AND r.Module = 'OCC'
		AND ur.Line = 'DTL'
		AND r.IsActive = 1
		AND r.Line NOT IN ('All')
	) a
	WHERE Line = 'DTL'
	AND Module = 'OCC' and TrackType='mainline'
	
	-- NEL TAR
	SELECT ID, RoleDesc, Line,TrackType, Module, Role, UserID FROM
	(
		SELECT r.ID, r.RoleDesc, r.Line, r.TrackType, r.Module, r.Role, ur.UserID 
		FROM TAMS_Role r LEFT JOIN TAMS_User_Role ur
		ON ur.RoleID = r.ID
		AND ur.UserID = @UserID
		AND r.Line = 'NEL' 
		AND r.Module = 'TAR'
		AND r.TrackType='mainline'
		AND ur.Line = 'NEL'
		AND r.IsActive = 1
		AND r.Line NOT IN ('All')
	) a
	WHERE Line = 'NEL'
	AND Module = 'TAR' and TrackType='mainline'

	-- NEL OCC
	SELECT ID, RoleDesc, Line,TrackType, Module, Role, UserID FROM
	(
		SELECT r.ID, r.RoleDesc, r.Line,r.TrackType, r.Module, r.Role, ur.UserID 
		FROM TAMS_Role r LEFT JOIN TAMS_User_Role ur
		ON ur.RoleID = r.ID
		AND ur.UserID = @UserID
		AND r.Line = 'NEL' 
		AND (r.Module = 'OCC')
		AND ur.Line = 'NEL'
		AND r.TrackType='mainline'
		AND r.IsActive = 1
		AND r.Line NOT IN ('All')
	) a
	WHERE Line = 'NEL'
	AND (Module = 'OCC') and TrackType='mainline'

	/*-- NEL TAR
	SELECT ID, RoleDesc, Line,TrackType, Module, Role, UserID FROM
	(
		SELECT r.ID, r.RoleDesc, r.Line,r.TrackType, r.Module, r.Role, ur.UserID 
		FROM TAMS_Role r LEFT JOIN TAMS_User_Role ur
		ON ur.RoleID = r.ID
		AND ur.UserID = @UserID
		AND r.Line = 'SPLRT' 
		AND r.Module = 'TAR'
		AND ur.Line = 'SPLRT'
		AND r.IsActive = 1
		AND r.Line NOT IN ('All')
	) a
	WHERE Line = 'SPLRT'
	AND Module = 'TAR'

	-- NEL OCC
	SELECT ID, RoleDesc, Line,TrackType, Module, Role, UserID FROM
	(
		SELECT r.ID, r.RoleDesc, r.Line,r.TrackType, r.Module, r.Role, ur.UserID 
		FROM TAMS_Role r LEFT JOIN TAMS_User_Role ur
		ON ur.RoleID = r.ID
		AND ur.UserID = @UserID
		AND r.Line = 'SPLRT' 
		AND r.Module = 'OCC'
		AND ur.Line = 'SPLRT'
		AND r.IsActive = 1
		AND r.Line NOT IN ('All')
	) a
	WHERE Line = 'SPLRT'
	AND Module = 'OCC'*/

	-- NEL Depot TAR
	SELECT ID, RoleDesc, Line,TrackType, Module, Role, UserID FROM
	(
		SELECT r.ID, r.RoleDesc, r.Line,r.TrackType, r.Module, r.Role, ur.UserID 
		FROM TAMS_Role r LEFT JOIN TAMS_User_Role ur
		ON ur.RoleID = r.ID
		AND ur.UserID = @UserID
		AND r.Line = 'NEL' 
		AND r.TrackType='Depot'
		AND (r.Module='TAR')
		AND ur.Line = 'NEL'
		AND r.IsActive = 1
		AND r.Line NOT IN ('All')
	) a
	WHERE Line = 'NEL'
	AND (Module='TAR') and TrackType='Depot'

	-- NEL Depot DCC
	SELECT ID, RoleDesc, Line,TrackType, Module, Role, UserID FROM
	(
		SELECT r.ID, r.RoleDesc, r.Line,r.TrackType, r.Module, r.Role, ur.UserID 
		FROM TAMS_Role r LEFT JOIN TAMS_User_Role ur
		ON ur.RoleID = r.ID
		AND ur.UserID = @UserID
		AND r.Line = 'NEL' 
		AND r.TrackType='Depot'
		AND (r.Module='DCC')
		AND ur.Line = 'NEL'
		AND r.IsActive = 1
		AND r.Line NOT IN ('All')
	) a
	WHERE Line = 'NEL'
	AND (Module='DCC') and TrackType='Depot'
END
