CREATE PROCEDURE [dbo].[sp_TAMS_GetTarAccessRequirementsByTarId]
	@TarId AS integer = 0
AS
BEGIN
  select tta.id, tarid, tar.operationrequirement, tta.ispower, tta.isselected, tta.[order]
  from tams_tar_accessreq tta, TAMS_Access_Requirement tar
