/****** START PROCEDURE 165 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_GetTarByTarId
CREATE PROCEDURE [dbo].[sp_TAMS_GetTarByTarId]
	@TarId AS integer = 0
AS
BEGIN
	SELECT [Id],
	[Line],
	[TARNo],
	[TARType],
	[Company],
	[Designation],
	[Name],
	[OfficeNo],
	[MobileNo],
	[Email],
	[SubmitDate],
	[AccessDate],
	[AccessTimeFrom],
	[AccessTimeTo],
	[AccessLocation],
	[AccessType],
	[IsNeutralGap],
	[IsExclusive],
	[DescOfWork],
	[ARRemark],
	[Is13ASocket],
	[CrossOver], 
	[ProtectionType], 
	[WithdrawRemark], 
	Convert(varchar,WithdrawDate,103) as WithdrawDate,
	(Select top 1 Name from TAMS_User where Userid = WithdrawBy) as WithdrawBy, 
	TARStatusId, 
	(Select top 1 WFStatus from TAMS_WFStatus where WFStatusId = TARStatusId and TAMS_WFStatus.Line = TAMS_TAR.Line and TAMS_WFStatus.TrackType =TAMS_TAR.TrackType  and WFType='TARWFStatus')  as TARStatus
	FROM TAMS_TAR
	WHERE [Id] = @TarId;
END
GO
/****** END PROCEDURE 165 ******/

/****** START PROCEDURE 166 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_GetTarEnquiryResult
CREATE PROCEDURE [dbo].[sp_TAMS_GetTarEnquiryResult]
	@uid AS integer = 0,
	@Line AS nvarchar(10) = NULL,
	@AccessType AS nvarchar(50) = NULL,
	@TarStatusId AS integer = 0,
	@AccessDateFrom as nvarchar(50) = NULL,
	@AccessDateTo as nvarchar(50) = NULL,
	@isNEL_Applicant as bit = 0,
	@isDTL_Applicant as bit = 0,
	@isNEL_ApplicantHOD as bit = 0,
	@isDTL_ApplicantHOD as bit = 0,
	@isNEL_PowerApprover as bit = 0,
	@isDTL_PowerApprover as bit = 0,
	@isNEL_PowerVerifier as bit = 0

AS
BEGIN
	DECLARE @Line1 as varchar(3),
			@Line2 as varchar(3),
			@Dept as nvarchar(50)

	DECLARE @cond as varchar(2000);

	PRINT '@isNEL_ApplicantHOD: ' + CAST(@isNEL_ApplicantHOD AS nvarchar(1));
	SET @Line1 = SUBSTRING(@Line,1,3);
	SET @Line2 = SUBSTRING(@Line,5,7);

	IF @AccessType IS NOT NULL AND @AccessType != ''  AND @AccessType != '-1' 
	BEGIN 
		SET @cond = @cond + ' AND AccessType=''' + @AccessType + '''';
	END;

	IF @TarStatusId IS NOT NULL AND @TarStatusId != ''  AND @TarStatusId != '-1' 
	BEGIN 
		SET @cond = @cond + ' AND TarStatusId=''' + @TarStatusId + '''';
	END;

	IF NOT ISNULL(@AccessDateFrom, '') = '' AND NOT @AccessDateFrom = ''
	BEGIN			
		SET @cond = @cond + ' AND AccessDate >= convert(datetime,''' + @AccessDateFrom + ''',103)';
	END;

	IF NOT ISNULL(@AccessDateTo, '') = '' AND NOT @AccessDateTo = ''
	BEGIN			
		SET @cond = @cond + ' AND AccessDate <= convert(datetime,''' + @AccessDateTo + ''',103)';
	END;	

	DECLARE @sql nvarchar(2000);
	IF @Line1 <> ''
	BEGIN
		IF @Line1 = 'NEL'
		BEGIN
			IF (@isNEL_Applicant = 1 AND @isNEL_ApplicantHOD = 0 AND @isNEL_PowerApprover = 0 AND @isNEL_PowerVerifier = 0)
			BEGIN
				SET @sql = 'select t.tarno, t.tartype, t.accesstype, t.accessdate, s.wfstatus
				from TAMS_TAR_Test t, TAMS_WFStatus s
				where t.TARStatusId = s.WFStatusId
				and t.Line = s.Line
				and t.createdby = ''' + CAST(@uid as nvarchar(10)) +'''
				and t.Line = ''' + @Line1 +'''' + @cond
			END;
			IF (@isNEL_Applicant = 1 AND @isNEL_ApplicantHOD = 0 AND (@isNEL_PowerApprover = 0 OR @isNEL_PowerVerifier = 1 OR @isNEL_PowerApprover = 1 OR @isNEL_PowerVerifier = 0))
			BEGIN
				SET @sql = 'select t.tarno, t.tartype, t.accesstype, t.accessdate, s.wfstatus
				from TAMS_TAR_Test t, TAMS_WFStatus s
				where t.TARStatusId = s.WFStatusId
				and t.Line = s.Line
				and (t.createdby = ''' + CAST(@uid as nvarchar(10)) +''' or t.InvolvePower = 1)
				and t.Line = ''' + @Line1 +'''' + @cond
			END;
			IF (@isNEL_Applicant = 0 AND @isNEL_ApplicantHOD = 0 AND (@isNEL_PowerApprover = 0 OR @isNEL_PowerVerifier = 1 OR @isNEL_PowerApprover = 1 OR @isNEL_PowerVerifier = 0))
			BEGIN
				--SET @sql = '';
				SET @sql = 'select t.tarno, t.tartype, t.accesstype, t.accessdate, s.wfstatus
				from TAMS_TAR_Test t, TAMS_WFStatus s
				where t.TARStatusId = s.WFStatusId
				and t.Line = s.Line
				and t.InvolvePower = 1
				and t.Line = ''' + @Line1 +'''' + @cond
			END;
			IF ((@isNEL_Applicant = 0 OR @isNEL_Applicant = 1) AND @isNEL_ApplicantHOD = 1 AND @isNEL_PowerApprover = 0 AND @isNEL_PowerVerifier = 0)
			BEGIN
				--SET @sql = '';
				SET @sql = 'select t.tarno, t.tartype, t.accesstype, t.accessdate, s.wfstatus
				from TAMS_TAR_Test t, TAMS_WFStatus s
				where t.TARStatusId = s.WFStatusId
				and t.Line = s.Line
				and t.company in (select TARQueryDept FROM TAMS_User_QueryDept WHERE SUBSTRING(TARQueryDept,1,4) = ''NEL'' AND UserID = ''' + CAST(@uid AS nvarchar(10)) + ''')
				and t.Line = ''' + @Line1 +'''' + @cond
			END;
			IF (@isNEL_Applicant = 0 AND @isNEL_ApplicantHOD = 1 AND (@isNEL_PowerApprover = 0 OR @isNEL_PowerVerifier = 1 OR @isNEL_PowerApprover = 1 OR @isNEL_PowerVerifier = 0))
			BEGIN
				--SET @sql = '';
				SET @sql = 'select t.tarno, t.tartype, t.accesstype, t.accessdate, s.wfstatus
				from TAMS_TAR_Test t, TAMS_WFStatus s
				where t.TARStatusId = s.WFStatusId
				and t.Line = s.Line
				and (t.company in (select TARQueryDept FROM TAMS_User_QueryDept WHERE SUBSTRING(TARQueryDept,1,4) = ''NEL'' AND UserID = ''' + CAST(@uid AS nvarchar(10)) + ''' or t.InvolvePower = 1)
				and t.Line = ''' + @Line1 +'''' + @cond
			END;
			PRINT (@sql);

		END;
		IF @Line1 = 'DTL'
		BEGIN
			IF (@isDTL_Applicant = 1 AND @isDTL_ApplicantHOD = 0 AND @isDTL_PowerApprover = 0)
			BEGIN
				SET @sql = 'select t.tarno, t.tartype, t.accesstype, t.accessdate, s.wfstatus
				from TAMS_TAR_Test t, TAMS_WFStatus s
				where t.TARStatusId = s.WFStatusId
				and t.Line = s.Line
				and t.createdby = ''' + CAST(@uid as nvarchar(10)) +'''
				and t.Line = ''' + @Line1 +'''' + @cond
			END;
			IF (@isDTL_Applicant = 1 AND @isDTL_ApplicantHOD = 0 AND @isDTL_PowerApprover = 1)
			BEGIN
				SET @sql = 'select t.tarno, t.tartype, t.accesstype, t.accessdate, s.wfstatus
				from TAMS_TAR_Test t, TAMS_WFStatus s
				where t.TARStatusId = s.WFStatusId
				and t.Line = s.Line
				and (t.createdby = ''' + CAST(@uid as nvarchar(10)) +''' or t.InvolvePower = 1)
				and t.Line = ''' + @Line1 +'''' + @cond
			END;
			IF (@isDTL_Applicant = 0 AND @isDTL_ApplicantHOD = 0 AND @isDTL_PowerApprover = 1)
			BEGIN
				--SET @sql = '';
				SET @sql = 'select t.tarno, t.tartype, t.accesstype, t.accessdate, s.wfstatus
				from TAMS_TAR_Test t, TAMS_WFStatus s
				where t.TARStatusId = s.WFStatusId
				and t.Line = s.Line
				and t.InvolvePower = 1
				and t.Line = ''' + @Line1 +'''' + @cond
			END;
			IF ((@isDTL_Applicant = 0 OR @isDTL_Applicant = 1) AND @isDTL_ApplicantHOD = 1 AND @isDTL_PowerApprover = 0)
			BEGIN
				--SET @sql = '';
				SET @sql = 'select t.tarno, t.tartype, t.accesstype, t.accessdate, s.wfstatus
				from TAMS_TAR_Test t, TAMS_WFStatus s
				where t.TARStatusId = s.WFStatusId
				and t.Line = s.Line
				and t.company in (select TARQueryDept FROM TAMS_User_QueryDept WHERE SUBSTRING(TARQueryDept,1,4) = ''DTL'' AND UserID = ''' + CAST(@uid AS nvarchar(10)) + ''')
				and t.Line = ''' + @Line1 +'''' + @cond
			END;
			IF (@isDTL_Applicant = 0 AND @isDTL_ApplicantHOD = 1 AND @isDTL_PowerApprover = 1)
			BEGIN
				--SET @sql = '';
				SET @sql = 'select t.tarno, t.tartype, t.accesstype, t.accessdate, s.wfstatus
				from TAMS_TAR_Test t, TAMS_WFStatus s
				where t.TARStatusId = s.WFStatusId
				and t.Line = s.Line
				and (t.company in (select TARQueryDept FROM TAMS_User_QueryDept WHERE SUBSTRING(TARQueryDept,1,4) = ''DTL'' AND UserID = ''' + CAST(@uid AS nvarchar(10)) + ''' or t.InvolvePower = 1)
				and t.Line = ''' + @Line1 +'''' + @cond
			END;
		END;
	END;

	IF @Line1 <> '' AND	@Line2 <> ''
	BEGIN
		SET @sql = @sql + ' union ';
	END;

	IF @Line2 <> ''
		IF @Line1 = 'DTL'
		BEGIN
			IF (@isDTL_Applicant = 1 AND @isDTL_ApplicantHOD = 0 AND @isDTL_PowerApprover = 0)
			BEGIN
				SET @sql = 'select t.tarno, t.tartype, t.accesstype, t.accessdate, s.wfstatus
				from TAMS_TAR_Test t, TAMS_WFStatus s
				where t.TARStatusId = s.WFStatusId
				and t.Line = s.Line
				and t.createdby = ''' + CAST(@uid as nvarchar(10)) +'''
				and t.Line = ''' + @Line1 +'''' + @cond
			END;
			IF (@isDTL_Applicant = 1 AND @isDTL_ApplicantHOD = 0 AND @isDTL_PowerApprover = 1)
			BEGIN
				SET @sql = 'select t.tarno, t.tartype, t.accesstype, t.accessdate, s.wfstatus
				from TAMS_TAR_Test t, TAMS_WFStatus s
				where t.TARStatusId = s.WFStatusId
				and t.Line = s.Line
				and (t.createdby = ''' + CAST(@uid as nvarchar(10)) +''' or t.InvolvePower = 1)
				and t.Line = ''' + @Line1 +'''' + @cond
			END;
			IF (@isDTL_Applicant = 0 AND @isDTL_ApplicantHOD = 0 AND @isDTL_PowerApprover = 1)
			BEGIN
				--SET @sql = '';
				SET @sql = 'select t.tarno, t.tartype, t.accesstype, t.accessdate, s.wfstatus
				from TAMS_TAR_Test t, TAMS_WFStatus s
				where t.TARStatusId = s.WFStatusId
				and t.Line = s.Line
				and t.InvolvePower = 1
				and t.Line = ''' + @Line1 +'''' + @cond
			END;
			IF ((@isDTL_Applicant = 0 OR @isDTL_Applicant = 1) AND @isDTL_ApplicantHOD = 1 AND @isDTL_PowerApprover = 0)
			BEGIN
				--SET @sql = '';
				SET @sql = 'select t.tarno, t.tartype, t.accesstype, t.accessdate, s.wfstatus
				from TAMS_TAR_Test t, TAMS_WFStatus s
				where t.TARStatusId = s.WFStatusId
				and t.Line = s.Line
				and t.company in (select TARQueryDept FROM TAMS_User_QueryDept WHERE SUBSTRING(TARQueryDept,1,4) = ''DTL'' AND UserID = ''' + CAST(@uid AS nvarchar(10)) + ''')
				and t.Line = ''' + @Line1 +'''' + @cond
			END;
			IF (@isDTL_Applicant = 0 AND @isDTL_ApplicantHOD = 1 AND @isDTL_PowerApprover = 1)
			BEGIN
				--SET @sql = '';
				SET @sql = 'select t.tarno, t.tartype, t.accesstype, t.accessdate, s.wfstatus
				from TAMS_TAR_Test t, TAMS_WFStatus s
				where t.TARStatusId = s.WFStatusId
				and t.Line = s.Line
				and (t.company in (select TARQueryDept FROM TAMS_User_QueryDept WHERE SUBSTRING(TARQueryDept,1,4) = ''DTL'' AND UserID = ''' + CAST(@uid AS nvarchar(10)) + ''' or t.InvolvePower = 1)
				and t.Line = ''' + @Line1 +'''' + @cond
			END;
		END;


	EXEC (@sql);	
	--PRINT (@sql);

END

GO
/****** END PROCEDURE 166 ******/

/****** START PROCEDURE 167 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_GetTarEnquiryResult_Department
CREATE procedure  [dbo].[sp_TAMS_GetTarEnquiryResult_Department]
	@uid AS integer = 0,
	@Line AS nvarchar(50) = NULL,
	@TrackType AS nvarchar(50) = NULL,
	@TarType AS nvarchar(50) = NULL,
	@AccessType AS nvarchar(50) = NULL,
	@TarStatusId AS integer = 0,
	@AccessDateFrom as nvarchar(50) = NULL,
	@AccessDateTo as nvarchar(50) = NULL 
 
AS
BEGIN
	DECLARE  @Dept as nvarchar(50),
			@StatusId as int
	declare @IsAll as int
	declare @IsPower as int
	declare @IsDep as int

	if ( ( Select count(*) 
	From TAMS_User u,TAMS_User_Role ur,TAMS_Role r
	Where u.Userid = ur.UserID and ur.RoleID= r.ID and r.TrackType = @TrackType
	and r.Role in ('NEL_OCCScheduler','DTL_OCCScheduler','NEL_TrafficController','DTL_TrafficController','NEL_DCC','NEL_ChiefController','NEL_SDS','NEL_TAPApprover','NEL_TAPHOD','NEL_TAPVerifier', 'DTL_TAPApprover','DTL_TAPHOD','DTL_TAPVerifier','DTL_ChiefController')
	and u.Userid = @uid
	) ) > 0 
	begin
		set @IsAll = 1 ;
	end;

	if ( ( Select count(*) 
	From TAMS_User u,TAMS_User_Role ur,TAMS_Role r
	Where u.Userid = ur.UserID and ur.RoleID= r.ID and r.TrackType = @TrackType
	and r.Role in ('NEL_PowerEndorser' ,'NEL_PowerHOD','NEL_PFR', 'DTL_PowerEndorser','DTL_PFR')
	and u.Userid = @uid
	) ) > 0 
	begin 
		set @IsPower = 1 
	end;


	if ( ( Select count(*) 
	From TAMS_User u,TAMS_User_Role ur,TAMS_Role r
	Where u.Userid = ur.UserID and ur.RoleID= r.ID and r.TrackType = @TrackType
	and r.Role in ('NEL_ApplicantHOD','NEL_Applicant','DTL_Applicant','DTL_ApplicantHOD')
	and u.Userid = @uid
	) ) > 0 
	begin 
		set @IsDep = 1 
	end;

	DECLARE @cond as varchar(max);

	SET @cond = '';

	 
	IF @Line IS NOT NULL AND @Line != ''  AND @Line != '-1' 
	BEGIN 
		SET @cond = ' AND t.Line='''+@Line+'''';
	END;
	IF @TarType IS NOT NULL AND @TarType != ''  AND @TarType != '-1' 
	BEGIN 
		SET @cond = ' AND t.TarType='''+@TarType+'''';
	END;

	IF @AccessType IS NOT NULL AND @AccessType != ''  AND @AccessType != '-1' 
	BEGIN 
		SET @cond = @cond + ' AND AccessType='''+@AccessType+'''';
	END;

	IF @TarStatusId IS NOT NULL AND @TarStatusId != ''  AND @TarStatusId != '-1' 
	BEGIN 
		SET @cond = @cond + ' AND TarStatusId='''+CAST(@TarStatusId as nvarchar(10))+'''';
	END;

	IF NOT ISNULL(@AccessDateFrom, '') = '' AND NOT @AccessDateFrom = ''
	BEGIN			
		SET @cond = @cond + ' AND AccessDate >= convert(datetime,'''+@AccessDateFrom+''',103)';
	END;

	IF NOT ISNULL(@AccessDateTo, '') = '' AND NOT @AccessDateTo = ''
	BEGIN			
		SET @cond = @cond + ' AND AccessDate <= convert(datetime,'''+@AccessDateTo+''',103)';
	END;	

	 

	DECLARE @sql nvarchar(max);
	 
	SET @sql = 'SELECT ROW_NUMBER() OVER(ORDER BY t.company  ) AS sno,   t.company FROM ( '


	if @IsAll = 1 
	begin 
		SET @sql = @sql + 'SELECT distinct    t.company
				from TAMS_TAR t, TAMS_WFStatus s
				where t.TARStatusId = s.WFStatusId
				and t.Line = s.Line
				and t.TrackType = ''' +  @TrackType +'''
				and s.WFType = ''TARWFStatus''
				 ' + @cond
	end;
	else if @IsPower = 1 
	begin 
		SET @sql = @sql + 'SELECT distinct   t.company
				from TAMS_TAR t, TAMS_WFStatus s
				where t.TARStatusId = s.WFStatusId
				and t.Line = s.Line
				and s.WFType = ''TARWFStatus''
				and (t.InvolvePower = 1 OR t.createdby = ''' + CAST(@uid as nvarchar(10)) +''')
				and t.TrackType = ''' +  @TrackType +'''' + @cond 
	end; 
	else if @IsDep = 1 
	begin 
		SET @sql = @sql + 'SELECT distinct   t.company
				from TAMS_TAR t, TAMS_WFStatus s
				where t.TARStatusId = s.WFStatusId
				and t.Line = s.Line
				and s.WFType = ''TARWFStatus''
				and t.TrackType = ''' +  @TrackType +'''
				and ( t.company in (select Department FROM TAMS_User where UserID = ''' + CAST(@uid AS nvarchar(10)) + ''')
					  OR  t.createdby = ''' + CAST(@uid as nvarchar(10)) +''') ' + @cond
	end;
	else 
	begin 
		SET @sql = @sql + 'SELECT distinct   t.company
				from TAMS_TAR t, TAMS_WFStatus s
				where t.TARStatusId = s.WFStatusId
				and t.Line = s.Line
				and t.TrackType = ''' +  @TrackType +'''
				and s.WFType = ''TARWFStatus''
				and t.createdby = ''' + CAST(@uid as nvarchar(10)) +''''  + @cond 
				 
	end;
	---- applicant can view own created tar

	--- PFR, PowerHOD, power_endorser InvolvePower = 1 
	--- applicant hod role can view TAR under own department 
	--	TAP verifier/approver/HOD/scheduler/SDS/CC/TC can see all TAR under own Line 


	  

	SET @sql = @sql + ') as t';
	PRINT (@sql);

	EXEC (@sql);	

END


GO
/****** END PROCEDURE 167 ******/

/****** START PROCEDURE 168 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_GetTarEnquiryResult_Header
CREATE procedure  [dbo].[sp_TAMS_GetTarEnquiryResult_Header]
	@uid AS integer = 0,
	@Line AS nvarchar(50) = NULL,
	@TrackType AS nvarchar(50) = NULL,
	@TarType AS nvarchar(50) = NULL,
	@AccessType AS nvarchar(50) = NULL,
	@TarStatusId AS integer = 0,
	@AccessDateFrom as nvarchar(50) = NULL,
	@AccessDateTo as nvarchar(50) = NULL , 
	@Department as nvarchar(50) = NULL,
	@Userid as nvarchar(50)=NULL
 
AS
BEGIN
	DECLARE  @Dept as nvarchar(50),
			@StatusId as int
	declare @IsAll as int
	declare @IsPower as int
	declare @IsDep as int


	if ( ( Select count(*) 
	From TAMS_User u,TAMS_User_Role ur,TAMS_Role r
	Where u.Userid = ur.UserID and ur.RoleID= r.ID and r.TrackType = @TrackType
	and r.Role in ('NEL_OCCScheduler','DTL_OCCScheduler','NEL_TrafficController','DTL_TrafficController','NEL_DCC','NEL_ChiefController','NEL_SDS','NEL_TAPApprover','NEL_TAPHOD','NEL_TAPVerifier', 'DTL_TAPApprover','DTL_TAPHOD','DTL_TAPVerifier','DTL_ChiefController')
	and u.Userid = @uid
	) ) > 0 
	begin
		set @IsAll = 1 ;
	end;

	if ( ( Select count(*) 
	From TAMS_User u,TAMS_User_Role ur,TAMS_Role r
	Where u.Userid = ur.UserID and ur.RoleID= r.ID and r.TrackType = @TrackType
	and r.Role in ('NEL_PowerEndorser' ,'NEL_PowerHOD','NEL_PFR', 'DTL_PowerEndorser','DTL_PFR')
	and u.Userid = @uid
	) ) > 0 
	begin 
		set @IsPower = 1 
	end;

	if ( ( Select count(*) 
	From TAMS_User u,TAMS_User_Role ur,TAMS_Role r
	Where u.Userid = ur.UserID and ur.RoleID= r.ID and r.TrackType = @TrackType
	and r.Role in ('NEL_ApplicantHOD','NEL_Applicant','DTL_Applicant','DTL_ApplicantHOD')
	and u.Userid = @uid
	) ) > 0 
	begin 
		set @IsDep = 1 
	end;


	-- For external User
	if ( ( Select count(*) 
	From TAMS_User u,TAMS_User_Role ur,TAMS_Role r
	Where u.Userid = ur.UserID and ur.RoleID= r.ID and r.TrackType = @TrackType
	and u.IsExternal=1
	and u.Userid = @uid
	) ) > 0 
	begin 
		set @IsDep = 0
		set @IsPower = 0
		set @IsAll = 0
	end;

	PRINT @IsDep
	PRINT @IsPower
	PRINT @IsAll

	DECLARE @cond as varchar(max);

	SET @cond = '';

	 PRINT @Line

	IF @Line IS NOT NULL AND @Line != ''  AND @Line != '-1' 
	BEGIN 
		SET @cond = @cond + ' AND t.Line='''+@Line+'''';

	END;
	IF @TarType IS NOT NULL AND @TarType != ''  AND @TarType != '-1' 
	BEGIN 
		SET @cond  = @cond + ' AND t.TarType='''+@TarType+'''';
	END;

	IF @AccessType IS NOT NULL AND @AccessType != ''  AND @AccessType != '-1' 
	BEGIN 
		SET @cond = @cond + ' AND AccessType='''+@AccessType+'''';
	END;

	IF @TarStatusId IS NOT NULL AND @TarStatusId != ''  AND @TarStatusId != '-1' 
	BEGIN 
		SET @cond = @cond + ' AND TarStatusId='''+CAST(@TarStatusId as nvarchar(10))+'''';
	END;

	IF NOT ISNULL(@AccessDateFrom, '') = '' AND NOT @AccessDateFrom = ''
	BEGIN			
		SET @cond = @cond + ' AND AccessDate >= convert(datetime,'''+@AccessDateFrom+''',103)';
	END;

	IF NOT ISNULL(@AccessDateTo, '') = '' AND NOT @AccessDateTo = ''
	BEGIN			
		SET @cond = @cond + ' AND AccessDate <= convert(datetime,'''+@AccessDateTo+''',103)';
	END;	

	IF NOT ISNULL(@Department, '') = '' AND NOT @Department = ''
	BEGIN			
		SET @cond = @cond + ' AND Company = ''' + @Department + '''';
	END;

	IF NOT ISNULL(@Userid, '') = '' AND NOT @Userid = ''
	BEGIN			
		SET @cond = @cond + ' AND t.createdby = ''' + @Userid + '''';
	END;


	DECLARE @sql nvarchar(max);
	 
	SET @sql = 'SELECT ROW_NUMBER() OVER(ORDER BY t.tarno desc) AS sno, t.id, t.line, t.tarno, t.tartype, t.accesstype, t.accessdate,t.AccessTimeSlot, tarstatus, t.company,t.createdby,u.Name  FROM ( '


	if @IsAll = 1 
	begin 
		SET @sql = @sql + 'SELECT distinct t.id, t.line, t.tarno, t.tartype, t.accesstype, t.accessdate,t.AccessTimeSlot, s.wfstatus as tarstatus, t.company,t.createdby
				from TAMS_TAR t, TAMS_WFStatus s, TAMS_User u
				where t.TARStatusId = s.WFStatusId
				and t.Line = s.Line
				and t.TrackType = ''' +  @TrackType +''' and s.TrackType=t.TrackType
				and s.WFType = ''TARWFStatus''
				 ' + @cond
	end;
	else if @IsPower = 1 
	begin 
		SET @sql = @sql + 'SELECT distinct t.id, t.line, t.tarno, t.tartype, t.accesstype, t.accessdate,t.AccessTimeSlot, s.wfstatus as tarstatus, t.company,t.createdby
				from TAMS_TAR t, TAMS_WFStatus s
				where t.TARStatusId = s.WFStatusId
				and t.Line = s.Line
				and s.WFType = ''TARWFStatus''
				and (t.InvolvePower = 1 OR t.createdby = ''' + CAST(@uid as nvarchar(10)) +''')
				and s.TrackType=t.TrackType and t.TrackType = ''' +  @TrackType +'''' + @cond 
	end; 
	else if @IsDep = 1 
	begin 


		SET @sql = @sql + 'SELECT distinct t.id, t.line, t.tarno, t.tartype, t.accesstype, t.accessdate,t.AccessTimeSlot, s.wfstatus as tarstatus, t.company,t.createdby
				from TAMS_TAR t, TAMS_WFStatus s, TAMS_User u
				where t.TARStatusId = s.WFStatusId
				and t.Line = s.Line
				and s.WFType = ''TARWFStatus''
				and t.TrackType = ''' +  @TrackType +'''
				and s.TrackType=t.TrackType
				and ( t.company in (select Department FROM TAMS_User where UserID = ''' + CAST(@uid AS nvarchar(10)) + ''')
				  OR  t.createdby = ''' + CAST(@uid as nvarchar(10)) +''') ' + @cond
	end;
	else 
	begin 
		SET @sql = @sql + 'SELECT distinct t.id, t.line, t.tarno, t.tartype, t.accesstype, t.accessdate,t.AccessTimeSlot, s.wfstatus as tarstatus, t.company,t.createdby
				from TAMS_TAR t, TAMS_WFStatus s, TAMS_User u
				where t.TARStatusId = s.WFStatusId
				and t.Line = s.Line
				and t.TrackType = ''' +  @TrackType +'''
				and s.TrackType=t.TrackType
				and s.WFType = ''TARWFStatus''
				and t.createdby = ''' + CAST(@uid as nvarchar(10)) +''''  + @cond 
				 
	end;
	---- applicant can view own created tar

	--- PFR, PowerHOD, power_endorser InvolvePower = 1 
	--- applicant hod role can view TAR under own department 
	--	TAP verifier/approver/HOD/scheduler/SDS/CC/TC can see all TAR under own Line 


	  

	SET @sql = @sql + ') as t INNER JOIN TAMS_User U 
				ON u.Userid=t.CreatedBy';
	PRINT (@sql);

	EXEC (@sql);	

END
GO
