			ELSE IF ((@isDTL_Applicant = 0 OR @isDTL_Applicant = 1) AND (@isDTL_ApplicantHOD = 0 OR @isDTL_ApplicantHOD = 1) AND (@isDTL_PFR = 0 OR @isDTL_PFR = 1) AND (@isDTL_PowerEndorser = 0 OR @isDTL_PowerEndorser = 1) AND (@isDTL_TAPVerifier = 0 OR @isDTL_TAPVerifier = 1) AND (@isDTL_TAPApprover = 0 OR @isDTL_TAPApprover = 1) AND (@isDTL_TAPHOD = 0 OR @isDTL_TAPHOD = 1) AND (@isDTL_ChiefController = 0 OR @isDTL_ChiefController = 1) AND (@isDTL_TrafficController = 0 OR @isDTL_TrafficController = 1) AND (@isDTL_OCCScheduler = 0 OR @isDTL_OCCScheduler = 1) AND (@isDTL_TAR_SysAdmin = 0 OR @isDTL_TAR_SysAdmin = 1))
			BEGIN
				SET @sql = @sql + 'SELECT t.id, t.line, t.tarno, t.tartype, t.accesstype, t.accessdate, s.wfstatus as tarstatus, t.company
				from TAMS_TAR t, TAMS_WFStatus s
				where t.TARStatusId = s.WFStatusId
				and t.Line = s.Line
				and s.WFType = ''TARWFStatus''
				and t.Line = ''' + @Line1 +'''' + @cond
			END;
		END;
	END;

	----SELECT @sql

	--IF @Line1 <> '' AND	@Line2 <> ''
	--	BEGIN
	--		print 'dtl';
	--		SET @sql = @sql + ' union ';
	--	END;

	IF @Line2 <> ''
		BEGIN
			IF @Line2 = 'DTL'
			--select @StatusId = WFStatusId from TAMS_WFStatus where Line = @Line2 and WFType = 'TARWFStatus' and WFStatus = 'Cancel'
			BEGIN
				IF (@isDTL_Applicant = 1 AND @isDTL_ApplicantHOD = 0 AND @isDTL_PFR = 0 AND @isDTL_PowerEndorser = 0 AND @isDTL_TAPVerifier = 0 AND @isDTL_TAPApprover = 0 AND @isDTL_TAPHOD = 0 AND @isDTL_ChiefController = 0 AND @isDTL_TrafficController = 0 AND @isDTL_OCCScheduler = 0 AND @isDTL_TAR_SysAdmin = 0)
				BEGIN
					SET @sql = @sql + ' select t.id, t.line, t.tarno, t.tartype, t.accesstype, t.accessdate, s.wfstatus as tarstatus, t.company
					from TAMS_TAR t, TAMS_WFStatus s
					where t.TARStatusId = s.WFStatusId
					and t.Line = s.Line
					and s.WFType = ''TARWFStatus''
					and t.createdby = ''' + CAST(@uid as nvarchar(10)) +'''
					and t.Line = ''' + @Line2 +'''' + @cond

				END;
				ELSE IF (@isDTL_Applicant = 1 AND @isDTL_ApplicantHOD = 0 AND ((@isDTL_PowerEndorser = 1 OR @isDTL_PFR = 0) OR (@isDTL_PowerEndorser = 0 OR @isDTL_PFR = 1)) AND @isDTL_TAPVerifier = 0 AND @isDTL_TAPApprover = 0 AND @isDTL_TAPHOD = 0 AND @isDTL_ChiefController = 0 AND @isDTL_TrafficController = 0 AND @isDTL_OCCScheduler = 0 AND @isDTL_TAR_SysAdmin = 0)
				BEGIN
					SET @sql = @sql + 'SELECT t.id, t.line, t.tarno, t.tartype, t.accesstype, t.accessdate, s.wfstatus as tarstatus, t.company
					from TAMS_TAR t, TAMS_WFStatus s
