--	WHERE a.Line = @Line
--	AND Direction = @Direction
--	AND IsActive = 1 
--	AND EffectiveDate <= GETDATE() AND ExpiryDate >= GETDATE()
--	ORDER BY [Order] ASC
--END
--ELSE IF @Line = 'NEL'
--BEGIN
--	SELECT a.ID, a.Line, Direction, Sector, TarNo, AccessDate, AccessType, SectorId, IsBuffer, ColourCode
--	FROM TAMS_Sector a
--	LEFT JOIN TAMS_TAR_Sector_Test c
--	LEFT JOIN TAMS_TAR_Test b
--	on b.Id = c.TarId
--	on a.id = c.SectorId 
--	AND AccessDate = @AccessDate
--	AND TARStatusId = 8
--	AND (AccessType = 'Protection' OR (AccessType = 'Protection' OR isExclusive = 1))
--	WHERE a.Line = @Line
--	AND Direction = @Direction
--	AND IsActive = 1 
--	AND (ElectricalSector <> '')
--	AND EffectiveDate <= GETDATE() AND ExpiryDate >= GETDATE()
--	ORDER BY [Order] ASC
END

update #TMP
set ColourCode = (select ColourCode from #TMP where SameSector is not null and TarNo is not null and ColourCode is not null)
where SameSector is not null

SELECT * FROM #TMP;

--select ColourCode from #TMP where SameSector is not null and TarNo is not null and ColourCode is not null
DROP TABLE #TMP;
