	FROM #TmpSector a -- >>LEFT OUTER JOIN #TmpInboxList b ON a.SectorID = b.SectorID
		WHERE a.Direction = 2
	GROUP BY a.Line, a.SectorID, a.SectorStr, a.Direction, a.SectorOrder -- >>, b.TARID, b.TARNo, b.TARType, b.AccessDate, b.AccessType
	ORDER BY a.SectorOrder

-- >> Logic to check userid not yet inside

/*
	EXEC sp_TAMS_Inbox_OnLoad 'DTL', '', '', 'CSAPEX57'	
	EXEC sp_TAMS_Inbox_OnLoad 'NEL', '', '', 'CSAPEX57'	
*/

DROP TABLE #TmpSector
DROP TABLE #TmpInbox
DROP TABLE #TmpInboxList

END
