		SET @Body = ''
		SET @Body = @Body1 + @Body2 + @Body3

		SET @BCCList = ''

		EXEC [dbo].EAlertQ_EnQueue 
			@Sender = @Sender, 
			@UserId = @SysID, 
			@Subject = @Subject,        
			@Sys = @Sys,  
			@Greetings = @Greetings, 
			@AlertMsg = @Body, 
			@SendTo = @ToList,        
			@CC = @CCList, 
			@BCC= @BCCList, 
			@Separator = @Separator, 
			@AlertID =  @AlertID output
	

		COMMIT TRANSACTION;
	END TRY
	BEGIN CATCH
		ROLLBACK TRANSACTION;
	END CATCH

END;
GO
/****** END PROCEDURE 208 ******/

