RackedOutTime	DATETIME,
CreatedOn		DATETIME,
CreatedBy		INT,
UpdatedOn		DATETIME NULL,
UpdatedBy		INT NULL)

CREATE TABLE #TmpOCCAuthWorkflow 
(ID					INT,
OCCAuthId			INT,
