				--SELECT ID, Line, OperationDate, AccessDate, 
				--	TractionPowerId, Remark, PFRRemark, OCCAuthStatusId, 
				--	IsBuffer, PowerOn, PowerOffTime, RackedOutTime 
				--	FROM #TmpOCCAuth
				--		ORDER BY 1

				SELECT ID, TractionPowerId
					FROM #TmpOCCAuth
						ORDER BY 1
				OPEN @Cur01
				FETCH NEXT FROM @Cur01 INTO @C1ID, @C1TractionPowerId
				WHILE @@FETCH_STATUS = 0 
					BEGIN
						SET @TARSecRecCtr = 0

						SELECT @TARSecRecCtr = COUNT(*) 
							FROM #TmpTARSectors
								WHERE TractionPowerID = @C1TractionPowerId
									-- >> AND IsBuffer = 1

						IF @TARSecRecCtr > 0
							BEGIN
								SELECT TOP 1 @TARSectorIsBuffer = IsBuffer,
										@TARSectorPowerOn = PowerOn 
									FROM #TmpTARSectors
										WHERE TractionPowerID = @C1TractionPowerId
											-- >> AND IsBuffer = 1

								IF (@TARSectorIsBuffer = 1 AND @TARSectorPowerOn = 1)
									BEGIN
										UPDATE #TmpOCCAuth
											SET IsBuffer = 1,
												PowerOn = 1
										WHERE ID = @C1ID
											AND TractionPowerId = @C1TractionPowerId
									END
								ELSE IF (@TARSectorIsBuffer = 0 AND @TARSectorPowerOn = 1)
									BEGIN
										UPDATE #TmpOCCAuth
											SET IsBuffer = 0,
												PowerOn = 1
										WHERE ID = @C1ID
											AND TractionPowerId = @C1TractionPowerId
									END
								--ELSE IF (@TARSectorIsBuffer = 0 AND @TARSectorPowerOn = 1)
								--	BEGIN
								--		UPDATE #TmpOCCAuth
								--			SET IsBuffer = 0,
								--				PowerOn = 1
								--		WHERE ID = @C1ID
								--			AND TractionPowerId = @C1TractionPowerId
								--	END
								ELSE
									BEGIN
										UPDATE #TmpOCCAuth
											SET IsBuffer = 0,
												PowerOn = 0
										WHERE ID = @C1ID
											AND TractionPowerId = @C1TractionPowerId
									END
							END
						
						FETCH NEXT FROM @Cur01 INTO @C1ID, @C1TractionPowerId
					END 	
				CLOSE @Cur01
				DEALLOCATE @Cur01

				-- >>

				INSERT INTO [dbo].[TAMS_OCC_Auth]
				([Line], [OperationDate], [AccessDate], 
					[TractionPowerId], [Remark], [PFRRemark], [OCCAuthStatusId],
					[IsBuffer], [PowerOn], [PowerOffTime], [RackedOutTime],
					[CreatedOn], [CreatedBy], [UpdatedOn], [UpdatedBy])
				SELECT Line, OperationDate, AccessDate,
					TractionPowerId, Remark, PFRRemark, OCCAuthStatusId,
					IsBuffer, PowerOn, PowerOffTime, RackedOutTime,
					CreatedOn, CreatedBy, NULL, NULL 
					FROM #TmpOCCAuth
				ORDER BY ID

				-- >>
				
				SET @Row = 1

				SET @Cur02 = CURSOR FAST_FORWARD 
				FOR

				SELECT ID
					FROM TAMS_OCC_Auth
						WHERE Line = @Line
							AND AccessDate = @DerAccessDate
							AND OperationDate = @DerOPDate
						ORDER BY 1
				OPEN @Cur02
				FETCH NEXT FROM @Cur02 INTO @C2ID
				WHILE @@FETCH_STATUS = 0 
					BEGIN
						
						INSERT INTO #TmpOCCAuthWorkflow
							(ID, OCCAuthId, OCCAuthEndorserId, WFStatus, StationId, FISTestResult, ActionOn, ActionBy)
						VALUES
							(@Row, @C2ID, @EndorserID, 'Pending', 0, NULL, GETDATE(), 1)

						SET @Row = @Row + 1

						FETCH NEXT FROM @Cur02 INTO @C2ID
					END 	
				CLOSE @Cur02
				DEALLOCATE @Cur02

				-- >>

				INSERT INTO [dbo].[TAMS_OCC_Auth_Workflow]
					([OCCAuthId], [OCCAuthEndorserId], [WFStatus], [StationId], [FISTestResult], [ActionOn], [ActionBy])
				SELECT OCCAuthId, OCCAuthEndorserId, WFStatus, StationId, FISTestResult, ActionOn, ActionBy 
					FROM #TmpOCCAuthWorkflow
						ORDER BY ID

			END
	END

DROP TABLE #TmpOCCAuth
DROP TABLE #TmpTARSectors
DROP TABLE #TmpOCCAuthWorkflow

END
GO
/****** END PROCEDURE 218 ******/

/****** START PROCEDURE 219 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_OCC_Generate_Authorization_Trace
CREATE PROCEDURE [dbo].[sp_TAMS_OCC_Generate_Authorization_Trace]
	@Line	NVARCHAR(20) = NULL,
	@AccessDate	NVARCHAR(20) = NULL
AS

BEGIN

DECLARE @CurDate		DATE
DECLARE @CurTime		TIME
DECLARE @DerOPDate		DATE
DECLARE @DerAccessDate	DATE
DECLARE @CutOff			TIME

SET @CurDate = GETDATE()
SET @CurTime = CONVERT(TIME, GETDATE(), 108)
SET @CutOff = '06:00:00'

IF ISNULL(@AccessDate, '') = ''
	BEGIN
		IF @CurTime > @CutOff
			BEGIN
				SET @DerOPDate	= CONVERT(DATE, @CurDate, 103)
				SET @DerAccessDate	= DATEADD(DAY, 1, CONVERT(DATE, @CurDate, 103))
			END
		ELSE
			BEGIN
				SET @DerOPDate	= DATEADD(DAY, -1, CONVERT(DATE, @CurDate, 103))
				SET @DerAccessDate	= CONVERT(DATE, @CurDate, 103)
			END
		--SET @DerOPDate = CONVERT(DATE, @CurDate, 103)
		--SET @DerAccessDate = DATEADD(DAY, 1, CONVERT(DATE, @CurDate, 103))
	END
ELSE
	BEGIN
		SET @DerOPDate = DATEADD(DAY, -1, CONVERT(DATE, @AccessDate, 103))
		SET @DerAccessDate = CONVERT(DATE, @AccessDate, 103)
	END

DECLARE @OCCAuthCtr	INT = 0

SELECT @OCCAuthCtr = COUNT(*) 
	FROM [dbo].[TAMS_OCC_Auth] 
		WHERE [Line] = @Line 
			AND [AccessDate] = @DerAccessDate

DECLARE @WorkflowID	INT
DECLARE @WFStatusId INT
DECLARE @EndorserID	INT

SELECT @WorkflowID = ID
	FROM TAMS_Workflow
		WHERE Line = @Line
			AND WorkflowType = 'OCCAuth'
			AND GETDATE() BETWEEN EffectiveDate AND ExpiryDate
			AND IsActive = 1
		ORDER BY ID

SELECT @WFStatusId = WFStatusId,
		@EndorserID =  ID
	FROM TAMS_Endorser
		WHERE WorkflowId = @WorkflowID
			AND [Level] = 1
			AND GETDATE() BETWEEN EffectiveDate AND ExpiryDate
			AND IsActive = 1
		ORDER BY ID

CREATE TABLE #TmpTARSectors 
(ID				INT,
TARID			INT,
TractionPowerID	INT,
SectorID		INT,
IsBuffer		BIT,
ColourCode		NVARCHAR(100) NULL,
IsAddedBuffer	BIT,
PowerOn			BIT)

CREATE TABLE #TmpOCCAuth 
(ID				INT,
Line			NVARCHAR(10),
OperationDate	DATETIME,
AccessDate		DATETIME,
TractionPowerId	INT,
Remark			NVARCHAR(1000) NULL,
PFRRemark		NVARCHAR(1000) NULL,
OCCAuthStatusId	INT,
IsBuffer		BIT,
PowerOn			BIT,
PowerOffTime	DATETIME,
RackedOutTime	DATETIME,
CreatedOn		DATETIME,
CreatedBy		INT,
UpdatedOn		DATETIME NULL,
UpdatedBy		INT NULL)

CREATE TABLE #TmpOCCAuthWorkflow 
(ID					INT,
OCCAuthId			INT,
OCCAuthEndorserId	INT,
WFStatus			NVARCHAR(50),
StationId			INT,
FISTestResult		NVARCHAR(50) NULL,
ActionOn			DATETIME,
ActionBy			INT)

TRUNCATE TABLE #TmpTARSectors
TRUNCATE TABLE #TmpOCCAuth
TRUNCATE TABLE #TmpOCCAuthWorkflow

IF @Line = 'DTL'
	BEGIN
		INSERT INTO #TmpTARSectors
		SELECT s.id, tarid, d.tractionpowerid, s.sectorid, isbuffer, colourcode, isaddedbuffer, t.poweron
			FROM TAMS_TAR t, TAMS_TAR_Sector s, TAMS_Traction_Power_Detail d
				WHERE t.id = s.TARId
					AND s.sectorid = d.sectorid
					AND t.TARStatusId = 8
					AND t.Line = @Line
					AND t.AccessDate = CONVERT(DATETIME, @DerAccessDate, 103)
			ORDER by d.tractionpowerid ASC
	END;
ELSE IF @Line = 'NEL'
	BEGIN
		INSERT INTO #TmpTARSectors
		-- >> SELECT s.id, tarid, d.PowerSection AS tractionpowerid, s.powersectorid AS sectorid, isbuffer, '' AS colourcode, 0 AS isaddedbuffer, t.poweron
		SELECT s.id, tarid, d.ID AS tractionpowerid, s.powersectorid AS sectorid, isbuffer, '' AS colourcode, 0 AS isaddedbuffer, t.poweron
			FROM TAMS_TAR t, TAMS_TAR_Power_Sector s, TAMS_Power_Sector d
				WHERE t.id = s.TARId
					AND s.PowerSectorId = d.ID
					AND t.TARStatusId = 9
					AND t.Line = @Line
					AND t.AccessDate = CONVERT(DATETIME, @DerAccessDate, 103)
			ORDER by s.powersectorid ASC
	END;

DECLARE @TARSectorCtr	INT = 0
DECLARE @TARSecRecCtr	INT = 0

SELECT @TARSectorCtr = COUNT(*) FROM #TmpTARSectors

DECLARE @Cur01 CURSOR;
DECLARE @Cur02 CURSOR;

DECLARE @C1ID			INT,
	@C1TractionPowerId	INT,
	@C1OCCAuthStatusId	INT,
	@TARSectorIsBuffer	BIT,
	@TARSectorPowerOn	BIT,
	@C2ID				INT,
	@Row				INT = 0


/*
EXEC sp_TAMS_OCC_Generate_Authorization 'DTL', NULL
EXEC sp_TAMS_OCC_Generate_Authorization 'NEL', NULL
*/

IF @OCCAuthCtr > 0
	BEGIN
		IF @TARSectorCtr > 0
			BEGIN

				INSERT INTO #TmpOCCAuth
				SELECT [Order], [Line], @DerOPDate, @DerAccessDate, [ID], '', '', @WFStatusId, 0, 0, NULL, NULL, GETDATE(), 1, NULL, NULL
				FROM [dbo].[TAMS_Traction_Power]
					WHERE [Line] = @Line
						AND GETDATE() BETWEEN EffectiveDate AND ExpiryDate
						AND IsActive = 1
				ORDER BY [Order] ASC

				-- >> 

				SET @Cur01 = CURSOR FAST_FORWARD 
				FOR

				--SELECT ID, Line, OperationDate, AccessDate, 
				--	TractionPowerId, Remark, PFRRemark, OCCAuthStatusId, 
				--	IsBuffer, PowerOn, PowerOffTime, RackedOutTime 
				--	FROM #TmpOCCAuth
				--		ORDER BY 1

				SELECT ID, TractionPowerId
					FROM #TmpOCCAuth
						ORDER BY 1
				OPEN @Cur01
				FETCH NEXT FROM @Cur01 INTO @C1ID, @C1TractionPowerId
				WHILE @@FETCH_STATUS = 0 
					BEGIN
						SET @TARSecRecCtr = 0

						SELECT @TARSecRecCtr = COUNT(*) 
							FROM #TmpTARSectors
								WHERE TractionPowerID = @C1TractionPowerId
									-- >> AND IsBuffer = 1

						IF @TARSecRecCtr > 0
							BEGIN
								SELECT TOP 1 @TARSectorIsBuffer = IsBuffer,
										@TARSectorPowerOn = PowerOn 
									FROM #TmpTARSectors
										WHERE TractionPowerID = @C1TractionPowerId
											-- >> AND IsBuffer = 1

								IF (@TARSectorIsBuffer = 1 AND @TARSectorPowerOn = 1)
									BEGIN
										UPDATE #TmpOCCAuth
											SET IsBuffer = 1,
												PowerOn = 1
										WHERE ID = @C1ID
											AND TractionPowerId = @C1TractionPowerId
									END
								ELSE IF (@TARSectorIsBuffer = 0 AND @TARSectorPowerOn = 1)
									BEGIN
										UPDATE #TmpOCCAuth
											SET IsBuffer = 0,
												PowerOn = 1
										WHERE ID = @C1ID
											AND TractionPowerId = @C1TractionPowerId
									END
								--ELSE IF (@TARSectorIsBuffer = 0 AND @TARSectorPowerOn = 1)
								--	BEGIN
								--		UPDATE #TmpOCCAuth
								--			SET IsBuffer = 0,
								--				PowerOn = 1
								--		WHERE ID = @C1ID
								--			AND TractionPowerId = @C1TractionPowerId
								--	END
								ELSE
									BEGIN
										UPDATE #TmpOCCAuth
											SET IsBuffer = 0,
												PowerOn = 0
										WHERE ID = @C1ID
											AND TractionPowerId = @C1TractionPowerId
									END
							END
						
						FETCH NEXT FROM @Cur01 INTO @C1ID, @C1TractionPowerId
					END 	
				CLOSE @Cur01
				DEALLOCATE @Cur01

				-- >>

				----INSERT INTO [dbo].[TAMS_OCC_Auth]
				----([Line], [OperationDate], [AccessDate], 
				----	[TractionPowerId], [Remark], [PFRRemark], [OCCAuthStatusId],
				----	[IsBuffer], [PowerOn], [PowerOffTime], [RackedOutTime],
				----	[CreatedOn], [CreatedBy], [UpdatedOn], [UpdatedBy])
				SELECT Line, OperationDate, AccessDate,
					TractionPowerId, Remark, PFRRemark, OCCAuthStatusId,
					IsBuffer, PowerOn, PowerOffTime, RackedOutTime,
					CreatedOn, CreatedBy, NULL, NULL 
					FROM #TmpOCCAuth
				ORDER BY ID

				-- >>
				
				SET @Row = 1

				SET @Cur02 = CURSOR FAST_FORWARD 
				FOR

				SELECT ID
					FROM TAMS_OCC_Auth
						WHERE Line = @Line
							AND AccessDate = @DerAccessDate
							AND OperationDate = @DerOPDate
						ORDER BY 1
				OPEN @Cur02
				FETCH NEXT FROM @Cur02 INTO @C2ID
				WHILE @@FETCH_STATUS = 0 
					BEGIN
						
						INSERT INTO #TmpOCCAuthWorkflow
							(ID, OCCAuthId, OCCAuthEndorserId, WFStatus, StationId, FISTestResult, ActionOn, ActionBy)
						VALUES
							(@Row, @C2ID, @EndorserID, 'Pending', 0, NULL, GETDATE(), 1)

						SET @Row = @Row + 1

						FETCH NEXT FROM @Cur02 INTO @C2ID
					END 	
				CLOSE @Cur02
				DEALLOCATE @Cur02

				-- >>

				----INSERT INTO [dbo].[TAMS_OCC_Auth_Workflow]
				----	([OCCAuthId], [OCCAuthEndorserId], [WFStatus], [StationId], [FISTestResult], [ActionOn], [ActionBy])
				SELECT OCCAuthId, OCCAuthEndorserId, WFStatus, StationId, FISTestResult, ActionOn, ActionBy 
					FROM #TmpOCCAuthWorkflow
						ORDER BY ID

			END
	END

DROP TABLE #TmpOCCAuth
DROP TABLE #TmpTARSectors
DROP TABLE #TmpOCCAuthWorkflow

END
GO
/****** END PROCEDURE 219 ******/

/****** START PROCEDURE 220 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_OCC_GetEndorserByWorkflowId
CREATE PROCEDURE [dbo].[sp_TAMS_OCC_GetEndorserByWorkflowId]
	@ID AS INT = 0
AS
BEGIN

	SELECT ID, Line, WorkflowId, [Level], RoleId, Title, RequireValidation, RequireBuffer, RequireTVF, WFStatusId FROM TAMS_Endorser
	WHERE WorkflowId = @ID
	AND [Level] = 1
	AND EffectiveDate <= GETDATE()
	AND ExpiryDate >= GETDATE()
	AND IsActive = 1
	ORDER BY ID
END
GO
/****** END PROCEDURE 220 ******/

/****** START PROCEDURE 221 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_OCC_GetOCCAuthByLineAndAccessDate
CREATE PROCEDURE [dbo].[sp_TAMS_OCC_GetOCCAuthByLineAndAccessDate]
	@Line AS nvarchar(10) = NULL,
	@AccessDate as nvarchar(50) = NULL


AS
BEGIN
	SELECT [ID]
	,[Line]
	,[OperationDate]
	,[AccessDate]
	,[TractionPowerId]
	,[Remark]
	,[PFRRemark]
	,[OCCAuthStatusId]
	,[IsBuffer]
	,[PowerOn]
	,[PowerOffTime]
	,[RackedOutTime]
	FROM [dbo].[TAMS_OCC_Auth]
	WHERE [Line] = @Line
	AND [AccessDate] = convert(datetime,@AccessDate,103)
	ORDER BY [ID] ASC
END
GO
/****** END PROCEDURE 221 ******/

/****** START PROCEDURE 222 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_OCC_GetOCCAuthorisationByParameters_NEL
CREATE PROCEDURe  [dbo].[sp_TAMS_OCC_GetOCCAuthorisationByParameters_NEL]
	@UserID		as int,
	@Line AS nvarchar(10) = NULL,
	@TrackType AS nvarchar(50) = NULL,
	@OperationDate as date,
	@AccessDate as date,
	@RosterCode as nvarchar(50)

AS

DECLARE @WorkflowId as int,
		@OCCAuthID as int,
		@EndorserID as int,
		@EndorserLevel as int,
		@EndorserTitle as nvarchar(250),
		@WFStatus as nvarchar(50),
		@ActionOn as datetime

CREATE TABLE #TMP
(
	TractionPowerId int not null,	
	StationName nvarchar(50)
);

CREATE TABLE #TMP_Endorser
(
	ID int not null,	
	Line nvarchar(10),
	[Level] int,
	RoleId int,
	Title nvarchar(250)
);

CREATE TABLE #TMP_OCCAuthNEL
(
	SNO int not null,
	ID int not null,	
	OCCAuthID int not null,
	Remark nvarchar(1000),
	--PFRRemark nvarchar(1000),
	IsBuffer bit,
	PowerOn bit,
	Line nvarchar(10),
	TractionPowerSection nvarchar(100),
	HSCBName nvarchar(100),
	--StationName nvarchar(50),
	--TC nvarchar(10),
	Train nvarchar(50),
	TrainClearCert_TC nvarchar(8),
	TrainClearCert_CC nvarchar(8),
	MainlineTractionCurrentSwitchOff_Request_CC nvarchar(50),
	MainlineTractionCurrentSwitchOff_TractionCurrentOff_PFR nvarchar(50),
	MainlineTractionCurrentSwitchOff_TractionCurrentOff_RackOut_PFR nvarchar(50),
	AuthForTrackAccess_CC nvarchar(8),
	AuthForTrackAccess_TC nvarchar(8),
	LineClearCertTOA_TC nvarchar(8),
	LineClearCertSCD_TC nvarchar(8),
	LineClearCert_CC nvarchar(8),
	MainlineTractionCurrentSwitchOn_Request_CC nvarchar(50),
	MainlineTractionCurrentSwitchOn_TractionCurrentOn_PFR nvarchar(50),
	MainlineTractionCurrentSwitchOn_TractionCurrentOn_RackIn_PFR nvarchar(50),
	AuthForTrainInsert_CC nvarchar(8),
	AuthForTrainInsert_TC nvarchar(8),
	Remarks nvarchar(1000)

);

BEGIN

	SELECT @WorkflowId = ID FROM [TAMS_Workflow]
						WHERE Line = @Line
						and TrackType = @TrackType
						AND  WorkflowType = 'OCCAuth'
						AND IsActive = 1
						AND EffectiveDate <= GETDATE()
						AND ExpiryDate >= GETDATE()

	INSERT INTO #TMP_Endorser(ID, Line, [Level], RoleId, Title)
	SELECT ID, Line, [Level], RoleId, Title FROM [TAMS_Endorser]
	WHERE Line = 'NEL'
	AND WorkflowId = @WorkflowId
	ORDER BY Level ASC
	--AND RoleId = 13
	--AND Level in (1,9,10,11,20)

	INSERT INTO #TMP_OCCAuthNEL(
	SNO, 
	ID, 
	OCCAuthID,
	Remark,
	--PFRRemark,
	IsBuffer,
	PowerOn,
	Line, 
	TractionPowerSection,  
	HSCBName,
	--StationName,
	--TC,
	Train,
	TrainClearCert_TC,
	TrainClearCert_CC,
	MainlineTractionCurrentSwitchOff_Request_CC,
	MainlineTractionCurrentSwitchOff_TractionCurrentOff_PFR,
	MainlineTractionCurrentSwitchOff_TractionCurrentOff_RackOut_PFR,
	AuthForTrackAccess_CC,
	AuthForTrackAccess_TC,
	LineClearCertTOA_TC,
	LineClearCertSCD_TC,
	LineClearCert_CC,
	MainlineTractionCurrentSwitchOn_Request_CC,
	MainlineTractionCurrentSwitchOn_TractionCurrentOn_PFR,
	MainlineTractionCurrentSwitchOn_TractionCurrentOn_RackIn_PFR,
	AuthForTrainInsert_CC,
	AuthForTrainInsert_TC,
	Remarks)
	SELECT ROW_NUMBER() OVER(ORDER BY tp.ID ASC) AS SNO
		  ,tp.[ID]
		  ,oa.[ID]
		  ,oa.[Remark]
		  --,oa.[PFRRemark]
		  ,oa.[IsBuffer]
		  ,oa.[PowerOn]
		  ,tp.[Line]
		  ,[TractionPowerSection]
		  ,[HSCBName]
		  --,[StationName]
		  --,[TC]
		  ,[Train]
		  ,'' AS TrainClearCert_TC
		  ,'' AS TrainClearCert_CC
		  ,'' AS MainlineTractionCurrentSwitchOff_Request_CC
		  ,'' AS MainlineTractionCurrentSwitchOff_TractionCurrentOff_PFR
		  ,'' AS MainlineTractionCurrentSwitchOff_TractionCurrentOff_RackOut_PFR
		  ,'' AS AuthForTrackAccess_CC
		  ,'' AS AuthForTrackAccess_TC
		  ,'' AS LineClearCertTOA_TC
		  ,'' AS LineClearCertSCD_TC
		  ,'' AS LineClearCert_CC
		  ,'' AS MainlineTractionCurrentSwitchOn_Request_CC
		  ,'' AS MainlineTractionCurrentSwitchOn_TractionCurrentOn_PFR
		  ,'' AS MainlineTractionCurrentSwitchOn_TractionCurrentOn_RackIn_PFR
		  ,'' AS AuthForTrainInsert_CC
		  ,'' AS AuthForTrainInsert_TC
		  ,'' AS Remarks
	  FROM [TAMS_Traction_Power] tp, [TAMS_OCC_Auth] oa
	  WHERE tp.ID = oa.TractionPowerId
	  AND EffectiveDate <= GETDATE() and ExpiryDate >= GETDATE()
	  AND IsActive = 1
	  AND oa.OperationDate = @OperationDate
	  AND oa.AccessDate = @AccessDate
	  AND oa.Line = @Line
	  and oa.TrackType = @TrackType
	  --AND TC in 
	  --(SELECT RosterCode FROM TAMS_OCC_Duty_Roster 
	  -- WHERE OperationDate = CAST(@OperationDate as DATE)
	  -- and [shift] = 3
	  -- and [IsActive] = 1
	  -- and [DutyStaffId] = @UserID
	  -- )


	DECLARE cur CURSOR FOR
	SELECT OCCAuthID FROM #TMP_OCCAuthNEL


	OPEN cur;

	FETCH NEXT FROM cur INTO @OCCAuthID
	WHILE @@FETCH_STATUS = 0
	BEGIN

		DECLARE cur1 CURSOR FOR
		SELECT ID, [Level], Title FROM #TMP_Endorser

		OPEN Cur1;

		FETCH NEXT FROM Cur1 INTO @EndorserID, @EndorserLevel, @EndorserTitle;
		WHILE @@FETCH_STATUS = 0
		BEGIN
			IF @EndorserID = 117	--1
			BEGIN
				SELECT @WFStatus = WFStatus, @ActionOn = ActionOn 
				FROM [TAMS_OCC_Auth_Workflow] 
				WHERE OCCAuthId = @OCCAuthID AND OCCAuthEndorserId = 117;
				IF @WFStatus = 'Pending' AND @RosterCode = 'TC'
				BEGIN
					UPDATE #TMP_OCCAuthNEL
					SET TrainClearCert_TC = @WFStatus
					WHERE OCCAuthID = @OCCAuthID
				END;
				ELSE IF @WFStatus = 'Pending' AND @RosterCode != 'TC'
				BEGIN
					UPDATE #TMP_OCCAuthNEL
					SET TrainClearCert_TC = ''
					WHERE OCCAuthID = @OCCAuthID
				END;
				ELSE IF @WFStatus = 'Completed'
				BEGIN
					UPDATE #TMP_OCCAuthNEL
					SET TrainClearCert_TC = CONVERT(TIME, @ActionOn)
					WHERE OCCAuthID = @OCCAuthID
				END;

				SET @WFStatus = '';
				SET @ActionOn = '';
			END;

			IF @EndorserID = 118	--2
			BEGIN
				SELECT @WFStatus = WFStatus, @ActionOn = ActionOn 
				FROM [TAMS_OCC_Auth_Workflow] 
				WHERE OCCAuthId = @OCCAuthID AND OCCAuthEndorserId = 118;
				IF @WFStatus = 'Pending' AND @RosterCode = 'CC'
				BEGIN
					UPDATE #TMP_OCCAuthNEL
					SET TrainClearCert_CC = @WFStatus
					WHERE OCCAuthID = @OCCAuthID
				END;
				ELSE IF @WFStatus = 'Pending' AND @RosterCode != 'CC'
				BEGIN
					UPDATE #TMP_OCCAuthNEL
					SET TrainClearCert_CC = ''
					WHERE OCCAuthID = @OCCAuthID
				END;
				ELSE IF @WFStatus = 'Completed'
				BEGIN
					UPDATE #TMP_OCCAuthNEL
					SET TrainClearCert_CC = CONVERT(TIME, @ActionOn)
					WHERE OCCAuthID = @OCCAuthID
				END;
				SET @WFStatus = '';
				SET @ActionOn = '';
			END;

			IF @EndorserID = 119	--3
			BEGIN
				SELECT @WFStatus = WFStatus, @ActionOn = ActionOn 
				FROM [TAMS_OCC_Auth_Workflow] 
				WHERE OCCAuthId = @OCCAuthID AND OCCAuthEndorserId = 119;
				IF @WFStatus = 'Pending' AND @RosterCode = 'CC'
				BEGIN
					UPDATE #TMP_OCCAuthNEL
					SET MainlineTractionCurrentSwitchOff_Request_CC = @WFStatus
					WHERE OCCAuthID = @OCCAuthID
				END;
				ELSE IF (@WFStatus = 'Completed' OR @WFStatus = 'N.A.')  
					BEGIN
						IF @WFStatus = 'Completed'
							BEGIN
								UPDATE #TMP_OCCAuthNEL
								SET MainlineTractionCurrentSwitchOff_Request_CC = convert(varchar,  @ActionOn,108)
								WHERE OCCAuthID = @OCCAuthID
							END;
						ELSE IF @WFStatus = 'N.A.'
							BEGIN
								UPDATE #TMP_OCCAuthNEL
								SET MainlineTractionCurrentSwitchOff_Request_CC = 'N.A. (' +  convert(varchar,  @ActionOn,108) + ')'
								WHERE OCCAuthID = @OCCAuthID
							END;
					END;
				ELSE IF @WFStatus = 'Pending' AND @RosterCode != 'CC'
				BEGIN
					UPDATE #TMP_OCCAuthNEL
					SET MainlineTractionCurrentSwitchOff_Request_CC = ''
					WHERE OCCAuthID = @OCCAuthID
				END;
				 
				SET @WFStatus = '';
				SET @ActionOn = '';
