-- PROCEDURE NAME: dbo.sp_TAMS_OCC_GetOCCAuthorisationByParameters_NEL_bak20230727
CREATE PROCEDURE  [dbo].[sp_TAMS_OCC_GetOCCAuthorisationByParameters_NEL_bak20230727]
	@UserID		as int,
	@Line AS nvarchar(10) = NULL,
	@TrackType AS nvarchar(50) = NULL,
	@OperationDate as date,
	@AccessDate as date,
	@RosterCode as nvarchar(50)

AS

DECLARE @WorkflowId as int,
		@OCCAuthID as int,
		@EndorserID as int,
		@EndorserLevel as int,
		@EndorserTitle as nvarchar(250),
		@WFStatus as nvarchar(50),
		@ActionOn as datetime

CREATE TABLE #TMP
(
	TractionPowerId int not null,	
	StationName nvarchar(50)
);

CREATE TABLE #TMP_Endorser
(
	ID int not null,	
	Line nvarchar(10),
	[Level] int,
	RoleId int,
	Title nvarchar(250)
);

CREATE TABLE #TMP_OCCAuthNEL
(
	SNO int not null,
	ID int not null,	
	OCCAuthID int not null,
	Remark nvarchar(1000),
	--PFRRemark nvarchar(1000),
	IsBuffer bit,
	PowerOn bit,
	Line nvarchar(10),
	TractionPowerSection nvarchar(100),
	HSCBName nvarchar(100),
	--StationName nvarchar(50),
	--TC nvarchar(10),
	Train nvarchar(50),
	TrainClearCert_TC nvarchar(8),
	TrainClearCert_CC nvarchar(8),
	MainlineTractionCurrentSwitchOff_Request_CC nvarchar(8),
	MainlineTractionCurrentSwitchOff_TractionCurrentOff_PFR nvarchar(8),
	MainlineTractionCurrentSwitchOff_TractionCurrentOff_RackOut_PFR nvarchar(8),
	AuthForTrackAccess_CC nvarchar(8),
	AuthForTrackAccess_TC nvarchar(8),
	LineClearCertTOA_TC nvarchar(8),
	LineClearCertSCD_TC nvarchar(8),
	LineClearCert_CC nvarchar(8),
	MainlineTractionCurrentSwitchOn_Request_CC nvarchar(8),
	MainlineTractionCurrentSwitchOn_TractionCurrentOn_PFR nvarchar(8),
	MainlineTractionCurrentSwitchOn_TractionCurrentOn_RackIn_PFR nvarchar(8),
	AuthForTrainInsert_CC nvarchar(8),
	AuthForTrainInsert_TC nvarchar(8),
	Remarks nvarchar(1000)

);

BEGIN

	SELECT @WorkflowId = ID FROM [TAMS_Workflow]
						WHERE Line = @Line
						and TrackType = @TrackType
						AND  WorkflowType = 'OCCAuth'
						AND IsActive = 1
						AND EffectiveDate <= GETDATE()
						AND ExpiryDate >= GETDATE()

	INSERT INTO #TMP_Endorser(ID, Line, [Level], RoleId, Title)
	SELECT ID, Line, [Level], RoleId, Title FROM [TAMS_Endorser]
	WHERE Line = 'NEL'
	AND WorkflowId = @WorkflowId
	ORDER BY Level ASC
	--AND RoleId = 13
	--AND Level in (1,9,10,11,20)

	INSERT INTO #TMP_OCCAuthNEL(
	SNO, 
	ID, 
	OCCAuthID,
	Remark,
	--PFRRemark,
	IsBuffer,
	PowerOn,
	Line, 
	TractionPowerSection,  
	HSCBName,
	--StationName,
	--TC,
	Train,
	TrainClearCert_TC,
	TrainClearCert_CC,
	MainlineTractionCurrentSwitchOff_Request_CC,
	MainlineTractionCurrentSwitchOff_TractionCurrentOff_PFR,
	MainlineTractionCurrentSwitchOff_TractionCurrentOff_RackOut_PFR,
	AuthForTrackAccess_CC,
	AuthForTrackAccess_TC,
	LineClearCertTOA_TC,
	LineClearCertSCD_TC,
	LineClearCert_CC,
	MainlineTractionCurrentSwitchOn_Request_CC,
	MainlineTractionCurrentSwitchOn_TractionCurrentOn_PFR,
	MainlineTractionCurrentSwitchOn_TractionCurrentOn_RackIn_PFR,
	AuthForTrainInsert_CC,
	AuthForTrainInsert_TC,
	Remarks)
	SELECT ROW_NUMBER() OVER(ORDER BY tp.ID ASC) AS SNO
		  ,tp.[ID]
		  ,oa.[ID]
		  ,oa.[Remark]
		  --,oa.[PFRRemark]
		  ,oa.[IsBuffer]
		  ,oa.[PowerOn]
		  ,tp.[Line]
		  ,[TractionPowerSection]
		  ,[HSCBName]
		  --,[StationName]
		  --,[TC]
		  ,[Train]
		  ,'' AS TrainClearCert_TC
		  ,'' AS TrainClearCert_CC
		  ,'' AS MainlineTractionCurrentSwitchOff_Request_CC
		  ,'' AS MainlineTractionCurrentSwitchOff_TractionCurrentOff_PFR
		  ,'' AS MainlineTractionCurrentSwitchOff_TractionCurrentOff_RackOut_PFR
		  ,'' AS AuthForTrackAccess_CC
		  ,'' AS AuthForTrackAccess_TC
		  ,'' AS LineClearCertTOA_TC
		  ,'' AS LineClearCertSCD_TC
		  ,'' AS LineClearCert_CC
		  ,'' AS MainlineTractionCurrentSwitchOn_Request_CC
		  ,'' AS MainlineTractionCurrentSwitchOn_TractionCurrentOn_PFR
		  ,'' AS MainlineTractionCurrentSwitchOn_TractionCurrentOn_RackIn_PFR
		  ,'' AS AuthForTrainInsert_CC
		  ,'' AS AuthForTrainInsert_TC
		  ,'' AS Remarks
	  FROM [TAMS_Traction_Power] tp, [TAMS_OCC_Auth] oa
	  WHERE tp.ID = oa.TractionPowerId
	  AND EffectiveDate <= GETDATE() and ExpiryDate >= GETDATE()
	  AND IsActive = 1
	  AND oa.OperationDate = @OperationDate
	  AND oa.AccessDate = @AccessDate
	  AND oa.Line = @Line
	  and oa.TrackType = @TrackType
	  --AND TC in 
	  --(SELECT RosterCode FROM TAMS_OCC_Duty_Roster 
	  -- WHERE OperationDate = CAST(@OperationDate as DATE)
	  -- and [shift] = 3
	  -- and [IsActive] = 1
	  -- and [DutyStaffId] = @UserID
	  -- )


	DECLARE cur CURSOR FOR
	SELECT OCCAuthID FROM #TMP_OCCAuthNEL


	OPEN cur;

	FETCH NEXT FROM cur INTO @OCCAuthID
	WHILE @@FETCH_STATUS = 0
	BEGIN

		DECLARE cur1 CURSOR FOR
		SELECT ID, [Level], Title FROM #TMP_Endorser

		OPEN Cur1;

		FETCH NEXT FROM Cur1 INTO @EndorserID, @EndorserLevel, @EndorserTitle;
		WHILE @@FETCH_STATUS = 0
		BEGIN
			IF @EndorserID = 117	--1
			BEGIN
				SELECT @WFStatus = WFStatus, @ActionOn = ActionOn 
				FROM [TAMS_OCC_Auth_Workflow] 
				WHERE OCCAuthId = @OCCAuthID AND OCCAuthEndorserId = 117;
				IF @WFStatus = 'Pending' AND @RosterCode = 'TC'
				BEGIN
					UPDATE #TMP_OCCAuthNEL
					SET TrainClearCert_TC = @WFStatus
					WHERE OCCAuthID = @OCCAuthID
				END;
				ELSE IF @WFStatus = 'Pending' AND @RosterCode != 'TC'
				BEGIN
					UPDATE #TMP_OCCAuthNEL
					SET TrainClearCert_TC = ''
					WHERE OCCAuthID = @OCCAuthID
				END;
				ELSE IF @WFStatus = 'Completed'
				BEGIN
					UPDATE #TMP_OCCAuthNEL
					SET TrainClearCert_TC = CONVERT(TIME, @ActionOn)
					WHERE OCCAuthID = @OCCAuthID
				END;

				SET @WFStatus = '';
				SET @ActionOn = '';
			END;

			IF @EndorserID = 118	--2
			BEGIN
				SELECT @WFStatus = WFStatus, @ActionOn = ActionOn 
				FROM [TAMS_OCC_Auth_Workflow] 
				WHERE OCCAuthId = @OCCAuthID AND OCCAuthEndorserId = 118;
				IF @WFStatus = 'Pending' AND @RosterCode = 'CC'
				BEGIN
					UPDATE #TMP_OCCAuthNEL
					SET TrainClearCert_CC = @WFStatus
					WHERE OCCAuthID = @OCCAuthID
				END;
				ELSE IF @WFStatus = 'Pending' AND @RosterCode != 'CC'
				BEGIN
					UPDATE #TMP_OCCAuthNEL
					SET TrainClearCert_CC = ''
					WHERE OCCAuthID = @OCCAuthID
				END;
				ELSE IF @WFStatus = 'Completed'
				BEGIN
					UPDATE #TMP_OCCAuthNEL
					SET TrainClearCert_CC = CONVERT(TIME, @ActionOn)
					WHERE OCCAuthID = @OCCAuthID
				END;
				SET @WFStatus = '';
				SET @ActionOn = '';
			END;

			IF @EndorserID = 119	--3
			BEGIN
				SELECT @WFStatus = WFStatus, @ActionOn = ActionOn 
				FROM [TAMS_OCC_Auth_Workflow] 
				WHERE OCCAuthId = @OCCAuthID AND OCCAuthEndorserId = 119;
				IF @WFStatus = 'Pending' AND @RosterCode = 'CC'
				BEGIN
					UPDATE #TMP_OCCAuthNEL
					SET MainlineTractionCurrentSwitchOff_Request_CC = @WFStatus
					WHERE OCCAuthID = @OCCAuthID
				END;
				ELSE IF @WFStatus = 'Pending' AND @RosterCode != 'CC'
				BEGIN
					UPDATE #TMP_OCCAuthNEL
					SET MainlineTractionCurrentSwitchOff_Request_CC = ''
