					UPDATE #TMP_OCCAuthTC
					SET LineClearCertSCD = CONVERT(TIME, @ActionOn)
					WHERE OCCAuthID = @OCCAuthID
				END;
				SET @WFStatus = '';
				SET @ActionOn = '';
			END;

			IF @EndorserID = 116
			BEGIN
				SELECT @WFStatus = WFStatus, @ActionOn = ActionOn 
				FROM [TAMS_OCC_Auth_Workflow] 
				WHERE OCCAuthId = @OCCAuthID AND OCCAuthEndorserId = 116;
				IF @WFStatus = 'Pending'
				BEGIN
					UPDATE #TMP_OCCAuthTC
					SET AuthForTrainInsert = @WFStatus
					WHERE OCCAuthID = @OCCAuthID
				END;
				IF @WFStatus = 'Completed'
				BEGIN
					UPDATE #TMP_OCCAuthTC
					SET AuthForTrainInsert = CONVERT(TIME, @ActionOn)
					WHERE OCCAuthID = @OCCAuthID
				END;
				SET @WFStatus = '';
				SET @ActionOn = '';
			END;

			FETCH NEXT FROM Cur1 INTO @EndorserID, @EndorserLevel, @EndorserTitle;
		END

		CLOSE Cur1;
		DEALLOCATE Cur1;

		FETCH NEXT FROM cur INTO @OCCAuthID;

	END;

	CLOSE cur;
	DEALLOCATE cur;


	SELECT * FROM #TMP_OCCAuthTC;
	--SELECT * FROM #TMP;

END

DROP TABLE #TMP;

DROP TABLE #TMP_Endorser;

DROP TABLE #TMP_OCCAuthTC;
GO
/****** END PROCEDURE 229 ******/

/****** START PROCEDURE 230 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_OCC_GetOCCAuthorisationTCByParameters_20230216_M
CREATE PROCEDURE [dbo].[sp_TAMS_OCC_GetOCCAuthorisationTCByParameters_20230216_M]
	@UserID		as int,
	@Line AS nvarchar(10) = NULL,
	@OperationDate as date,
	@AccessDate as date

AS

DECLARE @WorkflowId as int,
		@OCCAuthID as int,
		@EndorserID as int,
		@EndorserLevel as int,
		@EndorserTitle as nvarchar(250),
		@WFStatus as nvarchar(50),
		@ActionOn as datetime

CREATE TABLE #TMP
(
	TractionPowerId int not null,	
	StationName nvarchar(50)
);

CREATE TABLE #TMP_Endorser
(
	ID int not null,	
	Line nvarchar(10),
	[Level] int,
	RoleId int,
	Title nvarchar(250)
);

CREATE TABLE #TMP_OCCAuthTC
(
	SNO int not null,
	ID int not null,	
	OCCAuthID int not null,
	Remark nvarchar(1000),
	PFRRemark nvarchar(1000),
	IsBuffer bit,
	PowerOn bit,
	Line nvarchar(10),
	TractionPowerSection nvarchar(100),
	HSCBName nvarchar(100),
	StationName nvarchar(50),
	TC nvarchar(10),
	Train nvarchar(50),
	TrainClearCert nvarchar(8),
	AuthForTrackAccess nvarchar(8),
	LineClearCertTOA nvarchar(8),
	LineClearCertSCD nvarchar(8),
	AuthForTrainInsert nvarchar(8)
);

IF @Line = 'DTL'
BEGIN

	SELECT @WorkflowId = ID FROM [TAMS_Workflow]
						WHERE Line = @Line
						AND  WorkflowType = 'OCCAuth'
						AND IsActive = 1
						AND EffectiveDate <= GETDATE()
						AND ExpiryDate >= GETDATE()

	INSERT INTO #TMP_Endorser(ID, Line, [Level], RoleId, Title)
	SELECT ID, Line, [Level], RoleId, Title FROM [TAMS_Endorser]
	WHERE Line = 'DTL'
	AND WorkflowId = @WorkflowId
	AND RoleId = 13
	--AND Level in (1,9,10,11,20)

	INSERT INTO #TMP(TractionPowerId, StationName)
	SELECT 
	   Id,
	   STUFF((SELECT ';' + S.StationName
			  FROM [TAMS_Traction_Power_Detail] TPD, [TAMS_Station] S
			  WHERE TPD.TractionPowerId = TP.ID
			  AND TPD.StationId = S.ID
			  AND  TPD.TractionPowerType = 'Station'
			  FOR XML PATH('')), 1, 1, '') [StationName]
	FROM [TAMS_Traction_Power] TP
	WHERE TP.Line = 'DTL'
	GROUP BY TP.ID

	INSERT INTO #TMP_OCCAuthTC(
	SNO, 
	ID, 
	OCCAuthID,
	Remark,
	PFRRemark,
	IsBuffer,
	PowerOn,
	Line, 
	TractionPowerSection,  
	HSCBName,
	StationName,
	TC,
	Train,
	TrainClearCert,
	AuthForTrackAccess,
	LineClearCertTOA,
	LineClearCertSCD,
	AuthForTrainInsert)
	SELECT ROW_NUMBER() OVER(ORDER BY tp.ID ASC) AS SNO
		  ,tp.[ID]
		  ,oa.[ID]
		  ,oa.[Remark]
		  ,oa.[PFRRemark]
		  ,oa.[IsBuffer]
		  ,oa.[PowerOn]
		  ,tp.[Line]
		  ,[TractionPowerSection]
		  ,[HSCBName]
		  ,[StationName]
		  ,[TC]
		  ,[Train]
		  ,'' AS TrainClearCert
		  ,'' AS AuthForTrackAccess
		  ,'' AS LineClearCertTOA
		  ,'' AS LineClearCertSCD
		  ,'' AS AuthForTrainInsert
	  FROM [TAMS_Traction_Power] tp, #TMP tmp, [TAMS_OCC_Auth] oa
	  WHERE tp.ID = tmp.TractionPowerId
	  AND tmp.TractionPowerId = oa.TractionPowerId
	  AND EffectiveDate <= GETDATE() and ExpiryDate >= GETDATE()
	  AND IsActive = 1
	  AND oa.OperationDate = @OperationDate
	  AND oa.AccessDate = @AccessDate
	  AND TC in 
	  (SELECT RosterCode FROM TAMS_OCC_Duty_Roster 
	   WHERE OperationDate = CAST(@OperationDate as DATE)
	   and [shift] = 3
	   and [IsActive] = 1
	   and [DutyStaffId] = @UserID
	   )


	DECLARE cur CURSOR FOR
	SELECT OCCAuthID FROM #TMP_OCCAuthTC


	OPEN cur;

	FETCH NEXT FROM cur INTO @OCCAuthID
	WHILE @@FETCH_STATUS = 0
	BEGIN

		DECLARE cur1 CURSOR FOR
		SELECT ID, [Level], Title FROM #TMP_Endorser

		OPEN Cur1;

		FETCH NEXT FROM Cur1 INTO @EndorserID, @EndorserLevel, @EndorserTitle;
		WHILE @@FETCH_STATUS = 0
		BEGIN
			IF @EndorserID = 97
			BEGIN
				SELECT @WFStatus = WFStatus, @ActionOn = ActionOn 
				FROM [TAMS_OCC_Auth_Workflow] 
				WHERE OCCAuthId = @OCCAuthID AND OCCAuthEndorserId = 97;
				IF @WFStatus = 'Pending'
				BEGIN
					UPDATE #TMP_OCCAuthTC
					SET TrainClearCert = @WFStatus
					WHERE OCCAuthID = @OCCAuthID
				END;
				IF @WFStatus = 'Completed'
				BEGIN
					UPDATE #TMP_OCCAuthTC
					SET TrainClearCert = CONVERT(TIME, @ActionOn)
					WHERE OCCAuthID = @OCCAuthID
				END;

				SET @WFStatus = '';
				SET @ActionOn = '';
			END;

			IF @EndorserID = 105
			BEGIN
				SELECT @WFStatus = WFStatus, @ActionOn = ActionOn 
				FROM [TAMS_OCC_Auth_Workflow] 
				WHERE OCCAuthId = @OCCAuthID AND OCCAuthEndorserId = 105;
				IF @WFStatus = 'Pending'
				BEGIN
					UPDATE #TMP_OCCAuthTC
					SET AuthForTrackAccess = @WFStatus
					WHERE OCCAuthID = @OCCAuthID
				END;
				IF @WFStatus = 'Completed'
				BEGIN
					UPDATE #TMP_OCCAuthTC
					SET AuthForTrackAccess = CONVERT(TIME, @ActionOn)
					WHERE OCCAuthID = @OCCAuthID
				END;
				SET @WFStatus = '';
				SET @ActionOn = '';
			END;
			IF @EndorserID = 106
			BEGIN
				SELECT @WFStatus = WFStatus, @ActionOn = ActionOn 
				FROM [TAMS_OCC_Auth_Workflow] 
				WHERE OCCAuthId = @OCCAuthID AND OCCAuthEndorserId = 106;
				IF @WFStatus = 'Pending'
				BEGIN
					UPDATE #TMP_OCCAuthTC
					SET LineClearCertTOA = @WFStatus
					WHERE OCCAuthID = @OCCAuthID
				END;
				IF @WFStatus = 'Completed'
				BEGIN
					UPDATE #TMP_OCCAuthTC
					SET LineClearCertTOA = CONVERT(TIME, @ActionOn)
					WHERE OCCAuthID = @OCCAuthID
				END;
				SET @WFStatus = '';
				SET @ActionOn = '';
			END;

			IF @EndorserID = 107
			BEGIN
				SELECT @WFStatus = WFStatus, @ActionOn = ActionOn 
				FROM [TAMS_OCC_Auth_Workflow] 
				WHERE OCCAuthId = @OCCAuthID AND OCCAuthEndorserId = 107;
				IF @WFStatus = 'Pending'
				BEGIN
					UPDATE #TMP_OCCAuthTC
					SET LineClearCertSCD = @WFStatus
					WHERE OCCAuthID = @OCCAuthID
				END;
				IF @WFStatus = 'Remove' OR @WFStatus = 'N.A.'
				BEGIN
					UPDATE #TMP_OCCAuthTC
					SET LineClearCertSCD = CONVERT(TIME, @ActionOn)
					WHERE OCCAuthID = @OCCAuthID
				END;
				SET @WFStatus = '';
				SET @ActionOn = '';
			END;

			IF @EndorserID = 116
			BEGIN
				SELECT @WFStatus = WFStatus, @ActionOn = ActionOn 
				FROM [TAMS_OCC_Auth_Workflow] 
				WHERE OCCAuthId = @OCCAuthID AND OCCAuthEndorserId = 116;
				IF @WFStatus = 'Pending'
				BEGIN
					UPDATE #TMP_OCCAuthTC
					SET AuthForTrainInsert = @WFStatus
					WHERE OCCAuthID = @OCCAuthID
				END;
				IF @WFStatus = 'Completed'
				BEGIN
					UPDATE #TMP_OCCAuthTC
					SET AuthForTrainInsert = CONVERT(TIME, @ActionOn)
					WHERE OCCAuthID = @OCCAuthID
				END;
				SET @WFStatus = '';
				SET @ActionOn = '';
			END;

			FETCH NEXT FROM Cur1 INTO @EndorserID, @EndorserLevel, @EndorserTitle;
		END

		CLOSE Cur1;
		DEALLOCATE Cur1;

		FETCH NEXT FROM cur INTO @OCCAuthID;

	END;

	CLOSE cur;
	DEALLOCATE cur;


	SELECT * FROM #TMP_OCCAuthTC;
	--SELECT * FROM #TMP;

END

DROP TABLE #TMP;

DROP TABLE #TMP_Endorser;

DROP TABLE #TMP_OCCAuthTC;
GO
/****** END PROCEDURE 230 ******/

/****** START PROCEDURE 231 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_OCC_GetOCCAuthPreviewByParameters
CREATE PROCEDURE  [dbo].[sp_TAMS_OCC_GetOCCAuthPreviewByParameters]
	@Line AS nvarchar(10) = NULL,
	@TrackType AS nvarchar(50) = NULL,
	@OperationDate as date,
	@AccessDate as date

AS

DECLARE @OCCAuthID as int,
		@OCCAuthEndorserID as int,
		@StationID as int,
		@FISTestResult as nvarchar(50),
		@ActionBy as int,
		@WFStatus as nvarchar(50),
		@ActionOn as datetime

CREATE TABLE #TMP
(
	TractionPowerId int not null,	
	StationName nvarchar(50)
);


CREATE TABLE #TMP_OCCAuthPreview
(
	SNO int not null,
	ID int not null,	
	OCCAuthID int not null,
	Line nvarchar(10),
	PowerOn bit,
	IsBuffer bit,
	TractionPowerSection nvarchar(100),
	HSCBName nvarchar(100),
	StationName nvarchar(50),
	TC nvarchar(10),
	Train nvarchar(50),
	TrainClearCert_TC_Time nvarchar(8),
	TrainClearCert_TC_Name nvarchar(500),
	TrainClearCert_CC_Time nvarchar(8),
	TrainClearCert_CC_Name nvarchar(500),
	MT_Traction_Current_Off_Req_CC_Time nvarchar(8),
	MT_Traction_Current_Off_Req_CC_Name nvarchar(500),
	MT_Traction_Current_Off_PFR_Time nvarchar(50),
	MT_Traction_Current_Off_PFR_Name nvarchar(500),
	MT_Traction_Current_Off_RackOut_PFR_Time nvarchar(50),
	MT_Traction_Current_Off_RackOut_PFR_Name nvarchar(500),
	MT_Traction_Current_Off_STA_PFR_Time nvarchar(50),
	MT_Traction_Current_Off_STA_PFR_Name nvarchar(500),
	Permanent_Closing_VLD_PFR_Station nvarchar(50),
	Permanent_Closing_VLD_PFR_Time nvarchar(50),
	Permanent_Closing_VLD_PFR_Name nvarchar(500),
	AuthForTrackAccess_CC_Time nvarchar(8),
	AuthForTrackAccess_CC_Name nvarchar(500),
	AuthForTrackAccess_TC_Time nvarchar(8),
	AuthForTrackAccess_TC_Name nvarchar(500),
	LineClearCert_TOA_TC_Time nvarchar(8),
	LineClearCert_TOA_TC_Name nvarchar(500),
	LineClearCert_SCD_TC_Time nvarchar(8),
	LineClearCert_SCD_TC_Name nvarchar(500),
	LineClearCert_STA_PFR_Time nvarchar(50),
	LineClearCert_STA_PFR_Name nvarchar(500),
	LineClearCert_RackIn_PFR_Time nvarchar(50),
	LineClearCert_RackIn_PFR_Name nvarchar(500),
	LineClearCert_CC_Time nvarchar(8),
	LineClearCert_CC_Name nvarchar(500),
	Normalisation_VLD_PFR_Station nvarchar(50),
	Normalisation_VLD_PFR_Time nvarchar(50),
	Normalisation_VLD_PFR_Name nvarchar(500),
	MT_Traction_Current_On_Req_CC_Time nvarchar(8),
	MT_Traction_Current_On_Req_CC_Name nvarchar(500),
	MT_Traction_Current_On_PFR_Time nvarchar(50),
	MT_Traction_Current_On_PFR_Name nvarchar(500),
	MT_Traction_Current_On_FIS nvarchar(50),
	AuthForTrainInsert_CC_Time nvarchar(8),
	AuthForTrainInsert_CC_Name nvarchar(500),
	AuthForTrainInsert_TC_Time nvarchar(8),
	AuthForTrainInsert_TC_Name nvarchar(500),
	Remark nvarchar(1000),
	PFRRemark nvarchar(1000)
);

IF @Line = 'DTL'
BEGIN

	INSERT INTO #TMP(TractionPowerId, StationName)
	SELECT 
	   Id,
	   STUFF((SELECT ';' + S.StationName
			  FROM [TAMS_Traction_Power_Detail] TPD, [TAMS_Station] S
			  WHERE TPD.TractionPowerId = TP.ID
			  AND TPD.StationId = S.ID
			  AND  TPD.TractionPowerType = 'Station'
			  FOR XML PATH('')), 1, 1, '') [StationName]
	FROM [TAMS_Traction_Power] TP
	WHERE TP.Line = 'DTL'
	AND TrackType = @TrackType
	GROUP BY TP.ID

	INSERT INTO #TMP_OCCAuthPreview(
	SNO, 
	ID, 
	OCCAuthID,
	Line, 
	IsBuffer,
	PowerOn,
	TractionPowerSection,  
	HSCBName,
	StationName,
	TC,
	Train,
	TrainClearCert_TC_Time,
	TrainClearCert_TC_Name,
	TrainClearCert_CC_Time,
	TrainClearCert_CC_Name,
	MT_Traction_Current_Off_Req_CC_Time,
	MT_Traction_Current_Off_Req_CC_Name,
	MT_Traction_Current_Off_PFR_Time,
	MT_Traction_Current_Off_PFR_Name,
	MT_Traction_Current_Off_RackOut_PFR_Time,
	MT_Traction_Current_Off_RackOut_PFR_Name,
	MT_Traction_Current_Off_STA_PFR_Time,
	MT_Traction_Current_Off_STA_PFR_Name,
	Permanent_Closing_VLD_PFR_Station,
	Permanent_Closing_VLD_PFR_Time,
	Permanent_Closing_VLD_PFR_Name,
	AuthForTrackAccess_CC_Time,
	AuthForTrackAccess_CC_Name,
	AuthForTrackAccess_TC_Time,
	AuthForTrackAccess_TC_Name,
	LineClearCert_TOA_TC_Time,
	LineClearCert_TOA_TC_Name,
	LineClearCert_SCD_TC_Time,
	LineClearCert_SCD_TC_Name,
	LineClearCert_STA_PFR_Time,
	LineClearCert_STA_PFR_Name,
	LineClearCert_RackIn_PFR_Time,
	LineClearCert_RackIn_PFR_Name,
	LineClearCert_CC_Time,
	LineClearCert_CC_Name,
	Normalisation_VLD_PFR_Station,
	Normalisation_VLD_PFR_Time,
	Normalisation_VLD_PFR_Name,
	MT_Traction_Current_On_Req_CC_Time,
	MT_Traction_Current_On_Req_CC_Name,
	MT_Traction_Current_On_PFR_Time,
	MT_Traction_Current_On_PFR_Name,
	MT_Traction_Current_On_FIS,
	AuthForTrainInsert_CC_Time,
	AuthForTrainInsert_CC_Name,
	AuthForTrainInsert_TC_Time,
	AuthForTrainInsert_TC_Name,
	Remark,
	PFRRemark
	)
	SELECT ROW_NUMBER() OVER(ORDER BY tp.ID ASC) AS SNO
		  ,tp.[ID]
		  ,oa.[ID]
		  ,tp.[Line]
		  ,oa.[IsBuffer]
		  ,oa.[PowerOn]
		  ,[TractionPowerSection]
		  ,[HSCBName]
		  ,[StationName]
		  ,[TC]
		  ,[Train]
		  ,'' AS TrainClearCert_TC_Time
		  ,'' AS TrainClearCert_TC_Name
		  ,'' AS TrainClearCert_CC_Time
		  ,'' AS TrainClearCert_CC_Name 
		  ,'' AS MT_Traction_Current_Off_Req_CC_Time 
		  ,'' AS MT_Traction_Current_Off_Req_CC_Name 
		  ,'' AS MT_Traction_Current_Off_PFR_Time 
		  ,'' AS MT_Traction_Current_Off_PFR_Name 
		  ,'' AS MT_Traction_Current_Off_RackOut_PFR_Time 
		  ,'' AS MT_Traction_Current_Off_RackOut_PFR_Name 
		  ,'' AS MT_Traction_Current_Off_STA_PFR_Time 
		  ,'' AS MT_Traction_Current_Off_STA_PFR_Name 
		  ,'' AS Permanent_Closing_VLD_PFR_Station 
		  ,'' AS Permanent_Closing_VLD_PFR_Time 
		  ,'' AS Permanent_Closing_VLD_PFR_Name 
		  ,'' AS AuthForTrackAccess_CC_Time
		  ,'' AS AuthForTrackAccess_CC_Name
		  ,'' AS AuthForTrackAccess_TC_Time
		  ,'' AS AuthForTrackAccess_TC_Name
		  ,'' AS LineClearCert_TOA_TC_Time
		  ,'' AS LineClearCert_TOA_TC_Name
		  ,'' AS LineClearCert_SCD_TC_Time
		  ,'' AS LineClearCert_SCD_TC_Name
		  ,'' AS LineClearCert_STA_PFR_Time
		  ,'' AS LineClearCert_STA_PFR_Name
		  ,'' AS LineClearCert_RackIn_PFR_Time
		  ,'' AS LineClearCert_RackIn_PFR_Name
		  ,'' AS LineClearCert_CC_Time
		  ,'' AS LineClearCert_CC_Name
		  ,'' AS Normalisation_VLD_PFR_Station
		  ,'' AS Normalisation_VLD_PFR_Time
		  ,'' AS Normalisation_VLD_PFR_Name
		  ,'' AS MT_Traction_Current_On_Req_CC_Time 
		  ,'' AS MT_Traction_Current_On_Req_CC_Name 
		  ,'' AS MT_Traction_Current_On_PFR_Time 
		  ,'' AS MT_Traction_Current_On_PFR_Name 
		  ,'' AS MT_Traction_Current_On_FIS 
		  ,'' AS AuthForTrainInsert_CC_Time
		  ,'' AS AuthForTrainInsert_CC_Name
		  ,'' AS AuthForTrainInsert_TC_Time
		  ,'' AS AuthForTrainInsert_TC_Name
		  ,oa.[Remark]
		  ,oa.[PFRRemark]
	  FROM [TAMS_Traction_Power] tp, #TMP tmp, [TAMS_OCC_Auth] oa
	  WHERE tp.ID = tmp.TractionPowerId
	  AND tmp.TractionPowerId = oa.TractionPowerId
	  AND EffectiveDate <= GETDATE() and ExpiryDate >= GETDATE()
	  AND IsActive = 1
	  AND oa.OperationDate = @OperationDate
	  AND oa.AccessDate = @AccessDate
	  AND oa.Line = @Line
	  and oa.TrackType = @TrackType
	  --AND TC in 
	  --(SELECT RosterCode FROM TAMS_OCC_Duty_Roster 
	  -- WHERE OperationDate = CAST(@OperationDate as DATE)
	  -- and [shift] = 3
	  -- and [IsActive] = 1
	  -- and [DutyStaffId] = @UserID
	  -- )


	DECLARE cur CURSOR FOR
	SELECT OCCAuthID FROM #TMP_OCCAuthPreview


	OPEN cur;

	FETCH NEXT FROM cur INTO @OCCAuthID
	WHILE @@FETCH_STATUS = 0
	BEGIN

		DECLARE cur1 CURSOR FOR
		SELECT OCCAuthEndorserId, StationId, FISTestResult, ActionOn, ActionBy,WFStatus FROM TAMS_OCC_Auth_Workflow WHERE OCCAuthId = @OCCAuthID AND ActionBy <> 1;

		OPEN Cur1;

		FETCH NEXT FROM Cur1 INTO @OCCAuthEndorserID, @StationID, @FISTestResult, @ActionOn, @ActionBy,@WFStatus;
		WHILE @@FETCH_STATUS = 0
		BEGIN
			IF @OCCAuthEndorserID = 97
			BEGIN
				UPDATE #TMP_OCCAuthPreview
				SET TrainClearCert_TC_Time = convert(varchar,  @ActionOn,108), 
				TrainClearCert_TC_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
				WHERE OCCAuthID = @OCCAuthID
			END;

			IF @OCCAuthEndorserID = 98
			BEGIN
				UPDATE #TMP_OCCAuthPreview
				SET TrainClearCert_CC_Time = convert(varchar,  @ActionOn,108), 
				TrainClearCert_CC_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
				WHERE OCCAuthID = @OCCAuthID
			END;

			IF @OCCAuthEndorserID = 99
			BEGIN
				UPDATE #TMP_OCCAuthPreview
				SET MT_Traction_Current_Off_Req_CC_Time = convert(varchar,  @ActionOn,108), 
				MT_Traction_Current_Off_Req_CC_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
				WHERE OCCAuthID = @OCCAuthID
			END;

			IF @OCCAuthEndorserID = 100
			BEGIN
				UPDATE #TMP_OCCAuthPreview
				SET MT_Traction_Current_Off_PFR_Time = convert(varchar,  @ActionOn,108), 
				MT_Traction_Current_Off_PFR_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
				WHERE OCCAuthID = @OCCAuthID
			END;

			IF @OCCAuthEndorserID = 101
			BEGIN
				if @WFStatus = 'N.A.'
				begin 
					UPDATE #TMP_OCCAuthPreview
					SET MT_Traction_Current_Off_RackOut_PFR_Time = 'N.A. (' + convert(varchar,  @ActionOn,108) + ')', 
					MT_Traction_Current_Off_RackOut_PFR_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
					WHERE OCCAuthID = @OCCAuthID
				end;
				else 
				begin 
					UPDATE #TMP_OCCAuthPreview
					SET MT_Traction_Current_Off_RackOut_PFR_Time = convert(varchar,  @ActionOn,108), 
					MT_Traction_Current_Off_RackOut_PFR_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
					WHERE OCCAuthID = @OCCAuthID
				end; 
				
			END;

			IF @OCCAuthEndorserID = 102
			BEGIN
				if @WFStatus = 'N.A.'
				begin 
					UPDATE #TMP_OCCAuthPreview
					SET MT_Traction_Current_Off_STA_PFR_Time =  'N.A. (' + convert(varchar,  @ActionOn,108) + ')', 
					MT_Traction_Current_Off_STA_PFR_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
					WHERE OCCAuthID = @OCCAuthID
				end;
				else
				begin 
					UPDATE #TMP_OCCAuthPreview
					SET MT_Traction_Current_Off_STA_PFR_Time = convert(varchar,  @ActionOn,108), 
					MT_Traction_Current_Off_STA_PFR_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
					WHERE OCCAuthID = @OCCAuthID
				end; 
				
			END;

			IF @OCCAuthEndorserID = 103
			BEGIN
				UPDATE #TMP_OCCAuthPreview
				SET Permanent_Closing_VLD_PFR_Station = (SELECT StationName FROM TAMS_Station WHERE ID = @StationID), 
				Permanent_Closing_VLD_PFR_Time = convert(varchar,  @ActionOn,108),
				Permanent_Closing_VLD_PFR_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
				WHERE OCCAuthID = @OCCAuthID
			END;

			IF @OCCAuthEndorserID = 104
			BEGIN
				UPDATE #TMP_OCCAuthPreview
				SET AuthForTrackAccess_CC_Time = convert(varchar,  @ActionOn,108), 
				AuthForTrackAccess_CC_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
				WHERE OCCAuthID = @OCCAuthID
			END;

			IF @OCCAuthEndorserID = 105
			BEGIN
				UPDATE #TMP_OCCAuthPreview
				SET AuthForTrackAccess_TC_Time = convert(varchar,  @ActionOn,108), 
				AuthForTrackAccess_TC_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
				WHERE OCCAuthID = @OCCAuthID
			END;

			IF @OCCAuthEndorserID = 106
			BEGIN
				UPDATE #TMP_OCCAuthPreview
				SET LineClearCert_TOA_TC_Time = convert(varchar,  @ActionOn,108), 
				LineClearCert_TOA_TC_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
