			END;

			IF @OCCAuthEndorserID = 107
			BEGIN
				UPDATE #TMP_OCCAuthPreview
				SET LineClearCert_SCD_TC_Time = convert(varchar,  @ActionOn,108), 
				LineClearCert_SCD_TC_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
				WHERE OCCAuthID = @OCCAuthID
			END;

			IF @OCCAuthEndorserID = 108
			BEGIN
				if @WFStatus = 'N.A.'
				begin 
					UPDATE #TMP_OCCAuthPreview
					SET LineClearCert_STA_PFR_Time = 'N.A. (' + convert(varchar,  @ActionOn,108) + ')', 
					LineClearCert_STA_PFR_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
					WHERE OCCAuthID = @OCCAuthID
				end;
				else 
				begin 
					UPDATE #TMP_OCCAuthPreview
					SET LineClearCert_STA_PFR_Time = convert(varchar,  @ActionOn,108), 
					LineClearCert_STA_PFR_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
					WHERE OCCAuthID = @OCCAuthID
				end;
			END;

			IF @OCCAuthEndorserID = 109
			BEGIN
				if @WFStatus = 'N.A.'
				begin 
					UPDATE #TMP_OCCAuthPreview
					SET LineClearCert_RackIn_PFR_Time = 'N.A. ('  + convert(varchar,  @ActionOn,108) + ')', 
					LineClearCert_RackIn_PFR_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
					WHERE OCCAuthID = @OCCAuthID
				end; 
				else 
				begin 
					UPDATE #TMP_OCCAuthPreview
					SET LineClearCert_RackIn_PFR_Time = convert(varchar,  @ActionOn,108), 
					LineClearCert_RackIn_PFR_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
					WHERE OCCAuthID = @OCCAuthID
				end;
			END;

			IF @OCCAuthEndorserID = 110
			BEGIN
				UPDATE #TMP_OCCAuthPreview
				SET LineClearCert_CC_Time = convert(varchar,  @ActionOn,108), 
				LineClearCert_CC_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
				WHERE OCCAuthID = @OCCAuthID
			END;

			IF @OCCAuthEndorserID = 111
			BEGIN
				UPDATE #TMP_OCCAuthPreview
				SET Normalisation_VLD_PFR_Station = Permanent_Closing_VLD_PFR_Station, 
				Normalisation_VLD_PFR_Time = convert(varchar,  @ActionOn,108),
				Normalisation_VLD_PFR_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
				WHERE OCCAuthID = @OCCAuthID
			END;

			IF @OCCAuthEndorserID = 112
			BEGIN
				UPDATE #TMP_OCCAuthPreview
				SET MT_Traction_Current_On_Req_CC_Time = convert(varchar,  @ActionOn,108), 
				MT_Traction_Current_On_Req_CC_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
				WHERE OCCAuthID = @OCCAuthID
			END;

			IF @OCCAuthEndorserID = 113
			BEGIN
				UPDATE #TMP_OCCAuthPreview
				SET MT_Traction_Current_On_PFR_Time = convert(varchar,  @ActionOn,108), 
				MT_Traction_Current_On_PFR_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
				WHERE OCCAuthID = @OCCAuthID
			END;

			IF @OCCAuthEndorserID = 114
			BEGIN
				UPDATE #TMP_OCCAuthPreview
				SET MT_Traction_Current_On_FIS = @FISTestResult
				WHERE OCCAuthID = @OCCAuthID
			END;

			IF @OCCAuthEndorserID = 115
			BEGIN
				UPDATE #TMP_OCCAuthPreview
				SET AuthForTrainInsert_CC_Time = convert(varchar,  @ActionOn,108), 
				AuthForTrainInsert_CC_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
				WHERE OCCAuthID = @OCCAuthID
			END;

			IF @OCCAuthEndorserID = 116
			BEGIN
				UPDATE #TMP_OCCAuthPreview
				SET AuthForTrainInsert_TC_Time = convert(varchar,  @ActionOn,108), 
				AuthForTrainInsert_TC_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
				WHERE OCCAuthID = @OCCAuthID
			END;

			FETCH NEXT FROM Cur1 INTO @OCCAuthEndorserID, @StationID, @FISTestResult, @ActionOn, @ActionBy,@WFStatus;
		END

		CLOSE Cur1;
		DEALLOCATE Cur1;

		FETCH NEXT FROM cur INTO @OCCAuthID;

	END;

	CLOSE cur;
	DEALLOCATE cur;


	SELECT * FROM #TMP_OCCAuthPreview;
	--SELECT * FROM #TMP;

END

DROP TABLE #TMP;

--DROP TABLE #TMP_Endorser;

DROP TABLE #TMP_OCCAuthPreview;
GO
