	MT_Traction_Current_On_RackIn_PFR_Time nvarchar(8),
	MT_Traction_Current_On_RackIn_PFR_Name nvarchar(500),
	MT_Traction_Current_On_PFR_Time nvarchar(8),
	MT_Traction_Current_On_PFR_Name nvarchar(500),
	AuthForTrainInsert_CC_Time nvarchar(8),
	AuthForTrainInsert_CC_Name nvarchar(500),
	AuthForTrainInsert_TC_Time nvarchar(8),
	AuthForTrainInsert_TC_Name nvarchar(500),
	Remark nvarchar(1000),
);

IF @Line = 'NEL'
BEGIN

	--INSERT INTO #TMP(TractionPowerId, StationName)
	--SELECT 
	--   Id,
	--   STUFF((SELECT ';' + S.StationName
	--		  FROM [TAMS_Traction_Power_Detail] TPD, [TAMS_Station] S
	--		  WHERE TPD.TractionPowerId = TP.ID
	--		  AND TPD.StationId = S.ID
	--		  AND  TPD.TractionPowerType = 'Station'
	--		  FOR XML PATH('')), 1, 1, '') [StationName]
	--FROM [TAMS_Traction_Power] TP
	--WHERE TP.Line = 'NEL'
	--GROUP BY TP.ID

	INSERT INTO #TMP_OCCAuthPreview(
	SNO, 
	ID, 
	OCCAuthID,
	Line, 
	TractionPowerSection,  
	HSCBName,
	Train,
	TrainClearCert_TC_Time,
	TrainClearCert_TC_Name,
	TrainClearCert_CC_Time,
	TrainClearCert_CC_Name,
	MT_Traction_Current_Off_Req_CC_Time,
	MT_Traction_Current_Off_Req_CC_Name,
	MT_Traction_Current_Off_PFR_Time,
	MT_Traction_Current_Off_PFR_Name,
	MT_Traction_Current_Off_RackOut_PFR_Time,
	MT_Traction_Current_Off_RackOut_PFR_Name,
	AuthForTrackAccess_CC_Time,
	AuthForTrackAccess_CC_Name,
	AuthForTrackAccess_TC_Time,
	AuthForTrackAccess_TC_Name,
	LineClearCert_TOA_TC_Time,
	LineClearCert_TOA_TC_Name,
	LineClearCert_SCD_TC_Time,
	LineClearCert_SCD_TC_Name,
	LineClearCert_CC_Time,
	LineClearCert_CC_Name,
	MT_Traction_Current_On_Req_CC_Time,
	MT_Traction_Current_On_Req_CC_Name,
	MT_Traction_Current_On_RackIn_PFR_Time,
	MT_Traction_Current_On_RackIn_PFR_Name,
	MT_Traction_Current_On_PFR_Time,
	MT_Traction_Current_On_PFR_Name,
	AuthForTrainInsert_CC_Time,
	AuthForTrainInsert_CC_Name,
	AuthForTrainInsert_TC_Time,
	AuthForTrainInsert_TC_Name,
	Remark
	)
	SELECT ROW_NUMBER() OVER(ORDER BY tp.ID ASC) AS SNO
		  ,tp.[ID]
		  ,oa.[ID]
		  ,tp.[Line]
		  ,[TractionPowerSection]
		  ,[HSCBName]
		  ,[Train]
		  ,'' AS TrainClearCert_TC_Time
		  ,'' AS TrainClearCert_TC_Name
		  ,'' AS TrainClearCert_CC_Time
		  ,'' AS TrainClearCert_CC_Name 
		  ,'' AS MT_Traction_Current_Off_Req_CC_Time 
		  ,'' AS MT_Traction_Current_Off_Req_CC_Name 
		  ,'' AS MT_Traction_Current_Off_PFR_Time 
		  ,'' AS MT_Traction_Current_Off_PFR_Name 
		  ,'' AS MT_Traction_Current_Off_RackOut_PFR_Time 
		  ,'' AS MT_Traction_Current_Off_RackOut_PFR_Name 
		  ,'' AS AuthForTrackAccess_CC_Time
		  ,'' AS AuthForTrackAccess_CC_Name
		  ,'' AS AuthForTrackAccess_TC_Time
		  ,'' AS AuthForTrackAccess_TC_Name
		  ,'' AS LineClearCert_TOA_TC_Time
		  ,'' AS LineClearCert_TOA_TC_Name
		  ,'' AS LineClearCert_SCD_TC_Time
		  ,'' AS LineClearCert_SCD_TC_Name
		  ,'' AS LineClearCert_CC_Time
		  ,'' AS LineClearCert_CC_Name
		  ,'' AS MT_Traction_Current_On_Req_CC_Time 
		  ,'' AS MT_Traction_Current_On_Req_CC_Name 
		  ,'' AS MT_Traction_Current_On_RackIn_PFR_Time 
		  ,'' AS MT_Traction_Current_On_RackIn_PFR_Name
		  ,'' AS MT_Traction_Current_On_PFR_Time 
		  ,'' AS MT_Traction_Current_On_PFR_Name 
		  ,'' AS AuthForTrainInsert_CC_Time
		  ,'' AS AuthForTrainInsert_CC_Name
		  ,'' AS AuthForTrainInsert_TC_Time
		  ,'' AS AuthForTrainInsert_TC_Name
		  ,oa.[Remark]
	  FROM [TAMS_Traction_Power] tp, [TAMS_OCC_Auth] oa
	  WHERE tp.ID = oa.TractionPowerId
	  AND EffectiveDate <= GETDATE() and ExpiryDate >= GETDATE()
	  AND IsActive = 1
	  AND oa.OperationDate = @OperationDate
	  AND oa.AccessDate = @AccessDate
	  AND oa.Line = @Line
	  --AND TC in 
	  --(SELECT RosterCode FROM TAMS_OCC_Duty_Roster 
	  -- WHERE OperationDate = CAST(@OperationDate as DATE)
	  -- and [shift] = 3
	  -- and [IsActive] = 1
	  -- and [DutyStaffId] = @UserID
	  -- )


	DECLARE cur CURSOR FOR
	SELECT OCCAuthID FROM #TMP_OCCAuthPreview


	OPEN cur;

	FETCH NEXT FROM cur INTO @OCCAuthID
	WHILE @@FETCH_STATUS = 0
	BEGIN

		DECLARE cur1 CURSOR FOR
		SELECT OCCAuthEndorserId, WFStatus, ActionOn, ActionBy FROM TAMS_OCC_Auth_Workflow WHERE OCCAuthId = @OCCAuthID AND ActionBy <> 1;

		OPEN Cur1;

		FETCH NEXT FROM Cur1 INTO @OCCAuthEndorserID, @WFStatus, @ActionOn, @ActionBy;
		WHILE @@FETCH_STATUS = 0
		BEGIN
			IF @OCCAuthEndorserID = 117	--1
				BEGIN
					UPDATE #TMP_OCCAuthPreview
					SET TrainClearCert_TC_Time = CONVERT(TIME, @ActionOn), 
					TrainClearCert_TC_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
					WHERE OCCAuthID = @OCCAuthID
				END;

			IF @OCCAuthEndorserID = 118	--2
				BEGIN
					UPDATE #TMP_OCCAuthPreview
					SET TrainClearCert_CC_Time = CONVERT(TIME, @ActionOn), 
					TrainClearCert_CC_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
					WHERE OCCAuthID = @OCCAuthID
				END;

			IF @OCCAuthEndorserID = 119 --3
				BEGIN
					UPDATE #TMP_OCCAuthPreview
					SET MT_Traction_Current_Off_Req_CC_Time = CONVERT(TIME, @ActionOn), 
					MT_Traction_Current_Off_Req_CC_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
					WHERE OCCAuthID = @OCCAuthID
				END;

			IF @OCCAuthEndorserID = 120	--4
				BEGIN
					--UPDATE #TMP_OCCAuthPreview
					--SET MT_Traction_Current_Off_PFR_Time = CONVERT(TIME, @ActionOn), 
					--MT_Traction_Current_Off_PFR_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
					--WHERE OCCAuthID = @OCCAuthID

					IF @WFStatus = 'Completed'
						BEGIN
							UPDATE #TMP_OCCAuthPreview
							SET MT_Traction_Current_Off_PFR_Time = CONVERT(TIME, @ActionOn), 
							MT_Traction_Current_Off_PFR_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
							WHERE OCCAuthID = @OCCAuthID
						END;
					ELSE IF @WFStatus = 'N.A.'
						BEGIN
							UPDATE #TMP_OCCAuthPreview
							SET MT_Traction_Current_Off_PFR_Time = 'N.A.', 
							MT_Traction_Current_Off_PFR_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
							WHERE OCCAuthID = @OCCAuthID
						END;
				END;

			IF @OCCAuthEndorserID = 121	--5
				BEGIN
					IF @WFStatus = 'Completed'
						BEGIN
							UPDATE #TMP_OCCAuthPreview
							SET MT_Traction_Current_Off_RackOut_PFR_Time = CONVERT(TIME, @ActionOn), 
							MT_Traction_Current_Off_RackOut_PFR_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
							WHERE OCCAuthID = @OCCAuthID
						END;
					ELSE IF @WFStatus = 'N.A.'
						BEGIN
							UPDATE #TMP_OCCAuthPreview
							SET MT_Traction_Current_Off_RackOut_PFR_Time = 'N.A.', 
							MT_Traction_Current_Off_RackOut_PFR_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
							WHERE OCCAuthID = @OCCAuthID
						END;
				END;

			IF @OCCAuthEndorserID = 122	--6
				BEGIN
					UPDATE #TMP_OCCAuthPreview
					SET AuthForTrackAccess_CC_Time = CONVERT(TIME, @ActionOn), 
					AuthForTrackAccess_CC_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
					WHERE OCCAuthID = @OCCAuthID
				END;

			IF @OCCAuthEndorserID = 123	--7
				BEGIN
					UPDATE #TMP_OCCAuthPreview
					SET AuthForTrackAccess_TC_Time = CONVERT(TIME, @ActionOn), 
					AuthForTrackAccess_TC_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
					WHERE OCCAuthID = @OCCAuthID
				END;

			IF @OCCAuthEndorserID = 124	--8
				BEGIN
					UPDATE #TMP_OCCAuthPreview
					SET LineClearCert_TOA_TC_Time = CONVERT(TIME, @ActionOn), 
					LineClearCert_TOA_TC_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
					WHERE OCCAuthID = @OCCAuthID
				END;

			IF @OCCAuthEndorserID = 125	--9
				BEGIN
					UPDATE #TMP_OCCAuthPreview
					SET LineClearCert_SCD_TC_Time = CONVERT(TIME, @ActionOn), 
					LineClearCert_SCD_TC_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
					WHERE OCCAuthID = @OCCAuthID
				END;

			IF @OCCAuthEndorserID = 126	--10
				BEGIN
					UPDATE #TMP_OCCAuthPreview
					SET LineClearCert_CC_Time = CONVERT(TIME, @ActionOn), 
					LineClearCert_CC_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
					WHERE OCCAuthID = @OCCAuthID
				END;

			IF @OCCAuthEndorserID = 127	--11
				BEGIN
					UPDATE #TMP_OCCAuthPreview
					SET MT_Traction_Current_On_Req_CC_Time = CONVERT(TIME, @ActionOn), 
					MT_Traction_Current_On_Req_CC_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
					WHERE OCCAuthID = @OCCAuthID
				END;

			IF @OCCAuthEndorserID = 128	--12
				BEGIN
					IF @WFStatus = 'Completed'
						BEGIN
							UPDATE #TMP_OCCAuthPreview
							SET MT_Traction_Current_On_RackIn_PFR_Time = CONVERT(TIME, @ActionOn), 
							MT_Traction_Current_On_RackIn_PFR_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
							WHERE OCCAuthID = @OCCAuthID
						END;
					ELSE IF @WFStatus = 'N.A.'
						BEGIN
							UPDATE #TMP_OCCAuthPreview
							SET MT_Traction_Current_On_RackIn_PFR_Time = 'N.A.', 
							MT_Traction_Current_On_RackIn_PFR_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
							WHERE OCCAuthID = @OCCAuthID
						END;
				END;

			IF @OCCAuthEndorserID = 129	--13
				BEGIN
					----UPDATE #TMP_OCCAuthPreview
					----SET MT_Traction_Current_On_PFR_Time = CONVERT(TIME, @ActionOn), 
					----MT_Traction_Current_On_PFR_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
					----WHERE OCCAuthID = @OCCAuthID

					IF @WFStatus = 'Completed'
						BEGIN
							UPDATE #TMP_OCCAuthPreview
							SET MT_Traction_Current_On_PFR_Time = CONVERT(TIME, @ActionOn), 
							MT_Traction_Current_On_PFR_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
							WHERE OCCAuthID = @OCCAuthID
						END;
					ELSE IF @WFStatus = 'N.A.'
						BEGIN
							UPDATE #TMP_OCCAuthPreview
							SET MT_Traction_Current_On_PFR_Time = 'N.A.', 
							MT_Traction_Current_On_PFR_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
							WHERE OCCAuthID = @OCCAuthID
						END;
				END;

			IF @OCCAuthEndorserID = 130	--14
				BEGIN
					UPDATE #TMP_OCCAuthPreview
					SET AuthForTrainInsert_CC_Time = CONVERT(TIME, @ActionOn), 
					AuthForTrainInsert_CC_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
					WHERE OCCAuthID = @OCCAuthID
				END;

			IF @OCCAuthEndorserID = 131	--15
				BEGIN
					UPDATE #TMP_OCCAuthPreview
					SET AuthForTrainInsert_TC_Time = CONVERT(TIME, @ActionOn), 
					AuthForTrainInsert_TC_Name = (SELECT Name FROM TAMS_User WHERE Userid = @ActionBy)
					WHERE OCCAuthID = @OCCAuthID
				END;

			FETCH NEXT FROM Cur1 INTO @OCCAuthEndorserID, @WFStatus, @ActionOn, @ActionBy;
		END

		CLOSE Cur1;
		DEALLOCATE Cur1;

		FETCH NEXT FROM cur INTO @OCCAuthID;

	END;

	CLOSE cur;
	DEALLOCATE cur;


	SELECT * FROM #TMP_OCCAuthPreview;
	--SELECT * FROM #TMP;

END

--DROP TABLE #TMP;

--DROP TABLE #TMP_Endorser;

DROP TABLE #TMP_OCCAuthPreview;
GO
/****** END PROCEDURE 233 ******/

/****** START PROCEDURE 234 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_OCC_GetOCCTarTVFByParameters
CREATE PROCEDURE [dbo].[sp_TAMS_OCC_GetOCCTarTVFByParameters]
	@StationId	as int,
	@AccessDate as date

AS

DECLARE @TVF_Ack_CNT int;
DECLARE @Id as int,
		@TarNo as nvarchar(50),
		@PersonInCharge nvarchar(500),
		@TVFMode as nvarchar(50),
		@TVFDirection as nvarchar(10)


CREATE TABLE #TMP_TVF
(
	Id int not null,	
	TarNo nvarchar(50),
	PersonInCharge nvarchar(500),
	TVFMode nvarchar(20),
	TVFDirection nvarchar(10)
);

CREATE TABLE #TMP_TAR_TVF
(
	Id int not null,	
	TarNo nvarchar(50),
	PersonInCharge nvarchar(500),
	TVFDirection1 bit,
	TVFDirection2 bit,
	TVFMode nvarchar(20)
);


BEGIN

	TRUNCATE TABLE #TMP_TVF;

	TRUNCATE TABLE #TMP_TAR_TVF;

	INSERT INTO #TMP_TVF(Id, TarNo, PersonInCharge, TVFDirection, TVFMode)
	SELECT tar.id, tar.tarno, inchargename, tvf.TVFDirection, tar.TVFMode
	FROM TAMS_TAR tar
	INNER JOIN TAMS_TAR_TVF tvf
	ON tar.Id = tvf.TARID
	LEFT JOIN TAMS_TOA toa
	ON  tar.id = toa.TARId
	WHERE tvf.TVFStationId = @StationId
	AND tar.AccessDate = @AccessDate

	DECLARE cur CURSOR FOR
	SELECT Id, TarNo, PersonInCharge, TVFDirection, TVFMode FROM #TMP_TVF ORDER BY ID ASC

	OPEN cur;

	FETCH NEXT FROM cur INTO @Id, @TarNo, @PersonInCharge, @TVFDirection, @TVFMode

	WHILE @@FETCH_STATUS = 0
	BEGIN
		IF NOT EXISTS
		(
			SELECT ID
			FROM #TMP_TAR_TVF
			WHERE ID = @ID
		)
			BEGIN
				IF @TVFDirection = 'XB'
				BEGIN
					INSERT INTO #TMP_TAR_TVF(Id, TarNo, PersonInCharge, TVFDirection1, TVFDirection2, TVFMode)
					VALUES(@Id, @TarNo, @PersonInCharge, 1, 0, @TVFMode)
				END;
				IF @TVFDirection = 'BB'
				BEGIN
					INSERT INTO #TMP_TAR_TVF(Id, TarNo, PersonInCharge, TVFDirection1, TVFDirection2, TVFMode)
					VALUES(@Id, @TarNo, @PersonInCharge, 0, 1, @TVFMode)
				END;
			END
		ELSE
			BEGIN
				IF @TVFDirection = 'XB'
				BEGIN
					UPDATE #TMP_TAR_TVF
					SET TVFDirection1 = 1;
				END;
				IF @TVFDirection = 'BB'
				BEGIN
					UPDATE #TMP_TAR_TVF
					SET TVFDirection2 = 1;
				END;
			END;
		FETCH NEXT FROM Cur INTO @Id, @TarNo, @PersonInCharge, @TVFDirection, @TVFMode;
	END;
	CLOSE Cur;
	DEALLOCATE Cur;

	SELECT * FROM #TMP_TAR_TVF;
	--SELECT * FROM #TMP;
END;

DROP TABLE #TMP_TVF;

DROP TABLE #TMP_TAR_TVF;
GO
/****** END PROCEDURE 234 ******/

/****** START PROCEDURE 235 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_OCC_GetOCCTVFAckByParameters
CREATE PROCEDURE  [dbo].[sp_TAMS_OCC_GetOCCTVFAckByParameters]
	@UserID		as int,
	@Line AS nvarchar(10) = NULL,
	@TrackType AS nvarchar(50) = NULL,
	@OperationDate as date,
	@AccessDate as date

AS

DECLARE @TVF_Ack_CNT int;
DECLARE @TVFStationId as int,
		@TVFMode as nvarchar(50),
		@TVFDirection as nvarchar(10)

CREATE TABLE #TMP_Station
(
	Id int not null,	
	StationName nvarchar(50)
);

CREATE TABLE #TMP_TVF
(
	Id int not null,	
	TARID int,
	TVFStationId int,
	TVFMode nvarchar(20),
	TVFDirection nvarchar(10)
);

CREATE TABLE #TMP_TVF_ToUpdate
(
	TVFStationId int,
	TVFMode nvarchar(20),
	TVFDirection nvarchar(10),
	TVFDirection1 bit,
	TVFDirection2 bit
);

CREATE TABLE #TMP_OCCTVF_Ack
(
	SNO int not null,
	ID int,
	--TARID int,
	AccessDate date,
	OperationDate date,
	StationId int,
	StationName nvarchar(50),
	TVFDirection1 bit,
	TVFDirection2 bit,
	TVFMode nvarchar(50),
	AcknowledgedBy nvarchar(500),
	AcknowledgedOn datetime,
	--TVFDirection nvarchar(50),
	TVFOnTime datetime,
	OperatedBy nvarchar(500),
	VerifiedBy nvarchar(500),
	VerifiedOn datetime
);

IF @Line = 'DTL'
BEGIN

	SELECT @TVF_Ack_CNT = COUNT(*) FROM [TAMS_TVF_Acknowledge] WHERE AccessDate = @AccessDate;

	IF @TVF_Ack_CNT = 0
	BEGIN

		TRUNCATE TABLE #TMP_TVF_ToUpdate;

		INSERT INTO #TMP_TVF(Id, TARID, TVFStationId, TVFMode, TVFDirection)
		SELECT t.id, tarid, tvfstationid, tvfmode, tvfdirection
		FROM [TAMS_TAR] t
		INNER JOIN [TAMS_TAR_TVF] tvf
		ON t.id = tvf.TARID
		AND AccessDate = @AccessDate
		WHERE (t.TVFMode IS NOT NULL OR t.TVFMode != 'N.A.')
		and t.TrackType = @TrackType
		ORDER BY TVFStationId, TVFMode ASC

		DECLARE cur CURSOR FOR
		SELECT TVFStationId, TVFMode, TVFDirection FROM #TMP_TVF ORDER BY TVFStationId, TVFMode ASC

		OPEN cur;

		FETCH NEXT FROM cur INTO @TVFStationId, @TVFMode, @TVFDirection
		print @TVFMode;
		WHILE @@FETCH_STATUS = 0
		BEGIN
			IF NOT EXISTS
			(
				SELECT TVFStationId
				FROM #TMP_TVF_ToUpdate
				WHERE TVFStationId = @TVFStationId
			)
				BEGIN
					IF @TVFDirection = 'XB'
					BEGIN
						INSERT INTO #TMP_TVF_ToUpdate(TVFStationId, TVFMode, TVFDirection1, TVFDirection2)
						VALUES(@TVFStationId, @TVFMode, 1, 0)
					END;
					IF @TVFDirection = 'BB'
					BEGIN
						INSERT INTO #TMP_TVF_ToUpdate(TVFStationId, TVFMode, TVFDirection1, TVFDirection2)
						VALUES(@TVFStationId, @TVFMode, 0, 1)
					END;
				END
			ELSE
				BEGIN
					IF @TVFMode = 'Emergency'
					BEGIN
						--print 'emergency';

						UPDATE #TMP_TVF_ToUpdate
						SET TVFMode = @TVFMode
						WHERE TVFStationId = @TVFStationId

						IF @TVFDirection = 'XB'
						BEGIN
							UPDATE #TMP_TVF_ToUpdate
							SET TVFDirection1 = 1, TVFDirection2 = 0
							WHERE TVFStationId = @TVFStationId
						END;
						IF @TVFDirection = 'BB'
						BEGIN
							UPDATE #TMP_TVF_ToUpdate
							SET TVFDirection2 = 1, TVFDirection1 = 0
							WHERE TVFStationId = @TVFStationId
						END;
					END;
					ELSE
					BEGIN
						--print 'congestion';
						UPDATE #TMP_TVF_ToUpdate
						SET TVFMode = @TVFMode
						WHERE TVFStationId = @TVFStationId

						IF @TVFDirection = 'XB'
						BEGIN
							UPDATE #TMP_TVF_ToUpdate
							SET TVFDirection1 = 1
							WHERE TVFStationId = @TVFStationId
						END;
						IF @TVFDirection = 'BB'
						BEGIN
							UPDATE #TMP_TVF_ToUpdate
							SET TVFDirection2 = 1
							WHERE TVFStationId = @TVFStationId
						END;
					END;
				END
			FETCH NEXT FROM Cur INTO @TVFStationId, @TVFMode, @TVFDirection;
		END;
		CLOSE Cur;
		DEALLOCATE Cur;

		--SELECT * FROM #TMP_TVF_ToUpdate;

		INSERT INTO #TMP_Station(Id, StationName)
		SELECT id, stationcode + ' ' + StationName AS station
		FROM [TAMS_Station] 
		WHERE Line = 'DTL'
		AND IsActive = 1
		AND IsStation = 1
		ORDER BY [Order] ASC

		INSERT INTO #TMP_OCCTVF_Ack(
		SNO, 
		ID, 
		AccessDate,
		OperationDate,
		StationId,
		StationName,
		TVFDirection1,
		TVFDirection2,
		TVFMode, 
		AcknowledgedBy,  
		AcknowledgedOn,
		--TVFDirection,
		TVFOnTime,
		OperatedBy,
		VerifiedBy,
		VerifiedOn)
		SELECT ROW_NUMBER() OVER(ORDER BY tvf.ID ASC) AS SNO
			  ,tvf.[ID]
			  ,tvf.[AccessDate]
			  ,tvf.[OperationDate]
			  ,tmp.[Id]
			  ,tmp.[StationName]
			  ,tvf.[TVFDirection1]
			  ,tvf.[TVFDirection2]
			  ,tvf.[TVFMode]
			  ,(SELECT Name FROM [TAMS_User] WHERE UserId = tvf.[AcknowledgedBy])
			  ,tvf.[AcknowledgedOn]
			  --,tvf.[TVFDirection]
			  ,tvf.[TVFOnTime]
			  ,(SELECT Name FROM [TAMS_User] WHERE UserId = tvf.[OperatedBy])
			  ,(SELECT Name FROM [TAMS_User] WHERE UserId = tvf.[VerifiedBy])
			  ,tvf.[VerifiedOn]
		  FROM [TAMS_TVF_Acknowledge] tvf
		  RIGHT JOIN #TMP_Station tmp
		  ON tvf.StationId = tmp.Id	  
		  AND tvf.OperationDate = @OperationDate
		  AND tvf.AccessDate = @AccessDate

		  UPDATE t1
		  SET t1.TVFDirection1 = t2.TVFDirection1,
			t1.TVFDirection2 = t2.TVFDirection2,
			t1.TVFMode = t2.TVFMode
		  FROM #TMP_OCCTVF_Ack t1 INNER JOIN #TMP_TVF_ToUpdate t2
		  ON t1.StationId = t2.TVFStationId

		SELECT * FROM #TMP_OCCTVF_Ack;
		--SELECT * FROM #TMP;
	END;
	ELSE
	BEGIN
			INSERT INTO #TMP_Station(Id, StationName)
			SELECT id, stationcode + ' ' + StationName AS station
			FROM [TAMS_Station] 
			WHERE Line = 'DTL'
			AND IsActive = 1
			AND IsStation = 1
			ORDER BY [Order] ASC

			INSERT INTO #TMP_OCCTVF_Ack(
			SNO, 
			ID, 
			AccessDate,
			OperationDate,
			StationId,
			StationName,
			TVFDirection1,
			TVFDirection2,
			TVFMode, 
			AcknowledgedBy,  
			AcknowledgedOn,
			--TVFDirection,
			TVFOnTime,
			OperatedBy,
			VerifiedBy,
			VerifiedOn)
			SELECT ROW_NUMBER() OVER(ORDER BY tvf.ID ASC) AS SNO
				  ,tvf.[ID]
				  ,tvf.[AccessDate]
				  ,tvf.[OperationDate]
				  ,tmp.[Id]
				  ,tmp.[StationName]
				  ,tvf.[TVFDirection1]
				  ,tvf.[TVFDirection2]
				  ,tvf.[TVFMode]
				  ,(SELECT Name FROM [TAMS_User] WHERE UserId = tvf.[AcknowledgedBy])
				  ,tvf.[AcknowledgedOn]
				  --,tvf.[TVFDirection]
				  ,tvf.[TVFOnTime]
				  ,(SELECT Name FROM [TAMS_User] WHERE UserId = tvf.[OperatedBy])
			      ,(SELECT Name FROM [TAMS_User] WHERE UserId = tvf.[VerifiedBy])
				  ,tvf.[VerifiedOn]
			  FROM [TAMS_TVF_Acknowledge] tvf
			  RIGHT JOIN #TMP_Station tmp
			  ON tvf.StationId = tmp.Id	  
			  AND tvf.OperationDate = @OperationDate
			  AND tvf.AccessDate = @AccessDate

			  SELECT * FROM #TMP_OCCTVF_Ack
			  ORDER BY StationId ASC
	END;

END;
DROP TABLE #TMP_Station;


DROP TABLE #TMP_OCCTVF_Ack;

DROP TABLE #TMP_TVF_ToUpdate;
GO
/****** END PROCEDURE 235 ******/

