-- PROCEDURE NAME: dbo.sp_TAMS_OCC_GetTractionPowerDetailsByIdAndType
CREATE PROCEDURE [dbo].[sp_TAMS_OCC_GetTractionPowerDetailsByIdAndType]
	@ID AS int = 0

AS
BEGIN
	SELECT [ID],
		[TractionPowerId],
		[TractionPowerType],
		[StationId],
		[SectorId],
		[PowerSectionId]
	FROM TAMS_Traction_Power_Detail
	WHERE [TractionPowerId]= @ID
	AND [TractionPowerType] = 'Sector'
	AND IsActive = 1
	ORDER BY [ID] ASC
END
GO
/****** END PROCEDURE 240 ******/

/****** START PROCEDURE 241 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_OCC_GetTractionsPowerByLine
CREATE PROCEDURE [dbo].[sp_TAMS_OCC_GetTractionsPowerByLine]
	@Line as nvarchar(10) = null

AS
BEGIN
	SELECT [ID],
	[Line],
	[TractionPowerSection],
	[HSCBName],
	[TC],
	[Train],
	[Order]
	FROM [dbo].[TAMS_Traction_Power]
	WHERE [Line] = @Line
	AND EffectiveDate <= GETDATE() and ExpiryDate >= GETDATE()
	AND IsActive = 1
	ORDER BY [Order] ASC
END
GO
/****** END PROCEDURE 241 ******/

/****** START PROCEDURE 242 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_OCC_GetWorkflowByLineAndType
CREATE PROCEDURE [dbo].[sp_TAMS_OCC_GetWorkflowByLineAndType]
	@Line AS NVARCHAR(10) = NULL,
	@Type AS NVARCHAR(50) = NULL
AS
BEGIN

	SELECT ID, Line, WorkflowType, InvolvePower FROM TAMS_Workflow
	WHERE Line = @Line
	AND WorkflowType = @Type
	AND EffectiveDate <= GETDATE()
	AND ExpiryDate >= GETDATE()
	AND IsActive = 1
	ORDER BY ID
END
GO
/****** END PROCEDURE 242 ******/

/****** START PROCEDURE 243 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_OCC_InsertToDutyOCCRosterTable
CREATE PROCEDURE  [dbo].[sp_TAMS_OCC_InsertToDutyOCCRosterTable]
	@TAMS_OCC_DutyRoster [dbo].[TAMS_OCC_DutyRoster] READONLY



AS
BEGIN

	declare @count as int = 0;
	declare @loop as int = 0;
	declare @operationdate as date;
	declare @shift as nvarchar(1);
	declare @line as nvarchar(10);
	declare @tracktype as nvarchar(50);

	select @operationdate = operationdate, @shift = [shift], @line = [line],@tracktype=TrackType from @TAMS_OCC_DutyRoster where 1=1;
		

	select @count = count(*) from TAMS_OCC_Duty_Roster where UPPER(TrackType)=UPPER(@tracktype) and operationdate = @operationdate and [shift] = @shift and [line] = @line;


	if @count = 0
	begin
		INSERT INTO TAMS_OCC_Duty_Roster(Line,
		TrackType,
		OperationDate,
		[Shift],
		RosterCode,
		DutyStaffId,
		IsActive,
		CreatedOn,
		CreatedBy,
		UpdatedOn,
		UpdatedBy
		)
		SELECT Line,
		TrackType,
		OperationDate,
		[Shift],
		RosterCode,
		DutyStaffId,
		IsActive,
		CreatedOn,
		CreatedBy,
		UpdatedOn,
		UpdatedBy
		FROM @TAMS_OCC_DutyRoster

		INSERT INTO TAMS_OCC_Duty_Roster_Audit(
		ActionBy,
		ActionOn,
		AuditAction,
		DutyRosterId,
		Line,
		TrackType,
		OperationDate,
		[Shift],
		RosterCode,
		DutyStaffId,
		IsActive,
		CreatedOn,
		CreatedBy,
		UpdatedOn,
		UpdatedBy
		)
		SELECT 
		CreatedBy,
		UpdatedOn,
		'I',
		DutyStaffId,
		Line,
		TrackType,
		OperationDate,
		[Shift],
		RosterCode,
		DutyStaffId,
		IsActive,
		CreatedOn,
		CreatedBy,
		UpdatedOn,
		UpdatedBy
		FROM @TAMS_OCC_DutyRoster
	end;
	else
	begin
		update TAMS_OCC_Duty_Roster
		set DutyStaffId = dr.DutyStaffId,
		UpdatedOn = dr.UpdatedOn,
		UpdatedBy = dr.UpdatedBy
		from  @TAMS_OCC_DutyRoster dr
		where TAMS_OCC_Duty_Roster.ID = dr.ID
		and TAMS_OCC_Duty_Roster.Line = dr.Line
		and TAMS_OCC_Duty_Roster.TrackType = dr.TrackType
		and TAMS_OCC_Duty_Roster.OperationDate = dr.operationdate
		and TAMS_OCC_Duty_Roster.[shift] = dr.[shift]
		and TAMS_OCC_Duty_Roster.RosterCode = dr.RosterCode

		INSERT INTO TAMS_OCC_Duty_Roster_Audit(
		ActionBy,
		ActionOn,
		AuditAction,
		DutyRosterId,
		Line,
		TrackType,
		OperationDate,
		[Shift],
		RosterCode,
		DutyStaffId,
		IsActive,
		CreatedOn,
		CreatedBy,
		UpdatedOn,
		UpdatedBy
		)
		SELECT 
		CreatedBy,
		UpdatedOn,
		'U',
		DutyStaffId,
		Line,
		TrackType,
		OperationDate,
		[Shift],
		RosterCode,
		DutyStaffId,
		IsActive,
		CreatedOn,
		CreatedBy,
		UpdatedOn,
		UpdatedBy
		FROM @TAMS_OCC_DutyRoster
	end;
END
GO
/****** END PROCEDURE 243 ******/

