CREATE PROCEDURE [dbo].[sp_TAMS_OCC_InsertToDutyOCCRosterTable_20221116_M]
	@TAMS_OCC_DutyRoster [dbo].[TAMS_OCC_DutyRoster] READONLY
AS
BEGIN

	declare @count as int = 0;
	declare @loop as int = 0;
	declare @operationdate as date;
	declare @shift as nvarchar(1);
	declare @line as nvarchar(10);

	SELECT @operationdate = operationdate, 
		@shift = [shift], 
		@line = [line] 
	FROM @TAMS_OCC_DutyRoster 
		WHERE 1=1;

	SELECT @count = count(*) 
		FROM TAMS_OCC_Duty_Roster 
			WHERE operationdate = @operationdate 
				and [shift] = @shift 
				and [line] = @line;

	if @count = 0
	begin
