		OperationDate,
		[Shift],
		RosterCode,
		DutyStaffId,
		IsActive,
		CreatedOn,
		CreatedBy,
		UpdatedOn,
		UpdatedBy
		)
		SELECT 
		CreatedBy,
		UpdatedOn,
		'I',
		DutyStaffId,
		Line,
		OperationDate,
		[Shift],
		RosterCode,
		DutyStaffId,
		IsActive,
		CreatedOn,
		CreatedBy,
		UpdatedOn,
		UpdatedBy
		FROM @TAMS_OCC_DutyRoster
	end;
	else
	begin
		update TAMS_OCC_Duty_Roster
		set DutyStaffId = dr.DutyStaffId,
		UpdatedOn = dr.UpdatedOn,
		UpdatedBy = dr.UpdatedBy
		from  @TAMS_OCC_DutyRoster dr
		where TAMS_OCC_Duty_Roster.ID = dr.ID
		and TAMS_OCC_Duty_Roster.Line = dr.Line
		and TAMS_OCC_Duty_Roster.OperationDate = dr.operationdate
		and TAMS_OCC_Duty_Roster.[shift] = dr.[shift]
		and TAMS_OCC_Duty_Roster.RosterCode = dr.RosterCode

		INSERT INTO TAMS_OCC_Duty_Roster_Audit(
		ActionBy,
		ActionOn,
		AuditAction,
		DutyRosterId,
		Line,
		OperationDate,
		[Shift],
		RosterCode,
		DutyStaffId,
		IsActive,
		CreatedOn,
		CreatedBy,
		UpdatedOn,
		UpdatedBy
		)
		SELECT 
		CreatedBy,
		UpdatedOn,
		'U',
		DutyStaffId,
		Line,
		OperationDate,
		[Shift],
		RosterCode,
		DutyStaffId,
		IsActive,
		CreatedOn,
		CreatedBy,
		UpdatedOn,
		UpdatedBy
		FROM @TAMS_OCC_DutyRoster
	end;
END
