-- PROCEDURE NAME: dbo.sp_TAMS_OCC_InsertTVFAckByParameters
CREATE PROCEDURE [dbo].[sp_TAMS_OCC_InsertTVFAckByParameters]
	@OperationDate datetime = null,
	@AccessDate datetime = null,
	@UserID as int = 0,
	@StationId as int = 0,	
	@TVFMode as varchar(10) = null,	
	@TVFDirection1 as bit = null,	
	@TVFDirection2 as bit = null



AS
	DECLARE @NewID AS int;
BEGIN
	BEGIN TRY
		BEGIN TRANSACTION;
			INSERT INTO TAMS_TVF_Acknowledge(
			AccessDate,
			OperationDate,
			StationId,
			TVFMode,
			TVFDirection1,
			TVFDirection2,
			AcknowledgedBy,
			AcknowledgedOn,
			VerifiedBy,
			VerifiedOn,
			OperatedBy,
			TVFOnTime,
			CreatedOn,
			CreatedBy,
			UpdatedOn,
			UpdatedBy)
			VALUES (
			@AccessDate,
			@OperationDate,
			@StationId,
			@TVFMode,
			@TVFDirection1,
			@TVFDirection2,
			@UserID,
			GETDATE(),
			NULL,
			NULL,
			NULL,
			NULL,
			GETDATE(),
			@UserID,
			NULL,
			NULL)

			SELECT @NewID = SCOPE_IDENTITY();

			UPDATE TAMS_TVF_Acknowledge
			SET AcknowledgedBy = NULL, AcknowledgedOn = NULL, CreatedOn = NULL, CreatedBy = NULL
			WHERE TVFMode = 'Select'

			INSERT INTO TAMS_TVF_Acknowledge_Audit(
			   [ActionBy]
			  ,[ActionOn]
			  ,[AuditAction]
			  ,[TVFAckId]
			  ,[AccessDate]
			  ,[OperationDate]
			  ,[StationId]
			  ,[TVFMode]
			  ,[TVFDirection1]
			  ,[TVFDirection2]
			  ,[AcknowledgedBy]
			  ,[AcknowledgedOn]
			  ,[VerifiedBy]
			  ,[VerifiedOn]
			  ,[OperatedBy]
			  ,[TVFOnTime]
			  ,[CreatedOn]
			  ,[CreatedBy]
			  ,[UpdatedOn]
			  ,[UpdatedBy])
			  SELECT 
			   @UserID
			  ,GETDATE()
			  ,'A'
			  ,@NewID
			  ,[AccessDate]
			  ,[OperationDate]
			  ,[StationId]
			  ,[TVFMode]
			  ,[TVFDirection1]
			  ,[TVFDirection2]
			  ,[AcknowledgedBy]
			  ,[AcknowledgedOn]
			  ,[VerifiedBy]
			  ,[VerifiedOn]
			  ,[OperatedBy]
			  ,[TVFOnTime]
			  ,[CreatedOn]
			  ,[CreatedBy]
			  ,[UpdatedOn]
			  ,[UpdatedBy]
			  FROM TAMS_TVF_Acknowledge
			  WHERE ID = @NewID

			  --UPDATE TAMS_TVF_Acknowledge_Audit
			  --SET ActionBy = @UserID,
			  --ActionOn = GETDATE(),
			  --AuditAction = 'INSERT',
			  --TVFAckId = @NewID
			  --WHERE TVFAckId = @NewID;

		COMMIT TRANSACTION;
	END TRY
	BEGIN CATCH
		PRINT ERROR_MESSAGE();
		ROLLBACK TRANSACTION;
	END CATCH
END
GO
