	@OCCAuthID		as int,
	@OCCLevel		as int,
	--@OCCEndorserID	as int,
	@Line			AS nvarchar(10),
	@TrackType			AS nvarchar(50),
	@Remarks		as nvarchar(1000),
	@SelectionValue as nvarchar(50)
AS



--GET Operation Date and Access Date 

DECLARE @CurDate		DATE
DECLARE @CurTime		TIME
DECLARE @OperationDate	DATE
DECLARE @AccessDate		DATE
DECLARE @OCCAuthTractionPowerID int;

SELECT @OCCAuthTractionPowerID  = TractionPowerId
FROM TAMS_OCC_Auth 
WHERE ID = @OCCAuthID;

SET @CurDate = GETDATE()
SET @CurTime = CONVERT(TIME, GETDATE(), 108)

DECLARE @CutOff				TIME
DECLARE @TOACallBackTime	NVARCHAR(10)
SET @TOACallBackTime = '04:00'
SET @CutOff = '06:00:00'
IF @CurTime > @CutOff
	BEGIN
		SET @OperationDate	= @CurDate
		SET @AccessDate		= DATEADD(DAY, 1, @CurDate)
	END
ELSE
	BEGIN
		SET @OperationDate	= DATEADD(DAY, -1, @CurDate)
		SET @AccessDate		= @CurDate
	END

IF @Line = 'NEL'
BEGIN
	BEGIN TRY
		BEGIN TRANSACTION;

			DECLARE @OCCEndorserID INT
			DECLARE @OCCEndorserID_Next INT
			DECLARE @WorkflowId INT
			DECLARE @WFStatusId INT

			IF @OCCLevel = 1
				BEGIN
					SELECT @WorkflowId = ID FROM [TAMS_Workflow]
					WHERE Line = @Line
					AND TrackType = @TrackType 
					AND  WorkflowType = 'OCCAuth'
					AND IsActive = 1
					AND EffectiveDate <= GETDATE()
					AND ExpiryDate >= GETDATE()

					SELECT @OCCEndorserID = ID FROM [TAMS_Endorser]
					WHERE WorkflowId = @WorkflowId AND Line = @Line
					AND [Level] = @OCCLevel;

					UPDATE [TAMS_OCC_Auth_Workflow]
					SET [WFStatus] = 'Completed', [ActionOn] = GETDATE(), [ActionBy] = @UserID
					WHERE [OCCAuthId] = @OCCAuthID AND [OCCAuthEndorserId] = @OCCEndorserID

					SELECT @OCCEndorserID_Next = ID, @WFStatusId = WFStatusId
					FROM [dbo].[TAMS_Endorser]
					WHERE Line = @Line
					AND WorkflowId = @WorkflowId
					AND [Level] = @OCCLevel + 1;

					INSERT INTO [TAMS_OCC_Auth_Workflow](OCCAuthId, OCCAuthEndorserId, WFStatus, StationId, FISTestResult, ActionOn, ActionBy)
					VALUES (@OCCAuthID, @OCCEndorserID_Next, 'Pending', 0, NULL, '1900-01-01 00:00:00', 1)

					UPDATE [TAMS_OCC_Auth]
					SET [OCCAuthStatusId] = @WFStatusId, [Remark] = @Remarks, [UpdatedOn] = GETDATE(), [UpdatedBy] = @UserID
					WHERE ID = @OCCAuthID;
				END; 

			IF @OCCLevel = 2
				BEGIN
					SELECT @WorkflowId = ID FROM [TAMS_Workflow]
					WHERE Line = @Line
					AND TrackType = @TrackType
					AND  WorkflowType = 'OCCAuth'
					AND IsActive = 1
					AND EffectiveDate <= GETDATE()
					AND ExpiryDate >= GETDATE()

					SELECT @OCCEndorserID = ID FROM [TAMS_Endorser]
					WHERE WorkflowId = @WorkflowId AND Line = @Line
					AND [Level] = @OCCLevel;

					UPDATE [TAMS_OCC_Auth_Workflow]
					SET [WFStatus] = 'Completed', [ActionOn] = GETDATE(), [ActionBy] = @UserID
					WHERE [OCCAuthId] = @OCCAuthID AND [OCCAuthEndorserId] = @OCCEndorserID

					SELECT @OCCEndorserID_Next = ID, @WFStatusId = WFStatusId
					FROM [dbo].[TAMS_Endorser]
					WHERE Line = @Line
					AND WorkflowId = @WorkflowId
					AND [Level] = @OCCLevel + 1;

					INSERT INTO [TAMS_OCC_Auth_Workflow](OCCAuthId, OCCAuthEndorserId, WFStatus, StationId, FISTestResult, ActionOn, ActionBy)
					VALUES (@OCCAuthID, @OCCEndorserID_Next, 'Pending', 0, NULL, '1900-01-01 00:00:00', 1)

					UPDATE [TAMS_OCC_Auth]
					SET [OCCAuthStatusId] = @WFStatusId, [Remark] = @Remarks, [UpdatedOn] = GETDATE(), [UpdatedBy] = @UserID
					WHERE ID = @OCCAuthID;
				END;

			IF @OCCLevel = 3
				BEGIN
					SELECT @WorkflowId = ID FROM [TAMS_Workflow]
					WHERE Line = @Line
					AND TrackType = @TrackType
					AND  WorkflowType = 'OCCAuth'
					AND IsActive = 1
					AND EffectiveDate <= GETDATE()
					AND ExpiryDate >= GETDATE()

					SELECT @OCCEndorserID = ID FROM [TAMS_Endorser]
					WHERE WorkflowId = @WorkflowId AND Line = @Line
					AND [Level] = @OCCLevel;

					UPDATE [TAMS_OCC_Auth_Workflow]
					SET [WFStatus] = @SelectionValue, [ActionOn] = GETDATE(), [ActionBy] = @UserID
					WHERE [OCCAuthId] = @OCCAuthID AND [OCCAuthEndorserId] = @OCCEndorserID

					SELECT @OCCEndorserID_Next = ID, @WFStatusId = WFStatusId
					FROM [dbo].[TAMS_Endorser]
					WHERE Line = @Line
					AND WorkflowId = @WorkflowId
					AND [Level] = @OCCLevel + 1;

					INSERT INTO [TAMS_OCC_Auth_Workflow](OCCAuthId, OCCAuthEndorserId, WFStatus, StationId, FISTestResult, ActionOn, ActionBy)
					VALUES (@OCCAuthID, @OCCEndorserID_Next, 'Pending', 0, NULL, '1900-01-01 00:00:00', 1)

					UPDATE [TAMS_OCC_Auth]
					SET [OCCAuthStatusId] = @WFStatusId, [Remark] = @Remarks, [UpdatedOn] = GETDATE(), [UpdatedBy] = @UserID
					WHERE ID = @OCCAuthID;
				END;

			IF @OCCLevel = 4
				BEGIN
					SELECT @WorkflowId = ID FROM [TAMS_Workflow]
					WHERE Line = @Line
					AND TrackType = @TrackType
					AND  WorkflowType = 'OCCAuth'
					AND IsActive = 1
					AND EffectiveDate <= GETDATE()
					AND ExpiryDate >= GETDATE()

					SELECT @OCCEndorserID = ID FROM [TAMS_Endorser]
					WHERE WorkflowId = @WorkflowId AND Line = @Line
					AND [Level] = @OCCLevel;

					--UPDATE [TAMS_OCC_Auth_Workflow]
					--SET [WFStatus] = 'Completed', [ActionOn] = GETDATE(), [ActionBy] = @UserID
					--WHERE [OCCAuthId] = @OCCAuthID AND [OCCAuthEndorserId] = @OCCEndorserID

					UPDATE [TAMS_OCC_Auth_Workflow]
					SET [WFStatus] = @SelectionValue, [ActionOn] = GETDATE(), [ActionBy] = @UserID
					WHERE [OCCAuthId] = @OCCAuthID AND [OCCAuthEndorserId] = @OCCEndorserID

					SELECT @OCCEndorserID_Next = ID, @WFStatusId = WFStatusId
					FROM [dbo].[TAMS_Endorser]
					WHERE Line = @Line
					AND WorkflowId = @WorkflowId
					AND [Level] = @OCCLevel + 1;

					INSERT INTO [TAMS_OCC_Auth_Workflow](OCCAuthId, OCCAuthEndorserId, WFStatus, StationId, FISTestResult, ActionOn, ActionBy)
					VALUES (@OCCAuthID, @OCCEndorserID_Next, 'Pending', 0, NULL, '1900-01-01 00:00:00', 1)


					-- apply the same logic to Power Off 
					IF @SelectionValue = 'Completed'
						BEGIN
							UPDATE [TAMS_OCC_Auth]
								SET [OCCAuthStatusId] = @WFStatusId, 
									[Remark] = @Remarks, 
									[PowerOffTime] = GETDATE(), 
									[PowerOffType] = @SelectionValue,
									[UpdatedOn] = GETDATE(), 
									[UpdatedBy] = @UserID
							WHERE ID = @OCCAuthID;
						END
					ELSE
						BEGIN
							UPDATE [TAMS_OCC_Auth]
								SET [OCCAuthStatusId] = @WFStatusId, 
									[Remark] = @Remarks, 
									[PowerOffTime] = NULL, 
									[PowerOffType] = @SelectionValue,
									[UpdatedOn] = GETDATE(), 
									[UpdatedBy] = @UserID
							WHERE ID = @OCCAuthID;
						END

					
				END;

			IF @OCCLevel = 5
				BEGIN
					SELECT @WorkflowId = ID FROM [TAMS_Workflow]
					WHERE Line = @Line
					AND TrackType = @TrackType
					AND  WorkflowType = 'OCCAuth'
					AND IsActive = 1
					AND EffectiveDate <= GETDATE()
					AND ExpiryDate >= GETDATE()

					SELECT @OCCEndorserID = ID FROM [TAMS_Endorser]
					WHERE WorkflowId = @WorkflowId AND Line = @Line
					AND [Level] = @OCCLevel;

					UPDATE [TAMS_OCC_Auth_Workflow]
					SET [WFStatus] = @SelectionValue, [ActionOn] = GETDATE(), [ActionBy] = @UserID
					WHERE [OCCAuthId] = @OCCAuthID AND [OCCAuthEndorserId] = @OCCEndorserID

					SELECT @OCCEndorserID_Next = ID, @WFStatusId = WFStatusId
					FROM [dbo].[TAMS_Endorser]
					WHERE Line = @Line
					AND WorkflowId = @WorkflowId
					AND [Level] = @OCCLevel + 1;

					INSERT INTO [TAMS_OCC_Auth_Workflow](OCCAuthId, OCCAuthEndorserId, WFStatus, StationId, FISTestResult, ActionOn, ActionBy)
					VALUES (@OCCAuthID, @OCCEndorserID_Next, 'Pending', 0, NULL, '1900-01-01 00:00:00', 1)

					-- >> Jeffrey 2023-02-10
					IF @SelectionValue = 'Completed'
						BEGIN
							UPDATE [TAMS_OCC_Auth]
								SET [OCCAuthStatusId] = @WFStatusId, 
									[Remark] = @Remarks, 
									[RackedOutTime] = GETDATE(), 
									[RackedOutType] = @SelectionValue,
									[UpdatedOn] = GETDATE(), 
									[UpdatedBy] = @UserID
							WHERE ID = @OCCAuthID;
						END
					ELSE
						BEGIN
							UPDATE [TAMS_OCC_Auth]
								SET [OCCAuthStatusId] = @WFStatusId, 
									[Remark] = @Remarks, 
									[RackedOutTime] = NULL, 
									[RackedOutType] = @SelectionValue,
									[UpdatedOn] = GETDATE(), 
									[UpdatedBy] = @UserID
							WHERE ID = @OCCAuthID;
						END
				END;

			IF @OCCLevel = 6
				BEGIN
					SELECT @WorkflowId = ID FROM [TAMS_Workflow]
					WHERE Line = @Line
					AND TrackType = @TrackType
					AND  WorkflowType = 'OCCAuth'
					AND IsActive = 1
					AND EffectiveDate <= GETDATE()
					AND ExpiryDate >= GETDATE()

					SELECT @OCCEndorserID = ID FROM [TAMS_Endorser]
					WHERE WorkflowId = @WorkflowId AND Line = @Line
					AND [Level] = @OCCLevel;

					UPDATE [TAMS_OCC_Auth_Workflow]
					SET [WFStatus] = 'Completed', [ActionOn] = GETDATE(), [ActionBy] = @UserID
					WHERE [OCCAuthId] = @OCCAuthID AND [OCCAuthEndorserId] = @OCCEndorserID

					SELECT @OCCEndorserID_Next = ID, @WFStatusId = WFStatusId
					FROM [dbo].[TAMS_Endorser]
					WHERE Line = @Line
					AND WorkflowId = @WorkflowId
