					INSERT INTO [TAMS_OCC_Auth_Workflow](OCCAuthId, OCCAuthEndorserId, WFStatus, StationId, FISTestResult, ActionOn, ActionBy)
					VALUES (@OCCAuthID, @OCCEndorserID_Next, 'Pending', 0, NULL, '1900-01-01 00:00:00', 1)

					UPDATE [TAMS_OCC_Auth]
					SET [OCCAuthStatusId] = 7, [Remark] = @Remarks, [UpdatedOn] = GETDATE(), [UpdatedBy] = @UserID
					WHERE ID = @OCCAuthID;
				END;

			IF @OCCLevel = 7	-- >>> 
				BEGIN
					SELECT @WorkflowId = ID FROM [TAMS_Workflow]
					WHERE Line = @Line
					AND TrackType = @TrackType
					AND  WorkflowType = 'OCCAuth'
					AND IsActive = 1
					AND EffectiveDate <= GETDATE()
					AND ExpiryDate >= GETDATE()

					SELECT @OCCEndorserID = ID FROM [TAMS_Endorser]
					WHERE WorkflowId = @WorkflowId AND Line = @Line
					AND [Level] = @OCCLevel;

					UPDATE [TAMS_OCC_Auth_Workflow]
					SET [WFStatus] = 'Completed', [ActionOn] = GETDATE(), [ActionBy] = @UserID
					WHERE [OCCAuthId] = @OCCAuthID AND [OCCAuthEndorserId] = @OCCEndorserID

					SELECT @OCCEndorserID_Next = ID, @WFStatusId = WFStatusId
					FROM [dbo].[TAMS_Endorser]
					WHERE Line = @Line
					AND WorkflowId = @WorkflowId
					AND [Level] = @OCCLevel + 1;

					/* To check if the sector has TAR or Surrendered TAR, it will auto start the 1nd phase of workflow. */
					 if( --***************NO TAR under selected Power sector*************/
						(SELECT count(a.ID )
						FROM   TAMS_TAR a
						left join TAMS_TAR_Power_Sector c ON a.Id = c.TARId
						WHERE   a.AccessDate = @AccessDate
						AND c.PowerSectorId in (Select PowerSectionId From TAMS_Traction_Power_Detail WHERE TractionPowerId = @OCCAuthTractionPowerID ))=0
					 )
					 begin  
						print 'NO TAR under selected sector ';
						   INSERT INTO [TAMS_OCC_Auth_Workflow](OCCAuthId, OCCAuthEndorserId, WFStatus, StationId, FISTestResult, ActionOn, ActionBy)
						  VALUES (@OCCAuthID, @OCCEndorserID_Next, 'Pending', 0, NULL, '1900-01-01 00:00:00', 1)
						  UPDATE [TAMS_OCC_Auth]
							SET [OCCAuthStatusId] = 8, [Remark] = @Remarks, [UpdatedOn] = GETDATE(), [UpdatedBy] = @UserID
							WHERE ID = @OCCAuthID;
					 end;
					 else 
					 begin 
						print 'There is TAR under selected sector';
						if(
							Select count(t.ID ) From TAMS_TOA t WHERE t.TARId in (
							(SELECT a.ID
							FROM   TAMS_TAR a
							left join TAMS_TAR_Power_Sector c ON a.Id = c.TARId
							WHERE   a.AccessDate = @AccessDate
							AND c.PowerSectorId in (Select PowerSectionId From TAMS_Traction_Power_Detail WHERE TractionPowerId = @OCCAuthTractionPowerID )
							))) = 0
						begin 
							print 'But NO TOA registeration ';
							 INSERT INTO [TAMS_OCC_Auth_Workflow](OCCAuthId, OCCAuthEndorserId, WFStatus, StationId, FISTestResult, ActionOn, ActionBy)
						  VALUES (@OCCAuthID, @OCCEndorserID_Next, 'Pending', 0, NULL, '1900-01-01 00:00:00', 1)
						  UPDATE [TAMS_OCC_Auth]
							SET [OCCAuthStatusId] = 8, [Remark] = @Remarks, [UpdatedOn] = GETDATE(), [UpdatedBy] = @UserID
							WHERE ID = @OCCAuthID;
						end;
						else
						begin 
							print 'There is TOA registeration ';
							if(
							Select count(t.ID ) From TAMS_TOA t WHERE t.TARId in (
							(SELECT a.ID
							FROM   TAMS_TAR a
							left join TAMS_TAR_Power_Sector c ON a.Id = c.TARId
							WHERE   a.AccessDate = @AccessDate
							AND c.PowerSectorId in (Select PowerSectionId From TAMS_Traction_Power_Detail WHERE TractionPowerId = @OCCAuthTractionPowerID )
							))  
							AND (t.TOAStatus != 0 and t.TOAStatus != 6 and t.TOAStatus != 5 )) > 0
							begin 
								print ' TOA in progress';
							end;
							else
							begin
								print  ' TOA is Cancelled/Draft or Acknowledged Surrender';
								 INSERT INTO [TAMS_OCC_Auth_Workflow](OCCAuthId, OCCAuthEndorserId, WFStatus, StationId, FISTestResult, ActionOn, ActionBy)
								  VALUES (@OCCAuthID, @OCCEndorserID_Next, 'Pending', 0, NULL, '1900-01-01 00:00:00', 1)
								  UPDATE [TAMS_OCC_Auth]
									SET [OCCAuthStatusId] = 8, [Remark] = @Remarks, [UpdatedOn] = GETDATE(), [UpdatedBy] = @UserID
									WHERE ID = @OCCAuthID;
							end;
						end;

					 
					 end;
				  	UPDATE [TAMS_OCC_Auth]
					SET  [OCCAuthStatusId] = 8, [Remark] = @Remarks, [UpdatedOn] = GETDATE(), [UpdatedBy] = @UserID
					WHERE ID = @OCCAuthID;
					 
					
				END;


			IF @OCCLevel = 8
				BEGIN
					SELECT @WorkflowId = ID FROM [TAMS_Workflow]
					WHERE Line = @Line
					AND TrackType = @TrackType
					AND  WorkflowType = 'OCCAuth'
					AND IsActive = 1
