/****** START PROCEDURE 256 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_OCC_UpdateOCCAuthorisationTCByParameters
CREATE procedure  [dbo].[sp_TAMS_OCC_UpdateOCCAuthorisationTCByParameters]
	@UserID			as int,
	@OCCAuthID		as int,
	@OCCLevel		as int,
	--@OCCEndorserID	as int,
	@Line			AS nvarchar(10),
	@TrackType			AS nvarchar(50),
	@SelectionValue as nvarchar(50)

AS


IF @Line = 'DTL'
BEGIN
	BEGIN TRY
		BEGIN TRANSACTION;

			DECLARE @OCCEndorserID INT
			DECLARE @OCCEndorserID_Next INT
			DECLARE @WorkflowId INT
			DECLARE @WFStatusId INT

			IF @OCCLevel = 1
			BEGIN

				SELECT @WorkflowId = ID FROM [TAMS_Workflow]
				WHERE Line = @Line
				and TrackType = @TrackType
				AND  WorkflowType = 'OCCAuth'
				AND IsActive = 1
				AND EffectiveDate <= GETDATE()
				AND ExpiryDate >= GETDATE()
				
				SELECT @OCCEndorserID = ID FROM [TAMS_Endorser]
				WHERE WorkflowId = @WorkflowId AND Line = @Line
				AND [Level] = @OCCLevel;

				UPDATE [TAMS_OCC_Auth_Workflow]
				SET [WFStatus] = 'Completed', [ActionOn] = GETDATE(), [ActionBy] = @UserID
				WHERE [OCCAuthId] = @OCCAuthID AND [OCCAuthEndorserId] = @OCCEndorserID

				SELECT @OCCEndorserID_Next = ID, @WFStatusId = WFStatusId
				FROM [dbo].[TAMS_Endorser]
				WHERE Line = @Line
				AND WorkflowId = @WorkflowId
				AND [Level] = @OCCLevel + 1;

				INSERT INTO [TAMS_OCC_Auth_Workflow](OCCAuthId, OCCAuthEndorserId, WFStatus, StationId, FISTestResult, ActionOn, ActionBy)
				VALUES (@OCCAuthID, @OCCEndorserID_Next, 'Pending', 0, NULL, '1900-01-01 00:00:00', 1)

				UPDATE [TAMS_OCC_Auth]
				SET [OCCAuthStatusId] = @WFStatusId, [UpdatedOn] = GETDATE(), [UpdatedBy] = @UserID
				WHERE ID = @OCCAuthID;
			END; 

			IF @OCCLevel = 9
			BEGIN
				SELECT @WorkflowId = ID FROM [TAMS_Workflow]
				WHERE Line = @Line
				and TrackType = @TrackType
				AND  WorkflowType = 'OCCAuth'
				AND IsActive = 1
				AND EffectiveDate <= GETDATE()
				AND ExpiryDate >= GETDATE()

				SELECT @OCCEndorserID = ID FROM [TAMS_Endorser]
				WHERE WorkflowId = @WorkflowId AND Line = @Line
				AND [Level] = @OCCLevel;

				UPDATE [TAMS_OCC_Auth_Workflow]
				SET [WFStatus] = 'Completed', [ActionOn] = GETDATE(), [ActionBy] = @UserID
				WHERE [OCCAuthId] = @OCCAuthID AND [OCCAuthEndorserId] = @OCCEndorserID

				SELECT @OCCEndorserID_Next = ID, @WFStatusId = WFStatusId
				FROM [dbo].[TAMS_Endorser]
				WHERE Line = @Line
				AND WorkflowId = @WorkflowId
				AND [Level] = @OCCLevel + 1;

				/*To remove */
				--INSERT INTO [TAMS_OCC_Auth_Workflow](OCCAuthId, OCCAuthEndorserId, WFStatus, StationId, FISTestResult, ActionOn, ActionBy)
				--VALUES (@OCCAuthID, @OCCEndorserID_Next, 'Pending', 0, NULL, '1900-01-01 00:00:00', 1)

				UPDATE [TAMS_OCC_Auth]
				SET [OCCAuthStatusId] = 10, [UpdatedOn] = GETDATE(), [UpdatedBy] = @UserID
				WHERE ID = @OCCAuthID;
			END;

			IF @OCCLevel = 10
			BEGIN
				SELECT @WorkflowId = ID FROM [TAMS_Workflow]
				WHERE Line = @Line
				and TrackType = @TrackType
				AND  WorkflowType = 'OCCAuth'
				AND IsActive = 1
				AND EffectiveDate <= GETDATE()
				AND ExpiryDate >= GETDATE()

				SELECT @OCCEndorserID = ID FROM [TAMS_Endorser]
				WHERE WorkflowId = @WorkflowId AND Line = @Line
				AND [Level] = @OCCLevel;

				UPDATE [TAMS_OCC_Auth_Workflow]
				SET [WFStatus] = 'Completed', [ActionOn] = GETDATE(), [ActionBy] = @UserID
				WHERE [OCCAuthId] = @OCCAuthID AND [OCCAuthEndorserId] = @OCCEndorserID

				SELECT @OCCEndorserID_Next = ID, @WFStatusId = WFStatusId
				FROM [dbo].[TAMS_Endorser]
				WHERE Line = @Line
				AND WorkflowId = @WorkflowId
				AND [Level] = @OCCLevel + 1;

				INSERT INTO [TAMS_OCC_Auth_Workflow](OCCAuthId, OCCAuthEndorserId, WFStatus, StationId, FISTestResult, ActionOn, ActionBy)
				VALUES (@OCCAuthID, @OCCEndorserID_Next, 'Pending', 0, NULL, '1900-01-01 00:00:00', 1)

				/* To remove */
				--UPDATE [TAMS_OCC_Auth]
				--SET [OCCAuthStatusId] = 11, [UpdatedOn] = GETDATE(), [UpdatedBy] = @UserID
				--WHERE ID = @OCCAuthID;
			END;

			IF @OCCLevel = 11
			BEGIN
				SELECT @WorkflowId = ID FROM [TAMS_Workflow]
				WHERE Line = @Line
				and TrackType = @TrackType
				AND  WorkflowType = 'OCCAuth'
				AND IsActive = 1
				AND EffectiveDate <= GETDATE()
				AND ExpiryDate >= GETDATE()

				SELECT @OCCEndorserID = ID FROM [TAMS_Endorser]
				WHERE WorkflowId = @WorkflowId AND Line = @Line
				AND [Level] = @OCCLevel;

				UPDATE [TAMS_OCC_Auth_Workflow]
				SET [WFStatus] = @SelectionValue, [ActionOn] = GETDATE(), [ActionBy] = @UserID
				WHERE [OCCAuthId] = @OCCAuthID AND [OCCAuthEndorserId] = @OCCEndorserID

				SELECT @OCCEndorserID_Next = ID, @WFStatusId = WFStatusId
				FROM [dbo].[TAMS_Endorser]
				WHERE Line = @Line
				AND WorkflowId = @WorkflowId
				AND [Level] = @OCCLevel + 1;

				SELECT @WFStatusId = WFStatusId
				FROM [dbo].[TAMS_Endorser]
				WHERE Line = @Line
				AND WorkflowId = @WorkflowId
				AND [Level] = @OCCLevel

				INSERT INTO [TAMS_OCC_Auth_Workflow](OCCAuthId, OCCAuthEndorserId, WFStatus, StationId, FISTestResult, ActionOn, ActionBy)
				VALUES (@OCCAuthID, @OCCEndorserID_Next, 'Pending', 0, NULL, '1900-01-01 00:00:00', 1)

				UPDATE [TAMS_OCC_Auth]
				SET [OCCAuthStatusId] = @WFStatusId, [UpdatedOn] = GETDATE(), [UpdatedBy] = @UserID
				WHERE ID = @OCCAuthID;
			END;
			IF @OCCLevel = 20
			BEGIN
				SELECT @WorkflowId = ID FROM [TAMS_Workflow]
				WHERE Line = @Line
				and TrackType = @TrackType
				AND  WorkflowType = 'OCCAuth'
				AND IsActive = 1
				AND EffectiveDate <= GETDATE()
				AND ExpiryDate >= GETDATE()

				SELECT @OCCEndorserID = ID FROM [TAMS_Endorser]
				WHERE WorkflowId = @WorkflowId AND Line = @Line
				AND [Level] = @OCCLevel;

				UPDATE [TAMS_OCC_Auth_Workflow]
				SET [WFStatus] = 'Completed', [ActionOn] = GETDATE(), [ActionBy] = @UserID
				WHERE [OCCAuthId] = @OCCAuthID AND [OCCAuthEndorserId] = @OCCEndorserID



				--SELECT @OCCEndorserID_Next = ID
				--FROM [dbo].[TAMS_Endorser]
				--WHERE Line = @Line
				--AND WorkflowId = @WorkflowId
				--AND [Level] = 21;

				--INSERT INTO [TAMS_OCC_Auth_Workflow](OCCAuthId, OCCAuthEndorserId, WFStatus, StationId, FISTestResult, ActionOn, ActionBy)
				--VALUES (@OCCAuthID, @OCCEndorserID_Next, 'Pending', 0, NULL, '1900-01-01 00:00:00', 1)

				--UPDATE [TAMS_OCC_Auth]
				--SET [OCCAuthStatusId] = 21, [UpdatedOn] = GETDATE(), [UpdatedBy] = @UserID
				--WHERE ID = @OCCAuthID;
			END;

			SET @OCCLevel = 0;


				-- >> Insert to Audit
				INSERT INTO [dbo].[TAMS_OCC_Auth_Workflow_Audit]
				([AuditActionBy], [AuditActionOn], [AuditAction], 
					[OCCAuthWorkflowID], [OCCAuthId], [OCCAuthEndorserId], [WFStatus], [StationId], [FISTestResult], [ActionOn], [ActionBy])
				SELECT @UserID, GETDATE(), 'U', 
					[ID], [OCCAuthId], [OCCAuthEndorserId], [WFStatus], [StationId], [FISTestResult], [ActionOn], [ActionBy]
					FROM [dbo].[TAMS_OCC_Auth_Workflow]
						WHERE OCCAuthId = @OCCAuthID AND [OCCAuthEndorserId] = @OCCEndorserID
				-- >> Insert to Audit

				-- >> Insert to Audit
				INSERT INTO [dbo].[TAMS_OCC_Auth_Workflow_Audit]
				([AuditActionBy], [AuditActionOn], [AuditAction], 
					[OCCAuthWorkflowID], [OCCAuthId], [OCCAuthEndorserId], [WFStatus], [StationId], [FISTestResult], [ActionOn], [ActionBy])
				SELECT @UserID, GETDATE(), 'I', 
					[ID], [OCCAuthId], [OCCAuthEndorserId], [WFStatus], [StationId], [FISTestResult], [ActionOn], [ActionBy]
					FROM [dbo].[TAMS_OCC_Auth_Workflow]
						WHERE OCCAuthId = @OCCAuthID AND [OCCAuthEndorserId] = @OCCEndorserID_Next AND WFStatus = 'Pending'
				-- >> Insert to Audit

				-- >> Insert to Audit
				INSERT INTO [dbo].[TAMS_OCC_Auth_Audit]
				([ActionBy], [ActionOn], [AuditAction], 
					[OCCAuthID], [Line], [OperationDate], [AccessDate], [TractionPowerId], [Remark], [PFRRemark], 
					[OCCAuthStatusId], [IsBuffer], [PowerOn], [PowerOffTime], [RackedOutTime], 
					[CreatedOn], [CreatedBy], [UpdatedOn], [UpdatedBy])
				SELECT @UserID, GETDATE(), 'U',
					[ID], [Line], [OperationDate], [AccessDate], [TractionPowerId], [Remark], [PFRRemark],
					[OCCAuthStatusId], [IsBuffer], [PowerOn], [PowerOffTime], [RackedOutTime],
					[CreatedOn], [CreatedBy], [UpdatedOn], [UpdatedBy]
				  FROM [dbo].[TAMS_OCC_Auth]
						WHERE ID = @OCCAuthID
				-- >> Insert to Audit

		COMMIT TRANSACTION;
	END TRY
	BEGIN CATCH
		ROLLBACK TRANSACTION;
	END CATCH

END


GO
