/****** START PROCEDURE 259 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_OPD_OnLoad
CREATE PROCEDURE  [dbo].[sp_TAMS_OPD_OnLoad]
	@Line		NVARCHAR(20) = NULL,
	@TrackType		NVARCHAR(50) = NULL
AS

BEGIN

DECLARE @CurDate		DATE
DECLARE @CurTime		TIME
DECLARE @OperationDate	DATE
DECLARE @AccessDate		DATE
DECLARE @AccessDateStr	NVARCHAR(20)

SET @CurDate = GETDATE()
SET @CurTime = CONVERT(TIME, GETDATE(), 108)

DECLARE @CutOff	TIME

SET @CutOff = '06:00:00'

IF @CurTime > @CutOff
	BEGIN
		SET @OperationDate	= @CurDate
		SET @AccessDate		= DATEADD(DAY, 1, @CurDate)
	END
ELSE
	BEGIN
		SET @OperationDate	= DATEADD(DAY, -1, @CurDate)
		SET @AccessDate		= @CurDate
	END

SET @AccessDateStr = CONVERT(NVARCHAR(20), @AccessDate, 103)

CREATE TABLE #TmpOPD
(DirID				INT,
Dir					NVARCHAR(10),
SectorID			BIGINT,
Sector				NVARCHAR(100),
DHorizontalX		BIGINT,
DHorizontalY		BIGINT,
DHorizontalWidth	BIGINT,
DHorizontalHeight	BIGINT,
TARInformation		NVARCHAR(4000),
BGColor				NVARCHAR(50))

TRUNCATE TABLE #TmpOPD

INSERT INTO #TmpOPD
SELECT CASE WHEN @Line = 'DTL' THEN 
		CASE WHEN a.Direction = 'BB' THEN 1 ELSE 2 END 
		ELSE CASE WHEN a.Direction = 'NB' THEN 1 ELSE 2 END END AS DirID,
		a.Direction,
		a.ID,
		a.Sector,
		b.DHorizontalX,
		b.DHorizontalY,
		b.DHorizontalWidth,
		b.DHorizontalHeight,
		--CASE WHEN a.IsGap = 1 THEN '' ELSE
		--	ISNULL((SELECT [VALUE] FROM dbo.SPLIT(';', dbo.TAMS_Get_TOA_WPCount(@Line, a.ID, @AccessDateStr)) WHERE ROWID = 2), '') END,
		ISNULL((SELECT [VALUE] FROM dbo.SPLIT(';', dbo.TAMS_Get_TOA_WPCount(@Line, a.ID, @AccessDateStr)) WHERE ROWID = 2), ''),
		ISNULL((SELECT [VALUE] FROM dbo.SPLIT(';', dbo.TAMS_Get_TOA_WPCount(@Line, a.ID, @AccessDateStr)) WHERE ROWID = 1), '')
	FROM TAMS_Sector a, TAMS_Track_Coordinates b
		WHERE a.ID = b.SectorId
			AND a.Line = @Line
			and a.TrackType = @TrackType

-- >> Dir2 Above
SELECT * 
	FROM #TmpOPD
		WHERE DirID = CASE WHEN @Line = 'DTL' THEN 2 ELSE 1 END
			AND DHorizontalX <> 0
	ORDER BY SectorID ASC

-- >> Dir1 Below
SELECT * 
	FROM #TmpOPD
		WHERE DirID = CASE WHEN @Line = 'DTL' THEN 1 ELSE 2 END
			AND DHorizontalX <> 0
	ORDER BY SectorID ASC

SELECT CONVERT(NVARCHAR(20), @OperationDate, 103) AS OperationDate,  
	CONVERT(NVARCHAR(20), @AccessDate, 103) AS AccessDate

DROP TABLE #TmpOPD

END

GO
/****** END PROCEDURE 259 ******/

/****** START PROCEDURE 260 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_Reject_UserRegistrationRequestByRegModID
CREATE PROCEDURE [dbo].[sp_TAMS_Reject_UserRegistrationRequestByRegModID] 	
	@RegModID			INT,
	@UpdatedBy			INT
AS
BEGIN
	--BEGIN TRY
	--	BEGIN TRANSACTION;
		DECLARE @Line NVARCHAR(10);
		DECLARE @Module NVARCHAR(10);
		DECLARE @RegID INT;
		DECLARE @RegStatusID INT;
		DECLARE @WFStatus NVARCHAR(100);

		SELECT @RegID = RegID, @Line = Line, @Module = Module, @RegStatusID = RegStatus 
			FROM TAMS_Reg_Module WHERE ID = @RegModID;

		SELECT @WFStatus = WFStatus FROM TAMS_WFStatus WHERE ID = @RegStatusID;
		 
		-- If status still at Pending Company Registration || Pending Company Approval, reject the entire request. 
		IF @WFStatus = 'Pending Company Registration' OR @WFStatus = 'Pending Company Approval'
		BEGIN
			DECLARE @cLine NVARCHAR(10);
			DECLARE @cModule NVARCHAR(10);
			DECLARE @cRegModID INT;
			DECLARE @cRegStatus INT;

			DECLARE cur CURSOR FOR 
			SELECT ID, Line, Module, RegStatus FROM TAMS_Reg_Module WHERE RegID = @RegID;

			OPEN cur;
			FETCH NEXT FROM cur INTO @cRegModID, @cLine, @cModule, @cRegStatus

			DECLARE @Sender NVARCHAR (100);
			DECLARE @SysID NVARCHAR(10);
			DECLARE @Subject NVARCHAR(500);    
			DECLARE @Sys NVARCHAR(100);
			DECLARE @Greetings  NVARCHAR(20);     
			DECLARE @ToList NVARCHAR(MAX);
			DECLARE @CCList NVARCHAR(MAX);
			DECLARE @BCCList NVARCHAR(MAX);
			DECLARE @Separator NVARCHAR(10);        
			DECLARE @AlertMsg NVARCHAR(MAX);
			DECLARE @AlertID AS INTEGER; 

			DECLARE @Body VARCHAR(max);
			DECLARE @Body1 VARCHAR(max);
			DECLARE @Body2 VARCHAR(max);
			DECLARE @Body3 VARCHAR(max);
			DECLARE @Link NVARCHAR(MAX);

			DECLARE @LoginPage	NVARCHAR(500)
					
			DECLARE @SendTo	NVARCHAR(200);	

			WHILE @@FETCH_STATUS = 0
			BEGIN
				DECLARE @NextStageTitle NVARCHAR(100);
				DECLARE @NextStageID	INT;

				-- Reject straight to last stage. Hard Coded to Company Rejected
				SELECT @NextStageID = ID
				FROM TAMS_WFStatus 
				WHERE WFType = 'UserRegStatus' 
				AND Line = (SELECT Line FROM TAMS_Reg_Module WHERE ID = @cRegModID)
				AND WFStatus = 'Company Rejected'

				UPDATE TAMS_Reg_Module 
				SET RegStatus = @NextStageID, 
					WFStatus = 'Rejected',
					UpdatedOn = GETDATE(), 
					UpdatedBy = @UpdatedBy 
				WHERE ID = @cRegModID

				-- Sends email
				-- Get Send to list
				SELECT @ToList = Email FROM TAMS_Registration WHERE ID = @RegID;
			

				SET @Sender = 'TAMS Admin';
				SET @SysID = 'TAMS';
				SET @Subject = 'For your information: Company Registration has been rejected.'
				SET @Sys = 'Track Access Management System'   
				SET @Greetings = 'Dear Sir/Madam, '  
				--SET @ToList = ''
				SET @CCList = ''   
				SET @BCCList = ''
				SET @Separator = ','    
				SET @CCList = ''
				--SET @ToList = '';

				SET @Body1 = ''
				SET @Body2 = ''
				SET @Body3 = ''
			
				SET @Body1 = @Body1 + '<table width="100%">'
				SET @Body1 = @Body1 + '<tr align="left" valign="middle" style="font-size:10pt; font-face:Arial;">'
				SET @Body1 = @Body1 + '<td>Please be informed that your company registration has been rejected. Thus, your User application has also been rejected. You will need to reapply for User registration.</td>'
				SET @Body1 = @Body1 + '</tr>'
				SET @Body1 = @Body1 + '</table>'
 
				SET @Body3 = @Body3 + '<br>'
				SET @Body3 = @Body3 + '<table width="100%">'
				SET @Body3 = @Body3 + '<tr align="left" valign="middle" style="font-size:10pt; font-face:Arial;">'
				SET @Body3 = @Body3 + '<td>***********************************************<br>Do Not reply. This is a computer generated Email. <br>***********************************************</td>'
				SET @Body3 = @Body3 + '</tr>'
				SET @Body3 = @Body3 + '</table>'

				SET @Body = ''
				SET @Body = @Body1 + @Body2 + @Body3

				SET @BCCList = ''

				EXEC [dbo].EAlertQ_EnQueue 
					@Sender = @Sender, 
					@UserId = @SysID, 
					@Subject = @Subject,        
					@Sys = @Sys,  
					@Greetings = @Greetings, 
					@AlertMsg = @Body, 
					@SendTo = @ToList,        
					@CC = @CCList, 
					@BCC= @BCCList, 
					@Separator = @Separator, 
					@AlertID =  @AlertID output

				FETCH NEXT FROM cur INTO @cRegModID, @cLine, @cModule, @cRegStatus
			END;

			CLOSE cur;
			DEALLOCATE cur;

			-- Insert Audit Log
			INSERT INTO TAMS_Action_Log VALUES 
			(
				'All', 
				'All', 
				'UserReg-Registration', 
				@RegID, 
				'User Registration has been rejected', 
				GETDATE(), 
				@UpdatedBy
			)

		END;

		IF @WFStatus = 'Pending System Admin Approval' OR @WFStatus = 'Pending System Approver Approval'
		BEGIN
			-- Reject straight to last stage. Hard Coded to Rejected
			SELECT @NextStageID = ID
			FROM TAMS_WFStatus 
			WHERE WFType = 'UserRegStatus' 
			AND Line = (SELECT Line FROM TAMS_Reg_Module WHERE ID = @RegModID)
			AND WFStatus = 'Rejected'

			UPDATE TAMS_Reg_Module 
			SET RegStatus = @NextStageID, 
				WFStatus = 'Rejected',
				UpdatedOn = GETDATE(), 
				UpdatedBy = @UpdatedBy 
			WHERE ID = @RegModID

			-- Insert Audit Log
			INSERT INTO TAMS_Action_Log VALUES 
			(
				@Line, 
				@Module, 
				'UserReg-Registration', 
				@RegID, 
				'Module in Registration has been rejected', 
				GETDATE(), 
				@UpdatedBy
			)

			-- Sends email
			SELECT @ToList = Email FROM TAMS_Registration WHERE ID = @RegID;
			

			SET @Sender = 'TAMS Admin';
			SET @SysID = 'TAMS';
			SET @Subject = 'For your information: User Registration Request has been rejected'
			SET @Sys = 'Track Access Management System'   
			SET @Greetings = 'Dear Sir/Madam, '  
			--SET @ToList = ''
			SET @CCList = ''   
			SET @BCCList = ''
			SET @Separator = ','    
			SET @CCList = ''
			--SET @ToList = '';

			SET @Body1 = ''
			SET @Body2 = ''
			SET @Body3 = ''
			
			SET @Body1 = @Body1 + '<table width="100%">'
			SET @Body1 = @Body1 + '<tr align="left" valign="middle" style="font-size:10pt; font-face:Arial;">'
			SET @Body1 = @Body1 + '<td>Please be informed that your User Registration for ' + @Line + ' ' + @Module + ' has been rejected.</td>'
			SET @Body1 = @Body1 + '</tr>'
			SET @Body1 = @Body1 + '</table>'
			 

			SET @Body3 = @Body3 + '<br>'
			SET @Body3 = @Body3 + '<table width="100%">'
			SET @Body3 = @Body3 + '<tr align="left" valign="middle" style="font-size:10pt; font-face:Arial;">'
			SET @Body3 = @Body3 + '<td>***********************************************<br>Do Not reply. This is a computer generated Email. <br>***********************************************</td>'
			SET @Body3 = @Body3 + '</tr>'
			SET @Body3 = @Body3 + '</table>'

			SET @Body = ''
			SET @Body = @Body1 + @Body2 + @Body3

			SET @BCCList = ''

			EXEC [dbo].EAlertQ_EnQueue 
				@Sender = @Sender, 
				@UserId = @SysID, 
				@Subject = @Subject,        
				@Sys = @Sys,  
				@Greetings = @Greetings, 
				@AlertMsg = @Body, 
				@SendTo = @ToList,        
				@CC = @CCList, 
				@BCC= @BCCList, 
				@Separator = @Separator, 
				@AlertID =  @AlertID output

		END; 

		

		-- Else move to rejected by Line/Module

	--	COMMIT TRANSACTION;
	--END TRY
	--BEGIN CATCH
	--	ROLLBACK TRANSACTION;
	--END CATCH

END;
GO
