-- PROCEDURE NAME: dbo.sp_TAMS_Reject_UserRegistrationRequestByRegModID_20231009
create PROCEDURE [dbo].[sp_TAMS_Reject_UserRegistrationRequestByRegModID_20231009] 	
	@RegModID			INT,
	@UpdatedBy			INT
AS
BEGIN
	--BEGIN TRY
