				UPDATE TAMS_Reg_Module 
				SET RegStatus = @NextStageID, 
					WFStatus = 'Rejected',
					UpdatedOn = GETDATE(), 
					UpdatedBy = @UpdatedBy 
				WHERE ID = @cRegModID

				-- Sends email
