----	IF @SMSOutputMsg <> ''
----		BEGIN
----			SET @Message = 'Error SMS Sending'
----			GOTO TRAP_ERROR
----		END
------ >> 20220818 Quickly trigger SMS Sending

IF @@ERROR <> 0 BEGIN
	SET @Message = 'Error RGS Ack SMS'
	GOTO TRAP_ERROR
END

