WHERE TARId = @TARID

DECLARE @SMSMsg	NVARCHAR(4000)
SET @SMSMsg = ''

DECLARE @lv_IsAllAckSurrender BIT
DECLARE @AckSurrenderTime NVARCHAR(20)
DECLARE @TARNo NVARCHAR(50)
DECLARE @TOANo NVARCHAR(50)
DECLARE @Line NVARCHAR(5)
DECLARE @CurrDate NVARCHAR(20)
DECLARE @CurrTime NVARCHAR(20)
DECLARE @AccessDate DATE
DECLARE @OperationDate DATE


SET @lv_IsAllAckSurrender = 1

SET @AckSurrenderTime = ''
SET @TARNo = ''
SET @Line = ''
SET @CurrDate = ''

SET @CurrDate = CONVERT(NVARCHAR(20), GETDATE(), 103)
SET @CurrTime = CONVERT(NVARCHAR(20), GETDATE(), 108)

SELECT @TARNo = a.TARNo,
		@TOANo = b.TOANo, 
		@Line = a.Line, 
		@AckSurrenderTime = CONVERT(NVARCHAR(20), b.AckSurrenderTime, 108),
		@AccessDate = b.AccessDate,
		@OperationDate = b.OperationDate
	FROM TAMS_TAR a, TAMS_TOA b	
		WHERE a.Id = b.TARId
			AND a.Id = @TARID

DECLARE @Endorser1 INT
DECLARE @Endorser2 INT
DECLARE @Endorser3 INT

IF @Line = 'DTL'
	BEGIN
		SELECT @Endorser1 = a.ID 
			FROM TAMS_Endorser a, TAMS_Workflow b
				WHERE b.WorkflowType = 'OCCAuth'
					AND a.WorkflowId = b.ID
					AND b.Line = 'DTL'
					AND a.Level = 10

		SELECT @Endorser2 = a.ID 
			FROM TAMS_Endorser a, TAMS_Workflow b
				WHERE b.WorkflowType = 'OCCAuth'
					AND a.WorkflowId = b.ID
					AND b.Line = 'DTL'
					AND a.Level = 11

		SELECT @Endorser3 = a.ID 
			FROM TAMS_Endorser a, TAMS_Workflow b
				WHERE b.WorkflowType = 'OCCAuth'
					AND a.WorkflowId = b.ID
					AND b.Line = 'DTL'
					AND a.Level = 12
	END
ELSE
	BEGIN
		SELECT @Endorser1 = a.ID 
			FROM TAMS_Endorser a, TAMS_Workflow b
				WHERE b.WorkflowType = 'OCCAuth'
					AND a.WorkflowId = b.ID
					AND b.Line = 'NEL'
					AND a.Level = 7
	END

DECLARE @Cur01 CURSOR;
DECLARE @TOAStatus	INT

SET @Cur01 = CURSOR FAST_FORWARD 
FOR
SELECT b.TOAStatus
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND b.AccessDate = @AccessDate
			AND b.TOAStatus NOT IN (0, 6)
			AND a.Line = @Line
	ORDER BY b.Id
OPEN @Cur01
FETCH NEXT FROM @Cur01 INTO @TOAStatus
WHILE @@FETCH_STATUS = 0 
	BEGIN
		IF @TOAStatus <> 5
			BEGIN
				SET @lv_IsAllAckSurrender = 0
			END
		FETCH NEXT FROM @Cur01 INTO @TOAStatus
	END 	
CLOSE @Cur01
DEALLOCATE @Cur01

IF @lv_IsAllAckSurrender = 1
	BEGIN
		IF @Line = 'DTL'
			BEGIN
				DECLARE @Cur02 CURSOR;
				DECLARE @Cur03 CURSOR;
				DECLARE @DTLOCCAuthID	INT

				SET @Cur02 = CURSOR FAST_FORWARD 
				FOR
				SELECT a.ID
					FROM TAMS_OCC_Auth a
						WHERE a.Line = @Line
							AND a.OperationDate = @OperationDate
							AND a.AccessDate = @AccessDate
							AND a.OCCAuthStatusId = 10
							AND a.PowerOn = 0
				OPEN @Cur02
				FETCH NEXT FROM @Cur02 INTO @DTLOCCAuthID
				WHILE @@FETCH_STATUS = 0 
					BEGIN
						UPDATE TAMS_OCC_Auth
							SET OCCAuthStatusId = 11,
								UpdatedOn = GETDATE(),
								UpdatedBy = @UserID
							WHERE ID = @DTLOCCAuthID

						INSERT INTO [dbo].[TAMS_OCC_Auth_Workflow]
							([OCCAuthId], [OCCAuthEndorserId], [WFStatus], 
								[StationId], [FISTestResult], [ActionOn], [ActionBy])
						VALUES (@DTLOCCAuthID, @Endorser1, 'Pending',
							0, NULL, GETDATE(), @UserID)

						FETCH NEXT FROM @Cur02 INTO @DTLOCCAuthID
					END 	
				CLOSE @Cur02
				DEALLOCATE @Cur02

				-- >> 
				SET @Cur03 = CURSOR FAST_FORWARD 
				FOR
				SELECT a.ID
					FROM TAMS_OCC_Auth a
						WHERE a.Line = @Line
							AND a.OperationDate = @OperationDate
							AND a.AccessDate = @AccessDate
							AND a.OCCAuthStatusId = 8 -- >> Check with Reno how to know this one end already
				OPEN @Cur03
				FETCH NEXT FROM @Cur03 INTO @DTLOCCAuthID
				WHILE @@FETCH_STATUS = 0 
					BEGIN
						UPDATE TAMS_OCC_Auth
							SET OCCAuthStatusId = 12,
								UpdatedOn = GETDATE(),
								UpdatedBy = @UserID
							WHERE ID = @DTLOCCAuthID

						INSERT INTO [dbo].[TAMS_OCC_Auth_Workflow]
							([OCCAuthId], [OCCAuthEndorserId], [WFStatus], 
								[StationId], [FISTestResult], [ActionOn], [ActionBy])
						VALUES (@DTLOCCAuthID, @Endorser1, 'Terminated',
							0, NULL, GETDATE(), @UserID)

						FETCH NEXT FROM @Cur03 INTO @DTLOCCAuthID
					END 	
				CLOSE @Cur03
				DEALLOCATE @Cur03

				-- >> 
				SET @Cur03 = CURSOR FAST_FORWARD 
				FOR
				SELECT a.ID
					FROM TAMS_OCC_Auth a
						WHERE a.Line = @Line
							AND a.OperationDate = @OperationDate
							AND a.AccessDate = @AccessDate
							AND a.OCCAuthStatusId = 8 -- >> Check with Reno how to know this one end already
				OPEN @Cur03
				FETCH NEXT FROM @Cur03 INTO @DTLOCCAuthID
				WHILE @@FETCH_STATUS = 0 
					BEGIN
						INSERT INTO [dbo].[TAMS_OCC_Auth_Workflow]
							([OCCAuthId], [OCCAuthEndorserId], [WFStatus], 
								[StationId], [FISTestResult], [ActionOn], [ActionBy])
						VALUES (@DTLOCCAuthID, @Endorser2, 'Terminated',
							0, NULL, GETDATE(), @UserID)

						FETCH NEXT FROM @Cur03 INTO @DTLOCCAuthID
					END 	
				CLOSE @Cur03
				DEALLOCATE @Cur03

				-- >> 
				SET @Cur03 = CURSOR FAST_FORWARD 
				FOR
				SELECT a.ID
					FROM TAMS_OCC_Auth a
						WHERE a.Line = @Line
							AND a.OperationDate = @OperationDate
							AND a.AccessDate = @AccessDate
							AND a.OCCAuthStatusId = 8 -- >> Check with Reno how to know this one end already
				OPEN @Cur03
				FETCH NEXT FROM @Cur03 INTO @DTLOCCAuthID
				WHILE @@FETCH_STATUS = 0 
					BEGIN
						INSERT INTO [dbo].[TAMS_OCC_Auth_Workflow]
							([OCCAuthId], [OCCAuthEndorserId], [WFStatus], 
								[StationId], [FISTestResult], [ActionOn], [ActionBy])
						VALUES (@DTLOCCAuthID, @Endorser3, 'Pending',
							0, NULL, GETDATE(), @UserID)

						FETCH NEXT FROM @Cur03 INTO @DTLOCCAuthID
					END 	
				CLOSE @Cur03
				DEALLOCATE @Cur03
			END
		ELSE
			BEGIN
				DECLARE @Cur04 CURSOR;
				DECLARE @NELOCCAuthID	INT

				SET @Cur02 = CURSOR FAST_FORWARD 
				FOR
				SELECT a.ID
					FROM TAMS_OCC_Auth a
						WHERE a.Line = @Line
							AND a.OperationDate = @OperationDate
							AND a.AccessDate = @AccessDate
							AND a.OCCAuthStatusId = 7
							AND a.PowerOn = 0
				OPEN @Cur02
				FETCH NEXT FROM @Cur02 INTO @NELOCCAuthID
				WHILE @@FETCH_STATUS = 0 
					BEGIN
						UPDATE TAMS_OCC_Auth
							SET OCCAuthStatusId = 8,
								UpdatedOn = GETDATE(),
								UpdatedBy = @UserID
							WHERE ID = @NELOCCAuthID

						INSERT INTO [dbo].[TAMS_OCC_Auth_Workflow]
							([OCCAuthId], [OCCAuthEndorserId], [WFStatus], 
								[StationId], [FISTestResult], [ActionOn], [ActionBy])
						VALUES (@NELOCCAuthID, @Endorser1, 'Pending',
							0, NULL, GETDATE(), @UserID)

						FETCH NEXT FROM @Cur02 INTO @NELOCCAuthID
					END 	
				CLOSE @Cur02
				DEALLOCATE @Cur02
			END
	END

IF @Line = 'DTL'
	BEGIN
		SET @SMSMsg = CAST(@TOANo AS NVARCHAR(50)) + ' surrender has been acknowledged by DTL OCC @ ' + CAST(@CurrTime AS NVARCHAR(20))
			+ ' hrs on ' + CAST(@CurrDate AS NVARCHAR(20)) + '. Thank you!'
	END
ELSE
	BEGIN
		SET @SMSMsg = CAST(@TOANo AS NVARCHAR(50)) + ' surrender has been acknowledged by NEL OCC @ ' + CAST(@CurrTime AS NVARCHAR(20))
			+ ' hrs on ' + CAST(@CurrDate AS NVARCHAR(20)) + '. Thank you!'
	END


-- >> SEND SMS

IF @@ERROR <> 0 BEGIN
	SET @Message = 'ERROR INSERTING TAMS_TOA_Parties'
	GOTO TRAP_ERROR
END

FORCE_EXIT_PROC:	
	IF @IntrnlTrans = 1 COMMIT TRAN
	RETURN @Message 

TRAP_ERROR:
	IF @IntrnlTrans = 1 ROLLBACK TRAN
	RETURN @Message

END
GO
/****** END PROCEDURE 275 ******/

/****** START PROCEDURE 276 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_RGS_Cancel
CREATE procedure [dbo].[sp_TAMS_RGS_Cancel]
	@TARID		AS BIGINT = 0,
	@CancelRemarks	AS NVARCHAR(1000) = NULL,
	@UserID		AS NVARCHAR(500),
	@tracktype as nvarchar(50)='MAINLINE',
	@Message	AS NVARCHAR(500) = NULL OUTPUT
AS

BEGIN

DECLARE	@IntrnlTrans	TINYINT
SELECT 	@IntrnlTrans 	= 0	

IF (@@TRANCOUNT = 0) 
BEGIN
	SET @IntrnlTrans = 1
	BEGIN TRAN
END

SET @Message = ''

DECLARE @NewLine AS CHAR(2) = CHAR(30) + CHAR(10)

UPDATE TAMS_TOA
	SET	TOAStatus = 6,
		CancelRemark = @CancelRemarks,
		UpdatedOn = GETDATE(),
		UpdatedBy = @UserID
WHERE TARId = @TARID
		
INSERT INTO TAMS_TOA_Audit
SELECT @UserID, GETDATE(), 'U', * FROM TAMS_TOA
	WHERE TARId = @TARID



DECLARE @IDUserID BIGINT

SELECT @IDUserID = Userid
	FROM TAMS_User
		WHERE LoginId = @UserID
			
DECLARE @SMSMsg	NVARCHAR(4000)
SET @SMSMsg = ''

IF @tracktype='MAINLINE' 
BEGIN

DECLARE @lv_IsAllAckSurrender BIT
DECLARE @TARNo NVARCHAR(50)
DECLARE @TOANo NVARCHAR(50)
DECLARE @Line NVARCHAR(5)
DECLARE @CurrDate NVARCHAR(20)
DECLARE @CurrTime NVARCHAR(20)
DECLARE @AccessDate DATE
DECLARE @OperationDate DATE
DECLARE @HPNo NVARCHAR(20)

SET @lv_IsAllAckSurrender = 1

SET @TARNo = ''
SET @TOANo = ''
SET @Line = ''
SET @CurrDate = ''
SET @HPNo = ''

SET @CurrDate = CONVERT(NVARCHAR(20), GETDATE(), 103)
SET @CurrTime = CONVERT(NVARCHAR(20), GETDATE(), 108)

SELECT @TARNo = ISNULL(a.TARNo, ''),
		@TOANo = ISNULL(b.TOANo, ''), 
		@Line = a.Line, 
		@AccessDate = b.AccessDate,
		@OperationDate = b.OperationDate,
		@HPNo = b.MobileNo
	FROM TAMS_TAR a, TAMS_TOA b	
		WHERE a.Id = b.TARId
			AND a.Id = @TARID

DECLARE @LogMsg NVARCHAR(100)
SET @LogMsg = ''
SET @LogMsg = CAST(@TARNo AS NVARCHAR(20)) + ' ' + CAST(@TOANo AS NVARCHAR(20)) + ' RGS Cancel Action Log for checking'
-- >> SELECT @LogMsg

INSERT INTO TAMS_Action_Log
VALUES(@Line, 'RGS', 'RGS-Cancel', @TarId, @LogMsg, GETDATE(), 88);

DECLARE @Endorser1 INT
DECLARE @Endorser2 INT

IF @Line = 'DTL'
	BEGIN
		SELECT @Endorser1 = a.ID 
			FROM TAMS_Endorser a, TAMS_Workflow b
				WHERE b.WorkflowType = 'OCCAuth'
					AND a.WorkflowId = b.ID
					AND b.Line = 'DTL'
					AND a.Level = 10
					AND b.TrackType='mainline' -- Bug INC-11855, added by yongde

		SELECT @Endorser2 = a.ID 
			FROM TAMS_Endorser a, TAMS_Workflow b
				WHERE b.WorkflowType = 'OCCAuth'
					AND a.WorkflowId = b.ID
					AND b.Line = 'DTL'
					AND a.Level = 12
					AND b.TrackType='mainline'-- Bug INC-11855, added by yongde
	END
ELSE
	BEGIN
		SELECT @Endorser1 = a.ID 
			FROM TAMS_Endorser a, TAMS_Workflow b
				WHERE b.WorkflowType = 'OCCAuth'
					AND a.WorkflowId = b.ID
					AND b.Line = 'NEL'
					AND a.Level = 8
					AND b.TrackType='mainline'-- Bug INC-11855, added by yongde
	END

DECLARE @Cur01 CURSOR;
DECLARE @TOAStatus	INT

SET @Cur01 = CURSOR FAST_FORWARD 
FOR
SELECT b.TOAStatus
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND b.AccessDate = @AccessDate
			AND b.TOAStatus NOT IN (0, 6)
			AND a.Line = @Line
	ORDER BY b.Id
OPEN @Cur01
FETCH NEXT FROM @Cur01 INTO @TOAStatus
WHILE @@FETCH_STATUS = 0 
	BEGIN
		IF @TOAStatus <> 5
			BEGIN
				SET @lv_IsAllAckSurrender = 0
			END
		FETCH NEXT FROM @Cur01 INTO @TOAStatus
	END 	
CLOSE @Cur01
DEALLOCATE @Cur01


		IF @Line = 'DTL'
			BEGIN
				IF @lv_IsAllAckSurrender = 1
					BEGIN
								DECLARE @Cur02 CURSOR;
								DECLARE @Cur03 CURSOR;
								DECLARE @DTLOCCAuthID	INT

								SET @Cur02 = CURSOR FAST_FORWARD 
								FOR
								SELECT a.ID
									FROM TAMS_OCC_Auth a
										WHERE a.Line = @Line
											AND a.OperationDate = @OperationDate
											AND a.AccessDate = @AccessDate
											-- >> If last cancel, start 2nd half of all
											-- >> AND a.OCCAuthStatusId = 10
											AND a.PowerOn = 0
								OPEN @Cur02
								FETCH NEXT FROM @Cur02 INTO @DTLOCCAuthID
								WHILE @@FETCH_STATUS = 0 
									BEGIN
										UPDATE TAMS_OCC_Auth
											SET OCCAuthStatusId = 11,
												UpdatedOn = GETDATE(),
												UpdatedBy = @IDUserID
											WHERE ID = @DTLOCCAuthID

										-- >> Insert to Audit
										INSERT INTO [dbo].[TAMS_OCC_Auth_Audit]
										([ActionBy], [ActionOn], [AuditAction], 
											[OCCAuthID], [Line], [OperationDate], [AccessDate], [TractionPowerId], [Remark], [PFRRemark], 
											[OCCAuthStatusId], [IsBuffer], [PowerOn], [PowerOffTime], [RackedOutTime], 
											[CreatedOn], [CreatedBy], [UpdatedOn], [UpdatedBy])
										SELECT @IDUserID, GETDATE(), 'U',
											[ID], [Line], [OperationDate], [AccessDate], [TractionPowerId], [Remark], [PFRRemark],
											[OCCAuthStatusId], [IsBuffer], [PowerOn], [PowerOffTime], [RackedOutTime],
											[CreatedOn], [CreatedBy], [UpdatedOn], [UpdatedBy]
										  FROM [dbo].[TAMS_OCC_Auth]
												WHERE ID = @DTLOCCAuthID
										-- >> Insert to Audit

										INSERT INTO [dbo].[TAMS_OCC_Auth_Workflow]
											([OCCAuthId], [OCCAuthEndorserId], [WFStatus], 
												[StationId], [FISTestResult], [ActionOn], [ActionBy])
										VALUES (@DTLOCCAuthID, @Endorser1, 'Pending',
											0, NULL, GETDATE(), 1)

										-- >> Insert to Audit
										INSERT INTO [dbo].[TAMS_OCC_Auth_Workflow_Audit]
										([AuditActionBy], [AuditActionOn], [AuditAction], 
											[OCCAuthWorkflowID], [OCCAuthId], [OCCAuthEndorserId], [WFStatus], [StationId], [FISTestResult], [ActionOn], [ActionBy])
										SELECT 1, GETDATE(), 'I', 
											[ID], [OCCAuthId], [OCCAuthEndorserId], [WFStatus], [StationId], [FISTestResult], [ActionOn], [ActionBy]
											FROM [dbo].[TAMS_OCC_Auth_Workflow]
												WHERE OCCAuthId = @DTLOCCAuthID AND [OCCAuthEndorserId] = @Endorser1 AND WFStatus = 'Pending'
										-- >> Insert to Audit

										FETCH NEXT FROM @Cur02 INTO @DTLOCCAuthID
									END 	
								CLOSE @Cur02
								DEALLOCATE @Cur02


								-- >> Buffer Zone
								-- >> 
								SET @Cur03 = CURSOR FAST_FORWARD 
								FOR
								SELECT a.ID
									FROM TAMS_OCC_Auth a
										WHERE a.Line = @Line
											AND a.OperationDate = @OperationDate
											AND a.AccessDate = @AccessDate
											-- >> If last cancel, start 2nd half of all
											-- >> AND a.OCCAuthStatusId = 7 -- >> Check with Reno how to know this one end already
											AND a.IsBuffer = 1
								OPEN @Cur03
								FETCH NEXT FROM @Cur03 INTO @DTLOCCAuthID
								WHILE @@FETCH_STATUS = 0 
									BEGIN
										UPDATE TAMS_OCC_Auth
											SET OCCAuthStatusId = 13,
												UpdatedOn = GETDATE(),
												UpdatedBy = @IDUserID
											WHERE ID = @DTLOCCAuthID

										-- >> Insert to Audit
										INSERT INTO [dbo].[TAMS_OCC_Auth_Audit]
										([ActionBy], [ActionOn], [AuditAction], 
											[OCCAuthID], [Line], [OperationDate], [AccessDate], [TractionPowerId], [Remark], [PFRRemark], 
											[OCCAuthStatusId], [IsBuffer], [PowerOn], [PowerOffTime], [RackedOutTime], 
											[CreatedOn], [CreatedBy], [UpdatedOn], [UpdatedBy])
										SELECT @IDUserID, GETDATE(), 'U',
											[ID], [Line], [OperationDate], [AccessDate], [TractionPowerId], [Remark], [PFRRemark],
											[OCCAuthStatusId], [IsBuffer], [PowerOn], [PowerOffTime], [RackedOutTime],
											[CreatedOn], [CreatedBy], [UpdatedOn], [UpdatedBy]
										  FROM [dbo].[TAMS_OCC_Auth]
												WHERE ID = @DTLOCCAuthID
										-- >> Insert to Audit

										INSERT INTO [dbo].[TAMS_OCC_Auth_Workflow]
											([OCCAuthId], [OCCAuthEndorserId], [WFStatus], 
												[StationId], [FISTestResult], [ActionOn], [ActionBy])
										VALUES (@DTLOCCAuthID, @Endorser2, 'Pending', -- >> Check with Reno what is the EndorserID
											0, NULL, '1900-01-01 00:00:00', 1)

										-- >> Insert to Audit
										INSERT INTO [dbo].[TAMS_OCC_Auth_Workflow_Audit]
										([AuditActionBy], [AuditActionOn], [AuditAction], 
											[OCCAuthWorkflowID], [OCCAuthId], [OCCAuthEndorserId], [WFStatus], [StationId], [FISTestResult], [ActionOn], [ActionBy])
										SELECT 1, GETDATE(), 'I', 
											[ID], [OCCAuthId], [OCCAuthEndorserId], [WFStatus], [StationId], [FISTestResult], [ActionOn], [ActionBy]
											FROM [dbo].[TAMS_OCC_Auth_Workflow]
												WHERE OCCAuthId = @DTLOCCAuthID AND [OCCAuthEndorserId] = @Endorser2 AND WFStatus = 'Pending'
										-- >> Insert to Audit

										FETCH NEXT FROM @Cur03 INTO @DTLOCCAuthID
									END 	
								CLOSE @Cur03
								DEALLOCATE @Cur03
								-- >> 
								-- >> Buffer Zone
							END

			END -- DTL no change of checking 
		--ELSE
		--	BEGIN
		--		DECLARE @Cur04 CURSOR;
		--		DECLARE @NELOCCAuthID	INT

		--		SET @Cur02 = CURSOR FAST_FORWARD 
		--		FOR
		--		SELECT a.ID
		--			FROM TAMS_OCC_Auth a
		--				WHERE a.Line = @Line
		--					AND a.OperationDate = @OperationDate
		--					AND a.AccessDate = @AccessDate
		--					-- >> If last cancel, start 2nd half of all
		--					-- >> AND a.OCCAuthStatusId = 8
		--					AND a.PowerOn = 0
		--		OPEN @Cur02
		--		FETCH NEXT FROM @Cur02 INTO @NELOCCAuthID
		--		WHILE @@FETCH_STATUS = 0 
		--			BEGIN
		--				UPDATE TAMS_OCC_Auth
		--					-- SET OCCAuthStatusId = 8,
		--					SET OCCAuthStatusId = 9,
		--						UpdatedOn = GETDATE(),
		--						UpdatedBy = @IDUserID
		--					WHERE ID = @NELOCCAuthID

		--				-- >> Insert to Audit
		--				INSERT INTO [dbo].[TAMS_OCC_Auth_Audit]
		--				([ActionBy], [ActionOn], [AuditAction], 
		--					[OCCAuthID], [Line], [OperationDate], [AccessDate], [TractionPowerId], [Remark], [PFRRemark], 
		--					[OCCAuthStatusId], [IsBuffer], [PowerOn], [PowerOffTime], [RackedOutTime], 
		--					[CreatedOn], [CreatedBy], [UpdatedOn], [UpdatedBy])
		--				SELECT @IDUserID, GETDATE(), 'U',
		--					[ID], [Line], [OperationDate], [AccessDate], [TractionPowerId], [Remark], [PFRRemark],
		--					[OCCAuthStatusId], [IsBuffer], [PowerOn], [PowerOffTime], [RackedOutTime],
		--					[CreatedOn], [CreatedBy], [UpdatedOn], [UpdatedBy]
		--				  FROM [dbo].[TAMS_OCC_Auth]
		--						WHERE ID = @NELOCCAuthID
		--				-- >> Insert to Audit

		--				INSERT INTO [dbo].[TAMS_OCC_Auth_Workflow]
		--					([OCCAuthId], [OCCAuthEndorserId], [WFStatus], 
		--						[StationId], [FISTestResult], [ActionOn], [ActionBy])
		--				VALUES (@NELOCCAuthID, @Endorser1, 'Pending',
		--					0, NULL, GETDATE(), 1)

		--				-- >> Insert to Audit
		--				INSERT INTO [dbo].[TAMS_OCC_Auth_Workflow_Audit]
		--				([AuditActionBy], [AuditActionOn], [AuditAction], 
		--					[OCCAuthWorkflowID], [OCCAuthId], [OCCAuthEndorserId], [WFStatus], [StationId], [FISTestResult], [ActionOn], [ActionBy])
		--				SELECT 1, GETDATE(), 'I', 
		--					[ID], [OCCAuthId], [OCCAuthEndorserId], [WFStatus], [StationId], [FISTestResult], [ActionOn], [ActionBy]
		--					FROM [dbo].[TAMS_OCC_Auth_Workflow]
		--						WHERE OCCAuthId = @NELOCCAuthID AND [OCCAuthEndorserId] = @Endorser1 AND WFStatus = 'Pending'
		--				-- >> Insert to Audit

		--				FETCH NEXT FROM @Cur02 INTO @NELOCCAuthID
		--			END 	
		--		CLOSE @Cur02
		--		DEALLOCATE @Cur02
		--	END
	 


	-- >> 

--IF @Line = 'DTL'
--	BEGIN
--		SET @SMSMsg = CAST(@TOANo AS NVARCHAR(50)) + ' surrender has been acknowledged by DTL OCC @ ' + CAST(@CurrTime AS NVARCHAR(20))
--			+ ' hrs on ' + CAST(@CurrDate AS NVARCHAR(20)) + '. Thank you!'
--	END
--ELSE
--	BEGIN
--		SET @SMSMsg = CAST(@TOANo AS NVARCHAR(50)) + ' surrender has been acknowledged by NEL OCC @ ' + CAST(@CurrTime AS NVARCHAR(20))
--			+ ' hrs on ' + CAST(@CurrDate AS NVARCHAR(20)) + '. Thank you!'
--	END


 	/***********************Changes for NEL , to start second phase of OCC once the TAR sectors has cleared********************************/
		IF @Line = 'NEL'
		BEGIN

		DECLARE @CurNELOCC CURSOR;
		DECLARE @TractionPowerID int;
		SET @CurNELOCC = CURSOR FAST_FORWARD 
		FOR
		SELECT distinct  TractionPowerId
		From  TAMS_Traction_Power_Detail 
		WHERE  PowerSectionId in (
			Select  powersectorid 
			From TAMS_TAR_Power_Sector where TARId = @TARID
		) 
		OPEN @CurNELOCC
		FETCH NEXT FROM @CurNELOCC INTO @TractionPowerID
		WHILE @@FETCH_STATUS = 0 
			BEGIN

			   IF ((SELECT count(b.Id )
						FROM   TAMS_TAR a left join TAMS_TOA b on a.Id = b.TARId
						left join TAMS_TAR_Power_Sector c ON a.Id = c.TARId
						WHERE  b.TARId is NOT null 
						AND  a.AccessDate = @AccessDate
						AND (b.TOAStatus != 0 and b.TOAStatus != 6 and b.TOAStatus != 5 )
						AND c.PowerSectorId in (Select PowerSectionId From TAMS_Traction_Power_Detail WHERE TractionPowerId = @TractionPowerID ))=0
			)
				BEGIN 
					

					INSERT INTO [dbo].[TAMS_OCC_Auth_Workflow]
						([OCCAuthId], [OCCAuthEndorserId], [WFStatus], 
							[StationId], [FISTestResult], [ActionOn], [ActionBy])
					SELECT ID, @Endorser1, 'Pending',0, NULL,GETDATE(),1 
					FROM TAMS_OCC_Auth WHERE TractionPowerId = @TractionPowerID
						AND OperationDate = @OperationDate 
						and AccessDate = @AccessDate
						AND OCCAuthStatusId = 8
					 

					-- >> Insert to Audit
					INSERT INTO [dbo].[TAMS_OCC_Auth_Workflow_Audit]
					([AuditActionBy], [AuditActionOn], [AuditAction], 
						[OCCAuthWorkflowID], [OCCAuthId], [OCCAuthEndorserId], [WFStatus], [StationId], [FISTestResult], [ActionOn], [ActionBy])
					SELECT 1, GETDATE(), 'I', 
						[ID], [OCCAuthId], [OCCAuthEndorserId], [WFStatus], [StationId], [FISTestResult], [ActionOn], [ActionBy]
						FROM [dbo].[TAMS_OCC_Auth_Workflow]
							WHERE  WFStatus = 'Pending' and OCCAuthId in (
							Select ID
							FROM TAMS_OCC_Auth WHERE TractionPowerId = @TractionPowerID
						AND OperationDate = @OperationDate 
						and AccessDate = @AccessDate
						AND OCCAuthStatusId = 8
							)
					-- >> Insert to Audit

					-- insert into OCC Workflow table 
						UPDATE TAMS_OCC_Auth
						SET OCCAuthStatusId = 9,
							UpdatedOn = GETDATE(),
							UpdatedBy = @IDUserID
						WHERE TractionPowerId = @TractionPowerID
						AND OperationDate = @OperationDate 
						and AccessDate = @AccessDate
						AND OCCAuthStatusId = 8

					-- >> Insert to Audit
					INSERT INTO [dbo].[TAMS_OCC_Auth_Audit]
					([ActionBy], [ActionOn], [AuditAction], 
						[OCCAuthID], [Line], [OperationDate], [AccessDate], [TractionPowerId], [Remark], [PFRRemark], 
						[OCCAuthStatusId], [IsBuffer], [PowerOn], [PowerOffTime], [RackedOutTime], 
						[CreatedOn], [CreatedBy], [UpdatedOn], [UpdatedBy])
					SELECT @IDUserID, GETDATE(), 'U',
						[ID], [Line], [OperationDate], [AccessDate], [TractionPowerId], [Remark], [PFRRemark],
						[OCCAuthStatusId], [IsBuffer], [PowerOn], [PowerOffTime], [RackedOutTime],
						[CreatedOn], [CreatedBy], [UpdatedOn], [UpdatedBy]
						FROM [dbo].[TAMS_OCC_Auth]
						WHERE TractionPowerId = @TractionPowerID
						AND OperationDate = @OperationDate 
						and AccessDate = @AccessDate
						AND OCCAuthStatusId = 8
					-- >> Insert to Audit

				END;


				 
				FETCH NEXT FROM @CurNELOCC INTO @TractionPowerID
			END 	
		CLOSE @CurNELOCC
		DEALLOCATE @CurNELOCC

		 			 

		END;
	END
		/***********************END of Changes for NEL , to start second phase of OCC once the TAR sectors has cleared********************************/
ELSE
BEGIN
	PRINT 'depot'

	SELECT @Line=Line from TAMS_TAR where Id=@TARID
	PRINT @Line;
	--For Depot
		/***********************Changes for NEL , to start second phase of OCC once the TAR sectors has cleared********************************/
		IF @Line = 'NEL'
		BEGIN
			PRINT @TARID

			-- If during cancellation, Status is after Line Clear Certification, 
			iF EXISTS(Select * from TAMS_TOA INNER JOIN TAMS_Depot_Auth ON
			TAMS_Depot_Auth.TarID=TAMS_TOA.TARId
			where TAMS_TOA.TARId=@TARID
			)
			BEGIN
				DECLARE @depotauthid as int;
				
				Select @depotauthid=DepotAuthStatusId from TAMS_TOA INNER JOIN TAMS_Depot_Auth ON
				TAMS_Depot_Auth.TarID=TAMS_TOA.TARId
				where TAMS_TOA.TARId=@TARID


				DECLARE @authid as int;
				DECLARE @statusid as int;
				DECLARE @newstatusid as int;
				DECLARE @newworkflowid as int;
				DECLARE @workflowid as int;


				SELECT @authid=TAMS_Depot_Auth.ID,@statusid=DepotAuthStatusId FROM TAMS_Depot_Auth where TarID=@TARID
				PRINT @authid

				if @depotauthid=1
				BEGIN
					-- Cancel authorisation
					DELETE FROM TAMS_Depot_Auth_Powerzone where AuthID=@authid

					DELETE FROM TAMS_Depot_DTCAuth_SPKS where AuthID=@authid

					DELETE FROM TAMS_Depot_Auth_Workflow where TAMS_Depot_Auth_Workflow.DTCAuthId=@authid

					DELETE FROM TAMS_Depot_Auth where ID=@authid
				END
				ELSE

		

				-- status Pending no train movemnent

				-- check if all surrender
				if not EXISTS(SELECT * from TAMS_TOA where TARId=@TARID and TOAStatus=5)
				--if @depotauthid<=3 and @depotauthid>1
				BEGIN
					
					select @newstatusid=WFStatusId from TAMS_WFStatus where WFType='dtcauth' and WFStatus=CASE WHEN @depotauthid=1 THEN 'Line Clear Certification (TOA/SCD) (CC)' ELSE 'Line Clear Certification (TOA/SCD) (DTC)' END 
					and isActive=1
					order by [Order] ASC;

					SELECT @workflowid=ID from TAMS_WFStatus where WFType='dtcauth' and WFStatusId=@statusid
					Select @newworkflowid=ID from TAMS_WFStatus where WFType='dtcauth' and WFStatusId=@newstatusid


					--Select * from TAMS_Depot_Auth_Workflow
					--UPDATE TAMS_Depot_Auth_Workflow
					--SET WFStatus='Completed', ActionBy=@UserID, ActionOn=getDate(),CheckBoxValue=1
					--where WorkflowID=@workflowid
					UPDATE TAMS_Depot_Auth_Workflow
					SET isCancelled=1
					where WorkflowID=@workflowid and DTCAuthId=@authid

					INSERT INTO TAMS_Depot_Auth_Workflow
					SELECT @authid, null, null, null, @newworkflowid,null,0

					UPDATE TAMS_Depot_Auth
					SET DepotAuthStatusId=@newstatusid,UpdatedOn=getDate(),UpdatedBy=@UserID
					where ID=@authid
				
				END
				ELSE
				BEGIN
					PRINT 'set message'
					SET @Message = '-2'
					GOTO TRAP_ERROR
				END
				--select @newstatusid=WFStatusId from TAMS_WFStatus where WFType='dtcauth' and WFStatus='Line Clear Certification (TOA/SCD) (DTC)'
				--and isActive=1
				--order by [Order] ASC;
				
				PRINT @newworkflowid

			
			END
		 			 

		END;
END



DECLARE @OCCContactNo	NVARCHAR(100)
SET @OCCContactNo = ''

-- >> 2024-01-16 Changes to add nelocc email to the recipient list, include contact no
SELECT @OCCContactNo = ParaValue2
	FROM TAMS_Parameters
		WHERE ParaCode = 'OCCContact'
			AND ParaValue1 = @Line

IF @Line = 'DTL'
	BEGIN
		-- >> SET @SMSMsg = CAST(@NoStr AS NVARCHAR(50)) + ' has been cancelled on TAMS due to TPO/PC inactivity. Please call back OCC at 67187110 if you have surrendered TOA on TAMS.'
		IF CAST(@TOANo AS NVARCHAR(50)) = ''
			BEGIN
				SET @SMSMsg = CAST(@TARNo AS NVARCHAR(50)) + ' has been cancelled on TAMS & contact OCC ' + CAST(@OCCContactNo AS NVARCHAR(100)) + ', if required.'
			END
		ELSE
			BEGIN
				SET @SMSMsg = CAST(@TOANo AS NVARCHAR(50)) + ' has been cancelled on TAMS & contact OCC ' + CAST(@OCCContactNo AS NVARCHAR(100)) + ', IMMEDIATELY.'
			END	
	END
ELSE
	BEGIN
		-- >> NEL
		IF CAST(@TOANo AS NVARCHAR(50)) = ''
			BEGIN
				SET @SMSMsg = CAST(@TARNo AS NVARCHAR(50)) + ' has been cancelled on TAMS & contact OCC ' + CAST(@OCCContactNo AS NVARCHAR(100)) + ', if required.'
			END
		ELSE
			BEGIN
				SET @SMSMsg = CAST(@TOANo AS NVARCHAR(50)) + ' has been cancelled on TAMS & contact OCC ' + CAST(@OCCContactNo AS NVARCHAR(100)) + ', IMMEDIATELY.'
			END
	END

-- >> SEND SMS
DECLARE @RetVal NVARCHAR(5)
SET @RetVal = ''

	IF @HPNo <> ''
		BEGIN
			EXEC sp_api_send_sms @HPNo, 'TAMS RGS', @SMSMsg, @RetVal OUTPUT
		END

------ >> 20220818 Quickly trigger SMS Sending
----	DECLARE @SMSOutputMsg NVARCHAR(500) 

----	SET @SMSOutputMsg = ''

----	EXEC SP_Call_SMTP_Send_SMSAlert @SMSOutputMsg OUTPUT

----	IF @SMSOutputMsg <> ''
----		BEGIN
----			SET @Message = 'Error SMS Sending'
----			--GOTO TRAP_ERROR
----		END
------ >> 20220818 Quickly trigger SMS Sending

IF @@ERROR <> 0 BEGIN
	SET @Message = 'Error RGS Cancel'
	GOTO TRAP_ERROR
END

FORCE_EXIT_PROC:	
	IF @IntrnlTrans = 1 COMMIT TRAN
	RETURN @Message 

TRAP_ERROR:
	IF @IntrnlTrans = 1 ROLLBACK TRAN
	--PRINT @Message
	RETURN -1

END
GO
/****** END PROCEDURE 276 ******/

/****** START PROCEDURE 277 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_RGS_Cancel_20221107
CREATE PROCEDURE [dbo].[sp_TAMS_RGS_Cancel_20221107]
	@TARID		AS BIGINT = 0,
	@CancelRemarks	AS NVARCHAR(1000) = NULL,
	@UserID		AS NVARCHAR(500),
	@Message	AS NVARCHAR(500) = NULL OUTPUT
AS

BEGIN

DECLARE	@IntrnlTrans	TINYINT
SELECT 	@IntrnlTrans 	= 0	

IF (@@TRANCOUNT = 0) 
BEGIN
	SET @IntrnlTrans = 1
	BEGIN TRAN
END

SET @Message = ''

DECLARE @NewLine AS CHAR(2) = CHAR(30) + CHAR(10)

UPDATE TAMS_TOA
	SET	TOAStatus = 6,
		CancelRemark = @CancelRemarks,
		UpdatedOn = GETDATE(),
		UpdatedBy = @UserID
WHERE TARId = @TARID
		
DECLARE @IDUserID BIGINT

SELECT @IDUserID = Userid
	FROM TAMS_User
		WHERE LoginId = @UserID
			
DECLARE @SMSMsg	NVARCHAR(4000)
SET @SMSMsg = ''

DECLARE @lv_IsAllAckSurrender BIT
DECLARE @TARNo NVARCHAR(50)
DECLARE @TOANo NVARCHAR(50)
DECLARE @Line NVARCHAR(5)
DECLARE @CurrDate NVARCHAR(20)
DECLARE @CurrTime NVARCHAR(20)
DECLARE @AccessDate DATE
DECLARE @OperationDate DATE
DECLARE @HPNo NVARCHAR(20)

SET @lv_IsAllAckSurrender = 1

SET @TARNo = ''
SET @Line = ''
SET @CurrDate = ''
SET @HPNo = ''

SET @CurrDate = CONVERT(NVARCHAR(20), GETDATE(), 103)
SET @CurrTime = CONVERT(NVARCHAR(20), GETDATE(), 108)

SELECT @TARNo = a.TARNo,
		@TOANo = b.TOANo, 
		@Line = a.Line, 
		@AccessDate = b.AccessDate,
		@OperationDate = b.OperationDate,
		@HPNo = b.MobileNo
	FROM TAMS_TAR a, TAMS_TOA b	
		WHERE a.Id = b.TARId
			AND a.Id = @TARID

INSERT INTO TAMS_Action_Log
VALUES(@Line, 'RGS', 'RGS-Cancel', @TarId, CAST(@TARNo AS NVARCHAR(20)) + ' ' + CAST(@TOANo AS NVARCHAR(20)) + ' RGS Cancel Action Log for checking', GETDATE(), 88);


DECLARE @Endorser1 INT
DECLARE @Endorser2 INT

IF @Line = 'DTL'
	BEGIN
		SELECT @Endorser1 = a.ID 
			FROM TAMS_Endorser a, TAMS_Workflow b
				WHERE b.WorkflowType = 'OCCAuth'
					AND a.WorkflowId = b.ID
					AND b.Line = 'DTL'
					AND a.Level = 10

		SELECT @Endorser2 = a.ID 
			FROM TAMS_Endorser a, TAMS_Workflow b
				WHERE b.WorkflowType = 'OCCAuth'
					AND a.WorkflowId = b.ID
					AND b.Line = 'DTL'
					AND a.Level = 12
	END
ELSE
	BEGIN
		SELECT @Endorser1 = a.ID 
			FROM TAMS_Endorser a, TAMS_Workflow b
				WHERE b.WorkflowType = 'OCCAuth'
					AND a.WorkflowId = b.ID
					AND b.Line = 'NEL'
					AND a.Level = 7
	END

DECLARE @Cur01 CURSOR;
DECLARE @TOAStatus	INT

SET @Cur01 = CURSOR FAST_FORWARD 
FOR
SELECT b.TOAStatus
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND b.AccessDate = @AccessDate
			AND b.TOAStatus NOT IN (0, 6)
			AND a.Line = @Line
	ORDER BY b.Id
OPEN @Cur01
FETCH NEXT FROM @Cur01 INTO @TOAStatus
WHILE @@FETCH_STATUS = 0 
	BEGIN
		IF @TOAStatus <> 5
			BEGIN
				SET @lv_IsAllAckSurrender = 0
			END
		FETCH NEXT FROM @Cur01 INTO @TOAStatus
	END 	
CLOSE @Cur01
DEALLOCATE @Cur01

IF @lv_IsAllAckSurrender = 1
	BEGIN
		IF @Line = 'DTL'
			BEGIN
				DECLARE @Cur02 CURSOR;
				DECLARE @Cur03 CURSOR;
				DECLARE @DTLOCCAuthID	INT

				SET @Cur02 = CURSOR FAST_FORWARD 
				FOR
				SELECT a.ID
					FROM TAMS_OCC_Auth a
						WHERE a.Line = @Line
							AND a.OperationDate = @OperationDate
							AND a.AccessDate = @AccessDate
							AND a.OCCAuthStatusId = 10
							AND a.PowerOn = 0
				OPEN @Cur02
				FETCH NEXT FROM @Cur02 INTO @DTLOCCAuthID
				WHILE @@FETCH_STATUS = 0 
					BEGIN
						UPDATE TAMS_OCC_Auth
							SET OCCAuthStatusId = 11,
								UpdatedOn = GETDATE(),
								UpdatedBy = @IDUserID
							WHERE ID = @DTLOCCAuthID

						INSERT INTO [dbo].[TAMS_OCC_Auth_Workflow]
							([OCCAuthId], [OCCAuthEndorserId], [WFStatus], 
								[StationId], [FISTestResult], [ActionOn], [ActionBy])
						VALUES (@DTLOCCAuthID, @Endorser1, 'Pending',
							0, NULL, GETDATE(), @IDUserID)

						FETCH NEXT FROM @Cur02 INTO @DTLOCCAuthID
					END 	
				CLOSE @Cur02
				DEALLOCATE @Cur02


				-- >> Buffer Zone
				-- >> 
				SET @Cur03 = CURSOR FAST_FORWARD 
				FOR
				SELECT a.ID
					FROM TAMS_OCC_Auth a
						WHERE a.Line = @Line
							AND a.OperationDate = @OperationDate
							AND a.AccessDate = @AccessDate
							AND a.OCCAuthStatusId = 7 -- >> Check with Reno how to know this one end already
				OPEN @Cur03
				FETCH NEXT FROM @Cur03 INTO @DTLOCCAuthID
				WHILE @@FETCH_STATUS = 0 
					BEGIN
						UPDATE TAMS_OCC_Auth
							SET OCCAuthStatusId = 13,
								UpdatedOn = GETDATE(),
								UpdatedBy = @IDUserID
							WHERE ID = @DTLOCCAuthID

						INSERT INTO [dbo].[TAMS_OCC_Auth_Workflow]
							([OCCAuthId], [OCCAuthEndorserId], [WFStatus], 
								[StationId], [FISTestResult], [ActionOn], [ActionBy])
						VALUES (@DTLOCCAuthID, @Endorser2, 'Pending', -- >> Check with Reno what is the EndorserID
							0, NULL, GETDATE(), @IDUserID)

						FETCH NEXT FROM @Cur03 INTO @DTLOCCAuthID
					END 	
				CLOSE @Cur03
				DEALLOCATE @Cur03
				-- >> 
				-- >> Buffer Zone
			END
		ELSE
			BEGIN
				DECLARE @Cur04 CURSOR;
				DECLARE @NELOCCAuthID	INT

				SET @Cur02 = CURSOR FAST_FORWARD 
				FOR
				SELECT a.ID
					FROM TAMS_OCC_Auth a
						WHERE a.Line = @Line
							AND a.OperationDate = @OperationDate
							AND a.AccessDate = @AccessDate
							AND a.OCCAuthStatusId = 7
							AND a.PowerOn = 0
				OPEN @Cur02
				FETCH NEXT FROM @Cur02 INTO @NELOCCAuthID
				WHILE @@FETCH_STATUS = 0 
					BEGIN
						UPDATE TAMS_OCC_Auth
							SET OCCAuthStatusId = 8,
								UpdatedOn = GETDATE(),
								UpdatedBy = @IDUserID
							WHERE ID = @NELOCCAuthID

						INSERT INTO [dbo].[TAMS_OCC_Auth_Workflow]
							([OCCAuthId], [OCCAuthEndorserId], [WFStatus], 
								[StationId], [FISTestResult], [ActionOn], [ActionBy])
						VALUES (@NELOCCAuthID, @Endorser1, 'Pending',
							0, NULL, GETDATE(), @IDUserID)

						FETCH NEXT FROM @Cur02 INTO @NELOCCAuthID
					END 	
				CLOSE @Cur02
				DEALLOCATE @Cur02
			END
	END

IF @Line = 'DTL'
	BEGIN
		SET @SMSMsg = CAST(@TOANo AS NVARCHAR(50)) + ' surrender has been acknowledged by DTL OCC @ ' + CAST(@CurrTime AS NVARCHAR(20))
			+ ' hrs on ' + CAST(@CurrDate AS NVARCHAR(20)) + '. Thank you!'
	END
ELSE
	BEGIN
		SET @SMSMsg = CAST(@TOANo AS NVARCHAR(50)) + ' surrender has been acknowledged by NEL OCC @ ' + CAST(@CurrTime AS NVARCHAR(20))
			+ ' hrs on ' + CAST(@CurrDate AS NVARCHAR(20)) + '. Thank you!'
	END

-- >> SEND SMS
DECLARE @RetVal NVARCHAR(5)
SET @RetVal = ''

	IF @HPNo <> ''
		BEGIN
			EXEC sp_api_send_sms @HPNo, 'TAMS RGS', @SMSMsg, @RetVal OUTPUT
		END

IF @@ERROR <> 0 BEGIN
	SET @Message = 'ERROR INSERTING TAMS_TOA_Parties'
	GOTO TRAP_ERROR
END

FORCE_EXIT_PROC:	
	IF @IntrnlTrans = 1 COMMIT TRAN
	RETURN @Message 

TRAP_ERROR:
	IF @IntrnlTrans = 1 ROLLBACK TRAN
	RETURN @Message

END
GO
/****** END PROCEDURE 277 ******/

/****** START PROCEDURE 278 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_RGS_Cancel_20230209_AllCancel
CREATE PROCEDURE [dbo].[sp_TAMS_RGS_Cancel_20230209_AllCancel]
	@TARID		AS BIGINT = 0,
	@CancelRemarks	AS NVARCHAR(1000) = NULL,
	@UserID		AS NVARCHAR(500),
	@Message	AS NVARCHAR(500) = NULL OUTPUT
AS

BEGIN

DECLARE	@IntrnlTrans	TINYINT
SELECT 	@IntrnlTrans 	= 0	

IF (@@TRANCOUNT = 0) 
BEGIN
	SET @IntrnlTrans = 1
	BEGIN TRAN
END

SET @Message = ''

DECLARE @NewLine AS CHAR(2) = CHAR(30) + CHAR(10)

UPDATE TAMS_TOA
	SET	TOAStatus = 6,
		CancelRemark = @CancelRemarks,
		UpdatedOn = GETDATE(),
		UpdatedBy = @UserID
WHERE TARId = @TARID
		
INSERT INTO TAMS_TOA_Audit
SELECT @UserID, GETDATE(), 'U', * FROM TAMS_TOA
	WHERE TARId = @TARID

DECLARE @IDUserID BIGINT

SELECT @IDUserID = Userid
	FROM TAMS_User
		WHERE LoginId = @UserID
			
DECLARE @SMSMsg	NVARCHAR(4000)
SET @SMSMsg = ''

DECLARE @lv_IsAllAckSurrender BIT
DECLARE @TARNo NVARCHAR(50)
DECLARE @TOANo NVARCHAR(50)
DECLARE @Line NVARCHAR(5)
DECLARE @CurrDate NVARCHAR(20)
DECLARE @CurrTime NVARCHAR(20)
DECLARE @AccessDate DATE
DECLARE @OperationDate DATE
DECLARE @HPNo NVARCHAR(20)

SET @lv_IsAllAckSurrender = 1

SET @TARNo = ''
SET @TOANo = ''
SET @Line = ''
SET @CurrDate = ''
SET @HPNo = ''

SET @CurrDate = CONVERT(NVARCHAR(20), GETDATE(), 103)
SET @CurrTime = CONVERT(NVARCHAR(20), GETDATE(), 108)

SELECT @TARNo = ISNULL(a.TARNo, ''),
		@TOANo = ISNULL(b.TOANo, ''), 
		@Line = a.Line, 
		@AccessDate = b.AccessDate,
		@OperationDate = b.OperationDate,
		@HPNo = b.MobileNo
	FROM TAMS_TAR a, TAMS_TOA b	
		WHERE a.Id = b.TARId
			AND a.Id = @TARID

DECLARE @LogMsg NVARCHAR(100)
SET @LogMsg = ''
SET @LogMsg = CAST(@TARNo AS NVARCHAR(20)) + ' ' + CAST(@TOANo AS NVARCHAR(20)) + ' RGS Cancel Action Log for checking'
-- >> SELECT @LogMsg

INSERT INTO TAMS_Action_Log
VALUES(@Line, 'RGS', 'RGS-Cancel', @TarId, @LogMsg, GETDATE(), 88);

DECLARE @Endorser1 INT
DECLARE @Endorser2 INT

IF @Line = 'DTL'
	BEGIN
		SELECT @Endorser1 = a.ID 
			FROM TAMS_Endorser a, TAMS_Workflow b
				WHERE b.WorkflowType = 'OCCAuth'
					AND a.WorkflowId = b.ID
					AND b.Line = 'DTL'
					AND a.Level = 10

		SELECT @Endorser2 = a.ID 
			FROM TAMS_Endorser a, TAMS_Workflow b
				WHERE b.WorkflowType = 'OCCAuth'
					AND a.WorkflowId = b.ID
					AND b.Line = 'DTL'
					AND a.Level = 12
	END
ELSE
	BEGIN
		SELECT @Endorser1 = a.ID 
			FROM TAMS_Endorser a, TAMS_Workflow b
				WHERE b.WorkflowType = 'OCCAuth'
					AND a.WorkflowId = b.ID
					AND b.Line = 'NEL'
					AND a.Level = 7
	END

DECLARE @Cur01 CURSOR;
DECLARE @TOAStatus	INT

SET @Cur01 = CURSOR FAST_FORWARD 
FOR
SELECT b.TOAStatus
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND b.AccessDate = @AccessDate
			AND b.TOAStatus NOT IN (0, 6)
			AND a.Line = @Line
	ORDER BY b.Id
OPEN @Cur01
FETCH NEXT FROM @Cur01 INTO @TOAStatus
WHILE @@FETCH_STATUS = 0 
	BEGIN
		IF @TOAStatus <> 5
			BEGIN
				SET @lv_IsAllAckSurrender = 0
			END
		FETCH NEXT FROM @Cur01 INTO @TOAStatus
	END 	
CLOSE @Cur01
DEALLOCATE @Cur01

IF @lv_IsAllAckSurrender = 1
	BEGIN
		IF @Line = 'DTL'
			BEGIN
				DECLARE @Cur02 CURSOR;
				DECLARE @Cur03 CURSOR;
				DECLARE @DTLOCCAuthID	INT

				SET @Cur02 = CURSOR FAST_FORWARD 
				FOR
				SELECT a.ID
					FROM TAMS_OCC_Auth a
						WHERE a.Line = @Line
							AND a.OperationDate = @OperationDate
							AND a.AccessDate = @AccessDate
							-- >> If last cancel, start 2nd half of all
							-- >> AND a.OCCAuthStatusId = 10
							AND a.PowerOn = 0
				OPEN @Cur02
				FETCH NEXT FROM @Cur02 INTO @DTLOCCAuthID
				WHILE @@FETCH_STATUS = 0 
					BEGIN
						UPDATE TAMS_OCC_Auth
							SET OCCAuthStatusId = 11,
								UpdatedOn = GETDATE(),
								UpdatedBy = @IDUserID
							WHERE ID = @DTLOCCAuthID

						INSERT INTO [dbo].[TAMS_OCC_Auth_Workflow]
							([OCCAuthId], [OCCAuthEndorserId], [WFStatus], 
								[StationId], [FISTestResult], [ActionOn], [ActionBy])
						VALUES (@DTLOCCAuthID, @Endorser1, 'Pending',
							0, NULL, GETDATE(), @IDUserID)

						FETCH NEXT FROM @Cur02 INTO @DTLOCCAuthID
					END 	
				CLOSE @Cur02
				DEALLOCATE @Cur02


				-- >> Buffer Zone
				-- >> 
				SET @Cur03 = CURSOR FAST_FORWARD 
				FOR
				SELECT a.ID
					FROM TAMS_OCC_Auth a
						WHERE a.Line = @Line
							AND a.OperationDate = @OperationDate
							AND a.AccessDate = @AccessDate
							-- >> If last cancel, start 2nd half of all
							-- >> AND a.OCCAuthStatusId = 7 -- >> Check with Reno how to know this one end already
							AND a.IsBuffer = 1
				OPEN @Cur03
				FETCH NEXT FROM @Cur03 INTO @DTLOCCAuthID
				WHILE @@FETCH_STATUS = 0 
					BEGIN
						UPDATE TAMS_OCC_Auth
							SET OCCAuthStatusId = 13,
								UpdatedOn = GETDATE(),
								UpdatedBy = @IDUserID
							WHERE ID = @DTLOCCAuthID

						INSERT INTO [dbo].[TAMS_OCC_Auth_Workflow]
							([OCCAuthId], [OCCAuthEndorserId], [WFStatus], 
								[StationId], [FISTestResult], [ActionOn], [ActionBy])
						VALUES (@DTLOCCAuthID, @Endorser2, 'Pending', -- >> Check with Reno what is the EndorserID
							0, NULL, GETDATE(), @IDUserID)

						FETCH NEXT FROM @Cur03 INTO @DTLOCCAuthID
					END 	
				CLOSE @Cur03
				DEALLOCATE @Cur03
				-- >> 
				-- >> Buffer Zone
			END
		ELSE
			BEGIN
				DECLARE @Cur04 CURSOR;
				DECLARE @NELOCCAuthID	INT

				SET @Cur02 = CURSOR FAST_FORWARD 
				FOR
				SELECT a.ID
					FROM TAMS_OCC_Auth a
						WHERE a.Line = @Line
							AND a.OperationDate = @OperationDate
							AND a.AccessDate = @AccessDate
							-- >> If last cancel, start 2nd half of all
							-- >> AND a.OCCAuthStatusId = 8
							AND a.PowerOn = 0
				OPEN @Cur02
				FETCH NEXT FROM @Cur02 INTO @NELOCCAuthID
				WHILE @@FETCH_STATUS = 0 
					BEGIN
						UPDATE TAMS_OCC_Auth
							-- SET OCCAuthStatusId = 8,
							SET OCCAuthStatusId = 9,
								UpdatedOn = GETDATE(),
								UpdatedBy = @IDUserID
							WHERE ID = @NELOCCAuthID

						INSERT INTO [dbo].[TAMS_OCC_Auth_Workflow]
							([OCCAuthId], [OCCAuthEndorserId], [WFStatus], 
								[StationId], [FISTestResult], [ActionOn], [ActionBy])
						VALUES (@NELOCCAuthID, @Endorser1, 'Pending',
							0, NULL, GETDATE(), @IDUserID)

						FETCH NEXT FROM @Cur02 INTO @NELOCCAuthID
					END 	
				CLOSE @Cur02
				DEALLOCATE @Cur02
			END
	END


	-- >> 

--IF @Line = 'DTL'
--	BEGIN
--		SET @SMSMsg = CAST(@TOANo AS NVARCHAR(50)) + ' surrender has been acknowledged by DTL OCC @ ' + CAST(@CurrTime AS NVARCHAR(20))
--			+ ' hrs on ' + CAST(@CurrDate AS NVARCHAR(20)) + '. Thank you!'
--	END
--ELSE
--	BEGIN
--		SET @SMSMsg = CAST(@TOANo AS NVARCHAR(50)) + ' surrender has been acknowledged by NEL OCC @ ' + CAST(@CurrTime AS NVARCHAR(20))
--			+ ' hrs on ' + CAST(@CurrDate AS NVARCHAR(20)) + '. Thank you!'
--	END

IF @Line = 'DTL'
	BEGIN
		-- >> SET @SMSMsg = CAST(@NoStr AS NVARCHAR(50)) + ' has been cancelled on TAMS due to TPO/PC inactivity. Please call back OCC at 67187110 if you have surrendered TOA on TAMS.'
		IF CAST(@TOANo AS NVARCHAR(50)) = ''
			BEGIN
				SET @SMSMsg = CAST(@TARNo AS NVARCHAR(50)) + ' has been cancelled on TAMS & contact OCC 67187110, if required.'
			END
		ELSE
			BEGIN
				SET @SMSMsg = CAST(@TOANo AS NVARCHAR(50)) + ' has been cancelled on TAMS & contact OCC 67187110, IMMEDIATELY.'
			END	
	END
ELSE
	BEGIN
		-- >> NEL
		IF CAST(@TOANo AS NVARCHAR(50)) = ''
			BEGIN
				SET @SMSMsg = CAST(@TARNo AS NVARCHAR(50)) + ' has been cancelled on TAMS & contact OCC 64132001, if required.'
			END
		ELSE
			BEGIN
				SET @SMSMsg = CAST(@TOANo AS NVARCHAR(50)) + ' has been cancelled on TAMS & contact OCC 64132001, IMMEDIATELY.'
			END
	END

-- >> SEND SMS
DECLARE @RetVal NVARCHAR(5)
SET @RetVal = ''

	IF @HPNo <> ''
		BEGIN
			EXEC sp_api_send_sms @HPNo, 'TAMS RGS', @SMSMsg, @RetVal OUTPUT
		END

-- >> 20220818 Quickly trigger SMS Sending
	DECLARE @SMSOutputMsg NVARCHAR(500) 

	SET @SMSOutputMsg = ''

	EXEC SP_Call_SMTP_Send_SMSAlert @SMSOutputMsg OUTPUT

	IF @SMSOutputMsg <> ''
		BEGIN
			SET @Message = 'Error SMS Sending'
			--GOTO TRAP_ERROR
		END
-- >> 20220818 Quickly trigger SMS Sending

IF @@ERROR <> 0 BEGIN
	SET @Message = 'Error RGS Cancel'
	GOTO TRAP_ERROR
END

FORCE_EXIT_PROC:	
	IF @IntrnlTrans = 1 COMMIT TRAN
	RETURN @Message 

TRAP_ERROR:
	IF @IntrnlTrans = 1 ROLLBACK TRAN
	RETURN @Message

END
GO
/****** END PROCEDURE 278 ******/

