/****** START PROCEDURE 288 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_RGS_GrantTOA_20230801_M
CREATE PROCEDURE [dbo].[sp_TAMS_RGS_GrantTOA_20230801_M]
	@TARID		AS BIGINT = 0,
	@EncTARID	AS NVARCHAR(250),
	@UserID		AS NVARCHAR(500),
	@Message	AS NVARCHAR(500) = NULL OUTPUT
AS

BEGIN

DECLARE	@IntrnlTrans	TINYINT
SELECT 	@IntrnlTrans 	= 0	

IF (@@TRANCOUNT = 0) 
BEGIN
	SET @IntrnlTrans = 1
	BEGIN TRAN
END

SET @Message = ''

DECLARE @NewLine AS CHAR(2) = CHAR(30) + CHAR(10)

DECLARE @SMSMsg	NVARCHAR(4000)
SET @SMSMsg = ''

DECLARE @OPDate NVARCHAR(20)
DECLARE @TARNo NVARCHAR(50)
DECLARE @Line NVARCHAR(5)
DECLARE @CurrDate NVARCHAR(20)
DECLARE @AccessType NVARCHAR(20)
DECLARE @Site NVARCHAR(200)
DECLARE @HPNo NVARCHAR(20)
DECLARE @TOAStatus INT

SET @TARNo = ''
SET @Line = ''
SET @CurrDate = ''
SET @AccessType = ''
SET @Site = ''
SET @HPNo = ''
SET @TOAStatus = 0

SELECT @TARNo = a.TARNo, 
		@Line = a.Line, 
		@OPDate = CONVERT(NVARCHAR(20), b.OperationDate, 103),
		@AccessType = a.AccessType,
		@HPNo = b.MobileNo,
		@TOAStatus = b.TOAStatus
	FROM TAMS_TAR a, TAMS_TOA b	
		WHERE a.Id = b.TARId
			AND a.Id = @TARID

IF @TOAStatus = 2
	BEGIN
		DECLARE @RefNum		NVARCHAR(20)
		DECLARE @RefNumMsg	NVARCHAR(20)
		SET @RefNum = ''
		SET @RefNumMsg = ''
		EXEC sp_Generate_Ref_Num_TOA 'TOA', @Line, @OPDate, @RefNum OUTPUT, @RefNumMsg OUTPUT

		UPDATE TAMS_TOA
			SET	TOAStatus = 3,
				TOANo = @RefNum,
				GrantTOATime = GETDATE(),
				UpdatedOn = GETDATE(),
				UpdatedBy = @UserID
		WHERE TARId = @TARID

		INSERT INTO TAMS_TOA_Audit
		SELECT @UserID, GETDATE(), 'U', * FROM TAMS_TOA
			WHERE TARId = @TARID

		SET @CurrDate = CONVERT(NVARCHAR(20), GETDATE(), 103)

		--IF @AccessType = 'Possession'
		--	BEGIN
		--		SET @SMSMsg = CAST(@RefNum AS NVARCHAR(50)) + ' has been granted for TAR ID ' + CAST(@TARNo AS NVARCHAR(20))
		--			+ '. You may now setup protection limit. Click on the link to acknowledge TOA :~'
		--			+ @Site + 'https://pulsewebuat.sbstransit.com.sg/TAMS/RGSAckSMS.aspx?TARID=' + CAST(@EncTARID AS NVARCHAR(500)) + '&SMSType=2'
		--	END
		--ELSE
		--	BEGIN
		--		SET @SMSMsg = CAST(@RefNum AS NVARCHAR(50)) + ' has been granted for TAR ID ' + CAST(@TARNo AS NVARCHAR(20))
		--			+ '. You may now proceed to work on track. Click on the link to acknowledge TOA :~'
		--			+ @Site + 'https://pulsewebuat.sbstransit.com.sg/TAMS/RGSAckSMS.aspx?TARID=' + CAST(@EncTARID AS NVARCHAR(500)) + '&SMSType=1'
		--	END

		IF @AccessType = 'Possession'
			BEGIN
				SET @SMSMsg = CAST(@RefNum AS NVARCHAR(50)) + ' has been granted for TAR ID ' + CAST(@TARNo AS NVARCHAR(20))
					+ '. Click on the link to acknowledge TOA :~'
					+ @Site + 'https://sbstweb.sbstransit.com.sg/TAMS/RGSAckSMS.aspx?TARID=' + CAST(@EncTARID AS NVARCHAR(500)) + '&SMSType=2'
			END
		ELSE
			BEGIN
				SET @SMSMsg = CAST(@RefNum AS NVARCHAR(50)) + ' has been granted for TAR ID ' + CAST(@TARNo AS NVARCHAR(20))
					+ '. Click on the link to acknowledge TOA :~'
					+ @Site + 'https://sbstweb.sbstransit.com.sg/TAMS/RGSAckSMS.aspx?TARID=' + CAST(@EncTARID AS NVARCHAR(500)) + '&SMSType=1'
			END


		-- >> SEND SMS
		DECLARE @RetVal NVARCHAR(5)
		SET @RetVal = ''

			IF @HPNo <> ''
				BEGIN
					EXEC sp_api_send_sms @HPNo, 'TAMS RGS', @SMSMsg, @RetVal OUTPUT
				END

		-- >> 20220818 Quickly trigger SMS Sending
			DECLARE @SMSOutputMsg NVARCHAR(500) 

			SET @SMSOutputMsg = ''

			EXEC SP_Call_SMTP_Send_SMSAlert @SMSOutputMsg OUTPUT

			IF @SMSOutputMsg <> ''
				BEGIN
					SET @Message = 'Error SMS Sending'
					GOTO TRAP_ERROR
				END
		-- >> 20220818 Quickly trigger SMS Sending
	END
ELSE
	BEGIN
		IF @TOAStatus = 3
			BEGIN
				SET @Message = '1'
				-- TOA already granted. Please refresh RGS.
				GOTO TRAP_ERROR
			END
		ELSE
			BEGIN
				SET @Message = 'Invalid TAR status. Please refresg RGS.'
				GOTO TRAP_ERROR
			END
	END

IF @@ERROR <> 0 BEGIN
	SET @Message = 'Error RGS Grant TOA'
	GOTO TRAP_ERROR
END

FORCE_EXIT_PROC:	
	IF @IntrnlTrans = 1 COMMIT TRAN
	RETURN @Message 

TRAP_ERROR:
	IF @IntrnlTrans = 1 ROLLBACK TRAN
	RETURN @Message

END
GO
/****** END PROCEDURE 288 ******/

/****** START PROCEDURE 289 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_RGS_OnLoad
CREATE procedure  [dbo].[sp_TAMS_RGS_OnLoad]
	@Line		NVARCHAR(20) = NULL,
	@TrackType	NVARCHAR(50) = NULL
AS

BEGIN

DECLARE @NewLine AS NVARCHAR(6)
SET @NewLine = '<br />'

DECLARE @RGSPossBG			NVARCHAR(20)
DECLARE @RGSProtBG			NVARCHAR(20)
DECLARE @RGSCancBG			NVARCHAR(20)

--DECLARE @trainLine as NVARCHAR(10)
--SET @trainLine='DTL'
--DECLARE @trackType as nvarchar(10)
--SET @trackType='mainline'

DECLARE @accessDate as Date
DECLARE @OperationDate as Date

DECLARE @CurDate		DATE
DECLARE @CurTime		TIME

SET @CurDate =  GETDATE()
SET @CurTime = CONVERT(TIME, GETDATE(), 108)


DECLARE @CutOff	TIME
SET @CutOff = '06:00:00'

	IF @CurTime > @CutOff
		BEGIN
			SET @OperationDate	= @CurDate
			SET @AccessDate		= DATEADD(DAY, 1, @CurDate)
		END
	ELSE
		BEGIN
			SET @OperationDate	= DATEADD(DAY, -1, @CurDate)
			SET @AccessDate		= @CurDate
		END
	
--SET @OperationDate = '2023-11-17'
--SET @AccessDate = '2023-11-18'

SELECT @RGSPossBG = ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'RGSPossessionBG'
			AND ParaValue1 = @Line

SELECT @RGSProtBG = ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'RGSProtectionBG'
			AND ParaValue1 = @Line

SELECT @RGSCancBG = ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'RGSCancelledBG'
			AND ParaValue1 = @Line



DECLARE @TOACallBackTime	NVARCHAR(10)
SET @TOACallBackTime = '04:00'


			
			DECLARE @possession_ctrl as bit=0

			SET @possession_ctrl=IIF(EXISTS(
			(
			
			SELECT counttotal from (
			SELECT Count(1) as counttotal 
			FROM TAMS_TAR a, TAMS_TOA b
			WHERE a.Id = b.TARId
			AND a.AccessDate = @accessDate
			AND b.TOAStatus NOT IN (0, 6)
			AND a.Line = 'DTL'
			and a.TrackType = @TrackType
			AND a.AccessType = 'Possession'
			) B where B.counttotal=(
			SELECT COUNT(*) 
			FROM TAMS_TAR a, TAMS_TOA b
			WHERE a.Id = b.TARId
			AND a.AccessDate = @accessDate
			AND b.TOAStatus NOT IN (0, 6)
			AND a.Line = 'DTL'
			and a.TrackType = @TrackType
			AND a.AccessType = 'Possession' 
			AND NOT (ISNULL(CONVERT(NVARCHAR(5), b.AckProtectionLimitTime, 108), '') = ''
			OR ISNULL(CONVERT(NVARCHAR(5), b.AckProtectionLimitTime, 108), '')= '00:00:00')) )),1,0)
			

			PRINT @possession_ctrl


SELECT ROW_NUMBER() OVER (
ORDER BY a.AccessType, b.TOAStatus DESC,CASE WHEN b.SurrenderTime=NULL THEN 1 ELSE b.SurrenderTime END DESC,CASE WHEN b.GrantTOATime=NULL THEN 1 ELSE b.GrantTOATime END DESC, a.Id
) as Sno,a.TARNo as TARNo, dbo.TAMS_Get_ES_NoBufferZone(a.Id) as ElectricalSections,
		CASE WHEN (a.Line='NEL' AND a.PowerOn = 1 AND a.AccessType='Possession')THEN (
			''
		)  WHEN (a.Line='NEL' ) THEN (
			(SELECT  ISNULL(CONVERT(NVARCHAR(5), max(c.PowerOffTime), 108), '')
					FROM TAMS_OCC_Auth c, TAMS_Traction_Power_Detail d
						WHERE c.TractionPowerId = d.TractionPowerId
							AND d.PowerSectionId in (
							SELECT  PowerSectorId from TAMS_TAR_Power_Sector where TARId = a.Id AND  ((a.PowerOn  = 0) or (a.PowerOn  = 1 and TAMS_TAR_Power_Sector.IsBuffer<>1))
								 )
							AND d.TractionPowerType = 'Sector'
							AND c.OperationDate = @OperationDate
							AND c.AccessDate = @accessDate
							 AND c.PowerOffTime is not null  and c.PowerOffType = 'Completed'
			)
		)  
		ELSE (
					SELECT  ISNULL(CONVERT(NVARCHAR(5), max(c.PowerOffTime), 108), '')
					FROM TAMS_OCC_Auth c, TAMS_Traction_Power_Detail d
						WHERE c.TractionPowerId = d.TractionPowerId
							 AND d.SectorId in (
												SELECT e.SectorId
											FROM TAMS_TAR_Sector e, TAMS_Sector f
												WHERE e.SectorId = f.ID
													AND e.TARId = a.Id
													AND ISNULL(f.IsGap, 0) = 0
													AND e.IsBuffer = 0
											)
							AND d.TractionPowerType = 'Sector'
							AND c.OperationDate = @OperationDate
							AND c.AccessDate = @accessDate
							 AND c.PowerOffTime IS NOT NULL and c.PowerOffType='Completed'
		)END as PowerOffTime, 
		CASE WHEN a.Line='DTL' THEN (
					SELECT  ISNULL(CONVERT(NVARCHAR(5), max(g.RackedOutTime), 108), '')
						FROM TAMS_OCC_Auth g, TAMS_Traction_Power_Detail h 
							WHERE g.TractionPowerId = h.TractionPowerId
								 AND h.SectorId in (
													SELECT g1.SectorId
												FROM TAMS_TAR_Sector g1, TAMS_Sector h1
													WHERE g1.SectorId = h1.ID
														AND g1.TARId = a.Id
														AND ISNULL(h1.IsGap, 0) = 0
														AND g1.IsBuffer = 0
												)
								AND h.TractionPowerType = 'Sector'
								AND g.OperationDate = @OperationDate
								AND g.AccessDate = @accessDate
								 AND g.RackedOutTime IS NOT NULL and g.RackedOutType='Completed'
				
		
		) ELSE (
					SELECT  ISNULL(CONVERT(NVARCHAR(5), max(i.RackedOutTime), 108), '')
					FROM TAMS_OCC_Auth i, TAMS_Traction_Power_Detail j, (
					SELECT i11.TARId 
					FROM TAMS_TAR_AccessReq i11, TAMS_Access_Requirement j11
						WHERE i11.IsPower = 1
							AND i11.OperationRequirement = j11.ID
							AND j11.ID = 27	-- >> 27 FOR NEL
							AND i11.IsSelected = 1
						) j2
						WHERE i.TractionPowerId = j.TractionPowerId
							AND j.PowerSectionId in (
								select PowerSectorId from TAMS_TAR_Power_Sector where TARId = a.Id
							)
							AND j2.TARId=a.Id
							AND j.TractionPowerType = 'Sector'
							AND i.OperationDate = @OperationDate
							AND i.AccessDate = @accessDate
							 AND i.RackedOutTime is not null and i.RackedOutType = 'Completed' 
						) END as CircuitBreakOutTime,
						dbo.TAMS_Get_TOA_Parties(b.Id) as PartiesName,
						b.NoOfParties  as NoOfPersons,a.DescOfWork as WorkDescription, (b.MobileNo + @NewLine + b.TetraRadioNo) as ContactNo
						,ISNULL(b.TOANo, '') as TOANo,
		--b.Id, a.TARNo, a.ARRemark, a.TVFMode, a.AccessType, b.TOAStatus, 
		-- >> ISNULL(CONVERT(NVARCHAR(20), b.AckProtectionLimitTime, 108), '00:00:00'), 
		--ISNULL(CONVERT(NVARCHAR(5), b.AckProtectionLimitTime, 108), ''), 
		--b.NoOfParties as NoOfPersons,
		--a.DescOfWork as WorkDescription, b.MobileNo as ContactNo, b.TetraRadioNo, ISNULL(b.TOANo, '') as TOANo,
		CASE WHEN ISNULL(b.TOANo, '') = '' THEN '' ELSE @TOACallBackTime END as CallBackTime,
		ISNULL(CONVERT(NVARCHAR(5), b.GrantTOATime, 108), '') as RadioMsgTime,
		ISNULL(CONVERT(NVARCHAR(5), b.AckSurrenderTime, 108), '') as LineClearMsgTime,
		[dbo].[SP_TAMS_RGS_Comments](a.Id,b.Id,'NEL','mainline') as Remarks,
		b.TOAStatus,
		CONVERT(bit,
		CASE WHEN a.Line='DTL' THEN 
		(
			SELECT IIF(EXISTS(SELECT * FROM TAMS_OCC_Auth a1, TAMS_Traction_Power_Detail b1
				WHERE a1.TractionPowerId = b1.TractionPowerId AND b1.SectorId in (
												SELECT a2.SectorId
											FROM TAMS_TAR_Sector a2, TAMS_Sector b2
												WHERE a2.SectorId = b2.ID
													AND a2.TARId = a.Id
													AND ISNULL(b2.IsGap, 0) = 0
													AND a2.IsBuffer = 0
											)
											AND b1.TractionPowerType = 'Sector'
											AND a1.OperationDate = @OperationDate
											AND a1.AccessDate = @accessDate
											AND ((a1.OCCAuthStatusId < 10 and a1.IsBuffer = 0) OR ((a1.OCCAuthStatusId < 7 and a1.IsBuffer = 1)))	 
										) or not EXISTS(SELECT aocc1.ID
									FROM TAMS_OCC_Auth aocc1 
									WHERE  aocc1.Line = @Line
									and aocc1.TrackType = @TrackType
									AND aocc1.OperationDate = @OperationDate
									AND aocc1.AccessDate = @AccessDate),0,1) 
		) ELSE (
			SELECT IIF(EXISTS(SELECT *
					FROM TAMS_OCC_Auth aa1, TAMS_Traction_Power_Detail bb1 
						WHERE aa1.TractionPowerId = bb1.TractionPowerId
							AND bb1.PowerSectionId in (
								select PowerSectorId from TAMS_TAR_Power_Sector where TARId = a.Id
							)
							AND bb1.TractionPowerType = 'Sector'
							AND aa1.OperationDate = @OperationDate
							AND aa1.AccessDate = @accessDate
							 AND aa1.OCCAuthStatusId < 8) or not exists(
								select aocc.ID FROM TAMS_OCC_Auth aocc, TAMS_Traction_Power_Detail bpd 
								WHERE aocc.TractionPowerId = bpd.TractionPowerId
									AND bpd.PowerSectionId in (
										select PowerSectorId from TAMS_TAR_Power_Sector where TARId = a.Id
									)
									AND bpd.TractionPowerType = 'Sector'
									AND aocc.OperationDate = @OperationDate
									AND aocc.AccessDate = @AccessDate
							 ),0,1)
		
		) END) as IsTOAAuth,
		CASE WHEN TOAStatus=6 THEN @RGSCancBG ELSE CASE WHEN a.AccessType='Possession' THEN @RGSPossBG ELSE @RGSProtBG END END as ColourCode,
		--Grant TOA
		CONVERT(bit,IIF(b.TOAStatus=6,1,IIF(a.Line='DTL',IIF(a.AccessType='Possession',1, IIF(@possession_ctrl=1,1,0)),1))) as IsGrantTOAEnable,
		ISNULL(CONVERT(NVARCHAR(5), b.UpdateQTSTime, 108), '') as UpdQTSTime,
		a.AccessType as AccessType,
		ISNULL(CONVERT(NVARCHAR(8), b.AckGrantTOATime, 108), '') as AckGrantTOATime,
		ISNULL(CONVERT(NVARCHAR(5), b.AckProtectionLimitTime, 108), '') as AckProtLimitTIme, 
		a.Id as TARID,
		b.Id as TOAID,
		dbo.DecryptString(b.InChargeNRIC) as InChargeNRIC
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND a.AccessDate = @accessDate
			and a.TrackType = @TrackType
			AND b.TOAStatus <> 0
			AND a.Line = @Line
			AND UPPER(a.TrackType)=UPPER(@TrackType)
	ORDER BY a.AccessType, b.TOAStatus DESC, CASE WHEN b.AckSurrenderTime=NULL THEN 1 ELSE b.AckSurrenderTime END DESC,CASE WHEN b.GrantTOATime=NULL THEN 1 ELSE b.GrantTOATime END DESC, a.Id
	-- >> ORDER BY a.AccessType, b.TOAType, a.Id
	--ORDER BY a.AccessType,a.TARNo
	--ORDER BY a.AccessType, b.TOAStatus DESC,CASE WHEN b.GrantTOATime=NULL THEN 1 ELSE b.GrantTOATime END DESC,  a.Id

-- >> Cancel List
SELECT a.Id AS Val, a.TARNo AS Txt
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND b.TOAStatus NOT IN (0, 5, 6)
			AND a.AccessDate = @accessDate
			AND a.Line = @Line
			AND a.TrackType = @TrackType
	ORDER BY 1

SELECT CONVERT(NVARCHAR(20), @OperationDate, 103) AS OperationDate,  
	CONVERT(NVARCHAR(20), @accessDate, 103) AS AccessDate

	
END
GO
/****** END PROCEDURE 289 ******/

/****** START PROCEDURE 290 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_RGS_OnLoad_20221107
CREATE PROCEDURE [dbo].[sp_TAMS_RGS_OnLoad_20221107]
	@Line		NVARCHAR(20) = NULL
AS

BEGIN
	
/*
Notes :
OCCAuthStatusId 
DTL = 10
NEL = 7
*/

CREATE TABLE #TmpRGS 
(Sno				INT,
TARNo				NVARCHAR(30),
ElectricalSections	NVARCHAR(4000),
PowerOffTime		NVARCHAR(20),
CircuitBreakOutTime	NVARCHAR(20),
PartiesName			NVARCHAR(4000),
NoOfPersons			NVARCHAR(20),
WorkDescription		NVARCHAR(4000),
ContactNo			NVARCHAR(50),
TOANo				NVARCHAR(30),
CallBackTime		NVARCHAR(20),
RadioMsgTime		NVARCHAR(20),
LineClearMsgTime	NVARCHAR(20),
Remarks				NVARCHAR(4000),
TOAStatus			NVARCHAR(20),
IsTOAAuth			BIT,
ColourCode			NVARCHAR(20),
IsGrantTOAEnable	BIT,
UpdQTSTime			NVARCHAR(20),
AccessType			NVARCHAR(20),
AckGrantTOATime		NVARCHAR(20),
AckProtLimitTime	NVARCHAR(20),
TARID				INT,
TOAID				INT,
InchargeNRIC		NVARCHAR(100))

CREATE TABLE #TmpRGSSectors 
(OCCAuthID			INT,
OperationDate		DATE,
AccessDate			DATE,
OCCAuthStatus		NVARCHAR(50),
TractionPowerID		INT,
TractionPowerType	NVARCHAR(50),
SectorID			INT,
Sector				NVARCHAR(100),
WorkFlowTime		DATETIME)

TRUNCATE TABLE #TmpRGS
TRUNCATE TABLE #TmpRGSSectors

DECLARE @CurDate		DATE
DECLARE @CurTime		TIME
DECLARE @OperationDate	DATE
DECLARE @AccessDate		DATE

SET @CurDate = GETDATE()
SET @CurTime = CONVERT(TIME, GETDATE(), 108)

DECLARE @CutOff				TIME
DECLARE @TOACallBackTime	NVARCHAR(10)
DECLARE @RGSPossBG			NVARCHAR(20)
DECLARE @RGSProtBG			NVARCHAR(20)

SET @TOACallBackTime = '04:00'
SET @CutOff = '06:00:00'

SELECT @RGSPossBG = ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'RGSPossessionBG'
			AND ParaValue1 = @Line

SELECT @RGSProtBG = ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'RGSProtectionBG'
			AND ParaValue1 = @Line

IF @CurTime > @CutOff
	BEGIN
		SET @OperationDate	= @CurDate
		SET @AccessDate		= DATEADD(DAY, 1, @CurDate)
	END
ELSE
	BEGIN
		SET @OperationDate	= DATEADD(DAY, -1, @CurDate)
		SET @AccessDate		= @CurDate
	END

--SET @OperationDate = '2021-12-19'
--SET @AccessDate = '2021-12-20'
--SELECT @OperationDate, @AccessDate


DECLARE @Cur01 CURSOR;
DECLARE @Cur02 CURSOR;

DECLARE @TARID BIGINT,
@TOAID	BIGINT,
@ARRemark NVARCHAR(1000),
@TVFMode NVARCHAR(20),
@AccessType NVARCHAR(30),
@TOAStatus INT,
@ProtTimeLimit NVARCHAR(10),
@TARNo NVARCHAR(30),
@NoOfParties INT,
@DescOfWork NVARCHAR(1000),
@MobileNo NVARCHAR(20),
@TetraRadioNo NVARCHAR(50),
@TOANo NVARCHAR(50),
@GrantTOATime NVARCHAR(10),
@AckSurrenderTime NVARCHAR(10),
@AckGrantTOATime NVARCHAR(10),
@UpdateQTSTime NVARCHAR(10),
@InchargeNRIC NVARCHAR(100)

DECLARE @lv_Sno INT,
	@lv_IsTOAAuth BIT,
	@lv_PartiesName	NVARCHAR(4000),
	@lv_Remarks	NVARCHAR(4000),
	@lv_IsPowerOff BIT,
	@lv_PowerOffTime NVARCHAR(20),
	@lv_IsCircuitBreak BIT,
	@lv_CircuitBreakTime NVARCHAR(20),
	@lv_ColourCode NVARCHAR(20),
	@lv_ES NVARCHAR(100),
	@lv_SectorID INT,
	@lv_TVFStations NVARCHAR(1000),
	@lv_PossessionCtr INT,
	@lv_IsGrantTOAEnable BIT,
	@lv_ContactNo NVARCHAR(200)

DECLARE @SqlCtr1 INT,
	@SqlCtr2 INT,
	@SqlCtr3 INT,
	@WorkFlowTime NVARCHAR(20)

SET @lv_Sno = 0
SET @SqlCtr1 = 0
SET @SqlCtr2 = 0
SET @SqlCtr3 = 0
SET @lv_PossessionCtr = 0

SELECT @lv_PossessionCtr = COUNT(*)
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND a.AccessDate = @AccessDate
			AND b.TOAStatus NOT IN (0, 6)
			AND a.Line = @Line
			AND a.AccessType = 'Possession'

----DECLARE @NewLine AS CHAR(2) = CHAR(30) + CHAR(10)
DECLARE @NewLine AS NVARCHAR(6)
SET @NewLine = '<br />'
-- >> SELECT @NewUID = SCOPE_IDENTITY();

SET @Cur01 = CURSOR FAST_FORWARD 
FOR

SELECT a.Id, b.Id, a.TARNo, a.ARRemark, a.TVFMode, a.AccessType, b.TOAStatus, 
		-- >> ISNULL(CONVERT(NVARCHAR(20), b.AckProtectionLimitTime, 108), '00:00:00'), 
		ISNULL(CONVERT(NVARCHAR(5), b.AckProtectionLimitTime, 108), ''), 
		b.NoOfParties,
		a.DescOfWork, b.MobileNo, b.TetraRadioNo, ISNULL(b.TOANo, ''),
		ISNULL(CONVERT(NVARCHAR(5), b.GrantTOATime, 108), ''),
		ISNULL(CONVERT(NVARCHAR(5), b.AckSurrenderTime, 108), ''),
		ISNULL(CONVERT(NVARCHAR(8), b.AckGrantTOATime, 108), ''),
		ISNULL(CONVERT(NVARCHAR(5), b.UpdateQTSTime, 108), ''),
		dbo.DecryptString(b.InChargeNRIC)
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND a.AccessDate = @AccessDate
			AND b.TOAStatus <> 0
			AND a.Line = @Line
	-- >> ORDER BY a.AccessType, b.TOAType, a.Id
	ORDER BY a.AccessType, b.TOAStatus DESC, a.Id
	-- >> EXEC sp_TAMS_RGS_OnLoad 'NEL'
OPEN @Cur01
	
FETCH NEXT FROM @Cur01 INTO @TARID, @TOAID, @TARNo, @ARRemark, @TVFMode, @AccessType, @TOAStatus, 
	@ProtTimeLimit, 
	@NoOfParties,
	@DescOfWork, @MobileNo, @TetraRadioNo, @TOANo,
	@GrantTOATime, @AckSurrenderTime, @AckGrantTOATime, @UpdateQTSTime,
	@InchargeNRIC
	
WHILE @@FETCH_STATUS = 0 
	
	BEGIN

		SET @lv_Sno = @lv_Sno + 1
		SET	@lv_IsTOAAuth = 1
		SET @lv_PartiesName	= ''
		SET @lv_Remarks	= ''
		SET @lv_IsPowerOff = 1
		SET @lv_PowerOffTime = ''
		SET @lv_IsCircuitBreak = 1
		SET @lv_CircuitBreakTime = ''
		SET @lv_ColourCode = ''
		SET @lv_ES = ''
		SET @lv_ContactNo = ''

		SELECT @lv_ES = dbo.TAMS_Get_ES_NoBufferZone(@TARID)
		SELECT @lv_PartiesName = dbo.TAMS_Get_TOA_Parties(@TOAID)
		SET @lv_ContactNo = @MobileNo + @NewLine + @TetraRadioNo

		-- >> Electrical Sector Cursor
		-- >> 	EXEC sp_TAMS_RGS_OnLoad_20210819_M 'NEL'

		IF @Line = 'DTL'
			BEGIN
				SET @Cur02 = CURSOR FAST_FORWARD 
				FOR

				SELECT a.SectorId
					FROM TAMS_TAR_Sector a, TAMS_Sector b
						WHERE a.SectorId = b.ID
							AND a.TARId = @TARID
							AND ISNULL(b.IsGap, 0) = 0
							AND a.IsBuffer = 0
					
				OPEN @Cur02
	
				FETCH NEXT FROM @Cur02 INTO @lv_SectorID
	
				WHILE @@FETCH_STATUS = 0 
	
					BEGIN

						SET @SqlCtr1 = 0

						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.Sector, NULL
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.SectorId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND c.IsGap = 0
									-- >> AND a.OCCAuthStatusId = 10
									AND ((a.OCCAuthStatusId = 10 and a.IsBuffer = 0) OR ((a.OCCAuthStatusId = 7 and a.IsBuffer = 1)))
									AND c.Line = @Line

						SELECT @SqlCtr1 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr1 = 0
							BEGIN
								SET @lv_IsTOAAuth = 0
							END

						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.Sector, a.PowerOffTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.SectorId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND c.IsGap = 0
									AND a.PowerOffTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr2 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr2 = 0
							BEGIN
								SET @lv_IsPowerOff = 0
								SET @lv_PowerOffTime = ''
							END
						ELSE
							BEGIN
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM  #TmpRGSSectors

								IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_PowerOffTime = ''
									END
								ELSE
									BEGIN
										SET @lv_PowerOffTime = @WorkFlowTime
									END
							END

						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.Sector, a.RackedOutTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.SectorId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND c.IsGap = 0
									AND a.RackedOutTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr3 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr3 = 0
							BEGIN
								SET @lv_IsCircuitBreak = 0
								SET @lv_CircuitBreakTime = ''
							END
						ELSE
							BEGIN
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM  #TmpRGSSectors

									IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_CircuitBreakTime = ''
									END
								ELSE
									BEGIN
										SET @lv_CircuitBreakTime = @WorkFlowTime
									END
							END
						

						FETCH NEXT FROM @Cur02 INTO @lv_SectorID
					END 	

				CLOSE @Cur02
	
				DEALLOCATE @Cur02
			END
		ELSE
			BEGIN
				SET @Cur02 = CURSOR FAST_FORWARD 
				FOR

				SELECT a.PowerSectorId 
					FROM TAMS_TAR_Power_Sector a
						WHERE a.TARId = @TARID
							AND a.IsBuffer = 0
							

				OPEN @Cur02
	
				FETCH NEXT FROM @Cur02 INTO @lv_SectorID
	
				WHILE @@FETCH_STATUS = 0 
	
					BEGIN

						SET @SqlCtr1 = 0

						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.PowerSection, NULL
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Power_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.PowerSectionId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND a.OCCAuthStatusId = 7
									AND c.Line = @Line

						SELECT @SqlCtr1 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr1 = 0
							BEGIN
								SET @lv_IsTOAAuth = 0
							END

						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.PowerSection, a.PowerOffTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Power_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.PowerSectionId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND a.PowerOffTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr2 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr2 = 0
							BEGIN
								SET @lv_IsPowerOff = 0
								SET @lv_PowerOffTime = ''
							END
						ELSE
							BEGIN
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM  #TmpRGSSectors

									IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_PowerOffTime = ''
									END
								ELSE
									BEGIN
										SET @lv_PowerOffTime = @WorkFlowTime
									END
							END

						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.PowerSection, a.RackedOutTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Power_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.PowerSectionId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND a.RackedOutTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr3 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr3 = 0
							BEGIN
								SET @lv_IsCircuitBreak = 0
								SET @lv_CircuitBreakTime = ''
							END
						ELSE
							BEGIN
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM #TmpRGSSectors

									IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_CircuitBreakTime = ''
									END
								ELSE
									BEGIN
										SET @lv_CircuitBreakTime = @WorkFlowTime
									END
							END

						FETCH NEXT FROM @Cur02 INTO @lv_SectorID
					END 	

				CLOSE @Cur02
	
				DEALLOCATE @Cur02
			END
		-- >>
		-- >> Electrical Sector Cursor

		IF @Line = 'DTL'
			BEGIN
				SET @lv_Remarks = LTRIM(RTRIM(@ARRemark)) + @NewLine + LTRIM(RTRIM(ISNULL(@TVFMode, '')))
			END
		ELSE
			BEGIN
				DECLARE @RackOutCtr	INT

				SELECT @RackOutCtr = COUNT(*) 
					FROM TAMS_TAR_AccessReq a, TAMS_Access_Requirement b
						WHERE a.IsPower = 1
							AND a.OperationRequirement = b.ID
							AND b.ID = 27	-- >> 27 FOR NEL
							AND a.IsSelected = 1
							AND a.TARId = @TARID

				IF @RackOutCtr > 0
					BEGIN
						SET @lv_Remarks = 'Rack Out' + @NewLine + @NewLine + LTRIM(RTRIM(@ARRemark)) + @NewLine + LTRIM(RTRIM(ISNULL(@TVFMode, '')))
					END
				ELSE
					BEGIN
						SET @lv_Remarks = LTRIM(RTRIM(@ARRemark)) + @NewLine + LTRIM(RTRIM(ISNULL(@TVFMode, '')))
					END
				
			END
		SELECT @lv_TVFStations = dbo.TAMS_Get_TOA_TVF_Stations(@TOAID)

		IF @lv_Remarks = ''
			BEGIN
				SET @lv_Remarks = @lv_TVFStations
			END
		ELSE
			BEGIN
				SET @lv_Remarks = @lv_Remarks + @NewLine + @lv_TVFStations
			END

		IF @AccessType = 'Possession'
			BEGIN
				SET @lv_ColourCode = @RGSPossBG

				IF @TOAStatus = 6
					BEGIN
						IF @lv_PossessionCtr = 0
							BEGIN
								SET @lv_PossessionCtr = @lv_PossessionCtr
							END
						ELSE
							BEGIN
								SET @lv_PossessionCtr = @lv_PossessionCtr - 1
							END
					END
				ELSE
					BEGIN
						IF @ProtTimeLimit = '' OR @ProtTimeLimit = '00:00:00'
							BEGIN
								-- >> SELECT '1'
								-- >> SET @lv_PossessionCtr = @lv_PossessionCtr + 1
								SET @lv_PossessionCtr = @lv_PossessionCtr
							END
						ELSE
							BEGIN
								-- >> SELECT '2'
								IF @lv_PossessionCtr = 0
									BEGIN
										-- >> SELECT '3'
										SET @lv_PossessionCtr = @lv_PossessionCtr
									END
								ELSE
									BEGIN
										-- >> SELECT '4'
										SET @lv_PossessionCtr = @lv_PossessionCtr - 1
									END
							END
					END

				SET @lv_IsGrantTOAEnable = 1

			END
		ELSE
			BEGIN
				-- >> SELECT @lv_PossessionCtr AS PossCtr
				-- 	EXEC sp_TAMS_RGS_OnLoad 'NEL'
				SET @lv_ColourCode = @RGSProtBG

				IF @TOAStatus = 6
					BEGIN
						SET @lv_IsGrantTOAEnable = 1
					END
				ELSE
					BEGIN
						IF @lv_PossessionCtr > 0
							BEGIN
								SET @lv_IsGrantTOAEnable = 0
							END
						ELSE
							BEGIN
								SET @lv_IsGrantTOAEnable = 1
							END
					END
			END

		IF @TOANo = ''
			BEGIN
				SET @TOACallBackTime = ''
			END
		
		INSERT INTO #TmpRGS
			(Sno, TARNo, ElectricalSections,
				PowerOffTime, CircuitBreakOutTime,
				PartiesName, NoOfPersons, 
				WorkDescription, ContactNo, TOANo,
				CallBackTime, RadioMsgTime, LineClearMsgTime,
				Remarks, TOAStatus, IsTOAAuth, ColourCode, IsGrantTOAEnable, 
				UpdQTSTime, AccessType,
				AckGrantTOATime, AckProtLimitTime, 
				TARID, TOAID, InchargeNRIC)
		VALUES (@lv_Sno, @TARNo, @lv_ES, 
			@lv_PowerOffTime, @lv_CircuitBreakTime, 
			@lv_PartiesName, @NoOfParties, 
			@DescOfWork, @lv_ContactNo, @TOANo, 
			@TOACallBackTime, @GrantTOATime, @AckSurrenderTime, 
			@lv_Remarks, @TOAStatus, @lv_IsTOAAuth, @lv_ColourCode, @lv_IsGrantTOAEnable, 
			@UpdateQTSTime, @AccessType, 
			@AckGrantTOATime, @ProtTimeLimit, 
			@TARID, @TOAID, @InchargeNRIC)

		FETCH NEXT FROM @Cur01 INTO @TARID, @TOAID, @TARNo, @ARRemark, @TVFMode, @AccessType, @TOAStatus, 
			@ProtTimeLimit, 
			@NoOfParties,
			@DescOfWork, @MobileNo, @TetraRadioNo, @TOANo,
			@GrantTOATime, @AckSurrenderTime, @AckGrantTOATime, @UpdateQTSTime,
			@InchargeNRIC
	END 	

CLOSE @Cur01
	
DEALLOCATE @Cur01


-- >> RGS List
SELECT Sno, TARNo, ElectricalSections,
	PowerOffTime, CircuitBreakOutTime,
	PartiesName, NoOfPersons, 
	WorkDescription, ContactNo, TOANo,
	CallBackTime, RadioMsgTime, LineClearMsgTime,
	Remarks, TOAStatus, IsTOAAuth, ColourCode, IsGrantTOAEnable, 
	UpdQTSTime, AccessType,
	AckGrantTOATime, AckProtLimitTime, 
	TARID, TOAID,
	InchargeNRIC
FROM #TmpRGS
	ORDER BY Sno

-- >> Cancel List
SELECT a.Id AS Val, a.TARNo AS Txt
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND b.TOAStatus NOT IN (0, 5, 6)
			AND a.AccessDate = @AccessDate
			AND a.Line = @Line
	ORDER BY 1

SELECT CONVERT(NVARCHAR(20), @OperationDate, 103) AS OperationDate,  
	CONVERT(NVARCHAR(20), @AccessDate, 103) AS AccessDate

DROP TABLE #TmpRGS
DROP TABLE #TmpRGSSectors

END
GO
/****** END PROCEDURE 290 ******/

/****** START PROCEDURE 291 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_RGS_OnLoad_20221118
CREATE PROCEDURE [dbo].[sp_TAMS_RGS_OnLoad_20221118]
	@Line		NVARCHAR(20) = NULL
AS

BEGIN
	
/*
Notes :
OCCAuthStatusId 
DTL = 10
NEL = 7
*/

CREATE TABLE #TmpRGS 
(Sno				INT,
TARNo				NVARCHAR(30),
ElectricalSections	NVARCHAR(4000),
PowerOffTime		NVARCHAR(20),
CircuitBreakOutTime	NVARCHAR(20),
PartiesName			NVARCHAR(4000),
NoOfPersons			NVARCHAR(20),
WorkDescription		NVARCHAR(4000),
ContactNo			NVARCHAR(50),
TOANo				NVARCHAR(30),
CallBackTime		NVARCHAR(20),
RadioMsgTime		NVARCHAR(20),
LineClearMsgTime	NVARCHAR(20),
Remarks				NVARCHAR(4000),
TOAStatus			NVARCHAR(20),
IsTOAAuth			BIT,
ColourCode			NVARCHAR(20),
IsGrantTOAEnable	BIT,
UpdQTSTime			NVARCHAR(20),
AccessType			NVARCHAR(20),
AckGrantTOATime		NVARCHAR(20),
AckProtLimitTime	NVARCHAR(20),
TARID				INT,
TOAID				INT,
InchargeNRIC		NVARCHAR(100))

CREATE TABLE #TmpRGSSectors 
(OCCAuthID			INT,
OperationDate		DATE,
AccessDate			DATE,
OCCAuthStatus		NVARCHAR(50),
TractionPowerID		INT,
TractionPowerType	NVARCHAR(50),
SectorID			INT,
Sector				NVARCHAR(100),
WorkFlowTime		DATETIME)

TRUNCATE TABLE #TmpRGS
TRUNCATE TABLE #TmpRGSSectors

DECLARE @CurDate		DATE
DECLARE @CurTime		TIME
DECLARE @OperationDate	DATE
DECLARE @AccessDate		DATE

SET @CurDate = GETDATE()
SET @CurTime = CONVERT(TIME, GETDATE(), 108)

DECLARE @CutOff				TIME
DECLARE @TOACallBackTime	NVARCHAR(10)
DECLARE @RGSPossBG			NVARCHAR(20)
DECLARE @RGSProtBG			NVARCHAR(20)

SET @TOACallBackTime = '04:00'
SET @CutOff = '06:00:00'

SELECT @RGSPossBG = ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'RGSPossessionBG'
			AND ParaValue1 = @Line

SELECT @RGSProtBG = ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'RGSProtectionBG'
			AND ParaValue1 = @Line

IF @CurTime > @CutOff
	BEGIN
		SET @OperationDate	= @CurDate
		SET @AccessDate		= DATEADD(DAY, 1, @CurDate)
	END
ELSE
	BEGIN
		SET @OperationDate	= DATEADD(DAY, -1, @CurDate)
		SET @AccessDate		= @CurDate
	END

--SET @OperationDate = '2022-08-23'
--SET @AccessDate = '2022-08-24'
--SELECT @OperationDate, @AccessDate


DECLARE @Cur01 CURSOR;
DECLARE @Cur02 CURSOR;

DECLARE @TARID BIGINT,
@TOAID	BIGINT,
@ARRemark NVARCHAR(1000),
@TVFMode NVARCHAR(20),
@AccessType NVARCHAR(30),
@TOAStatus INT,
@ProtTimeLimit NVARCHAR(10),
@TARNo NVARCHAR(30),
@NoOfParties INT,
@DescOfWork NVARCHAR(1000),
@MobileNo NVARCHAR(20),
@TetraRadioNo NVARCHAR(50),
@TOANo NVARCHAR(50),
@GrantTOATime NVARCHAR(10),
@AckSurrenderTime NVARCHAR(10),
@AckGrantTOATime NVARCHAR(10),
@UpdateQTSTime NVARCHAR(10),
@InchargeNRIC NVARCHAR(100)

DECLARE @lv_Sno INT,
	@lv_IsTOAAuth BIT,
	@lv_PartiesName	NVARCHAR(4000),
	@lv_Remarks	NVARCHAR(4000),
	@lv_IsPowerOff BIT,
	@lv_PowerOffTime NVARCHAR(20),
	@lv_IsCircuitBreak BIT,
	@lv_CircuitBreakTime NVARCHAR(20),
	@lv_ColourCode NVARCHAR(20),
	@lv_ES NVARCHAR(100),
	@lv_SectorID INT,
	@lv_TVFStations NVARCHAR(1000),
	@lv_PossessionCtr INT,
	@lv_IsGrantTOAEnable BIT,
	@lv_ContactNo NVARCHAR(200)

DECLARE @SqlCtr1 INT,
	@SqlCtr2 INT,
	@SqlCtr3 INT,
	@WorkFlowTime NVARCHAR(20)

SET @lv_Sno = 0
SET @SqlCtr1 = 0
SET @SqlCtr2 = 0
SET @SqlCtr3 = 0
SET @lv_PossessionCtr = 0

SELECT @lv_PossessionCtr = COUNT(*)
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND a.AccessDate = @AccessDate
			AND b.TOAStatus NOT IN (0, 6)
			AND a.Line = @Line
			AND a.AccessType = 'Possession'

----DECLARE @NewLine AS CHAR(2) = CHAR(30) + CHAR(10)
DECLARE @NewLine AS NVARCHAR(6)
SET @NewLine = '<br />'
-- >> SELECT @NewUID = SCOPE_IDENTITY();

SET @Cur01 = CURSOR FAST_FORWARD 
FOR

SELECT a.Id, b.Id, a.TARNo, a.ARRemark, a.TVFMode, a.AccessType, b.TOAStatus, 
		-- >> ISNULL(CONVERT(NVARCHAR(20), b.AckProtectionLimitTime, 108), '00:00:00'), 
		ISNULL(CONVERT(NVARCHAR(5), b.AckProtectionLimitTime, 108), ''), 
		b.NoOfParties,
		a.DescOfWork, b.MobileNo, b.TetraRadioNo, ISNULL(b.TOANo, ''),
		ISNULL(CONVERT(NVARCHAR(5), b.GrantTOATime, 108), ''),
		ISNULL(CONVERT(NVARCHAR(5), b.AckSurrenderTime, 108), ''),
		ISNULL(CONVERT(NVARCHAR(8), b.AckGrantTOATime, 108), ''),
		ISNULL(CONVERT(NVARCHAR(5), b.UpdateQTSTime, 108), ''),
		dbo.DecryptString(b.InChargeNRIC)
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND a.AccessDate = @AccessDate
			AND b.TOAStatus <> 0
			AND a.Line = @Line
	-- >> ORDER BY a.AccessType, b.TOAType, a.Id
	ORDER BY a.AccessType, b.TOAStatus DESC, a.Id
	-- >> EXEC sp_TAMS_RGS_OnLoad 'NEL'
OPEN @Cur01
	
FETCH NEXT FROM @Cur01 INTO @TARID, @TOAID, @TARNo, @ARRemark, @TVFMode, @AccessType, @TOAStatus, 
	@ProtTimeLimit, 
	@NoOfParties,
	@DescOfWork, @MobileNo, @TetraRadioNo, @TOANo,
	@GrantTOATime, @AckSurrenderTime, @AckGrantTOATime, @UpdateQTSTime,
	@InchargeNRIC
	
WHILE @@FETCH_STATUS = 0 
	
	BEGIN

		SET @lv_Sno = @lv_Sno + 1
		SET	@lv_IsTOAAuth = 1
		SET @lv_PartiesName	= ''
		SET @lv_Remarks	= ''
		SET @lv_IsPowerOff = 1
		SET @lv_PowerOffTime = ''
		SET @lv_IsCircuitBreak = 1
		SET @lv_CircuitBreakTime = ''
		SET @lv_ColourCode = ''
		SET @lv_ES = ''
		SET @lv_ContactNo = ''

		SELECT @lv_ES = dbo.TAMS_Get_ES_NoBufferZone(@TARID)
		SELECT @lv_PartiesName = dbo.TAMS_Get_TOA_Parties(@TOAID)
		SET @lv_ContactNo = @MobileNo + @NewLine + @TetraRadioNo

		-- >> Electrical Sector Cursor
		-- >> 	EXEC sp_TAMS_RGS_OnLoad_20210819_M 'NEL'

		IF @Line = 'DTL'
			BEGIN
				SET @Cur02 = CURSOR FAST_FORWARD 
				FOR

				SELECT a.SectorId
					FROM TAMS_TAR_Sector a, TAMS_Sector b
						WHERE a.SectorId = b.ID
							AND a.TARId = @TARID
							AND ISNULL(b.IsGap, 0) = 0
							AND a.IsBuffer = 0
					
				OPEN @Cur02
	
				FETCH NEXT FROM @Cur02 INTO @lv_SectorID
	
				WHILE @@FETCH_STATUS = 0 
	
					BEGIN

						SET @SqlCtr1 = 0

						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.Sector, NULL
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.SectorId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND c.IsGap = 0
									-- >> AND a.OCCAuthStatusId = 10
									AND ((a.OCCAuthStatusId = 10 and a.IsBuffer = 0) OR ((a.OCCAuthStatusId = 7 and a.IsBuffer = 1)))
									AND c.Line = @Line

						SELECT @SqlCtr1 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr1 = 0
							BEGIN
								SET @lv_IsTOAAuth = 0
							END

						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.Sector, a.PowerOffTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.SectorId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND c.IsGap = 0
									AND a.PowerOffTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr2 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr2 = 0
							BEGIN
								SET @lv_IsPowerOff = 0
								SET @lv_PowerOffTime = ''
							END
						ELSE
							BEGIN
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM  #TmpRGSSectors

								IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_PowerOffTime = ''
									END
								ELSE
									BEGIN
										SET @lv_PowerOffTime = @WorkFlowTime
									END
							END

						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.Sector, a.RackedOutTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.SectorId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND c.IsGap = 0
									AND a.RackedOutTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr3 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr3 = 0
							BEGIN
								SET @lv_IsCircuitBreak = 0
								SET @lv_CircuitBreakTime = ''
							END
						ELSE
							BEGIN
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM  #TmpRGSSectors

									IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_CircuitBreakTime = ''
									END
								ELSE
									BEGIN
										SET @lv_CircuitBreakTime = @WorkFlowTime
									END
							END
						

						FETCH NEXT FROM @Cur02 INTO @lv_SectorID
					END 	

				CLOSE @Cur02
	
				DEALLOCATE @Cur02
			END
		ELSE
			BEGIN
				SET @Cur02 = CURSOR FAST_FORWARD 
				FOR

				SELECT a.PowerSectorId 
					FROM TAMS_TAR_Power_Sector a
						WHERE a.TARId = @TARID
							AND a.IsBuffer = 0
							

				OPEN @Cur02
	
				FETCH NEXT FROM @Cur02 INTO @lv_SectorID
	
				WHILE @@FETCH_STATUS = 0 
	
					BEGIN

						SET @SqlCtr1 = 0

						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.PowerSection, NULL
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Power_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.PowerSectionId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND a.OCCAuthStatusId = 8
									AND c.Line = @Line

						SELECT @SqlCtr1 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr1 = 0
							BEGIN
								SET @lv_IsTOAAuth = 0
							END

						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.PowerSection, a.PowerOffTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Power_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.PowerSectionId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND a.PowerOffTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr2 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr2 = 0
							BEGIN
								SET @lv_IsPowerOff = 0
								SET @lv_PowerOffTime = ''
							END
						ELSE
							BEGIN
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM  #TmpRGSSectors

									IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_PowerOffTime = ''
									END
								ELSE
									BEGIN
										SET @lv_PowerOffTime = @WorkFlowTime
									END
							END

						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.PowerSection, a.RackedOutTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Power_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.PowerSectionId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND a.RackedOutTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr3 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr3 = 0
							BEGIN
								SET @lv_IsCircuitBreak = 0
								SET @lv_CircuitBreakTime = ''
							END
						ELSE
							BEGIN
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM #TmpRGSSectors

									IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_CircuitBreakTime = ''
									END
								ELSE
									BEGIN
										SET @lv_CircuitBreakTime = @WorkFlowTime
									END
							END

						FETCH NEXT FROM @Cur02 INTO @lv_SectorID
					END 	

				CLOSE @Cur02
	
				DEALLOCATE @Cur02
			END
		-- >>
		-- >> Electrical Sector Cursor

		IF @Line = 'DTL'
			BEGIN
				SET @lv_Remarks = LTRIM(RTRIM(@ARRemark)) + @NewLine + LTRIM(RTRIM(ISNULL(@TVFMode, '')))
			END
		ELSE
			BEGIN
				DECLARE @RackOutCtr	INT

				SELECT @RackOutCtr = COUNT(*) 
					FROM TAMS_TAR_AccessReq a, TAMS_Access_Requirement b
						WHERE a.IsPower = 1
							AND a.OperationRequirement = b.ID
							AND b.ID = 27	-- >> 27 FOR NEL
							AND a.IsSelected = 1
							AND a.TARId = @TARID

				IF @RackOutCtr > 0
					BEGIN
						SET @lv_Remarks = 'Rack Out' + @NewLine + @NewLine + LTRIM(RTRIM(@ARRemark)) + @NewLine + LTRIM(RTRIM(ISNULL(@TVFMode, '')))
					END
				ELSE
					BEGIN
						SET @lv_Remarks = LTRIM(RTRIM(@ARRemark)) + @NewLine + LTRIM(RTRIM(ISNULL(@TVFMode, '')))
					END
			END

		DECLARE @SCDCtr	INT

		SELECT @SCDCtr = COUNT(*) 
			FROM TAMS_TAR_AccessReq a, TAMS_Access_Requirement b
				WHERE a.IsPower = 1
					AND a.OperationRequirement = b.ID
					AND b.OperationRequirement = 'SCD Application'
					AND a.IsSelected = 1
					AND a.TARId = @TARID

		IF @SCDCtr > 0
			BEGIN
				SET @lv_Remarks = 'SCD' + @NewLine + @NewLine + LTRIM(RTRIM(@lv_Remarks))
			END
			
		SELECT @lv_TVFStations = dbo.TAMS_Get_TOA_TVF_Stations(@TOAID)

		IF @lv_Remarks = ''
			BEGIN
				SET @lv_Remarks = @lv_TVFStations
			END
		ELSE
			BEGIN
				SET @lv_Remarks = @lv_Remarks + @NewLine + @lv_TVFStations
			END

		IF @AccessType = 'Possession'
			BEGIN
				SET @lv_ColourCode = @RGSPossBG

				IF @TOAStatus = 6
					BEGIN
						IF @lv_PossessionCtr = 0
							BEGIN
								SET @lv_PossessionCtr = @lv_PossessionCtr
							END
						ELSE
							BEGIN
								SET @lv_PossessionCtr = @lv_PossessionCtr - 1
							END
					END
				ELSE
					BEGIN
						IF @ProtTimeLimit = '' OR @ProtTimeLimit = '00:00:00'
							BEGIN
								-- >> SELECT '1'
								SET @lv_PossessionCtr = @lv_PossessionCtr + 1
								-- >> SET @lv_PossessionCtr = @lv_PossessionCtr
							END
						ELSE
							BEGIN
								-- >> SELECT '2'
								IF @lv_PossessionCtr = 0
									BEGIN
										-- >> SELECT '3'
										SET @lv_PossessionCtr = @lv_PossessionCtr
									END
								ELSE
									BEGIN
										-- >> SELECT '4'
										SET @lv_PossessionCtr = @lv_PossessionCtr - 1
									END
							END
					END

				SET @lv_IsGrantTOAEnable = 1

			END
		ELSE
			BEGIN
				-- >> SELECT @lv_PossessionCtr AS PossCtr
				-- 	EXEC sp_TAMS_RGS_OnLoad 'DTL'
				SET @lv_ColourCode = @RGSProtBG

				IF @TOAStatus = 6
					BEGIN
						SET @lv_IsGrantTOAEnable = 1
					END
				ELSE
					BEGIN
						IF @lv_PossessionCtr > 0
							BEGIN
								SET @lv_IsGrantTOAEnable = 0
							END
						ELSE
							BEGIN
								SET @lv_IsGrantTOAEnable = 1
							END
					END
			END

		IF @TOANo = ''
			BEGIN
				SET @TOACallBackTime = ''
			END
		ELSE
			BEGIN
				SET @TOACallBackTime = '04:00'
			END
		
		INSERT INTO #TmpRGS
			(Sno, TARNo, ElectricalSections,
				PowerOffTime, CircuitBreakOutTime,
				PartiesName, NoOfPersons, 
				WorkDescription, ContactNo, TOANo,
				CallBackTime, RadioMsgTime, LineClearMsgTime,
				Remarks, TOAStatus, IsTOAAuth, ColourCode, IsGrantTOAEnable, 
				UpdQTSTime, AccessType,
				AckGrantTOATime, AckProtLimitTime, 
				TARID, TOAID, InchargeNRIC)
		VALUES (@lv_Sno, @TARNo, @lv_ES, 
			@lv_PowerOffTime, @lv_CircuitBreakTime, 
			@lv_PartiesName, @NoOfParties, 
			@DescOfWork, @lv_ContactNo, @TOANo, 
			@TOACallBackTime, @GrantTOATime, @AckSurrenderTime, 
			@lv_Remarks, @TOAStatus, @lv_IsTOAAuth, @lv_ColourCode, @lv_IsGrantTOAEnable, 
			@UpdateQTSTime, @AccessType, 
			@AckGrantTOATime, @ProtTimeLimit, 
			@TARID, @TOAID, @InchargeNRIC)

		FETCH NEXT FROM @Cur01 INTO @TARID, @TOAID, @TARNo, @ARRemark, @TVFMode, @AccessType, @TOAStatus, 
			@ProtTimeLimit, 
			@NoOfParties,
			@DescOfWork, @MobileNo, @TetraRadioNo, @TOANo,
			@GrantTOATime, @AckSurrenderTime, @AckGrantTOATime, @UpdateQTSTime,
			@InchargeNRIC
	END 	

CLOSE @Cur01
	
DEALLOCATE @Cur01


-- >> RGS List
SELECT Sno, TARNo, ElectricalSections,
	PowerOffTime, CircuitBreakOutTime,
	PartiesName, NoOfPersons, 
	WorkDescription, ContactNo, TOANo,
	CallBackTime, RadioMsgTime, LineClearMsgTime,
	Remarks, TOAStatus, IsTOAAuth, ColourCode, IsGrantTOAEnable, 
	UpdQTSTime, AccessType,
	AckGrantTOATime, AckProtLimitTime, 
	TARID, TOAID,
	InchargeNRIC
FROM #TmpRGS
	ORDER BY Sno

-- >> Cancel List
SELECT a.Id AS Val, a.TARNo AS Txt
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND b.TOAStatus NOT IN (0, 5, 6)
			AND a.AccessDate = @AccessDate
			AND a.Line = @Line
	ORDER BY 1

SELECT CONVERT(NVARCHAR(20), @OperationDate, 103) AS OperationDate,  
	CONVERT(NVARCHAR(20), @AccessDate, 103) AS AccessDate

DROP TABLE #TmpRGS
DROP TABLE #TmpRGSSectors

END

GO
/****** END PROCEDURE 291 ******/

/****** START PROCEDURE 292 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_RGS_OnLoad_20221118_M
CREATE PROCEDURE [dbo].[sp_TAMS_RGS_OnLoad_20221118_M]
	@Line		NVARCHAR(20) = NULL
AS

BEGIN
	
/*
Notes :
OCCAuthStatusId 
DTL = 10
NEL = 7
*/

CREATE TABLE #TmpRGS 
(Sno				INT,
TARNo				NVARCHAR(30),
ElectricalSections	NVARCHAR(4000),
PowerOffTime		NVARCHAR(20),
CircuitBreakOutTime	NVARCHAR(20),
PartiesName			NVARCHAR(4000),
NoOfPersons			NVARCHAR(20),
WorkDescription		NVARCHAR(4000),
ContactNo			NVARCHAR(50),
TOANo				NVARCHAR(30),
CallBackTime		NVARCHAR(20),
RadioMsgTime		NVARCHAR(20),
LineClearMsgTime	NVARCHAR(20),
Remarks				NVARCHAR(4000),
TOAStatus			NVARCHAR(20),
IsTOAAuth			BIT,
ColourCode			NVARCHAR(20),
IsGrantTOAEnable	BIT,
UpdQTSTime			NVARCHAR(20),
AccessType			NVARCHAR(20),
AckGrantTOATime		NVARCHAR(20),
AckProtLimitTime	NVARCHAR(20),
TARID				INT,
TOAID				INT,
InchargeNRIC		NVARCHAR(100))

CREATE TABLE #TmpRGSSectors 
(OCCAuthID			INT,
OperationDate		DATE,
AccessDate			DATE,
OCCAuthStatus		NVARCHAR(50),
TractionPowerID		INT,
TractionPowerType	NVARCHAR(50),
SectorID			INT,
Sector				NVARCHAR(100),
WorkFlowTime		DATETIME)

TRUNCATE TABLE #TmpRGS
TRUNCATE TABLE #TmpRGSSectors

DECLARE @CurDate		DATE
DECLARE @CurTime		TIME
DECLARE @OperationDate	DATE
DECLARE @AccessDate		DATE

SET @CurDate = GETDATE()
SET @CurTime = CONVERT(TIME, GETDATE(), 108)

DECLARE @CutOff				TIME
DECLARE @TOACallBackTime	NVARCHAR(10)
DECLARE @RGSPossBG			NVARCHAR(20)
DECLARE @RGSProtBG			NVARCHAR(20)

SET @TOACallBackTime = '04:00'
SET @CutOff = '06:00:00'

SELECT @RGSPossBG = ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'RGSPossessionBG'
			AND ParaValue1 = @Line

SELECT @RGSProtBG = ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'RGSProtectionBG'
			AND ParaValue1 = @Line

IF @CurTime > @CutOff
	BEGIN
		SET @OperationDate	= @CurDate
		SET @AccessDate		= DATEADD(DAY, 1, @CurDate)
	END
ELSE
	BEGIN
		SET @OperationDate	= DATEADD(DAY, -1, @CurDate)
		SET @AccessDate		= @CurDate
	END

SET @OperationDate = '2022-11-17'
SET @AccessDate = '2022-11-18'
SELECT @OperationDate, @AccessDate

-- EXEC sp_TAMS_RGS_OnLoad_20221118_M 'DTL' 

DECLARE @Cur01 CURSOR;
DECLARE @Cur02 CURSOR;

DECLARE @TARID BIGINT,
@TOAID	BIGINT,
@ARRemark NVARCHAR(1000),
@TVFMode NVARCHAR(20),
@AccessType NVARCHAR(30),
@TOAStatus INT,
@ProtTimeLimit NVARCHAR(10),
@TARNo NVARCHAR(30),
@NoOfParties INT,
@DescOfWork NVARCHAR(1000),
@MobileNo NVARCHAR(20),
@TetraRadioNo NVARCHAR(50),
@TOANo NVARCHAR(50),
@GrantTOATime NVARCHAR(10),
@AckSurrenderTime NVARCHAR(10),
@AckGrantTOATime NVARCHAR(10),
@UpdateQTSTime NVARCHAR(10),
@InchargeNRIC NVARCHAR(100)

DECLARE @lv_Sno INT,
	@lv_IsTOAAuth BIT,
	@lv_PartiesName	NVARCHAR(4000),
	@lv_Remarks	NVARCHAR(4000),
	@lv_IsPowerOff BIT,
	@lv_PowerOffTime NVARCHAR(20),
	@lv_IsCircuitBreak BIT,
	@lv_CircuitBreakTime NVARCHAR(20),
	@lv_ColourCode NVARCHAR(20),
	@lv_ES NVARCHAR(100),
	@lv_SectorID INT,
	@lv_TVFStations NVARCHAR(1000),
	@lv_PossessionCtr INT,
	@lv_IsGrantTOAEnable BIT,
	@lv_ContactNo NVARCHAR(200)

DECLARE @SqlCtr1 INT,
	@SqlCtr2 INT,
	@SqlCtr3 INT,
	@WorkFlowTime NVARCHAR(20)

SET @lv_Sno = 0
SET @SqlCtr1 = 0
SET @SqlCtr2 = 0
SET @SqlCtr3 = 0
SET @lv_PossessionCtr = 0

SELECT @lv_PossessionCtr = COUNT(*)
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND a.AccessDate = @AccessDate
			AND b.TOAStatus NOT IN (0, 6)
			AND a.Line = @Line
			AND a.AccessType = 'Possession'

----DECLARE @NewLine AS CHAR(2) = CHAR(30) + CHAR(10)
DECLARE @NewLine AS NVARCHAR(6)
SET @NewLine = '<br />'
-- >> SELECT @NewUID = SCOPE_IDENTITY();

SET @Cur01 = CURSOR FAST_FORWARD 
FOR

SELECT a.Id, b.Id, a.TARNo, a.ARRemark, a.TVFMode, a.AccessType, b.TOAStatus, 
		-- >> ISNULL(CONVERT(NVARCHAR(20), b.AckProtectionLimitTime, 108), '00:00:00'), 
		CASE WHEN a.id = 10983 THEN '01:22:23' ELSE ISNULL(CONVERT(NVARCHAR(5), b.AckProtectionLimitTime, 108), '') END, 
		b.NoOfParties,
		a.DescOfWork, b.MobileNo, b.TetraRadioNo, ISNULL(b.TOANo, ''),
		ISNULL(CONVERT(NVARCHAR(5), b.GrantTOATime, 108), ''),
		ISNULL(CONVERT(NVARCHAR(5), b.AckSurrenderTime, 108), ''),
		ISNULL(CONVERT(NVARCHAR(8), b.AckGrantTOATime, 108), ''),
		ISNULL(CONVERT(NVARCHAR(5), b.UpdateQTSTime, 108), ''),
		dbo.DecryptString(b.InChargeNRIC)
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND a.AccessDate = @AccessDate
			AND b.TOAStatus <> 0
			AND a.Line = @Line
	-- >> ORDER BY a.AccessType, b.TOAType, a.Id
	ORDER BY a.AccessType, b.TOAStatus DESC, a.Id
	-- >> EXEC sp_TAMS_RGS_OnLoad 'NEL'
OPEN @Cur01
	
FETCH NEXT FROM @Cur01 INTO @TARID, @TOAID, @TARNo, @ARRemark, @TVFMode, @AccessType, @TOAStatus, 
	@ProtTimeLimit, 
	@NoOfParties,
	@DescOfWork, @MobileNo, @TetraRadioNo, @TOANo,
	@GrantTOATime, @AckSurrenderTime, @AckGrantTOATime, @UpdateQTSTime,
	@InchargeNRIC
	
WHILE @@FETCH_STATUS = 0 
	
	BEGIN

		SET @lv_Sno = @lv_Sno + 1
		SET	@lv_IsTOAAuth = 1
		SET @lv_PartiesName	= ''
		SET @lv_Remarks	= ''
		SET @lv_IsPowerOff = 1
		SET @lv_PowerOffTime = ''
		SET @lv_IsCircuitBreak = 1
		SET @lv_CircuitBreakTime = ''
		SET @lv_ColourCode = ''
		SET @lv_ES = ''
		SET @lv_ContactNo = ''

		SELECT @lv_ES = dbo.TAMS_Get_ES_NoBufferZone(@TARID)
		SELECT @lv_PartiesName = dbo.TAMS_Get_TOA_Parties(@TOAID)
		SET @lv_ContactNo = @MobileNo + @NewLine + @TetraRadioNo

		-- >> Electrical Sector Cursor
		-- >> 	EXEC sp_TAMS_RGS_OnLoad_20210819_M 'NEL'

		IF @Line = 'DTL'
			BEGIN
				SET @Cur02 = CURSOR FAST_FORWARD 
				FOR

				SELECT a.SectorId
					FROM TAMS_TAR_Sector a, TAMS_Sector b
						WHERE a.SectorId = b.ID
							AND a.TARId = @TARID
							AND ISNULL(b.IsGap, 0) = 0
							AND a.IsBuffer = 0
					
				OPEN @Cur02
	
				FETCH NEXT FROM @Cur02 INTO @lv_SectorID
	
				WHILE @@FETCH_STATUS = 0 
	
					BEGIN

						SET @SqlCtr1 = 0

						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.Sector, NULL
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.SectorId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND c.IsGap = 0
									-- >> AND a.OCCAuthStatusId = 10
									AND ((a.OCCAuthStatusId = 10 and a.IsBuffer = 0) OR ((a.OCCAuthStatusId = 7 and a.IsBuffer = 1)))
									AND c.Line = @Line

						SELECT @SqlCtr1 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr1 = 0
							BEGIN
								SET @lv_IsTOAAuth = 0
							END

						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.Sector, a.PowerOffTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.SectorId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND c.IsGap = 0
									AND a.PowerOffTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr2 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr2 = 0
							BEGIN
								SET @lv_IsPowerOff = 0
								SET @lv_PowerOffTime = ''
							END
						ELSE
							BEGIN
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM  #TmpRGSSectors

								IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_PowerOffTime = ''
									END
								ELSE
									BEGIN
										SET @lv_PowerOffTime = @WorkFlowTime
									END
							END

						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.Sector, a.RackedOutTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.SectorId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND c.IsGap = 0
									AND a.RackedOutTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr3 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr3 = 0
							BEGIN
								SET @lv_IsCircuitBreak = 0
								SET @lv_CircuitBreakTime = ''
							END
						ELSE
							BEGIN
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM  #TmpRGSSectors

									IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_CircuitBreakTime = ''
									END
								ELSE
									BEGIN
										SET @lv_CircuitBreakTime = @WorkFlowTime
									END
							END
						

						FETCH NEXT FROM @Cur02 INTO @lv_SectorID
					END 	

				CLOSE @Cur02
	
				DEALLOCATE @Cur02
			END
		ELSE
			BEGIN
				SET @Cur02 = CURSOR FAST_FORWARD 
				FOR

				SELECT a.PowerSectorId 
					FROM TAMS_TAR_Power_Sector a
						WHERE a.TARId = @TARID
							AND a.IsBuffer = 0
							

				OPEN @Cur02
	
				FETCH NEXT FROM @Cur02 INTO @lv_SectorID
	
				WHILE @@FETCH_STATUS = 0 
	
					BEGIN

						SET @SqlCtr1 = 0

						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.PowerSection, NULL
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Power_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.PowerSectionId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND a.OCCAuthStatusId = 8
									AND c.Line = @Line

						SELECT @SqlCtr1 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr1 = 0
							BEGIN
								SET @lv_IsTOAAuth = 0
							END

						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.PowerSection, a.PowerOffTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Power_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.PowerSectionId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND a.PowerOffTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr2 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr2 = 0
							BEGIN
								SET @lv_IsPowerOff = 0
								SET @lv_PowerOffTime = ''
							END
						ELSE
							BEGIN
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM  #TmpRGSSectors

									IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_PowerOffTime = ''
									END
								ELSE
									BEGIN
										SET @lv_PowerOffTime = @WorkFlowTime
									END
							END

						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.PowerSection, a.RackedOutTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Power_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.PowerSectionId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND a.RackedOutTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr3 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr3 = 0
							BEGIN
								SET @lv_IsCircuitBreak = 0
								SET @lv_CircuitBreakTime = ''
							END
						ELSE
							BEGIN
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM #TmpRGSSectors

									IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_CircuitBreakTime = ''
									END
								ELSE
									BEGIN
										SET @lv_CircuitBreakTime = @WorkFlowTime
									END
							END

						FETCH NEXT FROM @Cur02 INTO @lv_SectorID
					END 	

				CLOSE @Cur02
	
				DEALLOCATE @Cur02
			END
		-- >>
		-- >> Electrical Sector Cursor

		IF @Line = 'DTL'
			BEGIN
				SET @lv_Remarks = LTRIM(RTRIM(@ARRemark)) + @NewLine + LTRIM(RTRIM(ISNULL(@TVFMode, '')))
			END
		ELSE
			BEGIN
				DECLARE @RackOutCtr	INT

				SELECT @RackOutCtr = COUNT(*) 
					FROM TAMS_TAR_AccessReq a, TAMS_Access_Requirement b
						WHERE a.IsPower = 1
							AND a.OperationRequirement = b.ID
							AND b.ID = 27	-- >> 27 FOR NEL
							AND a.IsSelected = 1
							AND a.TARId = @TARID

				IF @RackOutCtr > 0
					BEGIN
						SET @lv_Remarks = 'Rack Out' + @NewLine + @NewLine + LTRIM(RTRIM(@ARRemark)) + @NewLine + LTRIM(RTRIM(ISNULL(@TVFMode, '')))
					END
				ELSE
					BEGIN
						SET @lv_Remarks = LTRIM(RTRIM(@ARRemark)) + @NewLine + LTRIM(RTRIM(ISNULL(@TVFMode, '')))
					END
			END

		DECLARE @SCDCtr	INT

		SELECT @SCDCtr = COUNT(*) 
			FROM TAMS_TAR_AccessReq a, TAMS_Access_Requirement b
				WHERE a.IsPower = 1
					AND a.OperationRequirement = b.ID
					AND b.OperationRequirement = 'SCD Application'
					AND a.IsSelected = 1
					AND a.TARId = @TARID

		IF @SCDCtr > 0
			BEGIN
				SET @lv_Remarks = 'SCD' + @NewLine + @NewLine + LTRIM(RTRIM(@lv_Remarks))
			END
			
		SELECT @lv_TVFStations = dbo.TAMS_Get_TOA_TVF_Stations(@TOAID)

		IF @lv_Remarks = ''
			BEGIN
				SET @lv_Remarks = @lv_TVFStations
			END
		ELSE
			BEGIN
				SET @lv_Remarks = @lv_Remarks + @NewLine + @lv_TVFStations
			END


		--EXEC sp_TAMS_RGS_OnLoad_20221118_M 'DTL'

		SELECT 'PossCtr', @lv_PossessionCtr

		IF @AccessType = 'Possession'
			BEGIN
				SET @lv_ColourCode = @RGSPossBG

				IF @TOAStatus = 6
					BEGIN
						IF @lv_PossessionCtr = 0
							BEGIN
								SET @lv_PossessionCtr = @lv_PossessionCtr
							END
						ELSE
							BEGIN
								SET @lv_PossessionCtr = @lv_PossessionCtr - 1
							END
					END
				ELSE
					BEGIN
						IF @ProtTimeLimit = '' OR @ProtTimeLimit = '00:00:00'
							BEGIN
								SELECT '1'
								SET @lv_PossessionCtr = @lv_PossessionCtr + 1
								-- >> SET @lv_PossessionCtr = @lv_PossessionCtr
							END
						ELSE
							BEGIN
								-- >> SELECT '2'
								IF @lv_PossessionCtr = 0
									BEGIN
										SELECT '3'
										SET @lv_PossessionCtr = @lv_PossessionCtr
									END
								ELSE
									BEGIN
										SELECT '4'
										SET @lv_PossessionCtr = @lv_PossessionCtr - 1
									END
							END
					END

				SET @lv_IsGrantTOAEnable = 1

			END
		ELSE
			BEGIN
				-- >> SELECT @lv_PossessionCtr AS PossCtr
				-- 	EXEC sp_TAMS_RGS_OnLoad 'DTL'
				SET @lv_ColourCode = @RGSProtBG

				IF @TOAStatus = 6
					BEGIN
						SET @lv_IsGrantTOAEnable = 1
					END
				ELSE
					BEGIN
						IF @lv_PossessionCtr > 0
							BEGIN
								SET @lv_IsGrantTOAEnable = 0
							END
						ELSE
							BEGIN
								SET @lv_IsGrantTOAEnable = 1
							END
					END
			END

		IF @TOANo = ''
			BEGIN
				SET @TOACallBackTime = ''
			END
		ELSE
			BEGIN
				SET @TOACallBackTime = '04:00'
			END
		
		INSERT INTO #TmpRGS
			(Sno, TARNo, ElectricalSections,
				PowerOffTime, CircuitBreakOutTime,
				PartiesName, NoOfPersons, 
				WorkDescription, ContactNo, TOANo,
				CallBackTime, RadioMsgTime, LineClearMsgTime,
				Remarks, TOAStatus, IsTOAAuth, ColourCode, IsGrantTOAEnable, 
				UpdQTSTime, AccessType,
				AckGrantTOATime, AckProtLimitTime, 
				TARID, TOAID, InchargeNRIC)
		VALUES (@lv_Sno, @TARNo, @lv_ES, 
			@lv_PowerOffTime, @lv_CircuitBreakTime, 
			@lv_PartiesName, @NoOfParties, 
			@DescOfWork, @lv_ContactNo, @TOANo, 
			@TOACallBackTime, @GrantTOATime, @AckSurrenderTime, 
			@lv_Remarks, @TOAStatus, @lv_IsTOAAuth, @lv_ColourCode, @lv_IsGrantTOAEnable, 
			@UpdateQTSTime, @AccessType, 
			@AckGrantTOATime, @ProtTimeLimit, 
			@TARID, @TOAID, @InchargeNRIC)

		FETCH NEXT FROM @Cur01 INTO @TARID, @TOAID, @TARNo, @ARRemark, @TVFMode, @AccessType, @TOAStatus, 
			@ProtTimeLimit, 
			@NoOfParties,
			@DescOfWork, @MobileNo, @TetraRadioNo, @TOANo,
			@GrantTOATime, @AckSurrenderTime, @AckGrantTOATime, @UpdateQTSTime,
			@InchargeNRIC
	END 	

CLOSE @Cur01
	
DEALLOCATE @Cur01


-- >> RGS List
SELECT Sno, TARNo, ElectricalSections,
	PowerOffTime, CircuitBreakOutTime,
	PartiesName, NoOfPersons, 
	WorkDescription, ContactNo, TOANo,
	CallBackTime, RadioMsgTime, LineClearMsgTime,
	Remarks, TOAStatus, IsTOAAuth, ColourCode, IsGrantTOAEnable, 
	UpdQTSTime, AccessType,
	AckGrantTOATime, AckProtLimitTime, 
	TARID, TOAID,
	InchargeNRIC
FROM #TmpRGS
	ORDER BY Sno

-- >> Cancel List
SELECT a.Id AS Val, a.TARNo AS Txt
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND b.TOAStatus NOT IN (0, 5, 6)
			AND a.AccessDate = @AccessDate
			AND a.Line = @Line
	ORDER BY 1

SELECT CONVERT(NVARCHAR(20), @OperationDate, 103) AS OperationDate,  
	CONVERT(NVARCHAR(20), @AccessDate, 103) AS AccessDate

DROP TABLE #TmpRGS
DROP TABLE #TmpRGSSectors

END

GO
/****** END PROCEDURE 292 ******/

/****** START PROCEDURE 293 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_RGS_OnLoad_20230202
CREATE PROCEDURE [dbo].[sp_TAMS_RGS_OnLoad_20230202]
	@Line		NVARCHAR(20) = NULL
AS

BEGIN
	
/*
Notes :
OCCAuthStatusId 
DTL = 10
NEL = 7
*/

CREATE TABLE #TmpRGS 
(Sno				INT,
TARNo				NVARCHAR(30),
ElectricalSections	NVARCHAR(4000),
PowerOffTime		NVARCHAR(20),
CircuitBreakOutTime	NVARCHAR(20),
PartiesName			NVARCHAR(4000),
NoOfPersons			NVARCHAR(20),
WorkDescription		NVARCHAR(4000),
ContactNo			NVARCHAR(50),
TOANo				NVARCHAR(30),
CallBackTime		NVARCHAR(20),
RadioMsgTime		NVARCHAR(20),
LineClearMsgTime	NVARCHAR(20),
Remarks				NVARCHAR(4000),
TOAStatus			NVARCHAR(20),
IsTOAAuth			BIT,
ColourCode			NVARCHAR(20),
IsGrantTOAEnable	BIT,
UpdQTSTime			NVARCHAR(20),
AccessType			NVARCHAR(20),
AckGrantTOATime		NVARCHAR(20),
AckProtLimitTime	NVARCHAR(20),
TARID				INT,
TOAID				INT,
InchargeNRIC		NVARCHAR(100))

CREATE TABLE #TmpRGSSectors 
(OCCAuthID			INT,
OperationDate		DATE,
AccessDate			DATE,
OCCAuthStatus		NVARCHAR(50),
TractionPowerID		INT,
TractionPowerType	NVARCHAR(50),
SectorID			INT,
Sector				NVARCHAR(100),
WorkFlowTime		DATETIME)

TRUNCATE TABLE #TmpRGS
TRUNCATE TABLE #TmpRGSSectors

DECLARE @CurDate		DATE
DECLARE @CurTime		TIME
DECLARE @OperationDate	DATE
DECLARE @AccessDate		DATE

SET @CurDate = GETDATE()
SET @CurTime = CONVERT(TIME, GETDATE(), 108)

DECLARE @CutOff				TIME
DECLARE @TOACallBackTime	NVARCHAR(10)
DECLARE @RGSPossBG			NVARCHAR(20)
DECLARE @RGSProtBG			NVARCHAR(20)

SET @TOACallBackTime = '04:00'
SET @CutOff = '06:00:00'

SELECT @RGSPossBG = ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'RGSPossessionBG'
			AND ParaValue1 = @Line

SELECT @RGSProtBG = ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'RGSProtectionBG'
			AND ParaValue1 = @Line

IF @CurTime > @CutOff
	BEGIN
		SET @OperationDate	= @CurDate
		SET @AccessDate		= DATEADD(DAY, 1, @CurDate)
	END
ELSE
	BEGIN
		SET @OperationDate	= DATEADD(DAY, -1, @CurDate)
		SET @AccessDate		= @CurDate
	END

--SET @OperationDate = '2022-08-23'
--SET @AccessDate = '2022-08-24'
--SELECT @OperationDate, @AccessDate


DECLARE @Cur01 CURSOR;
DECLARE @Cur02 CURSOR;

DECLARE @TARID BIGINT,
@TOAID	BIGINT,
@ARRemark NVARCHAR(1000),
@TVFMode NVARCHAR(20),
@AccessType NVARCHAR(30),
@TOAStatus INT,
@ProtTimeLimit NVARCHAR(10),
@TARNo NVARCHAR(30),
@NoOfParties INT,
@DescOfWork NVARCHAR(1000),
@MobileNo NVARCHAR(20),
@TetraRadioNo NVARCHAR(50),
@TOANo NVARCHAR(50),
@GrantTOATime NVARCHAR(10),
@AckSurrenderTime NVARCHAR(10),
@AckGrantTOATime NVARCHAR(10),
@UpdateQTSTime NVARCHAR(10),
@InchargeNRIC NVARCHAR(100)

DECLARE @lv_Sno INT,
	@lv_IsTOAAuth BIT,
	@lv_PartiesName	NVARCHAR(4000),
	@lv_Remarks	NVARCHAR(4000),
	@lv_IsPowerOff BIT,
	@lv_PowerOffTime NVARCHAR(20),
	@lv_IsCircuitBreak BIT,
	@lv_CircuitBreakTime NVARCHAR(20),
	@lv_ColourCode NVARCHAR(20),
	@lv_ES NVARCHAR(100),
	@lv_SectorID INT,
	@lv_TVFStations NVARCHAR(1000),
	@lv_PossessionCtr INT,
	@lv_IsGrantTOAEnable BIT,
	@lv_ContactNo NVARCHAR(200)

DECLARE @SqlCtr1 INT,
	@SqlCtr2 INT,
	@SqlCtr3 INT,
	@WorkFlowTime NVARCHAR(20)

SET @lv_Sno = 0
SET @SqlCtr1 = 0
SET @SqlCtr2 = 0
SET @SqlCtr3 = 0
SET @lv_PossessionCtr = 0

SELECT @lv_PossessionCtr = COUNT(*)
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND a.AccessDate = @AccessDate
			AND b.TOAStatus NOT IN (0, 6)
			AND a.Line = @Line
			AND a.AccessType = 'Possession'

----DECLARE @NewLine AS CHAR(2) = CHAR(30) + CHAR(10)
DECLARE @NewLine AS NVARCHAR(6)
SET @NewLine = '<br />'
-- >> SELECT @NewUID = SCOPE_IDENTITY();

SET @Cur01 = CURSOR FAST_FORWARD 
FOR

SELECT a.Id, b.Id, a.TARNo, a.ARRemark, a.TVFMode, a.AccessType, b.TOAStatus, 
		-- >> ISNULL(CONVERT(NVARCHAR(20), b.AckProtectionLimitTime, 108), '00:00:00'), 
		ISNULL(CONVERT(NVARCHAR(5), b.AckProtectionLimitTime, 108), ''), 
		b.NoOfParties,
		a.DescOfWork, b.MobileNo, b.TetraRadioNo, ISNULL(b.TOANo, ''),
		ISNULL(CONVERT(NVARCHAR(5), b.GrantTOATime, 108), ''),
		ISNULL(CONVERT(NVARCHAR(5), b.AckSurrenderTime, 108), ''),
		ISNULL(CONVERT(NVARCHAR(8), b.AckGrantTOATime, 108), ''),
		ISNULL(CONVERT(NVARCHAR(5), b.UpdateQTSTime, 108), ''),
		dbo.DecryptString(b.InChargeNRIC)
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND a.AccessDate = @AccessDate
			AND b.TOAStatus <> 0
			AND a.Line = @Line
	-- >> ORDER BY a.AccessType, b.TOAType, a.Id
	ORDER BY a.AccessType, b.TOAStatus DESC, a.Id
	-- >> EXEC sp_TAMS_RGS_OnLoad 'NEL'
OPEN @Cur01
	
FETCH NEXT FROM @Cur01 INTO @TARID, @TOAID, @TARNo, @ARRemark, @TVFMode, @AccessType, @TOAStatus, 
	@ProtTimeLimit, 
	@NoOfParties,
	@DescOfWork, @MobileNo, @TetraRadioNo, @TOANo,
	@GrantTOATime, @AckSurrenderTime, @AckGrantTOATime, @UpdateQTSTime,
	@InchargeNRIC
	
WHILE @@FETCH_STATUS = 0 
	
	BEGIN

		SET @lv_Sno = @lv_Sno + 1
		SET	@lv_IsTOAAuth = 1
		SET @lv_PartiesName	= ''
		SET @lv_Remarks	= ''
		SET @lv_IsPowerOff = 1
		SET @lv_PowerOffTime = ''
		SET @lv_IsCircuitBreak = 1
		SET @lv_CircuitBreakTime = ''
		SET @lv_ColourCode = ''
		SET @lv_ES = ''
		SET @lv_ContactNo = ''

		SELECT @lv_ES = dbo.TAMS_Get_ES_NoBufferZone(@TARID)
		SELECT @lv_PartiesName = dbo.TAMS_Get_TOA_Parties(@TOAID)
		SET @lv_ContactNo = @MobileNo + @NewLine + @TetraRadioNo

		-- >> Electrical Sector Cursor
		-- >> 	EXEC sp_TAMS_RGS_OnLoad_20210819_M 'NEL'

		IF @Line = 'DTL'
			BEGIN
				SET @Cur02 = CURSOR FAST_FORWARD 
				FOR

				SELECT a.SectorId
					FROM TAMS_TAR_Sector a, TAMS_Sector b
						WHERE a.SectorId = b.ID
							AND a.TARId = @TARID
							AND ISNULL(b.IsGap, 0) = 0
							AND a.IsBuffer = 0
					
				OPEN @Cur02
	
				FETCH NEXT FROM @Cur02 INTO @lv_SectorID
	
				WHILE @@FETCH_STATUS = 0 
	
					BEGIN

						SET @SqlCtr1 = 0

						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.Sector, NULL
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.SectorId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND c.IsGap = 0
									-- >> AND a.OCCAuthStatusId = 10
									AND ((a.OCCAuthStatusId = 10 and a.IsBuffer = 0) OR ((a.OCCAuthStatusId = 7 and a.IsBuffer = 1)))
									AND c.Line = @Line

						SELECT @SqlCtr1 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr1 = 0
							BEGIN
								SET @lv_IsTOAAuth = 0
							END

						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.Sector, a.PowerOffTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.SectorId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND c.IsGap = 0
									AND a.PowerOffTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr2 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr2 = 0
							BEGIN
								SET @lv_IsPowerOff = 0
								SET @lv_PowerOffTime = ''
							END
						ELSE
							BEGIN
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM  #TmpRGSSectors

								IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_PowerOffTime = ''
									END
								ELSE
									BEGIN
										SET @lv_PowerOffTime = @WorkFlowTime
									END
							END

						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.Sector, a.RackedOutTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.SectorId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND c.IsGap = 0
									AND a.RackedOutTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr3 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr3 = 0
							BEGIN
								SET @lv_IsCircuitBreak = 0
								SET @lv_CircuitBreakTime = ''
							END
						ELSE
							BEGIN
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM  #TmpRGSSectors

									IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_CircuitBreakTime = ''
									END
								ELSE
									BEGIN
										SET @lv_CircuitBreakTime = @WorkFlowTime
									END
							END
						

						FETCH NEXT FROM @Cur02 INTO @lv_SectorID
					END 	

				CLOSE @Cur02
	
				DEALLOCATE @Cur02
			END
		ELSE
			BEGIN
				SET @Cur02 = CURSOR FAST_FORWARD 
				FOR

				SELECT a.PowerSectorId 
					FROM TAMS_TAR_Power_Sector a
						WHERE a.TARId = @TARID
							AND a.IsBuffer = 0
							

				OPEN @Cur02
	
				FETCH NEXT FROM @Cur02 INTO @lv_SectorID
	
				WHILE @@FETCH_STATUS = 0 
	
					BEGIN

						SET @SqlCtr1 = 0

						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.PowerSection, NULL
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Power_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.PowerSectionId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND a.OCCAuthStatusId = 8
									AND c.Line = @Line

						SELECT @SqlCtr1 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr1 = 0
							BEGIN
								SET @lv_IsTOAAuth = 0
							END

						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.PowerSection, a.PowerOffTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Power_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.PowerSectionId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND a.PowerOffTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr2 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr2 = 0
							BEGIN
								SET @lv_IsPowerOff = 0
								SET @lv_PowerOffTime = ''
							END
						ELSE
							BEGIN
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM  #TmpRGSSectors

									IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_PowerOffTime = ''
									END
								ELSE
									BEGIN
										SET @lv_PowerOffTime = @WorkFlowTime
									END
							END

						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.PowerSection, a.RackedOutTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Power_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.PowerSectionId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND a.RackedOutTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr3 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr3 = 0
							BEGIN
								SET @lv_IsCircuitBreak = 0
								SET @lv_CircuitBreakTime = ''
							END
						ELSE
							BEGIN
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM #TmpRGSSectors

									IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_CircuitBreakTime = ''
									END
								ELSE
									BEGIN
										SET @lv_CircuitBreakTime = @WorkFlowTime
									END
							END

						FETCH NEXT FROM @Cur02 INTO @lv_SectorID
					END 	

				CLOSE @Cur02
	
				DEALLOCATE @Cur02
			END
		-- >>
		-- >> Electrical Sector Cursor

		IF @Line = 'DTL'
			BEGIN
				SET @lv_Remarks = LTRIM(RTRIM(@ARRemark)) + @NewLine + LTRIM(RTRIM(ISNULL(@TVFMode, '')))
			END
		ELSE
			BEGIN
				DECLARE @RackOutCtr	INT

				SELECT @RackOutCtr = COUNT(*) 
					FROM TAMS_TAR_AccessReq a, TAMS_Access_Requirement b
						WHERE a.IsPower = 1
							AND a.OperationRequirement = b.ID
							AND b.ID = 27	-- >> 27 FOR NEL
							AND a.IsSelected = 1
							AND a.TARId = @TARID

				IF @RackOutCtr > 0
					BEGIN
						SET @lv_Remarks = 'Rack Out' + @NewLine + @NewLine + LTRIM(RTRIM(@ARRemark)) + @NewLine + LTRIM(RTRIM(ISNULL(@TVFMode, '')))
					END
				ELSE
					BEGIN
						SET @lv_Remarks = LTRIM(RTRIM(@ARRemark)) + @NewLine + LTRIM(RTRIM(ISNULL(@TVFMode, '')))
					END
			END

		DECLARE @SCDCtr	INT

		SELECT @SCDCtr = COUNT(*) 
			FROM TAMS_TAR_AccessReq a, TAMS_Access_Requirement b
				WHERE a.IsPower = 1
					AND a.OperationRequirement = b.ID
					AND b.OperationRequirement = 'SCD Application'
					AND a.IsSelected = 1
					AND a.TARId = @TARID

		IF @SCDCtr > 0
			BEGIN
				SET @lv_Remarks = 'SCD' + @NewLine + @NewLine + LTRIM(RTRIM(@lv_Remarks))
			END
			
		SELECT @lv_TVFStations = dbo.TAMS_Get_TOA_TVF_Stations(@TOAID)

		IF @lv_Remarks = ''
			BEGIN
				SET @lv_Remarks = @lv_TVFStations
			END
		ELSE
			BEGIN
				SET @lv_Remarks = @lv_Remarks + @NewLine + @lv_TVFStations
			END

		IF @AccessType = 'Possession'
			BEGIN
				SET @lv_ColourCode = @RGSPossBG

				IF @TOAStatus = 6
					BEGIN
						IF @lv_PossessionCtr = 0
							BEGIN
								SET @lv_PossessionCtr = @lv_PossessionCtr
							END
						ELSE
							BEGIN
								SET @lv_PossessionCtr = @lv_PossessionCtr - 1
							END
					END
				ELSE
					BEGIN
						IF @ProtTimeLimit = '' OR @ProtTimeLimit = '00:00:00'
							BEGIN
								-- >> SELECT '1'
								SET @lv_PossessionCtr = @lv_PossessionCtr + 1
								-- >> SET @lv_PossessionCtr = @lv_PossessionCtr
							END
						ELSE
							BEGIN
								-- >> SELECT '2'
								IF @lv_PossessionCtr = 0
									BEGIN
										-- >> SELECT '3'
										SET @lv_PossessionCtr = @lv_PossessionCtr
									END
								ELSE
									BEGIN
										-- >> SELECT '4'
										SET @lv_PossessionCtr = @lv_PossessionCtr - 1
									END
							END
					END

				SET @lv_IsGrantTOAEnable = 1

			END
		ELSE
			BEGIN
				-- >> SELECT @lv_PossessionCtr AS PossCtr
				-- 	EXEC sp_TAMS_RGS_OnLoad 'DTL'
				SET @lv_ColourCode = @RGSProtBG

				IF @TOAStatus = 6
					BEGIN
						SET @lv_IsGrantTOAEnable = 1
					END
				ELSE
					BEGIN
						IF @lv_PossessionCtr > 0
							BEGIN
								SET @lv_IsGrantTOAEnable = 0
							END
						ELSE
							BEGIN
								SET @lv_IsGrantTOAEnable = 1
							END
					END
			END

		IF @TOANo = ''
			BEGIN
				SET @TOACallBackTime = ''
			END
		ELSE
			BEGIN
				SET @TOACallBackTime = '04:00'
			END
		
		INSERT INTO #TmpRGS
			(Sno, TARNo, ElectricalSections,
				PowerOffTime, CircuitBreakOutTime,
				PartiesName, NoOfPersons, 
				WorkDescription, ContactNo, TOANo,
				CallBackTime, RadioMsgTime, LineClearMsgTime,
				Remarks, TOAStatus, IsTOAAuth, ColourCode, IsGrantTOAEnable, 
				UpdQTSTime, AccessType,
				AckGrantTOATime, AckProtLimitTime, 
				TARID, TOAID, InchargeNRIC)
		VALUES (@lv_Sno, @TARNo, @lv_ES, 
			@lv_PowerOffTime, @lv_CircuitBreakTime, 
			@lv_PartiesName, @NoOfParties, 
			@DescOfWork, @lv_ContactNo, @TOANo, 
			@TOACallBackTime, @GrantTOATime, @AckSurrenderTime, 
			@lv_Remarks, @TOAStatus, @lv_IsTOAAuth, @lv_ColourCode, @lv_IsGrantTOAEnable, 
			@UpdateQTSTime, @AccessType, 
			@AckGrantTOATime, @ProtTimeLimit, 
			@TARID, @TOAID, @InchargeNRIC)

		FETCH NEXT FROM @Cur01 INTO @TARID, @TOAID, @TARNo, @ARRemark, @TVFMode, @AccessType, @TOAStatus, 
			@ProtTimeLimit, 
			@NoOfParties,
			@DescOfWork, @MobileNo, @TetraRadioNo, @TOANo,
			@GrantTOATime, @AckSurrenderTime, @AckGrantTOATime, @UpdateQTSTime,
			@InchargeNRIC
	END 	

CLOSE @Cur01
	
DEALLOCATE @Cur01


-- >> RGS List
SELECT Sno, TARNo, ElectricalSections,
	PowerOffTime, CircuitBreakOutTime,
	PartiesName, NoOfPersons, 
	WorkDescription, ContactNo, TOANo,
	CallBackTime, RadioMsgTime, LineClearMsgTime,
	Remarks, TOAStatus, IsTOAAuth, ColourCode, IsGrantTOAEnable, 
	UpdQTSTime, AccessType,
	AckGrantTOATime, AckProtLimitTime, 
	TARID, TOAID,
	InchargeNRIC
FROM #TmpRGS
	ORDER BY Sno

-- >> Cancel List
SELECT a.Id AS Val, a.TARNo AS Txt
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND b.TOAStatus NOT IN (0, 5, 6)
			AND a.AccessDate = @AccessDate
			AND a.Line = @Line
	ORDER BY 1

SELECT CONVERT(NVARCHAR(20), @OperationDate, 103) AS OperationDate,  
	CONVERT(NVARCHAR(20), @AccessDate, 103) AS AccessDate

DROP TABLE #TmpRGS
DROP TABLE #TmpRGSSectors

END

GO
/****** END PROCEDURE 293 ******/

/****** START PROCEDURE 294 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_RGS_OnLoad_20230202_M
CREATE PROCEDURE [dbo].[sp_TAMS_RGS_OnLoad_20230202_M]
	@Line		NVARCHAR(20) = NULL
AS

BEGIN
	
/*
Notes :
OCCAuthStatusId 
DTL = 10
NEL = 7
*/

CREATE TABLE #TmpRGS 
(Sno				INT,
TARNo				NVARCHAR(30),
ElectricalSections	NVARCHAR(4000),
PowerOffTime		NVARCHAR(20),
CircuitBreakOutTime	NVARCHAR(20),
PartiesName			NVARCHAR(4000),
NoOfPersons			NVARCHAR(20),
WorkDescription		NVARCHAR(4000),
ContactNo			NVARCHAR(50),
TOANo				NVARCHAR(30),
CallBackTime		NVARCHAR(20),
RadioMsgTime		NVARCHAR(20),
LineClearMsgTime	NVARCHAR(20),
Remarks				NVARCHAR(4000),
TOAStatus			NVARCHAR(20),
IsTOAAuth			BIT,
ColourCode			NVARCHAR(20),
IsGrantTOAEnable	BIT,
UpdQTSTime			NVARCHAR(20),
AccessType			NVARCHAR(20),
AckGrantTOATime		NVARCHAR(20),
AckProtLimitTime	NVARCHAR(20),
TARID				INT,
TOAID				INT,
InchargeNRIC		NVARCHAR(100))

CREATE TABLE #TmpRGSSectors 
(OCCAuthID			INT,
OperationDate		DATE,
AccessDate			DATE,
OCCAuthStatus		NVARCHAR(50),
TractionPowerID		INT,
TractionPowerType	NVARCHAR(50),
SectorID			INT,
Sector				NVARCHAR(100),
WorkFlowTime		DATETIME)

TRUNCATE TABLE #TmpRGS
TRUNCATE TABLE #TmpRGSSectors

DECLARE @CurDate		DATE
DECLARE @CurTime		TIME
DECLARE @OperationDate	DATE
DECLARE @AccessDate		DATE

SET @CurDate = GETDATE()
SET @CurTime = CONVERT(TIME, GETDATE(), 108)

DECLARE @CutOff				TIME
DECLARE @TOACallBackTime	NVARCHAR(10)
DECLARE @RGSPossBG			NVARCHAR(20)
DECLARE @RGSProtBG			NVARCHAR(20)
DECLARE @RGSCancBG			NVARCHAR(20)

SET @TOACallBackTime = '04:00'
SET @CutOff = '06:00:00'

SELECT @RGSPossBG = ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'RGSPossessionBG'
			AND ParaValue1 = @Line

SELECT @RGSProtBG = ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'RGSProtectionBG'
			AND ParaValue1 = @Line

SELECT @RGSCancBG = ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'RGSCancelledBG'
			AND ParaValue1 = @Line

IF @CurTime > @CutOff
	BEGIN
		SET @OperationDate	= @CurDate
		SET @AccessDate		= DATEADD(DAY, 1, @CurDate)
	END
ELSE
	BEGIN
		SET @OperationDate	= DATEADD(DAY, -1, @CurDate)
		SET @AccessDate		= @CurDate
	END

--SET @OperationDate = '2022-08-23'
--SET @AccessDate = '2022-08-24'
--SELECT @OperationDate, @AccessDate


DECLARE @Cur01 CURSOR;
DECLARE @Cur02 CURSOR;

DECLARE @TARID BIGINT,
@TOAID	BIGINT,
@ARRemark NVARCHAR(1000),
@TVFMode NVARCHAR(20),
@AccessType NVARCHAR(30),
@TOAStatus INT,
@ProtTimeLimit NVARCHAR(10),
@TARNo NVARCHAR(30),
@NoOfParties INT,
@DescOfWork NVARCHAR(1000),
@MobileNo NVARCHAR(20),
@TetraRadioNo NVARCHAR(50),
@TOANo NVARCHAR(50),
@GrantTOATime NVARCHAR(10),
@AckSurrenderTime NVARCHAR(10),
@AckGrantTOATime NVARCHAR(10),
@UpdateQTSTime NVARCHAR(10),
@InchargeNRIC NVARCHAR(100), 
@CancelRemark NVARCHAR(1000)

DECLARE @lv_Sno INT,
	@lv_IsTOAAuth BIT,
	@lv_PartiesName	NVARCHAR(4000),
	@lv_Remarks	NVARCHAR(4000),
	@lv_IsPowerOff BIT,
	@lv_PowerOffTime NVARCHAR(20),
	@lv_IsCircuitBreak BIT,
	@lv_CircuitBreakTime NVARCHAR(20),
	@lv_ColourCode NVARCHAR(20),
	@lv_ES NVARCHAR(100),
	@lv_SectorID INT,
	@lv_TVFStations NVARCHAR(1000),
	@lv_PossessionCtr INT,
	@lv_IsGrantTOAEnable BIT,
	@lv_ContactNo NVARCHAR(200)

DECLARE @SqlCtr1 INT,
	@SqlCtr2 INT,
	@SqlCtr3 INT,
	@WorkFlowTime NVARCHAR(20)

SET @lv_Sno = 0
SET @SqlCtr1 = 0
SET @SqlCtr2 = 0
SET @SqlCtr3 = 0
SET @lv_PossessionCtr = 0

SELECT @lv_PossessionCtr = COUNT(*)
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND a.AccessDate = @AccessDate
			AND b.TOAStatus NOT IN (0, 6)
			AND a.Line = @Line
			AND a.AccessType = 'Possession'

----DECLARE @NewLine AS CHAR(2) = CHAR(30) + CHAR(10)
DECLARE @NewLine AS NVARCHAR(6)
SET @NewLine = '<br />'
-- >> SELECT @NewUID = SCOPE_IDENTITY();

SET @Cur01 = CURSOR FAST_FORWARD 
FOR

SELECT a.Id, b.Id, a.TARNo, a.ARRemark, a.TVFMode, a.AccessType, b.TOAStatus, 
		-- >> ISNULL(CONVERT(NVARCHAR(20), b.AckProtectionLimitTime, 108), '00:00:00'), 
		ISNULL(CONVERT(NVARCHAR(5), b.AckProtectionLimitTime, 108), ''), 
		b.NoOfParties,
		a.DescOfWork, b.MobileNo, b.TetraRadioNo, ISNULL(b.TOANo, ''),
		ISNULL(CONVERT(NVARCHAR(5), b.GrantTOATime, 108), ''),
		ISNULL(CONVERT(NVARCHAR(5), b.AckSurrenderTime, 108), ''),
		ISNULL(CONVERT(NVARCHAR(8), b.AckGrantTOATime, 108), ''),
		ISNULL(CONVERT(NVARCHAR(5), b.UpdateQTSTime, 108), ''),
		dbo.DecryptString(b.InChargeNRIC),
		b.CancelRemark
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND a.AccessDate = @AccessDate
			AND b.TOAStatus <> 0
			AND a.Line = @Line
	-- >> ORDER BY a.AccessType, b.TOAType, a.Id
	ORDER BY a.AccessType, b.TOAStatus DESC, a.Id
	-- >> EXEC sp_TAMS_RGS_OnLoad 'NEL'
OPEN @Cur01
	
FETCH NEXT FROM @Cur01 INTO @TARID, @TOAID, @TARNo, @ARRemark, @TVFMode, @AccessType, @TOAStatus, 
	@ProtTimeLimit, 
	@NoOfParties,
	@DescOfWork, @MobileNo, @TetraRadioNo, @TOANo,
	@GrantTOATime, @AckSurrenderTime, @AckGrantTOATime, @UpdateQTSTime,
	@InchargeNRIC, @CancelRemark
	
WHILE @@FETCH_STATUS = 0 
	
	BEGIN

		SET @lv_Sno = @lv_Sno + 1
		SET	@lv_IsTOAAuth = 1
		SET @lv_PartiesName	= ''
		SET @lv_Remarks	= ''
		SET @lv_IsPowerOff = 1
		SET @lv_PowerOffTime = ''
		SET @lv_IsCircuitBreak = 1
		SET @lv_CircuitBreakTime = ''
		SET @lv_ColourCode = ''
		SET @lv_ES = ''
		SET @lv_ContactNo = ''

		SELECT @lv_ES = dbo.TAMS_Get_ES_NoBufferZone(@TARID)
		SELECT @lv_PartiesName = dbo.TAMS_Get_TOA_Parties(@TOAID)
		SET @lv_ContactNo = @MobileNo + @NewLine + @TetraRadioNo

		-- >> Electrical Sector Cursor
		-- >> 	EXEC sp_TAMS_RGS_OnLoad_20210819_M 'NEL'

		IF @Line = 'DTL'
			BEGIN
				SET @Cur02 = CURSOR FAST_FORWARD 
				FOR

				SELECT a.SectorId
					FROM TAMS_TAR_Sector a, TAMS_Sector b
						WHERE a.SectorId = b.ID
							AND a.TARId = @TARID
							AND ISNULL(b.IsGap, 0) = 0
							AND a.IsBuffer = 0
					
				OPEN @Cur02
	
				FETCH NEXT FROM @Cur02 INTO @lv_SectorID
	
				WHILE @@FETCH_STATUS = 0 
	
					BEGIN

						SET @SqlCtr1 = 0

						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.Sector, NULL
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.SectorId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND c.IsGap = 0
									-- >> AND a.OCCAuthStatusId = 10
									AND ((a.OCCAuthStatusId = 10 and a.IsBuffer = 0) OR ((a.OCCAuthStatusId = 7 and a.IsBuffer = 1)))
									AND c.Line = @Line

						SELECT @SqlCtr1 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr1 = 0
							BEGIN
								SET @lv_IsTOAAuth = 0
							END

						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.Sector, a.PowerOffTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.SectorId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND c.IsGap = 0
									AND a.PowerOffTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr2 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr2 = 0
							BEGIN
								SET @lv_IsPowerOff = 0
								SET @lv_PowerOffTime = ''
							END
						ELSE
							BEGIN
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM  #TmpRGSSectors

								IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_PowerOffTime = ''
									END
								ELSE
									BEGIN
										SET @lv_PowerOffTime = @WorkFlowTime
									END
							END

						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.Sector, a.RackedOutTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.SectorId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND c.IsGap = 0
									AND a.RackedOutTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr3 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr3 = 0
							BEGIN
								SET @lv_IsCircuitBreak = 0
								SET @lv_CircuitBreakTime = ''
							END
						ELSE
							BEGIN
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM  #TmpRGSSectors

									IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_CircuitBreakTime = ''
									END
								ELSE
									BEGIN
										SET @lv_CircuitBreakTime = @WorkFlowTime
									END
							END
						

						FETCH NEXT FROM @Cur02 INTO @lv_SectorID
					END 	

				CLOSE @Cur02
	
				DEALLOCATE @Cur02
			END
		ELSE
			BEGIN
				SET @Cur02 = CURSOR FAST_FORWARD 
				FOR

				SELECT a.PowerSectorId 
					FROM TAMS_TAR_Power_Sector a
						WHERE a.TARId = @TARID
							AND a.IsBuffer = 0
							

				OPEN @Cur02
	
				FETCH NEXT FROM @Cur02 INTO @lv_SectorID
	
				WHILE @@FETCH_STATUS = 0 
	
					BEGIN

						SET @SqlCtr1 = 0

						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.PowerSection, NULL
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Power_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.PowerSectionId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND a.OCCAuthStatusId = 8
									AND c.Line = @Line

						SELECT @SqlCtr1 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr1 = 0
							BEGIN
								SET @lv_IsTOAAuth = 0
							END

						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.PowerSection, a.PowerOffTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Power_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.PowerSectionId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND a.PowerOffTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr2 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr2 = 0
							BEGIN
								SET @lv_IsPowerOff = 0
								SET @lv_PowerOffTime = ''
							END
						ELSE
							BEGIN
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM  #TmpRGSSectors

									IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_PowerOffTime = ''
									END
								ELSE
									BEGIN
										SET @lv_PowerOffTime = @WorkFlowTime
									END
							END

						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.PowerSection, a.RackedOutTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Power_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.PowerSectionId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND a.RackedOutTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr3 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr3 = 0
							BEGIN
								SET @lv_IsCircuitBreak = 0
								SET @lv_CircuitBreakTime = ''
							END
						ELSE
							BEGIN
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM #TmpRGSSectors

									IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_CircuitBreakTime = ''
									END
								ELSE
									BEGIN
										SET @lv_CircuitBreakTime = @WorkFlowTime
									END
							END

						FETCH NEXT FROM @Cur02 INTO @lv_SectorID
					END 	

				CLOSE @Cur02
	
				DEALLOCATE @Cur02
			END
		-- >>
		-- >> Electrical Sector Cursor

		IF @Line = 'DTL'
			BEGIN
				SET @lv_Remarks = LTRIM(RTRIM(@ARRemark)) + @NewLine + LTRIM(RTRIM(ISNULL(@TVFMode, '')))
			END
		ELSE
			BEGIN
				DECLARE @RackOutCtr	INT

				SELECT @RackOutCtr = COUNT(*) 
					FROM TAMS_TAR_AccessReq a, TAMS_Access_Requirement b
						WHERE a.IsPower = 1
							AND a.OperationRequirement = b.ID
							AND b.ID = 27	-- >> 27 FOR NEL
							AND a.IsSelected = 1
							AND a.TARId = @TARID

				IF @RackOutCtr > 0
					BEGIN
						SET @lv_Remarks = 'Rack Out' + @NewLine + @NewLine + LTRIM(RTRIM(@ARRemark)) + @NewLine + LTRIM(RTRIM(ISNULL(@TVFMode, '')))
					END
				ELSE
					BEGIN
						SET @lv_Remarks = LTRIM(RTRIM(@ARRemark)) + @NewLine + LTRIM(RTRIM(ISNULL(@TVFMode, '')))
					END
			END

		DECLARE @SCDCtr	INT

		SELECT @SCDCtr = COUNT(*) 
			FROM TAMS_TAR_AccessReq a, TAMS_Access_Requirement b
				WHERE a.IsPower = 1
					AND a.OperationRequirement = b.ID
					AND b.OperationRequirement = 'SCD Application'
					AND a.IsSelected = 1
					AND a.TARId = @TARID

		IF @SCDCtr > 0
			BEGIN
				SET @lv_Remarks = 'SCD' + @NewLine + @NewLine + LTRIM(RTRIM(@lv_Remarks))
			END
			
		SELECT @lv_TVFStations = dbo.TAMS_Get_TOA_TVF_Stations(@TOAID)

		IF @lv_Remarks = ''
			BEGIN
				SET @lv_Remarks = @lv_TVFStations
			END
		ELSE
			BEGIN
				SET @lv_Remarks = @lv_Remarks + @NewLine + @lv_TVFStations
			END

		IF @AccessType = 'Possession'
			BEGIN
				SET @lv_ColourCode = @RGSPossBG

				IF @TOAStatus = 6
					BEGIN
						IF @lv_PossessionCtr = 0
							BEGIN
								SET @lv_PossessionCtr = @lv_PossessionCtr
							END
						ELSE
							BEGIN
								SET @lv_PossessionCtr = @lv_PossessionCtr - 1
							END
					END
				ELSE
					BEGIN
						IF @ProtTimeLimit = '' OR @ProtTimeLimit = '00:00:00'
							BEGIN
								-- >> SELECT '1'
								SET @lv_PossessionCtr = @lv_PossessionCtr + 1
								-- >> SET @lv_PossessionCtr = @lv_PossessionCtr
							END
						ELSE
							BEGIN
								-- >> SELECT '2'
								IF @lv_PossessionCtr = 0
									BEGIN
										-- >> SELECT '3'
										SET @lv_PossessionCtr = @lv_PossessionCtr
									END
								ELSE
									BEGIN
										-- >> SELECT '4'
										SET @lv_PossessionCtr = @lv_PossessionCtr - 1
									END
							END
					END

				SET @lv_IsGrantTOAEnable = 1

			END
		ELSE
			BEGIN
				-- >> SELECT @lv_PossessionCtr AS PossCtr
				-- 	EXEC sp_TAMS_RGS_OnLoad 'DTL'
				SET @lv_ColourCode = @RGSProtBG

				IF @TOAStatus = 6
					BEGIN
						SET @lv_IsGrantTOAEnable = 1
					END
				ELSE
					BEGIN
						IF @lv_PossessionCtr > 0
							BEGIN
								SET @lv_IsGrantTOAEnable = 0
							END
						ELSE
							BEGIN
								SET @lv_IsGrantTOAEnable = 1
							END
					END
			END

		IF @TOANo = ''
			BEGIN
				SET @TOACallBackTime = ''
			END
		ELSE
			BEGIN
				SET @TOACallBackTime = '04:00'
			END
		
		-- >> 2023 change highlight for cancelled records
		-- >> Include Cancel remarks after new line
		IF @TOAStatus = 6
			BEGIN
				SET @lv_ColourCode = @RGSCancBG
				SET @lv_Remarks = @lv_Remarks + @NewLine + @NewLine + 'Cancel Remark:' + LTRIM(RTRIM(@CancelRemark))
			END

		INSERT INTO #TmpRGS
			(Sno, TARNo, ElectricalSections,
				PowerOffTime, CircuitBreakOutTime,
				PartiesName, NoOfPersons, 
				WorkDescription, ContactNo, TOANo,
				CallBackTime, RadioMsgTime, LineClearMsgTime,
				Remarks, TOAStatus, IsTOAAuth, ColourCode, IsGrantTOAEnable, 
				UpdQTSTime, AccessType,
				AckGrantTOATime, AckProtLimitTime, 
				TARID, TOAID, InchargeNRIC)
		VALUES (@lv_Sno, @TARNo, @lv_ES, 
			@lv_PowerOffTime, @lv_CircuitBreakTime, 
			@lv_PartiesName, @NoOfParties, 
			@DescOfWork, @lv_ContactNo, @TOANo, 
			@TOACallBackTime, @GrantTOATime, @AckSurrenderTime, 
			@lv_Remarks, @TOAStatus, @lv_IsTOAAuth, @lv_ColourCode, @lv_IsGrantTOAEnable, 
			@UpdateQTSTime, @AccessType, 
			@AckGrantTOATime, @ProtTimeLimit, 
			@TARID, @TOAID, @InchargeNRIC)

		FETCH NEXT FROM @Cur01 INTO @TARID, @TOAID, @TARNo, @ARRemark, @TVFMode, @AccessType, @TOAStatus, 
			@ProtTimeLimit, 
			@NoOfParties,
			@DescOfWork, @MobileNo, @TetraRadioNo, @TOANo,
			@GrantTOATime, @AckSurrenderTime, @AckGrantTOATime, @UpdateQTSTime,
			@InchargeNRIC, @CancelRemark
	END 	

CLOSE @Cur01
	
DEALLOCATE @Cur01


-- >> RGS List
SELECT Sno, TARNo, ElectricalSections,
	PowerOffTime, CircuitBreakOutTime,
	PartiesName, NoOfPersons, 
	WorkDescription, ContactNo, TOANo,
	CallBackTime, RadioMsgTime, LineClearMsgTime,
	Remarks, TOAStatus, IsTOAAuth, ColourCode, IsGrantTOAEnable, 
	UpdQTSTime, AccessType,
	AckGrantTOATime, AckProtLimitTime, 
	TARID, TOAID,
	InchargeNRIC
FROM #TmpRGS
	ORDER BY Sno

-- >> Cancel List
SELECT a.Id AS Val, a.TARNo AS Txt
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND b.TOAStatus NOT IN (0, 5, 6)
			AND a.AccessDate = @AccessDate
			AND a.Line = @Line
	ORDER BY 1

SELECT CONVERT(NVARCHAR(20), @OperationDate, 103) AS OperationDate,  
	CONVERT(NVARCHAR(20), @AccessDate, 103) AS AccessDate

DROP TABLE #TmpRGS
DROP TABLE #TmpRGSSectors

END

GO
/****** END PROCEDURE 294 ******/

/****** START PROCEDURE 295 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_RGS_OnLoad_20230707
CREATE PROCEDURE [dbo].[sp_TAMS_RGS_OnLoad_20230707]
	@Line		NVARCHAR(20) = NULL
AS

BEGIN
	
/*
Notes :
OCCAuthStatusId 
DTL = 10
NEL = 7
*/

CREATE TABLE #TmpRGS 
(Sno				INT,
TARNo				NVARCHAR(30),
ElectricalSections	NVARCHAR(4000),
PowerOffTime		NVARCHAR(20),
CircuitBreakOutTime	NVARCHAR(20),
PartiesName			NVARCHAR(4000),
NoOfPersons			NVARCHAR(20),
WorkDescription		NVARCHAR(4000),
ContactNo			NVARCHAR(50),
TOANo				NVARCHAR(30),
CallBackTime		NVARCHAR(20),
RadioMsgTime		NVARCHAR(20),
LineClearMsgTime	NVARCHAR(20),
Remarks				NVARCHAR(4000),
TOAStatus			NVARCHAR(20),
IsTOAAuth			BIT,
ColourCode			NVARCHAR(20),
IsGrantTOAEnable	BIT,
UpdQTSTime			NVARCHAR(20),
AccessType			NVARCHAR(20),
AckGrantTOATime		NVARCHAR(20),
AckProtLimitTime	NVARCHAR(20),
TARID				INT,
TOAID				INT,
InchargeNRIC		NVARCHAR(100))

CREATE TABLE #TmpRGSSectors 
(OCCAuthID			INT,
OperationDate		DATE,
AccessDate			DATE,
OCCAuthStatus		NVARCHAR(50),
TractionPowerID		INT,
TractionPowerType	NVARCHAR(50),
SectorID			INT,
Sector				NVARCHAR(100),
WorkFlowTime		DATETIME)

TRUNCATE TABLE #TmpRGS
TRUNCATE TABLE #TmpRGSSectors

DECLARE @CurDate		DATE
DECLARE @CurTime		TIME
DECLARE @OperationDate	DATE
DECLARE @AccessDate		DATE

SET @CurDate = GETDATE()
SET @CurTime = CONVERT(TIME, GETDATE(), 108)

DECLARE @CutOff				TIME
DECLARE @TOACallBackTime	NVARCHAR(10)
DECLARE @RGSPossBG			NVARCHAR(20)
DECLARE @RGSProtBG			NVARCHAR(20)
DECLARE @RGSCancBG			NVARCHAR(20)

SET @TOACallBackTime = '04:00'
SET @CutOff = '06:00:00'

SELECT @RGSPossBG = ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'RGSPossessionBG'
			AND ParaValue1 = @Line

SELECT @RGSProtBG = ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'RGSProtectionBG'
			AND ParaValue1 = @Line

SELECT @RGSCancBG = ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'RGSCancelledBG'
			AND ParaValue1 = @Line

IF @CurTime > @CutOff
	BEGIN
		SET @OperationDate	= @CurDate
		SET @AccessDate		= DATEADD(DAY, 1, @CurDate)
	END
ELSE
	BEGIN
		SET @OperationDate	= DATEADD(DAY, -1, @CurDate)
		SET @AccessDate		= @CurDate
	END

--SET @OperationDate = '2023-07-05'
--SET @AccessDate = '2023-07-06'
--SELECT @OperationDate, @AccessDate

SET @OperationDate = '2024-08-01'
SET @AccessDate = '2024-08-30'

DECLARE @Cur01 CURSOR;
DECLARE @Cur02 CURSOR;

DECLARE @TARID BIGINT,
@TOAID	BIGINT,
@ARRemark NVARCHAR(1000),
@TVFMode NVARCHAR(20),
@AccessType NVARCHAR(30),
@TOAStatus INT,
@ProtTimeLimit NVARCHAR(10),
@TARNo NVARCHAR(30),
@NoOfParties INT,
@DescOfWork NVARCHAR(1000),
@MobileNo NVARCHAR(20),
@TetraRadioNo NVARCHAR(50),
@TOANo NVARCHAR(50),
@GrantTOATime NVARCHAR(10),
@AckSurrenderTime NVARCHAR(10),
@AckGrantTOATime NVARCHAR(10),
@UpdateQTSTime NVARCHAR(10),
@InchargeNRIC NVARCHAR(100), 
@CancelRemark NVARCHAR(1000)

DECLARE @lv_Sno INT,
	@lv_IsTOAAuth BIT,
	@lv_PartiesName	NVARCHAR(4000),
	@lv_Remarks	NVARCHAR(4000),
	@lv_IsPowerOff BIT,
	@lv_PowerOffTime NVARCHAR(20),
	@lv_IsCircuitBreak BIT,
	@lv_CircuitBreakTime NVARCHAR(20),
	@lv_ColourCode NVARCHAR(20),
	@lv_ES NVARCHAR(100),
	@lv_SectorID INT,
	@lv_TVFStations NVARCHAR(1000),
	@lv_PossessionCtr INT,
	@lv_IsGrantTOAEnable BIT,
	@lv_ContactNo NVARCHAR(200)

DECLARE @SqlCtr1 INT,
	@SqlCtr2 INT,
	@SqlCtr3 INT,
	@WorkFlowTime NVARCHAR(20)

SET @lv_Sno = 0
SET @SqlCtr1 = 0
SET @SqlCtr2 = 0
SET @SqlCtr3 = 0
SET @lv_PossessionCtr = 0

SELECT @lv_PossessionCtr = COUNT(*)
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND a.AccessDate = @AccessDate
			AND b.TOAStatus NOT IN (0, 6)
			AND a.Line = @Line
			AND a.AccessType = 'Possession'

----DECLARE @NewLine AS CHAR(2) = CHAR(30) + CHAR(10)
DECLARE @NewLine AS NVARCHAR(6)
SET @NewLine = '<br />'
-- >> SELECT @NewUID = SCOPE_IDENTITY();

SET @Cur01 = CURSOR FAST_FORWARD 
FOR

SELECT a.Id, b.Id, a.TARNo, a.ARRemark, a.TVFMode, a.AccessType, b.TOAStatus, 
		-- >> ISNULL(CONVERT(NVARCHAR(20), b.AckProtectionLimitTime, 108), '00:00:00'), 
		ISNULL(CONVERT(NVARCHAR(5), b.AckProtectionLimitTime, 108), ''), 
		b.NoOfParties,
		a.DescOfWork, b.MobileNo, b.TetraRadioNo, ISNULL(b.TOANo, ''),
		ISNULL(CONVERT(NVARCHAR(5), b.GrantTOATime, 108), ''),
		ISNULL(CONVERT(NVARCHAR(5), b.AckSurrenderTime, 108), ''),
		ISNULL(CONVERT(NVARCHAR(8), b.AckGrantTOATime, 108), ''),
		ISNULL(CONVERT(NVARCHAR(5), b.UpdateQTSTime, 108), ''),
		dbo.DecryptString(b.InChargeNRIC),
		b.CancelRemark
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND a.AccessDate = @AccessDate
			AND b.TOAStatus <> 0
			AND a.Line = @Line
	-- >> ORDER BY a.AccessType, b.TOAType, a.Id
	ORDER BY a.AccessType, b.TOAStatus DESC, a.Id
	-- >> EXEC sp_TAMS_RGS_OnLoad 'NEL'
OPEN @Cur01
	
FETCH NEXT FROM @Cur01 INTO @TARID, @TOAID, @TARNo, @ARRemark, @TVFMode, @AccessType, @TOAStatus, 
	@ProtTimeLimit, 
	@NoOfParties,
	@DescOfWork, @MobileNo, @TetraRadioNo, @TOANo,
	@GrantTOATime, @AckSurrenderTime, @AckGrantTOATime, @UpdateQTSTime,
	@InchargeNRIC, @CancelRemark
	
WHILE @@FETCH_STATUS = 0 
	
	BEGIN

		SET @lv_Sno = @lv_Sno + 1
		SET	@lv_IsTOAAuth = 1
		SET @lv_PartiesName	= ''
		SET @lv_Remarks	= ''
		SET @lv_IsPowerOff = 1
		SET @lv_PowerOffTime = ''
		SET @lv_IsCircuitBreak = 1
		SET @lv_CircuitBreakTime = ''
		SET @lv_ColourCode = ''
		SET @lv_ES = ''
		SET @lv_ContactNo = ''

		SELECT @lv_ES = dbo.TAMS_Get_ES_NoBufferZone(@TARID)
		SELECT @lv_PartiesName = dbo.TAMS_Get_TOA_Parties(@TOAID)
		SET @lv_ContactNo = @MobileNo + @NewLine + @TetraRadioNo

		-- >> Electrical Sector Cursor
		-- >> 	EXEC sp_TAMS_RGS_OnLoad_20210819_M 'NEL'

		IF @Line = 'DTL'
			BEGIN
				SET @Cur02 = CURSOR FAST_FORWARD 
				FOR

				SELECT a.SectorId
					FROM TAMS_TAR_Sector a, TAMS_Sector b
						WHERE a.SectorId = b.ID
							AND a.TARId = @TARID
							AND ISNULL(b.IsGap, 0) = 0
							AND a.IsBuffer = 0
					
				OPEN @Cur02
	
				FETCH NEXT FROM @Cur02 INTO @lv_SectorID
	
				WHILE @@FETCH_STATUS = 0 
	
					BEGIN

						SET @SqlCtr1 = 0

						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.Sector, NULL
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.SectorId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND c.IsGap = 0
									-- >> AND a.OCCAuthStatusId = 10
									AND ((a.OCCAuthStatusId = 10 and a.IsBuffer = 0) OR ((a.OCCAuthStatusId = 7 and a.IsBuffer = 1)))
									AND c.Line = @Line

						SELECT @SqlCtr1 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr1 = 0
							BEGIN
								SET @lv_IsTOAAuth = 0
							END

						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.Sector, a.PowerOffTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.SectorId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND c.IsGap = 0
									AND a.PowerOffTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr2 = COUNT(*) FROM #TmpRGSSectors
						print 'PowerOffTime';
						print @SqlCtr2;
						
						IF @SqlCtr2 = 0
							BEGIN
								SET @lv_IsPowerOff = 0
								SET @lv_PowerOffTime = ''
							END
						ELSE
							BEGIN
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM  #TmpRGSSectors

								IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_PowerOffTime = ''
									END
								ELSE
									BEGIN
										SET @lv_PowerOffTime = @WorkFlowTime
									END
							END
						  print @WorkFlowTime; 
						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.Sector, a.RackedOutTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.SectorId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND c.IsGap = 0
									AND a.RackedOutTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr3 = COUNT(*) FROM #TmpRGSSectors
						print 'RackedOutTime';
						print @SqlCtr3;
						IF @SqlCtr3 = 0
							BEGIN
								SET @lv_IsCircuitBreak = 0
								SET @lv_CircuitBreakTime = ''
							END
						ELSE
							BEGIN
								select * from #TmpRGSSectors;
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM  #TmpRGSSectors
									print 'workflowtime' +  @WorkFlowTime; 

									IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_CircuitBreakTime = ''
									END
								ELSE
									BEGIN
										SET @lv_CircuitBreakTime = @WorkFlowTime
									END

									print '@lv_CircuitBreakTime' +  @lv_CircuitBreakTime; 
							END
						print @WorkFlowTime; 

						FETCH NEXT FROM @Cur02 INTO @lv_SectorID
					END 	

				CLOSE @Cur02
	
				DEALLOCATE @Cur02
			END
		ELSE
			BEGIN
				SET @Cur02 = CURSOR FAST_FORWARD 
				FOR

				SELECT a.PowerSectorId 
					FROM TAMS_TAR_Power_Sector a
						WHERE a.TARId = @TARID
							AND a.IsBuffer = 0
							

				OPEN @Cur02
	
				FETCH NEXT FROM @Cur02 INTO @lv_SectorID
	
				WHILE @@FETCH_STATUS = 0 
	
					BEGIN

						SET @SqlCtr1 = 0

						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.PowerSection, NULL
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Power_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.PowerSectionId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND a.OCCAuthStatusId = 8
									AND c.Line = @Line

						SELECT @SqlCtr1 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr1 = 0
							BEGIN
								SET @lv_IsTOAAuth = 0
							END

						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.PowerSection, a.PowerOffTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Power_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.PowerSectionId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND a.PowerOffTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr2 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr2 = 0
							BEGIN
								SET @lv_IsPowerOff = 0
								SET @lv_PowerOffTime = ''
							END
						ELSE
							BEGIN
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM  #TmpRGSSectors

									IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_PowerOffTime = ''
									END
								ELSE
									BEGIN
										SET @lv_PowerOffTime = @WorkFlowTime
									END
							END

						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.PowerSection, a.RackedOutTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Power_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.PowerSectionId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND a.RackedOutTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr3 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr3 = 0
							BEGIN
								SET @lv_IsCircuitBreak = 0
								SET @lv_CircuitBreakTime = ''
							END
						ELSE
							BEGIN
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM #TmpRGSSectors

									IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_CircuitBreakTime = ''
									END
								ELSE
									BEGIN
										SET @lv_CircuitBreakTime = @WorkFlowTime
									END
							END

						FETCH NEXT FROM @Cur02 INTO @lv_SectorID
					END 	

				CLOSE @Cur02
	
				DEALLOCATE @Cur02
			END
		-- >>
		-- >> Electrical Sector Cursor

		IF @Line = 'DTL'
			BEGIN
				SET @lv_Remarks = LTRIM(RTRIM(@ARRemark)) + @NewLine + LTRIM(RTRIM(ISNULL(@TVFMode, '')))
			END
		ELSE
			BEGIN
				DECLARE @RackOutCtr	INT

				SELECT @RackOutCtr = COUNT(*) 
					FROM TAMS_TAR_AccessReq a, TAMS_Access_Requirement b
						WHERE a.IsPower = 1
							AND a.OperationRequirement = b.ID
							AND b.ID = 27	-- >> 27 FOR NEL
							AND a.IsSelected = 1
							AND a.TARId = @TARID

				IF @RackOutCtr > 0
					BEGIN
						SET @lv_Remarks = 'Rack Out' + @NewLine + @NewLine + LTRIM(RTRIM(@ARRemark)) + @NewLine + LTRIM(RTRIM(ISNULL(@TVFMode, '')))
					END
				ELSE
					BEGIN
						SET @lv_Remarks = LTRIM(RTRIM(@ARRemark)) + @NewLine + LTRIM(RTRIM(ISNULL(@TVFMode, '')))
					END
			END

		DECLARE @SCDCtr	INT

		SELECT @SCDCtr = COUNT(*) 
			FROM TAMS_TAR_AccessReq a, TAMS_Access_Requirement b
				WHERE a.IsPower = 1
					AND a.OperationRequirement = b.ID
					AND b.OperationRequirement = 'SCD Application'
					AND a.IsSelected = 1
					AND a.TARId = @TARID

		IF @SCDCtr > 0
			BEGIN
				SET @lv_Remarks = 'SCD' + @NewLine + @NewLine + LTRIM(RTRIM(@lv_Remarks))
			END
			
		SELECT @lv_TVFStations = dbo.TAMS_Get_TOA_TVF_Stations(@TOAID)

		IF @lv_Remarks = ''
			BEGIN
				SET @lv_Remarks = @lv_TVFStations
			END
		ELSE
			BEGIN
				SET @lv_Remarks = @lv_Remarks + @NewLine + @lv_TVFStations
			END

		IF @AccessType = 'Possession'
			BEGIN
				SET @lv_ColourCode = @RGSPossBG

				IF @TOAStatus = 6
					BEGIN
						IF @lv_PossessionCtr = 0
							BEGIN
								SET @lv_PossessionCtr = @lv_PossessionCtr
							END
						ELSE
							BEGIN
								SET @lv_PossessionCtr = @lv_PossessionCtr - 1
							END
					END
				ELSE
					BEGIN
						IF @ProtTimeLimit = '' OR @ProtTimeLimit = '00:00:00'
							BEGIN
								-- >> SELECT '1'
								SET @lv_PossessionCtr = @lv_PossessionCtr + 1
								-- >> SET @lv_PossessionCtr = @lv_PossessionCtr
							END
						ELSE
							BEGIN
								-- >> SELECT '2'
								IF @lv_PossessionCtr = 0
									BEGIN
										-- >> SELECT '3'
										SET @lv_PossessionCtr = @lv_PossessionCtr
									END
								ELSE
									BEGIN
										-- >> SELECT '4'
										SET @lv_PossessionCtr = @lv_PossessionCtr - 1
									END
							END
					END

				SET @lv_IsGrantTOAEnable = 1

			END
		ELSE
			BEGIN
				-- >> SELECT @lv_PossessionCtr AS PossCtr
				-- 	EXEC sp_TAMS_RGS_OnLoad 'DTL'
				SET @lv_ColourCode = @RGSProtBG

				IF @TOAStatus = 6
					BEGIN
						SET @lv_IsGrantTOAEnable = 1
					END
				ELSE
					BEGIN
						IF @lv_PossessionCtr > 0
							BEGIN
								SET @lv_IsGrantTOAEnable = 0
							END
						ELSE
							BEGIN
								SET @lv_IsGrantTOAEnable = 1
							END
					END
			END

		IF @TOANo = ''
			BEGIN
				SET @TOACallBackTime = ''
			END
		ELSE
			BEGIN
				SET @TOACallBackTime = '04:00'
			END
		
		-- >> 2023 change highlight for cancelled records
		-- >> Include Cancel remarks after new line
		IF @TOAStatus = 6
			BEGIN
				SET @lv_ColourCode = @RGSCancBG
				SET @lv_Remarks = @lv_Remarks + @NewLine + @NewLine + 'Cancel Remark: ' + LTRIM(RTRIM(@CancelRemark))
			END

		INSERT INTO #TmpRGS
			(Sno, TARNo, ElectricalSections,
				PowerOffTime, CircuitBreakOutTime,
				PartiesName, NoOfPersons, 
				WorkDescription, ContactNo, TOANo,
				CallBackTime, RadioMsgTime, LineClearMsgTime,
				Remarks, TOAStatus, IsTOAAuth, ColourCode, IsGrantTOAEnable, 
				UpdQTSTime, AccessType,
				AckGrantTOATime, AckProtLimitTime, 
				TARID, TOAID, InchargeNRIC)
		VALUES (@lv_Sno, @TARNo, @lv_ES, 
			@lv_PowerOffTime, @lv_CircuitBreakTime, 
			@lv_PartiesName, @NoOfParties, 
			@DescOfWork, @lv_ContactNo, @TOANo, 
			@TOACallBackTime, @GrantTOATime, @AckSurrenderTime, 
			@lv_Remarks, @TOAStatus, @lv_IsTOAAuth, @lv_ColourCode, @lv_IsGrantTOAEnable, 
			@UpdateQTSTime, @AccessType, 
			@AckGrantTOATime, @ProtTimeLimit, 
			@TARID, @TOAID, @InchargeNRIC)

		FETCH NEXT FROM @Cur01 INTO @TARID, @TOAID, @TARNo, @ARRemark, @TVFMode, @AccessType, @TOAStatus, 
			@ProtTimeLimit, 
			@NoOfParties,
			@DescOfWork, @MobileNo, @TetraRadioNo, @TOANo,
			@GrantTOATime, @AckSurrenderTime, @AckGrantTOATime, @UpdateQTSTime,
			@InchargeNRIC, @CancelRemark
	END 	

CLOSE @Cur01
	
DEALLOCATE @Cur01


-- >> RGS List
SELECT Sno, TARNo, ElectricalSections,
	PowerOffTime, CircuitBreakOutTime,
	PartiesName, NoOfPersons, 
	WorkDescription, ContactNo, TOANo,
	CallBackTime, RadioMsgTime, LineClearMsgTime,
	Remarks, TOAStatus, IsTOAAuth, ColourCode, IsGrantTOAEnable, 
	UpdQTSTime, AccessType,
	AckGrantTOATime, AckProtLimitTime, 
	TARID, TOAID,
	InchargeNRIC
FROM #TmpRGS
	ORDER BY Sno

-- >> Cancel List
SELECT a.Id AS Val, a.TARNo AS Txt
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND b.TOAStatus NOT IN (0, 5, 6)
			AND a.AccessDate = @AccessDate
			AND a.Line = @Line
	ORDER BY 1

SELECT CONVERT(NVARCHAR(20), @OperationDate, 103) AS OperationDate,  
	CONVERT(NVARCHAR(20), @AccessDate, 103) AS AccessDate

DROP TABLE #TmpRGS
DROP TABLE #TmpRGSSectors

END

GO
/****** END PROCEDURE 295 ******/

/****** START PROCEDURE 296 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_RGS_OnLoad_20250128
CREATE procedure  [dbo].[sp_TAMS_RGS_OnLoad_20250128]
	@Line		NVARCHAR(20) = NULL,
	@TrackType	NVARCHAR(50) = NULL
AS

BEGIN

DECLARE @NewLine AS NVARCHAR(6)
SET @NewLine = '<br />'

DECLARE @RGSPossBG			NVARCHAR(20)
DECLARE @RGSProtBG			NVARCHAR(20)
DECLARE @RGSCancBG			NVARCHAR(20)

--DECLARE @trainLine as NVARCHAR(10)
--SET @trainLine='DTL'
--DECLARE @trackType as nvarchar(10)
--SET @trackType='mainline'

DECLARE @accessDate as Date
DECLARE @OperationDate as Date

DECLARE @CurDate		DATE
DECLARE @CurTime		TIME

SET @CurDate =  GETDATE()
SET @CurTime = CONVERT(TIME, GETDATE(), 108)


DECLARE @CutOff	TIME
SET @CutOff = '06:00:00'

	IF @CurTime > @CutOff
		BEGIN
			SET @OperationDate	= @CurDate
			SET @AccessDate		= DATEADD(DAY, 1, @CurDate)
		END
	ELSE
		BEGIN
			SET @OperationDate	= DATEADD(DAY, -1, @CurDate)
			SET @AccessDate		= @CurDate
		END
	
--SET @OperationDate = '2023-11-17'
--SET @AccessDate = '2023-11-18'

SET @OperationDate = '2024-08-01'
SET @AccessDate = '2024-08-30'

SELECT @RGSPossBG = ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'RGSPossessionBG'
			AND ParaValue1 = @Line

SELECT @RGSProtBG = ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'RGSProtectionBG'
			AND ParaValue1 = @Line

SELECT @RGSCancBG = ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'RGSCancelledBG'
			AND ParaValue1 = @Line


DECLARE @TOACallBackTime	NVARCHAR(10)
SET @TOACallBackTime = '04:00'


			
			DECLARE @possession_ctrl as bit=0

			SET @possession_ctrl=IIF(EXISTS(
			(
			
			SELECT counttotal from (
			SELECT Count(1) as counttotal 
			FROM TAMS_TAR a, TAMS_TOA b
			WHERE a.Id = b.TARId
			AND a.AccessDate = @accessDate
			AND b.TOAStatus NOT IN (0, 6)
			AND a.Line = 'DTL'
			and a.TrackType = @TrackType
			AND a.AccessType = 'Possession'
			) B where B.counttotal=(
			SELECT COUNT(*) 
			FROM TAMS_TAR a, TAMS_TOA b
			WHERE a.Id = b.TARId
			AND a.AccessDate = @accessDate
			AND b.TOAStatus NOT IN (0, 6)
			AND a.Line = 'DTL'
			and a.TrackType = @TrackType
			AND a.AccessType = 'Possession' 
			AND NOT (ISNULL(CONVERT(NVARCHAR(5), b.AckProtectionLimitTime, 108), '') = ''
			OR ISNULL(CONVERT(NVARCHAR(5), b.AckProtectionLimitTime, 108), '')= '00:00:00')) )),1,0)
			

			PRINT @possession_ctrl

SELECT ROW_NUMBER() OVER (ORDER BY a.AccessType, b.TOAStatus DESC, a.Id) as Sno,a.TARNo as TARNo, dbo.TAMS_Get_ES_NoBufferZone(a.Id) as ElectricalSections,
		CASE WHEN (a.Line='NEL' AND a.PowerOn = 1 AND a.AccessType='Possession')THEN (
			''
		)  WHEN (a.Line='NEL' ) THEN (
			(SELECT  ISNULL(CONVERT(NVARCHAR(5), max(c.PowerOffTime), 108), '')
					FROM TAMS_OCC_Auth c, TAMS_Traction_Power_Detail d
						WHERE c.TractionPowerId = d.TractionPowerId
							AND d.PowerSectionId in (
							SELECT  PowerSectorId from TAMS_TAR_Power_Sector where TARId = a.Id AND  ((a.PowerOn  = 0) or (a.PowerOn  = 1 and TAMS_TAR_Power_Sector.IsBuffer<>1))
								 )
							AND d.TractionPowerType = 'Sector'
							AND c.OperationDate = @OperationDate
							AND c.AccessDate = @accessDate
							 AND c.PowerOffTime is not null  and c.PowerOffType = 'Completed'
			)
		)  
		ELSE (
					SELECT  ISNULL(CONVERT(NVARCHAR(5), max(c.PowerOffTime), 108), '')
					FROM TAMS_OCC_Auth c, TAMS_Traction_Power_Detail d
						WHERE c.TractionPowerId = d.TractionPowerId
							 AND d.SectorId in (
												SELECT e.SectorId
											FROM TAMS_TAR_Sector e, TAMS_Sector f
												WHERE e.SectorId = f.ID
													AND e.TARId = a.Id
													AND ISNULL(f.IsGap, 0) = 0
													AND e.IsBuffer = 0
											)
							AND d.TractionPowerType = 'Sector'
							AND c.OperationDate = @OperationDate
							AND c.AccessDate = @accessDate
							 AND c.PowerOffTime IS NOT NULL and c.PowerOffType='Completed'
		)END as PowerOffTime, 
		CASE WHEN a.Line='DTL' THEN (
					SELECT  ISNULL(CONVERT(NVARCHAR(5), max(g.RackedOutTime), 108), '')
						FROM TAMS_OCC_Auth g, TAMS_Traction_Power_Detail h 
							WHERE g.TractionPowerId = h.TractionPowerId
								 AND h.SectorId in (
													SELECT g1.SectorId
												FROM TAMS_TAR_Sector g1, TAMS_Sector h1
													WHERE g1.SectorId = h1.ID
														AND g1.TARId = a.Id
														AND ISNULL(h1.IsGap, 0) = 0
														AND g1.IsBuffer = 0
												)
								AND h.TractionPowerType = 'Sector'
								AND g.OperationDate = @OperationDate
								AND g.AccessDate = @accessDate
								 AND g.RackedOutTime IS NOT NULL and g.RackedOutType='Completed'
				
		
		) ELSE (
					SELECT  ISNULL(CONVERT(NVARCHAR(5), max(i.RackedOutTime), 108), '')
					FROM TAMS_OCC_Auth i, TAMS_Traction_Power_Detail j, (
					SELECT i11.TARId 
					FROM TAMS_TAR_AccessReq i11, TAMS_Access_Requirement j11
						WHERE i11.IsPower = 1
							AND i11.OperationRequirement = j11.ID
							AND j11.ID = 27	-- >> 27 FOR NEL
							AND i11.IsSelected = 1
						) j2
						WHERE i.TractionPowerId = j.TractionPowerId
							AND j.PowerSectionId in (
								select PowerSectorId from TAMS_TAR_Power_Sector where TARId = a.Id
							)
							AND j2.TARId=a.Id
							AND j.TractionPowerType = 'Sector'
							AND i.OperationDate = @OperationDate
							AND i.AccessDate = @accessDate
							 AND i.RackedOutTime is not null and i.RackedOutType = 'Completed' 
						) END as CircuitBreakOutTime,
						dbo.TAMS_Get_TOA_Parties(b.Id) as PartiesName,
						b.NoOfParties  as NoOfPersons,a.DescOfWork as WorkDescription, (b.MobileNo + @NewLine + b.TetraRadioNo) as ContactNo
						,ISNULL(b.TOANo, '') as TOANo,
		--b.Id, a.TARNo, a.ARRemark, a.TVFMode, a.AccessType, b.TOAStatus, 
		-- >> ISNULL(CONVERT(NVARCHAR(20), b.AckProtectionLimitTime, 108), '00:00:00'), 
		--ISNULL(CONVERT(NVARCHAR(5), b.AckProtectionLimitTime, 108), ''), 
		--b.NoOfParties as NoOfPersons,
		--a.DescOfWork as WorkDescription, b.MobileNo as ContactNo, b.TetraRadioNo, ISNULL(b.TOANo, '') as TOANo,
		CASE WHEN ISNULL(b.TOANo, '') = '' THEN '' ELSE '04:00' END as CallBackTime,
		ISNULL(CONVERT(NVARCHAR(5), b.GrantTOATime, 108), '') as RadioMsgTime,
		ISNULL(CONVERT(NVARCHAR(5), b.AckSurrenderTime, 108), '') as LineClearMsgTime,
		[dbo].[SP_TAMS_RGS_Comments](a.Id,b.Id,'NEL') as Remarks,
		b.TOAStatus,
		CONVERT(bit,
		CASE WHEN a.Line='DTL' THEN 
		(
			SELECT IIF(EXISTS(SELECT * FROM TAMS_OCC_Auth a1, TAMS_Traction_Power_Detail b1
				WHERE a1.TractionPowerId = b1.TractionPowerId AND b1.SectorId in (
												SELECT a2.SectorId
											FROM TAMS_TAR_Sector a2, TAMS_Sector b2
												WHERE a2.SectorId = b2.ID
													AND a2.TARId = a.Id
													AND ISNULL(b2.IsGap, 0) = 0
													AND a2.IsBuffer = 0
											)
											AND b1.TractionPowerType = 'Sector'
											AND a1.OperationDate = @OperationDate
											AND a1.AccessDate = @accessDate
											AND ((a1.OCCAuthStatusId < 10 and a1.IsBuffer = 0) OR ((a1.OCCAuthStatusId < 7 and a1.IsBuffer = 1)))	 
										) or not EXISTS(SELECT aocc1.ID
									FROM TAMS_OCC_Auth aocc1 
									WHERE  aocc1.Line = @Line
									and aocc1.TrackType = @TrackType
									AND aocc1.OperationDate = @OperationDate
									AND aocc1.AccessDate = @AccessDate),0,1) 
		) ELSE (
			SELECT IIF(EXISTS(SELECT *
					FROM TAMS_OCC_Auth aa1, TAMS_Traction_Power_Detail bb1 
						WHERE aa1.TractionPowerId = bb1.TractionPowerId
							AND bb1.PowerSectionId in (
								select PowerSectorId from TAMS_TAR_Power_Sector where TARId = a.Id
							)
							AND bb1.TractionPowerType = 'Sector'
							AND aa1.OperationDate = @OperationDate
							AND aa1.AccessDate = @accessDate
							 AND aa1.OCCAuthStatusId < 8) or not exists(
								select aocc.ID FROM TAMS_OCC_Auth aocc, TAMS_Traction_Power_Detail bpd 
								WHERE aocc.TractionPowerId = bpd.TractionPowerId
									AND bpd.PowerSectionId in (
										select PowerSectorId from TAMS_TAR_Power_Sector where TARId = a.Id
									)
									AND bpd.TractionPowerType = 'Sector'
									AND aocc.OperationDate = @OperationDate
									AND aocc.AccessDate = @AccessDate
							 ),0,1)
		
		) END) as IsTOAAuth,
		CASE WHEN TOAStatus=6 THEN @RGSCancBG ELSE CASE WHEN a.AccessType='Possession' THEN @RGSPossBG ELSE @RGSProtBG END END as ColourCode,
		--Grant TOA
		CONVERT(bit,IIF(b.TOAStatus=6,1,IIF(a.Line='DTL',IIF(a.AccessType='Possession',1, IIF(@possession_ctrl=1,1,0)),1))) as IsGrantTOAEnable,
		ISNULL(CONVERT(NVARCHAR(5), b.UpdateQTSTime, 108), '') as UpdQTSTime,
		a.AccessType as AccessType,
		ISNULL(CONVERT(NVARCHAR(8), b.AckGrantTOATime, 108), '') as AckGrantTOATime,
		ISNULL(CONVERT(NVARCHAR(5), b.AckProtectionLimitTime, 108), '') as AckProtLimitTIme, 
		a.Id as TARID,
		b.Id as TOAID,
		dbo.DecryptString(b.InChargeNRIC) as InChargeNRIC
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND a.AccessDate = @accessDate
			and a.TrackType = @TrackType
			AND b.TOAStatus <> 0
			AND a.Line = @Line
			AND UPPER(a.TrackType)=UPPER(@TrackType)
	-- >> ORDER BY a.AccessType, b.TOAType, a.Id
	--ORDER BY a.AccessType,a.TARNo
	ORDER BY a.AccessType, b.TOAStatus DESC, a.Id

-- >> Cancel List
SELECT a.Id AS Val, a.TARNo AS Txt
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND b.TOAStatus NOT IN (0, 5, 6)
			AND a.AccessDate = @accessDate
			AND a.Line = @Line
			AND a.TrackType = @TrackType
	ORDER BY 1

SELECT CONVERT(NVARCHAR(20), @OperationDate, 103) AS OperationDate,  
	CONVERT(NVARCHAR(20), @accessDate, 103) AS AccessDate

	
END
GO
/****** END PROCEDURE 296 ******/

/****** START PROCEDURE 297 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_RGS_OnLoad_AckSMS
CREATE PROCEDURE [dbo].[sp_TAMS_RGS_OnLoad_AckSMS]
	@TARID		AS BIGINT = 0
AS

BEGIN

	SELECT b.AccessType, 
			ISNULL(CONVERT(NVARCHAR(10), a.AckGrantTOATime, 103) + ' ' + CONVERT(NVARCHAR(8), a.AckGrantTOATime, 108), '00:00:00') AS AckGrantTOATime, 
			ISNULL(CONVERT(NVARCHAR(10), a.AckProtectionLimitTime, 103) + ' ' + CONVERT(NVARCHAR(8), a.AckProtectionLimitTime, 108), '00:00:00') AS AckProtectionLimitTime,
			b.TARNo,
			a.TOANo
		FROM TAMS_TOA a, TAMS_TAR b
			WHERE b.Id = a.TARId
				AND a.TARId = @TARID
END
GO
/****** END PROCEDURE 297 ******/

/****** START PROCEDURE 298 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_RGS_OnLoad_AckSMS_20221107
CREATE PROCEDURE [dbo].[sp_TAMS_RGS_OnLoad_AckSMS_20221107]
	@TARID		AS BIGINT = 0
AS

BEGIN

	SELECT b.AccessType, 
			ISNULL(CONVERT(NVARCHAR(10), a.AckGrantTOATime, 103) + ' ' + CONVERT(NVARCHAR(8), a.AckGrantTOATime, 108), '00:00:00') AS AckGrantTOATime, 
			ISNULL(CONVERT(NVARCHAR(10), a.AckProtectionLimitTime, 103) + ' ' + CONVERT(NVARCHAR(8), a.AckProtectionLimitTime, 108), '00:00:00') AS AckProtectionLimitTime,
			b.TARNo,
			a.TOANo
		FROM TAMS_TOA a, TAMS_TAR b
			WHERE b.Id = a.TARId
				AND a.TARId = @TARID
END
GO
/****** END PROCEDURE 298 ******/

/****** START PROCEDURE 299 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_RGS_OnLoad_Enq
CREATE PROCEDURE  [dbo].[sp_TAMS_RGS_OnLoad_Enq]
	@Line	NVARCHAR(20) = NULL,
	@TrackType nvarchar(50) = null,
	@OPDate	NVARCHAR(20) = NULL
AS

BEGIN
	
/*
Notes :
OCCAuthStatusId 
DTL = 10
NEL = 7
*/

CREATE TABLE #TmpRGS 
(Sno				INT,
TARNo				NVARCHAR(30),
ElectricalSections	NVARCHAR(4000),
PowerOffTime		NVARCHAR(20),
CircuitBreakOutTime	NVARCHAR(20),
PartiesName			NVARCHAR(4000),
NoOfPersons			NVARCHAR(20),
WorkDescription		NVARCHAR(4000),
ContactNo			NVARCHAR(50),
TOANo				NVARCHAR(30),
CallBackTime		NVARCHAR(20),
RadioMsgTime		NVARCHAR(20),
LineClearMsgTime	NVARCHAR(20),
Remarks				NVARCHAR(4000),
TOAStatus			NVARCHAR(20),
IsTOAAuth			BIT,
ColourCode			NVARCHAR(20),
IsGrantTOAEnable	BIT,
UpdQTSTime			NVARCHAR(20),
AccessType			NVARCHAR(20),
AckGrantTOATime		NVARCHAR(20),
AckProtLimitTime	NVARCHAR(20),
TARID				INT,
TOAID				INT,
InchargeNRIC		NVARCHAR(100))

CREATE TABLE #TmpRGSSectors 
(OCCAuthID			INT,
OperationDate		DATE,
AccessDate			DATE,
OCCAuthStatus		NVARCHAR(50),
TractionPowerID		INT,
TractionPowerType	NVARCHAR(50),
SectorID			INT,
Sector				NVARCHAR(100),
WorkFlowTime		DATETIME)

TRUNCATE TABLE #TmpRGS
TRUNCATE TABLE #TmpRGSSectors

DECLARE @CurDate		DATE
DECLARE @CurTime		TIME
DECLARE @OperationDate	DATE
DECLARE @AccessDate		DATE

SET @CurDate = GETDATE()
SET @CurTime = CONVERT(TIME, GETDATE(), 108)

DECLARE @CutOff				TIME
DECLARE @TOACallBackTime	NVARCHAR(10)
DECLARE @RGSPossBG			NVARCHAR(20)
DECLARE @RGSProtBG			NVARCHAR(20)
DECLARE @RGSCancBG			NVARCHAR(20)

--SET @TOACallBackTime = '04:00'
SET @CutOff = '06:00:00'

SELECT @TOACallBackTime = CAST(ParaTime AS NVARCHAR(5))
	FROM TAMS_Parameters
		WHERE ParaCode = 'TOACallbackTime'
			AND ParaValue1 = @Line
			AND ParaValue2 = @TrackType

SELECT @RGSPossBG = ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'RGSPossessionBG'
			AND ParaValue1 = @Line

SELECT @RGSProtBG = ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'RGSProtectionBG'
			AND ParaValue1 = @Line

SELECT @RGSCancBG = ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'RGSCancelledBG'
			AND ParaValue1 = @Line

IF @CurTime > @CutOff
	BEGIN
		SET @OperationDate	= @CurDate
		SET @AccessDate		= DATEADD(DAY, 1, @CurDate)
	END
ELSE
	BEGIN
		SET @OperationDate	= DATEADD(DAY, -1, @CurDate)
		SET @AccessDate		= @CurDate
	END

SET @OperationDate = CONVERT(DATE, @OPDate, 103)
SET @AccessDate = DATEADD(DAY, 1, CONVERT(DATE, @OPDate, 103))

if UPPER(@TrackType)='DEPOT' BEGIN
	SET @AccessDate = @OperationDate
END

--SELECT @OperationDate, @AccessDate

DECLARE @Cur01 CURSOR;
DECLARE @Cur02 CURSOR;

DECLARE @TARID BIGINT,
@TOAID	BIGINT,
@ARRemark NVARCHAR(1000),
@TVFMode NVARCHAR(20),
@AccessType NVARCHAR(30),
@TOAStatus INT,
@ProtTimeLimit NVARCHAR(10),
@TARNo NVARCHAR(30),
@NoOfParties INT,
@DescOfWork NVARCHAR(1000),
@MobileNo NVARCHAR(20),
@TetraRadioNo NVARCHAR(50),
@TOANo NVARCHAR(50),
@GrantTOATime NVARCHAR(10),
@AckSurrenderTime NVARCHAR(10),
@AckGrantTOATime NVARCHAR(10),
@UpdateQTSTime NVARCHAR(10),
@InchargeNRIC NVARCHAR(100), 
@CancelRemark NVARCHAR(1000)

DECLARE @lv_Sno INT,
	@lv_IsTOAAuth BIT,
	@lv_PartiesName	NVARCHAR(4000),
	@lv_Remarks	NVARCHAR(4000),
	@lv_IsPowerOff BIT,
	@lv_PowerOffTime NVARCHAR(20),
	@lv_IsCircuitBreak BIT,
	@lv_CircuitBreakTime NVARCHAR(20),
	@lv_ColourCode NVARCHAR(20),
	@lv_ES NVARCHAR(100),
	@lv_SectorID INT,
	@lv_TVFStations NVARCHAR(1000),
	@lv_PossessionCtr INT,
	@lv_IsGrantTOAEnable BIT,
	@lv_ContactNo NVARCHAR(200), 
	@lv_Callbacktime datetime

DECLARE @SqlCtr1 INT,
	@SqlCtr2 INT,
	@SqlCtr3 INT,
	@WorkFlowTime NVARCHAR(20)

SET @lv_Sno = 0
SET @SqlCtr1 = 0
SET @SqlCtr2 = 0
SET @SqlCtr3 = 0
SET @lv_PossessionCtr = 0

SELECT @lv_PossessionCtr = COUNT(*)
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND a.AccessDate = @AccessDate
			AND b.TOAStatus NOT IN (0, 6)
			AND a.Line = @Line
			and a.TrackType = @TrackType
			AND a.AccessType = 'Possession'

DECLARE @NewLine AS NVARCHAR(6)
SET @NewLine = '<br />'

SET @Cur01 = CURSOR FAST_FORWARD 
FOR

SELECT a.Id, b.Id, a.TARNo, a.ARRemark, a.TVFMode, a.AccessType, b.TOAStatus, 
		-- >> ISNULL(CONVERT(NVARCHAR(20), b.AckProtectionLimitTime, 108), '00:00:00'), 
		ISNULL(CONVERT(NVARCHAR(5), b.AckProtectionLimitTime, 108), ''), 
		b.NoOfParties,
		a.DescOfWork, b.MobileNo, b.TetraRadioNo, ISNULL(b.TOANo, ''),
		ISNULL(CONVERT(NVARCHAR(5), b.GrantTOATime, 108), ''),
		ISNULL(CONVERT(NVARCHAR(5), b.AckSurrenderTime, 108), ''),
		ISNULL(CONVERT(NVARCHAR(8), b.AckGrantTOATime, 108), ''),
		ISNULL(CONVERT(NVARCHAR(5), b.UpdateQTSTime, 108), ''),
		dbo.DecryptString(b.InChargeNRIC),
		b.CancelRemark,b.TOACallbackTime
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND a.AccessDate = @AccessDate
			AND b.TOAStatus <> 0
			AND a.Line = @Line
			and a.TrackType = @TrackType
	-- >> ORDER BY a.AccessType, b.TOAType, a.Id
	ORDER BY a.AccessType, b.TOAStatus DESC, a.Id

OPEN @Cur01
	
FETCH NEXT FROM @Cur01 INTO @TARID, @TOAID, @TARNo, @ARRemark, @TVFMode, @AccessType, @TOAStatus, 
	@ProtTimeLimit, 
	@NoOfParties,
	@DescOfWork, @MobileNo, @TetraRadioNo, @TOANo,
	@GrantTOATime, @AckSurrenderTime, @AckGrantTOATime, @UpdateQTSTime,
	@InchargeNRIC, @CancelRemark,@lv_Callbacktime
	
WHILE @@FETCH_STATUS = 0 
	
	BEGIN

		SET @lv_Sno = @lv_Sno + 1
		SET	@lv_IsTOAAuth = 0
		SET @lv_PartiesName	= ''
		SET @lv_Remarks	= ''
		SET @lv_IsPowerOff = 0
		SET @lv_PowerOffTime = ''
		SET @lv_IsCircuitBreak = 0
		SET @lv_CircuitBreakTime = ''
		SET @lv_ColourCode = ''
		SET @lv_ES = ''
		SET @lv_ContactNo = ''

		SELECT @lv_ES = dbo.TAMS_Get_ES_NoBufferZone(@TARID)
		SELECT @lv_PartiesName = dbo.TAMS_Get_TOA_Parties(@TOAID)
		SET @lv_ContactNo = @MobileNo + @NewLine + @TetraRadioNo

		-- >> Electrical Sector Cursor
		-- >> 	EXEC sp_TAMS_RGS_OnLoad_20210819_M 'NEL'

		IF @Line = 'DTL'
			BEGIN

			set @lv_CircuitBreakTime = '';
				set @lv_IsTOAAuth = 0;
				set @lv_PowerOffTime = '';
				set @lv_IsPowerOff = 0 ;

			if exists(SELECT a.ID
							FROM TAMS_OCC_Auth a 
								WHERE  a.Line = @Line
									and a.TrackType = @TrackType
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate)
			begin
				if(
					SELECT Count(a.ID)
									FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b 
										WHERE a.TractionPowerId = b.TractionPowerId
											AND b.SectorId in (
												SELECT a.SectorId
											FROM TAMS_TAR_Sector a, TAMS_Sector b
												WHERE a.SectorId = b.ID
													AND a.TARId = @TARID
													AND ISNULL(b.IsGap, 0) = 0
													AND a.IsBuffer = 0
											)
											AND b.TractionPowerType = 'Sector'
											AND a.OperationDate = @OperationDate
											AND a.AccessDate = @AccessDate
											 
											AND ((a.OCCAuthStatusId < 10 and a.IsBuffer = 0) OR ((a.OCCAuthStatusId < 7 and a.IsBuffer = 1)))
											 
								) = 0 
								begin 
									set @lv_IsTOAAuth = 1;
								end;
				end;


				-- To check whether PFR has done action for all the sector ; Power OFF type is NULL means they has not completed the action
				if not exists(
					select * 
					FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b 
						WHERE a.TractionPowerId = b.TractionPowerId
							 AND b.SectorId in (
												SELECT a.SectorId
											FROM TAMS_TAR_Sector a, TAMS_Sector b
												WHERE a.SectorId = b.ID
													AND a.TARId = @TARID
													AND ISNULL(b.IsGap, 0) = 0
													AND a.IsBuffer = 0
											)
							AND b.TractionPowerType = 'Sector'
							AND a.OperationDate = @OperationDate
							AND a.AccessDate = @AccessDate
							 AND a.PowerOffType IS NULL  
						)
					begin
							SELECT  @lv_PowerOffTime = ISNULL(CONVERT(NVARCHAR(5), max(a.PowerOffTime), 108), '')
					FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b 
						WHERE a.TractionPowerId = b.TractionPowerId
							 AND b.SectorId in (
												SELECT a.SectorId
											FROM TAMS_TAR_Sector a, TAMS_Sector b
												WHERE a.SectorId = b.ID
													AND a.TARId = @TARID
													AND ISNULL(b.IsGap, 0) = 0
													AND a.IsBuffer = 0
											)
							AND b.TractionPowerType = 'Sector'
							AND a.OperationDate = @OperationDate
							AND a.AccessDate = @AccessDate
							 AND a.PowerOffTime IS NOT NULL and a.PowerOffType='Completed'
				 	
					end;		 
				if @lv_PowerOffTime <> ''
				begin 
					set @lv_IsPowerOff = 1 ;
				end; 
				
				-- To check whether PFR has done action for all the sector ; Rack Out type is NULL means they has not completed the action
				if not exists(
					select *
					FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b 
								WHERE a.TractionPowerId = b.TractionPowerId
									 AND b.SectorId in (
														SELECT a.SectorId
													FROM TAMS_TAR_Sector a, TAMS_Sector b
														WHERE a.SectorId = b.ID
															AND a.TARId = @TARID
															AND ISNULL(b.IsGap, 0) = 0
															AND a.IsBuffer = 0
													)
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									 AND a.RackedOutType IS  NULL 

				)
				begin 
						SELECT  @lv_CircuitBreakTime = ISNULL(CONVERT(NVARCHAR(5), max(a.RackedOutTime), 108), '')
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b 
								WHERE a.TractionPowerId = b.TractionPowerId
									 AND b.SectorId in (
														SELECT a.SectorId
													FROM TAMS_TAR_Sector a, TAMS_Sector b
														WHERE a.SectorId = b.ID
															AND a.TARId = @TARID
															AND ISNULL(b.IsGap, 0) = 0
															AND a.IsBuffer = 0
													)
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									 AND a.RackedOutTime IS NOT NULL and a.RackedOutType='Completed'
 
				end;
 			
			END
		ELSE
			BEGIN
			 	-----For NEL Checking .. 

				set @lv_CircuitBreakTime = '';
				set @lv_IsTOAAuth = 0;
				set @lv_PowerOffTime = '';
				set @lv_IsPowerOff = 0 ;


				if exists(select a.ID FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b 
					WHERE a.TractionPowerId = b.TractionPowerId
						AND b.PowerSectionId in (
							select PowerSectorId from TAMS_TAR_Power_Sector where TARId = @TARID
						)
						AND b.TractionPowerType = 'Sector'
						AND a.OperationDate = @OperationDate
						AND a.AccessDate = @AccessDate)
				begin
				 	if(SELECT COUNT(a.ID)
					FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b 
						WHERE a.TractionPowerId = b.TractionPowerId
							AND b.PowerSectionId in (
								select PowerSectorId from TAMS_TAR_Power_Sector where TARId = @TARID
							)
							AND b.TractionPowerType = 'Sector'
							AND a.OperationDate = @OperationDate
							AND a.AccessDate = @AccessDate
							 AND a.OCCAuthStatusId < 8)= 0 
					begin 
						set @lv_IsTOAAuth = 1 ; 
					end;
				end;


			-- To check whether PFR has done action for all the sector ; Power OFF type is NULL means they has not completed the action
			if not exists(
				select * 
				FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b 
					WHERE a.TractionPowerId = b.TractionPowerId
						AND b.PowerSectionId in (
							select PowerSectorId from TAMS_TAR_Power_Sector where TARId = @TARID
						)
						AND b.TractionPowerType = 'Sector'
						AND a.OperationDate = @OperationDate
						AND a.AccessDate = @AccessDate
						 AND a.PowerOffType is   null   
			)
			begin
				SELECT  @lv_PowerOffTime = ISNULL(CONVERT(NVARCHAR(5), max(a.PowerOffTime), 108), '')
				FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b 
					WHERE a.TractionPowerId = b.TractionPowerId
						AND b.PowerSectionId in (
							select PowerSectorId from TAMS_TAR_Power_Sector where TARId = @TARID
						)
						AND b.TractionPowerType = 'Sector'
						AND a.OperationDate = @OperationDate
						AND a.AccessDate = @AccessDate
						 AND a.PowerOffTime is not null  and a.PowerOffType = 'Completed' 
				end;		
				
				if @lv_PowerOffTime <> ''
				begin 
					set @lv_IsPowerOff = 1 ;
				end; 

				-- To check whether PFR has done action for all the sector ; Power OFF type is NULL means they has not completed the action
			if not exists(
				select *
				FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b 
					WHERE a.TractionPowerId = b.TractionPowerId
						AND b.PowerSectionId in (
							select PowerSectorId from TAMS_TAR_Power_Sector where TARId = @TARID
						)
						AND b.TractionPowerType = 'Sector'
						AND a.OperationDate = @OperationDate
						AND a.AccessDate = @AccessDate
						 AND a.RackedOuttype is   null 
			)
			begin
				SELECT  @lv_CircuitBreakTime = ISNULL(CONVERT(NVARCHAR(5), max(a.RackedOutTime), 108), '')
				FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b 
					WHERE a.TractionPowerId = b.TractionPowerId
						AND b.PowerSectionId in (
							select PowerSectorId from TAMS_TAR_Power_Sector where TARId = @TARID
						)
						AND b.TractionPowerType = 'Sector'
						AND a.OperationDate = @OperationDate
						AND a.AccessDate = @AccessDate
						 AND a.RackedOutTime is not null and a.RackedOutType = 'Completed' 
				print @TARID; 	 
				print @lv_CircuitBreakTime;
			end;
			END
		-- >>
		-- >> Electrical Sector Cursor

		IF @Line = 'DTL'
			BEGIN
				SET @lv_Remarks = LTRIM(RTRIM(@ARRemark)) + @NewLine + LTRIM(RTRIM(ISNULL(@TVFMode, '')))
			END
		ELSE
			BEGIN

					-- DTL also will follow the same rule as NEL (meaning if TAR is without Rackout, RGS screen show blank in Rackout column)
		
				DECLARE @RackOutCtr	INT

				SELECT @RackOutCtr = COUNT(*) 
					FROM TAMS_TAR_AccessReq a, TAMS_Access_Requirement b
						WHERE a.IsPower = 1
							AND a.OperationRequirement = b.ID
							AND b.ID = 27	-- >> 27 FOR NEL
							AND a.IsSelected = 1
							AND a.TARId = @TARID

				IF @RackOutCtr > 0
					BEGIN
						SET @lv_Remarks = 'Rack Out' + @NewLine + @NewLine + LTRIM(RTRIM(@ARRemark)) + @NewLine + LTRIM(RTRIM(ISNULL(@TVFMode, '')))
					END
				ELSE
					BEGIN
						-- >> Don't show RackedOutTime for NEL if Power Requirement is with out Racked Out
						SET @lv_CircuitBreakTime = ''
						SET @lv_Remarks = LTRIM(RTRIM(@ARRemark)) + @NewLine + LTRIM(RTRIM(ISNULL(@TVFMode, '')))
					END
			 END

		DECLARE @SCDCtr	INT

		SELECT @SCDCtr = COUNT(*) 
			FROM TAMS_TAR_AccessReq a, TAMS_Access_Requirement b
				WHERE -- >> a.IsPower = 1 AND  -- >> 07082023 To remove this condition Jeffrey
					a.OperationRequirement = b.ID
					AND b.OperationRequirement = 'SCD Application'
					AND a.IsSelected = 1
					AND a.TARId = @TARID

		IF @SCDCtr > 0
			BEGIN
				SET @lv_Remarks = 'SCD' + @NewLine + @NewLine + LTRIM(RTRIM(@lv_Remarks))
			END

		SELECT @lv_TVFStations = dbo.TAMS_Get_TOA_TVF_Stations(@TOAID)

		IF @lv_Remarks = ''
			BEGIN
				SET @lv_Remarks = @lv_TVFStations
			END
		ELSE
			BEGIN
				SET @lv_Remarks = @lv_Remarks + @NewLine + @lv_TVFStations
			END

		 
		IF @Line = 'DTL'	-- >> DTL to continue with Possession Priority Rule. 
			BEGIN
				IF @AccessType = 'Possession'
					BEGIN
						SET @lv_ColourCode = @RGSPossBG

						IF @TOAStatus = 6
							BEGIN
								IF @lv_PossessionCtr = 0
									BEGIN
										SET @lv_PossessionCtr = @lv_PossessionCtr
									END
								ELSE
									BEGIN
										SET @lv_PossessionCtr = @lv_PossessionCtr - 1
									END
							END
						ELSE
							BEGIN
								IF @ProtTimeLimit = '' OR @ProtTimeLimit = '00:00:00'
									BEGIN
										-- >> SELECT '1'
										SET @lv_PossessionCtr = @lv_PossessionCtr + 1
										-- >> SET @lv_PossessionCtr = @lv_PossessionCtr
									END
								ELSE
									BEGIN
										-- >> SELECT '2'
										IF @lv_PossessionCtr = 0
											BEGIN
												-- >> SELECT '3'
												SET @lv_PossessionCtr = @lv_PossessionCtr
											END
										ELSE
											BEGIN
												-- >> SELECT '4'
												SET @lv_PossessionCtr = @lv_PossessionCtr - 1
											END
									END
							END

						SET @lv_IsGrantTOAEnable = 1

					END
				ELSE
					BEGIN
						-- >> SELECT @lv_PossessionCtr AS PossCtr
						-- 	EXEC sp_TAMS_RGS_OnLoad 'DTL'
						SET @lv_ColourCode = @RGSProtBG

						IF @TOAStatus = 6
							BEGIN
								SET @lv_IsGrantTOAEnable = 1
							END
						ELSE
							BEGIN
								IF @lv_PossessionCtr > 0
									BEGIN
										SET @lv_IsGrantTOAEnable = 0
									END
								ELSE
									BEGIN
										SET @lv_IsGrantTOAEnable = 1
									END
							END
					END
			END
		ELSE	-- >> NEL to change with no Priority
			BEGIN
				IF @AccessType = 'Possession'
					BEGIN
						SET @lv_ColourCode = @RGSPossBG
					END
				ELSE
					BEGIN
						SET @lv_ColourCode = @RGSProtBG
					END

				SET @lv_IsGrantTOAEnable = 1
			END

		-- >> 2023 change highlight for cancelled records
		-- >> Include Cancel remarks after new line
		IF @TOAStatus = 6
			BEGIN
				SET @lv_ColourCode = @RGSCancBG
				SET @lv_Remarks = @lv_Remarks + @NewLine + @NewLine + 'Cancel Remark: ' + LTRIM(RTRIM(@CancelRemark))
			END

		INSERT INTO #TmpRGS
			(Sno, TARNo, ElectricalSections,
				PowerOffTime, CircuitBreakOutTime,
				PartiesName, NoOfPersons, 
				WorkDescription, ContactNo, TOANo,
				CallBackTime, 
				RadioMsgTime, LineClearMsgTime,
				Remarks, TOAStatus, IsTOAAuth, ColourCode, IsGrantTOAEnable, 
				UpdQTSTime, AccessType,
				AckGrantTOATime, AckProtLimitTime, 
				TARID, TOAID, InchargeNRIC)
		VALUES (@lv_Sno, @TARNo, @lv_ES, 
			@lv_PowerOffTime, @lv_CircuitBreakTime, 
			@lv_PartiesName, @NoOfParties, 
			@DescOfWork, @lv_ContactNo, @TOANo, 
			CASE WHEN @TrackType = 'Depot' THEN format(@lv_Callbacktime,'HH:mm') when @TOANo = '' THEN '' ELSE @TOACallBackTime END, 
			@GrantTOATime, @AckSurrenderTime, 
			@lv_Remarks, @TOAStatus, @lv_IsTOAAuth, @lv_ColourCode, @lv_IsGrantTOAEnable, 
			@UpdateQTSTime, @AccessType, 
			@AckGrantTOATime, @ProtTimeLimit, 
			@TARID, @TOAID, @InchargeNRIC)

		FETCH NEXT FROM @Cur01 INTO @TARID, @TOAID, @TARNo, @ARRemark, @TVFMode, @AccessType, @TOAStatus, 
			@ProtTimeLimit, 
			@NoOfParties,
			@DescOfWork, @MobileNo, @TetraRadioNo, @TOANo,
			@GrantTOATime, @AckSurrenderTime, @AckGrantTOATime, @UpdateQTSTime,
			@InchargeNRIC, @CancelRemark,@lv_Callbacktime
	END 	

CLOSE @Cur01
	
DEALLOCATE @Cur01


-- >> RGS List
SELECT Sno, TARNo, ElectricalSections,
	PowerOffTime, CircuitBreakOutTime,
	PartiesName, NoOfPersons, 
	WorkDescription, ContactNo, TOANo,
	CallBackTime, RadioMsgTime, LineClearMsgTime,
	Remarks, TOAStatus, IsTOAAuth, ColourCode, IsGrantTOAEnable, 
	UpdQTSTime, AccessType,
	AckGrantTOATime, AckProtLimitTime, 
	TARID, TOAID,
	InchargeNRIC
FROM #TmpRGS
	ORDER BY Sno

---- >> Cancel List
--SELECT a.Id AS Val, a.TARNo AS Txt
--	FROM TAMS_TAR a, TAMS_TOA b
--		WHERE a.Id = b.TARId
--			AND b.TOAStatus NOT IN (0, 5, 6)
--			AND a.AccessDate = @AccessDate
--			AND a.Line = @Line
--	ORDER BY 1

--SELECT CONVERT(NVARCHAR(20), @OperationDate, 103) AS OperationDate,  
--	CONVERT(NVARCHAR(20), @AccessDate, 103) AS AccessDate

SELECT CONVERT(NVARCHAR(20), @OperationDate, 105) AS OperationDate,  
	CONVERT(NVARCHAR(20), @AccessDate, 105) AS AccessDate

DROP TABLE #TmpRGS
DROP TABLE #TmpRGSSectors

END
GO
/****** END PROCEDURE 299 ******/

/****** START PROCEDURE 300 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_RGS_OnLoad_Enq_20221107
CREATE PROCEDURE [dbo].[sp_TAMS_RGS_OnLoad_Enq_20221107]
	@Line	NVARCHAR(20) = NULL,
	@OPDate	NVARCHAR(20) = NULL
AS

BEGIN
	
/*
Notes :
OCCAuthStatusId 
DTL = 10
NEL = 7
*/

CREATE TABLE #TmpRGS 
(Sno				INT,
TARNo				NVARCHAR(30),
ElectricalSections	NVARCHAR(4000),
PowerOffTime		NVARCHAR(20),
CircuitBreakOutTime	NVARCHAR(20),
PartiesName			NVARCHAR(4000),
NoOfPersons			NVARCHAR(20),
WorkDescription		NVARCHAR(4000),
ContactNo			NVARCHAR(50),
TOANo				NVARCHAR(30),
CallBackTime		NVARCHAR(20),
RadioMsgTime		NVARCHAR(20),
LineClearMsgTime	NVARCHAR(20),
Remarks				NVARCHAR(4000),
TOAStatus			NVARCHAR(20),
IsTOAAuth			BIT,
ColourCode			NVARCHAR(20),
IsGrantTOAEnable	BIT,
UpdQTSTime			NVARCHAR(20),
AccessType			NVARCHAR(20),
AckGrantTOATime		NVARCHAR(20),
AckProtLimitTime	NVARCHAR(20),
TARID				INT,
TOAID				INT,
InchargeNRIC		NVARCHAR(100))

CREATE TABLE #TmpRGSSectors 
(OCCAuthID			INT,
OperationDate		DATE,
AccessDate			DATE,
OCCAuthStatus		NVARCHAR(50),
TractionPowerID		INT,
TractionPowerType	NVARCHAR(50),
SectorID			INT,
Sector				NVARCHAR(100),
WorkFlowTime		DATETIME)

TRUNCATE TABLE #TmpRGS
TRUNCATE TABLE #TmpRGSSectors

DECLARE @CurDate		DATE
DECLARE @CurTime		TIME
DECLARE @OperationDate	DATE
DECLARE @AccessDate		DATE

SET @CurDate = GETDATE()
SET @CurTime = CONVERT(TIME, GETDATE(), 108)

DECLARE @CutOff				TIME
DECLARE @TOACallBackTime	NVARCHAR(10)
DECLARE @RGSPossBG			NVARCHAR(20)
DECLARE @RGSProtBG			NVARCHAR(20)

--SET @TOACallBackTime = '04:00'
SET @CutOff = '06:00:00'

SELECT @TOACallBackTime = CAST(ParaTime AS NVARCHAR(5))
	FROM TAMS_Parameters
		WHERE ParaCode = 'TOACallbackTime'
			AND ParaValue1 = @Line

SELECT @RGSPossBG = ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'RGSPossessionBG'
			AND ParaValue1 = @Line

SELECT @RGSProtBG = ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'RGSProtectionBG'
			AND ParaValue1 = @Line

IF @CurTime > @CutOff
	BEGIN
		SET @OperationDate	= @CurDate
		SET @AccessDate		= DATEADD(DAY, 1, @CurDate)
	END
ELSE
	BEGIN
		SET @OperationDate	= DATEADD(DAY, -1, @CurDate)
		SET @AccessDate		= @CurDate
	END

SET @OperationDate = CONVERT(DATE, @OPDate, 103)
SET @AccessDate = DATEADD(DAY, 1, CONVERT(DATE, @OPDate, 103))

--SELECT @OperationDate, @AccessDate

DECLARE @Cur01 CURSOR;
DECLARE @Cur02 CURSOR;

DECLARE @TARID BIGINT,
@TOAID	BIGINT,
@ARRemark NVARCHAR(1000),
@TVFMode NVARCHAR(20),
@AccessType NVARCHAR(30),
@TOAStatus INT,
@ProtTimeLimit NVARCHAR(10),
@TARNo NVARCHAR(30),
@NoOfParties INT,
@DescOfWork NVARCHAR(1000),
@MobileNo NVARCHAR(20),
@TetraRadioNo NVARCHAR(50),
@TOANo NVARCHAR(50),
@GrantTOATime NVARCHAR(10),
@AckSurrenderTime NVARCHAR(10),
@AckGrantTOATime NVARCHAR(10),
@UpdateQTSTime NVARCHAR(10),
@InchargeNRIC NVARCHAR(100)

DECLARE @lv_Sno INT,
	@lv_IsTOAAuth BIT,
	@lv_PartiesName	NVARCHAR(4000),
	@lv_Remarks	NVARCHAR(4000),
	@lv_IsPowerOff BIT,
	@lv_PowerOffTime NVARCHAR(20),
	@lv_IsCircuitBreak BIT,
	@lv_CircuitBreakTime NVARCHAR(20),
	@lv_ColourCode NVARCHAR(20),
	@lv_ES NVARCHAR(100),
	@lv_SectorID INT,
	@lv_TVFStations NVARCHAR(1000),
	@lv_PossessionCtr INT,
	@lv_IsGrantTOAEnable BIT,
	@lv_ContactNo NVARCHAR(200)

DECLARE @SqlCtr1 INT,
	@SqlCtr2 INT,
	@SqlCtr3 INT,
	@WorkFlowTime NVARCHAR(20)

SET @lv_Sno = 0
SET @SqlCtr1 = 0
SET @SqlCtr2 = 0
SET @SqlCtr3 = 0
SET @lv_PossessionCtr = 0

SELECT @lv_PossessionCtr = COUNT(*)
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND a.AccessDate = @AccessDate
			AND b.TOAStatus NOT IN (0, 6)
			AND a.Line = @Line
			AND a.AccessType = 'Possession'

----DECLARE @NewLine AS CHAR(2) = CHAR(30) + CHAR(10)
DECLARE @NewLine AS NVARCHAR(6)
SET @NewLine = '<br />'
-- >> SELECT @NewUID = SCOPE_IDENTITY();

SET @Cur01 = CURSOR FAST_FORWARD 
FOR

SELECT a.Id, b.Id, a.TARNo, a.ARRemark, a.TVFMode, a.AccessType, b.TOAStatus, 
		-- >> ISNULL(CONVERT(NVARCHAR(20), b.AckProtectionLimitTime, 108), '00:00:00'), 
		ISNULL(CONVERT(NVARCHAR(5), b.AckProtectionLimitTime, 108), ''), 
		b.NoOfParties,
		a.DescOfWork, b.MobileNo, b.TetraRadioNo, ISNULL(b.TOANo, ''),
		ISNULL(CONVERT(NVARCHAR(5), b.GrantTOATime, 108), ''),
		ISNULL(CONVERT(NVARCHAR(5), b.AckSurrenderTime, 108), ''),
		ISNULL(CONVERT(NVARCHAR(8), b.AckGrantTOATime, 108), ''),
		ISNULL(CONVERT(NVARCHAR(5), b.UpdateQTSTime, 108), ''),
		dbo.DecryptString(b.InChargeNRIC)
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND a.AccessDate = @AccessDate
			AND b.TOAStatus <> 0
			AND a.Line = @Line
	-- >> ORDER BY a.AccessType, b.TOAType, a.Id
	ORDER BY a.AccessType, b.TOAStatus DESC, a.Id

OPEN @Cur01
	
FETCH NEXT FROM @Cur01 INTO @TARID, @TOAID, @TARNo, @ARRemark, @TVFMode, @AccessType, @TOAStatus, 
	@ProtTimeLimit, 
	@NoOfParties,
	@DescOfWork, @MobileNo, @TetraRadioNo, @TOANo,
	@GrantTOATime, @AckSurrenderTime, @AckGrantTOATime, @UpdateQTSTime,
	@InchargeNRIC
	
WHILE @@FETCH_STATUS = 0 
	
	BEGIN

		SET @lv_Sno = @lv_Sno + 1
		SET	@lv_IsTOAAuth = 1
		SET @lv_PartiesName	= ''
		SET @lv_Remarks	= ''
		SET @lv_IsPowerOff = 1
		SET @lv_PowerOffTime = ''
		SET @lv_IsCircuitBreak = 1
		SET @lv_CircuitBreakTime = ''
		SET @lv_ColourCode = ''
		SET @lv_ES = ''
		SET @lv_ContactNo = ''

		SELECT @lv_ES = dbo.TAMS_Get_ES(@TARID)
		SELECT @lv_PartiesName = dbo.TAMS_Get_TOA_Parties(@TOAID)
		SET @lv_ContactNo = @MobileNo + @NewLine + @TetraRadioNo

		-- >> Electrical Sector Cursor
		-- >> 	EXEC sp_TAMS_RGS_OnLoad_20210819_M 'NEL'

		IF @Line = 'DTL'
			BEGIN
				SET @Cur02 = CURSOR FAST_FORWARD 
				FOR

				SELECT a.SectorId
					FROM TAMS_TAR_Sector a, TAMS_Sector b
						WHERE a.SectorId = b.ID
							AND a.TARId = @TARID
							AND ISNULL(b.IsGap, 0) = 0
							AND a.IsBuffer = 0
					
				OPEN @Cur02
	
				FETCH NEXT FROM @Cur02 INTO @lv_SectorID
	
				WHILE @@FETCH_STATUS = 0 
	
					BEGIN

						SET @SqlCtr1 = 0

						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.Sector, NULL
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.SectorId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND c.IsGap = 0
									-- >> AND a.OCCAuthStatusId = 10
									AND ((a.OCCAuthStatusId = 10 and a.IsBuffer = 0) OR ((a.OCCAuthStatusId = 7 and a.IsBuffer = 1)))
									AND c.Line = @Line

						SELECT @SqlCtr1 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr1 = 0
							BEGIN
								SET @lv_IsTOAAuth = 0
							END

						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.Sector, a.PowerOffTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.SectorId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND c.IsGap = 0
									AND a.PowerOffTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr2 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr2 = 0
							BEGIN
								SET @lv_IsPowerOff = 0
								SET @lv_PowerOffTime = ''
							END
						ELSE
							BEGIN
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM  #TmpRGSSectors

								IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_PowerOffTime = ''
									END
								ELSE
									BEGIN
										SET @lv_PowerOffTime = @WorkFlowTime
									END
							END

						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.Sector, a.RackedOutTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.SectorId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND c.IsGap = 0
									AND a.RackedOutTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr3 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr3 = 0
							BEGIN
								SET @lv_IsCircuitBreak = 0
								SET @lv_CircuitBreakTime = ''
							END
						ELSE
							BEGIN
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM  #TmpRGSSectors

									IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_CircuitBreakTime = ''
									END
								ELSE
									BEGIN
										SET @lv_CircuitBreakTime = @WorkFlowTime
									END
							END
						

						FETCH NEXT FROM @Cur02 INTO @lv_SectorID
					END 	

				CLOSE @Cur02
	
				DEALLOCATE @Cur02
			END
		ELSE
			BEGIN
				SET @Cur02 = CURSOR FAST_FORWARD 
				FOR

				SELECT a.PowerSectorId 
					FROM TAMS_TAR_Power_Sector a
						WHERE a.TARId = @TARID
							AND a.IsBuffer = 0
							

				OPEN @Cur02
	
				FETCH NEXT FROM @Cur02 INTO @lv_SectorID
	
				WHILE @@FETCH_STATUS = 0 
	
					BEGIN

						SET @SqlCtr1 = 0

						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.PowerSection, NULL
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Power_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.PowerSectionId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND a.OCCAuthStatusId = 7
									AND c.Line = @Line

						SELECT @SqlCtr1 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr1 = 0
							BEGIN
								SET @lv_IsTOAAuth = 0
							END

						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.PowerSection, a.PowerOffTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Power_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.PowerSectionId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND a.PowerOffTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr2 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr2 = 0
							BEGIN
								SET @lv_IsPowerOff = 0
								SET @lv_PowerOffTime = ''
							END
						ELSE
							BEGIN
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM  #TmpRGSSectors

									IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_PowerOffTime = ''
									END
								ELSE
									BEGIN
										SET @lv_PowerOffTime = @WorkFlowTime
									END
							END

						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.PowerSection, a.RackedOutTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Power_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.PowerSectionId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND a.RackedOutTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr3 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr3 = 0
							BEGIN
								SET @lv_IsCircuitBreak = 0
								SET @lv_CircuitBreakTime = ''
							END
						ELSE
							BEGIN
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM #TmpRGSSectors

									IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_CircuitBreakTime = ''
									END
								ELSE
									BEGIN
										SET @lv_CircuitBreakTime = @WorkFlowTime
									END
							END

						FETCH NEXT FROM @Cur02 INTO @lv_SectorID
					END 	

				CLOSE @Cur02
	
				DEALLOCATE @Cur02
			END
		-- >>
		-- >> Electrical Sector Cursor

		IF @Line = 'DTL'
			BEGIN
				SET @lv_Remarks = LTRIM(RTRIM(@ARRemark)) + @NewLine + LTRIM(RTRIM(ISNULL(@TVFMode, '')))
			END
		ELSE
			BEGIN
				DECLARE @RackOutCtr	INT

				SELECT @RackOutCtr = COUNT(*) 
					FROM TAMS_TAR_AccessReq a, TAMS_Access_Requirement b
						WHERE a.IsPower = 1
							AND a.OperationRequirement = b.ID
							AND b.ID = 27	-- >> 27 FOR NEL
							AND a.IsSelected = 1
							AND a.TARId = @TARID

				IF @RackOutCtr > 0
					BEGIN
						SET @lv_Remarks = 'Rack Out' + @NewLine + @NewLine + LTRIM(RTRIM(@ARRemark)) + @NewLine + LTRIM(RTRIM(ISNULL(@TVFMode, '')))
					END
				ELSE
					BEGIN
						-- >> Don't show RackedOutTime for NEL if Power Requirement is with out Racked Out
						SET @lv_CircuitBreakTime = ''
						SET @lv_Remarks = LTRIM(RTRIM(@ARRemark)) + @NewLine + LTRIM(RTRIM(ISNULL(@TVFMode, '')))
					END
			END

		SELECT @lv_TVFStations = dbo.TAMS_Get_TOA_TVF_Stations(@TOAID)

		IF @lv_Remarks = ''
			BEGIN
				SET @lv_Remarks = @lv_TVFStations
			END
		ELSE
			BEGIN
				SET @lv_Remarks = @lv_Remarks + @NewLine + @lv_TVFStations
			END

		IF @AccessType = 'Possession'
			BEGIN
				SET @lv_ColourCode = @RGSPossBG

				IF @TOAStatus = 6
					BEGIN
						IF @lv_PossessionCtr = 0
							BEGIN
								SET @lv_PossessionCtr = @lv_PossessionCtr
							END
						ELSE
							BEGIN
								SET @lv_PossessionCtr = @lv_PossessionCtr - 1
							END
					END
				ELSE
					BEGIN
						IF @ProtTimeLimit = '' OR @ProtTimeLimit = '00:00:00'
							BEGIN
								-- >> SET @lv_PossessionCtr = @lv_PossessionCtr + 1
								SET @lv_PossessionCtr = @lv_PossessionCtr
							END
						ELSE
							BEGIN
								IF @lv_PossessionCtr = 0
									BEGIN
										SET @lv_PossessionCtr = @lv_PossessionCtr
									END
								ELSE
									BEGIN
										SET @lv_PossessionCtr = @lv_PossessionCtr - 1
									END
							END
					END
				SET @lv_IsGrantTOAEnable = 1
			END
		ELSE
			BEGIN
				--SELECT @lv_PossessionCtr AS PossCtr
				-- 	EXEC sp_TAMS_RGS_OnLoad 'DTL'
				SET @lv_ColourCode = @RGSProtBG

				IF @TOAStatus = 6
					BEGIN
						SET @lv_IsGrantTOAEnable = 1
					END
				ELSE
					BEGIN
						IF @lv_PossessionCtr > 0
							BEGIN
								SET @lv_IsGrantTOAEnable = 0
							END
						ELSE
							BEGIN
								SET @lv_IsGrantTOAEnable = 1
							END
					END
			END
		
		INSERT INTO #TmpRGS
			(Sno, TARNo, ElectricalSections,
				PowerOffTime, CircuitBreakOutTime,
				PartiesName, NoOfPersons, 
				WorkDescription, ContactNo, TOANo,
				CallBackTime, 
				RadioMsgTime, LineClearMsgTime,
				Remarks, TOAStatus, IsTOAAuth, ColourCode, IsGrantTOAEnable, 
				UpdQTSTime, AccessType,
				AckGrantTOATime, AckProtLimitTime, 
				TARID, TOAID, InchargeNRIC)
		VALUES (@lv_Sno, @TARNo, @lv_ES, 
			@lv_PowerOffTime, @lv_CircuitBreakTime, 
			@lv_PartiesName, @NoOfParties, 
			@DescOfWork, @lv_ContactNo, @TOANo, 
			CASE WHEN @TOANo = '' THEN '' ELSE @TOACallBackTime END, 
			@GrantTOATime, @AckSurrenderTime, 
			@lv_Remarks, @TOAStatus, @lv_IsTOAAuth, @lv_ColourCode, @lv_IsGrantTOAEnable, 
			@UpdateQTSTime, @AccessType, 
			@AckGrantTOATime, @ProtTimeLimit, 
			@TARID, @TOAID, @InchargeNRIC)

		FETCH NEXT FROM @Cur01 INTO @TARID, @TOAID, @TARNo, @ARRemark, @TVFMode, @AccessType, @TOAStatus, 
			@ProtTimeLimit, 
			@NoOfParties,
			@DescOfWork, @MobileNo, @TetraRadioNo, @TOANo,
			@GrantTOATime, @AckSurrenderTime, @AckGrantTOATime, @UpdateQTSTime,
			@InchargeNRIC
	END 	

CLOSE @Cur01
	
DEALLOCATE @Cur01


-- >> RGS List
SELECT Sno, TARNo, ElectricalSections,
	PowerOffTime, CircuitBreakOutTime,
	PartiesName, NoOfPersons, 
	WorkDescription, ContactNo, TOANo,
	CallBackTime, RadioMsgTime, LineClearMsgTime,
	Remarks, TOAStatus, IsTOAAuth, ColourCode, IsGrantTOAEnable, 
	UpdQTSTime, AccessType,
	AckGrantTOATime, AckProtLimitTime, 
	TARID, TOAID,
	InchargeNRIC
FROM #TmpRGS
	ORDER BY Sno

---- >> Cancel List
--SELECT a.Id AS Val, a.TARNo AS Txt
--	FROM TAMS_TAR a, TAMS_TOA b
--		WHERE a.Id = b.TARId
--			AND b.TOAStatus NOT IN (0, 5, 6)
--			AND a.AccessDate = @AccessDate
--			AND a.Line = @Line
--	ORDER BY 1

--SELECT CONVERT(NVARCHAR(20), @OperationDate, 103) AS OperationDate,  
--	CONVERT(NVARCHAR(20), @AccessDate, 103) AS AccessDate

SELECT CONVERT(NVARCHAR(20), @OperationDate, 105) AS OperationDate,  
	CONVERT(NVARCHAR(20), @AccessDate, 105) AS AccessDate

DROP TABLE #TmpRGS
DROP TABLE #TmpRGSSectors

END

GO
/****** END PROCEDURE 300 ******/

/****** START PROCEDURE 301 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_RGS_OnLoad_Enq_20230202
CREATE PROCEDURE [dbo].[sp_TAMS_RGS_OnLoad_Enq_20230202]
	@Line	NVARCHAR(20) = NULL,
	@OPDate	NVARCHAR(20) = NULL
AS

BEGIN
	
/*
Notes :
OCCAuthStatusId 
DTL = 10
NEL = 7
*/

CREATE TABLE #TmpRGS 
(Sno				INT,
TARNo				NVARCHAR(30),
ElectricalSections	NVARCHAR(4000),
PowerOffTime		NVARCHAR(20),
CircuitBreakOutTime	NVARCHAR(20),
PartiesName			NVARCHAR(4000),
NoOfPersons			NVARCHAR(20),
WorkDescription		NVARCHAR(4000),
ContactNo			NVARCHAR(50),
TOANo				NVARCHAR(30),
CallBackTime		NVARCHAR(20),
RadioMsgTime		NVARCHAR(20),
LineClearMsgTime	NVARCHAR(20),
Remarks				NVARCHAR(4000),
TOAStatus			NVARCHAR(20),
IsTOAAuth			BIT,
ColourCode			NVARCHAR(20),
IsGrantTOAEnable	BIT,
UpdQTSTime			NVARCHAR(20),
AccessType			NVARCHAR(20),
AckGrantTOATime		NVARCHAR(20),
AckProtLimitTime	NVARCHAR(20),
TARID				INT,
TOAID				INT,
InchargeNRIC		NVARCHAR(100))

CREATE TABLE #TmpRGSSectors 
(OCCAuthID			INT,
OperationDate		DATE,
AccessDate			DATE,
OCCAuthStatus		NVARCHAR(50),
TractionPowerID		INT,
TractionPowerType	NVARCHAR(50),
SectorID			INT,
Sector				NVARCHAR(100),
WorkFlowTime		DATETIME)

TRUNCATE TABLE #TmpRGS
TRUNCATE TABLE #TmpRGSSectors

DECLARE @CurDate		DATE
DECLARE @CurTime		TIME
DECLARE @OperationDate	DATE
DECLARE @AccessDate		DATE

SET @CurDate = GETDATE()
SET @CurTime = CONVERT(TIME, GETDATE(), 108)

DECLARE @CutOff				TIME
DECLARE @TOACallBackTime	NVARCHAR(10)
DECLARE @RGSPossBG			NVARCHAR(20)
DECLARE @RGSProtBG			NVARCHAR(20)

--SET @TOACallBackTime = '04:00'
SET @CutOff = '06:00:00'

SELECT @TOACallBackTime = CAST(ParaTime AS NVARCHAR(5))
	FROM TAMS_Parameters
		WHERE ParaCode = 'TOACallbackTime'
			AND ParaValue1 = @Line

SELECT @RGSPossBG = ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'RGSPossessionBG'
			AND ParaValue1 = @Line

SELECT @RGSProtBG = ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'RGSProtectionBG'
			AND ParaValue1 = @Line

IF @CurTime > @CutOff
	BEGIN
		SET @OperationDate	= @CurDate
		SET @AccessDate		= DATEADD(DAY, 1, @CurDate)
	END
ELSE
	BEGIN
		SET @OperationDate	= DATEADD(DAY, -1, @CurDate)
		SET @AccessDate		= @CurDate
	END

SET @OperationDate = CONVERT(DATE, @OPDate, 103)
SET @AccessDate = DATEADD(DAY, 1, CONVERT(DATE, @OPDate, 103))

--SELECT @OperationDate, @AccessDate

DECLARE @Cur01 CURSOR;
DECLARE @Cur02 CURSOR;

DECLARE @TARID BIGINT,
@TOAID	BIGINT,
@ARRemark NVARCHAR(1000),
@TVFMode NVARCHAR(20),
@AccessType NVARCHAR(30),
@TOAStatus INT,
@ProtTimeLimit NVARCHAR(10),
@TARNo NVARCHAR(30),
@NoOfParties INT,
@DescOfWork NVARCHAR(1000),
@MobileNo NVARCHAR(20),
@TetraRadioNo NVARCHAR(50),
@TOANo NVARCHAR(50),
@GrantTOATime NVARCHAR(10),
@AckSurrenderTime NVARCHAR(10),
@AckGrantTOATime NVARCHAR(10),
@UpdateQTSTime NVARCHAR(10),
@InchargeNRIC NVARCHAR(100)

DECLARE @lv_Sno INT,
	@lv_IsTOAAuth BIT,
	@lv_PartiesName	NVARCHAR(4000),
	@lv_Remarks	NVARCHAR(4000),
	@lv_IsPowerOff BIT,
	@lv_PowerOffTime NVARCHAR(20),
	@lv_IsCircuitBreak BIT,
	@lv_CircuitBreakTime NVARCHAR(20),
	@lv_ColourCode NVARCHAR(20),
	@lv_ES NVARCHAR(100),
	@lv_SectorID INT,
	@lv_TVFStations NVARCHAR(1000),
	@lv_PossessionCtr INT,
	@lv_IsGrantTOAEnable BIT,
	@lv_ContactNo NVARCHAR(200)

DECLARE @SqlCtr1 INT,
	@SqlCtr2 INT,
	@SqlCtr3 INT,
	@WorkFlowTime NVARCHAR(20)

SET @lv_Sno = 0
SET @SqlCtr1 = 0
SET @SqlCtr2 = 0
SET @SqlCtr3 = 0
SET @lv_PossessionCtr = 0

SELECT @lv_PossessionCtr = COUNT(*)
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND a.AccessDate = @AccessDate
			AND b.TOAStatus NOT IN (0, 6)
			AND a.Line = @Line
			AND a.AccessType = 'Possession'

----DECLARE @NewLine AS CHAR(2) = CHAR(30) + CHAR(10)
DECLARE @NewLine AS NVARCHAR(6)
SET @NewLine = '<br />'
-- >> SELECT @NewUID = SCOPE_IDENTITY();

SET @Cur01 = CURSOR FAST_FORWARD 
FOR

SELECT a.Id, b.Id, a.TARNo, a.ARRemark, a.TVFMode, a.AccessType, b.TOAStatus, 
		-- >> ISNULL(CONVERT(NVARCHAR(20), b.AckProtectionLimitTime, 108), '00:00:00'), 
		ISNULL(CONVERT(NVARCHAR(5), b.AckProtectionLimitTime, 108), ''), 
		b.NoOfParties,
		a.DescOfWork, b.MobileNo, b.TetraRadioNo, ISNULL(b.TOANo, ''),
		ISNULL(CONVERT(NVARCHAR(5), b.GrantTOATime, 108), ''),
		ISNULL(CONVERT(NVARCHAR(5), b.AckSurrenderTime, 108), ''),
		ISNULL(CONVERT(NVARCHAR(8), b.AckGrantTOATime, 108), ''),
		ISNULL(CONVERT(NVARCHAR(5), b.UpdateQTSTime, 108), ''),
		dbo.DecryptString(b.InChargeNRIC)
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND a.AccessDate = @AccessDate
			AND b.TOAStatus <> 0
			AND a.Line = @Line
	-- >> ORDER BY a.AccessType, b.TOAType, a.Id
	ORDER BY a.AccessType, b.TOAStatus DESC, a.Id

OPEN @Cur01
	
FETCH NEXT FROM @Cur01 INTO @TARID, @TOAID, @TARNo, @ARRemark, @TVFMode, @AccessType, @TOAStatus, 
	@ProtTimeLimit, 
	@NoOfParties,
	@DescOfWork, @MobileNo, @TetraRadioNo, @TOANo,
	@GrantTOATime, @AckSurrenderTime, @AckGrantTOATime, @UpdateQTSTime,
	@InchargeNRIC
	
WHILE @@FETCH_STATUS = 0 
	
	BEGIN

		SET @lv_Sno = @lv_Sno + 1
		SET	@lv_IsTOAAuth = 1
		SET @lv_PartiesName	= ''
		SET @lv_Remarks	= ''
		SET @lv_IsPowerOff = 1
		SET @lv_PowerOffTime = ''
		SET @lv_IsCircuitBreak = 1
		SET @lv_CircuitBreakTime = ''
		SET @lv_ColourCode = ''
		SET @lv_ES = ''
		SET @lv_ContactNo = ''

		SELECT @lv_ES = dbo.TAMS_Get_ES(@TARID)
		SELECT @lv_PartiesName = dbo.TAMS_Get_TOA_Parties(@TOAID)
		SET @lv_ContactNo = @MobileNo + @NewLine + @TetraRadioNo

		-- >> Electrical Sector Cursor
		-- >> 	EXEC sp_TAMS_RGS_OnLoad_20210819_M 'NEL'

		IF @Line = 'DTL'
			BEGIN
				SET @Cur02 = CURSOR FAST_FORWARD 
				FOR

				SELECT a.SectorId
					FROM TAMS_TAR_Sector a, TAMS_Sector b
						WHERE a.SectorId = b.ID
							AND a.TARId = @TARID
							AND ISNULL(b.IsGap, 0) = 0
							AND a.IsBuffer = 0
					
				OPEN @Cur02
	
				FETCH NEXT FROM @Cur02 INTO @lv_SectorID
	
				WHILE @@FETCH_STATUS = 0 
	
					BEGIN

						SET @SqlCtr1 = 0

						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.Sector, NULL
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.SectorId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND c.IsGap = 0
									-- >> AND a.OCCAuthStatusId = 10
									AND ((a.OCCAuthStatusId = 10 and a.IsBuffer = 0) OR ((a.OCCAuthStatusId = 7 and a.IsBuffer = 1)))
									AND c.Line = @Line

						SELECT @SqlCtr1 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr1 = 0
							BEGIN
								SET @lv_IsTOAAuth = 0
							END

						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.Sector, a.PowerOffTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.SectorId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND c.IsGap = 0
									AND a.PowerOffTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr2 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr2 = 0
							BEGIN
								SET @lv_IsPowerOff = 0
								SET @lv_PowerOffTime = ''
							END
						ELSE
							BEGIN
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM  #TmpRGSSectors

								IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_PowerOffTime = ''
									END
								ELSE
									BEGIN
										SET @lv_PowerOffTime = @WorkFlowTime
									END
							END

						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.Sector, a.RackedOutTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.SectorId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND c.IsGap = 0
									AND a.RackedOutTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr3 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr3 = 0
							BEGIN
								SET @lv_IsCircuitBreak = 0
								SET @lv_CircuitBreakTime = ''
							END
						ELSE
							BEGIN
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM  #TmpRGSSectors

									IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_CircuitBreakTime = ''
									END
								ELSE
									BEGIN
										SET @lv_CircuitBreakTime = @WorkFlowTime
									END
							END
						

						FETCH NEXT FROM @Cur02 INTO @lv_SectorID
					END 	

				CLOSE @Cur02
	
				DEALLOCATE @Cur02
			END
		ELSE
			BEGIN
				SET @Cur02 = CURSOR FAST_FORWARD 
				FOR

				SELECT a.PowerSectorId 
					FROM TAMS_TAR_Power_Sector a
						WHERE a.TARId = @TARID
							AND a.IsBuffer = 0
							

				OPEN @Cur02
	
				FETCH NEXT FROM @Cur02 INTO @lv_SectorID
	
				WHILE @@FETCH_STATUS = 0 
	
					BEGIN

						SET @SqlCtr1 = 0

						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.PowerSection, NULL
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Power_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.PowerSectionId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND a.OCCAuthStatusId = 8
									AND c.Line = @Line

						SELECT @SqlCtr1 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr1 = 0
							BEGIN
								SET @lv_IsTOAAuth = 0
							END

						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.PowerSection, a.PowerOffTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Power_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.PowerSectionId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND a.PowerOffTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr2 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr2 = 0
							BEGIN
								SET @lv_IsPowerOff = 0
								SET @lv_PowerOffTime = ''
							END
						ELSE
							BEGIN
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM  #TmpRGSSectors

									IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_PowerOffTime = ''
									END
								ELSE
									BEGIN
										SET @lv_PowerOffTime = @WorkFlowTime
									END
							END

						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.PowerSection, a.RackedOutTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Power_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.PowerSectionId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND a.RackedOutTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr3 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr3 = 0
							BEGIN
								SET @lv_IsCircuitBreak = 0
								SET @lv_CircuitBreakTime = ''
							END
						ELSE
							BEGIN
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM #TmpRGSSectors

									IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_CircuitBreakTime = ''
									END
								ELSE
									BEGIN
										SET @lv_CircuitBreakTime = @WorkFlowTime
									END
							END

						FETCH NEXT FROM @Cur02 INTO @lv_SectorID
					END 	

				CLOSE @Cur02
	
				DEALLOCATE @Cur02
			END
		-- >>
		-- >> Electrical Sector Cursor

		IF @Line = 'DTL'
			BEGIN
				SET @lv_Remarks = LTRIM(RTRIM(@ARRemark)) + @NewLine + LTRIM(RTRIM(ISNULL(@TVFMode, '')))
			END
		ELSE
			BEGIN
				DECLARE @RackOutCtr	INT

				SELECT @RackOutCtr = COUNT(*) 
					FROM TAMS_TAR_AccessReq a, TAMS_Access_Requirement b
						WHERE a.IsPower = 1
							AND a.OperationRequirement = b.ID
							AND b.ID = 27	-- >> 27 FOR NEL
							AND a.IsSelected = 1
							AND a.TARId = @TARID

				IF @RackOutCtr > 0
					BEGIN
						SET @lv_Remarks = 'Rack Out' + @NewLine + @NewLine + LTRIM(RTRIM(@ARRemark)) + @NewLine + LTRIM(RTRIM(ISNULL(@TVFMode, '')))
					END
				ELSE
					BEGIN
						-- >> Don't show RackedOutTime for NEL if Power Requirement is with out Racked Out
						SET @lv_CircuitBreakTime = ''
						SET @lv_Remarks = LTRIM(RTRIM(@ARRemark)) + @NewLine + LTRIM(RTRIM(ISNULL(@TVFMode, '')))
					END
			END

		SELECT @lv_TVFStations = dbo.TAMS_Get_TOA_TVF_Stations(@TOAID)

		IF @lv_Remarks = ''
			BEGIN
				SET @lv_Remarks = @lv_TVFStations
			END
		ELSE
			BEGIN
				SET @lv_Remarks = @lv_Remarks + @NewLine + @lv_TVFStations
			END

		IF @AccessType = 'Possession'
			BEGIN
				SET @lv_ColourCode = @RGSPossBG

				IF @TOAStatus = 6
					BEGIN
						IF @lv_PossessionCtr = 0
							BEGIN
								SET @lv_PossessionCtr = @lv_PossessionCtr
							END
						ELSE
							BEGIN
								SET @lv_PossessionCtr = @lv_PossessionCtr - 1
							END
					END
				ELSE
					BEGIN
						IF @ProtTimeLimit = '' OR @ProtTimeLimit = '00:00:00'
							BEGIN
								SET @lv_PossessionCtr = @lv_PossessionCtr + 1
								-- >> SET @lv_PossessionCtr = @lv_PossessionCtr
							END
						ELSE
							BEGIN
								IF @lv_PossessionCtr = 0
									BEGIN
										SET @lv_PossessionCtr = @lv_PossessionCtr
									END
								ELSE
									BEGIN
										SET @lv_PossessionCtr = @lv_PossessionCtr - 1
									END
							END
					END
				SET @lv_IsGrantTOAEnable = 1
			END
		ELSE
			BEGIN
				--SELECT @lv_PossessionCtr AS PossCtr
				-- 	EXEC sp_TAMS_RGS_OnLoad 'DTL'
				SET @lv_ColourCode = @RGSProtBG

				IF @TOAStatus = 6
					BEGIN
						SET @lv_IsGrantTOAEnable = 1
					END
				ELSE
					BEGIN
						IF @lv_PossessionCtr > 0
							BEGIN
								SET @lv_IsGrantTOAEnable = 0
							END
						ELSE
							BEGIN
								SET @lv_IsGrantTOAEnable = 1
							END
					END
			END
		
		INSERT INTO #TmpRGS
			(Sno, TARNo, ElectricalSections,
				PowerOffTime, CircuitBreakOutTime,
				PartiesName, NoOfPersons, 
				WorkDescription, ContactNo, TOANo,
				CallBackTime, 
				RadioMsgTime, LineClearMsgTime,
				Remarks, TOAStatus, IsTOAAuth, ColourCode, IsGrantTOAEnable, 
				UpdQTSTime, AccessType,
				AckGrantTOATime, AckProtLimitTime, 
				TARID, TOAID, InchargeNRIC)
		VALUES (@lv_Sno, @TARNo, @lv_ES, 
			@lv_PowerOffTime, @lv_CircuitBreakTime, 
			@lv_PartiesName, @NoOfParties, 
			@DescOfWork, @lv_ContactNo, @TOANo, 
			CASE WHEN @TOANo = '' THEN '' ELSE @TOACallBackTime END, 
			@GrantTOATime, @AckSurrenderTime, 
			@lv_Remarks, @TOAStatus, @lv_IsTOAAuth, @lv_ColourCode, @lv_IsGrantTOAEnable, 
			@UpdateQTSTime, @AccessType, 
			@AckGrantTOATime, @ProtTimeLimit, 
			@TARID, @TOAID, @InchargeNRIC)

		FETCH NEXT FROM @Cur01 INTO @TARID, @TOAID, @TARNo, @ARRemark, @TVFMode, @AccessType, @TOAStatus, 
			@ProtTimeLimit, 
			@NoOfParties,
			@DescOfWork, @MobileNo, @TetraRadioNo, @TOANo,
			@GrantTOATime, @AckSurrenderTime, @AckGrantTOATime, @UpdateQTSTime,
			@InchargeNRIC
	END 	

CLOSE @Cur01
	
DEALLOCATE @Cur01


-- >> RGS List
SELECT Sno, TARNo, ElectricalSections,
	PowerOffTime, CircuitBreakOutTime,
	PartiesName, NoOfPersons, 
	WorkDescription, ContactNo, TOANo,
	CallBackTime, RadioMsgTime, LineClearMsgTime,
	Remarks, TOAStatus, IsTOAAuth, ColourCode, IsGrantTOAEnable, 
	UpdQTSTime, AccessType,
	AckGrantTOATime, AckProtLimitTime, 
	TARID, TOAID,
	InchargeNRIC
FROM #TmpRGS
	ORDER BY Sno

---- >> Cancel List
--SELECT a.Id AS Val, a.TARNo AS Txt
--	FROM TAMS_TAR a, TAMS_TOA b
--		WHERE a.Id = b.TARId
--			AND b.TOAStatus NOT IN (0, 5, 6)
--			AND a.AccessDate = @AccessDate
--			AND a.Line = @Line
--	ORDER BY 1

--SELECT CONVERT(NVARCHAR(20), @OperationDate, 103) AS OperationDate,  
--	CONVERT(NVARCHAR(20), @AccessDate, 103) AS AccessDate

SELECT CONVERT(NVARCHAR(20), @OperationDate, 105) AS OperationDate,  
	CONVERT(NVARCHAR(20), @AccessDate, 105) AS AccessDate

DROP TABLE #TmpRGS
DROP TABLE #TmpRGSSectors

END

GO
/****** END PROCEDURE 301 ******/

/****** START PROCEDURE 302 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_RGS_OnLoad_Enq_20230202_M
CREATE PROCEDURE [dbo].[sp_TAMS_RGS_OnLoad_Enq_20230202_M]
	@Line	NVARCHAR(20) = NULL,
	@OPDate	NVARCHAR(20) = NULL
AS

BEGIN
	
/*
Notes :
OCCAuthStatusId 
DTL = 10
NEL = 7
*/

CREATE TABLE #TmpRGS 
(Sno				INT,
TARNo				NVARCHAR(30),
ElectricalSections	NVARCHAR(4000),
PowerOffTime		NVARCHAR(20),
CircuitBreakOutTime	NVARCHAR(20),
PartiesName			NVARCHAR(4000),
NoOfPersons			NVARCHAR(20),
WorkDescription		NVARCHAR(4000),
ContactNo			NVARCHAR(50),
TOANo				NVARCHAR(30),
CallBackTime		NVARCHAR(20),
RadioMsgTime		NVARCHAR(20),
LineClearMsgTime	NVARCHAR(20),
Remarks				NVARCHAR(4000),
TOAStatus			NVARCHAR(20),
IsTOAAuth			BIT,
ColourCode			NVARCHAR(20),
IsGrantTOAEnable	BIT,
UpdQTSTime			NVARCHAR(20),
AccessType			NVARCHAR(20),
AckGrantTOATime		NVARCHAR(20),
AckProtLimitTime	NVARCHAR(20),
TARID				INT,
TOAID				INT,
InchargeNRIC		NVARCHAR(100))

CREATE TABLE #TmpRGSSectors 
(OCCAuthID			INT,
OperationDate		DATE,
AccessDate			DATE,
OCCAuthStatus		NVARCHAR(50),
TractionPowerID		INT,
TractionPowerType	NVARCHAR(50),
SectorID			INT,
Sector				NVARCHAR(100),
WorkFlowTime		DATETIME)

TRUNCATE TABLE #TmpRGS
TRUNCATE TABLE #TmpRGSSectors

DECLARE @CurDate		DATE
DECLARE @CurTime		TIME
DECLARE @OperationDate	DATE
DECLARE @AccessDate		DATE

SET @CurDate = GETDATE()
SET @CurTime = CONVERT(TIME, GETDATE(), 108)

DECLARE @CutOff				TIME
DECLARE @TOACallBackTime	NVARCHAR(10)
DECLARE @RGSPossBG			NVARCHAR(20)
DECLARE @RGSProtBG			NVARCHAR(20)
DECLARE @RGSCancBG			NVARCHAR(20)

--SET @TOACallBackTime = '04:00'
SET @CutOff = '06:00:00'

SELECT @TOACallBackTime = CAST(ParaTime AS NVARCHAR(5))
	FROM TAMS_Parameters
		WHERE ParaCode = 'TOACallbackTime'
			AND ParaValue1 = @Line

SELECT @RGSPossBG = ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'RGSPossessionBG'
			AND ParaValue1 = @Line

SELECT @RGSProtBG = ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'RGSProtectionBG'
			AND ParaValue1 = @Line

SELECT @RGSCancBG = ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'RGSCancelledBG'
			AND ParaValue1 = @Line

IF @CurTime > @CutOff
	BEGIN
		SET @OperationDate	= @CurDate
		SET @AccessDate		= DATEADD(DAY, 1, @CurDate)
	END
ELSE
	BEGIN
		SET @OperationDate	= DATEADD(DAY, -1, @CurDate)
		SET @AccessDate		= @CurDate
	END

SET @OperationDate = CONVERT(DATE, @OPDate, 103)
SET @AccessDate = DATEADD(DAY, 1, CONVERT(DATE, @OPDate, 103))

--SELECT @OperationDate, @AccessDate

DECLARE @Cur01 CURSOR;
DECLARE @Cur02 CURSOR;

DECLARE @TARID BIGINT,
@TOAID	BIGINT,
@ARRemark NVARCHAR(1000),
@TVFMode NVARCHAR(20),
@AccessType NVARCHAR(30),
@TOAStatus INT,
@ProtTimeLimit NVARCHAR(10),
@TARNo NVARCHAR(30),
@NoOfParties INT,
@DescOfWork NVARCHAR(1000),
@MobileNo NVARCHAR(20),
@TetraRadioNo NVARCHAR(50),
@TOANo NVARCHAR(50),
@GrantTOATime NVARCHAR(10),
@AckSurrenderTime NVARCHAR(10),
@AckGrantTOATime NVARCHAR(10),
@UpdateQTSTime NVARCHAR(10),
@InchargeNRIC NVARCHAR(100), 
@CancelRemark NVARCHAR(1000)

DECLARE @lv_Sno INT,
	@lv_IsTOAAuth BIT,
	@lv_PartiesName	NVARCHAR(4000),
	@lv_Remarks	NVARCHAR(4000),
	@lv_IsPowerOff BIT,
	@lv_PowerOffTime NVARCHAR(20),
	@lv_IsCircuitBreak BIT,
	@lv_CircuitBreakTime NVARCHAR(20),
	@lv_ColourCode NVARCHAR(20),
	@lv_ES NVARCHAR(100),
	@lv_SectorID INT,
	@lv_TVFStations NVARCHAR(1000),
	@lv_PossessionCtr INT,
	@lv_IsGrantTOAEnable BIT,
	@lv_ContactNo NVARCHAR(200)

DECLARE @SqlCtr1 INT,
	@SqlCtr2 INT,
	@SqlCtr3 INT,
	@WorkFlowTime NVARCHAR(20)

SET @lv_Sno = 0
SET @SqlCtr1 = 0
SET @SqlCtr2 = 0
SET @SqlCtr3 = 0
SET @lv_PossessionCtr = 0

SELECT @lv_PossessionCtr = COUNT(*)
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND a.AccessDate = @AccessDate
			AND b.TOAStatus NOT IN (0, 6)
			AND a.Line = @Line
			AND a.AccessType = 'Possession'

DECLARE @NewLine AS NVARCHAR(6)
SET @NewLine = '<br />'

SET @Cur01 = CURSOR FAST_FORWARD 
FOR

SELECT a.Id, b.Id, a.TARNo, a.ARRemark, a.TVFMode, a.AccessType, b.TOAStatus, 
		-- >> ISNULL(CONVERT(NVARCHAR(20), b.AckProtectionLimitTime, 108), '00:00:00'), 
		ISNULL(CONVERT(NVARCHAR(5), b.AckProtectionLimitTime, 108), ''), 
		b.NoOfParties,
		a.DescOfWork, b.MobileNo, b.TetraRadioNo, ISNULL(b.TOANo, ''),
		ISNULL(CONVERT(NVARCHAR(5), b.GrantTOATime, 108), ''),
		ISNULL(CONVERT(NVARCHAR(5), b.AckSurrenderTime, 108), ''),
		ISNULL(CONVERT(NVARCHAR(8), b.AckGrantTOATime, 108), ''),
		ISNULL(CONVERT(NVARCHAR(5), b.UpdateQTSTime, 108), ''),
		dbo.DecryptString(b.InChargeNRIC),
		b.CancelRemark
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND a.AccessDate = @AccessDate
			AND b.TOAStatus <> 0
			AND a.Line = @Line
	-- >> ORDER BY a.AccessType, b.TOAType, a.Id
	ORDER BY a.AccessType, b.TOAStatus DESC, a.Id

OPEN @Cur01
	
FETCH NEXT FROM @Cur01 INTO @TARID, @TOAID, @TARNo, @ARRemark, @TVFMode, @AccessType, @TOAStatus, 
	@ProtTimeLimit, 
	@NoOfParties,
	@DescOfWork, @MobileNo, @TetraRadioNo, @TOANo,
	@GrantTOATime, @AckSurrenderTime, @AckGrantTOATime, @UpdateQTSTime,
	@InchargeNRIC, @CancelRemark
	
WHILE @@FETCH_STATUS = 0 
	
	BEGIN

		SET @lv_Sno = @lv_Sno + 1
		SET	@lv_IsTOAAuth = 1
		SET @lv_PartiesName	= ''
		SET @lv_Remarks	= ''
		SET @lv_IsPowerOff = 1
		SET @lv_PowerOffTime = ''
		SET @lv_IsCircuitBreak = 1
		SET @lv_CircuitBreakTime = ''
		SET @lv_ColourCode = ''
		SET @lv_ES = ''
		SET @lv_ContactNo = ''

		SELECT @lv_ES = dbo.TAMS_Get_ES(@TARID)
		SELECT @lv_PartiesName = dbo.TAMS_Get_TOA_Parties(@TOAID)
		SET @lv_ContactNo = @MobileNo + @NewLine + @TetraRadioNo

		-- >> Electrical Sector Cursor
		-- >> 	EXEC sp_TAMS_RGS_OnLoad_20210819_M 'NEL'

		IF @Line = 'DTL'
			BEGIN
				SET @Cur02 = CURSOR FAST_FORWARD 
				FOR

				SELECT a.SectorId
					FROM TAMS_TAR_Sector a, TAMS_Sector b
						WHERE a.SectorId = b.ID
							AND a.TARId = @TARID
							AND ISNULL(b.IsGap, 0) = 0
							AND a.IsBuffer = 0
					
				OPEN @Cur02
	
				FETCH NEXT FROM @Cur02 INTO @lv_SectorID
	
				WHILE @@FETCH_STATUS = 0 
	
					BEGIN

						SET @SqlCtr1 = 0

						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.Sector, NULL
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.SectorId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND c.IsGap = 0
									-- >> AND a.OCCAuthStatusId = 10
									AND ((a.OCCAuthStatusId = 10 and a.IsBuffer = 0) OR ((a.OCCAuthStatusId = 7 and a.IsBuffer = 1)))
									AND c.Line = @Line

						SELECT @SqlCtr1 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr1 = 0
							BEGIN
								SET @lv_IsTOAAuth = 0
							END

						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.Sector, a.PowerOffTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.SectorId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND c.IsGap = 0
									AND a.PowerOffTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr2 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr2 = 0
							BEGIN
								SET @lv_IsPowerOff = 0
								SET @lv_PowerOffTime = ''
							END
						ELSE
							BEGIN
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM  #TmpRGSSectors

								IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_PowerOffTime = ''
									END
								ELSE
									BEGIN
										SET @lv_PowerOffTime = @WorkFlowTime
									END
							END

						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.Sector, a.RackedOutTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.SectorId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND c.IsGap = 0
									AND a.RackedOutTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr3 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr3 = 0
							BEGIN
								SET @lv_IsCircuitBreak = 0
								SET @lv_CircuitBreakTime = ''
							END
						ELSE
							BEGIN
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM  #TmpRGSSectors

									IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_CircuitBreakTime = ''
									END
								ELSE
									BEGIN
										SET @lv_CircuitBreakTime = @WorkFlowTime
									END
							END
						

						FETCH NEXT FROM @Cur02 INTO @lv_SectorID
					END 	

				CLOSE @Cur02
	
				DEALLOCATE @Cur02
			END
		ELSE
			BEGIN
				SET @Cur02 = CURSOR FAST_FORWARD 
				FOR

				SELECT a.PowerSectorId 
					FROM TAMS_TAR_Power_Sector a
						WHERE a.TARId = @TARID
							AND a.IsBuffer = 0
							

				OPEN @Cur02
	
				FETCH NEXT FROM @Cur02 INTO @lv_SectorID
	
				WHILE @@FETCH_STATUS = 0 
	
					BEGIN

						SET @SqlCtr1 = 0

						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.PowerSection, NULL
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Power_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.PowerSectionId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND a.OCCAuthStatusId = 8
									AND c.Line = @Line

						SELECT @SqlCtr1 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr1 = 0
							BEGIN
								SET @lv_IsTOAAuth = 0
							END

						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.PowerSection, a.PowerOffTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Power_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.PowerSectionId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND a.PowerOffTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr2 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr2 = 0
							BEGIN
								SET @lv_IsPowerOff = 0
								SET @lv_PowerOffTime = ''
							END
						ELSE
							BEGIN
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM  #TmpRGSSectors

									IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_PowerOffTime = ''
									END
								ELSE
									BEGIN
										SET @lv_PowerOffTime = @WorkFlowTime
									END
							END

						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.PowerSection, a.RackedOutTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Power_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.PowerSectionId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND a.RackedOutTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr3 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr3 = 0
							BEGIN
								SET @lv_IsCircuitBreak = 0
								SET @lv_CircuitBreakTime = ''
							END
						ELSE
							BEGIN
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM #TmpRGSSectors

									IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_CircuitBreakTime = ''
									END
								ELSE
									BEGIN
										SET @lv_CircuitBreakTime = @WorkFlowTime
									END
							END

						FETCH NEXT FROM @Cur02 INTO @lv_SectorID
					END 	

				CLOSE @Cur02
	
				DEALLOCATE @Cur02
			END
		-- >>
		-- >> Electrical Sector Cursor

		IF @Line = 'DTL'
			BEGIN
				SET @lv_Remarks = LTRIM(RTRIM(@ARRemark)) + @NewLine + LTRIM(RTRIM(ISNULL(@TVFMode, '')))
			END
		ELSE
			BEGIN
				DECLARE @RackOutCtr	INT

				SELECT @RackOutCtr = COUNT(*) 
					FROM TAMS_TAR_AccessReq a, TAMS_Access_Requirement b
						WHERE a.IsPower = 1
							AND a.OperationRequirement = b.ID
							AND b.ID = 27	-- >> 27 FOR NEL
							AND a.IsSelected = 1
							AND a.TARId = @TARID

				IF @RackOutCtr > 0
					BEGIN
						SET @lv_Remarks = 'Rack Out' + @NewLine + @NewLine + LTRIM(RTRIM(@ARRemark)) + @NewLine + LTRIM(RTRIM(ISNULL(@TVFMode, '')))
					END
				ELSE
					BEGIN
						-- >> Don't show RackedOutTime for NEL if Power Requirement is with out Racked Out
						SET @lv_CircuitBreakTime = ''
						SET @lv_Remarks = LTRIM(RTRIM(@ARRemark)) + @NewLine + LTRIM(RTRIM(ISNULL(@TVFMode, '')))
					END
			END

		SELECT @lv_TVFStations = dbo.TAMS_Get_TOA_TVF_Stations(@TOAID)

		IF @lv_Remarks = ''
			BEGIN
				SET @lv_Remarks = @lv_TVFStations
			END
		ELSE
			BEGIN
				SET @lv_Remarks = @lv_Remarks + @NewLine + @lv_TVFStations
			END

		IF @AccessType = 'Possession'
			BEGIN
				SET @lv_ColourCode = @RGSPossBG

				IF @TOAStatus = 6
					BEGIN
						IF @lv_PossessionCtr = 0
							BEGIN
								SET @lv_PossessionCtr = @lv_PossessionCtr
							END
						ELSE
							BEGIN
								SET @lv_PossessionCtr = @lv_PossessionCtr - 1
							END
					END
				ELSE
					BEGIN
						IF @ProtTimeLimit = '' OR @ProtTimeLimit = '00:00:00'
							BEGIN
								SET @lv_PossessionCtr = @lv_PossessionCtr + 1
								-- >> SET @lv_PossessionCtr = @lv_PossessionCtr
							END
						ELSE
							BEGIN
								IF @lv_PossessionCtr = 0
									BEGIN
										SET @lv_PossessionCtr = @lv_PossessionCtr
									END
								ELSE
									BEGIN
										SET @lv_PossessionCtr = @lv_PossessionCtr - 1
									END
							END
					END
				SET @lv_IsGrantTOAEnable = 1
			END
		ELSE
			BEGIN
				--SELECT @lv_PossessionCtr AS PossCtr
				-- 	EXEC sp_TAMS_RGS_OnLoad 'DTL'
				SET @lv_ColourCode = @RGSProtBG

				IF @TOAStatus = 6
					BEGIN
						SET @lv_IsGrantTOAEnable = 1
					END
				ELSE
					BEGIN
						IF @lv_PossessionCtr > 0
							BEGIN
								SET @lv_IsGrantTOAEnable = 0
							END
						ELSE
							BEGIN
								SET @lv_IsGrantTOAEnable = 1
							END
					END
			END
		
		-- >> 2023 change highlight for cancelled records
		-- >> Include Cancel remarks after new line
		IF @TOAStatus = 6
			BEGIN
				SET @lv_ColourCode = @RGSCancBG
				SET @lv_Remarks = @lv_Remarks + @NewLine + @NewLine + 'Cancel Remark:' + LTRIM(RTRIM(@CancelRemark))
			END

		INSERT INTO #TmpRGS
			(Sno, TARNo, ElectricalSections,
				PowerOffTime, CircuitBreakOutTime,
				PartiesName, NoOfPersons, 
				WorkDescription, ContactNo, TOANo,
				CallBackTime, 
				RadioMsgTime, LineClearMsgTime,
				Remarks, TOAStatus, IsTOAAuth, ColourCode, IsGrantTOAEnable, 
				UpdQTSTime, AccessType,
				AckGrantTOATime, AckProtLimitTime, 
				TARID, TOAID, InchargeNRIC)
		VALUES (@lv_Sno, @TARNo, @lv_ES, 
			@lv_PowerOffTime, @lv_CircuitBreakTime, 
			@lv_PartiesName, @NoOfParties, 
			@DescOfWork, @lv_ContactNo, @TOANo, 
			CASE WHEN @TOANo = '' THEN '' ELSE @TOACallBackTime END, 
			@GrantTOATime, @AckSurrenderTime, 
			@lv_Remarks, @TOAStatus, @lv_IsTOAAuth, @lv_ColourCode, @lv_IsGrantTOAEnable, 
			@UpdateQTSTime, @AccessType, 
			@AckGrantTOATime, @ProtTimeLimit, 
			@TARID, @TOAID, @InchargeNRIC)

		FETCH NEXT FROM @Cur01 INTO @TARID, @TOAID, @TARNo, @ARRemark, @TVFMode, @AccessType, @TOAStatus, 
			@ProtTimeLimit, 
			@NoOfParties,
			@DescOfWork, @MobileNo, @TetraRadioNo, @TOANo,
			@GrantTOATime, @AckSurrenderTime, @AckGrantTOATime, @UpdateQTSTime,
			@InchargeNRIC, @CancelRemark
	END 	

CLOSE @Cur01
	
DEALLOCATE @Cur01


-- >> RGS List
SELECT Sno, TARNo, ElectricalSections,
	PowerOffTime, CircuitBreakOutTime,
	PartiesName, NoOfPersons, 
	WorkDescription, ContactNo, TOANo,
	CallBackTime, RadioMsgTime, LineClearMsgTime,
	Remarks, TOAStatus, IsTOAAuth, ColourCode, IsGrantTOAEnable, 
	UpdQTSTime, AccessType,
	AckGrantTOATime, AckProtLimitTime, 
	TARID, TOAID,
	InchargeNRIC
FROM #TmpRGS
	ORDER BY Sno

---- >> Cancel List
--SELECT a.Id AS Val, a.TARNo AS Txt
--	FROM TAMS_TAR a, TAMS_TOA b
--		WHERE a.Id = b.TARId
--			AND b.TOAStatus NOT IN (0, 5, 6)
--			AND a.AccessDate = @AccessDate
--			AND a.Line = @Line
--	ORDER BY 1

--SELECT CONVERT(NVARCHAR(20), @OperationDate, 103) AS OperationDate,  
--	CONVERT(NVARCHAR(20), @AccessDate, 103) AS AccessDate

SELECT CONVERT(NVARCHAR(20), @OperationDate, 105) AS OperationDate,  
	CONVERT(NVARCHAR(20), @AccessDate, 105) AS AccessDate

DROP TABLE #TmpRGS
DROP TABLE #TmpRGSSectors

END

GO
/****** END PROCEDURE 302 ******/

/****** START PROCEDURE 303 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_RGS_OnLoad_M
CREATE PROCEDURE [dbo].[sp_TAMS_RGS_OnLoad_M]
	@Line		NVARCHAR(20) = NULL
AS

BEGIN
	
/*
Notes :
OCCAuthStatusId 
DTL = 10
NEL = 7
*/

CREATE TABLE #TmpRGS 
(Sno				INT,
TARNo				NVARCHAR(30),
ElectricalSections	NVARCHAR(4000),
PowerOffTime		NVARCHAR(20),
CircuitBreakOutTime	NVARCHAR(20),
PartiesName			NVARCHAR(4000),
NoOfPersons			NVARCHAR(20),
WorkDescription		NVARCHAR(4000),
ContactNo			NVARCHAR(50),
TOANo				NVARCHAR(30),
CallBackTime		NVARCHAR(20),
RadioMsgTime		NVARCHAR(20),
LineClearMsgTime	NVARCHAR(20),
Remarks				NVARCHAR(4000),
TOAStatus			NVARCHAR(20),
IsTOAAuth			BIT,
ColourCode			NVARCHAR(20),
IsGrantTOAEnable	BIT,
UpdQTSTime			NVARCHAR(20),
AccessType			NVARCHAR(20),
AckGrantTOATime		NVARCHAR(20),
AckProtLimitTime	NVARCHAR(20),
TARID				INT,
TOAID				INT,
InchargeNRIC		NVARCHAR(100))

CREATE TABLE #TmpRGSSectors 
(OCCAuthID			INT,
OperationDate		DATE,
AccessDate			DATE,
OCCAuthStatus		NVARCHAR(50),
TractionPowerID		INT,
TractionPowerType	NVARCHAR(50),
SectorID			INT,
Sector				NVARCHAR(100),
WorkFlowTime		DATETIME)

TRUNCATE TABLE #TmpRGS
TRUNCATE TABLE #TmpRGSSectors

DECLARE @CurDate		DATE
DECLARE @CurTime		TIME
DECLARE @OperationDate	DATE
DECLARE @AccessDate		DATE

SET @CurDate = GETDATE()
SET @CurTime = CONVERT(TIME, GETDATE(), 108)

DECLARE @CutOff				TIME
DECLARE @TOACallBackTime	NVARCHAR(10)
DECLARE @RGSPossBG			NVARCHAR(20)
DECLARE @RGSProtBG			NVARCHAR(20)

SET @TOACallBackTime = '04:00'
SET @CutOff = '06:00:00'

SELECT @RGSPossBG = ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'RGSPossessionBG'
			AND ParaValue1 = @Line

SELECT @RGSProtBG = ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'RGSProtectionBG'
			AND ParaValue1 = @Line

IF @CurTime > @CutOff
	BEGIN
		SET @OperationDate	= @CurDate
		SET @AccessDate		= DATEADD(DAY, 1, @CurDate)
	END
ELSE
	BEGIN
		SET @OperationDate	= DATEADD(DAY, -1, @CurDate)
		SET @AccessDate		= @CurDate
	END

--SET @OperationDate = '2022-08-23'
--SET @AccessDate = '2022-08-24'
--SELECT @OperationDate, @AccessDate


DECLARE @Cur01 CURSOR;
DECLARE @Cur02 CURSOR;

DECLARE @TARID BIGINT,
@TOAID	BIGINT,
@ARRemark NVARCHAR(1000),
@TVFMode NVARCHAR(20),
@AccessType NVARCHAR(30),
@TOAStatus INT,
@ProtTimeLimit NVARCHAR(10),
@TARNo NVARCHAR(30),
@NoOfParties INT,
@DescOfWork NVARCHAR(1000),
@MobileNo NVARCHAR(20),
@TetraRadioNo NVARCHAR(50),
@TOANo NVARCHAR(50),
@GrantTOATime NVARCHAR(10),
@AckSurrenderTime NVARCHAR(10),
@AckGrantTOATime NVARCHAR(10),
@UpdateQTSTime NVARCHAR(10),
@InchargeNRIC NVARCHAR(100)

DECLARE @lv_Sno INT,
	@lv_IsTOAAuth BIT,
	@lv_PartiesName	NVARCHAR(4000),
	@lv_Remarks	NVARCHAR(4000),
	@lv_IsPowerOff BIT,
	@lv_PowerOffTime NVARCHAR(20),
	@lv_IsCircuitBreak BIT,
	@lv_CircuitBreakTime NVARCHAR(20),
	@lv_ColourCode NVARCHAR(20),
	@lv_ES NVARCHAR(100),
	@lv_SectorID INT,
	@lv_TVFStations NVARCHAR(1000),
	@lv_PossessionCtr INT,
	@lv_IsGrantTOAEnable BIT,
	@lv_ContactNo NVARCHAR(200)

DECLARE @SqlCtr1 INT,
	@SqlCtr2 INT,
	@SqlCtr3 INT,
	@WorkFlowTime NVARCHAR(20)

SET @lv_Sno = 0
SET @SqlCtr1 = 0
SET @SqlCtr2 = 0
SET @SqlCtr3 = 0
SET @lv_PossessionCtr = 0

SELECT @lv_PossessionCtr = COUNT(*)
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND a.AccessDate = @AccessDate
			AND b.TOAStatus NOT IN (0, 6)
			AND a.Line = @Line
			AND a.AccessType = 'Possession'

----DECLARE @NewLine AS CHAR(2) = CHAR(30) + CHAR(10)
DECLARE @NewLine AS NVARCHAR(6)
SET @NewLine = '<br />'
-- >> SELECT @NewUID = SCOPE_IDENTITY();

SET @Cur01 = CURSOR FAST_FORWARD 
FOR

SELECT a.Id, b.Id, a.TARNo, a.ARRemark, a.TVFMode, a.AccessType, b.TOAStatus, 
		-- >> ISNULL(CONVERT(NVARCHAR(20), b.AckProtectionLimitTime, 108), '00:00:00'), 
		ISNULL(CONVERT(NVARCHAR(5), b.AckProtectionLimitTime, 108), ''), 
		b.NoOfParties,
		a.DescOfWork, b.MobileNo, b.TetraRadioNo, ISNULL(b.TOANo, ''),
		ISNULL(CONVERT(NVARCHAR(5), b.GrantTOATime, 108), ''),
		ISNULL(CONVERT(NVARCHAR(5), b.AckSurrenderTime, 108), ''),
		ISNULL(CONVERT(NVARCHAR(8), b.AckGrantTOATime, 108), ''),
		ISNULL(CONVERT(NVARCHAR(5), b.UpdateQTSTime, 108), ''),
		dbo.DecryptString(b.InChargeNRIC)
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND a.AccessDate = @AccessDate
			AND b.TOAStatus <> 0
			AND a.Line = @Line
	-- >> ORDER BY a.AccessType, b.TOAType, a.Id
	ORDER BY a.AccessType, b.TOAStatus DESC, a.Id
	-- >> EXEC sp_TAMS_RGS_OnLoad 'NEL'
OPEN @Cur01
	
FETCH NEXT FROM @Cur01 INTO @TARID, @TOAID, @TARNo, @ARRemark, @TVFMode, @AccessType, @TOAStatus, 
	@ProtTimeLimit, 
	@NoOfParties,
	@DescOfWork, @MobileNo, @TetraRadioNo, @TOANo,
	@GrantTOATime, @AckSurrenderTime, @AckGrantTOATime, @UpdateQTSTime,
	@InchargeNRIC
	
WHILE @@FETCH_STATUS = 0 
	
	BEGIN

		SET @lv_Sno = @lv_Sno + 1
		SET	@lv_IsTOAAuth = 1
		SET @lv_PartiesName	= ''
		SET @lv_Remarks	= ''
		SET @lv_IsPowerOff = 1
		SET @lv_PowerOffTime = ''
		SET @lv_IsCircuitBreak = 1
		SET @lv_CircuitBreakTime = ''
		SET @lv_ColourCode = ''
		SET @lv_ES = ''
		SET @lv_ContactNo = ''

		SELECT @lv_ES = dbo.TAMS_Get_ES_NoBufferZone(@TARID)
		SELECT @lv_PartiesName = dbo.TAMS_Get_TOA_Parties(@TOAID)
		SET @lv_ContactNo = @MobileNo + @NewLine + @TetraRadioNo

		-- >> Electrical Sector Cursor
		-- >> 	EXEC sp_TAMS_RGS_OnLoad_20210819_M 'NEL'

		IF @Line = 'DTL'
			BEGIN
				SET @Cur02 = CURSOR FAST_FORWARD 
				FOR

				SELECT a.SectorId
					FROM TAMS_TAR_Sector a, TAMS_Sector b
						WHERE a.SectorId = b.ID
							AND a.TARId = @TARID
							AND ISNULL(b.IsGap, 0) = 0
							AND a.IsBuffer = 0
					
				OPEN @Cur02
	
				FETCH NEXT FROM @Cur02 INTO @lv_SectorID
	
				WHILE @@FETCH_STATUS = 0 
	
					BEGIN

						SET @SqlCtr1 = 0

						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.Sector, NULL
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.SectorId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND c.IsGap = 0
									-- >> AND a.OCCAuthStatusId = 10
									AND ((a.OCCAuthStatusId = 10 and a.IsBuffer = 0) OR ((a.OCCAuthStatusId = 7 and a.IsBuffer = 1)))
									AND c.Line = @Line

						SELECT @SqlCtr1 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr1 = 0
							BEGIN
								SET @lv_IsTOAAuth = 0
							END

						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.Sector, a.PowerOffTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.SectorId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND c.IsGap = 0
									AND a.PowerOffTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr2 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr2 = 0
							BEGIN
								SET @lv_IsPowerOff = 0
								SET @lv_PowerOffTime = ''
							END
						ELSE
							BEGIN
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM  #TmpRGSSectors

								IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_PowerOffTime = ''
									END
								ELSE
									BEGIN
										SET @lv_PowerOffTime = @WorkFlowTime
									END
							END

						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.Sector, a.RackedOutTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.SectorId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND c.IsGap = 0
									AND a.RackedOutTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr3 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr3 = 0
							BEGIN
								SET @lv_IsCircuitBreak = 0
								SET @lv_CircuitBreakTime = ''
							END
						ELSE
							BEGIN
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM  #TmpRGSSectors

									IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_CircuitBreakTime = ''
									END
								ELSE
									BEGIN
										SET @lv_CircuitBreakTime = @WorkFlowTime
									END
							END
						

						FETCH NEXT FROM @Cur02 INTO @lv_SectorID
					END 	

				CLOSE @Cur02
	
				DEALLOCATE @Cur02
			END
		ELSE
			BEGIN
				SET @Cur02 = CURSOR FAST_FORWARD 
				FOR

				SELECT a.PowerSectorId 
					FROM TAMS_TAR_Power_Sector a
						WHERE a.TARId = @TARID
							AND a.IsBuffer = 0
							

				OPEN @Cur02
	
				FETCH NEXT FROM @Cur02 INTO @lv_SectorID
	
				WHILE @@FETCH_STATUS = 0 
	
					BEGIN

						SET @SqlCtr1 = 0

						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.PowerSection, NULL
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Power_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.PowerSectionId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND a.OCCAuthStatusId = 8
									AND c.Line = @Line

						SELECT @SqlCtr1 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr1 = 0
							BEGIN
								SET @lv_IsTOAAuth = 0
							END

						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.PowerSection, a.PowerOffTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Power_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.PowerSectionId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND a.PowerOffTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr2 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr2 = 0
							BEGIN
								SET @lv_IsPowerOff = 0
								SET @lv_PowerOffTime = ''
							END
						ELSE
							BEGIN
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM  #TmpRGSSectors

									IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_PowerOffTime = ''
									END
								ELSE
									BEGIN
										SET @lv_PowerOffTime = @WorkFlowTime
									END
							END

						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.PowerSection, a.RackedOutTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Power_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.PowerSectionId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND a.RackedOutTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr3 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr3 = 0
							BEGIN
								SET @lv_IsCircuitBreak = 0
								SET @lv_CircuitBreakTime = ''
							END
						ELSE
							BEGIN
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM #TmpRGSSectors

									IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_CircuitBreakTime = ''
									END
								ELSE
									BEGIN
										SET @lv_CircuitBreakTime = @WorkFlowTime
									END
							END

						FETCH NEXT FROM @Cur02 INTO @lv_SectorID
					END 	

				CLOSE @Cur02
	
				DEALLOCATE @Cur02
			END
		-- >>
		-- >> Electrical Sector Cursor

		IF @Line = 'DTL'
			BEGIN
				SET @lv_Remarks = LTRIM(RTRIM(@ARRemark)) + @NewLine + LTRIM(RTRIM(ISNULL(@TVFMode, '')))
			END
		ELSE
			BEGIN
				DECLARE @RackOutCtr	INT

				SELECT @RackOutCtr = COUNT(*) 
					FROM TAMS_TAR_AccessReq a, TAMS_Access_Requirement b
						WHERE a.IsPower = 1
							AND a.OperationRequirement = b.ID
							AND b.ID = 27	-- >> 27 FOR NEL
							AND a.IsSelected = 1
							AND a.TARId = @TARID

				IF @RackOutCtr > 0
					BEGIN
						SET @lv_Remarks = 'Rack Out' + @NewLine + @NewLine + LTRIM(RTRIM(@ARRemark)) + @NewLine + LTRIM(RTRIM(ISNULL(@TVFMode, '')))
					END
				ELSE
					BEGIN
						SET @lv_Remarks = LTRIM(RTRIM(@ARRemark)) + @NewLine + LTRIM(RTRIM(ISNULL(@TVFMode, '')))
					END
			END

		DECLARE @SCDCtr	INT

		SELECT @SCDCtr = COUNT(*) 
			FROM TAMS_TAR_AccessReq a, TAMS_Access_Requirement b
				WHERE a.IsPower = 1
					AND a.OperationRequirement = b.ID
					AND b.OperationRequirement = 'SCD Application'
					AND a.IsSelected = 1
					AND a.TARId = @TARID

		IF @SCDCtr > 0
			BEGIN
				SET @lv_Remarks = 'SCD' + @NewLine + @NewLine + LTRIM(RTRIM(@lv_Remarks))
			END
			
		SELECT @lv_TVFStations = dbo.TAMS_Get_TOA_TVF_Stations(@TOAID)

		IF @lv_Remarks = ''
			BEGIN
				SET @lv_Remarks = @lv_TVFStations
			END
		ELSE
			BEGIN
				SET @lv_Remarks = @lv_Remarks + @NewLine + @lv_TVFStations
			END

		IF @AccessType = 'Possession'
			BEGIN
				SET @lv_ColourCode = @RGSPossBG

				IF @TOAStatus = 6
					BEGIN
						IF @lv_PossessionCtr = 0
							BEGIN
								SET @lv_PossessionCtr = @lv_PossessionCtr
							END
						ELSE
							BEGIN
								SET @lv_PossessionCtr = @lv_PossessionCtr - 1
							END
					END
				ELSE
					BEGIN
						IF @ProtTimeLimit = '' OR @ProtTimeLimit = '00:00:00'
							BEGIN
								-- >> SELECT '1'
								SET @lv_PossessionCtr = @lv_PossessionCtr + 1
								-- >> SET @lv_PossessionCtr = @lv_PossessionCtr
							END
						ELSE
							BEGIN
								-- >> SELECT '2'
								IF @lv_PossessionCtr = 0
									BEGIN
										-- >> SELECT '3'
										SET @lv_PossessionCtr = @lv_PossessionCtr
									END
								ELSE
									BEGIN
										-- >> SELECT '4'
										SET @lv_PossessionCtr = @lv_PossessionCtr - 1
									END
							END
					END

				SET @lv_IsGrantTOAEnable = 1

			END
		ELSE
			BEGIN
				-- >> SELECT @lv_PossessionCtr AS PossCtr
				-- 	EXEC sp_TAMS_RGS_OnLoad 'DTL'
				SET @lv_ColourCode = @RGSProtBG

				IF @TOAStatus = 6
					BEGIN
						SET @lv_IsGrantTOAEnable = 1
					END
				ELSE
					BEGIN
						IF @lv_PossessionCtr > 0
							BEGIN
								SET @lv_IsGrantTOAEnable = 0
							END
						ELSE
							BEGIN
								SET @lv_IsGrantTOAEnable = 1
							END
					END
			END

		IF @TOANo = ''
			BEGIN
				SET @TOACallBackTime = ''
			END
		ELSE
			BEGIN
				SET @TOACallBackTime = '04:00'
			END
		
		INSERT INTO #TmpRGS
			(Sno, TARNo, ElectricalSections,
				PowerOffTime, CircuitBreakOutTime,
				PartiesName, NoOfPersons, 
				WorkDescription, ContactNo, TOANo,
				CallBackTime, RadioMsgTime, LineClearMsgTime,
				Remarks, TOAStatus, IsTOAAuth, ColourCode, IsGrantTOAEnable, 
				UpdQTSTime, AccessType,
				AckGrantTOATime, AckProtLimitTime, 
				TARID, TOAID, InchargeNRIC)
		VALUES (@lv_Sno, @TARNo, @lv_ES, 
			@lv_PowerOffTime, @lv_CircuitBreakTime, 
			@lv_PartiesName, @NoOfParties, 
			@DescOfWork, @lv_ContactNo, @TOANo, 
			@TOACallBackTime, @GrantTOATime, @AckSurrenderTime, 
			@lv_Remarks, @TOAStatus, @lv_IsTOAAuth, @lv_ColourCode, @lv_IsGrantTOAEnable, 
			@UpdateQTSTime, @AccessType, 
			@AckGrantTOATime, @ProtTimeLimit, 
			@TARID, @TOAID, @InchargeNRIC)

		FETCH NEXT FROM @Cur01 INTO @TARID, @TOAID, @TARNo, @ARRemark, @TVFMode, @AccessType, @TOAStatus, 
			@ProtTimeLimit, 
			@NoOfParties,
			@DescOfWork, @MobileNo, @TetraRadioNo, @TOANo,
			@GrantTOATime, @AckSurrenderTime, @AckGrantTOATime, @UpdateQTSTime,
			@InchargeNRIC
	END 	

CLOSE @Cur01
	
DEALLOCATE @Cur01


-- >> RGS List
SELECT Sno, TARNo, ElectricalSections,
	PowerOffTime, CircuitBreakOutTime,
	PartiesName, NoOfPersons, 
	WorkDescription, ContactNo, TOANo,
	CallBackTime, RadioMsgTime, LineClearMsgTime,
	Remarks, TOAStatus, IsTOAAuth, ColourCode, IsGrantTOAEnable, 
	UpdQTSTime, AccessType,
	AckGrantTOATime, AckProtLimitTime, 
	TARID, TOAID,
	InchargeNRIC
FROM #TmpRGS
	ORDER BY Sno

-- >> Cancel List
SELECT a.Id AS Val, a.TARNo AS Txt
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND b.TOAStatus NOT IN (0, 5, 6)
			AND a.AccessDate = @AccessDate
			AND a.Line = @Line
	ORDER BY 1

SELECT CONVERT(NVARCHAR(20), @OperationDate, 103) AS OperationDate,  
	CONVERT(NVARCHAR(20), @AccessDate, 103) AS AccessDate

DROP TABLE #TmpRGS
DROP TABLE #TmpRGSSectors

END

GO
/****** END PROCEDURE 303 ******/

/****** START PROCEDURE 304 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_RGS_OnLoad_Trace
CREATE PROCEDURE [dbo].[sp_TAMS_RGS_OnLoad_Trace]
	@Line		NVARCHAR(20) = NULL,
	@ADStr		NVARCHAR(20) = NULL
AS

BEGIN
	
/*
Notes :
OCCAuthStatusId 
DTL = 10
NEL = 7
*/

CREATE TABLE #TmpRGS 
(Sno				INT,
TARNo				NVARCHAR(30),
ElectricalSections	NVARCHAR(4000),
PowerOffTime		NVARCHAR(20),
CircuitBreakOutTime	NVARCHAR(20),
PartiesName			NVARCHAR(4000),
NoOfPersons			NVARCHAR(20),
WorkDescription		NVARCHAR(4000),
ContactNo			NVARCHAR(50),
TOANo				NVARCHAR(30),
CallBackTime		NVARCHAR(20),
RadioMsgTime		NVARCHAR(20),
LineClearMsgTime	NVARCHAR(20),
Remarks				NVARCHAR(4000),
TOAStatus			NVARCHAR(20),
IsTOAAuth			BIT,
ColourCode			NVARCHAR(20),
IsGrantTOAEnable	BIT,
UpdQTSTime			NVARCHAR(20),
AccessType			NVARCHAR(20),
AckGrantTOATime		NVARCHAR(20),
AckProtLimitTime	NVARCHAR(20),
TARID				INT,
TOAID				INT,
InchargeNRIC		NVARCHAR(100))

CREATE TABLE #TmpRGSSectors 
(OCCAuthID			INT,
OperationDate		DATE,
AccessDate			DATE,
OCCAuthStatus		NVARCHAR(50),
TractionPowerID		INT,
TractionPowerType	NVARCHAR(50),
SectorID			INT,
Sector				NVARCHAR(100),
WorkFlowTime		DATETIME)

TRUNCATE TABLE #TmpRGS
TRUNCATE TABLE #TmpRGSSectors

DECLARE @CurDate		DATE
DECLARE @CurTime		TIME
DECLARE @OperationDate	DATE
DECLARE @AccessDate		DATE

SET @CurDate = GETDATE()
SET @CurTime = CONVERT(TIME, GETDATE(), 108)

DECLARE @CutOff				TIME
DECLARE @TOACallBackTime	NVARCHAR(10)
DECLARE @RGSPossBG			NVARCHAR(20)
DECLARE @RGSProtBG			NVARCHAR(20)

SET @TOACallBackTime = '04:00'
SET @CutOff = '06:00:00'

SELECT @RGSPossBG = ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'RGSPossessionBG'
			AND ParaValue1 = @Line

SELECT @RGSProtBG = ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'RGSProtectionBG'
			AND ParaValue1 = @Line

--IF @CurTime > @CutOff
--	BEGIN
--		SET @OperationDate	= @CurDate
--		SET @AccessDate		= DATEADD(DAY, 1, @CurDate)
--	END
--ELSE
--	BEGIN
--		SET @OperationDate	= DATEADD(DAY, -1, @CurDate)
--		SET @AccessDate		= @CurDate
--	END

SET @AccessDate = CONVERT(DATE, @ADStr, 103)
SET @OperationDate = DATEADD(DAY, -1, @AccessDate)

SELECT @AccessDate, @OperationDate

DECLARE @Cur01 CURSOR;
DECLARE @Cur02 CURSOR;

DECLARE @TARID BIGINT,
@TOAID	BIGINT,
@ARRemark NVARCHAR(1000),
@TVFMode NVARCHAR(20),
@AccessType NVARCHAR(30),
@TOAStatus INT,
@ProtTimeLimit NVARCHAR(10),
@TARNo NVARCHAR(30),
@NoOfParties INT,
@DescOfWork NVARCHAR(1000),
@MobileNo NVARCHAR(20),
@TetraRadioNo NVARCHAR(50),
@TOANo NVARCHAR(50),
@GrantTOATime NVARCHAR(10),
@AckSurrenderTime NVARCHAR(10),
@AckGrantTOATime NVARCHAR(10),
@UpdateQTSTime NVARCHAR(10),
@InchargeNRIC NVARCHAR(100)

DECLARE @lv_Sno INT,
	@lv_IsTOAAuth BIT,
	@lv_PartiesName	NVARCHAR(4000),
	@lv_Remarks	NVARCHAR(4000),
	@lv_IsPowerOff BIT,
	@lv_PowerOffTime NVARCHAR(20),
	@lv_IsCircuitBreak BIT,
	@lv_CircuitBreakTime NVARCHAR(20),
	@lv_ColourCode NVARCHAR(20),
	@lv_ES NVARCHAR(100),
	@lv_SectorID INT,
	@lv_TVFStations NVARCHAR(1000),
	@lv_PossessionCtr INT,
	@lv_IsGrantTOAEnable BIT,
	@lv_ContactNo NVARCHAR(200)

DECLARE @SqlCtr1 INT,
	@SqlCtr2 INT,
	@SqlCtr3 INT,
	@WorkFlowTime NVARCHAR(20)

SET @lv_Sno = 0
SET @SqlCtr1 = 0
SET @SqlCtr2 = 0
SET @SqlCtr3 = 0
SET @lv_PossessionCtr = 0

----DECLARE @NewLine AS CHAR(2) = CHAR(30) + CHAR(10)
DECLARE @NewLine AS NVARCHAR(6)
SET @NewLine = '<br />'
-- >> SELECT @NewUID = SCOPE_IDENTITY();

SET @Cur01 = CURSOR FAST_FORWARD 
FOR

SELECT a.Id, b.Id, a.TARNo, a.ARRemark, a.TVFMode, a.AccessType, b.TOAStatus, 
		-- >> ISNULL(CONVERT(NVARCHAR(20), b.AckProtectionLimitTime, 108), '00:00:00'), 
		ISNULL(CONVERT(NVARCHAR(5), b.AckProtectionLimitTime, 108), ''), 
		b.NoOfParties,
		a.DescOfWork, b.MobileNo, b.TetraRadioNo, ISNULL(b.TOANo, ''),
		ISNULL(CONVERT(NVARCHAR(5), b.GrantTOATime, 108), ''),
		ISNULL(CONVERT(NVARCHAR(5), b.AckSurrenderTime, 108), ''),
		ISNULL(CONVERT(NVARCHAR(8), b.AckGrantTOATime, 108), ''),
		ISNULL(CONVERT(NVARCHAR(5), b.UpdateQTSTime, 108), ''),
		dbo.DecryptString(b.InChargeNRIC)
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND a.AccessDate = @AccessDate
			AND b.TOAStatus <> 0
			AND a.Line = @Line
			--
			AND a.AccessType = 'Protection'
	ORDER BY a.AccessType, b.TOAType, a.Id

	-- EXEC sp_TAMS_RGS_OnLoad_Trace 'NEL', '30/09/2021'
OPEN @Cur01
	
FETCH NEXT FROM @Cur01 INTO @TARID, @TOAID, @TARNo, @ARRemark, @TVFMode, @AccessType, @TOAStatus, 
	@ProtTimeLimit, 
	@NoOfParties,
	@DescOfWork, @MobileNo, @TetraRadioNo, @TOANo,
	@GrantTOATime, @AckSurrenderTime, @AckGrantTOATime, @UpdateQTSTime,
	@InchargeNRIC
	
WHILE @@FETCH_STATUS = 0 
	
	BEGIN

		SET @lv_Sno = @lv_Sno + 1
		SET	@lv_IsTOAAuth = 1
		SET @lv_PartiesName	= ''
		SET @lv_Remarks	= ''
		SET @lv_IsPowerOff = 1
		SET @lv_PowerOffTime = ''
		SET @lv_IsCircuitBreak = 1
		SET @lv_CircuitBreakTime = ''
		SET @lv_ColourCode = ''
		SET @lv_ES = ''
		SET @lv_ContactNo = ''

		SELECT @lv_ES = dbo.TAMS_Get_ES(@TARID)
		SELECT @lv_PartiesName = dbo.TAMS_Get_TOA_Parties(@TOAID)
		SET @lv_ContactNo = @MobileNo + @NewLine + @TetraRadioNo

		-- >> Electrical Sector Cursor
		-- >> 	EXEC sp_TAMS_RGS_OnLoad_20210819_M 'NEL'

		IF @Line = 'DTL'
			BEGIN
				SET @Cur02 = CURSOR FAST_FORWARD 
				FOR

				SELECT a.SectorId
					FROM TAMS_TAR_Sector a, TAMS_Sector b
						WHERE a.SectorId = b.ID
							AND a.TARId = @TARID
							AND ISNULL(b.IsGap, 0) = 0
							AND a.IsBuffer = 0
					
				OPEN @Cur02
	
				FETCH NEXT FROM @Cur02 INTO @lv_SectorID
	
				WHILE @@FETCH_STATUS = 0 
	
					BEGIN

						SET @SqlCtr1 = 0

						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.Sector, NULL
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.SectorId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND c.IsGap = 0
									-- >> AND a.OCCAuthStatusId = 10
									AND ((a.OCCAuthStatusId = 10 and a.IsBuffer = 0) OR ((a.OCCAuthStatusId = 7 and a.IsBuffer = 1)))
									AND c.Line = @Line

						SELECT @SqlCtr1 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr1 = 0
							BEGIN
								SET @lv_IsTOAAuth = 0
							END

						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.Sector, a.PowerOffTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.SectorId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND c.IsGap = 0
									AND a.PowerOffTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr2 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr2 = 0
							BEGIN
								SET @lv_IsPowerOff = 0
								SET @lv_PowerOffTime = ''
							END
						ELSE
							BEGIN
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM  #TmpRGSSectors

								IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_PowerOffTime = ''
									END
								ELSE
									BEGIN
										SET @lv_PowerOffTime = @WorkFlowTime
									END
							END

						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.Sector, a.RackedOutTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.SectorId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND c.IsGap = 0
									AND a.RackedOutTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr3 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr3 = 0
							BEGIN
								SET @lv_IsCircuitBreak = 0
								SET @lv_CircuitBreakTime = ''
							END
						ELSE
							BEGIN
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM  #TmpRGSSectors

									IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_CircuitBreakTime = ''
									END
								ELSE
									BEGIN
										SET @lv_CircuitBreakTime = @WorkFlowTime
									END
							END
						

						FETCH NEXT FROM @Cur02 INTO @lv_SectorID
					END 	

				CLOSE @Cur02
	
				DEALLOCATE @Cur02
			END
		ELSE
			BEGIN
				SET @Cur02 = CURSOR FAST_FORWARD 
				FOR

				SELECT a.PowerSectorId 
					FROM TAMS_TAR_Power_Sector a
						WHERE a.TARId = @TARID
							AND a.IsBuffer = 0
							
				OPEN @Cur02
	
				FETCH NEXT FROM @Cur02 INTO @lv_SectorID
	
				WHILE @@FETCH_STATUS = 0 
	
					BEGIN

						SET @SqlCtr1 = 0

						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.PowerSection, NULL
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Power_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.PowerSectionId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND a.OCCAuthStatusId = 7
									AND c.Line = @Line


						SELECT @SqlCtr1 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr1 = 0
							BEGIN
								SELECT 'JEFFTRACE', @lv_SectorID, @OperationDate, @AccessDate, @Line
								SET @lv_IsTOAAuth = 0
							END


						-- 	EXEC sp_TAMS_RGS_OnLoad_Trace 'NEL', '30/09/2021'

						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.PowerSection, a.PowerOffTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Power_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.PowerSectionId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND a.PowerOffTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr2 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr2 = 0
							BEGIN
								SET @lv_IsPowerOff = 0
								SET @lv_PowerOffTime = ''
							END
						ELSE
							BEGIN
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM  #TmpRGSSectors

									IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_PowerOffTime = ''
									END
								ELSE
									BEGIN
										SET @lv_PowerOffTime = @WorkFlowTime
									END
							END

						SET @WorkFlowTime = ''
						TRUNCATE TABLE #TmpRGSSectors

						INSERT INTO #TmpRGSSectors
						SELECT a.ID, a.OperationDate, a.AccessDate, a.OCCAuthStatusId, b.ID, b.TractionPowerType,
							c.ID, c.PowerSection, a.RackedOutTime
							FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b, TAMS_Power_Sector c
								WHERE a.TractionPowerId = b.TractionPowerId
									AND b.PowerSectionId = c.ID
									AND b.TractionPowerType = 'Sector'
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate
									AND c.ID = @lv_SectorID
									AND a.RackedOutTime IS NOT NULL
									AND c.Line = @Line

						SELECT @SqlCtr3 = COUNT(*) FROM #TmpRGSSectors
						IF @SqlCtr3 = 0
							BEGIN
								SET @lv_IsCircuitBreak = 0
								SET @lv_CircuitBreakTime = ''
							END
						ELSE
							BEGIN
								SELECT @WorkFlowTime = ISNULL(CONVERT(NVARCHAR(5), WorkFlowTime, 108), '00:00:00')
									FROM #TmpRGSSectors

									IF @WorkFlowTime = '00:00:00'
									BEGIN
										SET @lv_CircuitBreakTime = ''
									END
								ELSE
									BEGIN
										SET @lv_CircuitBreakTime = @WorkFlowTime
									END
							END

						FETCH NEXT FROM @Cur02 INTO @lv_SectorID
					END 	

				CLOSE @Cur02
	
				DEALLOCATE @Cur02
			END
		-- >>
		-- >> Electrical Sector Cursor

		SET @lv_Remarks = LTRIM(RTRIM(@ARRemark)) + @NewLine + LTRIM(RTRIM(ISNULL(@TVFMode, '')))
		SELECT @lv_TVFStations = dbo.TAMS_Get_TOA_TVF_Stations(@TOAID)

		IF @lv_Remarks = ''
			BEGIN
				SET @lv_Remarks = @lv_TVFStations
			END
		ELSE
			BEGIN
				SET @lv_Remarks = @lv_Remarks + @NewLine + @lv_TVFStations
			END

		IF @AccessType = 'Possession'
			BEGIN
				SET @lv_ColourCode = @RGSPossBG

				IF @TOAStatus = 6
					BEGIN
						IF @lv_PossessionCtr = 0
							BEGIN
								SET @lv_PossessionCtr = @lv_PossessionCtr
							END
						ELSE
							BEGIN
								SET @lv_PossessionCtr = @lv_PossessionCtr - 1
							END
					END
				ELSE
					BEGIN
						IF @ProtTimeLimit = '' OR @ProtTimeLimit = '00:00:00'
							BEGIN
								SET @lv_PossessionCtr = @lv_PossessionCtr + 1
							END
						ELSE
							BEGIN
								IF @lv_PossessionCtr = 0
									BEGIN
										SET @lv_PossessionCtr = @lv_PossessionCtr
									END
								ELSE
									BEGIN
										SET @lv_PossessionCtr = @lv_PossessionCtr - 1
									END
							END
					END
				SET @lv_IsGrantTOAEnable = 1
			END
		ELSE
			BEGIN
				--SELECT @lv_PossessionCtr AS PossCtr
				-- 	EXEC sp_TAMS_RGS_OnLoad 'DTL'
				SET @lv_ColourCode = @RGSProtBG

				IF @TOAStatus = 6
					BEGIN
						SET @lv_IsGrantTOAEnable = 1
					END
				ELSE
					BEGIN
						IF @lv_PossessionCtr > 0
							BEGIN
								SET @lv_IsGrantTOAEnable = 0
							END
						ELSE
							BEGIN
								SET @lv_IsGrantTOAEnable = 1
							END
					END
			END

		IF @TOANo = ''
			BEGIN
				SET @TOACallBackTime = ''
			END
		
		INSERT INTO #TmpRGS
			(Sno, TARNo, ElectricalSections,
				PowerOffTime, CircuitBreakOutTime,
				PartiesName, NoOfPersons, 
				WorkDescription, ContactNo, TOANo,
				CallBackTime, RadioMsgTime, LineClearMsgTime,
				Remarks, TOAStatus, IsTOAAuth, ColourCode, IsGrantTOAEnable, 
				UpdQTSTime, AccessType,
				AckGrantTOATime, AckProtLimitTime, 
				TARID, TOAID, InchargeNRIC)
		VALUES (@lv_Sno, @TARNo, @lv_ES, 
			@lv_PowerOffTime, @lv_CircuitBreakTime, 
			@lv_PartiesName, @NoOfParties, 
			@DescOfWork, @lv_ContactNo, @TOANo, 
			@TOACallBackTime, @GrantTOATime, @AckSurrenderTime, 
			@lv_Remarks, @TOAStatus, @lv_IsTOAAuth, @lv_ColourCode, @lv_IsGrantTOAEnable, 
			@UpdateQTSTime, @AccessType, 
			@AckGrantTOATime, @ProtTimeLimit, 
			@TARID, @TOAID, @InchargeNRIC)

		FETCH NEXT FROM @Cur01 INTO @TARID, @TOAID, @TARNo, @ARRemark, @TVFMode, @AccessType, @TOAStatus, 
			@ProtTimeLimit, 
			@NoOfParties,
			@DescOfWork, @MobileNo, @TetraRadioNo, @TOANo,
			@GrantTOATime, @AckSurrenderTime, @AckGrantTOATime, @UpdateQTSTime,
			@InchargeNRIC
	END 	

CLOSE @Cur01
	
DEALLOCATE @Cur01


-- >> RGS List
SELECT Sno, TARNo, ElectricalSections,
	PowerOffTime, CircuitBreakOutTime,
	PartiesName, NoOfPersons, 
	WorkDescription, ContactNo, TOANo,
	CallBackTime, RadioMsgTime, LineClearMsgTime,
	Remarks, TOAStatus, IsTOAAuth, ColourCode, IsGrantTOAEnable, 
	UpdQTSTime, AccessType,
	AckGrantTOATime, AckProtLimitTime, 
	TARID, TOAID,
	InchargeNRIC
FROM #TmpRGS
	ORDER BY Sno

-- >> Cancel List
SELECT a.Id AS Val, a.TARNo AS Txt
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND b.TOAStatus NOT IN (0, 5, 6)
			AND a.AccessDate = @AccessDate
			AND a.Line = @Line
	ORDER BY 1

SELECT CONVERT(NVARCHAR(20), @OperationDate, 103) AS OperationDate,  
	CONVERT(NVARCHAR(20), @AccessDate, 103) AS AccessDate

DROP TABLE #TmpRGS
DROP TABLE #TmpRGSSectors

END

GO
/****** END PROCEDURE 304 ******/

/****** START PROCEDURE 305 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_RGS_OnLoad_YD_TEST_20231208
CREATE PROCEDURE  [dbo].[sp_TAMS_RGS_OnLoad_YD_TEST_20231208]
	@Line		NVARCHAR(20) = 'NEL',
	@TrackType	NVARCHAR(50) = 'mainline'
AS

BEGIN
	
/*
Notes :
OCCAuthStatusId 
DTL = 10
NEL = 7
*/

CREATE TABLE #TmpRGS 
(Sno				INT,
TARNo				NVARCHAR(30),
ElectricalSections	NVARCHAR(4000),
PowerOffTime		NVARCHAR(20),
CircuitBreakOutTime	NVARCHAR(20),
PartiesName			NVARCHAR(4000),
NoOfPersons			NVARCHAR(20),
WorkDescription		NVARCHAR(4000),
ContactNo			NVARCHAR(50),
TOANo				NVARCHAR(30),
CallBackTime		NVARCHAR(20),
RadioMsgTime		NVARCHAR(20),
LineClearMsgTime	NVARCHAR(20),
Remarks				NVARCHAR(4000),
TOAStatus			NVARCHAR(20),
IsTOAAuth			BIT,
ColourCode			NVARCHAR(20),
IsGrantTOAEnable	BIT,
UpdQTSTime			NVARCHAR(20),
AccessType			NVARCHAR(20),
AckGrantTOATime		NVARCHAR(20),
AckProtLimitTime	NVARCHAR(20),
TARID				INT,
TOAID				INT,
InchargeNRIC		NVARCHAR(100))

CREATE TABLE #TmpRGSSectors 
(OCCAuthID			INT,
OperationDate		DATE,
AccessDate			DATE,
OCCAuthStatus		NVARCHAR(50),
TractionPowerID		INT,
TractionPowerType	NVARCHAR(50),
SectorID			INT,
Sector				NVARCHAR(100),
WorkFlowTime		DATETIME)

TRUNCATE TABLE #TmpRGS
TRUNCATE TABLE #TmpRGSSectors

DECLARE @CurDate		DATE
DECLARE @CurTime		TIME
DECLARE @OperationDate	DATE
DECLARE @AccessDate		DATE

SET @CurDate =  GETDATE()
SET @CurTime = CONVERT(TIME, GETDATE(), 108)

DECLARE @CutOff				TIME
DECLARE @TOACallBackTime	NVARCHAR(10)
DECLARE @RGSPossBG			NVARCHAR(20)
DECLARE @RGSProtBG			NVARCHAR(20)
DECLARE @RGSCancBG			NVARCHAR(20)

SET @TOACallBackTime = '04:00'
SET @CutOff = '06:00:00'

SELECT @RGSPossBG = ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'RGSPossessionBG'
			AND ParaValue1 = @Line

SELECT @RGSProtBG = ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'RGSProtectionBG'
			AND ParaValue1 = @Line

SELECT @RGSCancBG = ParaValue2 
	FROM TAMS_Parameters
		WHERE ParaCode = 'RGSCancelledBG'
			AND ParaValue1 = @Line

IF @CurTime > @CutOff
	BEGIN
		SET @OperationDate	= @CurDate
		SET @AccessDate		= DATEADD(DAY, 1, @CurDate)
	END
ELSE
	BEGIN
		SET @OperationDate	= DATEADD(DAY, -1, @CurDate)
		SET @AccessDate		= @CurDate
	END

 SET @OperationDate = '2023-12-06'
 SET @AccessDate = '2023-12-07'
--SELECT @OperationDate, @AccessDate


DECLARE @Cur01 CURSOR;
DECLARE @Cur02 CURSOR;

DECLARE @TARID BIGINT,
@TOAID	BIGINT,
@ARRemark NVARCHAR(1000),
@TVFMode NVARCHAR(20),
@AccessType NVARCHAR(30),
@TOAStatus INT,
@ProtTimeLimit NVARCHAR(10),
@TARNo NVARCHAR(30),
@NoOfParties INT,
@DescOfWork NVARCHAR(1000),
@MobileNo NVARCHAR(20),
@TetraRadioNo NVARCHAR(50),
@TOANo NVARCHAR(50),
@GrantTOATime NVARCHAR(10),
@AckSurrenderTime NVARCHAR(10),
@AckGrantTOATime NVARCHAR(10),
@UpdateQTSTime NVARCHAR(10),
@InchargeNRIC NVARCHAR(100), 
@CancelRemark NVARCHAR(1000)

DECLARE @lv_Sno INT,
	@lv_IsTOAAuth BIT,
	@lv_PartiesName	NVARCHAR(4000),
	@lv_Remarks	NVARCHAR(4000),
	@lv_IsPowerOff BIT,
	@lv_PowerOffTime NVARCHAR(20),
	@lv_IsCircuitBreak BIT,
	@lv_CircuitBreakTime NVARCHAR(20),
	@lv_ColourCode NVARCHAR(20),
	@lv_ES NVARCHAR(100),
	@lv_SectorID INT,
	@lv_TVFStations NVARCHAR(1000),
	@lv_PossessionCtr INT,
	@lv_IsGrantTOAEnable BIT,
	@lv_ContactNo NVARCHAR(200)

DECLARE @SqlCtr1 INT,
	@SqlCtr2 INT,
	@SqlCtr3 INT,
	@WorkFlowTime NVARCHAR(20)

SET @lv_Sno = 0
SET @SqlCtr1 = 0
SET @SqlCtr2 = 0
SET @SqlCtr3 = 0
SET @lv_PossessionCtr = 0

SELECT @lv_PossessionCtr = COUNT(*)
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND a.AccessDate = @AccessDate
			AND b.TOAStatus NOT IN (0, 6)
			AND a.Line = @Line
			and a.TrackType = @TrackType
			AND a.AccessType = 'Possession'

----DECLARE @NewLine AS CHAR(2) = CHAR(30) + CHAR(10)
DECLARE @NewLine AS NVARCHAR(6)
SET @NewLine = '<br />'
-- >> SELECT @NewUID = SCOPE_IDENTITY();

SET @Cur01 = CURSOR FAST_FORWARD 
FOR

SELECT a.Id, b.Id, a.TARNo, a.ARRemark, a.TVFMode, a.AccessType, b.TOAStatus, 
		-- >> ISNULL(CONVERT(NVARCHAR(20), b.AckProtectionLimitTime, 108), '00:00:00'), 
		ISNULL(CONVERT(NVARCHAR(5), b.AckProtectionLimitTime, 108), ''), 
		b.NoOfParties,
		a.DescOfWork, b.MobileNo, b.TetraRadioNo, ISNULL(b.TOANo, ''),
		ISNULL(CONVERT(NVARCHAR(5), b.GrantTOATime, 108), ''),
		ISNULL(CONVERT(NVARCHAR(5), b.AckSurrenderTime, 108), ''),
		ISNULL(CONVERT(NVARCHAR(8), b.AckGrantTOATime, 108), ''),
		ISNULL(CONVERT(NVARCHAR(5), b.UpdateQTSTime, 108), ''),
		dbo.DecryptString(b.InChargeNRIC),
		b.CancelRemark
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND a.AccessDate = @AccessDate
			and a.TrackType = @TrackType
			AND b.TOAStatus <> 0
			AND a.Line = @Line
	-- >> ORDER BY a.AccessType, b.TOAType, a.Id
	ORDER BY a.AccessType,a.TARNo
	--b.TOAStatus DESC, a.Id
	-- >> EXEC sp_TAMS_RGS_OnLoad 'NEL'
OPEN @Cur01
	
FETCH NEXT FROM @Cur01 INTO @TARID, @TOAID, @TARNo, @ARRemark, @TVFMode, @AccessType, @TOAStatus, 
	@ProtTimeLimit, 
	@NoOfParties,
	@DescOfWork, @MobileNo, @TetraRadioNo, @TOANo,
	@GrantTOATime, @AckSurrenderTime, @AckGrantTOATime, @UpdateQTSTime,
	@InchargeNRIC, @CancelRemark
	
WHILE @@FETCH_STATUS = 0 
	
	BEGIN

		SET @lv_Sno = @lv_Sno + 1
		SET	@lv_IsTOAAuth = 0
		SET @lv_PartiesName	= ''
		SET @lv_Remarks	= ''
		SET @lv_IsPowerOff = 0
		SET @lv_PowerOffTime = ''
		SET @lv_IsCircuitBreak = 0
		SET @lv_CircuitBreakTime = ''
		SET @lv_ColourCode = ''
		SET @lv_ES = ''
		SET @lv_ContactNo = ''

		SELECT @lv_ES = dbo.TAMS_Get_ES_NoBufferZone(@TARID)
		SELECT @lv_PartiesName = dbo.TAMS_Get_TOA_Parties(@TOAID)
		SET @lv_ContactNo = @MobileNo + @NewLine + @TetraRadioNo

		-- >> Electrical Sector Cursor
		-- >> 	EXEC sp_TAMS_RGS_OnLoad_20210819_M 'NEL'
 
		IF @Line = 'DTL'
			BEGIN

			set @lv_CircuitBreakTime = '';
				set @lv_IsTOAAuth = 0;
				set @lv_PowerOffTime = '';
				set @lv_IsPowerOff = 0 ;

			if exists(SELECT a.ID
							FROM TAMS_OCC_Auth a 
								WHERE  a.Line = @Line
									and a.TrackType = @TrackType
									AND a.OperationDate = @OperationDate
									AND a.AccessDate = @AccessDate)
			begin
				if(
					SELECT Count(a.ID)
									FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b 
										WHERE a.TractionPowerId = b.TractionPowerId
											AND b.SectorId in (
												SELECT a.SectorId
											FROM TAMS_TAR_Sector a, TAMS_Sector b
												WHERE a.SectorId = b.ID
													AND a.TARId = @TARID
													AND ISNULL(b.IsGap, 0) = 0
													AND a.IsBuffer = 0
											)
											AND b.TractionPowerType = 'Sector'
											AND a.OperationDate = @OperationDate
											AND a.AccessDate = @AccessDate
											 
											AND ((a.OCCAuthStatusId < 10 and a.IsBuffer = 0) OR ((a.OCCAuthStatusId < 7 and a.IsBuffer = 1)))
											 
								) = 0 
								begin 
									set @lv_IsTOAAuth = 1;
								end;
				end;

				if not exists(
					select * 
					FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b 
						WHERE a.TractionPowerId = b.TractionPowerId
							 AND b.SectorId in (
												SELECT a.SectorId
											FROM TAMS_TAR_Sector a, TAMS_Sector b
												WHERE a.SectorId = b.ID
													AND a.TARId = @TARID
													AND ISNULL(b.IsGap, 0) = 0
													AND a.IsBuffer = 0
											)
							AND b.TractionPowerType = 'Sector'
							AND a.OperationDate = @OperationDate
							AND a.AccessDate = @AccessDate
							AND a.PowerOffType is null 
				)
				begin
					SELECT  @lv_PowerOffTime = ISNULL(CONVERT(NVARCHAR(5), max(a.PowerOffTime), 108), '')
					FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b 
						WHERE a.TractionPowerId = b.TractionPowerId
							 AND b.SectorId in (
												SELECT a.SectorId
											FROM TAMS_TAR_Sector a, TAMS_Sector b
												WHERE a.SectorId = b.ID
													AND a.TARId = @TARID
													AND ISNULL(b.IsGap, 0) = 0
													AND a.IsBuffer = 0
											)
							AND b.TractionPowerType = 'Sector'
							AND a.OperationDate = @OperationDate
							AND a.AccessDate = @AccessDate
							 AND a.PowerOffTime IS NOT NULL and a.PowerOffType='Completed'
				end;			 
				if @lv_PowerOffTime <> ''
				begin 
					set @lv_IsPowerOff = 1 ;
				end; 
				
				if not exists(
					SELECT * 
					FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b 
						WHERE a.TractionPowerId = b.TractionPowerId
							 AND b.SectorId in (
												SELECT a.SectorId
											FROM TAMS_TAR_Sector a, TAMS_Sector b
												WHERE a.SectorId = b.ID
													AND a.TARId = @TARID
													AND ISNULL(b.IsGap, 0) = 0
													AND a.IsBuffer = 0
											)
							AND b.TractionPowerType = 'Sector'
							AND a.OperationDate = @OperationDate
							AND a.AccessDate = @AccessDate
							AND a.RackedOutType is null 
					)
					begin
						SELECT  @lv_CircuitBreakTime = ISNULL(CONVERT(NVARCHAR(5), max(a.RackedOutTime), 108), '')
						FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b 
							WHERE a.TractionPowerId = b.TractionPowerId
								 AND b.SectorId in (
													SELECT a.SectorId
												FROM TAMS_TAR_Sector a, TAMS_Sector b
													WHERE a.SectorId = b.ID
														AND a.TARId = @TARID
														AND ISNULL(b.IsGap, 0) = 0
														AND a.IsBuffer = 0
												)
								AND b.TractionPowerType = 'Sector'
								AND a.OperationDate = @OperationDate
								AND a.AccessDate = @AccessDate
								 AND a.RackedOutTime IS NOT NULL and a.RackedOutType='Completed'
					end;

			
			END
		ELSE
			BEGIN

				-----For NEL Checking .. 

				set @lv_CircuitBreakTime = '';
				set @lv_IsTOAAuth = 0;
				set @lv_PowerOffTime = '';
				set @lv_IsPowerOff = 0 ;


				if exists(select a.ID FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b 
					WHERE a.TractionPowerId = b.TractionPowerId
						AND b.PowerSectionId in (
							select PowerSectorId from TAMS_TAR_Power_Sector where TARId = @TARID
						)
						AND b.TractionPowerType = 'Sector'
						AND a.OperationDate = @OperationDate
						AND a.AccessDate = @AccessDate)
				begin
					if(SELECT COUNT(a.ID)
					FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b 
						WHERE a.TractionPowerId = b.TractionPowerId
							AND b.PowerSectionId in (
								select PowerSectorId from TAMS_TAR_Power_Sector where TARId = @TARID
							)
							AND b.TractionPowerType = 'Sector'
							AND a.OperationDate = @OperationDate
							AND a.AccessDate = @AccessDate
							 AND a.OCCAuthStatusId < 8)= 0 
					begin 
						set @lv_IsTOAAuth = 1 ; 
					end;
				end;


				if not exists(
					select * 
					FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b 
					WHERE a.TractionPowerId = b.TractionPowerId
						AND b.PowerSectionId in (
							select PowerSectorId from TAMS_TAR_Power_Sector where TARId = @TARID
						)
						AND b.TractionPowerType = 'Sector'
						AND a.OperationDate = @OperationDate
						AND a.AccessDate = @AccessDate
						 AND a.PowerOffType is null 
				)
				begin
					SELECT  @lv_PowerOffTime = ISNULL(CONVERT(NVARCHAR(5), max(a.PowerOffTime), 108), '')
					FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b 
						WHERE a.TractionPowerId = b.TractionPowerId
							AND b.PowerSectionId in (
								select PowerSectorId from TAMS_TAR_Power_Sector where TARId = @TARID
							)
							AND b.TractionPowerType = 'Sector'
							AND a.OperationDate = @OperationDate
							AND a.AccessDate = @AccessDate
							 AND a.PowerOffTime is not null  and a.PowerOffType = 'Completed' 
				end;		 
				if @lv_PowerOffTime <> ''
				begin 
					set @lv_IsPowerOff = 1 ;
				end; 

				if not exists(
					select * 
					FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b 
					WHERE a.TractionPowerId = b.TractionPowerId
						AND b.PowerSectionId in (
							select PowerSectorId from TAMS_TAR_Power_Sector where TARId = @TARID
						)
						AND b.TractionPowerType = 'Sector'
						AND a.OperationDate = @OperationDate
						AND a.AccessDate = @AccessDate
						 AND a.RackedOutType is null 
				)
				begin
					SELECT  @lv_CircuitBreakTime = ISNULL(CONVERT(NVARCHAR(5), max(a.RackedOutTime), 108), '')
					FROM TAMS_OCC_Auth a, TAMS_Traction_Power_Detail b 
						WHERE a.TractionPowerId = b.TractionPowerId
							AND b.PowerSectionId in (
								select PowerSectorId from TAMS_TAR_Power_Sector where TARId = @TARID
							)
							AND b.TractionPowerType = 'Sector'
							AND a.OperationDate = @OperationDate
							AND a.AccessDate = @AccessDate
							 AND a.RackedOutTime is not null and a.RackedOutType = 'Completed' 
				end;		 
 			END
		-- >>
		-- >> Electrical Sector Cursor


		IF @Line = 'DTL'
			BEGIN
				SET @lv_Remarks = LTRIM(RTRIM(@ARRemark)) + @NewLine + LTRIM(RTRIM(ISNULL(@TVFMode, '')))
			END
		ELSE
			BEGIN

			-- DTL also will follow the same rule as NEL (meaning if TAR is without Rackout, RGS screen show blank in Rackout column)
				DECLARE @RackOutCtr	INT

				SELECT @RackOutCtr = COUNT(*) 
					FROM TAMS_TAR_AccessReq a, TAMS_Access_Requirement b
						WHERE a.IsPower = 1
							AND a.OperationRequirement = b.ID
							AND b.ID = 27	-- >> 27 FOR NEL
							AND a.IsSelected = 1
							AND a.TARId = @TARID

				IF @RackOutCtr > 0
					BEGIN
						SET @lv_Remarks = 'Rack Out' + @NewLine + @NewLine + LTRIM(RTRIM(@ARRemark)) + @NewLine + LTRIM(RTRIM(ISNULL(@TVFMode, '')))
					END
				ELSE
					BEGIN
						-- >> Don't show RackedOutTime for NEL if Power Requirement is with out Racked Out
						SET @lv_CircuitBreakTime = ''
						SET @lv_Remarks = LTRIM(RTRIM(@ARRemark)) + @NewLine + LTRIM(RTRIM(ISNULL(@TVFMode, '')))
					END
			 END


		DECLARE @SCDCtr	INT

		SELECT @SCDCtr = COUNT(*) 
			FROM TAMS_TAR_AccessReq a, TAMS_Access_Requirement b
				WHERE -- >> a.IsPower = 1 AND  -- >> 07082023 To remove this condition Jeffrey
					a.OperationRequirement = b.ID
					AND b.OperationRequirement = 'SCD Application'
					AND a.IsSelected = 1
					AND a.TARId = @TARID

		IF @SCDCtr > 0
			BEGIN
				SET @lv_Remarks = 'SCD' + @NewLine + @NewLine + LTRIM(RTRIM(@lv_Remarks))
			END
			
		SELECT @lv_TVFStations = dbo.TAMS_Get_TOA_TVF_Stations(@TOAID)

		IF @lv_Remarks = ''
			BEGIN
				SET @lv_Remarks = @lv_TVFStations
			END
		ELSE
			BEGIN
				SET @lv_Remarks = @lv_Remarks + @NewLine + @lv_TVFStations
			END

		IF @Line = 'DTL'	-- >> DTL to continue with Possession Priority Rule. 
			BEGIN
				IF @AccessType = 'Possession'
					BEGIN
						SET @lv_ColourCode = @RGSPossBG

						IF @TOAStatus = 6
							BEGIN
								IF @lv_PossessionCtr = 0
									BEGIN
										SET @lv_PossessionCtr = @lv_PossessionCtr
									END
								ELSE
									BEGIN
										SET @lv_PossessionCtr = @lv_PossessionCtr - 1
									END
							END
						ELSE
							BEGIN
								IF @ProtTimeLimit = '' OR @ProtTimeLimit = '00:00:00'
									BEGIN
										-- >> SELECT '1'
										SET @lv_PossessionCtr = @lv_PossessionCtr + 1
										-- >> SET @lv_PossessionCtr = @lv_PossessionCtr
									END
								ELSE
									BEGIN
										-- >> SELECT '2'
										IF @lv_PossessionCtr = 0
											BEGIN
												-- >> SELECT '3'
												SET @lv_PossessionCtr = @lv_PossessionCtr
											END
										ELSE
											BEGIN
												-- >> SELECT '4'
												SET @lv_PossessionCtr = @lv_PossessionCtr - 1
											END
									END
							END

						SET @lv_IsGrantTOAEnable = 1

					END
				ELSE
					BEGIN
						-- >> SELECT @lv_PossessionCtr AS PossCtr
						-- 	EXEC sp_TAMS_RGS_OnLoad 'DTL'
						SET @lv_ColourCode = @RGSProtBG

						IF @TOAStatus = 6
							BEGIN
								SET @lv_IsGrantTOAEnable = 1
							END
						ELSE
							BEGIN
								IF @lv_PossessionCtr > 0
									BEGIN
										SET @lv_IsGrantTOAEnable = 0
									END
								ELSE
									BEGIN
										SET @lv_IsGrantTOAEnable = 1
									END
							END
					END
			END
		ELSE	-- >> NEL to change with no Priority
			BEGIN
				IF @AccessType = 'Possession'
					BEGIN
						SET @lv_ColourCode = @RGSPossBG
					END
				ELSE
					BEGIN
						SET @lv_ColourCode = @RGSProtBG
					END

				SET @lv_IsGrantTOAEnable = 1
			END

		IF @TOANo = ''
			BEGIN
				SET @TOACallBackTime = ''
			END
		ELSE
			BEGIN
				SET @TOACallBackTime = '04:00'
			END
		
		-- >> 2023 change highlight for cancelled records
		-- >> Include Cancel remarks after new line
		IF @TOAStatus = 6
			BEGIN
				SET @lv_ColourCode = @RGSCancBG
				SET @lv_Remarks = @lv_Remarks + @NewLine + @NewLine + 'Cancel Remark: ' + LTRIM(RTRIM(@CancelRemark))
			END

			print @TARNo  ;print   @lv_IsGrantTOAEnable;print @lv_IsTOAAuth; 
		INSERT INTO #TmpRGS
			(Sno, TARNo, ElectricalSections,
				PowerOffTime, CircuitBreakOutTime,
				PartiesName, NoOfPersons, 
				WorkDescription, ContactNo, TOANo,
				CallBackTime, RadioMsgTime, LineClearMsgTime,
				Remarks, TOAStatus, IsTOAAuth, ColourCode, IsGrantTOAEnable, 
				UpdQTSTime, AccessType,
				AckGrantTOATime, AckProtLimitTime, 
				TARID, TOAID, InchargeNRIC)
		VALUES (@lv_Sno, @TARNo, @lv_ES, 
			@lv_PowerOffTime, @lv_CircuitBreakTime, 
			@lv_PartiesName, @NoOfParties, 
			@DescOfWork, @lv_ContactNo, @TOANo, 
			@TOACallBackTime, @GrantTOATime, @AckSurrenderTime, 
			@lv_Remarks, @TOAStatus, @lv_IsTOAAuth, @lv_ColourCode, @lv_IsGrantTOAEnable, 
			@UpdateQTSTime, @AccessType, 
			@AckGrantTOATime, @ProtTimeLimit, 
			@TARID, @TOAID, @InchargeNRIC)

		FETCH NEXT FROM @Cur01 INTO @TARID, @TOAID, @TARNo, @ARRemark, @TVFMode, @AccessType, @TOAStatus, 
			@ProtTimeLimit, 
			@NoOfParties,
			@DescOfWork, @MobileNo, @TetraRadioNo, @TOANo,
			@GrantTOATime, @AckSurrenderTime, @AckGrantTOATime, @UpdateQTSTime,
			@InchargeNRIC, @CancelRemark
	END 	

CLOSE @Cur01
	
DEALLOCATE @Cur01


-- >> RGS List
SELECT Sno, TARNo, ElectricalSections,
	PowerOffTime, CircuitBreakOutTime,
	PartiesName, NoOfPersons, 
	WorkDescription, ContactNo, TOANo,
	CallBackTime, RadioMsgTime, LineClearMsgTime,
	Remarks, TOAStatus, IsTOAAuth, ColourCode, IsGrantTOAEnable, 
	UpdQTSTime, AccessType,
	AckGrantTOATime, AckProtLimitTime, 
	TARID, TOAID,
	InchargeNRIC
FROM #TmpRGS
	ORDER BY Sno

-- >> Cancel List
SELECT a.Id AS Val, a.TARNo AS Txt
	FROM TAMS_TAR a, TAMS_TOA b
		WHERE a.Id = b.TARId
			AND b.TOAStatus NOT IN (0, 5, 6)
			AND a.AccessDate = @AccessDate
			AND a.Line = @Line
			AND a.TrackType = @TrackType
	ORDER BY 1

SELECT CONVERT(NVARCHAR(20), @OperationDate, 103) AS OperationDate,  
	CONVERT(NVARCHAR(20), @AccessDate, 103) AS AccessDate

DROP TABLE #TmpRGS
DROP TABLE #TmpRGSSectors

END

GO
/****** END PROCEDURE 305 ******/

/****** START PROCEDURE 306 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_RGS_Update_Details
CREATE PROCEDURE  [dbo].[sp_TAMS_RGS_Update_Details]
	@TARID			AS BIGINT,
	@InchargeNRIC	AS NVARCHAR(50),
	@MobileNo		AS NVARCHAR(20),
	@TetraRadioNo	AS NVARCHAR(50),
	@UserID			AS NVARCHAR(50),
	@Message		AS NVARCHAR(500) = NULL OUTPUT
AS

BEGIN

DECLARE	@IntrnlTrans	TINYINT

SELECT 	@IntrnlTrans 	= 0	

IF (@@TRANCOUNT = 0) 
BEGIN
	SET @IntrnlTrans = 1
	BEGIN TRAN
END

CREATE TABLE #tmpnric 
(id BIGINT IDENTITY(1,1) NOT NULL, 
nric NVARCHAR(50),
namestr NVARCHAR(500),
line NVARCHAR(50),
qualdate NVARCHAR(50),
qualcode NVARCHAR(100),
qualstatus NVARCHAR(100))

TRUNCATE TABLE #tmpnric

DECLARE @ExecString	NVARCHAR(MAX)
SET @ExecString = ''
DECLARE @QualDate	NVARCHAR(20)
SET @QualDate = ''

DECLARE @InChargeName	NVARCHAR(500)
DECLARE @InChargeStatus	NVARCHAR(20)

SET @InChargeName = ''
SET @InChargeStatus = ''

DECLARE @Line NVARCHAR(20)
DECLARE @AccessDate DATE
DECLARE @AccessType NVARCHAR(50)
DECLARE @TOAID BIGINT

SELECT @Line = a.Line,
	@AccessDate = a.AccessDate,
	@TOAID = a.Id,
	@AccessType = b.AccessType
FROM TAMS_TOA a, TAMS_TAR b 
	WHERE a.TARId = @TARID
		AND a.TARId = b.Id

DECLARE @QTSQualCode		NVARCHAR(20)
DECLARE @QTSQualCodeProt	NVARCHAR(20)

SELECT @QTSQualCode = ParaValue2
	FROM TAMS_Parameters
		WHERE ParaCode = 'QTSQualCode'
			AND ParaValue1 = @Line
			AND ParaValue3 = 'Mainline Possession'
			AND GETDATE() BETWEEN EffectiveDate AND ExpiryDate

SELECT @QTSQualCodeProt = ParaValue2
	FROM TAMS_Parameters
		WHERE ParaCode = 'QTSQualCode'
			AND ParaValue1 = @Line
			AND ParaValue3 = 'Mainline'
			AND GETDATE() BETWEEN EffectiveDate AND ExpiryDate

SET @QualDate = CONVERT(NVARCHAR(20), @AccessDate, 103)
SET @ExecString = 'sp_TAMS_TOA_QTS_Chk '+ '''' + @InchargeNRIC + ''', ''' + @QualDate + ''', ''' + @Line + ''', ''' + @QTSQualCode + ''''

INSERT INTO #tmpnric
EXEC(@ExecString)

SELECT @InChargeName = namestr,
	@InChargeStatus = qualstatus
FROM #tmpnric

DECLARE @QTSFinStatus NVARCHAR(20)
SET @QTSFinStatus = ''

IF @InChargeStatus	= 'InValid'
	BEGIN
		IF @AccessType = 'Protection'
			BEGIN
				TRUNCATE TABLE #tmpnric
				SET @InChargeName = ''
				SET @InChargeStatus = ''

				SET @ExecString = 'sp_TAMS_TOA_QTS_Chk '+ '''' + @InchargeNRIC + ''', ''' + @QualDate + ''', ''' + @Line + ''', ''' + @QTSQualCodeProt + ''''

				INSERT INTO #tmpnric
				EXEC(@ExecString)

				SELECT @InChargeName = namestr,
					@InChargeStatus = qualstatus
				FROM #tmpnric

				IF @InChargeStatus	= 'InValid'
					BEGIN
						SET @QTSFinStatus = 'InValid'
					END
				ELSE
					BEGIN
						SET @QTSFinStatus = 'Valid'
					END
			END
		ELSE
			BEGIN
				SET @QTSFinStatus = 'InValid'
			END
	END
ELSE
	BEGIN
		SET @QTSFinStatus = 'Valid'
	END

DROP TABLE #tmpnric

IF @QTSFinStatus = 'InValid'
	BEGIN
		SET @Message = '1' -- >> Invalid Qualification
	END
ELSE
	BEGIN
		DECLARE @InchargeCtr INT
		SET @InchargeCtr = 0
		SELECT @InchargeCtr = COUNT(*)
			FROM TAMS_TOA
				WHERE TARId = @TARID
					AND dbo.DecryptString(InChargeNRIC) = @InchargeNRIC

		IF @InchargeCtr = 0 -- >> New Incharge need to delete TOA_Parties
			BEGIN
				UPDATE TAMS_TOA
					SET InChargeNRIC = dbo.EncryptString(@InchargeNRIC),
						InChargeName = @InChargeName,
						MobileNo = @MobileNo,
						TetraRadioNo = @TetraRadioNo,
						UpdatedOn = GETDATE(),
						UpdatedBy = @UserID
					WHERE TARId = @TARID

				INSERT INTO TAMS_TOA_Audit
				SELECT @UserID, GETDATE(), 'U', * FROM TAMS_TOA
					WHERE TARId = @TARID

				INSERT INTO TAMS_TOA_Parties_Audit
				SELECT @UserID, GETDATE(), 'D', * FROM TAMS_TOA_Parties
					WHERE TOAId = @TOAID
						AND IsInCharge = 1

				DELETE FROM TAMS_TOA_Parties
					WHERE TOAId = @TOAID
						AND IsInCharge = 1

				INSERT INTO TAMS_TOA_Parties
					(TOAId, [Name], NRIC, IsInCharge, IsWitness, IsTMC, BookInTime, BookOutTime, BookInStatus)
				VALUES (@TOAID, @InChargeName, dbo.EncryptString(@InchargeNRIC), 1, 0, 0, GETDATE(), NULL, 'In')

				INSERT INTO TAMS_TOA_Parties_Audit
				SELECT @UserID, GETDATE(), 'I', * FROM TAMS_TOA_Parties
					WHERE TOAId = @TOAID
						AND IsInCharge = 1

			END
		ELSE
			BEGIN
				UPDATE TAMS_TOA
					SET MobileNo = @MobileNo,
						TetraRadioNo = @TetraRadioNo,
						UpdatedOn = GETDATE(),
						UpdatedBy = @UserID
					WHERE TARId = @TARID

				INSERT INTO TAMS_TOA_Audit
				SELECT @UserID, GETDATE(), 'U', * FROM TAMS_TOA
					WHERE TARId = @TARID
			END

		SET @Message = '0' -- >> Updated
	END

IF @@ERROR <> 0 BEGIN
	SET @Message = 'ERROR INSERTING INTO TAMS_TOA'
	GOTO TRAP_ERROR
END

FORCE_EXIT_PROC:	
	IF @IntrnlTrans = 1 COMMIT TRAN
	RETURN @Message 

TRAP_ERROR:
	IF @IntrnlTrans = 1 ROLLBACK TRAN
	RETURN @Message

END
GO
/****** END PROCEDURE 306 ******/

/****** START PROCEDURE 307 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_RGS_Update_QTS
CREATE procedure  [dbo].[sp_TAMS_RGS_Update_QTS]
	@TARID			AS BIGINT,
	@InchargeNRIC	AS NVARCHAR(50),
	@UserID			AS NVARCHAR(500),
	@TrackType		AS NVARCHAR(50)='Mainline',
	@Message		AS NVARCHAR(500) = NULL OUTPUT,
	@QTSQCode		AS NVARCHAR(50) = NULL OUTPUT,
	@QTSLine		AS NVARCHAR(10) = NULL OUTPUT
AS

BEGIN

DECLARE	@IntrnlTrans	TINYINT

SELECT 	@IntrnlTrans 	= 0	

IF (@@TRANCOUNT = 0) 
BEGIN
	SET @IntrnlTrans = 1
	BEGIN TRAN
END

CREATE TABLE #tmpnric 
(id BIGINT IDENTITY(1,1) NOT NULL, 
nric NVARCHAR(50),
namestr NVARCHAR(500),
line NVARCHAR(50),
qualdate NVARCHAR(50),
qualcode NVARCHAR(100),
qualstatus NVARCHAR(100))

TRUNCATE TABLE #tmpnric

DECLARE @ExecString	NVARCHAR(MAX)
SET @ExecString = ''
DECLARE @QualDate	NVARCHAR(20)
SET @QualDate = ''

DECLARE @InChargeName	NVARCHAR(500)
DECLARE @InChargeStatus	NVARCHAR(20)

SET @InChargeName = ''
SET @InChargeStatus = ''

DECLARE @Line NVARCHAR(20)
DECLARE @AccessDate DATE
DECLARE @AccessType NVARCHAR(50)
DECLARE @TOAID BIGINT

SELECT @Line = a.Line,
	@AccessDate = a.AccessDate,
	@TOAID = a.Id,
	@AccessType = b.AccessType
FROM TAMS_TOA a, TAMS_TAR b 
	WHERE a.TARId = @TARID
		AND a.TARId = b.Id

DECLARE @QTSQualCode		NVARCHAR(20)
DECLARE @QTSQualCodeProt	NVARCHAR(20)

SELECT @QTSQualCode = ParaValue2
	FROM TAMS_Parameters
		WHERE ParaCode = 'QTSQualCode'
			AND ParaValue1 = @Line
			AND ParaValue3 = 'Mainline Possession'
			AND GETDATE() BETWEEN EffectiveDate AND ExpiryDate

SELECT @QTSQualCodeProt = ParaValue2
	FROM TAMS_Parameters
		WHERE ParaCode = 'QTSQualCode'
			AND ParaValue1 = @Line
			AND ParaValue3 = 'Mainline'
			AND GETDATE() BETWEEN EffectiveDate AND ExpiryDate

SET @QualDate = CONVERT(NVARCHAR(20), @AccessDate, 103)
SET @ExecString = 'sp_TAMS_TOA_QTS_Chk '+ '''' + @InchargeNRIC + ''', ''' + @QualDate + ''', ''' + @Line + ''', ''' + @QTSQualCode + ''''

INSERT INTO #tmpnric
EXEC(@ExecString)

SELECT @InChargeName = namestr,
	@InChargeStatus = qualstatus
FROM #tmpnric

DECLARE @QTSFinStatus NVARCHAR(20)
SET @QTSFinStatus = ''

DECLARE @QTSFinQualCode NVARCHAR(50)
SET @QTSFinQualCode = ''

IF @InChargeStatus	= 'InValid'
	BEGIN
		IF @AccessType = 'Protection'
			BEGIN
				TRUNCATE TABLE #tmpnric
				SET @InChargeName = ''
				SET @InChargeStatus = ''

				SET @ExecString = 'sp_TAMS_TOA_QTS_Chk '+ '''' + @InchargeNRIC + ''', ''' + @QualDate + ''', ''' + @Line + ''', ''' + @QTSQualCodeProt + ''''

				INSERT INTO #tmpnric
				EXEC(@ExecString)

				SELECT @InChargeName = namestr,
					@InChargeStatus = qualstatus
				FROM #tmpnric

				IF @InChargeStatus	= 'InValid'
					BEGIN
						SET @QTSFinStatus = 'InValid'
						SET @QTSFinQualCode = ''
					END
				ELSE
					BEGIN
						SET @QTSFinStatus = 'Valid'
						SET @QTSFinQualCode = @QTSQualCodeProt
					END
			END
		ELSE
			BEGIN
				SET @QTSFinStatus = 'InValid'
				SET @QTSFinQualCode = ''
			END
	END
ELSE
	BEGIN
		SET @QTSFinStatus = 'Valid'
		SET @QTSFinQualCode = @QTSQualCode
	END

DROP TABLE #tmpnric

--SELECT @QTSFinQualCode

IF @QTSFinStatus = 'InValid'
	BEGIN
		SET @Message = '1' -- >> Invalid Qualification
		SET @QTSQCode = ''
		SET @QTSLine = ''
	END
ELSE
	BEGIN

		-- >> Remove update of QTS time before calling QTS update // 05/09/2023
		--UPDATE TAMS_TOA
		--	SET UpdateQTSTime = GETDATE(),
		--		UpdatedOn = GETDATE(),
		--		UpdatedBy = @UserID
		--	WHERE TARId = @TARID

		--INSERT INTO TAMS_TOA_Audit
		--SELECT @UserID, GETDATE(), 'U', * FROM TAMS_TOA
		--	WHERE TARId = @TARID
		-- >> Remove update of QTS time before calling QTS update // 05/09/2023

		SET @Message = '0' -- >> Updated
		SET @QTSQCode = @QTSFinQualCode
		SET @QTSLine = @Line

		DECLARE @TAMSUser	NVARCHAR(500)
		SET @TAMSUser = ''
		SET @TAMSUser = 'TAMS-' + @UserID

		DECLARE @RetMsg NVARCHAR(500)
		SET @RetMsg = '1'
		-- >> EXEC [mssqldevpsvr1].[QTSDB].[dbo].[sp_api_tams_qts_upd_accessdate] @InchargeNRIC, @QTSFinQualCode, @Line, @UserID, @RetMsg OUTPUT
		EXEC [flexnetskgsvr].[QTSDB].[dbo].[sp_api_tams_qts_upd_accessdate] @InchargeNRIC, @QTSFinQualCode, @Line, @TAMSUser, @RetMsg OUTPUT
		--SELECT @RetMsg

		IF @RetMsg = ''
			BEGIN
				UPDATE TAMS_TOA
					SET UpdateQTSTime = GETDATE(),
						UpdatedOn = GETDATE(),
						UpdatedBy = @UserID
					WHERE TARId = @TARID

				INSERT INTO TAMS_TOA_Audit
				SELECT @UserID, GETDATE(), 'U', * FROM TAMS_TOA
					WHERE TARId = @TARID

				SET @Message = '0' -- >> Updated
			END
		ELSE
			BEGIN
				SET @Message = '2' -- >> Error Updating
			END

	END

DECLARE @ErrorMessage NVARCHAR(4000);
DECLARE @ErrorNumber INT;
DECLARE @ErrorSeverity INT;
DECLARE @ErrorState INT;

SET @ErrorMessage = '';
SET @ErrorNumber = 0;
SET @ErrorSeverity = 0;
SET @ErrorState = 0;

IF @@ERROR <> 0 BEGIN
	SET @Message = 'ERROR INSERTING INTO TAMS_TOA'

	SET @ErrorMessage = ERROR_MESSAGE();
    SET @ErrorNumber = ERROR_NUMBER();
    SET @ErrorSeverity = ERROR_SEVERITY();
    SET @ErrorState = ERROR_STATE();

	GOTO TRAP_ERROR
END

FORCE_EXIT_PROC:	
	IF @IntrnlTrans = 1 COMMIT TRAN
	RETURN @Message 

TRAP_ERROR:
	IF @IntrnlTrans = 1 ROLLBACK TRAN

	INSERT INTO TAMS_QTS_Error_Log
		(TARID, InchargeNRIC, QualCode, RailLine, UserID, ErrorDateTime, FullErrorMsg)
	VALUES
		(@TARID, dbo.EncryptString(@InchargeNRIC), @QTSFinQualCode, @Line, @TAMSUser, GETDATE(), @ErrorMessage)

	RETURN @Message

END
GO
/****** END PROCEDURE 307 ******/

/****** START PROCEDURE 308 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_RGS_Update_QTS_20230907
CREATE PROCEDURE  [dbo].[sp_TAMS_RGS_Update_QTS_20230907]
	@TARID			AS BIGINT,
	@InchargeNRIC	AS NVARCHAR(50),
	@UserID			AS NVARCHAR(500),
	@Message		AS NVARCHAR(500) = NULL OUTPUT,
	@QTSQCode		AS NVARCHAR(50) = NULL OUTPUT,
	@QTSLine		AS NVARCHAR(10) = NULL OUTPUT
AS

BEGIN

DECLARE	@IntrnlTrans	TINYINT

SELECT 	@IntrnlTrans 	= 0	

IF (@@TRANCOUNT = 0) 
BEGIN
	SET @IntrnlTrans = 1
	BEGIN TRAN
END

CREATE TABLE #tmpnric 
(id BIGINT IDENTITY(1,1) NOT NULL, 
nric NVARCHAR(50),
namestr NVARCHAR(500),
line NVARCHAR(50),
qualdate NVARCHAR(50),
qualcode NVARCHAR(100),
qualstatus NVARCHAR(100))

TRUNCATE TABLE #tmpnric

DECLARE @ExecString	NVARCHAR(MAX)
SET @ExecString = ''
