		DECLARE @TOAProtNotExec NVARCHAR(4000) -- >> List of Not Executed
		DECLARE @CancelPossCtr INT -- >> Cancelled -- TAR cancelled after registered to TOA
		DECLARE @CancelProtCtr INT -- >> Cancelled -- TAR cancelled after registered to TOA
		DECLARE @CancelPoss NVARCHAR(4000) -- >> List of Cancelled TAR
		DECLARE @CancelProt NVARCHAR(4000) -- >> List of Cancelled TAR
		DECLARE @ExtPossCtr INT -- >> Extended -- TOA surrendered after 0400
		DECLARE @ExtProtCtr INT -- >> Extended -- TOA surrendered after 0400
		DECLARE @ExtPoss NVARCHAR(4000) -- >> List of Extended
		DECLARE @ExtProt NVARCHAR(4000) -- >> List of Extended

	-- >> Booked
	SET @TARPossCtr = 0
	SET @TARPoss = ''

	-- >> Cursor TARNo ; Sep
	DECLARE @Cur11 CURSOR;
	DECLARE @C11TarNo	NVARCHAR(50),
		@C11ID			BIGINT

	SET @Cur11 = CURSOR FAST_FORWARD 
	FOR
		-- >> Cursor TARNo ; Sep
		SELECT DISTINCT a.Id, a.TARNo
			FROM TAMS_TAR a
				WHERE a.AccessDate = CONVERT(DATE, @StrAccDate, 103)
					AND a.AccessType = 'Possession'
					AND ((@Line = 'DTL' and  a.PowerOn = 0) or @Line = 'NEL')
					AND a.TARStatusId = CASE WHEN @Line = 'NEL' THEN 9 ELSE 8 END
					AND a.Line = @Line
					and a.TrackType = @TrackType
				ORDER BY a.Id
	OPEN @Cur11
	FETCH NEXT FROM @Cur11 INTO @C11ID, @C11TarNo
	WHILE @@FETCH_STATUS = 0 
		BEGIN
			SET @TARPossCtr = @TARPossCtr + 1
			IF @TARPoss = ''
				BEGIN
					SET @TARPoss = @C11TarNo
				END 
			ELSE
				BEGIN
					SET @TARPoss = @TARPoss + '; ' + @C11TarNo
				END
			FETCH NEXT FROM @Cur11 INTO @C11ID, @C11TarNo
		END 
