		SET @CancelProtCtr = 0
		SET @CancelPoss = ''
		SET @CancelProt = ''
		SET @ExtPossCtr = 0
		SET @ExtProtCtr = 0

		SELECT @TARPossCtr = COUNT(*)
			FROM TAMS_TAR a
				WHERE a.AccessDate = CONVERT(DATE, @StrAccDate, 103)
					AND a.AccessType = 'Possession'
					AND a.PowerOn = 0
					AND a.TARStatusId = CASE WHEN @Line = 'NEL' THEN 9 ELSE 8 END
					AND a.Line = @Line
					and a.TrackType = @TrackType

		SELECT @TARProtCtr = COUNT(*)
			FROM TAMS_TAR a
				WHERE a.AccessDate = CONVERT(DATE, @StrAccDate, 103)
					AND a.AccessType = 'Protection'
					AND a.PowerOn = 0
					AND a.TARStatusId = CASE WHEN @Line = 'NEL' THEN 9 ELSE 8 END
					AND a.Line = @Line
					and a.TrackType = @TrackType

		SELECT @TOAPossCtr = COUNT(*)
			FROM TAMS_TAR a, TAMS_TOA b
				WHERE a.AccessDate = CONVERT(DATE, @StrAccDate, 103)
					AND a.AccessType = 'Possession'
					AND a.PowerOn = 0
					AND a.TARStatusId = CASE WHEN @Line = 'NEL' THEN 9 ELSE 8 END
					AND a.Line = @Line
					and a.TrackType = @TrackType
					AND a.Id = b.TARId

		SELECT @TOAProtCtr = COUNT(*)
			FROM TAMS_TAR a, TAMS_TOA b
				WHERE a.AccessDate = CONVERT(DATE, @StrAccDate, 103)
					AND a.AccessType = 'Protection'
					AND a.PowerOn = 0
					AND a.TARStatusId = CASE WHEN @Line = 'NEL' THEN 9 ELSE 8 END
					AND a.Line = @Line
					and a.TrackType = @TrackType
					AND a.Id = b.TARId

	SET @CancelProtCtr = 0
