-- PROCEDURE NAME: dbo.sp_TAMS_TB_Gen_Summary_20230904_M
CREATE PROCEDURE  [dbo].[sp_TAMS_TB_Gen_Summary_20230904_M]
	@Line			AS NVARCHAR(10) = NULL,
	@TrackType		AS NVARCHAR(50) = NULL,
	@AccessDateFrom	AS NVARCHAR(20) = NULL,
	@AccessDateTo	AS NVARCHAR(20) = NULL,
	@AccessType		AS NVARCHAR(20) = NULL

AS

BEGIN

	IF @Line = 'DTL'
		BEGIN
			-- >> 0
			SELECT CONVERT(NVARCHAR(20), CONVERT(DATETIME, a.AccessDate, 101), 105) AS [Access Date], 
				a.TARNo AS [TAR ID], 
				dbo.TAMS_Get_ES_NoBufferZone(a.Id) AS [Electrical Section], 
				LTRIM(RTRIM(a.DescOfWork)) AS [Nature of Work], 
				REPLACE(LTRIM(RTRIM(a.ARRemark)), '"', '') AS [Remarks]
			FROM TAMS_TAR a, TAMS_TAR_AccessReq b, TAMS_Access_Requirement c
				WHERE CONVERT(DATETIME, a.AccessDate, 103) BETWEEN CONVERT(DATETIME, @AccessDateFrom, 103) AND CONVERT(DATETIME, @AccessDateTo, 103) 
					AND a.Id = b.TarId
					AND a.TARStatusId = 8
					AND (a.AccessType = @AccessType OR ISNULL(@AccessType, '') = '')
					AND b.IsSelected = 1
					AND b.OperationRequirement = c.ID
					AND c.OperationRequirement = 'Power Off With Rack Out / 22KV Isolation'
					AND a.Line = 'DTL'
					AND a.TrackType = @TrackType
			ORDER BY CONVERT(DATETIME, a.AccessDate, 101), a.TARNo

			-- > 1
			SELECT CONVERT(NVARCHAR(20), CONVERT(DATETIME, a.AccessDate, 101), 105) AS [Access Date], 
				a.TARNo AS [TAR ID], 
				dbo.TAMS_Get_ES_NoBufferZone(a.Id) AS [Electrical Section], 
				LTRIM(RTRIM(a.DescOfWork)) AS [Nature of Work], 
				REPLACE(LTRIM(RTRIM(a.ARRemark)), '"', '') AS [Remarks]
			FROM TAMS_TAR a, TAMS_TAR_AccessReq b, TAMS_Access_Requirement c
				WHERE CONVERT(DATETIME, a.AccessDate, 103) BETWEEN CONVERT(DATETIME, @AccessDateFrom, 103) AND CONVERT(DATETIME, @AccessDateTo, 103) 
					AND a.Id = b.TarId
					AND a.TARStatusId = 8
					AND (a.AccessType = @AccessType OR ISNULL(@AccessType, '') = '')
					AND b.IsSelected = 1
					AND b.OperationRequirement = c.ID
					AND c.OperationRequirement = 'Use of Tunnel Ventilation'
					AND a.Line = 'DTL'
					AND a.TrackType = @TrackType
			ORDER BY CONVERT(DATETIME, a.AccessDate, 101), a.TARNo

			-- > 2
			SELECT CONVERT(NVARCHAR(20), CONVERT(DATETIME, a.AccessDate, 101), 105) AS [Access Date], 
				a.TARNo AS [TAR ID], 
				dbo.TAMS_Get_ES_NoBufferZone(a.Id) AS [Electrical Section], 
				LTRIM(RTRIM(a.DescOfWork)) AS [Nature of Work], 
				REPLACE(LTRIM(RTRIM(a.ARRemark)), '"', '') AS [Remarks]
			FROM TAMS_TAR a
				WHERE CONVERT(DATETIME, a.AccessDate, 103) BETWEEN CONVERT(DATETIME, @AccessDateFrom, 103) AND CONVERT(DATETIME, @AccessDateTo, 103)  
					AND a.TARStatusId = 8
					AND (a.AccessType = @AccessType OR ISNULL(@AccessType, '') = '')
					AND a.Company LIKE '%DTL SIG%'
					AND a.Line = 'DTL'
					AND a.TrackType = @TrackType
			ORDER BY CONVERT(DATETIME, a.AccessDate, 101), a.TARNo

			-- >> 3
			SELECT CONVERT(NVARCHAR(20), CONVERT(DATETIME, a.AccessDate, 101), 105) AS [Access Date], 
				a.TARNo AS [TAR ID], 
				dbo.TAMS_Get_ES_NoBufferZone(a.Id) AS [Electrical Section], 
				LTRIM(RTRIM(a.DescOfWork)) AS [Nature of Work], 
				REPLACE(LTRIM(RTRIM(a.ARRemark)), '"', '') AS [Remarks]
			FROM TAMS_TAR a
				WHERE CONVERT(DATETIME, a.AccessDate, 103) BETWEEN CONVERT(DATETIME, @AccessDateFrom, 103) AND CONVERT(DATETIME, @AccessDateTo, 103)  
					AND a.TARStatusId = 8
					AND (a.AccessType = @AccessType OR ISNULL(@AccessType, '') = '')
					AND a.Company LIKE '%DTL POWER%'
					AND a.Line = 'DTL'
					AND a.TrackType = @TrackType
			ORDER BY CONVERT(DATETIME, a.AccessDate, 101), a.TARNo

			-- >> 4
			SELECT CONVERT(NVARCHAR(20), CONVERT(DATETIME, a.AccessDate, 101), 105) AS [Access Date], 
				a.TARNo AS [TAR ID], 
				dbo.TAMS_Get_ES_NoBufferZone(a.Id) AS [Electrical Section], 
				LTRIM(RTRIM(a.DescOfWork)) AS [Nature of Work], 
				REPLACE(LTRIM(RTRIM(a.ARRemark)), '"', '') AS [Remarks]
			FROM TAMS_TAR a
				WHERE CONVERT(DATETIME, a.AccessDate, 103) BETWEEN CONVERT(DATETIME, @AccessDateFrom, 103) AND CONVERT(DATETIME, @AccessDateTo, 103)  
					AND a.TARStatusId = 8
					AND (a.AccessType = @AccessType OR ISNULL(@AccessType, '') = '')
					AND a.Company LIKE '%DTL COMMS%'
					AND a.Line = 'DTL'
					AND a.TrackType = @TrackType
			ORDER BY CONVERT(DATETIME, a.AccessDate, 101), a.TARNo

			-- >> 5
			SELECT CONVERT(NVARCHAR(20), CONVERT(DATETIME, a.AccessDate, 101), 105) AS [Access Date], 
				a.TARNo AS [TAR ID], 
				dbo.TAMS_Get_Station(a.Id) AS [Access Stations], 
				LTRIM(RTRIM(a.DescOfWork)) AS [Nature of Work], 
				REPLACE(LTRIM(RTRIM(a.ARRemark)), '"', '') AS [Remarks]
			FROM TAMS_TAR a
				WHERE CONVERT(DATETIME, a.AccessDate, 103) BETWEEN CONVERT(DATETIME, @AccessDateFrom, 103) AND CONVERT(DATETIME, @AccessDateTo, 103)  
					AND a.TARStatusId = 8
					AND (a.AccessType = @AccessType OR ISNULL(@AccessType, '') = '')
					AND a.Company LIKE '%DTL COMMS%'
					AND a.Line = 'DTL'
					AND a.TrackType = @TrackType
			ORDER BY CONVERT(DATETIME, a.AccessDate, 101), a.TARNo

			-- >> 6
			SELECT CONVERT(NVARCHAR(20), CONVERT(DATETIME, a.AccessDate, 101), 105) AS [Access Date], 
				a.TARNo AS [TAR ID], 
				dbo.TAMS_Get_ES_NoBufferZone(a.Id) AS [Electrical Section], 
				LTRIM(RTRIM(a.DescOfWork)) AS [Nature of Work], 
				REPLACE(LTRIM(RTRIM(a.ARRemark)), '"', '') AS [Remarks]
			FROM TAMS_TAR a
				WHERE CONVERT(DATETIME, a.AccessDate, 103) BETWEEN CONVERT(DATETIME, @AccessDateFrom, 103) AND CONVERT(DATETIME, @AccessDateTo, 103)  
					AND a.TARStatusId = 8
					AND (a.AccessType = @AccessType OR ISNULL(@AccessType, '') = '')
					AND (a.Company LIKE '%DTL Pway & FM%' OR a.Company LIKE '%DTL Pway & CS%' OR a.Company LIKE '%DTL FM%')
					AND a.Line = 'DTL'
					AND a.TrackType = @TrackType
			ORDER BY CONVERT(DATETIME, a.AccessDate, 101), a.TARNo

			-- >> 7
			SELECT CONVERT(NVARCHAR(20), CONVERT(DATETIME, a.AccessDate, 101), 105) AS [Access Date], 
				a.TARNo AS [TAR ID], 
				dbo.TAMS_Get_ES_NoBufferZone(a.Id) AS [Electrical Section], 
				LTRIM(RTRIM(a.DescOfWork)) AS [Nature of Work], 
				REPLACE(LTRIM(RTRIM(a.ARRemark)), '"', '') AS [Remarks]
			FROM TAMS_TAR a
				WHERE CONVERT(DATETIME, a.AccessDate, 103) BETWEEN CONVERT(DATETIME, @AccessDateFrom, 103) AND CONVERT(DATETIME, @AccessDateTo, 103)  
					AND a.TARStatusId = 8
					AND (a.AccessType = @AccessType OR ISNULL(@AccessType, '') = '')
					AND (a.Company LIKE '%DTL RS%')
					AND a.Line = 'DTL'
					AND a.TrackType = @TrackType
			ORDER BY CONVERT(DATETIME, a.AccessDate, 101), a.TARNo

			-- >> 8
			SELECT CONVERT(NVARCHAR(20), CONVERT(DATETIME, a.AccessDate, 101), 105) AS [Access Date], 
				a.TARNo AS [TAR ID], 
				dbo.TAMS_Get_ES_NoBufferZone(a.Id) AS [Electrical Section], 
				LTRIM(RTRIM(a.DescOfWork)) AS [Nature of Work], 
				REPLACE(LTRIM(RTRIM(a.ARRemark)), '"', '') AS [Remarks]
			FROM TAMS_TAR a
				WHERE CONVERT(DATETIME, a.AccessDate, 103) BETWEEN CONVERT(DATETIME, @AccessDateFrom, 103) AND CONVERT(DATETIME, @AccessDateTo, 103)  
					AND a.TARStatusId = 8
					AND (a.AccessType = @AccessType OR ISNULL(@AccessType, '') = '')
					AND (a.Company LIKE '%DTL Operations%' OR a.Company LIKE '%DTL Training%' OR a.Company LIKE '%DTL OPS%')
					AND a.Line = 'DTL'
					AND a.TrackType = @TrackType
			ORDER BY CONVERT(DATETIME, a.AccessDate, 101), a.TARNo

			-- >> 9
			SELECT CONVERT(NVARCHAR(20), CONVERT(DATETIME, a.AccessDate, 101), 105) AS [Access Date], 
				a.TARNo AS [TAR ID],  
				dbo.TAMS_Get_ES_NoBufferZone(a.Id) AS [Electrical Section], 
				a.Company AS [Company/Dept], 
				a.Name AS [Name],
				LTRIM(RTRIM(a.DescOfWork)) AS [Nature of Work], 
				REPLACE(LTRIM(RTRIM(a.ARRemark)), '"', '') AS [Remarks]
			FROM TAMS_TAR a
				WHERE CONVERT(DATETIME, a.AccessDate, 103) BETWEEN CONVERT(DATETIME, @AccessDateFrom, 103) AND CONVERT(DATETIME, @AccessDateTo, 103)  
					AND a.TARStatusId = 8
					AND (a.AccessType = @AccessType OR ISNULL(@AccessType, '') = '')
					AND (a.Company NOT IN (SELECT DISTINCT ParaValue2 
												FROM TAMS_Parameters
													WHERE ParaType = 'S'
														AND ParaCode = 'Company'
														AND ParaValue1 = a.Line))
					AND a.Line = 'DTL'
					AND a.TrackType = @TrackType
			ORDER BY CONVERT(DATETIME, a.AccessDate, 101), a.TARNo
		END
	ELSE IF @Line = 'NEL'
		BEGIN
			-- >> 0
			SELECT CONVERT(NVARCHAR(20), AccessDate, 103) + ' ' + SUBSTRING(DATENAME(dw, AccessDate), 1, 3)  AS [Date], 
				a.TARNo AS [TAR ID], 
				dbo.TAMS_Get_ES_NoBufferZone(a.Id) AS [Power Section], -- >> Create new function
				CAST(REPLACE(SUBSTRING(CONVERT(NVARCHAR(20), AccessTimeFrom, 108), 1, 5), ':', '') + 'hrs' AS NVARCHAR(20)) AS [From], 
				CAST(REPLACE(SUBSTRING(CONVERT(NVARCHAR(20), AccessTimeTo, 108), 1, 5), ':', '') + 'hrs' AS NVARCHAR(20)) AS [To], 
				LTRIM(RTRIM(a.DescOfWork)) AS [Activities]
			FROM TAMS_TAR a, TAMS_TAR_AccessReq b, TAMS_Access_Requirement c
				WHERE CONVERT(DATETIME, a.AccessDate, 103) BETWEEN CONVERT(DATETIME, @AccessDateFrom, 103) AND CONVERT(DATETIME, @AccessDateTo, 103) 
					AND a.Id = b.TarId
					AND a.TARStatusId = 8
					AND (a.AccessType = @AccessType OR ISNULL(@AccessType, '') = '')
					AND b.IsSelected = 1
					AND b.OperationRequirement = c.ID
					AND c.OperationRequirement = 'Power Off With Rack Out / 22KV Isolation'
					AND a.Line = 'NEL'
					AND a.TrackType = @TrackType
			ORDER BY CONVERT(DATETIME, a.AccessDate, 101), a.TARNo

			-- >> 1
			SELECT CONVERT(NVARCHAR(20), AccessDate, 103) + ' ' + SUBSTRING(DATENAME(dw, AccessDate), 1, 3)  AS [Date], 
				CAST(REPLACE(SUBSTRING(CONVERT(NVARCHAR(20), AccessTimeFrom, 108), 1, 5), ':', '') + 'hrs' AS NVARCHAR(20)) AS [Time From], 
				CAST(REPLACE(SUBSTRING(CONVERT(NVARCHAR(20), AccessTimeTo, 108), 1, 5), ':', '') + 'hrs' AS NVARCHAR(20)) AS [Time To], 
				a.TARNo AS [TAR ID], 
				dbo.TAMS_Get_Station_Dir(a.Id, 'Min') AS [Location From],
				dbo.TAMS_Get_Station_Dir(a.Id, 'Max') AS [Location To],
				LTRIM(RTRIM(a.DescOfWork)) AS [Activities]
			FROM TAMS_TAR a
				WHERE CONVERT(DATETIME, a.AccessDate, 103) BETWEEN CONVERT(DATETIME, @AccessDateFrom, 103) AND CONVERT(DATETIME, @AccessDateTo, 103) 
					AND a.TARStatusId = 8
					AND (a.AccessType = @AccessType OR ISNULL(@AccessType, '') = '')
					AND a.Is13ASocket = 1
					AND a.Line = 'NEL'
					AND a.TrackType = @TrackType
			ORDER BY CONVERT(DATETIME, a.AccessDate, 101), a.TARNo

			-- >> 2
			SELECT a.TARNo AS [TAR ID], 
				a.Company AS [Company],
				LTRIM(RTRIM(a.DescOfWork)) AS [Activities],
				a.TVFMode AS [TVF Request], -- >> TVF Running Mode -- Clarify with Adeline
				dbo.TAMS_Get_TVF_Station(a.Id) AS [Direction], -- >> Min to Max Station
				CAST(CONVERT(NVARCHAR(20), AccessDate, 103) AS NVARCHAR(20)) AS [Date From], 
				CAST(REPLACE(SUBSTRING(CONVERT(NVARCHAR(20), AccessTimeFrom, 108), 1, 5), ':', '') + 'hrs' AS NVARCHAR(20)) AS [Time From], 
				CAST(CONVERT(NVARCHAR(20), AccessDate, 103) AS NVARCHAR(20)) AS [Date To], 
				CAST(REPLACE(SUBSTRING(CONVERT(NVARCHAR(20), AccessTimeTo, 108), 1, 5), ':', '') + 'hrs' AS NVARCHAR(20)) AS [Time To]
			FROM TAMS_TAR a, TAMS_TAR_AccessReq b, TAMS_Access_Requirement c
				WHERE CONVERT(DATETIME, a.AccessDate, 103) BETWEEN CONVERT(DATETIME, @AccessDateFrom, 103) AND CONVERT(DATETIME, @AccessDateTo, 103) 
					AND a.Id = b.TarId
					AND a.TARStatusId = 8
					AND (a.AccessType = @AccessType OR ISNULL(@AccessType, '') = '')
					AND b.IsSelected = 1
					AND b.OperationRequirement = c.ID
					AND c.OperationRequirement = 'Use of Tunnel Ventilation'
					AND a.Line = 'NEL'
					AND a.TrackType = @TrackType
			ORDER BY CONVERT(DATETIME, a.AccessDate, 101), a.TARNo

			-- >> 3
			SELECT a.TARNo AS [TAR No], 
				CONVERT(NVARCHAR(20), AccessDate, 103) + ' ' + SUBSTRING(DATENAME(dw, AccessDate), 1, 3)  AS [Date],  
				dbo.TAMS_Get_Station(a.Id) AS [Stations], 
				LTRIM(RTRIM(a.DescOfWork)) AS [Nature of Work], 
				CAST(REPLACE(SUBSTRING(CONVERT(NVARCHAR(20), AccessTimeFrom, 108), 1, 5), ':', '') + 'hrs' AS NVARCHAR(20)) + ' to ' +
				CAST(REPLACE(SUBSTRING(CONVERT(NVARCHAR(20), AccessTimeTo, 108), 1, 5), ':', '') + 'hrs' AS NVARCHAR(20)) AS [Time], 
				REPLACE(LTRIM(RTRIM(a.ARRemark)), '"', '') AS [Remarks]
			FROM TAMS_TAR a
				WHERE CONVERT(DATETIME, a.AccessDate, 103) BETWEEN CONVERT(DATETIME, @AccessDateFrom, 103) AND CONVERT(DATETIME, @AccessDateTo, 103)  
					AND a.TARStatusId = 8
					AND (a.AccessType = @AccessType OR ISNULL(@AccessType, '') = '')
					-- >> AND a.Company LIKE '%NEL Sig%'
					AND a.Company = 'NEL Signalling'
					AND a.Line = 'NEL'
					AND a.TrackType = @TrackType
			ORDER BY CONVERT(DATETIME, a.AccessDate, 101), a.TARNo

			-- >> 4
			-- 'NEL ISCS and Systems'
			SELECT ROW_NUMBER() OVER(ORDER BY CONVERT(DATETIME, a.AccessDate, 101), a.TARNo) AS [S/No],
				a.TARNo AS [TAR No], 
				CONVERT(NVARCHAR(20), AccessDate, 103)  AS [Date],  
				LTRIM(RTRIM(a.DescOfWork)) AS [Nature of Work], 
				a.Company AS [Department],
				dbo.TAMS_Get_Station(a.Id) AS [Stations], 
				dbo.TAMS_Get_ES_NoBufferZone(a.Id) AS [Track Sector], 
				CAST(REPLACE(SUBSTRING(CONVERT(NVARCHAR(20), AccessTimeFrom, 108), 1, 5), ':', '') + 'hrs' AS NVARCHAR(20)) + ' to ' +
				CAST(REPLACE(SUBSTRING(CONVERT(NVARCHAR(20), AccessTimeTo, 108), 1, 5), ':', '') + 'hrs' AS NVARCHAR(20)) AS [Time], 
				REPLACE(LTRIM(RTRIM(a.ARRemark)), '"', '') AS [Remarks]
			FROM TAMS_TAR a
				WHERE CONVERT(DATETIME, a.AccessDate, 103) BETWEEN CONVERT(DATETIME, @AccessDateFrom, 103) AND CONVERT(DATETIME, @AccessDateTo, 103)  
					AND a.TARStatusId = 8
					AND (a.AccessType = @AccessType OR ISNULL(@AccessType, '') = '')
					-- >> AND a.Company LIKE '%NEL Sig%'
					AND a.Company = 'NEL ISCS and Systems'
					AND a.Line = 'NEL'
					AND a.TrackType = @TrackType
			ORDER BY CONVERT(DATETIME, a.AccessDate, 101), a.TARNo

			-- >> 5
			-- 'NEL ISCS and Systems'
			SELECT ROW_NUMBER() OVER(ORDER BY CONVERT(DATETIME, a.AccessDate, 101), a.TARNo) AS [S/No],
				a.TARNo AS [TAR No], 
				CONVERT(NVARCHAR(20), AccessDate, 103)  AS [Date],  
				LTRIM(RTRIM(a.DescOfWork)) AS [Nature of Work], 
				a.Company AS [Department],
				dbo.TAMS_Get_Station(a.Id) AS [Stations], 
				dbo.TAMS_Get_ES_NoBufferZone(a.Id) AS [Track Sector], 
				CAST(REPLACE(SUBSTRING(CONVERT(NVARCHAR(20), AccessTimeFrom, 108), 1, 5), ':', '') + 'hrs' AS NVARCHAR(20)) + ' to ' +
				CAST(REPLACE(SUBSTRING(CONVERT(NVARCHAR(20), AccessTimeTo, 108), 1, 5), ':', '') + 'hrs' AS NVARCHAR(20)) AS [Time], 
				REPLACE(LTRIM(RTRIM(a.ARRemark)), '"', '') AS [Remarks]
			FROM TAMS_TAR a
				WHERE CONVERT(DATETIME, a.AccessDate, 103) BETWEEN CONVERT(DATETIME, @AccessDateFrom, 103) AND CONVERT(DATETIME, @AccessDateTo, 103)  
					AND a.TARStatusId = 8
					AND (a.AccessType = @AccessType OR ISNULL(@AccessType, '') = '')
					AND a.Company = 'NEL Communications'
					AND a.Line = 'NEL'
					AND a.TrackType = @TrackType
			ORDER BY CONVERT(DATETIME, a.AccessDate, 101), a.TARNo

		END

END
GO
/****** END PROCEDURE 333 ******/

/****** START PROCEDURE 334 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_TB_Gen_Summary20250120
CREATE PROCEDURE  [dbo].[sp_TAMS_TB_Gen_Summary20250120]
	@Line			AS NVARCHAR(10) = NULL,
	@TrackType		AS NVARCHAR(50) = NULL,
	@AccessDateFrom	AS NVARCHAR(20) = NULL,
	@AccessDateTo	AS NVARCHAR(20) = NULL,
	@AccessType		AS NVARCHAR(20) = NULL

AS

BEGIN

	IF @Line = 'DTL'
		BEGIN
			-- >> 0
			SELECT CONVERT(NVARCHAR(20), CONVERT(DATETIME, a.AccessDate, 101), 105) AS [Access Date], 
				a.TARNo AS [TAR ID], 
				dbo.TAMS_Get_ES_NoBufferZone(a.Id) AS [Electrical Section], 
				LTRIM(RTRIM(a.DescOfWork)) AS [Nature of Work], 
				REPLACE(LTRIM(RTRIM(a.ARRemark)), '"', '') AS [Remarks]
			FROM TAMS_TAR a, TAMS_TAR_AccessReq b, TAMS_Access_Requirement c
				WHERE CONVERT(DATETIME, a.AccessDate, 103) BETWEEN CONVERT(DATETIME, @AccessDateFrom, 103) AND CONVERT(DATETIME, @AccessDateTo, 103) 
					AND a.Id = b.TarId
					AND a.TARStatusId = 8
					AND (a.AccessType = @AccessType OR ISNULL(@AccessType, '') = '')
					AND b.IsSelected = 1
					AND b.OperationRequirement = c.ID
					AND c.OperationRequirement = 'Power Off With Rack Out / 22KV Isolation'
					AND a.Line = 'DTL'
					AND a.TrackType = @TrackType
			ORDER BY CONVERT(DATETIME, a.AccessDate, 101), a.TARNo

			-- > 1
			SELECT CONVERT(NVARCHAR(20), CONVERT(DATETIME, a.AccessDate, 101), 105) AS [Access Date], 
				a.TARNo AS [TAR ID], 
				dbo.TAMS_Get_ES_NoBufferZone(a.Id) AS [Electrical Section], 
				LTRIM(RTRIM(a.DescOfWork)) AS [Nature of Work], 
				REPLACE(LTRIM(RTRIM(a.ARRemark)), '"', '') AS [Remarks]
			FROM TAMS_TAR a, TAMS_TAR_AccessReq b, TAMS_Access_Requirement c
				WHERE CONVERT(DATETIME, a.AccessDate, 103) BETWEEN CONVERT(DATETIME, @AccessDateFrom, 103) AND CONVERT(DATETIME, @AccessDateTo, 103) 
					AND a.Id = b.TarId
					AND a.TARStatusId = 8
					AND (a.AccessType = @AccessType OR ISNULL(@AccessType, '') = '')
					AND b.IsSelected = 1
					AND b.OperationRequirement = c.ID
					AND c.OperationRequirement = 'Use of Tunnel Ventilation'
					AND a.Line = 'DTL'
					AND a.TrackType = @TrackType
			ORDER BY CONVERT(DATETIME, a.AccessDate, 101), a.TARNo

			-- > 2
			SELECT CONVERT(NVARCHAR(20), CONVERT(DATETIME, a.AccessDate, 101), 105) AS [Access Date], 
				a.TARNo AS [TAR ID], 
				dbo.TAMS_Get_ES_NoBufferZone(a.Id) AS [Electrical Section], 
				LTRIM(RTRIM(a.DescOfWork)) AS [Nature of Work], 
				REPLACE(LTRIM(RTRIM(a.ARRemark)), '"', '') AS [Remarks]
			FROM TAMS_TAR a
				WHERE CONVERT(DATETIME, a.AccessDate, 103) BETWEEN CONVERT(DATETIME, @AccessDateFrom, 103) AND CONVERT(DATETIME, @AccessDateTo, 103)  
					AND a.TARStatusId = 8
					AND (a.AccessType = @AccessType OR ISNULL(@AccessType, '') = '')
					AND a.Company LIKE '%DTL SIG%'
					AND a.Line = 'DTL'
					AND a.TrackType = @TrackType
			ORDER BY CONVERT(DATETIME, a.AccessDate, 101), a.TARNo

			-- >> 3
			SELECT CONVERT(NVARCHAR(20), CONVERT(DATETIME, a.AccessDate, 101), 105) AS [Access Date], 
				a.TARNo AS [TAR ID], 
				dbo.TAMS_Get_ES_NoBufferZone(a.Id) AS [Electrical Section], 
				LTRIM(RTRIM(a.DescOfWork)) AS [Nature of Work], 
				REPLACE(LTRIM(RTRIM(a.ARRemark)), '"', '') AS [Remarks]
			FROM TAMS_TAR a
				WHERE CONVERT(DATETIME, a.AccessDate, 103) BETWEEN CONVERT(DATETIME, @AccessDateFrom, 103) AND CONVERT(DATETIME, @AccessDateTo, 103)  
					AND a.TARStatusId = 8
					AND (a.AccessType = @AccessType OR ISNULL(@AccessType, '') = '')
					AND a.Company LIKE '%DTL POWER%'
					AND a.Line = 'DTL'
					AND a.TrackType = @TrackType
			ORDER BY CONVERT(DATETIME, a.AccessDate, 101), a.TARNo

			-- >> 4
			SELECT CONVERT(NVARCHAR(20), CONVERT(DATETIME, a.AccessDate, 101), 105) AS [Access Date], 
				a.TARNo AS [TAR ID], 
				dbo.TAMS_Get_ES_NoBufferZone(a.Id) AS [Electrical Section], 
				LTRIM(RTRIM(a.DescOfWork)) AS [Nature of Work], 
				REPLACE(LTRIM(RTRIM(a.ARRemark)), '"', '') AS [Remarks]
			FROM TAMS_TAR a
				WHERE CONVERT(DATETIME, a.AccessDate, 103) BETWEEN CONVERT(DATETIME, @AccessDateFrom, 103) AND CONVERT(DATETIME, @AccessDateTo, 103)  
					AND a.TARStatusId = 8
					AND (a.AccessType = @AccessType OR ISNULL(@AccessType, '') = '')
					AND a.Company LIKE '%DTL COMMS%'
					AND a.Line = 'DTL'
					AND a.TrackType = @TrackType
			ORDER BY CONVERT(DATETIME, a.AccessDate, 101), a.TARNo

			-- >> 5
			SELECT CONVERT(NVARCHAR(20), CONVERT(DATETIME, a.AccessDate, 101), 105) AS [Access Date], 
				a.TARNo AS [TAR ID], 
				dbo.TAMS_Get_Station(a.Id) AS [Access Stations], 
				LTRIM(RTRIM(a.DescOfWork)) AS [Nature of Work], 
				REPLACE(LTRIM(RTRIM(a.ARRemark)), '"', '') AS [Remarks]
			FROM TAMS_TAR a
				WHERE CONVERT(DATETIME, a.AccessDate, 103) BETWEEN CONVERT(DATETIME, @AccessDateFrom, 103) AND CONVERT(DATETIME, @AccessDateTo, 103)  
					AND a.TARStatusId = 8
					AND (a.AccessType = @AccessType OR ISNULL(@AccessType, '') = '')
					AND a.Company LIKE '%DTL COMMS%'
					AND a.Line = 'DTL'
					AND a.TrackType = @TrackType
			ORDER BY CONVERT(DATETIME, a.AccessDate, 101), a.TARNo

			-- >> 6
			SELECT CONVERT(NVARCHAR(20), CONVERT(DATETIME, a.AccessDate, 101), 105) AS [Access Date], 
				a.TARNo AS [TAR ID], 
				dbo.TAMS_Get_ES_NoBufferZone(a.Id) AS [Electrical Section], 
				LTRIM(RTRIM(a.DescOfWork)) AS [Nature of Work], 
				REPLACE(LTRIM(RTRIM(a.ARRemark)), '"', '') AS [Remarks]
			FROM TAMS_TAR a
				WHERE CONVERT(DATETIME, a.AccessDate, 103) BETWEEN CONVERT(DATETIME, @AccessDateFrom, 103) AND CONVERT(DATETIME, @AccessDateTo, 103)  
					AND a.TARStatusId = 8
					AND (a.AccessType = @AccessType OR ISNULL(@AccessType, '') = '')
					AND (a.Company LIKE '%DTL Pway & FM%' OR a.Company LIKE '%DTL Pway & CS%' OR a.Company LIKE '%DTL FM%')
					AND a.Line = 'DTL'
					AND a.TrackType = @TrackType
			ORDER BY CONVERT(DATETIME, a.AccessDate, 101), a.TARNo

			-- >> 7
			SELECT CONVERT(NVARCHAR(20), CONVERT(DATETIME, a.AccessDate, 101), 105) AS [Access Date], 
				a.TARNo AS [TAR ID], 
				dbo.TAMS_Get_ES_NoBufferZone(a.Id) AS [Electrical Section], 
				LTRIM(RTRIM(a.DescOfWork)) AS [Nature of Work], 
				REPLACE(LTRIM(RTRIM(a.ARRemark)), '"', '') AS [Remarks]
			FROM TAMS_TAR a
				WHERE CONVERT(DATETIME, a.AccessDate, 103) BETWEEN CONVERT(DATETIME, @AccessDateFrom, 103) AND CONVERT(DATETIME, @AccessDateTo, 103)  
					AND a.TARStatusId = 8
					AND (a.AccessType = @AccessType OR ISNULL(@AccessType, '') = '')
					AND (a.Company LIKE '%DTL RS%')
					AND a.Line = 'DTL'
					AND a.TrackType = @TrackType
			ORDER BY CONVERT(DATETIME, a.AccessDate, 101), a.TARNo

			-- >> 8
			SELECT CONVERT(NVARCHAR(20), CONVERT(DATETIME, a.AccessDate, 101), 105) AS [Access Date], 
				a.TARNo AS [TAR ID], 
				dbo.TAMS_Get_ES_NoBufferZone(a.Id) AS [Electrical Section], 
				LTRIM(RTRIM(a.DescOfWork)) AS [Nature of Work], 
				REPLACE(LTRIM(RTRIM(a.ARRemark)), '"', '') AS [Remarks]
			FROM TAMS_TAR a
				WHERE CONVERT(DATETIME, a.AccessDate, 103) BETWEEN CONVERT(DATETIME, @AccessDateFrom, 103) AND CONVERT(DATETIME, @AccessDateTo, 103)  
					AND a.TARStatusId = 8
					AND (a.AccessType = @AccessType OR ISNULL(@AccessType, '') = '')
					AND (a.Company LIKE '%DTL Operations%' OR a.Company LIKE '%DTL Training%' OR a.Company LIKE '%DTL OPS%')
					AND a.Line = 'DTL'
					AND a.TrackType = @TrackType
			ORDER BY CONVERT(DATETIME, a.AccessDate, 101), a.TARNo

			-- >> 9
			SELECT CONVERT(NVARCHAR(20), CONVERT(DATETIME, a.AccessDate, 101), 105) AS [Access Date], 
				a.TARNo AS [TAR ID],  
				dbo.TAMS_Get_ES_NoBufferZone(a.Id) AS [Electrical Section], 
				a.Company AS [Company/Dept], 
				a.Name AS [Name],
				LTRIM(RTRIM(a.DescOfWork)) AS [Nature of Work], 
				REPLACE(LTRIM(RTRIM(a.ARRemark)), '"', '') AS [Remarks]
			FROM TAMS_TAR a
				WHERE CONVERT(DATETIME, a.AccessDate, 103) BETWEEN CONVERT(DATETIME, @AccessDateFrom, 103) AND CONVERT(DATETIME, @AccessDateTo, 103)  
					AND a.TARStatusId = 8
					AND (a.AccessType = @AccessType OR ISNULL(@AccessType, '') = '')
					AND (a.Company NOT IN (SELECT DISTINCT ParaValue2 
												FROM TAMS_Parameters
													WHERE ParaType = 'S'
														AND ParaCode = 'Company'
														AND ParaValue1 = a.Line))
					AND a.Line = 'DTL'
					AND a.TrackType = @TrackType
			ORDER BY CONVERT(DATETIME, a.AccessDate, 101), a.TARNo
		END
	ELSE IF @Line = 'NEL'
		BEGIN
			-- >> 0
			SELECT CONVERT(NVARCHAR(20), AccessDate, 103) + ' ' + SUBSTRING(DATENAME(dw, AccessDate), 1, 3)  AS [Date], 
				a.TARNo AS [TAR ID], 
				dbo.TAMS_Get_ES_NoBufferZone(a.Id) AS [Power Section], -- >> Create new function
				CAST(REPLACE(SUBSTRING(CONVERT(NVARCHAR(20), AccessTimeFrom, 108), 1, 5), ':', '') + 'hrs' AS NVARCHAR(20)) AS [From], 
				CAST(REPLACE(SUBSTRING(CONVERT(NVARCHAR(20), AccessTimeTo, 108), 1, 5), ':', '') + 'hrs' AS NVARCHAR(20)) AS [To], 
				LTRIM(RTRIM(a.DescOfWork)) AS [Activities]
			FROM TAMS_TAR a, TAMS_TAR_AccessReq b, TAMS_Access_Requirement c
				WHERE CONVERT(DATETIME, a.AccessDate, 103) BETWEEN CONVERT(DATETIME, @AccessDateFrom, 103) AND CONVERT(DATETIME, @AccessDateTo, 103) 
					AND a.Id = b.TarId
					AND a.TARStatusId = 9
					AND (a.AccessType = @AccessType OR ISNULL(@AccessType, '') = '')
					AND b.IsSelected = 1
					AND b.OperationRequirement = c.ID
					AND c.OperationRequirement = 'Power Off With Rack Out / 22KV Isolation'
					AND a.Line = 'NEL'
					AND a.TrackType = @TrackType
			ORDER BY CONVERT(DATETIME, a.AccessDate, 101), a.TARNo

			-- >> 1
			SELECT CONVERT(NVARCHAR(20), AccessDate, 103) + ' ' + SUBSTRING(DATENAME(dw, AccessDate), 1, 3)  AS [Date], 
				CAST(REPLACE(SUBSTRING(CONVERT(NVARCHAR(20), AccessTimeFrom, 108), 1, 5), ':', '') + 'hrs' AS NVARCHAR(20)) AS [Time From], 
				CAST(REPLACE(SUBSTRING(CONVERT(NVARCHAR(20), AccessTimeTo, 108), 1, 5), ':', '') + 'hrs' AS NVARCHAR(20)) AS [Time To], 
				a.TARNo AS [TAR ID], 
				dbo.TAMS_Get_Station_Dir(a.Id, 'Min') AS [Location From],
				dbo.TAMS_Get_Station_Dir(a.Id, 'Max') AS [Location To],
				LTRIM(RTRIM(a.DescOfWork)) AS [Activities]
			FROM TAMS_TAR a
				WHERE CONVERT(DATETIME, a.AccessDate, 103) BETWEEN CONVERT(DATETIME, @AccessDateFrom, 103) AND CONVERT(DATETIME, @AccessDateTo, 103) 
					AND a.TARStatusId = 9
					AND (a.AccessType = @AccessType OR ISNULL(@AccessType, '') = '')
					AND a.Is13ASocket = 1
					AND a.Line = 'NEL'
					AND a.TrackType = @TrackType
			ORDER BY CONVERT(DATETIME, a.AccessDate, 101), a.TARNo

			-- >> 2
			SELECT a.TARNo AS [TAR ID], 
				a.Company AS [Company],
				LTRIM(RTRIM(a.DescOfWork)) AS [Activities],
				a.TVFMode AS [TVF Request], -- >> TVF Running Mode -- Clarify with Adeline
				dbo.TAMS_Get_TVF_Station(a.Id) AS [Direction], -- >> Min to Max Station
				CAST(CONVERT(NVARCHAR(20), AccessDate, 103) AS NVARCHAR(20)) AS [Date From], 
				CAST(REPLACE(SUBSTRING(CONVERT(NVARCHAR(20), AccessTimeFrom, 108), 1, 5), ':', '') + 'hrs' AS NVARCHAR(20)) AS [Time From], 
				CAST(CONVERT(NVARCHAR(20), AccessDate, 103) AS NVARCHAR(20)) AS [Date To], 
				CAST(REPLACE(SUBSTRING(CONVERT(NVARCHAR(20), AccessTimeTo, 108), 1, 5), ':', '') + 'hrs' AS NVARCHAR(20)) AS [Time To]
			FROM TAMS_TAR a, TAMS_TAR_AccessReq b, TAMS_Access_Requirement c
				WHERE CONVERT(DATETIME, a.AccessDate, 103) BETWEEN CONVERT(DATETIME, @AccessDateFrom, 103) AND CONVERT(DATETIME, @AccessDateTo, 103) 
					AND a.Id = b.TarId
					AND a.TARStatusId = 9
					AND (a.AccessType = @AccessType OR ISNULL(@AccessType, '') = '')
					AND b.IsSelected = 1
					AND b.OperationRequirement = c.ID
					AND c.OperationRequirement = 'Use of Tunnel Ventilation'
					AND a.Line = 'NEL'
					AND a.TrackType = @TrackType
			ORDER BY CONVERT(DATETIME, a.AccessDate, 101), a.TARNo

			-- >> 3
			SELECT a.TARNo AS [TAR No], 
				CONVERT(NVARCHAR(20), AccessDate, 103) + ' ' + SUBSTRING(DATENAME(dw, AccessDate), 1, 3)  AS [Date],  
				dbo.TAMS_Get_Station(a.Id) AS [Stations], 
				LTRIM(RTRIM(a.DescOfWork)) AS [Nature of Work], 
				CAST(REPLACE(SUBSTRING(CONVERT(NVARCHAR(20), AccessTimeFrom, 108), 1, 5), ':', '') + 'hrs' AS NVARCHAR(20)) + ' to ' +
				CAST(REPLACE(SUBSTRING(CONVERT(NVARCHAR(20), AccessTimeTo, 108), 1, 5), ':', '') + 'hrs' AS NVARCHAR(20)) AS [Time], 
				REPLACE(LTRIM(RTRIM(a.ARRemark)), '"', '') AS [Remarks]
			FROM TAMS_TAR a
				WHERE CONVERT(DATETIME, a.AccessDate, 103) BETWEEN CONVERT(DATETIME, @AccessDateFrom, 103) AND CONVERT(DATETIME, @AccessDateTo, 103)  
					AND a.TARStatusId = 9
					AND (a.AccessType = @AccessType OR ISNULL(@AccessType, '') = '')
					-- >> AND a.Company LIKE '%NEL Sig%'
					AND a.Company = 'NEL Signalling'
					AND a.Line = 'NEL'
					AND a.TrackType = @TrackType
			ORDER BY CONVERT(DATETIME, a.AccessDate, 101), a.TARNo

			-- >> 4
			-- 'NEL ISCS and Systems'
			SELECT ROW_NUMBER() OVER(ORDER BY CONVERT(DATETIME, a.AccessDate, 101), a.TARNo) AS [S/No],
				a.TARNo AS [TAR No], 
				CONVERT(NVARCHAR(20), AccessDate, 103)  AS [Date],  
				LTRIM(RTRIM(a.DescOfWork)) AS [Nature of Work], 
				a.Company AS [Department],
				dbo.TAMS_Get_Station(a.Id) AS [Stations], 
				dbo.TAMS_Get_ES_NoBufferZone(a.Id) AS [Track Sector], 
				CAST(REPLACE(SUBSTRING(CONVERT(NVARCHAR(20), AccessTimeFrom, 108), 1, 5), ':', '') + 'hrs' AS NVARCHAR(20)) + ' to ' +
				CAST(REPLACE(SUBSTRING(CONVERT(NVARCHAR(20), AccessTimeTo, 108), 1, 5), ':', '') + 'hrs' AS NVARCHAR(20)) AS [Time], 
				REPLACE(LTRIM(RTRIM(a.ARRemark)), '"', '') AS [Remarks]
			FROM TAMS_TAR a
				WHERE CONVERT(DATETIME, a.AccessDate, 103) BETWEEN CONVERT(DATETIME, @AccessDateFrom, 103) AND CONVERT(DATETIME, @AccessDateTo, 103)  
					AND a.TARStatusId = 9
					AND (a.AccessType = @AccessType OR ISNULL(@AccessType, '') = '')
					-- >> AND a.Company LIKE '%NEL Sig%'
					AND a.Company = 'NEL ISCS and Systems'
					AND a.Line = 'NEL'
					AND a.TrackType = @TrackType
			ORDER BY CONVERT(DATETIME, a.AccessDate, 101), a.TARNo

			-- >> 5
			-- 'NEL ISCS and Systems'
			SELECT ROW_NUMBER() OVER(ORDER BY CONVERT(DATETIME, a.AccessDate, 101), a.TARNo) AS [S/No],
				a.TARNo AS [TAR No], 
				CONVERT(NVARCHAR(20), AccessDate, 103)  AS [Date],  
				LTRIM(RTRIM(a.DescOfWork)) AS [Nature of Work], 
				a.Company AS [Department],
				dbo.TAMS_Get_Station(a.Id) AS [Stations], 
				dbo.TAMS_Get_ES_NoBufferZone(a.Id) AS [Track Sector], 
				CAST(REPLACE(SUBSTRING(CONVERT(NVARCHAR(20), AccessTimeFrom, 108), 1, 5), ':', '') + 'hrs' AS NVARCHAR(20)) + ' to ' +
				CAST(REPLACE(SUBSTRING(CONVERT(NVARCHAR(20), AccessTimeTo, 108), 1, 5), ':', '') + 'hrs' AS NVARCHAR(20)) AS [Time], 
				REPLACE(LTRIM(RTRIM(a.ARRemark)), '"', '') AS [Remarks]
			FROM TAMS_TAR a
				WHERE CONVERT(DATETIME, a.AccessDate, 103) BETWEEN CONVERT(DATETIME, @AccessDateFrom, 103) AND CONVERT(DATETIME, @AccessDateTo, 103)  
					AND a.TARStatusId = 9
					AND (a.AccessType = @AccessType OR ISNULL(@AccessType, '') = '')
					AND a.Company = 'NEL Communications'
					AND a.Line = 'NEL'
					AND a.TrackType = @TrackType
			ORDER BY CONVERT(DATETIME, a.AccessDate, 101), a.TARNo

		END

END
GO
