/****** START PROCEDURE 383 ******/
-- PROCEDURE NAME: dbo.sp_TAMS_WithdrawTarByTarID
CREATE PROCEDURE [dbo].[sp_TAMS_WithdrawTarByTarID] 	
	@TarId AS integer = 0,
	@UID As integer = 0, 
	@Remark as nvarchar(1000) = null
AS
BEGIN
	DECLARE @Line as varchar(3),
			@StatusId as int,
			@Name as nvarchar(500)
	BEGIN TRY
		BEGIN TRANSACTION;
			BEGIN
				select @Line = line from TAMS_TAR where Id = @TarId;
				select @StatusId = WFStatusId from TAMS_WFStatus where Line = @Line and WFType = 'TARWFStatus' and WFStatus = 'Withdraw';
				select @Name = [Name] from TAMS_User where userid = @UID;

				UPDATE TAMS_TAR 
				SET TARStatusId = @StatusId, 
				WithdrawRemark= @Remark,
				WithdrawBy = @UID, 
				WithdrawDate = GETDATE(),
				UpdatedOn = GETDATE() ,
				UpdatedBy =@UID
				WHERE Id = @TarId;



				insert into TAMS_Action_Log
				values(@Line, 'TAR', 'Enquiry-Withdraw', @TarId, 'TAR Form has been withdrawn by ' + @Name + ' on ' + convert(varchar, getdate(), 103), GETDATE(), @UID);
			END;

		COMMIT TRANSACTION;
	END TRY
	BEGIN CATCH
		ROLLBACK TRANSACTION;
	END CATCH

END;
GO
/****** END PROCEDURE 383 ******/

/****** START PROCEDURE 384 ******/
-- PROCEDURE NAME: dbo.SP_Test
CREATE PROCEDURE [dbo].[SP_Test]
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

    -- Insert statements for procedure here
	
	

DECLARE @InChargeName	NVARCHAR(500)
DECLARE @InChargeStatus	NVARCHAR(20)
DECLARE @AccessType NVARCHAR(50)

	CREATE TABLE #tmpnric 
(id BIGINT IDENTITY(1,1) NOT NULL, 
nric NVARCHAR(50),
namestr NVARCHAR(500),
line NVARCHAR(50),
qualdate NVARCHAR(50),
qualcode NVARCHAR(100),
qualstatus NVARCHAR(100))

TRUNCATE TABLE #tmpnric
	
	DECLARE @QualDate	NVARCHAR(20)
	SET @QualDate = '2023/08/29'
								
	DECLARE @ExecString as nvarchar(max)					
	--SET @ExecString = 'sp_TAMS_TOA_QTS_Chk '+ ' S8719031E,' + '29/8/2023,DTL, PC (ML)'

	PRINT @ExecString

	SET @AccessType='Protection'


	INSERT INTO #tmpnric
												EXEC [dbo].[sp_TAMS_TOA_QTS_Chk]
												@nric = N'S8719031E',
												@qualdate = N'29/08/2023',
												@line = N'DTL',
												@AccessType=N'PC (ML)'


								SELECT @InChargeName = namestr,
									@InChargeStatus = qualstatus
								FROM #tmpnric

								
												WAITFOR DELAY '00:00:10'
								
								DECLARE @QTSFinStatus NVARCHAR(20)
								SET @QTSFinStatus = ''

								IF @InChargeStatus	= 'InValid'
									BEGIN
										IF @AccessType = 'Protection'
											BEGIN
												TRUNCATE TABLE #tmpnric
												SET @InChargeName = ''
												SET @InChargeStatus = ''
												
												

												SET @ExecString = 'sp_TAMS_TOA_QTS_Chk '+ ' S8719031E,' + '29/8/2023,DTL,TPO (NT)'

												INSERT INTO #tmpnric
												EXEC [dbo].[sp_TAMS_TOA_QTS_Chk]
												@nric = N'S8719031E',
												@qualdate = N'29/08/2023',
												@line = N'DTL',
												@AccessType=N'TPO (NT)'


												SELECT @InChargeName = namestr,
													@InChargeStatus = qualstatus
												FROM #tmpnric

												IF @InChargeStatus	= 'InValid'
													BEGIN
														SET @QTSFinStatus = 'InValid'
													END
												ELSE
													BEGIN
														SET @QTSFinStatus = 'Valid'
													END
											END
										ELSE
											BEGIN
												SET @QTSFinStatus = 'InValid'
											END
									END
								ELSE
									BEGIN
										SET @QTSFinStatus = 'Valid'
									END

								DROP TABLE #tmpnric
								
								PRINT @QTSFinStatus

END
GO
